# Progress callback interval during library walk (avoid lock overhead on huge libraries).
_LIBRARY_WALK_PROGRESS_EVERY = 256

# Never descend into these directory basenames (case-insensitive), like find -prune.
_LIBRARY_WALK_BUILTIN_PRUNE_DIRS = frozenset(
    {
        "#recycle",
        "@recycle",
        "$recycle.bin",
        "system volume information",
        "@eadir",
        ".snapshot",
        ".git",
    }
)


def _library_walk_prune_basenames(settings: dict | None) -> frozenset[str]:
    names: set[str] = set(_LIBRARY_WALK_BUILTIN_PRUNE_DIRS)
    if settings:
        raw = (settings.get("library_walk_prune_dirs") or "").strip()
        if raw:
            for part in raw.split(","):
                t = part.strip().lower()
                if t:
                    names.add(t)
    return frozenset(names)


def _is_video_filename(name: str) -> bool:
    dot = name.rfind(".")
    if dot < 0:
        return False
    return name[dot:].lower() in VIDEO_EXTENSIONS


def _movie_source_walk_onerror(exc: OSError) -> None:
    """Keep movie-queue scans working when a subfolder is unreadable (e.g. permissions)."""
    _log.warning("Movie input folder scan skipped a path: %s", exc)


def _movie_source_video_relpaths(
    root: Path, settings: dict | None = None
) -> list[tuple[str, Path]]:
    """Videos under the movies input folder (any depth). Keys are posix paths relative to root."""
    root = root.expanduser()
    if not root.exists() or not root.is_dir():
        return []
    prune = _library_walk_prune_basenames(settings)
    # Anchor on resolved root for a stable walk tree, but do not resolve each file path:
    # resolving a symlink can escape this directory and make relative_to fail, hiding the file.
    root_res = root.resolve()
    out: list[tuple[str, Path]] = []
    for dirpath, dirnames, filenames in os.walk(
        root_res, topdown=True, onerror=_movie_source_walk_onerror
    ):
        dirnames[:] = [d for d in dirnames if d.lower() not in prune]
        base = Path(dirpath)
        for fn in filenames:
            if not _is_video_filename(fn):
                continue
            full = base / fn
            try:
                if not full.is_file():
                    continue
            except OSError:
                continue
            try:
                rel = full.relative_to(root_res).as_posix()
            except ValueError:
                continue
            out.append((rel, full))
    out.sort(key=lambda t: t[0].lower())
    return out


