class _WarmCache:
    """Background-refreshed snapshot for hot read endpoints.

    GET handlers wrapped by this never pay the cost of rebuilding —
    they just hand back the latest snapshot reference. A worker thread
    rebuilds the snapshot when:

      • startup (the worker fires immediately so the cache is warm
        before any request lands),
      • ``invalidate()`` is called (typically from a mutation
        middleware or a Watchdog handler — coalesces multiple
        invalidations within one rebuild),
      • ``backstop_interval_s`` elapses with no other trigger (safety
        net for changes the in-process invalidator can't observe, like
        background scanner writes or external DB edits).

    The very first ``get()`` before the worker has produced anything
    blocks on the initial build; everything after is O(1) — readers
    just see whichever snapshot reference is current. Snapshot replace
    is a single attribute assignment, which is atomic in CPython, so
    readers never see a torn payload and never need to grab a lock.
    """

    def __init__(self, name: str, builder, backstop_interval_s: float):
        self._name = name
        self._builder = builder
        self._backstop = float(backstop_interval_s)
        self._snapshot = None
        self._snapshot_built_at = 0.0
        # Serialises rebuilds. The fast-path get() never grabs it.
        self._build_lock = threading.Lock()
        # Signal from invalidate() to the worker. wait(timeout=) gives
        # us "rebuild on invalidate OR every N seconds, whichever
        # comes first" without two timers.
        self._dirty = threading.Event()
        self._dirty.set()
        self._thread: threading.Thread | None = None
        self._started = False

    def start(self) -> None:
        if self._started:
            return
        self._started = True
        t = threading.Thread(
            target=self._loop, daemon=True, name=f"warmcache-{self._name}"
        )
        t.start()
        self._thread = t

    def get(self):
        """Latest snapshot. Only the very first call before the worker
        produces a snapshot blocks (synchronous rebuild)."""
        snap = self._snapshot
        if snap is not None:
            return snap
        # First-request cold path. Build inline under the lock so
        # multiple concurrent first-callers don't all rebuild.
        with self._build_lock:
            if self._snapshot is None:
                self._rebuild_locked()
            return self._snapshot

    def invalidate(self) -> None:
        """Schedule a rebuild. Multiple invalidations coalesce into a
        single rebuild — set is idempotent until the worker clears it."""
        self._dirty.set()

    def age_seconds(self) -> float:
        ts = self._snapshot_built_at
        if ts <= 0:
            return float("inf")
        return max(0.0, time.time() - ts)

    def _rebuild_locked(self) -> None:
        try:
            new = self._builder()
            self._snapshot = new
            self._snapshot_built_at = time.time()
        except Exception as e:
            _log.warning(f"WarmCache[{self._name}] rebuild failed: {e}")

    def _loop(self) -> None:
        while True:
            self._dirty.wait(timeout=self._backstop)
            self._dirty.clear()
            with self._build_lock:
                self._rebuild_locked()


def _favourites_progress_start(phase: str, total: int) -> None:
    with _favourites_index_lock:
        _favourites_index_progress.update(
            {
                "running": True,
                "phase": phase,
                "total": max(0, int(total)),
                "done": 0,
                "current_name": "",
            }
        )


def _favourites_progress_update(current_name: str, done: int) -> None:
    with _favourites_index_lock:
        _favourites_index_progress["current_name"] = current_name or ""
        _favourites_index_progress["done"] = max(0, int(done))


def _favourites_progress_finish() -> None:
    with _favourites_index_lock:
        _favourites_index_progress["running"] = False
        _favourites_index_progress["phase"] = ""
        _favourites_index_progress["total"] = 0
        _favourites_index_progress["done"] = 0
        _favourites_index_progress["current_name"] = ""


