class NewVideoHandler(FileSystemEventHandler):
    """Watches source folder and queues new video files after a hold period."""

    def on_created(self, event):
        if event.is_directory:
            return
        path = Path(event.src_path)
        if path.suffix.lower() not in VIDEO_EXTENSIONS:
            return
        s = db.get_settings()
        if s.get("folder_watch_enabled", "true").lower() != "true":
            return
        hold = int(s.get("folder_watch_hold_secs", "60"))
        with _pending_lock:
            if path.name not in _pending_files:
                emit(f"WATCHER detected: {path.name} (hold {hold}s)")
            _pending_files[path.name] = time.time() + hold
        # Source-dir contents changed — invalidate the warm queue
        # snapshot so the next GET /api/queue reflects the new file.
        try:
            _queue_warm.invalidate()
        except Exception:
            pass

    def on_moved(self, event):
        # Handle files moved/renamed into the folder
        self.on_created(type("E", (), {"is_directory": False, "src_path": event.dest_path})())

    def on_deleted(self, event):
        # File pulled out of the source dir (manual rm, processor moved
        # it to the library). Drop the warm queue snapshot so the row
        # vanishes from the next tab return.
        try:
            _queue_warm.invalidate()
        except Exception:
            pass

    def on_modified(self, event):
        # Some systems fire modified instead of created for file moves
        if event.is_directory:
            return
        path = Path(event.src_path)
        if path.suffix.lower() not in VIDEO_EXTENSIONS:
            return
        s = db.get_settings()
        if s.get("folder_watch_enabled", "true").lower() != "true":
            return
        hold = int(s.get("folder_watch_hold_secs", "60"))
        with _pending_lock:
            if path.name not in _pending_files:
                emit(f"WATCHER detected (modified): {path.name} (hold {hold}s)")
                _pending_files[path.name] = time.time() + hold
        try:
            _queue_warm.invalidate()
        except Exception:
            pass


class NewMovieVideoHandler(FileSystemEventHandler):
    """Watch movies_source_dir; queue video files after hold (same settings as scene watch)."""

    def _rel_under_movies_root(self, path: Path) -> str | None:
        s = db.get_settings()
        md = Path((s.get("movies_source_dir") or "").strip()).expanduser()
        if not md.is_dir():
            return None
        try:
            rp = path.resolve()
            return rp.relative_to(md.resolve()).as_posix()
        except ValueError:
            return None

    def on_created(self, event):
        if event.is_directory:
            return
        path = Path(event.src_path)
        if path.suffix.lower() not in VIDEO_EXTENSIONS:
            return
        s = db.get_settings()
        if s.get("folder_watch_enabled", "true").lower() != "true":
            return
        rel = self._rel_under_movies_root(path)
        if not rel or not path.is_file():
            return
        hold = int(s.get("folder_watch_hold_secs", "60"))
        with _pending_lock:
            if rel not in _pending_movie_files:
                emit(f"MOVIE WATCHER: {rel} (hold {hold}s)")
            _pending_movie_files[rel] = time.time() + hold
        # Movies source-dir contents changed — drop the warm snapshot so
        # the next GET /api/movies/queue reflects the new file.
        try:
            _movies_queue_warm.invalidate()
        except Exception:
            pass

    def on_moved(self, event):
        self.on_created(type("E", (), {"is_directory": False, "src_path": event.dest_path})())

    def on_deleted(self, event):
        # File pulled out of movies source dir (manual rm, processor
        # moved it into the library). Invalidate so the row vanishes
        # from the next tab return without waiting on the backstop.
        try:
            _movies_queue_warm.invalidate()
        except Exception:
            pass

    def on_modified(self, event):
        if event.is_directory:
            return
        path = Path(event.src_path)
        if path.suffix.lower() not in VIDEO_EXTENSIONS:
            return
        s = db.get_settings()
        if s.get("folder_watch_enabled", "true").lower() != "true":
            return
        rel = self._rel_under_movies_root(path)
        if not rel or not path.is_file():
            return
        hold = int(s.get("folder_watch_hold_secs", "60"))
        with _pending_lock:
            if rel not in _pending_movie_files:
                emit(f"MOVIE WATCHER (modified): {rel} (hold {hold}s)")
                _pending_movie_files[rel] = time.time() + hold
        try:
            _movies_queue_warm.invalidate()
        except Exception:
            pass


_poll_seen: set = set()  # files the poll has already queued (avoids re-queuing on every cycle)


def _check_pending_files():
    """Called by scheduler every 30s - fires pipeline for files past their hold time.
    Also polls the source directory for any NEW files that inotify missed."""
    if processing_state["running"]:
        return

    s = db.get_settings()
    if s.get("folder_watch_enabled", "true").lower() != "true":
        return

    source_dir = Path(s.get("source_dir", ""))
    hold = int(s.get("folder_watch_hold_secs", "60"))
    now = time.time()

    # Polling fallback: scan source dir for NEW video files only
    # Skip files we've already seen/queued, and files with any processing history
    if source_dir.exists():
        history = {r["filename"] for r in db.get_history(limit=10000)}
        with _pending_lock:
            for f in source_dir.iterdir():
                if f.is_file() and f.suffix.lower() in VIDEO_EXTENSIONS:
                    if (f.name not in _pending_files
                            and f.name not in _poll_seen
                            and f.name not in history):
                        _pending_files[f.name] = now + hold
                        _poll_seen.add(f.name)
                        emit(f"WATCHER poll detected: {f.name} (hold {hold}s)")

    # Clean up _poll_seen for files that no longer exist
    if source_dir.exists():
        current_files = {f.name for f in source_dir.iterdir() if f.is_file()}
        _poll_seen.difference_update(_poll_seen - current_files)

    # Fire pipeline for files past hold time
    ready = []
    with _pending_lock:
        for fname, fire_at in list(_pending_files.items()):
            if now >= fire_at:
                ready.append(fname)
                del _pending_files[fname]
    if ready:
        to_run = [f for f in ready if (source_dir / f).exists()]
        if to_run:
            run_pipeline(to_run)


def _check_pending_movies():
    """Poll movies_source_dir and fire movie pipeline when hold elapsed (matches scene watcher)."""
    if processing_state["running"]:
        return
    s = db.get_settings()
    if s.get("folder_watch_enabled", "true").lower() != "true":
        return
    movie_dir = Path((s.get("movies_source_dir") or "").strip()).expanduser()
    if not movie_dir.exists():
        return
    hold = int(s.get("folder_watch_hold_secs", "60"))
    now = time.time()
    terminal = db.get_movie_terminal_filenames()
    if movie_dir.exists():
        with _pending_lock:
            for rel, f in _movie_source_video_relpaths(movie_dir, s):
                if (
                    rel not in _pending_movie_files
                    and rel not in _movie_poll_seen
                    and rel not in terminal
                ):
                    _pending_movie_files[rel] = now + hold
                    _movie_poll_seen.add(rel)
                    emit(f"MOVIE WATCHER poll: {rel} (hold {hold}s)")
    if movie_dir.exists():
        current = {rel for rel, _ in _movie_source_video_relpaths(movie_dir, s)}
        _movie_poll_seen.difference_update(_movie_poll_seen - current)
    ready = []
    with _pending_lock:
        for fname, fire_at in list(_pending_movie_files.items()):
            if now >= fire_at:
                ready.append(fname)
                del _pending_movie_files[fname]
    if ready:
        md_res = movie_dir.resolve()
        to_run = [rel for rel in ready if (md_res / Path(rel)).is_file()]
        if to_run:
            run_movie_pipeline(to_run)


def _start_watcher():
    global observer
    s = db.get_settings()
    if s.get("folder_watch_enabled", "true").lower() != "true":
        return
    source_dir = Path(s.get("source_dir", ""))
    if not source_dir.exists():
        return
    if observer:
        observer.stop()
    observer = Observer()
    observer.schedule(NewVideoHandler(), str(source_dir), recursive=False)
    observer.start()


def _start_movie_watcher():
    global movie_observer
    s = db.get_settings()
    if s.get("folder_watch_enabled", "true").lower() != "true":
        if movie_observer:
            movie_observer.stop()
            movie_observer = None
        return
    md = Path((s.get("movies_source_dir") or "").strip()).expanduser()
    if not md.exists():
        if movie_observer:
            movie_observer.stop()
            movie_observer = None
        return
    if movie_observer:
        movie_observer.stop()
    movie_observer = Observer()
    movie_observer.schedule(NewMovieVideoHandler(), str(md), recursive=True)
    movie_observer.start()


def _restart_watcher():
    """Restart watcher with current settings - called after settings save."""
    global observer
    if observer:
        observer.stop()
        observer = None
    _start_watcher()
    _start_movie_watcher()

app = FastAPI(title="Top-Shelf")

# ---------------------------------------------------------------------------
# Auth helpers
# ---------------------------------------------------------------------------

COOKIE_NAME   = "ts_session"
LOGIN_PATH    = "/login"
PUBLIC_PATHS  = {"/login", "/api/auth/login", "/api/auth/logout", "/api/health", "/api/version"}

# Paths the boot-loading gate lets through while the app is warming up.
# Everything else redirects to /loading until ``_startup_complete`` is set.
LOADING_PATH    = "/loading"
BOOT_OPEN_PATHS = {LOADING_PATH, "/api/startup/status", "/api/status", "/api/version", "/favicon.ico"}

_startup_complete = threading.Event()
_startup_status_lock = threading.Lock()
_startup_status: dict = {
    "ready": False,
    "started_at": 0.0,
    "finished_at": 0.0,
    "current": "Starting up…",
    "current_subtext": "",
    "step_index": 0,
    "steps_total": 0,
    "steps_done": [],       # list of {"label": str, "subtext": str}
    "error": None,
}


def _startup_step(label: str, subtext: str, index: int, total: int, done: bool = False) -> None:
    """Update the boot-loading progress so the /loading page can poll it.
    `subtext` is the mono-style log-line rendered underneath the label."""
    with _startup_status_lock:
        _startup_status["current"] = label
        _startup_status["current_subtext"] = subtext
        _startup_status["step_index"] = index
        _startup_status["steps_total"] = total
        if done:
            _startup_status["steps_done"].append({"label": label, "subtext": subtext})


def _run_startup_warmup() -> None:
    """Warm the caches users hit first, but don't let any single step
    wedge the boot. Each step runs on its own daemon thread with a
    wall-time deadline; if it doesn't complete in time we move on so
    the /loading gate releases — the step keeps working in the
    background and populates its cache when it eventually finishes.

    A stuck RSS feed (slow TLS handshake that the per-request timeout
    can't unblock) used to leave the user on the loading screen
    forever; now it just delays the RSS feed appearing while the rest
    of the app is usable.
    """
    with _startup_status_lock:
        _startup_status["started_at"] = time.time()
        _startup_status["current"] = "Warming caches…"
        _startup_status["current_subtext"] = ""
    # Per-step deadline: long enough for cold external API calls to
    # complete on a normal connection, short enough that one slow
    # upstream can't push the whole startup past the loading-page
    # deadline (120 s in static/loading.html).
    PER_STEP_DEADLINE_S = 25.0
    steps: list[tuple[str, str, callable]] = [
        ("Setting the mood…",            "> checking_blinds: closed",          _refresh_hourly_content_cache),
        ("Uncovering your indulgences…", "> private_session: active",          _refresh_rss_cache),
        ("Skimming the gossip column…",  "> news_feed: warmed",                _refresh_news_rss_cache),
        ("Revealing your vices…",        "> locating_hidden_folders: success", _refresh_tag_scene_pools),
    ]
    total = len(steps)
    for i, (label, subtext, fn) in enumerate(steps):
        _startup_step(label, subtext, i + 1, total)
        emit(f"STARTUP warmup [{i + 1}/{total}]: {label} {subtext}")
        # Run the step on its own thread so we can wall-time-wait it
        # without losing the actual work — if the deadline passes, the
        # thread keeps running in the background and populates the
        # cache when it eventually completes (or stays stuck without
        # blocking anything else).
        done_evt = threading.Event()

        def _runner(_fn=fn, _label=label, _evt=done_evt) -> None:
            try:
                _fn()
            except Exception as e:
                emit(f"STARTUP warmup '{_label}' error: {e}")
            finally:
                _evt.set()

        t = threading.Thread(
            target=_runner,
            daemon=True,
            name=f"warmup-{i + 1}",
        )
        t.start()
        if not done_evt.wait(timeout=PER_STEP_DEADLINE_S):
            emit(
                f"STARTUP warmup '{label}' over {PER_STEP_DEADLINE_S:.0f}s — "
                f"continuing in background, advancing boot."
            )
        _startup_step(label, subtext, i + 1, total, done=True)
    # Kick off background workers for the hot read endpoints. Each
    # builds its first snapshot immediately so the post-warmup landing
    # page never blocks on a /api/favourites, /api/queue, or
    # /api/downloads round-trip — subsequent rebuilds happen on
    # mutation or after the per-cache backstop, off the request thread.
    try:
        _favourites_warm.start()
        _queue_warm.start()
        _movies_queue_warm.start()
        _downloads_warm.start()
    except Exception as e:
        emit(f"STARTUP warm-cache start error: {e}")

    with _startup_status_lock:
        _startup_status["ready"] = True
        _startup_status["current"] = "Ready"
        _startup_status["current_subtext"] = ""
        _startup_status["finished_at"] = time.time()
    _startup_complete.set()
    emit(f"STARTUP warmup complete in {int(_startup_status['finished_at'] - _startup_status['started_at'])}s")

    # Fire-and-forget: if scene_fingerprints is sparse compared to the
    # number of imported files, seed it in the background so the
    # /api/library/scenes-in phash crosswalk works on the next browse.
    # Doesn't block startup — runs on its own daemon thread.
    try:
        with db.get_conn() as _conn:
            _sf_count = int(_conn.execute(
                "SELECT COUNT(*) AS c FROM scene_fingerprints"
            ).fetchone()["c"])
            _pf_count = int(_conn.execute(
                "SELECT COUNT(*) AS c FROM processed_files "
                "WHERE status = 'success' "
                "  AND COALESCE(match_external_id, '') <> '' "
                "  AND lower(COALESCE(match_source, '')) IN ('stashdb','fansdb','tpdb','javstash')"
            ).fetchone()["c"])
        if _pf_count > 0 and _sf_count < _pf_count:
            emit(f"STARTUP: seeding scene_fingerprints "
                 f"(have {_sf_count} rows, {_pf_count} processed files)")
            def _seed_runner():
                rows: list[tuple[str, str]] = []
                with db.get_conn() as conn:
                    cur = conn.execute(
                        "SELECT DISTINCT lower(match_source) AS src, "
                        "                match_external_id AS sid "
                        "FROM processed_files "
                        "WHERE status = 'success' "
                        "  AND COALESCE(match_external_id, '') <> '' "
                        "  AND lower(COALESCE(match_source, '')) "
                        "      IN ('stashdb', 'fansdb', 'tpdb', 'javstash')"
                    )
                    for r in cur.fetchall():
                        rows.append((r["src"], r["sid"]))
                if not rows:
                    return
                known: set[str] = set()
                for src in ("stashdb", "fansdb", "tpdb", "javstash"):
                    ids_for_src = [i for (s, i) in rows if s == src]
                    if ids_for_src:
                        known |= {f"{src}:{x}" for x in
                                  db.scene_fingerprints_known_ids(src, ids_for_src)}
                todo = [(s, i) for (s, i) in rows if f"{s}:{i}" not in known]
                if not todo:
                    return
                emit(f"STARTUP: seeding {len(todo)} scene fingerprints")
                for chunk_start in range(0, len(todo), 30):
                    _library_scene_backfill_worker(
                        todo[chunk_start:chunk_start + 30]
                    )
                emit(f"STARTUP: scene fingerprint seed complete")
            threading.Thread(
                target=_seed_runner,
                daemon=True,
                name="lib-fp-seed-startup",
            ).start()
    except Exception as e:
        emit(f"STARTUP scene_fingerprints seed kickoff error: {e}")


def _is_authenticated(request: Request) -> bool:
    if not db.get_password_hash():
        return True  # No password set - open access
    token = request.cookies.get(COOKIE_NAME, "")
    return db.validate_session(token)


@app.middleware("http")
async def auth_middleware(request: Request, call_next):
    path = request.url.path
    # Static assets always available (loading page depends on them).
    if path.startswith("/static"):
        return await call_next(request)
    # Boot-loading gate: while warmup is running, only the loading page +
    # its status probe are reachable. This both pre-warms feeds before
    # login and prevents auth attempts against a half-initialised app.
    if not _startup_complete.is_set():
        if path in BOOT_OPEN_PATHS:
            return await call_next(request)
        if path.startswith("/api/"):
            from fastapi.responses import JSONResponse
            return JSONResponse({"error": "Warming up", "ready": False}, status_code=503)
        from fastapi.responses import RedirectResponse
        next_target = path if path != LOADING_PATH else "/scenes"
        return RedirectResponse(url=f"{LOADING_PATH}?next={next_target}", status_code=302)
    # After warmup: standard auth flow.
    if path not in PUBLIC_PATHS:
        if not _is_authenticated(request):
            if path.startswith("/api/"):
                from fastapi.responses import JSONResponse
                return JSONResponse({"error": "Unauthorised"}, status_code=401)
            from fastapi.responses import RedirectResponse
            return RedirectResponse(url=f"{LOGIN_PATH}?next={path}", status_code=302)
    # Auth-passed path. Dispatch to the handler, then invalidate any
    # warm snapshots whose source data the request just mutated. The
    # snapshot worker rebuilds in the background, so the next GET sees
    # fresh data without ever paying the rebuild cost on this request.
    response = await call_next(request)
    try:
        if (
            request.method != "GET"
            and 200 <= response.status_code < 300
        ):
            if path.startswith("/api/favourites"):
                # Covers star, lock, match, delete, ext-link, refresh,
                # scan, group-add/remove and every other mutation route
                # under /api/favourites/*.
                _favourites_warm.invalidate()
            if (
                path.startswith("/api/queue")
                or path.startswith("/api/file")
                or path.startswith("/api/run")
            ):
                # Scene-queue mutators: delete, suggestions accept/reject,
                # manual file actions, processor run kicks. Filesystem
                # state changes — next /api/queue must rescan.
                _queue_warm.invalidate()
            if path.startswith("/api/movies/"):
                # Movies-queue mutators: /api/movies/file (manual file),
                # /api/movies/run/* (processor kicks), /api/movies/manual
                # (manual TMDB/TPDB pick), /api/movies/skip, etc. Any POST
                # under /api/movies/* is assumed to affect the queue
                # snapshot — cheaper to over-invalidate (background
                # rebuild) than to whitelist each route.
                _movies_queue_warm.invalidate()
    except Exception:
        pass
    return response


class CachedStaticFiles(StaticFiles):
    async def get_response(self, path: str, scope):
        response = await super().get_response(path, scope)
        if isinstance(response, (Response, NotModifiedResponse)):
            ext = Path(path).suffix.lower()
            if ext in {".ttf", ".woff", ".woff2", ".ico", ".jpg", ".jpeg", ".png", ".gif", ".webp", ".avif", ".svg"}:
                #: Binary assets practically never change between deploys —
                #: keep them immutable so the browser doesn't even ask.
                response.headers["Cache-Control"] = "public, max-age=31536000, immutable"
            elif ext in {".css", ".js"}:
                #: CSS / JS DO change with every deploy, BUT every <script>
                #: and <link> tag in the templates already carries a
                #: `?v=...` cache-bust token (queue.js?v=1, app-shell.css?v=14,
                #: ...). Versioned URLs are immutable by definition —
                #: when the content changes, the URL changes, and the new
                #: token forces a fresh download. Without `immutable` the
                #: browser revalidates every cached script on every page
                #: navigation, adding one round-trip per asset even when
                #: the server returns 304. For un-versioned requests
                #: (legacy callers, dev tools) fall back to the
                #: conditional-revalidate policy so a stale cached file
                #: can't outlive a deploy.
                query = scope.get("query_string") or b""
                if b"v=" in query:
                    response.headers["Cache-Control"] = "public, max-age=31536000, immutable"
                else:
                    response.headers["Cache-Control"] = "no-cache, must-revalidate"
        return response


app.mount("/static", CachedStaticFiles(directory="static"), name="static")


def _apply_retry_schedule():
    """Read settings and (re)schedule the retry job."""
    try:
        scheduler.remove_job("retry")
    except Exception:
        pass
    s = db.get_settings()
    if s.get("retry_enabled", "true").lower() != "true":
        return
    hour = int(s.get("retry_hour", "1"))
    freq = int(s.get("retry_frequency_h", "24"))
    if freq == 24:
        trigger = CronTrigger(hour=hour, minute=0)
    else:
        trigger = CronTrigger(hour=f"*/{freq}", minute=0)
    scheduler.add_job(run_retry_pipeline, trigger, id="retry", replace_existing=True)


def run_retry_pipeline():
    """Re-run the full pipeline on all non-filed files that still exist in the source dir."""
    if processing_state["running"]:
        return
    s = db.get_settings()
    source_dir = Path(s.get("source_dir", ""))
    candidates = db.get_retry_files()
    # Only retry files that still exist on disk (DB key may be stem or full basename)
    to_retry = [f for f in candidates if db.resolve_source_video_path(source_dir, f) is not None]
    if not to_retry:
        return
    run_pipeline(to_retry)


#: In-memory bookkeeping for the IAFD trickle worker. Tracks names
#: that failed to resolve on IAFD so we don't retry them every tick
#: — simpler than persisting a failure column. Cleared on server
#: restart (so a transient IAFD outage gets another pass).
_iafd_trickle_fail_names: set[str] = set()
_iafd_trickle_state: dict = {
    "last_tick":    "",
    "last_name":    "",
    "last_status":  "",   # "scraped" | "skipped" | "unresolved" | "error: …"
    "films_last":   0,
}
_iafd_trickle_state_lock = threading.Lock()


def _iafd_trickle_queue_performer_names() -> set[str]:
    """Return the set of performer names mentioned in the current
    queue (raw filenames in ``source_dir``). Pulled from
    processed_files.performers because that's where the library-guess
    + history match writes land for each queue row. Normalised to
    lowercase for case-insensitive membership checks."""
    names: set[str] = set()
    try:
        settings = db.get_settings()
        source_dir = Path(settings.get("source_dir", ""))
        if not source_dir.is_dir():
            return names
        on_disk = {p.name for p in source_dir.iterdir() if p.is_file() and p.suffix.lower() in VIDEO_EXTENSIONS}
        if not on_disk:
            return names
        history = db.get_history(limit=10000)
        for row in history:
            fn = row.get("filename") or ""
            if fn not in on_disk and (fn + ".mp4") not in on_disk:  # stem fallback handled downstream
                continue
            raw = row.get("performers") or ""
            if not raw:
                continue
            for part in raw.replace("|", ",").replace(" / ", ",").split(","):
                nm = part.strip()
                if nm:
                    names.add(nm.lower())
    except Exception as exc:
        emit(f"IAFD trickle: queue-name scan failed ({exc})")
    return names


def _iafd_trickle_tick() -> None:
    """One step of the trickle worker: pick a single library performer
    and scrape their IAFD filmography.

    Priority order (all inside the stale-or-unscraped candidate set):
      1. Performers currently mentioned in the queue (jump the line
         so a user who just dropped new files gets enrichment fast).
      2. Never-scraped performers, oldest favourite first.
      3. Stale performers, oldest last_scraped first.

    Idempotent on errors — updates the trickle state dict so status
    endpoints can surface the last result without touching DB rows.
    """
    settings = db.get_settings()
    #: Default off — routine IAFD scraping was tripping the 403 cooldown
    #: for the install, and the marginal benefit of always-fresh
    #: filmographies is small versus the cost. Users who want the
    #: trickle can flip the setting in Settings → Databases.
    if (settings.get("iafd_trickle_enabled") or "false").strip().lower() != "true":
        return
    if processing_state.get("running"):
        #: Don't contend with a full pipeline run — they both make
        #: HTTP calls, and this is the less-urgent background work.
        return
    try:
        refresh_days = int(settings.get("iafd_trickle_refresh_days") or "30")
    except (ValueError, TypeError):
        refresh_days = 30
    stale_cutoff = (datetime.now() - timedelta(days=refresh_days)).isoformat(timespec="seconds")
    try:
        candidates = db.iafd_trickle_candidates(stale_cutoff)
    except Exception as exc:
        emit(f"IAFD trickle: candidate scan failed ({exc})")
        return
    if not candidates:
        return
    #: Filter out known-unresolvable names so we stop hammering
    #: IAFD for them on every tick.
    candidates = [c for c in candidates if c["folder_name"].lower() not in _iafd_trickle_fail_names]
    if not candidates:
        return
    queue_names = _iafd_trickle_queue_performer_names()
    if queue_names:
        #: Stable sort: queue-mentioned first, preserving the existing
        #: never-scraped-then-oldest-stale ordering inside each group.
        candidates.sort(key=lambda c: 0 if c["folder_name"].lower() in queue_names else 1)
    pick = candidates[0]
    name = pick["folder_name"]
    reason = "queue-jumper" if name.lower() in queue_names else ("fresh" if not pick["is_scraped"] else "stale")
    emit(f"IAFD trickle tick: picking {name!r} ({reason})")
    now_iso = datetime.now().isoformat(timespec="seconds")
    status = "skipped"
    films_count = 0
    try:
        perf_url = pick["iafd_url"] or _iafd_performer_url(name)
        if not perf_url:
            _iafd_trickle_fail_names.add(name.lower())
            emit(f"IAFD trickle: '{name}' not resolvable on IAFD — marked as skip")
            status = "unresolved"
        else:
            #: _iafd_performer_filmography already write-throughs to
            #: iafd_performers + iafd_films + the join table. No extra
            #: work needed here; just invoke and let persistence fall
            #: out as a side-effect.
            films = _iafd_performer_filmography(perf_url)
            films_count = len(films)
            status = "scraped" if films else "empty"
    except Exception as exc:
        emit(f"IAFD trickle: scrape failed for {name!r}: {exc}")
        status = f"error: {exc}"[:80]
    with _iafd_trickle_state_lock:
        _iafd_trickle_state.update({
            "last_tick":   now_iso,
            "last_name":   name,
            "last_status": status,
            "films_last":  films_count,
        })


def _apply_iafd_trickle_schedule():
    """Read settings and (re)schedule the IAFD trickle worker. Same
    pattern as the retry / TPDB-sync jobs: remove any existing
    registration, re-add if enabled."""
    try:
        scheduler.remove_job("iafd_trickle")
    except Exception:
        pass
    s = db.get_settings()
    if (s.get("iafd_trickle_enabled") or "false").strip().lower() != "true":
        return
    try:
        minutes = max(1, int(s.get("iafd_trickle_interval_minutes") or "5"))
    except (ValueError, TypeError):
        minutes = 5
    scheduler.add_job(
        _iafd_trickle_tick, "interval",
        minutes=minutes, id="iafd_trickle", replace_existing=True,
        #: Small next_run_time offset so the first tick doesn't fire
        #: inside boot (which is already doing heavy work). Keeps the
        #: initial app startup snappy — the user won't notice if IAFD
        #: scraping starts 10s late.
        next_run_time=datetime.now() + timedelta(seconds=10),
    )


def _apply_tpdb_sync_schedule():
    """Read settings and (re)schedule the TPDB favourites sync job."""
    s = db.get_settings()
    if s.get("tpdb_sync_enabled", "false").lower() != "true":
        try:
            scheduler.remove_job("tpdb_sync")
        except Exception:
            pass
        return
    hour = int(s.get("tpdb_sync_hour", "2"))
    freq = int(s.get("tpdb_sync_frequency_h", "24"))
    if freq == 24:
        trigger = CronTrigger(hour=hour, minute=0)
    else:
        trigger = CronTrigger(hour=f"*/{freq}", minute=0)
    scheduler.add_job(sync_tpdb_favourites, trigger, id="tpdb_sync", replace_existing=True)


def _apply_favourites_schedule():
    """Nightly scan of library performer/studio folders into Favourites index."""
    try:
        scheduler.remove_job("favourites_scan")
    except Exception:
        pass
    s = db.get_settings()
    if s.get("favourites_scan_enabled", "false").lower() != "true":
        return
    hour = int(s.get("favourites_scan_hour", "3")) % 24
    trigger = CronTrigger(hour=hour, minute=12)
    scheduler.add_job(
        run_favourites_scheduled_scan,
        trigger,
        id="favourites_scan",
        replace_existing=True,
    )


def _apply_library_phash3_schedule() -> None:
    try:
        scheduler.remove_job("library_phash3_rescan")
    except Exception:
        pass
    s = db.get_settings()
    if s.get("library_phash3_rescan_enabled", "false").lower() != "true":
        return
    trigger = CronTrigger(hour=5, minute=31)
    scheduler.add_job(
        run_library_phash3_scheduled_job,
        trigger,
        id="library_phash3_rescan",
        replace_existing=True,
    )


@app.on_event("startup")
async def startup():
    global log_queue
    log_queue = asyncio.Queue()
    db.init_db()
    _migrate_sidecar_phashes()
    _migrate_performer_images_if_needed()
    # Studio-logo maintenance used to run synchronously here — fine for
    # small libraries but with 8000+ drop-directory files it can add
    # several seconds of disk I/O to every boot and blocks the event
    # loop while HTTP is still "waiting for application startup". Offload
    # everything to a background thread so uvicorn finishes startup
    # immediately; the sync completes out-of-band and new logos become
    # visible on the next page load.
    def _studio_logos_boot_tasks() -> None:
        try:
            _seed_studio_logos_from_archive()
        except Exception as e:
            _log.warning(f"studio-logo seed failed: {e}")
        try:
            _normalise_existing_studio_logos()
        except Exception as e:
            _log.warning(f"studio-logo normalise failed: {e}")
        try:
            _sync_manual_studio_logos_from_disk()
        except Exception as e:
            _log.warning(f"studio-logo disk sync failed: {e}")
    threading.Thread(target=_studio_logos_boot_tasks, daemon=True, name="studio-logo-boot").start()
    # Vice folder migration — every monitored_tag on disk gets a folder
    # under vices_dir on first boot after the feature lands. Also fetches
    # TPDB tag images into vice_logos/ so /library renders with art.
    def _vices_boot_tasks() -> None:
        try:
            _sync_vice_folders()
        except Exception as e:
            _log.warning(f"vice-folder migration failed: {e}")
        try:
            _fetch_missing_vice_logos()
        except Exception as e:
            _log.warning(f"vice-logo fetch failed: {e}")
    threading.Thread(target=_vices_boot_tasks, daemon=True, name="vice-boot").start()
    _apply_retry_schedule()
    _apply_tpdb_sync_schedule()
    _apply_favourites_schedule()
    _apply_library_phash3_schedule()
    _apply_iafd_trickle_schedule()
    scheduler.add_job(_check_pending_files, "interval", seconds=30, id="pending_check")
    scheduler.add_job(_check_pending_movies, "interval", seconds=30, id="movie_pending_check")
    scheduler.add_job(db.purge_expired_sessions, "interval", hours=1, id="session_purge")
    scheduler.add_job(_refresh_rss_cache, "interval", hours=1, id="rss_cache_refresh")
    scheduler.add_job(_refresh_news_rss_cache, "interval", hours=1, id="news_rss_cache_refresh")
    scheduler.add_job(_studio_logo_fetcher_job, "interval", hours=6, id="studio_logos_fetch", replace_existing=True)
    scheduler.add_job(_check_pending_downloads, "interval", seconds=30, id="download_check")
    scheduler.add_job(
        _wanted_library_reconcile_job,
        "interval",
        minutes=15,
        id="wanted_library_reconcile",
        replace_existing=True,
    )
    # Pre-warm name-search suggestions for unmatched files that don't
    # yet have any cached candidates — so the user opening the
    # Suggestions modal always sees fresh hits without clicking "Brain"
    # per row. Scoped to a small batch per tick (rate-limited via the
    # job itself) so source-DB quotas aren't burned through on big
    # backlogs.
    scheduler.add_job(
        _suggestions_trickle_job,
        "interval",
        minutes=5,
        id="suggestions_trickle",
        replace_existing=True,
    )
    scheduler.add_job(_refresh_hourly_content_cache, "interval", hours=1, id="content_cache_refresh", replace_existing=True)
    scheduler.add_job(_refresh_tag_scene_pools, "interval", minutes=25, id="tag_scene_pools_refresh", replace_existing=True)
    scheduler.add_job(_activity_log_prune_job, "interval", hours=24, id="activity_log_prune", replace_existing=True)
    #: Network-error coalescer flush. Walks the per-host suppression
    #: state and emits a summary line for any window that closed since
    #: the last tick — so the user sees "N errors suppressed" even
    #: when no new error arrives to roll the window over.
    scheduler.add_job(_net_error_flush_expired, "interval", minutes=2, id="net_error_flush", replace_existing=True)
    # Scene-grab log housekeeping: prune consumed rows older than a
    # week and unconsumed (= grab never landed) rows older than 30
    # days. Daily is plenty — the table grows at most one row per
    # successful grab.
    scheduler.add_job(db.purge_orphan_scene_grabs, "interval", hours=24, id="scene_grab_purge", replace_existing=True)
    # Kick the boot-loading warmup thread. The HTTP middleware sends all
    # traffic to /loading until this thread sets ``_startup_complete``.
    threading.Thread(target=_run_startup_warmup, daemon=True, name="startup-warmup").start()
    # One-shot WebP migration — converts legacy .jpg/.png runtime caches
    # to .webp. Sentinel-guarded so subsequent boots are a fast no-op.
    # Runs in its own daemon so it doesn't block warmup or the loading
    # gate; the user keeps using the app while this works through
    # whatever's on disk.
    threading.Thread(target=_run_webp_migration_once, daemon=True, name="webp-migration").start()
    scheduler.start()
    try:
        _activity_log_prune_job()
    except Exception:
        pass
    _start_watcher()
    _start_movie_watcher()
    _start_download_watcher()
    # Cache warmup is handled by the ``_run_startup_warmup`` thread kicked
    # above — it feeds the /loading page progress and releases the gate
    # on completion.


@app.on_event("shutdown")
async def shutdown():
    global observer, download_observer, movie_observer
    if observer:
        observer.stop()
    if movie_observer:
        movie_observer.stop()
    if download_observer:
        download_observer.stop()
    scheduler.shutdown(wait=False)


def _migrate_sidecar_phashes():
    """One-time migration: read any existing .phash sidecar files into the DB and delete them."""
    settings = db.get_settings()
    source_dir = Path(settings.get("source_dir", ""))
    if not source_dir.exists():
        return
    for phash_file in source_dir.glob("*.phash"):
        filename = phash_file.stem + phash_file.with_suffix("").suffix
        # stem alone won't work for .mkv.phash - reconstruct the video filename
        video_name = phash_file.name[:-6]  # strip .phash
        try:
            phash = phash_file.read_text().strip()
            if phash:
                db.upsert_file(video_name)
                db.update_file(video_name, status="pending", phash=phash)
            phash_file.unlink()
        except Exception:
            pass

