def _tpdb_headers() -> dict:
    s = db.get_settings()
    return {"Accept": "application/json",
            "Authorization": f"Bearer {s.get('api_key_tpdb', '')}"}


def _extract_movie_genders(movie_data: dict) -> list[str]:
    """Extract performer genders from a TPDB movie/detail payload."""
    genders = []
    for p in (movie_data.get("performers") or []):
        if not isinstance(p, dict):
            continue
        perf = p.get("performer") or {}
        candidates = [
            ((p.get("parent") or {}).get("extras", {}) or {}).get("gender"),
            ((p.get("extra") or {}).get("gender")),
            (p.get("gender")),
            ((perf or {}).get("gender")),
            ((perf or {}).get("sex")),
        ]
        for g in candidates:
            if not g:
                continue
            g = str(g).strip().upper()
            if g and g != "UNKNOWN":
                genders.append(g)
                break
    return genders


def _classify_content(genders: list[str]) -> str:
    """Classify content from performer genders (first match wins).

    1. Any trans / non-binary / intersex-style label -> 'trans'
    2. Else: only females, exactly one -> 'solo_female'
    3. Else: more than one female, no males -> 'lesbian'
    4. Else: only male(s) -> 'gay'
    5. Else: at least one male and at least one female -> 'straight'
    6. Else -> 'unknown'
    """
    if not genders:
        return "unknown"

    females = 0
    males = 0
    trans = 0
    for g in genders:
        g = str(g).upper()
        if g in ("FEMALE", "F", "WOMAN", "CIS_FEMALE"):
            females += 1
        elif g in ("MALE", "M", "MAN", "CIS_MALE", "BOY", "GUY", "MALE_PERFORMER"):
            males += 1
        elif "TRANS" in g or g in ("NON_BINARY", "NONBINARY", "NON-BINARY", "INTERSEX", "OTHER"):
            trans += 1

    # 1. Trans / non-binary / intersex-style
    if trans > 0:
        return "trans"
    # 2. Single female, no males
    if females == 1 and males == 0:
        return "solo_female"
    # 3. Multiple females, no males
    if females > 1 and males == 0:
        return "lesbian"
    # 4. One or more males, no females
    if males > 0 and females == 0:
        return "gay"
    # 5. Mixed male and female
    if males > 0 and females > 0:
        return "straight"
    # 6. Unclassifiable (e.g. unrecognized gender strings only)
    return "unknown"


def _get_content_filter_config() -> tuple[dict[str, bool], bool, set[str]]:
    """Return content-filter settings as (cats, filter_active, allowed)."""
    s = db.get_settings()
    cats = {
        "straight":    s.get("cat_straight", "true") == "true",
        "lesbian":     s.get("cat_lesbian", "true") == "true",
        "gay":         s.get("cat_gay", "true") == "true",
        "solo_female": s.get("cat_solo_female", "true") == "true",
        "trans":       s.get("cat_trans", "true") == "true",
    }
    allowed = {k for k, v in cats.items() if v}
    filter_active = len(allowed) != 5
    return cats, filter_active, allowed


def _title_category_hint(title: str, studio: str = "") -> str:
    text = f" {(title or '').lower()} {(studio or '').lower()} "

    gay_terms = [
        " dick ", " dicks ", " bro ", " bros ", " men ", " boys ", " male ",
        " gay ", " twink ", " twinks ", " bareback ", " jock ", " dudes ",
        " me cum ", " loads ", " daddy ", " cocks ", " blowjob boys ",
        " corbin fisher ", " hot twinks ",
    ]
    lesbian_terms = [
        " lesbian ", " lesbians ", " girlsway ", " girlfriends films ",
        " girl girl ", " all girls ", " all-girl ", " stepmommy ",
    ]
    # Avoid bare "solo" — male solo titles often include it and were mislabeled as solo_female.
    solo_female_terms = [" masturbation ", " self play ", " solo girl ", " solochick "]
    female_context = (
        " her ", " she ", " milf ", " wife ", " girls ", " girl ", " babe ", " woman ",
        " women ", " mom ", " mommy ", " daughter ", " stepsis ", " step sis ",
    )
    trans_terms = [
        " trans ", " shemale ", " tgirl ", " tgirl ", " ts ",
    ]

    if any(term in text for term in trans_terms):
        return "trans"
    if any(term in text for term in gay_terms):
        return "gay"
    if any(term in text for term in lesbian_terms):
        return "lesbian"
    if any(term in text for term in solo_female_terms):
        if any(h in text for h in female_context):
            return "solo_female"
    if " solo " in text and any(h in text for h in female_context):
        return "solo_female"
    return "unknown"


_TPDB_MOVIE_DETAIL_CACHE: dict[str, tuple[float, dict]] = {}
_TPDB_MOVIE_DETAIL_CACHE_LOCK = threading.Lock()
_TPDB_MOVIE_DETAIL_CACHE_TTL = 600.0  # 10 min — long enough for paginated browsing
_TPDB_MOVIE_DETAIL_CACHE_MAX = 2000

#: TPDB scene-breakdown cache. Mirrors the IAFD breakdown cache so the
#: suggestions pre-warmer can populate it after a name search and the
#: Accept-click round-trip becomes a memory read instead of two HTTP
#: hops. Keyed by TPDB scene_id; value is ``(expires_at, [scenes])``.
_TPDB_BREAKDOWN_CACHE: dict[str, tuple[float, list[dict]]] = {}
_TPDB_BREAKDOWN_CACHE_LOCK = threading.Lock()
_TPDB_BREAKDOWN_CACHE_TTL = 1800.0  # 30 min


def _tpdb_breakdown_disk_put(scene_id: str, until: float, scenes: list) -> None:
    try:
        ser: list[dict] = []
        for s in scenes or []:
            if isinstance(s, dict):
                ser.append(dict(s, cast=list(s.get("cast") or [])))
        db.app_json_cache_put(
            f"tpdb_breakdown:{scene_id}",
            {"until": float(until), "scenes": ser},
        )
    except Exception:
        pass


def _tpdb_breakdown_disk_try(scene_id: str, now: float) -> list[dict] | None:
    try:
        snap = db.app_json_cache_get(f"tpdb_breakdown:{scene_id}")
    except Exception:
        return None
    if not isinstance(snap, dict):
        return None
    until = float(snap.get("until") or 0)
    raw = snap.get("scenes")
    if until <= now or not isinstance(raw, list):
        return None
    norm = [dict(s, cast=list(s.get("cast") or [])) for s in raw if isinstance(s, dict)]
    with _TPDB_BREAKDOWN_CACHE_LOCK:
        _TPDB_BREAKDOWN_CACHE[scene_id] = (until, norm)
    return norm


def _tpdb_scene_breakdowns(scene_id: str) -> list[dict]:
    """Find sibling scenes within the same TPDB movie, returning records
    in the same shape `_iafd_scene_breakdowns` does so the suggestions
    modal can drive a unified scene-picker UI.

    Flow:
      1. GET /scenes/{id}        → look at the response's `movie` field.
      2. If a parent movie is referenced, GET /movies/{movie_id}/scenes
         (TPDB exposes the per-movie scene list at this path, same
         pattern as /performers/{id}/scenes and /sites/{id}/scenes).
      3. Normalise into {scene_id, label, number, cast} entries.

    Returns [] when the scene has no parent movie or only one sibling
    (no point picking when there's nothing to pick from). Network /
    JSON failures are swallowed and treated as "no breakdown" so the
    accept flow can fall through to the normal one-click path.
    """
    if not scene_id:
        return []
    now = time.time()
    with _TPDB_BREAKDOWN_CACHE_LOCK:
        hit = _TPDB_BREAKDOWN_CACHE.get(scene_id)
        if hit and hit[0] > now:
            return [dict(s, cast=list(s.get("cast") or [])) for s in hit[1]]
    loaded = _tpdb_breakdown_disk_try(scene_id, now)
    if loaded is not None:
        return [dict(s, cast=list(s.get("cast") or [])) for s in loaded]
    headers = _tpdb_headers()
    movie_id = ""
    try:
        resp = requests.get(
            f"https://api.theporndb.net/scenes/{scene_id}",
            headers=headers, timeout=15,
        )
        if resp.status_code == 200:
            data = (resp.json() or {}).get("data") or {}
            mv = data.get("movie") or {}
            movie_id = str(mv.get("id") or "").strip()
    except Exception:
        # Negative-cache the failure so the pre-warmer doesn't keep
        # hammering on a flaky scene id while the user is browsing.
        with _TPDB_BREAKDOWN_CACHE_LOCK:
            _TPDB_BREAKDOWN_CACHE[scene_id] = (now + 60.0, [])
        _tpdb_breakdown_disk_put(scene_id, now + 60.0, [])
        return []
    if not movie_id:
        with _TPDB_BREAKDOWN_CACHE_LOCK:
            _TPDB_BREAKDOWN_CACHE[scene_id] = (now + _TPDB_BREAKDOWN_CACHE_TTL, [])
        _tpdb_breakdown_disk_put(scene_id, now + _TPDB_BREAKDOWN_CACHE_TTL, [])
        return []
    try:
        resp = requests.get(
            f"https://api.theporndb.net/movies/{movie_id}/scenes",
            params={"page": 1, "per_page": 50},
            headers=headers, timeout=15,
        )
        if resp.status_code != 200:
            return []
        parsed = _tpdb_scenes_list_from_response(resp.json() or {})
    except Exception:
        return []
    if not parsed or len(parsed) < 2:
        return []
    out: list[dict] = []
    for i, raw in enumerate(parsed):
        if not isinstance(raw, dict):
            continue
        sid = str(raw.get("_id") or raw.get("id") or "").strip()
        if not sid:
            continue
        title = (raw.get("title") or "").strip()
        idx_raw = raw.get("index") or raw.get("number") or raw.get("scene_number")
        try:
            number = int(idx_raw) if idx_raw is not None else (i + 1)
        except (TypeError, ValueError):
            number = i + 1
        cast: list[str] = []
        for p in (raw.get("performers") or []):
            if not isinstance(p, dict):
                continue
            inner = p.get("performer") if isinstance(p.get("performer"), dict) else None
            n = ((inner or p).get("name") or "").strip()
            if n and n not in cast:
                cast.append(n)
        out.append({
            "scene_id": sid,
            "number": number,
            "label": title or f"Scene {number}",
            "cast": cast,
        })
    exp = time.time() + _TPDB_BREAKDOWN_CACHE_TTL
    norm = [dict(s, cast=list(s.get("cast") or [])) for s in out]
    with _TPDB_BREAKDOWN_CACHE_LOCK:
        _TPDB_BREAKDOWN_CACHE[scene_id] = (exp, norm)
    _tpdb_breakdown_disk_put(scene_id, exp, norm)
    return norm


def _fetch_tpdb_movie_detail(movie_id: str) -> dict:
    if not movie_id:
        return {}
    now = time.time()
    ck = f"tpdb_movie_detail:{movie_id}"
    with _TPDB_MOVIE_DETAIL_CACHE_LOCK:
        hit = _TPDB_MOVIE_DETAIL_CACHE.get(movie_id)
        if hit and (now - hit[0]) < _TPDB_MOVIE_DETAIL_CACHE_TTL:
            return hit[1]
    try:
        snap = db.app_json_cache_get(ck)
        if isinstance(snap, dict):
            t0 = float(snap.get("t") or 0)
            pdata = snap.get("data")
            if isinstance(pdata, dict) and pdata and (now - t0) < _TPDB_MOVIE_DETAIL_CACHE_TTL:
                with _TPDB_MOVIE_DETAIL_CACHE_LOCK:
                    if len(_TPDB_MOVIE_DETAIL_CACHE) > _TPDB_MOVIE_DETAIL_CACHE_MAX:
                        cutoff = sorted(_TPDB_MOVIE_DETAIL_CACHE.items(), key=lambda kv: kv[1][0])
                        for k, _ in cutoff[: _TPDB_MOVIE_DETAIL_CACHE_MAX // 4]:
                            _TPDB_MOVIE_DETAIL_CACHE.pop(k, None)
                    _TPDB_MOVIE_DETAIL_CACHE[movie_id] = (t0, pdata)
                return pdata
    except Exception:
        pass
    try:
        resp = requests.get(f"https://api.theporndb.net/movies/{movie_id}", headers=_tpdb_headers(), timeout=15)
        if resp.status_code != 200:
            return {}
        data = resp.json().get("data") or {}
    except Exception:
        return {}
    with _TPDB_MOVIE_DETAIL_CACHE_LOCK:
        if len(_TPDB_MOVIE_DETAIL_CACHE) > _TPDB_MOVIE_DETAIL_CACHE_MAX:
            # Coarse eviction: drop the oldest ~25%.
            cutoff = sorted(_TPDB_MOVIE_DETAIL_CACHE.items(), key=lambda kv: kv[1][0])
            for k, _ in cutoff[: _TPDB_MOVIE_DETAIL_CACHE_MAX // 4]:
                _TPDB_MOVIE_DETAIL_CACHE.pop(k, None)
        _TPDB_MOVIE_DETAIL_CACHE[movie_id] = (now, data)
    if data:
        try:
            db.app_json_cache_put(ck, {"t": now, "data": data})
        except Exception:
            pass
    return data


def _extract_movie_genders_with_fallback(movie_data: dict) -> tuple[list[str], str, str]:
    """Return (genders, source, category) for MOVIES.
    Try the list payload first (no extra API call). Only fall back to a
    full movie-detail fetch when the payload genders are missing or
    unclassifiable. Title/studio heuristic last; then fail closed.
    source is one of payload/detail/title_heuristic/unknown."""
    # 1) Cheapest path: classify from the list-payload performers. The
    #    /movies list endpoint includes performer.gender for the vast
    #    majority of titles, so this short-circuits the slow detail call.
    genders = _extract_movie_genders(movie_data)
    category = _classify_content(genders)
    if genders and category != "unknown":
        return genders, "payload", category

    # 2) Payload was unusable — fall back to the full detail.
    movie_id = str(movie_data.get("_id") or movie_data.get("id") or "")
    if movie_id:
        detail = _fetch_tpdb_movie_detail(movie_id)
        d_genders = _extract_movie_genders(detail)
        d_category = _classify_content(d_genders)
        if d_genders and d_category != "unknown":
            return d_genders, "detail", d_category

    # 3) Title/studio heuristic.
    category = _title_category_hint(
        movie_data.get("title") or "",
        ((movie_data.get("site") or {}).get("name") or movie_data.get("studio") or ""),
    )
    if category != "unknown":
        return [], "title_heuristic", category

    return [], "unknown", "unknown"


def _passes_content_filter(genders, allowed: set = None, category: str | None = None) -> bool:
    """Check if content passes the category-based content filter.
    If no usable category data and filtering is active, exclude the content."""
    if isinstance(genders, set):
        genders = list(genders)
    if allowed is None:
        _, _, allowed = _get_content_filter_config()
        if len(allowed) == 5:
            return True

    if category is None:
        category = _classify_content(genders or [])

    if not category or category == "unknown":
        return False
    return category in allowed


#: Memoised tag-blacklist set, keyed by the raw setting string. Same
#: hot-path optimisation as the title blacklist — feed rendering used
#: to re-parse the JSON for every scene; now it parses once per save.
_TAG_BLACKLIST_CACHE: tuple[str, dict[str, frozenset[str]]] = ("", {
    "tpdb": frozenset(), "stashdb": frozenset(),
    "fansdb": frozenset(), "javstash": frozenset(), "any": frozenset(),
})


def _tag_blacklist_by_source() -> dict[str, frozenset[str]]:
    """Lowercase tag names from ``tag_blacklist``, indexed per source.

    Returns ``{"tpdb": {...}, "stashdb": {...}, "fansdb": {...},
    "javstash": {...}, "any": {union}}``. The ``any`` key is the union
    used as a conservative fallback by callers that don't know the
    scene's source.

    Accepts three storage formats:
    - JSON array of ``{"name", "tpdb_id", "stashdb_id", "fansdb_id",
      "javstash_id"}`` (new per-source picker format)
    - JSON array of ``{"id","slug","name"}`` (legacy single-list picker
      format) — names go into the ``any`` union for all sources
    - Comma-separated ``"Watersports, Fisting"`` (oldest format) —
      same: union, no per-source split
    """
    global _TAG_BLACKLIST_CACHE
    raw = (db.get_settings().get("tag_blacklist") or "").strip()
    cache_key, cached = _TAG_BLACKLIST_CACHE
    if cache_key == raw:
        return cached
    empty = frozenset()
    out: dict[str, set[str]] = {"tpdb": set(), "stashdb": set(), "fansdb": set(), "javstash": set(), "any": set()}
    if not raw:
        result = {k: frozenset(v) for k, v in out.items()}
        _TAG_BLACKLIST_CACHE = (raw, result)
        return result
    if raw.startswith("["):
        try:
            parsed = json.loads(raw)
            if isinstance(parsed, list):
                for t in parsed:
                    if not isinstance(t, dict):
                        continue
                    name = str(t.get("name") or "").strip().lower()
                    if not name:
                        continue
                    out["any"].add(name)
                    flagged_any_source = False
                    if str(t.get("tpdb_id") or "").strip():
                        out["tpdb"].add(name)
                        flagged_any_source = True
                    if str(t.get("stashdb_id") or t.get("stash_id") or "").strip():
                        out["stashdb"].add(name)
                        flagged_any_source = True
                    if str(t.get("fansdb_id") or "").strip():
                        out["fansdb"].add(name)
                        flagged_any_source = True
                    if str(t.get("javstash_id") or "").strip():
                        out["javstash"].add(name)
                        flagged_any_source = True
                    # Legacy entries had no per-source ids — apply
                    # across every source so old blacklists keep working.
                    if not flagged_any_source:
                        out["tpdb"].add(name)
                        out["stashdb"].add(name)
                        out["fansdb"].add(name)
                        out["javstash"].add(name)
                result = {k: frozenset(v) for k, v in out.items()}
                _TAG_BLACKLIST_CACHE = (raw, result)
                return result
        except Exception:
            pass
    legacy = frozenset(x.strip().lower() for x in raw.split(",") if x.strip())
    result = {
        "tpdb":     legacy,
        "stashdb":  legacy,
        "fansdb":   legacy,
        "javstash": legacy,
        "any":      legacy,
    }
    _TAG_BLACKLIST_CACHE = (raw, result)
    return result


def _tag_blacklist_normalized() -> frozenset[str]:
    """Legacy union accessor — kept for callers that don't know the source."""
    return _tag_blacklist_by_source()["any"]


#: Memoised title-blacklist set, keyed by the raw setting string so it
#: invalidates the instant the user adds or removes an entry. Hot-path
#: optimisation: ``_passes_title_filter`` runs per-scene during feed
#: rendering, and reading + JSON-parsing the setting on every call
#: meant 60+ DB reads per feed paint. Now it's one DB read per save.
_TITLE_BLACKLIST_CACHE: tuple[str, frozenset[str]] = ("", frozenset())


def _title_blacklist_normalized() -> frozenset[str]:
    """Per-scene title blacklist as a lowercase frozenset.

    Stored at ``scene_title_blacklist`` as a JSON array of either:
      - ``{"title": "...", "added_at": "..."}`` objects, or
      - bare strings (legacy entries).

    Match is exact case-insensitive on the lowercased trimmed title —
    O(1) per-scene lookup so feed filtering pays nothing per blocked
    entry beyond the membership test."""
    global _TITLE_BLACKLIST_CACHE
    raw = (db.get_settings().get("scene_title_blacklist") or "").strip()
    cache_key, cached = _TITLE_BLACKLIST_CACHE
    if cache_key == raw:
        return cached
    if not raw or raw in ("[]", "null"):
        _TITLE_BLACKLIST_CACHE = (raw, frozenset())
        return frozenset()
    out: set[str] = set()
    try:
        parsed = json.loads(raw)
    except Exception:
        _TITLE_BLACKLIST_CACHE = (raw, frozenset())
        return frozenset()
    if not isinstance(parsed, list):
        _TITLE_BLACKLIST_CACHE = (raw, frozenset())
        return frozenset()
    for entry in parsed:
        if isinstance(entry, dict):
            t = str(entry.get("title") or "").strip().lower()
        elif isinstance(entry, str):
            t = entry.strip().lower()
        else:
            continue
        if t:
            out.add(t)
    frozen = frozenset(out)
    _TITLE_BLACKLIST_CACHE = (raw, frozen)
    return frozen


def _passes_title_filter(scene: dict) -> bool:
    """True if the scene's title is NOT in the per-scene title blacklist."""
    bl = _title_blacklist_normalized()
    if not bl:
        return True
    title = str(scene.get("title") or "").strip().lower()
    if not title:
        return True
    return title not in bl


#: Cache the RSS keyword blacklist alongside the title blacklist — same
#: read-on-save invalidation pattern. Settings read happens once per save
#: rather than once per scene render.
_RSS_KEYWORD_BLACKLIST_CACHE: tuple[str, tuple[str, ...]] = ("", tuple())


def _rss_keyword_blacklist_terms() -> tuple[str, ...]:
    """Lowercase substring terms from the user's RSS keyword blacklist.
    The setting is a comma-separated string; an empty list disables
    the filter."""
    global _RSS_KEYWORD_BLACKLIST_CACHE
    raw = (db.get_settings().get("rss_keyword_blacklist") or "").strip()
    cache_key, cached = _RSS_KEYWORD_BLACKLIST_CACHE
    if cache_key == raw:
        return cached
    terms = tuple(t.strip().lower() for t in raw.split(",") if t.strip())
    _RSS_KEYWORD_BLACKLIST_CACHE = (raw, terms)
    return terms


def _passes_raw_scene_runtime_filter(scene: dict) -> bool:
    """Same drops as ``_passes_feed_runtime_filter`` but takes the raw
    source-DB scene dict (TPDB / stash-box queryScenes payload) rather
    than the post-build feed card. Reads ``release_date`` first (stash-
    box) then ``date`` (TPDB), and the source DB's ``title`` field.
    Used at every inline card-builder call site so future-dated +
    blacklisted scenes are skipped before any expensive image / cast
    extraction runs."""
    if not isinstance(scene, dict):
        return True
    from datetime import date as _date
    rd = (scene.get("release_date") or scene.get("date") or "")
    if isinstance(rd, str):
        rd = rd[:10]
    else:
        rd = ""
    if rd:
        try:
            if rd > _date.today().isoformat():
                return False
        except Exception:
            pass
    terms = _rss_keyword_blacklist_terms()
    if terms:
        title_l = str(scene.get("title") or "").lower()
        if any(term in title_l for term in terms):
            return False
    return True


def _passes_feed_runtime_filter(card: dict) -> bool:
    """Last-mile filter applied to every feed card before it ships to
    the client — covers two concerns the per-source filters above don't:

      1. Future-dated releases: JAVStash + TPDB both publish metadata
         weeks ahead of the actual release. The earlier _stashbox card
         builder filters JAVStash at fetch time, but the SQLite display
         pool persists across days — a scene cached as "tomorrow" stays
         in the pool the day after, even though it's still future-dated.
         Re-apply the filter on every serve so the pool stays clean.
      2. RSS keyword blacklist: the user-configured substring list (e.g.
         ``VR, gay, trans``) historically only applied to RSS feeds and
         Prowlarr search results. Apply it to /scenes feeds + Latest
         Movies too so the user's exclusion list is a single source of
         truth.

    Returns True if the card should be kept."""
    from datetime import date as _date
    try:
        today_iso = _date.today().isoformat()
    except Exception:
        today_iso = ""
    rd = str(card.get("date") or card.get("release_date") or "").strip()[:10]
    if rd and today_iso and rd > today_iso:
        return False
    terms = _rss_keyword_blacklist_terms()
    if terms:
        title_l = str(card.get("title") or "").lower()
        if any(term in title_l for term in terms):
            return False
    return True


def _filter_feed_cards(cards: list) -> list:
    """Apply ``_passes_feed_runtime_filter`` to a list of cards."""
    if not isinstance(cards, list):
        return cards
    return [c for c in cards if isinstance(c, dict) and _passes_feed_runtime_filter(c)]


def _tag_names_from_tpdb_entity(entity: dict) -> set[str]:
    """Lowercase tag names from a TPDB REST scene/movie payload."""
    names: set[str] = set()
    if not isinstance(entity, dict):
        return names
    raw = entity.get("tags")
    if not isinstance(raw, list):
        return names
    for t in raw:
        if isinstance(t, str) and t.strip():
            names.add(t.strip().lower())
        elif isinstance(t, dict):
            n = t.get("name") or t.get("label")
            if not n and isinstance(t.get("tag"), dict):
                n = t["tag"].get("name")
            if n and str(n).strip():
                names.add(str(n).strip().lower())
    return names


def _passes_tag_filter(entity: dict, source: str | None = None) -> bool:
    """Exclude if any item tag exactly matches a blacklisted tag (case-insensitive).

    If ``source`` is one of ``tpdb`` / ``stashdb`` / ``fansdb`` /
    ``javstash``, only that source's blacklist is checked. Otherwise
    the union of all source lists is used (legacy callers).

    If the blacklist for the active source is empty, always pass. If
    the API payload has no tags, pass (gender/category filters still
    apply)."""
    by_src = _tag_blacklist_by_source()
    bl = by_src.get((source or "").lower()) if source else by_src["any"]
    if not bl:
        return True
    item_tags = _tag_names_from_tpdb_entity(entity)
    if not item_tags:
        return True
    return not (item_tags & bl)


def _scene_passes_settings_filters(scene: dict) -> bool:
    """Apply Settings → Content Filters to a raw source-DB scene dict.

    Mirrors ``_tpdb_scene_payload_to_feed_card`` / ``_stashbox_scene_to_feed_card``:
    category toggles (with title/studio heuristic when genders are unknown)
    plus per-source tag blacklist."""
    if not isinstance(scene, dict):
        return False
    _, filter_active, _ = _get_content_filter_config()
    if filter_active:
        genders = _extract_movie_genders(scene)
        category = _classify_content(genders)
        if category == "unknown":
            studio = scene.get("studio") or {}
            studio_name = studio.get("name") if isinstance(studio, dict) else (studio or "")
            category = _title_category_hint(scene.get("title") or "", studio_name or "")
        if not _passes_content_filter(genders, category=category):
            return False
    if not _passes_title_filter(scene):
        return False
    if not _passes_raw_scene_runtime_filter(scene):
        return False
    src = (scene.get("_source") or "").strip().lower()
    src_key = {"stashdb": "stashdb", "tpdb": "tpdb", "fansdb": "fansdb", "javstash": "javstash"}.get(src)
    return _passes_tag_filter(scene, src_key)


def _suggestion_candidate_passes_filters(candidate: dict) -> bool:
    """Filter one ``queue_suggestions`` row using stored payload (or flat fields)."""
    if not isinstance(candidate, dict):
        return False
    scene = candidate.get("payload")
    if not isinstance(scene, dict) or not scene:
        scene = {
            "id":           candidate.get("source_id"),
            "title":        candidate.get("title") or "",
            "release_date": candidate.get("date") or "",
            "studio":       {"name": candidate.get("studio") or ""},
            "performers":   [
                {"performer": {"name": n.strip()}}
                for n in (candidate.get("performers") or "").split(",")
                if n and n.strip()
            ],
            "_source":      candidate.get("source_db") or "",
        }
    return _scene_passes_settings_filters(scene)


def _filter_suggestion_file_list(files: list[dict]) -> list[dict]:
    """Drop candidates (and files with none left) that fail content filters."""
    out: list[dict] = []
    for f in files or []:
        kept = [c for c in (f.get("candidates") or []) if _suggestion_candidate_passes_filters(c)]
        if not kept:
            continue
        row = dict(f)
        row["candidates"] = kept
        out.append(row)
    return out


def _content_filters_fingerprint() -> tuple:
    """Invalidate feed/movie caches when category toggles, tag blacklist,
    per-scene title blacklist, or the RSS keyword blacklist change."""
    s = db.get_settings()
    cats = tuple(
        s.get(k, "true") == "true"
        for k in ("cat_straight", "cat_lesbian", "cat_gay", "cat_solo_female", "cat_trans")
    )
    tag_bl = (s.get("tag_blacklist") or "").strip()
    title_bl = (s.get("scene_title_blacklist") or "").strip()
    rss_bl = (s.get("rss_keyword_blacklist") or "").strip()
    return (cats, tag_bl, title_bl, rss_bl)


def _movie_card_from_tpdb(m: dict) -> dict:
    poster = m.get("image") or m.get("poster") or m.get("poster_image")
    if not poster:
        posters_obj = m.get("posters") or {}
        if isinstance(posters_obj, dict):
            poster = posters_obj.get("full") or posters_obj.get("large")
    slug = m.get("slug") or str(m.get("_id", ""))
    # Pull performer names from the list payload so the feed card can show
    # hover headshots via /api/performers/headshots-by-name without needing
    # a follow-up detail fetch per card. Dedupe on a case-insensitive key
    # so TPDB records with the same performer listed twice (occasionally
    # happens on older entries) don't surface a duplicate headshot tile.
    perf_names: list[str] = []
    seen_perfs: set[str] = set()
    def _add_perf(n: str) -> None:
        s = (n or "").strip()
        if not s:
            return
        key = s.lower()
        if key in seen_perfs:
            return
        seen_perfs.add(key)
        perf_names.append(s)
    for p in (m.get("performers") or []):
        if isinstance(p, dict):
            perf = p.get("performer") or p
            _add_perf(perf.get("name") or perf.get("full_name") or "")
        elif isinstance(p, str):
            _add_perf(p)
    return {
        "id": str(m.get("_id") or m.get("id") or ""),
        "slug": slug,
        "title": m.get("title") or "",
        "date": m.get("date") or "",
        "studio": (m.get("site") or {}).get("name") or "",
        "poster": poster,
        "performer": ", ".join(perf_names),
        # Same `[{name, gender}]` shape as scenes — lets the front-end
        # render gender-coded performer chips on movie cards without a
        # follow-up detail fetch. Reuses `_scene_display_performers`
        # since TPDB movie payloads use the same `performers` shape.
        "display_performers": _scene_display_performers(m),
        "link": f"https://theporndb.net/movies/{slug}",
    }


def _collect_filtered_tpdb_movies(base_params: dict, page: int, page_size: int = 20) -> dict:
    """Collect filtered TPDB movies, applying filter before local paging.

    Per-movie classification is parallelised across a thread pool — the
    payload fast-path costs nothing, and any movies that need a full
    detail fetch run concurrently rather than serially.

    Sort note: we ask TPDB for `order=date direction=desc` but the
    server's behaviour on `/movies` has been unreliable — empirically
    the listing has returned 2011 backfills mixed into the top of the
    grid even with that param set. So we ALSO sort + age-floor on the
    client. The age floor stops the walk from chasing older pages
    indefinitely when the user's content filter rejects most recent
    titles; the post-walk sort guarantees strictly-newest-first
    ordering regardless of TPDB's per-page interleaving.
    """
    from concurrent.futures import ThreadPoolExecutor

    cats, filter_active, allowed = _get_content_filter_config()
    start = max(0, (int(page) - 1) * page_size)
    end = start + page_size
    upstream_page = 1
    accepted = []
    total_before_filter = 0
    excluded_unknown = 0
    excluded_by_category = 0
    excluded_by_tags = 0
    excluded_by_age = 0
    classification_sources = {"payload": 0, "detail": 0, "title_heuristic": 0, "unknown": 0}
    total_pages_hint = 1

    # Age floor — drop anything older than this so a strict content
    # filter can't drag 2011-era backfills into the served page. Two
    # years is wide enough that any genuinely active studio still
    # surfaces; older titles fall off. Override with no floor by
    # passing `_no_age_floor` in base_params (used by /movies search,
    # not the latest-feed endpoint).
    no_floor = bool(base_params.pop("_no_age_floor", False))
    cutoff = (
        None
        if no_floor
        else (datetime.now(timezone.utc) - timedelta(days=730)).strftime("%Y-%m-%d")
    )

    while True:
        params = dict(base_params)
        params["page"] = upstream_page
        params["limit"] = 50
        params.setdefault("order", "date")
        params.setdefault("direction", "desc")
        resp = requests.get("https://api.theporndb.net/movies", params=params, headers=_tpdb_headers(), timeout=15)
        if resp.status_code != 200:
            raise RuntimeError(f"TPDB returned {resp.status_code}")

        payload = resp.json() or {}
        raw_movies = payload.get("data") or []
        meta = payload.get("meta") or {}
        total_pages_hint = meta.get("last_page", total_pages_hint)
        total_before_filter += len(raw_movies)
        if not raw_movies:
            break

        # Pre-classify in parallel so any movies needing the slow
        # detail-fetch fallback overlap on the network.
        if filter_active:
            with ThreadPoolExecutor(max_workers=12) as pool:
                classifications = list(pool.map(_extract_movie_genders_with_fallback, raw_movies))
        else:
            classifications = [(None, "payload", "unknown")] * len(raw_movies)

        for m, (genders, source, category) in zip(raw_movies, classifications):
            if filter_active:
                classification_sources[source] = classification_sources.get(source, 0) + 1
                if category == "unknown":
                    excluded_unknown += 1
                    continue
                if not _passes_content_filter(genders, allowed, category):
                    excluded_by_category += 1
                    continue
            if not _passes_tag_filter(m, "tpdb"):
                excluded_by_tags += 1
                continue
            if not _passes_title_filter(m):
                excluded_by_tags += 1
                continue
            # RSS keyword blacklist (substring match on title) — same
            # exclusion the RSS feeds + Prowlarr search honour, applied
            # to Latest Movies too so the user's blacklist works
            # everywhere instead of just on RSS.
            bl_terms = _rss_keyword_blacklist_terms()
            if bl_terms:
                title_l = str(m.get("title") or "").lower()
                if any(term in title_l for term in bl_terms):
                    excluded_by_tags += 1
                    continue
            mdate_full = (m.get("date") or "")[:10]
            # Future-dated movies: TPDB sometimes lists releases days /
            # weeks ahead. Drop them so the "Latest" grid shows only
            # things the user could actually watch today.
            if mdate_full:
                try:
                    if mdate_full > datetime.now(timezone.utc).date().isoformat():
                        excluded_by_age += 1
                        continue
                except Exception:
                    pass
            # Age floor — drop pre-cutoff releases so an aggressive
            # content filter can't pull 2011 backfills into the grid.
            if cutoff is not None:
                mdate = mdate_full
                if mdate and mdate < cutoff:
                    excluded_by_age += 1
                    continue
            accepted.append(_movie_card_from_tpdb(m))

        if upstream_page >= int(meta.get("last_page") or upstream_page):
            break
        # Bound the walk so a strict filter can't burn the whole TPDB
        # archive looking for matches. Once we have ~2x the requested
        # page worth of accepted matches, stop — the post-walk sort
        # below picks the most-recent slice anyway.
        if len(accepted) >= max(end * 2, 60):
            break
        # Safety cap: never walk more than 20 TPDB pages even if filters
        # reject everything. Beyond that the results would be far too
        # old to belong in a "Latest Movies" view regardless.
        if upstream_page >= 20:
            break
        upstream_page += 1

    # Post-walk: sort strictly by release date desc so client never
    # sees an interleaved mix. Movies without a date sink (they'd be
    # filtered out by the cutoff above anyway unless the floor is off).
    accepted.sort(key=lambda c: (c.get("date") or ""), reverse=True)
    page_results = accepted[start:end]
    total_after_filter = len(accepted)
    computed_total_pages = max(1, ((total_after_filter - 1) // page_size) + 1) if total_after_filter else 1
    return {
        "results": page_results,
        "page": int(page),
        "total_pages": computed_total_pages,
        "total": total_after_filter,
        "_debug": {
            "filter_active": filter_active,
            "cats": cats,
            "total_before_filter": total_before_filter,
            "total_after_filter": total_after_filter,
            "excluded_unknown": excluded_unknown,
            "excluded_by_category": excluded_by_category,
            "excluded_by_tags": excluded_by_tags,
            "excluded_by_age": excluded_by_age,
            "classification_sources": classification_sources,
            "upstream_pages_scanned": upstream_page,
            "upstream_total_pages_hint": total_pages_hint,
        },
    }


ALLOWED_GENDER_BUCKETS = frozenset({"female", "male", "trans", "other"})


def normalize_performer_gender_to_bucket(g: str | None) -> str | None:
    """Map API gender strings to female | male | trans | other."""
    if not g or not str(g).strip():
        return None
    s = str(g).strip().upper().replace("-", "_").replace(" ", "_")
    if s in ("FEMALE", "F", "WOMAN", "CIS_FEMALE", "FEMALE_PERFORMER"):
        return "female"
    if s in ("MALE", "M", "MAN", "CIS_MALE", "MALE_PERFORMER", "BOY"):
        return "male"
    if "TRANS" in s or s in ("TRANSGENDER_FEMALE", "TRANSGENDER_MALE", "TRANSGENDER"):
        return "trans"
    if s in ("NON_BINARY", "NONBINARY", "INTERSEX", "OTHER", "NON_BINARY_GENDER"):
        return "other"
    return None


def gender_allowlist_from_json(s: str | None) -> frozenset[str] | None:
    """Empty list / missing = no filter. Non-empty JSON list → allow only those buckets."""
    if not s or not str(s).strip():
        return None
    try:
        arr = json.loads(s)
    except json.JSONDecodeError:
        return None
    if not isinstance(arr, list) or len(arr) == 0:
        return None
    out = {x for x in arr if x in ALLOWED_GENDER_BUCKETS}
    return frozenset(out) if out else None


def gender_allowlist_from_list(lst: list | None) -> frozenset[str] | None:
    if not lst or not isinstance(lst, list) or len(lst) == 0:
        return None
    out = {x for x in lst if x in ALLOWED_GENDER_BUCKETS}
    return frozenset(out) if out else None


def _tpdb_raw_gender_from_search_hit(p: dict) -> str | None:
    v = p.get("gender")
    if v:
        return str(v)
    ex = p.get("extra")
    if isinstance(ex, dict) and ex.get("gender"):
        return str(ex["gender"])
    extras = p.get("extras") or {}
    if isinstance(extras, dict) and extras.get("gender"):
        return str(extras["gender"])
    return None


def _tpdb_detail_gender_bucket(tpdb_id: str) -> str | None:
    """Authoritative gender from TPDB performer detail (search may omit extras)."""
    if not tpdb_id or not str(tpdb_id).strip():
        return None
    try:
        resp = requests.get(
            TPDB_PERFORMER_DETAIL.format(id=str(tpdb_id).strip()),
            headers=_tpdb_headers(),
            timeout=12,
        )
        if resp.status_code != 200:
            return None
        data = resp.json().get("data")
        if not data or not isinstance(data, dict):
            return None
        raw = _tpdb_raw_gender_from_search_hit(data)
        return normalize_performer_gender_to_bucket(raw)
    except Exception:
        return None


def _stashdb_find_performer_gender_bucket(sid: str) -> str | None:
    """Authoritative gender from StashDB findPerformer (search may omit or differ)."""
    settings = db.get_settings()
    key = (settings.get("api_key_stashdb") or "").strip()
    if not key or not sid or not str(sid).strip():
        return None
    try:
        gql = """
        query($id: ID!) {
          findPerformer(id: $id) {
            gender
          }
        }
        """
        resp = requests.post(
            "https://stashdb.org/graphql",
            json={"query": gql, "variables": {"id": str(sid).strip()}},
            headers={"ApiKey": key, "Content-Type": "application/json"},
            timeout=10,
        )
        if resp.status_code != 200:
            return None
        data = resp.json().get("data") or {}
        p = data.get("findPerformer") or {}
        raw_g = p.get("gender")
        raw_g = str(raw_g) if raw_g is not None else None
        return normalize_performer_gender_to_bucket(raw_g)
    except Exception:
        return None


def _fansdb_find_performer_gender_bucket(fid: str) -> str | None:
    if not fid or not str(fid).strip():
        return None
    try:
        data = _fansdb_gql(
            "query($id: ID!) { findPerformer(id: $id) { gender } }",
            {"id": str(fid).strip()},
        )
        p = data.get("findPerformer") or {}
        raw_g = p.get("gender")
        raw_g = str(raw_g) if raw_g is not None else None
        return normalize_performer_gender_to_bucket(raw_g)
    except Exception:
        return None


def _enforce_favourite_performer_slots_by_detail_gender(
    g_allow: frozenset[str],
    mt_id,
    mt_n,
    ms_id,
    ms_n,
    mf_id,
    mf_n,
):
    """Drop any link whose findPerformer / TPDB detail gender is not in the allowlist.
    Skips Stash/Fans verification when no API key (cannot call findPerformer)."""
    settings = db.get_settings()
    if mt_id:
        b = _tpdb_detail_gender_bucket(str(mt_id).strip())
        if b is None or b not in g_allow:
            mt_id = None
            mt_n = ""
    if ms_id and (settings.get("api_key_stashdb") or "").strip():
        b = _stashdb_find_performer_gender_bucket(str(ms_id).strip())
        if b is None or b not in g_allow:
            ms_id = None
            ms_n = ""
    if mf_id and (settings.get("api_key_fansdb") or "").strip():
        b = _fansdb_find_performer_gender_bucket(str(mf_id).strip())
        if b is None or b not in g_allow:
            mf_id = None
            mf_n = ""
    return mt_id, mt_n, ms_id, ms_n, mf_id, mf_n


def _apply_gender_allowlist(results: list[dict], allow: frozenset[str] | None) -> list[dict]:
    """When allowlist is set, keep only rows whose gender_bucket is in the set (unknown excluded)."""
    if not allow or len(allow) == 0:
        return results
    out: list[dict] = []
    for r in results:
        bucket = r.get("gender_bucket")
        if bucket is not None and bucket in allow:
            out.append(r)
    return out


def _fansdb_gql(query: str, variables: dict) -> dict:
    """FansDB is stash-box; use ApiKey like StashDB (Bearer alone is rejected)."""
    key = (db.get_settings().get("api_key_fansdb") or "").strip()
    if not key:
        return {}
    resp = requests.post(
        FANSDB_ENDPOINT,
        json={"query": query, "variables": variables},
        headers={"ApiKey": key, "Content-Type": "application/json"},
        timeout=15,
    )
    resp.raise_for_status()
    body = resp.json()
    if body.get("errors") and not body.get("data"):
        raise RuntimeError(str(body["errors"]))
    return body.get("data") or {}


def _performer_search_match_score(hit: dict, query: str) -> int:
    """Rank performer search hits: exact name > exact alias > token overlap > weak."""
    want = normalise(query or "")
    if not want:
        return 0
    name = normalise(hit.get("name") or "")
    q_toks = [t for t in want.split() if t]
    if name == want:
        return 100
    for alias in hit.get("aliases") or []:
        if normalise(str(alias)) == want:
            return 95
    if want in name:
        return 88
    if q_toks and all(t in name for t in q_toks):
        name_toks = [t for t in name.split() if t]
        if sorted(q_toks) == sorted(name_toks) and name != want:
            return 72
        return 65
    for alias in hit.get("aliases") or []:
        an = normalise(str(alias))
        if q_toks and all(t in an for t in q_toks):
            return 78
    return 10


def _hydrate_tpdb_search_aliases(results: list[dict], *, limit: int = 12) -> None:
    """TPDB list search often omits aliases; pull from performer detail for display."""
    from concurrent.futures import ThreadPoolExecutor, as_completed

    targets = [
        (i, h)
        for i, h in enumerate(results)
        if h.get("source") == "TPDB" and not (h.get("aliases") or [])
    ][:limit]
    if not targets:
        return

    def _one(pair: tuple[int, dict]) -> tuple[int, list[str]]:
        _i, h = pair
        tid = str(h.get("id") or "").strip()
        if not tid:
            return _i, []
        try:
            detail = fetch_performer_detail("TPDB", tid)
            if detail:
                return _i, _normalise_performer_aliases(
                    detail.get("aliases"), detail.get("name")
                )
        except Exception:
            pass
        return _i, []

    with ThreadPoolExecutor(max_workers=4) as pool:
        futs = [pool.submit(_one, t) for t in targets]
        for fut in as_completed(futs):
            try:
                idx, aliases = fut.result()
                if aliases:
                    results[idx]["aliases"] = aliases
            except Exception:
                pass


def _normalise_performer_aliases(raw, primary_name: str | None = None) -> list[str]:
    """Flatten a heterogenous aliases field into a deduped list of strings.

    Accepts: list of strings, list of dicts (``{"name": ...}``), a single
    comma-separated string, or None. Drops empties + duplicates
    case-insensitively, and drops the primary name so it isn't echoed
    as one of its own aliases.
    """
    if not raw:
        return []
    out: list[str] = []
    seen: set[str] = set()
    primary_key = (primary_name or "").strip().lower()
    candidates: list[str] = []
    if isinstance(raw, str):
        candidates = [x.strip() for x in raw.split(",")]
    elif isinstance(raw, list):
        for a in raw:
            if isinstance(a, str):
                candidates.append(a.strip())
            elif isinstance(a, dict):
                n = a.get("name") or a.get("alias") or ""
                if isinstance(n, str):
                    candidates.append(n.strip())
    for c in candidates:
        if not c:
            continue
        key = c.lower()
        if key == primary_key or key in seen:
            continue
        seen.add(key)
        out.append(c)
    return out


def search_performers(
    name: str,
    *,
    gender_allowlist: frozenset[str] | None = None,
    strict_name_match: bool = False,
) -> list[dict]:
    """Search TPDB + StashDB + FansDB. If strict_name_match, fetch a wider result set then keep
    only rows whose normalised name equals the query (no fuzzy/single-hit guessing)."""
    results = []
    settings = db.get_settings()
    # TPDB shallow search often omits gender; fuzzy mode used to keep only [:5],
    # which hid valid matches behind slightly different queries vs /discover.
    tpdb_take = 40 if strict_name_match else 25
    stash_limit = 40 if strict_name_match else 5
    fans_limit = 40 if strict_name_match else 10
    want_tpdb_gender_hydrate = bool(gender_allowlist and len(gender_allowlist) > 0)

    def _append_tpdb(p: dict) -> None:
        posters = p.get("posters") or []
        img = posters[0] if posters and isinstance(posters[0], str) else (posters[0].get("url") if posters else None)
        raw_g = _tpdb_raw_gender_from_search_hit(p)
        bucket = normalize_performer_gender_to_bucket(raw_g)
        tid = str(p.get("id") or p.get("_id") or "").strip()
        # Performer-directory gender filters (/library link modal) drop rows with no bucket.
        # TPDB search hits frequently lack extras — resolve from detail when filtering.
        if want_tpdb_gender_hydrate and bucket is None and tid:
            bucket = _tpdb_detail_gender_bucket(tid)
        results.append({
            "source": "TPDB",
            "id":     tid or "",
            "slug":   p.get("slug") or p.get("_id") or tid or "",
            "name":   p["name"],
            "image":  img,
            "gender": raw_g,
            "gender_bucket": bucket,
            # TPDB's /performers list endpoint generally omits aliases —
            # they appear only on the detail endpoint, and round-tripping
            # per hit would crater search latency. Accept whatever the
            # list payload happens to surface (some entries do carry it);
            # leave empty otherwise.
            "aliases": _normalise_performer_aliases(p.get("aliases"), p.get("name")),
        })

    # TPDB
    try:
        resp = requests.get(TPDB_PERFORMER_SEARCH, params={"q": name},
                            headers=_tpdb_headers(), timeout=15)
        if resp.status_code == 200:
            for p in (resp.json().get("data") or [])[:tpdb_take]:
                _append_tpdb(p)
    except Exception:
        pass
    # StashDB
    if settings.get("api_key_stashdb"):
        try:
            gql = f"""
            query($t: String!) {{
              searchPerformer(term: $t, limit: {stash_limit}) {{
                id name gender aliases images {{ url }}
              }}
            }}
            """
            resp = requests.post(
                "https://stashdb.org/graphql",
                json={"query": gql, "variables": {"t": name}},
                headers={"ApiKey": settings["api_key_stashdb"],
                          "Content-Type": "application/json"},
                timeout=10,
            )
            if resp.status_code == 200:
                body = resp.json()
                data = body.get("data") or {}
                # Do not skip Stash hits when TPDB already returned the same display name —
                # favourites needs one row per source so TPDB / Stash / Fans filters work.
                for p in (data.get("searchPerformer") or []):
                    imgs = p.get("images") or []
                    img = imgs[0].get("url") if imgs and isinstance(imgs[0], dict) else (imgs[0] if imgs else None)
                    raw_g = p.get("gender")
                    raw_g = str(raw_g) if raw_g is not None else None
                    results.append({
                        "source": "StashDB",
                        "id":     str(p["id"]),
                        "slug":   str(p["id"]),
                        "name":   p["name"],
                        "image":  img,
                        "gender": raw_g,
                        "gender_bucket": normalize_performer_gender_to_bucket(raw_g),
                        "aliases": _normalise_performer_aliases(p.get("aliases"), p.get("name")),
                    })
        except Exception:
            pass
    # FansDB (stash-box: same ApiKey auth as scene search; variable name `term` matches API)
    if settings.get("api_key_fansdb"):

        def _fansdb_append_from_data(data: dict) -> None:
            for p in (data.get("searchPerformer") or []):
                imgs = p.get("images") or []
                img = imgs[0].get("url") if imgs and isinstance(imgs[0], dict) else (imgs[0] if imgs else None)
                raw_g = p.get("gender")
                raw_g = str(raw_g) if raw_g is not None else None
                results.append({
                    "source": "FansDB",
                    "id":     str(p["id"]),
                    "slug":   str(p["id"]),
                    "name":   p["name"],
                    "image":  img,
                    "gender": raw_g,
                    "gender_bucket": normalize_performer_gender_to_bucket(raw_g),
                    "aliases": _normalise_performer_aliases(p.get("aliases"), p.get("name")),
                })

        try:
            gql_img = f"""
            query($term: String!) {{
              searchPerformer(term: $term, limit: {fans_limit}) {{
                id name gender aliases images {{ url }}
              }}
            }}
            """
            data = _fansdb_gql(gql_img, {"term": name})
            _fansdb_append_from_data(data)
        except Exception:
            try:
                gql_min = f"""
                query($term: String!) {{
                  searchPerformer(term: $term, limit: {fans_limit}) {{
                    id name gender aliases
                  }}
                }}
                """
                data = _fansdb_gql(gql_min, {"term": name})
                _fansdb_append_from_data(data)
            except Exception:
                pass
    # JAVStash (stash-box API; same searchPerformer shape as StashDB)
    if settings.get("api_key_javstash"):
        try:
            gql_js = f"""
            query($t: String!) {{
              searchPerformer(term: $t, limit: {stash_limit}) {{
                id name gender aliases images {{ url }}
              }}
            }}
            """
            resp = requests.post(
                JAVSTASH_ENDPOINT,
                json={"query": gql_js, "variables": {"t": name}},
                headers={"ApiKey": settings["api_key_javstash"],
                         "Content-Type": "application/json"},
                timeout=10,
            )
            if resp.status_code == 200:
                body = resp.json()
                data = body.get("data") or {}
                for p in (data.get("searchPerformer") or []):
                    imgs = p.get("images") or []
                    img = imgs[0].get("url") if imgs and isinstance(imgs[0], dict) else (imgs[0] if imgs else None)
                    raw_g = p.get("gender")
                    raw_g = str(raw_g) if raw_g is not None else None
                    results.append({
                        "source": "JAVStash",
                        "id":     str(p["id"]),
                        "slug":   str(p["id"]),
                        "name":   p["name"],
                        "image":  img,
                        "gender": raw_g,
                        "gender_bucket": normalize_performer_gender_to_bucket(raw_g),
                        "aliases": _normalise_performer_aliases(p.get("aliases"), p.get("name")),
                    })
        except Exception:
            pass
    if strict_name_match:
        want = normalise(name)
        results = [r for r in results if normalise(r.get("name") or "") == want]
    else:
        _hydrate_tpdb_search_aliases(results)
        results.sort(
            key=lambda r: (
                -_performer_search_match_score(r, name),
                normalise(r.get("name") or ""),
            )
        )
    return _apply_gender_allowlist(results, gender_allowlist)


def _tpdb_site_image_url(site: dict) -> str | None:
    """Resolve a usable image URL from a TPDB /sites item (logo/poster may be str or nested)."""
    for key in ("logo", "poster", "image"):
        v = site.get(key)
        if isinstance(v, str) and v.strip():
            return v.strip()
        if isinstance(v, dict):
            u = v.get("url") or v.get("full") or v.get("large")
            if isinstance(u, str) and u.strip():
                return u.strip()
    for key in ("logos", "posters", "images"):
        arr = site.get(key)
        if isinstance(arr, list) and arr and isinstance(arr[0], dict):
            got = (
                best_image_url(arr)
                if key == "logos"
                else best_studio_image_url(arr)
            )
            if got:
                return got
    return None


def _tpdb_scalar_media_url(val) -> str | None:
    """TPDB field that is either a URL string or {url, full, large}."""
    if isinstance(val, str) and val.strip():
        return val.strip()
    if isinstance(val, dict):
        u = val.get("url") or val.get("full") or val.get("large")
        if isinstance(u, str) and u.strip():
            return u.strip()
    return None


def search_studios(name: str) -> list[dict]:
    results = []
    settings = db.get_settings()
    try:
        resp = requests.get(TPDB_STUDIO_SEARCH, params={"q": name},
                            headers=_tpdb_headers(), timeout=15)
        if resp.status_code == 200:
            for s in (resp.json().get("data") or [])[:10]:
                sid = s.get("id") or s.get("_id")
                if sid is None:
                    continue
                sid_s = str(sid)
                results.append({
                    "source": "TPDB",
                    "id":     sid_s,
                    "slug":   str(s.get("slug") or s.get("_id") or sid_s),
                    "name":   s.get("name") or s.get("title", ""),
                    "image":  _tpdb_site_image_url(s),
                })
    except Exception:
        pass
    if settings.get("api_key_stashdb"):
        try:
            for s in stashdb_search_studio(name, settings["api_key_stashdb"])[:10]:
                results.append({
                    "source": "StashDB",
                    "id":     str(s["id"]),
                    "slug":   str(s["id"]),
                    "name":   s.get("name") or "",
                    "image":  best_studio_image_url(s.get("images") or []),
                })
        except Exception:
            pass
    if settings.get("api_key_fansdb"):
        try:
            gql = """
            query($term: String!) {
              searchStudio(term: $term, limit: 10) {
                id name images { url width height }
              }
            }
            """
            data = _fansdb_gql(gql, {"term": name})
            for s in (data.get("searchStudio") or []):
                imgs = s.get("images") or []
                img = best_studio_image_url(imgs) if imgs else None
                if not img and imgs and isinstance(imgs[0], dict):
                    img = (imgs[0].get("url") or "").strip() or None
                results.append({
                    "source": "FansDB",
                    "id":     str(s["id"]),
                    "slug":   str(s["id"]),
                    "name":   s.get("name") or "",
                    "image":  img,
                })
        except Exception:
            pass
    if settings.get("api_key_javstash"):
        try:
            gql = """
            query($term: String!) {
              searchStudio(term: $term, limit: 10) {
                id name images { url width height }
              }
            }
            """
            data = _stashbox_post(
                JAVSTASH_ENDPOINT,
                (settings.get("api_key_javstash") or "").strip(),
                gql,
                {"term": name},
            )
            for s in (data.get("searchStudio") or []):
                imgs = s.get("images") or []
                img = best_studio_image_url(imgs) if imgs else None
                if not img and imgs and isinstance(imgs[0], dict):
                    img = (imgs[0].get("url") or "").strip() or None
                results.append({
                    "source": "JAVStash",
                    "id":     str(s["id"]),
                    "slug":   str(s["id"]),
                    "name":   s.get("name") or "",
                    "image":  img,
                })
        except Exception:
            pass
    return results


def _pick_best_name_match(results: list[dict], folder_name: str) -> dict | None:
    """Normalised name equality only (no fuzzy or single-result fallback)."""
    if not results:
        return None
    want = normalise(folder_name)
    for r in results:
        if normalise(r.get("name") or "") == want:
            return r
    return None


def _favourite_parse_javstash_performer_from_folder(folder_path: str) -> tuple[str | None, str | None]:
    """JAVStash performer id and display name from tvshow.nfo (uniqueid or performers URL)."""
    root = Path(folder_path).expanduser()
    nfo = root / "tvshow.nfo"
    if not nfo.is_file():
        return None, None
    try:
        txt = nfo.read_text(encoding="utf-8", errors="ignore")
    except OSError:
        return None, None
    jid: str | None = None
    m = re.search(r"https?://javstash\.org/performers/([a-f0-9-]+)", txt, re.I)
    if m:
        jid = m.group(1).strip()
    else:
        m = re.search(
            r'<uniqueid[^>]*type=["\']javstash["\'][^>]*>([^<]+)</uniqueid>',
            txt,
            re.I,
        )
        if m:
            jid = m.group(1).strip()
    title: str | None = None
    mt = re.search(r"<title>([^<]+)</title>", txt, re.I)
    if mt:
        title = mt.group(1).strip()
    return jid, title


def _favourite_parse_javstash_from_folder(folder_path: str) -> tuple[str | None, str | None, str | None]:
    """Best-effort JAVStash scene id, title, and aired/premiered date from NFO text in folder."""
    root = Path(folder_path).expanduser()
    if not root.is_dir():
        return None, None, None
    js_id: str | None = None
    title: str | None = None
    aired: str | None = None
    try:
        nfo_paths = sorted(root.glob("*.nfo"), key=lambda p: p.name.lower())
    except OSError:
        return None, None, None
    for p in nfo_paths:
        try:
            txt = p.read_text(encoding="utf-8", errors="ignore")
        except OSError:
            continue
        if not js_id:
            m = re.search(r"https?://javstash\.org/scenes/([a-f0-9-]+)", txt, re.I)
            if m:
                js_id = m.group(1).strip()
            else:
                m = re.search(
                    r'<uniqueid[^>]*type=["\']javstash["\'][^>]*>([^<]+)</uniqueid>',
                    txt,
                    re.I,
                )
                if m:
                    js_id = m.group(1).strip()
        if title is None:
            mt = re.search(r"<title>([^<]+)</title>", txt, re.I)
            if mt:
                title = mt.group(1).strip()
        if aired is None:
            ma = re.search(r"<(?:aired|premiered)>(\d{4}-\d{2}-\d{2})", txt, re.I)
            if ma:
                aired = ma.group(1)
        if js_id and title and aired:
            break
    return js_id, title, aired


def _favourites_collect_folder_rows() -> list[dict]:
    """Subfolders under performer roots, series_dir (studios), features_dir (movies), jav_dir (JAV)."""
    rows: list[dict] = []
    s = db.get_settings()
    for entry in db.get_directories("performer"):
        base = Path((entry.get("path") or "").strip()).expanduser()
        label = entry.get("label") or base.name
        if not base.is_dir():
            emit(f"FAVOURITES collect: performer root not found: {base}")
            continue
        subdirs = sorted([d for d in base.iterdir() if d.is_dir() and not d.name.startswith(".")], key=lambda p: p.name.lower())
        emit(f"FAVOURITES collect: {len(subdirs)} folders in {label} ({base})")
        if not subdirs:
            emit(
                "FAVOURITES collect: this root has no immediate subfolders — "
                "the path must be a parent whose direct children are performer-named folders "
                f"(not a single performer's scene folder). ({label})"
            )
        for d in subdirs:
            gf = entry.get("gender_filters")
            if not isinstance(gf, list):
                gf = []
            rows.append({
                "kind": "performer",
                "folder_name": d.name,
                "path": str(d.resolve()),
                "root_label": label,
                "gender_filters": gf,
            })
    series_dir = (s.get("series_dir") or "").strip()
    if series_dir and Path(series_dir).expanduser().is_dir():
        base = Path(series_dir).expanduser()
        for d in sorted(base.iterdir(), key=lambda p: p.name.lower()):
            if d.is_dir() and not d.name.startswith("."):
                rows.append({
                    "kind": "studio",
                    "folder_name": d.name,
                    "path": str(d.resolve()),
                    "root_label": "Series",
                })
    features_dir = (s.get("features_dir") or "").strip()
    if features_dir and Path(features_dir).expanduser().is_dir():
        base = Path(features_dir).expanduser()
        label = base.name or "Features"
        for d in sorted(base.iterdir(), key=lambda p: p.name.lower()):
            if d.is_dir() and not d.name.startswith("."):
                rows.append({
                    "kind": "movie",
                    "folder_name": d.name,
                    "path": str(d.resolve()),
                    "root_label": label,
                })
    jav_dir = (s.get("jav_dir") or "").strip()
    if jav_dir and Path(jav_dir).expanduser().is_dir():
        base = Path(jav_dir).expanduser()
        label = base.name or "JAV"
        for d in sorted(base.iterdir(), key=lambda p: p.name.lower()):
            if d.is_dir() and not d.name.startswith("."):
                rows.append({
                    "kind": "jav",
                    "folder_name": d.name,
                    "path": str(d.resolve()),
                    "root_label": label,
                })
    return rows


def _normalize_sort_birth_date(raw: str | None) -> str | None:
    if not raw or not str(raw).strip():
        return None
    s = str(raw).strip()
    m = re.match(r"^(\d{4})(?:-(\d{2})(?:-(\d{2}))?)?", s)
    if not m:
        return None
    y, mo, d = m.group(1), m.group(2) or "01", m.group(3) or "01"
    try:
        mo_i = max(1, min(12, int(mo)))
        d_i = max(1, min(31, int(d)))
        return f"{y}-{mo_i:02d}-{d_i:02d}"
    except ValueError:
        return f"{y}-{mo}-{d}"


def _tpdb_performer_sort_birth_date(tpdb_id: str) -> str | None:
    try:
        resp = requests.get(
            TPDB_PERFORMER_DETAIL.format(id=tpdb_id),
            headers=_tpdb_headers(),
            timeout=12,
        )
        if resp.status_code != 200:
            return None
        data = resp.json().get("data") or {}
        extras = data.get("extras") or {}
        b = extras.get("birthday") or data.get("birth_date")
        return _normalize_sort_birth_date(b)
    except Exception:
        return None


def _fansdb_performer_sort_birth_date(fans_id: str) -> str | None:
    try:
        data = _fansdb_gql(
            "query($id: ID!) { findPerformer(id: $id) { birth_date } }",
            {"id": fans_id},
        )
        p = data.get("findPerformer") or {}
        return _normalize_sort_birth_date(p.get("birth_date"))
    except Exception:
        return None


def _stashdb_performer_sort_birth_date(sid: str) -> str | None:
    settings = db.get_settings()
    if not settings.get("api_key_stashdb"):
        return None
    try:
        gql = """
        query($id: ID!) {
          findPerformer(id: $id) {
            birth_date
          }
        }
        """
        resp = requests.post(
            "https://stashdb.org/graphql",
            json={"query": gql, "variables": {"id": sid}},
            headers={"ApiKey": settings["api_key_stashdb"],
                     "Content-Type": "application/json"},
            timeout=10,
        )
        if resp.status_code != 200:
            return None
        data = resp.json().get("data") or {}
        p = data.get("findPerformer") or {}
        return _normalize_sort_birth_date(p.get("birth_date"))
    except Exception:
        return None


def _favourite_performer_sort_birth_date(
    mt_id: str | None, ms_id: str | None, mf_id: str | None
) -> str | None:
    if mt_id:
        d = _tpdb_performer_sort_birth_date(mt_id)
        if d:
            return d
    if mf_id:
        d = _fansdb_performer_sort_birth_date(mf_id)
        if d:
            return d
    if ms_id:
        d = _stashdb_performer_sort_birth_date(ms_id)
        if d:
            return d
    return None


def _tpdb_studio_sort_birth_date(site_id: str) -> str | None:
    try:
        resp = requests.get(
            TPDB_STUDIO_DETAIL.format(id=site_id),
            headers=_tpdb_headers(),
            timeout=12,
        )
        if resp.status_code != 200:
            return None
        data = resp.json().get("data") or {}
        extras = data.get("extras") or {}
        y = extras.get("career_start_year") or extras.get("founded")
        if y is None or y == "":
            return None
        if isinstance(y, (int, float)):
            return f"{int(y)}-01-01"
        s = str(y).strip()
        m = re.match(r"^(\d{4})", s)
        if m:
            return f"{m.group(1)}-01-01"
        return _normalize_sort_birth_date(s)
    except Exception:
        return None


def _favourite_studio_sort_birth_date(mt_id: str | None) -> str | None:
    if mt_id:
        return _tpdb_studio_sort_birth_date(mt_id)
    return None


_FAVOURITE_LOCAL_POSTER_NAMES = ("poster.jpg", "folder.jpg")


def _favourite_find_local_back_file(folder_path: str) -> Path | None:
    """Find the back-cover / fanart image inside a movie or JAV folder.

    Convention: filing writes ``{folder_name}-fanart.jpg`` next to the
    video. Falls back to bare ``fanart.jpg`` / ``back.jpg`` for libraries
    organised by hand. Returns the first hit or ``None`` so a JAV tile
    can render the /scenes-style back+front duo cover when both exist
    (and degrade to a single front when only the poster is present)."""
    raw = (folder_path or "").strip()
    if not raw:
        return None
    try:
        root = Path(raw).expanduser().resolve()
    except (OSError, RuntimeError):
        return None
    if not root.is_dir():
        return None
    stem = root.name
    for ext in (".jpg", ".jpeg", ".png", ".webp"):
        for name in (
            f"{stem}-fanart{ext}",
            f"fanart{ext}",
            f"back{ext}",
            f"{stem}-back{ext}",
        ):
            p = root / name
            if p.is_file():
                try:
                    return p.resolve()
                except OSError:
                    return None
    return None


def _favourite_find_local_poster_file(folder_path: str) -> Path | None:
    """Root-of-folder poster.jpg or folder.jpg (case-insensitive)."""
    raw = (folder_path or "").strip()
    if not raw:
        return None
    try:
        root = Path(raw).expanduser().resolve()
    except (OSError, RuntimeError):
        return None
    if not root.is_dir():
        return None
    for name in _FAVOURITE_LOCAL_POSTER_NAMES:
        p = root / name
        if p.is_file():
            return p.resolve()
    found: dict[str, Path] = {}
    try:
        for child in root.iterdir():
            if not child.is_file():
                continue
            key = child.name.lower()
            if key in ("poster.jpg", "folder.jpg"):
                found[key] = child
    except OSError:
        return None
    for name in _FAVOURITE_LOCAL_POSTER_NAMES:
        p = found.get(name.lower())
        if p:
            try:
                return p.resolve()
            except OSError:
                continue
    return None


# Studio folder art: logos / landscape / banner before poster.jpg. Logo-only exact pass, then
# case-insensitive map, so Logo.png wins over poster.jpg on Linux before poster is considered.
_FAVOURITE_STUDIO_LOCAL_LOGO_NAMES = (
    "logo.png",
    "clearlogo.png",
    "logo.jpg",
    "clearlogo.jpg",
    "logo.jpeg",
    "clearlogo.jpeg",
    "logo.webp",
    "clearlogo.webp",
    "landscape.png",
    "landscape.jpg",
    "landscape.webp",
    "banner.png",
    "banner.jpg",
    "banner.webp",
    "clearart.png",
    "clearart.jpg",
    "clearart.webp",
)
_FAVOURITE_STUDIO_LOCAL_POSTER_NAMES = ("poster.jpg", "folder.jpg")
_STUDIO_ART_IMAGE_EXT = frozenset({".png", ".webp", ".jpg", ".jpeg"})
_STUDIO_LOGO_STEMS_EXACT = frozenset(
    {
        "logo",
        "clearlogo",
        "clear_logo",
        "studialogo",
        "landscape",
        "banner",
        "clearart",
    }
)
_STUDIO_LOGO_STEM_SEGMENTS = frozenset({"logo", "clearlogo", "clearart", "studialogo"})


def _favourite_studio_root_logo_candidates(root: Path) -> list[Path]:
    """Root files that look like logo art (not poster.jpg / folder.jpg)."""
    poster_lower = {n.lower() for n in _FAVOURITE_STUDIO_LOCAL_POSTER_NAMES}
    candidates: list[tuple[int, int, str, Path]] = []
    try:
        for child in root.iterdir():
            if not child.is_file():
                continue
            if child.suffix.lower() not in _STUDIO_ART_IMAGE_EXT:
                continue
            nl = child.name.lower()
            if nl in poster_lower:
                continue
            stem_l = child.stem.lower()
            tier: int | None = None
            if stem_l in _STUDIO_LOGO_STEMS_EXACT:
                tier = 0
            elif nl.startswith("clearlogo"):
                tier = 0
            elif stem_l.endswith("-logo") or stem_l.endswith("_logo"):
                tier = 1
            else:
                parts = [p for p in re.split(r"[-_.\s]+", stem_l) if p]
                if _STUDIO_LOGO_STEM_SEGMENTS.intersection(parts):
                    tier = 2
            if tier is None:
                continue
            candidates.append((tier, len(nl), nl, child))
    except OSError:
        return []
    candidates.sort(key=lambda t: (t[0], t[1], t[2]))
    out: list[Path] = []
    for _a, _b, _c, child in candidates:
        try:
            out.append(child.resolve())
        except OSError:
            continue
    return out


def _favourite_find_local_studio_art(folder_path: str) -> Path | None:
    """Show root: logo / landscape / banner art first, then poster.jpg / folder.jpg."""
    raw = (folder_path or "").strip()
    if not raw:
        return None
    try:
        root = Path(raw).expanduser().resolve()
    except (OSError, RuntimeError):
        return None
    if not root.is_dir():
        return None
    all_names = _FAVOURITE_STUDIO_LOCAL_LOGO_NAMES + _FAVOURITE_STUDIO_LOCAL_POSTER_NAMES
    allowed_lower = {n.lower() for n in all_names}

    for name in _FAVOURITE_STUDIO_LOCAL_LOGO_NAMES:
        p = root / name
        if p.is_file():
            try:
                return p.resolve()
            except OSError:
                continue

    found: dict[str, Path] = {}
    try:
        for child in root.iterdir():
            if not child.is_file():
                continue
            key = child.name.lower()
            if key in allowed_lower:
                found[key] = child
    except OSError:
        return None

    for name in _FAVOURITE_STUDIO_LOCAL_LOGO_NAMES:
        p = found.get(name.lower())
        if p:
            try:
                return p.resolve()
            except OSError:
                continue

    for p in _favourite_studio_root_logo_candidates(root):
        if p.is_file():
            return p

    for name in _FAVOURITE_STUDIO_LOCAL_POSTER_NAMES:
        p = root / name
        if p.is_file():
            try:
                return p.resolve()
            except OSError:
                continue
    for name in _FAVOURITE_STUDIO_LOCAL_POSTER_NAMES:
        p = found.get(name.lower())
        if p:
            try:
                return p.resolve()
            except OSError:
                continue
    return None


def _favourite_studio_folder_image_files(folder_path: str) -> list[Path]:
    """All image files directly inside a studio folder, sorted with the
    canonical logo/poster names first then alphabetical. Used by the
    studio popup image picker to surface what's already on disk."""
    raw = (folder_path or "").strip()
    if not raw:
        return []
    try:
        root = Path(raw).expanduser().resolve()
    except (OSError, RuntimeError):
        return []
    if not root.is_dir():
        return []
    canon = _FAVOURITE_STUDIO_LOCAL_LOGO_NAMES + _FAVOURITE_STUDIO_LOCAL_POSTER_NAMES
    canon_lower = {n.lower(): i for i, n in enumerate(canon)}
    out: list[Path] = []
    try:
        for child in root.iterdir():
            if not child.is_file():
                continue
            if child.suffix.lower() not in _STUDIO_ART_IMAGE_EXT:
                continue
            try:
                out.append(child.resolve())
            except OSError:
                continue
    except OSError:
        return []
    out.sort(key=lambda p: (canon_lower.get(p.name.lower(), 9999), p.name.lower()))
    return out


def _maybe_kick_performer_image_enrichment(row: dict) -> None:
    """Fire the enrichment thread if a performer row is missing any image
    data we can backfill (headshot, poster_secondary). Works for BOTH locked
    and unlocked rows — the lock is meant to freeze match IDs, not block
    image downloads. Callers pass the current row dict; this helper reads
    it directly and never mutates the database.
    """
    if (row or {}).get("kind") != "performer":
        return
    try:
        row_id = int(row["id"])
    except (KeyError, TypeError, ValueError):
        return
    try:
        _iafd_dir = _performers_iafd_dir(row_id)
        _meta = _performers_iafd_read_meta(row_id)
        _has_img = bool(_performers_iafd_image_api_url(row_id, 0, _meta))
        _fresh = not (_iafd_dir / f"{row_id}.json").exists()
        _missing_ext = not all([
            (row.get("match_iafd_url") or "").strip(),
            (row.get("match_freeones_url") or "").strip(),
            (row.get("match_babepedia_url") or "").strip(),
        ])
        _has_db_id = any([
            (row.get("match_tpdb_id") or "").strip(),
            (row.get("match_stashdb_id") or "").strip(),
            (row.get("match_fansdb_id") or "").strip(),
        ])
        _missing_poster_secondary = _perf_poster_resolve(row_id, "poster_secondary") is None
    except Exception:
        return
    if (
        _fresh
        or (not _has_img)
        or (_missing_ext and _has_db_id)
        or (_missing_poster_secondary and _has_db_id)
    ):
        threading.Thread(
            target=_enrich_performer_ext_links_bg, args=(row_id,), daemon=True
        ).start()


def favourites_refresh_entity_row(
    row_id: int,
    *,
    scrape_aliases: bool = True,
    only_missing: bool = False,
    seed_source: str | None = None,
    seed_id: str | None = None,
    seed_name: str | None = None,
) -> dict:
    """Resolve library folder → external IDs for cross-reference across databases.

    Each configured source (TPDB, StashDB, FansDB) is queried independently; when a
    performer/studio name matches (or a single unambiguous search hit), that source’s
    ID and display name are stored so the same folder links all three where possible.

    If only_missing is True, existing non-empty match_* ids are kept; only empty slots
    are filled. Image and aliases are not overwritten when already present unless a new
    match supplies them for an empty slot.

    When matches_locked is set, this function is skipped entirely (returns skipped: True).
    Manual link updates from the overlay search modal use api_favourites_match instead and
    are not blocked by the lock.
    """
    row = db.favourite_get(row_id)
    if not row:
        return {"error": "Not found"}
    if int(row.get("matches_locked") or 0):
        # Lock protects match IDs, but image enrichment (headshot + posters)
        # is safe to run — it only writes to metadata/performers/{id}/ and
        # never touches DB match_* columns. Fire the enrichment thread for
        # locked rows too so they can still catch up on missing images.
        _maybe_kick_performer_image_enrichment(row)
        return {"ok": True, "id": row_id, "skipped": True}
    name = row["folder_name"]
    kind = row["kind"]
    if kind not in ("performer", "studio", "movie", "jav"):
        return {"error": "unsupported kind"}
    if only_missing:
        scrape_aliases = False

    img: str | None = row.get("image_url")
    had_img = bool(str(img or "").strip())
    aliases: list[str] = []

    mt_id = mt_n = ms_id = ms_n = mf_id = mf_n = None
    mdb_id: str | None = None
    mdb_n: str | None = None
    movie_sort_bd: str | None = None
    jav_id = (row.get("match_javstash_id") or "").strip() or None
    jav_n = (row.get("match_javstash_name") or "").strip() or None
    jav_sort_bd: str | None = None

    if kind == "performer":
        g_allow = gender_allowlist_from_json(row.get("gender_filters_json"))
        res_tp = search_performers(
            name, gender_allowlist=g_allow, strict_name_match=True
        )
        res_st = [r for r in res_tp if r.get("source") == "StashDB"]
        res_tpdb = [r for r in res_tp if r.get("source") == "TPDB"]
        res_fan = [r for r in res_tp if r.get("source") == "FansDB"]
        res_jav = [r for r in res_tp if r.get("source") == "JAVStash"]
        p_tp = _pick_best_name_match(res_tpdb, name)
        p_st = _pick_best_name_match(res_st, name)
        p_fn = _pick_best_name_match(res_fan, name)
        p_js = _pick_best_name_match(res_jav, name)
        pj_id, pj_n = _favourite_parse_javstash_performer_from_folder(row.get("path") or "")
        if only_missing:
            mt_id = (row.get("match_tpdb_id") or "").strip() or None
            mt_n = (row.get("match_tpdb_name") or "") or ""
            ms_id = (row.get("match_stashdb_id") or "").strip() or None
            ms_n = (row.get("match_stashdb_name") or "") or ""
            mf_id = (row.get("match_fansdb_id") or "").strip() or None
            mf_n = (row.get("match_fansdb_name") or "") or ""
            # Drop stored links that violate the directory gender allowlist (search_performers
            # already filters; a stale match from before filters or wrong gender must be cleared).
            if g_allow is not None:

                def _id_in_results(res_list: list[dict], sid: str | None) -> bool:
                    if not sid or not str(sid).strip():
                        return False
                    s = str(sid).strip()
                    return any(str(r.get("id") or "") == s for r in res_list)

                if mt_id and not _id_in_results(res_tpdb, mt_id):
                    mt_id = None
                    mt_n = ""
                if ms_id and not _id_in_results(res_st, ms_id):
                    ms_id = None
                    ms_n = ""
                if mf_id and not _id_in_results(res_fan, mf_id):
                    mf_id = None
                    mf_n = ""
                if jav_id and not _id_in_results(res_jav, jav_id):
                    jav_id = None
                    jav_n = ""
            if not mt_id and p_tp:
                mt_id = str(p_tp.get("id") or "")
                mt_n = p_tp.get("name") or ""
                if not had_img and p_tp.get("image"):
                    img = p_tp.get("image")
                    had_img = True
            if not ms_id and p_st:
                ms_id = str(p_st.get("id") or "")
                ms_n = p_st.get("name") or ""
                if not had_img and p_st.get("image"):
                    img = p_st.get("image")
                    had_img = True
            if not mf_id and p_fn:
                mf_id = str(p_fn.get("id") or "")
                mf_n = p_fn.get("name") or ""
                if not had_img and p_fn.get("image"):
                    img = p_fn.get("image")
                    had_img = True
            if not jav_id and p_js:
                jav_id = str(p_js.get("id") or "")
                jav_n = p_js.get("name") or ""
                if not had_img and p_js.get("image"):
                    img = p_js.get("image")
                    had_img = True
        else:
            if p_tp:
                mt_id, mt_n = str(p_tp.get("id") or ""), p_tp.get("name") or ""
            if p_st:
                ms_id, ms_n = str(p_st.get("id") or ""), p_st.get("name") or ""
            if p_fn:
                mf_id, mf_n = str(p_fn.get("id") or ""), p_fn.get("name") or ""
            if p_js:
                jav_id, jav_n = str(p_js.get("id") or ""), p_js.get("name") or ""
            img = (
                (p_tp.get("image") if p_tp else None)
                or (p_st.get("image") if p_st else None)
                or (p_fn.get("image") if p_fn else None)
                or (p_js.get("image") if p_js else None)
                or img
            )
            if scrape_aliases:
                aliases = _fetch_performer_aliases(name, quiet=True)
        if not jav_id and pj_id:
            jav_id = pj_id
        if not jav_n and pj_n:
            jav_n = pj_n
        if seed_source and seed_id:
            sid_seed = str(seed_id).strip()
            sn_seed = (seed_name or name or "").strip()
            if sid_seed:
                if seed_source == "JAVStash":
                    jav_id, jav_n = sid_seed, sn_seed or jav_n or name
                elif seed_source == "StashDB":
                    ms_id, ms_n = sid_seed, sn_seed or ms_n or name
                elif seed_source == "FansDB":
                    mf_id, mf_n = sid_seed, sn_seed or mf_n or name
                elif seed_source == "TPDB":
                    mt_id, mt_n = sid_seed, sn_seed or mt_n or name
        if g_allow is not None:
            mt_id, mt_n, ms_id, ms_n, mf_id, mf_n = _enforce_favourite_performer_slots_by_detail_gender(
                g_allow, mt_id, mt_n, ms_id, ms_n, mf_id, mf_n
            )
    elif kind == "studio":
        res_s = search_studios(name)
        res_tpdb = [r for r in res_s if r.get("source") == "TPDB"]
        res_st = [r for r in res_s if r.get("source") == "StashDB"]
        res_fan = [r for r in res_s if r.get("source") == "FansDB"]
        p_tp = _pick_best_name_match(res_tpdb, name)
        p_st = _pick_best_name_match(res_st, name)
        p_fn = _pick_best_name_match(res_fan, name)
        if only_missing:
            mt_id = (row.get("match_tpdb_id") or "").strip() or None
            mt_n = (row.get("match_tpdb_name") or "") or ""
            ms_id = (row.get("match_stashdb_id") or "").strip() or None
            ms_n = (row.get("match_stashdb_name") or "") or ""
            mf_id = (row.get("match_fansdb_id") or "").strip() or None
            mf_n = (row.get("match_fansdb_name") or "") or ""
            if not mt_id and p_tp:
                mt_id = str(p_tp.get("id") or "")
                mt_n = p_tp.get("name") or ""
                if not had_img and p_tp.get("image"):
                    img = p_tp.get("image")
                    had_img = True
            if not ms_id and p_st:
                ms_id = str(p_st.get("id") or "")
                ms_n = p_st.get("name") or ""
                if not had_img and p_st.get("image"):
                    img = p_st.get("image")
                    had_img = True
            if not mf_id and p_fn:
                mf_id = str(p_fn.get("id") or "")
                mf_n = p_fn.get("name") or ""
                if not had_img and p_fn.get("image"):
                    img = p_fn.get("image")
                    had_img = True
        else:
            if p_tp:
                mt_id, mt_n = str(p_tp.get("id") or ""), p_tp.get("name") or ""
            if p_st:
                ms_id, ms_n = str(p_st.get("id") or ""), p_st.get("name") or ""
            if p_fn:
                mf_id, mf_n = str(p_fn.get("id") or ""), p_fn.get("name") or ""
            img = (
                (p_tp.get("image") if p_tp else None)
                or (p_st.get("image") if p_st else None)
                or (p_fn.get("image") if p_fn else None)
                or img
            )

    elif kind == "movie":
        title_guess, year_guess = guess_movie_query_from_filename(f"{name}.mkv")
        settings_mv = db.get_settings()
        tmdb_key_mv = (settings_mv.get("api_key_tmdb") or "").strip()
        tpdb_key_mv = (settings_mv.get("api_key_tpdb") or "").strip()
        ms_id = ms_n = mf_id = mf_n = None
        if only_missing:
            mdb_id = (row.get("match_tmdb_id") or "").strip() or None
            mdb_n = (row.get("match_tmdb_name") or "") or ""
            mt_id = (row.get("match_tpdb_id") or "").strip() or None
            mt_n = (row.get("match_tpdb_name") or "") or ""
            if not mdb_id and tmdb_key_mv:
                try:
                    t_res = search_tmdb(title_guess, year_guess) or []
                except Exception:
                    t_res = []
                if t_res:
                    try:
                        m_full = get_tmdb_movie(t_res[0]["id"])
                        mdb_id = str(m_full.get("id") or "").strip() or None
                        mdb_n = m_full.get("title") or ""
                        if not had_img and m_full.get("poster_url"):
                            img = m_full.get("poster_url")
                            had_img = True
                    except Exception:
                        pass
            if not mt_id and tpdb_key_mv:
                hit_mv = search_tpdb_movie_first_hit(title_guess, year_guess)
                if hit_mv:
                    mt_id = str(hit_mv.get("_id") or hit_mv.get("id") or "").strip() or None
                    mt_n = hit_mv.get("title") or ""
                    if not had_img:
                        pic_mv = _movie_card_from_tpdb(hit_mv).get("poster")
                        if pic_mv:
                            img = pic_mv
                            had_img = True
        else:
            mdb_id = mdb_n = mt_id = mt_n = None
            if tmdb_key_mv:
                try:
                    t_res = search_tmdb(title_guess, year_guess) or []
                except Exception:
                    t_res = []
                if t_res:
                    try:
                        m_full = get_tmdb_movie(t_res[0]["id"])
                        mdb_id = str(m_full.get("id") or "").strip() or None
                        mdb_n = m_full.get("title") or ""
                        img = m_full.get("poster_url") or img
                    except Exception:
                        pass
            if not mt_id and tpdb_key_mv:
                hit_mv = search_tpdb_movie_first_hit(title_guess, year_guess)
                if hit_mv:
                    mt_id = str(hit_mv.get("_id") or hit_mv.get("id") or "").strip() or None
                    mt_n = hit_mv.get("title") or ""
                    if not img:
                        pic_mv = _movie_card_from_tpdb(hit_mv).get("poster")
                        if pic_mv:
                            img = pic_mv
        y_key = year_guess if year_guess and len(year_guess) == 4 and year_guess.isdigit() else None
        if not y_key and mdb_id:
            try:
                mm = get_tmdb_movie(mdb_id)
                yy = (mm.get("year") or "")[:4]
                if yy.isdigit() and len(yy) == 4:
                    y_key = yy
            except Exception:
                pass
        movie_sort_bd = f"{y_key}-01-01" if y_key else None

    elif kind == "jav":
        mt_id = mt_n = ms_id = ms_n = mf_id = mf_n = None
        mdb_id = mdb_n = None
        pj_id, pj_n, aired = _favourite_parse_javstash_from_folder(row.get("path") or "")
        parsed_sd = _normalize_sort_birth_date(aired) if aired else None
        prev_sd = _normalize_sort_birth_date(row.get("sort_birth_date"))
        if only_missing:
            if not jav_id and pj_id:
                jav_id = pj_id
            if not jav_n and pj_n:
                jav_n = pj_n
            jav_sort_bd = prev_sd or parsed_sd
        else:
            jav_id, jav_n = pj_id, pj_n
            jav_sort_bd = parsed_sd or prev_sd
        jav_n = (jav_n or pj_n or name or "").strip() or None

    now = datetime.now(timezone.utc).isoformat()
    if kind == "performer" and scrape_aliases:
        aliases_json = json.dumps(aliases)
    elif kind == "performer":
        aliases_json = row.get("aliases_json")
    else:
        aliases_json = None

    if kind == "performer":
        sort_bd = _favourite_performer_sort_birth_date(mt_id, ms_id, mf_id)
    elif kind == "studio":
        sort_bd = _favourite_studio_sort_birth_date(mt_id)
    elif kind == "movie":
        sort_bd = movie_sort_bd
    elif kind == "jav":
        sort_bd = jav_sort_bd
    else:
        sort_bd = None

    if kind == "performer" and _favourite_find_local_poster_file(row.get("path") or ""):
        img = f"/api/favourites/folder-poster?row_id={row_id}"
    elif kind == "movie" and _favourite_find_local_poster_file(row.get("path") or ""):
        img = f"/api/favourites/folder-poster?row_id={row_id}"
    elif kind == "jav" and _favourite_find_local_poster_file(row.get("path") or ""):
        img = f"/api/favourites/folder-poster?row_id={row_id}"
    elif kind == "studio" and _favourite_find_local_studio_art(row.get("path") or ""):
        img = f"/api/favourites/folder-logo?row_id={row_id}"

    db.favourite_overwrite_matches(
        row_id,
        image_url=img,
        aliases_json=aliases_json,
        match_tmdb_id=mdb_id,
        match_tmdb_name=mdb_n,
        match_tpdb_id=mt_id,
        match_tpdb_name=mt_n,
        match_stashdb_id=ms_id,
        match_stashdb_name=ms_n,
        match_fansdb_id=mf_id,
        match_fansdb_name=mf_n,
        match_javstash_id=jav_id,
        match_javstash_name=jav_n,
        sort_birth_date=sort_bd,
    )
    with db.get_conn() as c:
        c.execute(
            "UPDATE favourite_entities SET scanned_at = ? WHERE id = ?",
            (now, row_id),
        )
        c.commit()
    # Kick off enrichment for performers: ext links from DB cross-refs,
    # headshot, and posters. Same helper the locked-skip branch uses so the
    # trigger conditions stay in one place.
    if kind == "performer":
        _maybe_kick_performer_image_enrichment(db.favourite_get(row_id) or row)
    return {"ok": True, "id": row_id}


def favourites_scan_index(
    *,
    prune_missing: bool = False,
    folders: list[dict] | None = None,
    progress_init: bool = True,
    only_missing: bool = True,
) -> dict:
    """Scan configured library folders into favourite_entities; optionally drop removed folders.

    only_missing: when True (default), refresh each row without overwriting existing DB matches.
    """
    if folders is None:
        folders = _favourites_collect_folder_rows()
    valid_paths = {f["path"] for f in folders}
    seen = 0
    done = 0
    failed = 0
    if progress_init:
        _favourites_progress_start("scan", len(folders))
    try:
        for f in folders:
            nm = f.get("folder_name") or ""
            _favourites_progress_update(nm, done)
            gf_json = None
            if f.get("kind") == "performer":
                lst = f.get("gender_filters")
                if isinstance(lst, list):
                    gf_json = json.dumps(lst)
            # Per-row try/except — one bad row (network blip on the
            # refresh-entity-row call, dodgy DB state, etc.) was
            # killing the entire scan loop without surfacing which
            # folder caused it. Track failures separately and keep
            # scanning so a new folder later in the list still gets
            # picked up.
            try:
                rid = db.favourite_upsert_folder(
                    f["kind"],
                    f["folder_name"],
                    f["path"],
                    f["root_label"],
                    gender_filters_json=gf_json,
                )
                seen += 1
                if rid:
                    favourites_refresh_entity_row(
                        rid,
                        scrape_aliases=not only_missing,
                        only_missing=only_missing,
                    )
            except Exception as exc:
                failed += 1
                emit(f"FAVOURITES scan: row {nm!r} failed — {exc}")
            done += 1
            _favourites_progress_update(nm, done)
        removed = 0
        if prune_missing:
            _favourites_progress_update("prune", done)
            removed = db.favourite_delete_missing_paths(valid_paths)
        _favourites_progress_update("paths", done)
        db.favourite_refresh_all_path_existence()
        emit(
            f"FAVOURITES index: {seen} folders scanned, "
            f"{removed} stale rows removed, {failed} failed"
        )
        # Bust the warm-cache snapshot now that the DB carries the new
        # rows. Without this, the snapshot the user sees in /library
        # was built BEFORE the background scan ran (the POST-handler
        # middleware invalidated when the response left, but the
        # rebuild raced ahead of this background task), leaving
        # newly-added folders invisible until the 1 h backstop fired.
        try:
            _favourites_warm.invalidate()
        except Exception:
            pass
        # Phase 3: NFO walk to discover any new studio names. Run in a daemon
        # thread so the scan response returns immediately — first run can be
        # slow on large libraries, subsequent runs are mtime-incremental.
        # Phase 4: kick the StashDB fetcher right after so newly-discovered
        # studios get their logos without waiting for the next scheduled tick.
        threading.Thread(
            target=lambda: (_studio_logos_discover_run(), _studio_logo_fetcher_job()),
            daemon=True,
            name="studio-logo-discover-fetch",
        ).start()
        return {"scanned": seen, "removed_stale": removed}
    finally:
        _favourites_progress_finish()


def _background_performer_poster_gap_fill() -> None:
    """Walk every performer row and try to fill missing primary / secondary
    posters using the existing _ensure_performer_posters() chain. The helper
    is already idempotent — it skips when the destination file exists and
    is > 500 bytes, so this never overwrites artwork the user has already
    curated. Designed to run on the daily favourites schedule so newly-
    matched performers and rows that failed their initial scrape (network
    blip, missing TPDB id at the time, etc.) gradually fill in instead of
    needing a manual nudge per row.
    """
    try:
        rows = [r for r in db.favourite_list() if r.get("kind") == "performer"]
    except Exception as e:
        emit(f"poster gap-fill: failed to list performers: {e}")
        return
    total = len(rows)
    if not total:
        return
    emit(f"poster gap-fill: scanning {total} performer rows for missing primary/secondary")
    filled_any = 0
    skipped = 0
    for r in rows:
        rid = r.get("id")
        if not rid:
            continue
        try:
            md = _metadata_dir_for("performer", rid)
            has_primary = any(
                (md / n).is_file() and (md / n).stat().st_size > 500
                for n in (f"{rid}_poster_primary.webp", f"{rid}_poster_primary.jpg", f"{rid}_poster_1.webp", f"{rid}_poster_1.jpg")
            )
            has_secondary = any(
                (md / n).is_file() and (md / n).stat().st_size > 500
                for n in (f"{rid}_poster_secondary.webp", f"{rid}_poster_secondary.jpg", f"{rid}_poster_2.webp", f"{rid}_poster_2.jpg", f"{rid}_poster.webp", f"{rid}_poster.jpg")
            )
            if has_primary and has_secondary:
                skipped += 1
                continue
            before = (has_primary, has_secondary)
            _ensure_performer_posters(int(rid))
            has_primary_after = any(
                (md / n).is_file() and (md / n).stat().st_size > 500
                for n in (f"{rid}_poster_primary.webp", f"{rid}_poster_primary.jpg", f"{rid}_poster_1.webp", f"{rid}_poster_1.jpg")
            )
            has_secondary_after = any(
                (md / n).is_file() and (md / n).stat().st_size > 500
                for n in (f"{rid}_poster_secondary.webp", f"{rid}_poster_secondary.jpg", f"{rid}_poster_2.webp", f"{rid}_poster_2.jpg", f"{rid}_poster.webp", f"{rid}_poster.jpg")
            )
            if (has_primary_after, has_secondary_after) != before:
                filled_any += 1
            # Only throttle when we actually hit external APIs (i.e. the
            # row had a gap and _ensure_performer_posters did real work);
            # complete rows short-circuit above and don't need pacing.
            time.sleep(0.4)
        except Exception as e:
            emit(f"poster gap-fill: row {rid} error: {e}")
    emit(f"poster gap-fill: done — {filled_any} rows updated, {skipped} already complete, {total - filled_any - skipped} still empty")


def run_favourites_scheduled_scan() -> None:
    s = db.get_settings()
    if s.get("favourites_scan_enabled", "false").lower() != "true":
        return
    try:
        favourites_scan_index(prune_missing=False, only_missing=True)
    except Exception as e:
        emit(f"FAVOURITES scheduled scan error: {e}")
    threading.Thread(target=_background_iafd_enrich_all, daemon=True).start()
    threading.Thread(target=_background_performer_poster_gap_fill, daemon=True).start()


def _normalize_metadata_db_source(source: str) -> str:
    """Canonicalise stash-box / TPDB source labels from URLs, caches, or UI."""
    s = (source or "").strip()
    if not s:
        return "TPDB"
    sl = s.lower().replace(" ", "")
    if sl in ("tpdb", "theporndb"):
        return "TPDB"
    if sl == "stashdb":
        return "StashDB"
    if sl == "fansdb":
        return "FansDB"
    if sl in ("javstash", "javstash.org"):
        return "JAVStash"
    return s


def fetch_performer_detail(source: str, pid: str) -> dict | None:
    source = _normalize_metadata_db_source(source)
    if source == "TPDB":
        try:
            resp = requests.get(TPDB_PERFORMER_DETAIL.format(id=pid),
                                headers=_tpdb_headers(), timeout=15)
            if resp.status_code == 200:
                data = resp.json().get("data")
                return data
        except Exception:
            pass
    elif source == "StashDB":
        key = (db.get_settings().get("api_key_stashdb") or "").strip()
        if not key:
            emit(f"fetch_performer_detail: no StashDB API key")
            return None
        try:
            # Stash-box's Performer type has cup_size/band_size/waist_size/
            # hip_size as top-level fields (not nested under measurements)
            # and has no `bio` field — we use disambiguation as the display
            # caption. Requesting either causes the server to reject the
            # query with HTTP 422.
            gql = """
            query($id: ID!) {
              findPerformer(id: $id) {
                id
                name
                disambiguation
                aliases
                birth_date
                ethnicity
                country
                gender
                hair_color
                height
                tattoos { location description }
                piercings { location description }
                breast_type
                cup_size
                band_size
                waist_size
                hip_size
                eye_color
                career_start_year
                career_end_year
                urls { url type }
                images { url }
              }
            }
            """
            resp = requests.post(
                "https://stashdb.org/graphql",
                json={"query": gql, "variables": {"id": str(pid).strip()}},
                headers={"ApiKey": key, "Content-Type": "application/json"},
                timeout=15,
            )
            if resp.status_code != 200:
                body_snip = (resp.text or "")[:240].replace("\n", " ")
                emit(f"fetch_performer_detail: StashDB HTTP {resp.status_code} for {pid}: {body_snip}")
                return None
            body = resp.json()
            if body.get("errors"):
                emit(f"fetch_performer_detail: StashDB GQL errors for {pid}: {body['errors']}")
                return None
            data = (body.get("data") or {}).get("findPerformer") or {}
            if not data:
                emit(f"fetch_performer_detail: StashDB returned empty for {pid}")
                return None

            def _stash_body_mod_line(mods) -> str | None:
                if not mods:
                    return None
                parts: list[str] = []
                for m in mods:
                    if not isinstance(m, dict):
                        continue
                    loc = (m.get("location") or "").strip()
                    desc = (m.get("description") or "").strip()
                    if loc and desc:
                        parts.append(f"{loc} ({desc})")
                    elif loc:
                        parts.append(loc)
                return "; ".join(parts) if parts else None

            meas_bits: list[str] = []
            for lbl, key in (
                ("Cup", "cup_size"),
                ("Band", "band_size"),
                ("Waist", "waist_size"),
                ("Hip", "hip_size"),
            ):
                v = data.get(key)
                if v is None or v == "":
                    continue
                meas_bits.append(f"{lbl} {v}")
            measure_line = ", ".join(meas_bits) if meas_bits else None

            extras = {
                "birthday": data.get("birth_date") or data.get("birthdate"),
                "ethnicity": data.get("ethnicity"),
                "nationality": data.get("country"),
                "gender": data.get("gender"),
                "hair_colour": data.get("hair_color"),
                "height": data.get("height"),
                "measurements": measure_line,
                "tattoos": _stash_body_mod_line(data.get("tattoos")),
                "piercings": _stash_body_mod_line(data.get("piercings")),
                "breast_type": data.get("breast_type"),
                "eye_color": data.get("eye_color"),
                "career_start_year": data.get("career_start_year"),
                "career_end_year": data.get("career_end_year"),
            }
            return {
                "stash_id": str(data.get("id") or "").strip() or None,
                "name": data.get("name"),
                "bio": data.get("disambiguation") or "",
                "aliases": data.get("aliases") or [],
                "posters": data.get("images") or [],
                "extras": {k: v for k, v in extras.items() if v is not None and str(v).strip()},
                "urls": data.get("urls") or [],
            }
        except Exception as exc:
            emit(f"fetch_performer_detail: StashDB exception for {pid}: {exc}")
    elif source == "JAVStash":
        jav_key = (db.get_settings().get("api_key_javstash") or "").strip()
        if not jav_key:
            emit("fetch_performer_detail: no JAVStash API key")
            return None
        try:
            gql = """
            query($id: ID!) {
              findPerformer(id: $id) {
                id
                name
                disambiguation
                aliases
                birth_date
                ethnicity
                country
                gender
                hair_color
                height
                tattoos { location description }
                piercings { location description }
                breast_type
                cup_size
                band_size
                waist_size
                hip_size
                eye_color
                career_start_year
                career_end_year
                urls { url type }
                images { url }
              }
            }
            """
            resp = requests.post(
                JAVSTASH_ENDPOINT,
                json={"query": gql, "variables": {"id": str(pid).strip()}},
                headers={"ApiKey": jav_key, "Content-Type": "application/json"},
                timeout=15,
            )
            if resp.status_code != 200:
                body_snip = (resp.text or "")[:240].replace("\n", " ")
                emit(f"fetch_performer_detail: JAVStash HTTP {resp.status_code} for {pid}: {body_snip}")
                return None
            body = resp.json()
            if body.get("errors"):
                emit(f"fetch_performer_detail: JAVStash GQL errors for {pid}: {body['errors']}")
                return None
            data = (body.get("data") or {}).get("findPerformer") or {}
            if not data:
                emit(f"fetch_performer_detail: JAVStash returned empty for {pid}")
                return None

            def _stash_body_mod_line(mods) -> str | None:
                if not mods:
                    return None
                parts: list[str] = []
                for m in mods:
                    if not isinstance(m, dict):
                        continue
                    loc = (m.get("location") or "").strip()
                    desc = (m.get("description") or "").strip()
                    if loc and desc:
                        parts.append(f"{loc} ({desc})")
                    elif loc:
                        parts.append(loc)
                return "; ".join(parts) if parts else None

            meas_bits: list[str] = []
            for lbl, fld in (
                ("Cup", "cup_size"),
                ("Band", "band_size"),
                ("Waist", "waist_size"),
                ("Hip", "hip_size"),
            ):
                v = data.get(fld)
                if v is None or v == "":
                    continue
                meas_bits.append(f"{lbl} {v}")
            measure_line = ", ".join(meas_bits) if meas_bits else None

            extras = {
                "birthday": data.get("birth_date") or data.get("birthdate"),
                "ethnicity": data.get("ethnicity"),
                "nationality": data.get("country"),
                "gender": data.get("gender"),
                "hair_colour": data.get("hair_color"),
                "height": data.get("height"),
                "measurements": measure_line,
                "tattoos": _stash_body_mod_line(data.get("tattoos")),
                "piercings": _stash_body_mod_line(data.get("piercings")),
                "breast_type": data.get("breast_type"),
                "eye_color": data.get("eye_color"),
                "career_start_year": data.get("career_start_year"),
                "career_end_year": data.get("career_end_year"),
            }
            jav_pid = str(data.get("id") or "").strip() or None
            return {
                "id": jav_pid,
                "javstash_id": jav_pid,
                "name": data.get("name"),
                "bio": data.get("disambiguation") or "",
                "aliases": data.get("aliases") or [],
                "posters": data.get("images") or [],
                "extras": {k: v for k, v in extras.items() if v is not None and str(v).strip()},
                "urls": data.get("urls") or [],
            }
        except Exception as exc:
            emit(f"fetch_performer_detail: JAVStash exception for {pid}: {exc}")
    elif source == "FansDB":
        try:
            data = _fansdb_gql(FANSDB_PERFORMER_DETAIL_GQL, {"id": pid})
            p = data.get("findPerformer")
            if p:
                ex = {
                    "birthday":    p.get("birth_date"),
                    "ethnicity":   p.get("ethnicity"),
                    "nationality": p.get("country"),
                }
                g = p.get("gender")
                if g is not None and str(g).strip():
                    ex["gender"] = g
                return {
                    "fansdb_id": str(pid).strip(),
                    "name":    p.get("name"),
                    "bio":     p.get("disambiguation") or "",
                    "aliases": p.get("aliases", []),
                    "posters": p.get("images", []),
                    "extras":  {k: v for k, v in ex.items() if v is not None and str(v).strip()},
                    "urls":    p.get("urls") or [],
                }
        except Exception:
            pass
    return None


