@app.get("/loading", response_class=HTMLResponse)
async def loading_page(next: str = "/scenes"):
    """Boot-loading page served while the warmup thread populates caches.
    Polls ``/api/startup/status`` and redirects to ``next`` when ready."""
    # Only allow relative internal paths as next-target. Anything with
    # scheme-like characters or protocol-relative prefixes falls back to
    # /scenes to prevent open-redirect injection via the ``next`` query.
    safe_next = next if (isinstance(next, str) and next.startswith("/") and not next.startswith("//") and "\n" not in next and "\"" not in next and "'" not in next and "<" not in next) else "/scenes"
    with open("static/loading.html") as f:
        html = f.read().replace("__NEXT__", safe_next)
    return HTMLResponse(content=html)


