@app.get("/api/log/history")
async def api_log_history(limit: int = 200, offset: int = 0, q: str = ""):
    qstr = (q or "").strip()
    lines = db.activity_log_fetch(limit=limit, offset=offset, q=qstr)
    total = db.activity_log_count(q=qstr)
    payload = {"lines": lines, "total": total, "limit": limit, "offset": offset}
    if qstr:
        # Total of the unfiltered log so the UI can show "showing 80
        # filtered from 12,431" instead of just the post-filter count.
        payload["total_unfiltered"] = db.activity_log_count()
        payload["q"] = qstr
    return payload


@app.get("/api/log/download")
async def api_log_download(q: str = ""):
    """Stream the full activity log as a plain-text file. Respects the
    same ``q`` substring filter as ``/api/log/history`` so the user can
    download just the lines matching whatever's in the search box.

    Streams oldest → newest via ``activity_log_iter_all`` so a
    multi-megabyte log doesn't pin memory. Filename includes the
    current timestamp so repeated downloads don't overwrite each other
    in the browser's Downloads folder."""
    qstr = (q or "").strip()
    #: Flush in a worker so the buffered-batch INSERT doesn't block the
    #: event loop right before we start streaming.
    await run_in_threadpool(flush_emit_buffer)

    def _iter():
        for ts, line in db.activity_log_iter_all(q=qstr):
            ts_clean = ts.replace("T", " ")
            line_clean = line.replace("\r", "").replace("\n", " ")
            # Strip the inline ISO UTC stamp that ``_emit_raw`` prepends —
            # the row's ``created_at`` column is the canonical source for
            # downloads (it's stored at insert time, not derived from the
            # line text) so the inline prefix would just duplicate it.
            # Old rows with the legacy ``HH:MM:SS\s`` 9-char prefix are
            # also stripped so a mixed log file still reads cleanly.
            if _LOG_TS_PREFIX_RE.match(line_clean):
                line_clean = line_clean[_LOG_TS_PREFIX_LEN:]
            elif re.match(r"^\d{2}:\d{2}:\d{2}\s", line_clean):
                line_clean = line_clean[9:]
            yield f"{ts_clean}  {line_clean}\n".encode("utf-8", errors="replace")

    stamp = datetime.now().strftime("%Y%m%d-%H%M%S")
    fname = f"top-shelf-log-{stamp}.txt"
    return StreamingResponse(
        _iter(),
        media_type="text/plain; charset=utf-8",
        headers={"Content-Disposition": f'attachment; filename="{fname}"'},
    )


