def _directories_config_signature(dirs: list) -> tuple:
    """Stable comparison key for Settings library directory rows (type, path, rank, …)."""
    rows: list[tuple[str, str, str, int, str]] = []
    for d in dirs or []:
        if not isinstance(d, dict):
            continue
        raw = (d.get("path") or "").strip()
        try:
            norm = os.path.normcase(os.path.normpath(str(Path(raw).expanduser())))
        except Exception:
            norm = os.path.normpath(raw)
        t = (d.get("type") or "").strip().lower()
        lbl = (d.get("label") or "").strip()
        try:
            rk = int(d.get("rank") or 0)
        except (TypeError, ValueError):
            rk = 0
        gf = d.get("gender_filters")
        if isinstance(gf, list):
            gf_s = ",".join(sorted(str(x).lower() for x in gf if str(x).strip()))
        elif isinstance(gf, str) and gf.strip():
            gf_s = gf.strip()
        else:
            gf_s = ""
        rows.append((t, norm, lbl, rk, gf_s))
    rows.sort(key=lambda x: (x[3], x[1], x[2], x[0], x[4]))
    return tuple(rows)


def _library_roots_path_signature() -> tuple[str, ...]:
    """Sorted normalised paths for every root from ``_health_library_roots`` (settings + directories)."""
    try:
        roots = _health_library_roots()
    except Exception:
        return tuple()
    out: list[str] = []
    for r in roots:
        p = (r.get("path") or "").strip()
        if not p:
            continue
        try:
            out.append(os.path.normcase(os.path.normpath(str(Path(p).expanduser()))))
        except Exception:
            out.append(os.path.normpath(p))
    return tuple(sorted(out))


# Settings keys that must not be overwritten when the client posts an
# empty string (password inputs left blank, or a partial/failed page load).
_SETTINGS_SECRET_KEYS = frozenset({
    "api_key_tmdb", "api_key_stashdb", "api_key_tpdb", "api_key_fansdb", "api_key_javstash",
    "dl_nzb_pass", "dl_nzb_api_key", "dl_torrent_pass",
    "prowlarr_api_key",
    "stash_api_key", "jellyfin_api_key", "plex_token", "emby_api_key",
})


@app.post("/api/settings")
async def save_settings(payload: dict):
    settings = payload.get("settings", {})
    _old = db.get_settings()
    for _sk in _SETTINGS_SECRET_KEYS:
        if _sk not in settings:
            continue
        if str(settings.get(_sk) or "").strip():
            continue
        if (_old.get(_sk) or "").strip():
            settings[_sk] = _old[_sk]
    # Spotlight v2: `require` is only honored for `spotlight_gender_mode`
    # (a hard gate is needed to keep gender-mismatched results out of the
    # spotlight regardless of weighting). Every other mode setting that
    # carries `require` is downcast to `prefer`.
    for _k in list(settings.keys()):
        if _k.startswith("spotlight_") and _k.endswith("_mode") and _k != "spotlight_gender_mode":
            if (settings.get(_k) or "").strip().lower() == "require":
                settings[_k] = "prefer"
    # Detect membership-changing spotlight settings BEFORE the save so
    # we can compare incoming vs persisted. Any of these affects which
    # rows belong in the v2 cache — once changed, the cache must be
    # wiped + re-harvested so the next render reflects the new policy.
    # Soft (prefer-mode) edits don't trigger this path; they re-score
    # live against existing cache rows.
    def _norm_csv(raw: str | None) -> tuple[str, ...]:
        if not raw:
            return ()
        return tuple(sorted(p.strip().lower() for p in str(raw).split(",") if p.strip()))

    _membership_changed = False
    # Blacklist — any add/remove/reorder forces a wipe (entries that
    # WERE allowed may now be blocked, and vice versa).
    if "spotlight_studio_blacklist" in settings:
        if _norm_csv(_old.get("spotlight_studio_blacklist")) != _norm_csv(settings.get("spotlight_studio_blacklist")):
            _membership_changed = True
    # Preferred list — only matters for require mode (changes
    # membership). Prefer-mode is read-time so no wipe needed.
    new_pref_mode = (settings.get("spotlight_studio_preferred_mode") or _old.get("spotlight_studio_preferred_mode") or "prefer").lower()
    if "spotlight_studio_preferred" in settings:
        if new_pref_mode == "require":
            if _norm_csv(_old.get("spotlight_studio_preferred")) != _norm_csv(settings.get("spotlight_studio_preferred")):
                _membership_changed = True
    if "spotlight_studio_preferred_mode" in settings:
        old_pref_mode = (_old.get("spotlight_studio_preferred_mode") or "prefer").lower()
        # Mode swaps to/from require change membership.
        if (old_pref_mode == "require") != (new_pref_mode == "require"):
            _membership_changed = True
    # Tag mode — same logic: require shapes the API query, prefer is
    # purely a score bonus.
    new_tags_mode = (settings.get("spotlight_tags_mode") or _old.get("spotlight_tags_mode") or "require").lower()
    if "spotlight_tags" in settings and new_tags_mode == "require":
        if _norm_csv(_old.get("spotlight_tags")) != _norm_csv(settings.get("spotlight_tags")):
            _membership_changed = True
    if "spotlight_tags_mode" in settings:
        old_tags_mode = (_old.get("spotlight_tags_mode") or "require").lower()
        if (old_tags_mode == "require") != (new_tags_mode == "require"):
            _membership_changed = True
    # Per-source toggles: switching one off doesn't need a wipe (the
    # score-from-cache reader already filters by enabled set), but
    # switching one back ON should not refire either — eviction +
    # next-tick harvest covers it.
    _blacklist_changed = _membership_changed
    old_lr_sig = _library_roots_path_signature()
    db.save_settings(settings)
    # Only replace directory rows when the client sends ``directories``.
    # Defaulting to [] used to wipe the table on any partial POST that
    # omitted the key (scripts, older clients) — same symptoms as a UI
    # bug but unrelated to how Joyu was added.
    _dirs_changed = False
    _dirs = payload.get("directories")
    if _dirs is not None:
        new_dirs = _dirs if isinstance(_dirs, list) else []
        old_sig = _directories_config_signature(db.get_directories())
        new_sig = _directories_config_signature(new_dirs)
        db.save_directories(new_dirs)
        _dirs_changed = old_sig != new_sig
    new_lr_sig = _library_roots_path_signature()
    _roots_layout_changed = old_lr_sig != new_lr_sig
    _apply_retry_schedule()
    _apply_tpdb_sync_schedule()
    _apply_favourites_schedule()
    _apply_library_phash3_schedule()
    _apply_iafd_trickle_schedule()
    scheduler.add_job(_refresh_hourly_content_cache, "interval", hours=1, id="content_cache_refresh", replace_existing=True)
    _restart_watcher()
    _restart_download_watcher()
    # If any spotlight settings changed, drop both the in-memory buffer
    # AND the disk cache so the next request cold-fetches under the new
    # filters. Without this, the buffer keeps serving the old filter set
    # for up to 6 hours (next scheduled refresh) and the disk-cache
    # fallback in `_fetch_spotlight_performers` re-pulls stale entries
    # from previous filter runs that happen to also pass current hard
    # filters. The background refresh below pre-warms the new buffer so
    # the next page load doesn't pay the full fetch latency synchronously.
    if any(k.startswith("spotlight_") for k in settings):
        _SPOTLIGHT_LIB_LOOKUP_CACHE["ts"] = 0.0
        _SPOTLIGHT_LIB_LOOKUP_CACHE["data"] = None
        with _spotlight_cache_lock:
            _spotlight_cache["performers"] = []
            _spotlight_cache["fetched_at"] = 0.0
        try:
            db.spotlight_clear_top_cache()
        except Exception as e:
            _log.warning("spotlight_clear_top_cache on settings save: %s", e)
        # Studio blacklist change: also wipe the v2 raw-performer cache
        # (spotlight_performers). The cache rows were upserted under the
        # OLD blacklist so they could contain performers from studios
        # that are now on the block list; we don't store the studio
        # name per cached row, so we can't filter them out at read time
        # — easiest is a full wipe + fresh harvest. The
        # `_refresh_spotlight_cache` thread kicked below repopulates
        # via the scene-driven harvesters which apply the new blacklist.
        if _blacklist_changed:
            for _src in ("StashDB", "TPDB", "FansDB", "JAVStash"):
                try:
                    _cleared = db.spotlight_perf_clear_source(_src)
                    if _cleared:
                        _log.info(
                            "spotlight v2: cleared %s %s rows after blacklist change",
                            _cleared, _src,
                        )
                except Exception as e:
                    _log.warning("spotlight blacklist clear (%s): %s", _src, e)
            # Flip the first-scan flag back so the next tick re-seeds
            # every source in parallel rather than round-robining one
            # per tick. Without this the user would only see ONE source
            # repopulate immediately after a blacklist change; the
            # others would wait their turn in the rotation.
            try:
                db.save_settings({"spotlight_first_scan_done": "false"})
            except Exception as e:
                _log.warning("spotlight first-scan reset after blacklist change: %s", e)
        # Also reset the recent-served dampening map so the user's first
        # post-save page load isn't biased by the previous session's history.
        with _spotlight_recent_lock:
            _spotlight_recent.clear()
        threading.Thread(target=_refresh_spotlight_cache, daemon=True, name="spotlight-settings-refresh").start()
    # If monitored tags changed, warm the per-tag scene pools so the Tags
    # feed on /scenes has a deep pool to draw from immediately. Also sync
    # the on-disk vice folders — every monitored_tag is a Vice and each
    # one needs its folder under vices_dir so /library can display it.
    if "monitored_tags" in settings:
        threading.Thread(target=_refresh_tag_scene_pools, daemon=True, name="tag-pools-settings-refresh").start()
        threading.Thread(target=_sync_vice_folders, daemon=True, name="vice-folder-sync").start()
        threading.Thread(target=_fetch_missing_vice_logos, daemon=True, name="vice-logo-fetch").start()
    if _roots_layout_changed:
        def _resync_library_after_root_path_change() -> None:
            try:
                emit(
                    "SETTINGS: library root paths changed (series / features / vices / jav and/or "
                    "performer directory roots) — scanning Favourites, then running Library Index. "
                    "Rows in `library_files` still keyed by old absolute paths are marked removed "
                    "when the file is gone; files under the new roots are indexed."
                )
                favourites_scan_index(prune_missing=False, only_missing=True)
            except Exception as e:
                emit(f"Favourites re-scan after root-path change: {e}")
            try:
                run_library_index_job()
            except Exception as e:
                emit(f"Library index after root-path change: {e}")

        threading.Thread(
            target=_resync_library_after_root_path_change,
            daemon=True,
            name="library-resync-after-roots",
        ).start()
    elif _dirs_changed:

        def _favourites_rescan_after_dir_metadata_change() -> None:
            try:
                emit(
                    "FAVOURITES: performer directory list changed (paths unchanged) — "
                    "refreshing Favourites index rows."
                )
                favourites_scan_index(prune_missing=False, only_missing=True)
            except Exception as e:
                emit(f"FAVOURITES re-scan after directory metadata change: {e}")

        threading.Thread(
            target=_favourites_rescan_after_dir_metadata_change,
            daemon=True,
            name="favourites-scan-after-dirs",
        ).start()
    return {"saved": True}


def _search_tpdb_tags(query: str, *, limit: int = 25) -> list[dict]:
    """TPDB tag catalogue hits as ``{id, slug, name, source}``."""
    q = (query or "").strip()
    if len(q) < 2:
        return []
    try:
        r = requests.get(
            "https://api.theporndb.net/tags",
            params={"q": q, "per_page": str(limit)},
            headers=_tpdb_headers(),
            timeout=12,
        )
        if r.status_code != 200:
            return []
        out: list[dict] = []
        seen: set[str] = set()
        for t in (r.json() or {}).get("data") or []:
            if not isinstance(t, dict):
                continue
            tid = str(t.get("id") or t.get("_id") or "").strip()
            name = str(t.get("name") or "").strip()
            slug = str(t.get("slug") or "").strip()
            if not tid or not name or tid in seen:
                continue
            seen.add(tid)
            out.append({
                "id": tid,
                "slug": slug,
                "name": name,
                "source": "TPDB",
                "tpdb_id": tid,
            })
        return out
    except Exception as e:
        emit(f"tag search TPDB {q!r}: {e}")
        return []


def _search_stashdb_tags(query: str, *, limit: int = 25) -> list[dict]:
    """StashDB tag catalogue hits as ``{id, slug, name, source, stashdb_id}``."""
    q = (query or "").strip()
    if len(q) < 2:
        return []
    api_key = (db.get_settings().get("api_key_stashdb") or "").strip()
    if not api_key:
        return []
    gql = """
    query TagSearch($n: String!) {
      queryTags(input: {name: $n, page: 1, per_page: 25}) {
        tags { id name }
      }
    }
    """
    try:
        body = _stashbox_post(
            STASHDB_ENDPOINT,
            api_key,
            gql,
            {"n": q},
        )
        raw = ((body.get("queryTags") or {}).get("tags")) or []
        out: list[dict] = []
        seen: set[str] = set()
        for t in raw[:limit]:
            if not isinstance(t, dict):
                continue
            tid = str(t.get("id") or "").strip()
            name = str(t.get("name") or "").strip()
            if not tid or not name or tid in seen:
                continue
            seen.add(tid)
            out.append({
                "id": tid,
                "slug": "",
                "name": name,
                "source": "StashDB",
                "stashdb_id": tid,
            })
        return out
    except Exception as e:
        emit(f"tag search StashDB {q!r}: {e}")
        return []


def _search_stashbox_tags(endpoint: str, api_key: str, source: str, source_key: str,
                          query: str, *, limit: int = 25) -> list[dict]:
    """Generic Stash-box tag catalogue search (StashDB / FansDB / JAVStash share schema)."""
    q = (query or "").strip()
    if len(q) < 2 or not api_key:
        return []
    gql = """
    query TagSearch($n: String!) {
      queryTags(input: {name: $n, page: 1, per_page: 25}) {
        tags { id name }
      }
    }
    """
    try:
        body = _stashbox_post(endpoint, api_key, gql, {"n": q})
        raw = ((body.get("queryTags") or {}).get("tags")) or []
        out: list[dict] = []
        seen: set[str] = set()
        for t in raw[:limit]:
            if not isinstance(t, dict):
                continue
            tid = str(t.get("id") or "").strip()
            name = str(t.get("name") or "").strip()
            if not tid or not name or tid in seen:
                continue
            seen.add(tid)
            out.append({
                "id": tid,
                "slug": "",
                "name": name,
                "source": source,
                source_key: tid,
            })
        return out
    except Exception as e:
        emit(f"tag search {source} {q!r}: {e}")
        return []


def _search_fansdb_tags(query: str, *, limit: int = 25) -> list[dict]:
    api_key = (db.get_settings().get("api_key_fansdb") or "").strip()
    return _search_stashbox_tags(FANSDB_ENDPOINT, api_key, "FansDB", "fansdb_id", query, limit=limit)


def _search_javstash_tags(query: str, *, limit: int = 25) -> list[dict]:
    api_key = (db.get_settings().get("api_key_javstash") or "").strip()
    return _search_stashbox_tags(JAVSTASH_ENDPOINT, api_key, "JAVStash", "javstash_id", query, limit=limit)


# Source metadata used by the multi-source merger + frontend pills.
# Keep keys lowercase; UI labels are user-facing.
_TAG_SEARCH_SOURCES = (
    ("tpdb",     "TPDB",     "tpdb_id"),
    ("stashdb",  "StashDB",  "stashdb_id"),
    ("fansdb",   "FansDB",   "fansdb_id"),
    ("javstash", "JAVStash", "javstash_id"),
)


def _merge_multi_source_tag_search(hits_by_source: dict[str, list[dict]]) -> list[dict]:
    """Group TPDB/StashDB/FansDB/JAVStash hits by lowercase name.

    Returns one entry per name with ``sources[]`` populated by source key
    (lowercased) and the per-source id fields filled. Frontend renders
    one row per group with a pill per source plus an 'All' affordance.
    """
    by_name: dict[str, dict] = {}
    for source_key, _label, id_field in _TAG_SEARCH_SOURCES:
        for t in hits_by_source.get(source_key) or []:
            key = str(t.get("name") or "").strip().lower()
            if not key:
                continue
            grp = by_name.setdefault(key, {
                "name": str(t.get("name") or "").strip(),
                "slug": str(t.get("slug") or ""),
                "sources": [],
                "tpdb_id": "",
                "stashdb_id": "",
                "fansdb_id": "",
                "javstash_id": "",
            })
            sid = str(t.get(id_field) or t.get("id") or "").strip()
            if not sid:
                continue
            if source_key not in grp["sources"]:
                grp["sources"].append(source_key)
            if not grp[id_field]:
                grp[id_field] = sid
    return [by_name[k] for k in sorted(by_name.keys())]


@app.get("/api/settings/tag-search")
async def api_settings_tag_search(q: str = ""):
    """Search TPDB / StashDB / FansDB / JAVStash tag catalogues in parallel for vice / blacklist pickers."""
    query = (q or "").strip()
    if len(query) < 2:
        return {"tags": []}
    from concurrent.futures import ThreadPoolExecutor

    futures = {}
    with ThreadPoolExecutor(max_workers=4) as pool:
        futures["tpdb"]     = pool.submit(_search_tpdb_tags,     query)
        futures["stashdb"]  = pool.submit(_search_stashdb_tags,  query)
        futures["fansdb"]   = pool.submit(_search_fansdb_tags,   query)
        futures["javstash"] = pool.submit(_search_javstash_tags, query)
        hits: dict[str, list[dict]] = {}
        for k, f in futures.items():
            try:
                hits[k] = f.result() or []
            except Exception:
                hits[k] = []

    settings = db.get_settings()
    errors: list[str] = []
    key_map = {
        "tpdb":     "api_key_tpdb",
        "stashdb":  "api_key_stashdb",
        "fansdb":   "api_key_fansdb",
        "javstash": "api_key_javstash",
    }
    for src, settings_key in key_map.items():
        if not hits[src] and not (settings.get(settings_key) or "").strip():
            errors.append(f"no_{src}_key")
    return {
        "tags": _merge_multi_source_tag_search(hits),
        "errors": errors,
    }


@app.get("/api/settings/tpdb-tag-search")
async def api_settings_tpdb_tag_search(q: str = ""):
    """Legacy alias — combined TPDB + StashDB tag search."""
    return await api_settings_tag_search(q)


@app.get("/api/settings/stashdb-tag-search")
async def api_settings_stashdb_tag_search(q: str = ""):
    """Legacy alias — combined TPDB + StashDB tag search."""
    return await api_settings_tag_search(q)


def _resolve_tag_id_for_source(name: str, source: str) -> str:
    """Look up a tag's source-specific ID by name.

    Used by the click-to-blacklist / click-to-vice flows: when the
    user clicks a tag chip on a scene, we know the scene came from
    e.g. TPDB but the chip text carries no ID. Hitting the relevant
    source's tag-search and picking the case-insensitive exact name
    match gives us the canonical ID so the saved entry lands in the
    correct per-source bucket in Settings and the per-source filter
    set at runtime.

    Returns the resolved ID, or "" if nothing matched. Best-effort:
    any network/API failure returns "" so the caller can still save
    a name-only entry."""
    if not name or not source:
        return ""
    src = source.lower().strip()
    try:
        if src == "tpdb":
            hits = _search_tpdb_tags(name, limit=10)
        elif src == "stashdb":
            hits = _search_stashdb_tags(name, limit=10)
        elif src == "fansdb":
            hits = _search_fansdb_tags(name, limit=10)
        elif src == "javstash":
            hits = _search_javstash_tags(name, limit=10)
        else:
            return ""
    except Exception:
        return ""
    norm = name.strip().lower()
    for h in hits or []:
        if str(h.get("name") or "").strip().lower() == norm:
            return str(h.get(f"{src}_id") or h.get("id") or "").strip()
    return ""


@app.post("/api/settings/tag-blacklist/add")
async def api_tag_blacklist_add(payload: dict = Body(...)):
    """Append a single tag to the existing ``tag_blacklist`` setting.
    Used by the click-a-tag popup so a freeform overwrite of the
    whole list isn't required. The payload mirrors the picker entry
    shape: ``{name, tpdb_id?, stashdb_id?, fansdb_id?, javstash_id?,
    source?}``. When ``source`` is provided but the matching ``*_id``
    is blank, the backend resolves the canonical ID via the source's
    tag-search so the entry lands in the right per-source bucket."""
    name = str((payload or {}).get("name") or "").strip()
    if not name:
        return JSONResponse({"error": "name is required"}, status_code=400)
    source_hint = str((payload or {}).get("source") or "").strip().lower()
    settings = db.get_settings()
    raw = (settings.get("tag_blacklist") or "").strip()
    cur: list = []
    if raw.startswith("["):
        try:
            parsed = json.loads(raw)
            if isinstance(parsed, list):
                cur = parsed
        except Exception:
            cur = []
    elif raw:
        #: Legacy comma-separated format — promote to JSON list so the
        #: new entry's IDs can ride along on a per-source basis.
        cur = [{"name": x.strip()} for x in raw.split(",") if x.strip()]
    norm = name.strip().lower()
    found_idx = -1
    for i, e in enumerate(cur):
        if isinstance(e, dict):
            n = str(e.get("name") or "").strip().lower()
            if n == norm:
                found_idx = i
                break
    new_row = {
        "name":        name.strip(),
        "tpdb_id":     str((payload or {}).get("tpdb_id") or "").strip(),
        "stashdb_id":  str((payload or {}).get("stashdb_id") or "").strip(),
        "fansdb_id":   str((payload or {}).get("fansdb_id") or "").strip(),
        "javstash_id": str((payload or {}).get("javstash_id") or "").strip(),
    }
    matched_source = ""
    if source_hint and source_hint in ("tpdb", "stashdb", "fansdb", "javstash"):
        sid_key = f"{source_hint}_id"
        if not new_row[sid_key]:
            resolved = await run_in_threadpool(_resolve_tag_id_for_source, name, source_hint)
            if resolved:
                new_row[sid_key] = resolved
                matched_source = source_hint
        else:
            matched_source = source_hint
    #: Reject name-only entries — every saved blacklist row must carry
    #: at least one source ID so it sits inside a specific per-source
    #: bucket. Catalogue lookup failed → tell the user instead of
    #: silently saving an entry the filter won't reliably partition.
    if not any(new_row[k] for k in ("tpdb_id", "stashdb_id", "fansdb_id", "javstash_id")):
        return JSONResponse(
            {"error": f"could not resolve '{name}' against any source DB ({source_hint or 'no source given'})"},
            status_code=422,
        )
    added = False
    if found_idx >= 0:
        #: Merge: keep whichever source IDs are now known so a later
        #: click that knows the StashDB id can upgrade a TPDB-only row.
        existing = cur[found_idx] if isinstance(cur[found_idx], dict) else {"name": name}
        for k in ("tpdb_id", "stashdb_id", "fansdb_id", "javstash_id"):
            v = new_row.get(k) or existing.get(k) or ""
            existing[k] = v
        existing["name"] = name.strip()
        cur[found_idx] = existing
    else:
        cur.append(new_row)
        added = True
    db.save_settings({"tag_blacklist": json.dumps(cur)})
    return {"ok": True, "added": added, "count": len(cur), "matched_source": matched_source}


@app.post("/api/vices/add-tag")
async def api_vice_add_tag(payload: dict = Body(...)):
    """Append a tag to one specific vice's tag list without sending
    the entire vices array back. ``vice_name`` is required; the tag
    payload mirrors the standard picker row shape. Idempotent — if
    the tag already exists on that vice (by lowercase name) we
    merge IDs rather than duplicate."""
    vice_name = str((payload or {}).get("vice_name") or "").strip()
    tag_name = str((payload or {}).get("name") or "").strip()
    if not vice_name or not tag_name:
        return JSONResponse({"error": "vice_name and name are required"}, status_code=400)
    source_hint = str((payload or {}).get("source") or "").strip().lower()
    new_tag = {
        "name":        tag_name,
        "tpdb_id":     str((payload or {}).get("tpdb_id") or "").strip(),
        "stashdb_id":  str((payload or {}).get("stashdb_id") or "").strip(),
        "fansdb_id":   str((payload or {}).get("fansdb_id") or "").strip(),
        "javstash_id": str((payload or {}).get("javstash_id") or "").strip(),
    }
    matched_source = ""
    if source_hint and source_hint in ("tpdb", "stashdb", "fansdb", "javstash"):
        sid_key = f"{source_hint}_id"
        if not new_tag[sid_key]:
            resolved = await run_in_threadpool(_resolve_tag_id_for_source, tag_name, source_hint)
            if resolved:
                new_tag[sid_key] = resolved
                matched_source = source_hint
        else:
            matched_source = source_hint
    #: Reject name-only entries — vice tags must be source-anchored so
    #: they appear under the right per-source bucket in Settings and
    #: the tag-pool refresh job can crosswalk them cleanly.
    if not any(new_tag[k] for k in ("tpdb_id", "stashdb_id", "fansdb_id", "javstash_id")):
        return JSONResponse(
            {"error": f"could not resolve '{tag_name}' against any source DB ({source_hint or 'no source given'})"},
            status_code=422,
        )
    vices = _load_vices()
    target = None
    for v in vices:
        if str(v.get("name") or "").strip().lower() == vice_name.strip().lower():
            target = v
            break
    if not target:
        return JSONResponse({"error": f"vice not found: {vice_name}"}, status_code=404)
    tags = list(target.get("tags") or [])
    norm = tag_name.strip().lower()
    found = False
    for i, t in enumerate(tags):
        if isinstance(t, dict):
            tn = str(t.get("name") or "").strip().lower()
        elif isinstance(t, str):
            tn = t.strip().lower()
        else:
            continue
        if tn == norm:
            #: Merge IDs — same upgrade-on-better-info pattern as the
            #: tag-blacklist add endpoint.
            row = t if isinstance(t, dict) else {"name": tag_name}
            for k in ("tpdb_id", "stashdb_id", "fansdb_id", "javstash_id"):
                row[k] = new_tag.get(k) or row.get(k) or ""
            row["name"] = tag_name
            tags[i] = row
            found = True
            break
    if not found:
        tags.append(new_tag)
    target["tags"] = tags
    _save_vices(vices)
    threading.Thread(target=_refresh_tag_scene_pools, daemon=True, name="tag-pools-vice-add-tag").start()
    return {
        "ok": True,
        "added": (not found),
        "vice_name": target.get("name"),
        "tag_count": len(tags),
        "matched_source": matched_source,
    }


@app.post("/api/scenes/title-blacklist/add")
async def api_scene_title_blacklist_add(payload: dict = Body(...)):
    """Persist a per-scene title blacklist entry. The /scenes hover
    icon hits this with ``{title: "..."}``; the title is stored in
    the ``scene_title_blacklist`` JSON array as a normalised lowercase
    string so feed filtering can membership-test against a frozenset
    in O(1) per scene."""
    title = str((payload or {}).get("title") or "").strip()
    if not title:
        return JSONResponse({"error": "title is required"}, status_code=400)
    norm = title.lower()
    settings = db.get_settings()
    raw = (settings.get("scene_title_blacklist") or "").strip()
    try:
        cur = json.loads(raw) if raw else []
        if not isinstance(cur, list):
            cur = []
    except Exception:
        cur = []
    #: Preserve the original casing of the user's title — the membership
    #: check in ``_title_blacklist_normalized`` lowercases at read time,
    #: so storage can keep the original for display in Settings without
    #: changing match behaviour.
    existing: set[str] = set()
    cleaned: list = []
    for e in cur:
        if isinstance(e, dict):
            t_disp = str(e.get("title") or "").strip()
            t_norm = t_disp.lower()
            if t_norm and t_norm not in existing:
                existing.add(t_norm)
                cleaned.append({"title": t_disp, "added_at": e.get("added_at") or ""})
        elif isinstance(e, str):
            t_disp = e.strip()
            t_norm = t_disp.lower()
            if t_norm and t_norm not in existing:
                existing.add(t_norm)
                cleaned.append({"title": t_disp, "added_at": ""})
    added = False
    if norm not in existing:
        cleaned.append({"title": title, "added_at": datetime.now(timezone.utc).isoformat()})
        added = True
    db.save_settings({"scene_title_blacklist": json.dumps(cleaned)})
    return {"ok": True, "added": added, "count": len(cleaned)}


@app.post("/api/scenes/title-blacklist/remove")
async def api_scene_title_blacklist_remove(payload: dict = Body(...)):
    """Drop a title from the per-scene blacklist."""
    title = str((payload or {}).get("title") or "").strip().lower()
    if not title:
        return JSONResponse({"error": "title is required"}, status_code=400)
    settings = db.get_settings()
    raw = (settings.get("scene_title_blacklist") or "").strip()
    try:
        cur = json.loads(raw) if raw else []
        if not isinstance(cur, list):
            cur = []
    except Exception:
        cur = []
    kept: list = []
    removed = False
    for e in cur:
        if isinstance(e, dict):
            t_disp = str(e.get("title") or "").strip()
            ts = e.get("added_at", "")
        elif isinstance(e, str):
            t_disp = e.strip()
            ts = ""
        else:
            continue
        if t_disp.lower() == title:
            removed = True
            continue
        if t_disp:
            kept.append({"title": t_disp, "added_at": ts})
    db.save_settings({"scene_title_blacklist": json.dumps(kept)})
    return {"ok": True, "removed": removed, "count": len(kept)}


