@app.post("/api/search")
async def search_scenes(payload: dict):
    """
    Search the configured databases for scenes.
    Accepts: term (free text), title, performer, studio, date_from, date_to,
    sources (optional list — `["StashDB","TPDB","FansDB","IAFD"]`). When
    `sources` is provided only those listed are queried; omitted = all.
    """
    term      = payload.get("term", "").strip() or None
    title     = payload.get("title", "").strip() or None
    performer = payload.get("performer", "").strip() or None
    studio    = payload.get("studio", "").strip() or None
    date_from = payload.get("date_from", "").strip() or None
    date_to   = payload.get("date_to", "").strip() or None
    sources_in = payload.get("sources")
    sources_filter: set[str] | None = None
    if isinstance(sources_in, list) and sources_in:
        sources_filter = {str(s).strip().upper() for s in sources_in if str(s).strip()}

    if not any([term, title, performer, studio, date_from, date_to]):
        return JSONResponse({"error": "Provide at least one search field"}, status_code=400)

    try:
        results = search_all_databases(
            term=term, title=title, performer=performer,
            studio=studio, date_from=date_from, date_to=date_to,
            sources=sources_filter,
        )
        # Format for UI
        formatted = []
        for scene in results:
            perf_names = [p["performer"]["name"] for p in scene.get("performers", [])]
            src = scene.get("_source", "")
            # IAFD rows carry their own detail URL — ship it to the
            # frontend so the "View ↗" link points at the IAFD page
            # instead of the stash-box fallback URL.
            view_url = scene.get("_iafd_url") if src == "IAFD" else None
            #: Duration is seconds on stash-box sources; IAFD doesn't
            #: expose it so ``scene.get('duration')`` is None there.
            dur_raw = scene.get("duration")
            try:
                duration_s = int(dur_raw) if dur_raw else 0
            except (TypeError, ValueError):
                duration_s = 0
            formatted.append({
                "id":          scene.get("id"),
                "title":       scene.get("title") or "Unknown",
                "studio":      (scene.get("studio") or {}).get("name") or "Unknown",
                "date":        scene.get("release_date") or "",
                "performers":  ", ".join(perf_names),
                "performer_count": len(perf_names),
                "duration":    duration_s,
                "code":        (scene.get("code") or "").strip(),
                "source":      src,
                "image":       best_image_url(scene.get("images") or []),
                "view_url":    view_url,
                "_raw":        scene,
            })
        return {"results": formatted, "count": len(formatted)}
    except Exception as e:
        return JSONResponse({"error": str(e)}, status_code=500)


@app.post("/api/iafd/scene-performers")
async def api_iafd_scene_performers(payload: dict):
    """Fetch the IAFD title page for a given URL and return its cast in
    stash-box shape, plus the per-scene breakdown table if the page has
    one. The /downloads queue-search confirm modal calls this before
    filing so the user can review/prune the list — IAFD pages are
    movies, so filing a single scene needs both (a) the movie-level
    cast as a fallback and (b) the breakdown so the user can pick the
    exact scene without inheriting everyone from the comp. Also
    returns the IAFD page's free-text synopsis so the scene popup can
    populate its plot/description field — IAFD search results carry
    only title/year/studio, so the synopsis only becomes available
    after this detail fetch."""
    url = (payload.get("url") or "").strip()
    if not url:
        return JSONResponse({"error": "url is required"}, status_code=400)
    performers = await run_in_threadpool(_iafd_scene_detail_performers, url)
    scenes = await run_in_threadpool(_iafd_scene_breakdowns, url)
    synopsis = await run_in_threadpool(_iafd_scene_synopsis, url)
    return {"performers": performers, "scenes": scenes, "synopsis": synopsis}


#: Live progress for the in-flight bulk scan — polled by the
#: scanning modal so the user can see "43 / 109 · 39%" tick by
#: rather than staring at a plain spinner. Updated from the
#: progress_cb inside _iafd_bulk_scan_for_performer. Reset on each
#: new scan so stale totals don't show after a re-run.
_iafd_bulk_scan_state: dict = {
    "running": False,
    "total": 0,
    "done": 0,
    "current": "",
    "performer": "",
}
_iafd_bulk_scan_state_lock = threading.Lock()


@app.get("/api/iafd/bulk-scan-status")
async def api_iafd_bulk_scan_status():
    with _iafd_bulk_scan_state_lock:
        return dict(_iafd_bulk_scan_state)


@app.get("/api/iafd/trickle-status")
async def api_iafd_trickle_status():
    """Expose the background enrichment worker's current state — lets
    a future settings UI surface "last run at, last performer scraped,
    N/total library performers enriched" without touching the DB
    directly. Cheap to poll (in-memory state + 1 COUNT)."""
    s = db.get_settings()
    enabled = (s.get("iafd_trickle_enabled") or "false").strip().lower() == "true"
    try:
        interval = int(s.get("iafd_trickle_interval_minutes") or "5")
    except (ValueError, TypeError):
        interval = 5
    try:
        refresh_days = int(s.get("iafd_trickle_refresh_days") or "30")
    except (ValueError, TypeError):
        refresh_days = 30
    #: APScheduler exposes .next_run_time on the Job so the UI can
    #: render "next scrape in N minutes" without us maintaining a
    #: parallel timer.
    next_run = ""
    try:
        job = scheduler.get_job("iafd_trickle")
        if job and job.next_run_time:
            next_run = job.next_run_time.isoformat(timespec="seconds")
    except Exception:
        pass
    try:
        persisted = db.iafd_performer_count()
    except Exception:
        persisted = 0
    with _iafd_trickle_state_lock:
        last = dict(_iafd_trickle_state)
    return {
        "enabled":           enabled,
        "interval_minutes":  interval,
        "refresh_days":      refresh_days,
        "next_run":          next_run,
        "persisted_count":   persisted,
        "unresolvable_names": sorted(_iafd_trickle_fail_names),
        **last,
    }


@app.post("/api/iafd/bulk-scan")
async def api_iafd_bulk_scan(payload: dict):
    """Bulk-match a batch of queue filenames against IAFD for a
    single performer. Frontend passes the performer name and the
    filenames it believes contain them (derived from the existing
    queue-row `performers` field). We parse each filename, run the
    IAFD search pipeline, take the top result, and pull scene
    breakdowns — returning groups keyed by IAFD movie URL so files
    from the same comp surface together in the UI.

    This is deliberately synchronous-per-request: the frontend shows
    a spinner while the scan runs. Progress is emitted to the log
    so users can watch big scans (50+ files) tick through.
    """
    performer = (payload.get("performer") or "").strip()
    filenames = payload.get("filenames") or []
    if not performer:
        return JSONResponse({"error": "performer is required"}, status_code=400)
    if not isinstance(filenames, list) or not filenames:
        return JSONResponse({"error": "filenames list is required"}, status_code=400)

    def _emit_progress(done: int, total: int, fname: str) -> None:
        if total <= 0:
            return
        if fname:
            emit(f"IAFD bulk-scan ({done + 1}/{total}): {fname[:80]}")
        else:
            emit(f"IAFD bulk-scan complete: {done}/{total}")
        with _iafd_bulk_scan_state_lock:
            _iafd_bulk_scan_state.update({
                "done": done,
                "total": total,
                "current": fname or "",
            })

    emit(f"IAFD bulk-scan: performer='{performer}' files={len(filenames)}")
    with _iafd_bulk_scan_state_lock:
        _iafd_bulk_scan_state.update({
            "running": True,
            "total": len(filenames),
            "done": 0,
            "current": "",
            "performer": performer,
        })
    try:
        groups = await run_in_threadpool(
            _iafd_bulk_scan_for_performer,
            performer,
            filenames,
            _emit_progress,
        )
    finally:
        with _iafd_bulk_scan_state_lock:
            _iafd_bulk_scan_state["running"] = False
            _iafd_bulk_scan_state["current"] = ""
    return {"performer": performer, "groups": groups}


#: Shared bookkeeping for the IAFD bulk-file background task so
#: /api/iafd/bulk-file-status can surface per-item progress to the
#: client without polling /api/status (which only exposes the
#: coarse running/not-running flag). Re-used across calls: we stash
#: the latest run's progress here until the next bulk-file starts.
_iafd_bulk_file_state: dict = {
    "running": False,
    "total": 0,
    "done": 0,
    "current": "",
    "results": [],  # list of {filename, status, error?}
}
_iafd_bulk_file_lock = threading.Lock()


@app.post("/api/iafd/bulk-file")
async def api_iafd_bulk_file(payload: dict, background_tasks: BackgroundTasks):
    """File a list of manually-matched scenes sequentially.

    The per-file ``/api/file/manual`` path races when called in a
    tight loop because ``processing_state['running']`` is set by a
    background task that hasn't started yet when the endpoint
    returns — the next call arrives, finds the flag clear, starts
    its own task, and both end up contending for the pipeline lock
    (409s on everything after the first). This endpoint processes
    the whole batch inside a single background task so the lock is
    held for the entire run and each file files cleanly in turn.
    """
    if processing_state["running"]:
        return JSONResponse({"error": "Pipeline already running"}, status_code=409)
    with _iafd_bulk_file_lock:
        if _iafd_bulk_file_state["running"]:
            return JSONResponse({"error": "Bulk filing already running"}, status_code=409)
    items = payload.get("items") or []
    if not isinstance(items, list) or not items:
        return JSONResponse({"error": "items list is required"}, status_code=400)

    #: Snapshot settings + validate every item up-front so we don't
    #: start the background task only to error out on the first file.
    settings = db.get_settings()
    source_dir = Path(settings.get("source_dir", ""))
    if not source_dir.exists():
        return JSONResponse({"error": f"Source dir not found: {source_dir}"}, status_code=500)
    prepared: list[tuple[str, Path, dict]] = []
    for it in items:
        if not isinstance(it, dict):
            continue
        filename = (it.get("filename") or "").strip()
        scene = it.get("scene")
        if not filename or not isinstance(scene, dict):
            continue
        video = source_dir / filename
        if not video.is_file():
            continue
        prepared.append((filename, video, scene))
    if not prepared:
        return JSONResponse({"error": "no valid items to file"}, status_code=400)

    with _iafd_bulk_file_lock:
        _iafd_bulk_file_state.update({
            "running": True,
            "total": len(prepared),
            "done": 0,
            "current": "",
            "results": [],
        })

    def run():
        processing_state["running"] = True
        processing_state["log"] = []
        processing_state["pipeline_total"] = len(prepared)
        processing_state["pipeline_done"] = 0
        try:
            for filename, video, scene in prepared:
                processing_state["current_file"] = filename
                with _iafd_bulk_file_lock:
                    _iafd_bulk_file_state["current"] = filename
                item_result: dict = {"filename": filename, "status": "", "error": ""}
                try:
                    #: Auto-enrich IAFD scenes missing cast (mirrors the
                    #: single-file flow in /api/file/manual) so the
                    #: filer can route even when the scanner returned
                    #: no breakdown.
                    iafd_url = (scene.get("_iafd_url") or "").strip()
                    if not iafd_url and isinstance(scene.get("id"), str) and scene["id"].startswith("iafd:"):
                        iafd_url = scene["id"][len("iafd:"):]
                    if iafd_url and not (scene.get("performers") or []):
                        scene["performers"] = _iafd_scene_detail_performers(iafd_url)
                    db.upsert_file(filename)
                    emit(f"FILE {filename}")
                    emit("  Source: manual selection (bulk)")
                    result = file_scene_from_match(video, scene, source="Manual")
                    status = (result or {}).get("status") or "unknown"
                    item_result["status"] = status
                    if status not in ("filed", "ok"):
                        item_result["error"] = (result or {}).get("error") or status
                    emit(f"  Result: {status}")
                except Exception as e:
                    item_result["status"] = "error"
                    item_result["error"] = str(e)
                    emit(f"  ERROR: {e}")
                with _iafd_bulk_file_lock:
                    _iafd_bulk_file_state["done"] += 1
                    _iafd_bulk_file_state["results"].append(item_result)
                processing_state["pipeline_done"] += 1
                emit("---")
        finally:
            processing_state["running"] = False
            processing_state["current_file"] = None
            processing_state["pipeline_total"] = 0
            processing_state["pipeline_done"] = 0
            with _iafd_bulk_file_lock:
                _iafd_bulk_file_state["running"] = False
                _iafd_bulk_file_state["current"] = ""

    background_tasks.add_task(run)
    return {"started": True, "total": len(prepared)}


@app.get("/api/iafd/bulk-file-status")
async def api_iafd_bulk_file_status():
    """Poll endpoint for the bulk-file UI — returns running flag,
    done/total counts, the current filename, and per-item results
    so the modal can tick filed rows off as each one completes."""
    with _iafd_bulk_file_lock:
        return {
            "running": _iafd_bulk_file_state["running"],
            "total":   _iafd_bulk_file_state["total"],
            "done":    _iafd_bulk_file_state["done"],
            "current": _iafd_bulk_file_state["current"],
            "results": list(_iafd_bulk_file_state["results"]),
        }


@app.post("/api/queue/delete")
async def queue_delete_file(payload: dict):
    """Delete a source video from disk (with its associated sidecars).

    The queue UI exposes this for files the user decides to drop —
    e.g. corrupt files, unwanted extras bundled in a release, or
    phash-matched dupes. Scoped strictly to ``source_dir`` so a
    malformed filename can't escape the download folder. After the
    unlink we mark the processed_files row as ``removed`` so the row
    disappears from the queue on the next refresh.
    """
    filename = (payload.get("filename") or "").strip()
    if not filename:
        return JSONResponse({"error": "filename is required"}, status_code=400)
    r = await run_in_threadpool(_queue_delete_filename_sync, filename)
    if not r.get("ok"):
        return JSONResponse({"error": r.get("error") or "delete failed"}, status_code=400)
    return {
        "deleted": bool(r.get("deleted")),
        "already_missing": bool(r.get("already_missing")),
        "filename": filename,
    }


@app.get("/api/queue/thumbs")
async def api_queue_thumbs(filename: str, data: int = 0):
    """Return the current filmstrip state for a queue file. Frames are
    taken at 10/30/50/70/90 % so we skip the typical intro/outro.
    Output: ``{thumbs:[{i,url,percent,data_url?}], count, ready,
    generating, backoff, retry_at}``.

    Non-blocking: when frames are missing, dispatches the async prewarm
    (which runs gated through ``_queue_thumb_semaphore`` and respects
    the 1h backoff for files ffmpeg can't decode) and returns whatever's
    already on disk. The frontend polls until ``ready`` or ``backoff``
    flips. Prior versions blocked the request inside
    ``_ensure_queue_thumbs``, so one slow file (or any file already in
    backoff) would freeze the popup for up to ~150s.

    Pass ``?data=1`` to inline each frame as a ``data:image/jpeg;base64,…``
    string under ``data_url`` — manual search uses that so a picked
    frame can be POSTed straight to ``/api/file/manual``'s
    ``thumb_data_url`` field.
    """
    filename = (filename or "").strip()
    if not filename:
        return JSONResponse({"error": "filename is required"}, status_code=400)
    want_data = bool(data)

    def _build_items() -> list[dict]:
        items: list[dict] = []
        for i in range(QUEUE_THUMB_COUNT):
            p = _queue_thumb_path(filename, i)
            if p.is_file() and p.stat().st_size > 0:
                mt = int(p.stat().st_mtime)
                entry: dict = {
                    "i": i,
                    "percent": QUEUE_THUMB_PERCENTS[i],
                    "url": f"/api/queue/thumb?filename={quote(filename, safe='')}&i={i}&v={mt}",
                }
                if want_data:
                    try:
                        import base64 as _b64
                        entry["data_url"] = (
                            "data:image/jpeg;base64,"
                            + _b64.b64encode(p.read_bytes()).decode()
                        )
                    except OSError as exc:
                        emit(f"queue thumb b64 encode failed for {filename!r} i={i}: {exc}")
                items.append(entry)
        return items

    items = await run_in_threadpool(_build_items) if want_data else _build_items()
    ready = len(items) == QUEUE_THUMB_COUNT
    generating = False
    backoff = False
    retry_at: float | None = None
    if not ready:
        # Surface backoff so the UI can stop polling and show a Retry
        # button instead of spinning forever on a file ffmpeg already
        # gave up on.
        with _queue_thumb_backoff_lock:
            expiry = _queue_thumb_backoff.get(filename)
        now = time.time()
        if expiry is not None and expiry > now:
            backoff = True
            retry_at = expiry
        else:
            # Dedup'd dispatch — if a prewarm thread is already running
            # for this file the second call is a no-op, so polling stays
            # cheap. ``interactive=True`` routes through the foreground
            # semaphore + parallel fan-out so the popup gets the strip
            # quickly even when the snapshot loop is grinding through
            # the background queue.
            _prewarm_queue_thumbs_async(filename, interactive=True)
            generating = True
    return {
        "filename":   filename,
        "thumbs":     items,
        "count":      len(items),
        "ready":      ready,
        "generating": generating,
        "backoff":    backoff,
        "retry_at":   retry_at,
    }


@app.post("/api/queue/thumbs/retry")
async def api_queue_thumbs_retry(payload: dict):
    """Clear the 1h backoff entry for *filename* and re-dispatch the
    async prewarm. Lets the user recover a stuck filmstrip from the UI
    instead of waiting for the backoff to expire on its own."""
    filename = (payload.get("filename") or "").strip()
    if not filename:
        return JSONResponse({"error": "filename is required"}, status_code=400)
    with _queue_thumb_backoff_lock:
        cleared = _queue_thumb_backoff.pop(filename, None) is not None
    if cleared:
        try: emit(f"queue thumbs: backoff cleared for {filename!r} (user retry)")
        except Exception: pass
    # User just hit Retry — treat as foreground.
    _prewarm_queue_thumbs_async(filename, interactive=True)
    return {"filename": filename, "cleared": cleared, "generating": True}


@app.get("/api/queue/thumb")
async def api_queue_thumb(filename: str, i: int, v: int = 0):
    """Serve a single cached frame from the filmstrip. Caller passes
    the index returned by ``/api/queue/thumbs`` plus the cache-bust
    ``v`` (mtime). Generates the frame on the fly if it isn't cached
    yet so a direct hit (e.g. user opens the URL in a new tab)
    still works."""
    filename = (filename or "").strip()
    if not filename or i < 0 or i >= QUEUE_THUMB_COUNT:
        return JSONResponse({"error": "bad request"}, status_code=400)
    p = _queue_thumb_path(filename, i)
    if not p.is_file() or p.stat().st_size == 0:
        await run_in_threadpool(_ensure_queue_thumbs, filename)
    if not p.is_file() or p.stat().st_size == 0:
        return JSONResponse({"error": "no thumb"}, status_code=404)
    return FileResponse(
        p,
        media_type="image/jpeg",
        headers={"Cache-Control": "private, max-age=3600"},
    )


@app.post("/api/file/manual")
async def file_manual(payload: dict, background_tasks: BackgroundTasks):
    """
    File a specific video using a manually selected scene rather than phash lookup.
    Accepts: filename (str), scene (dict matching stash-box scene shape)
    """
    if processing_state["running"]:
        return JSONResponse({"error": "Pipeline already running"}, status_code=409)

    filename = payload.get("filename", "").strip()
    scene    = payload.get("scene")
    submit_stashdb = bool(payload.get("submit_stashdb"))

    if not filename or not scene:
        return JSONResponse({"error": "filename and scene are required"}, status_code=400)

    settings = db.get_settings()
    source_dir = Path(settings.get("source_dir", ""))
    video = source_dir / filename

    if not video.exists():
        return JSONResponse({"error": f"File not found: {filename}"}, status_code=404)

    #: IAFD comprehensive-search results ship without a performers list
    #: (the page only has title/year/studio). Without cast the filer
    #: can't route into a performer folder, so lazy-fetch the title
    #: page here and backfill before kicking off filing. Cheap — one
    #: HTTP request per "Use this" click, only when needed.
    iafd_url = (scene.get("_iafd_url") or "").strip()
    if not iafd_url and isinstance(scene.get("id"), str) and scene["id"].startswith("iafd:"):
        iafd_url = scene["id"][len("iafd:"):]
    if iafd_url and not (scene.get("performers") or []):
        scene["performers"] = _iafd_scene_detail_performers(iafd_url)

    def run():
        processing_state["running"] = True
        processing_state["log"] = []
        processing_state["pipeline_total"] = 1
        processing_state["pipeline_done"] = 0
        processing_state["current_file"] = filename
        try:
            db.upsert_file(filename)
            emit(f"FILE {filename}")
            emit("  Source: manual selection")
            result = file_scene_from_match(video, scene, source="Manual")
            emit(f"  Result: {result.get('status')}")
            if submit_stashdb:
                _submit_manual_scene_to_stashdb(scene, filename)
        except Exception as e:
            emit(f"  ERROR: {e}")
        finally:
            processing_state["running"] = False
            processing_state["current_file"] = None
            processing_state["pipeline_total"] = 0
            processing_state["pipeline_done"] = 0
            emit("---")

    background_tasks.add_task(run)
    return {"started": True, "filename": filename}


def _submit_manual_scene_to_stashdb(scene: dict, filename: str) -> None:
    """Best-effort push of a manually-selected scene up to StashDB.

    Called from the /api/file/manual background task when the user
    ticks "Submit to StashDB". We resolve studio + performer names
    against StashDB first — the submit API needs IDs, not names — and
    only post if every name matches exactly. Anything less and we'd
    create a half-baked scene with a missing performer slot, which is
    worse than nothing. Failures log and return quietly so the filing
    itself is never held up.
    """
    settings = db.get_settings()
    api_key = settings.get("api_key_stashdb", "")
    if not api_key:
        emit("  Submit-StashDB skipped: no StashDB API key configured")
        return
    title = (scene.get("title") or "").strip()
    date = (scene.get("release_date") or scene.get("date") or "").strip()
    studio_name = ""
    studio_raw = scene.get("studio")
    if isinstance(studio_raw, dict):
        studio_name = (studio_raw.get("name") or "").strip()
    elif isinstance(studio_raw, str):
        studio_name = studio_raw.strip()
    performer_names = []
    for p in (scene.get("performers") or []):
        if isinstance(p, dict):
            inner = p.get("performer") if isinstance(p.get("performer"), dict) else p
            name = (inner.get("name") or "").strip()
            if name:
                performer_names.append(name)
    if not (title and date and studio_name and performer_names):
        emit("  Submit-StashDB skipped: missing title/date/studio/performers")
        return
    try:
        studio_matches = stashdb_search_studio(studio_name, api_key)
        studio_id = next(
            (m["id"] for m in studio_matches if m["name"].lower() == studio_name.lower()),
            None,
        )
        if not studio_id:
            emit(f"  Submit-StashDB skipped: studio '{studio_name}' has no exact match on StashDB")
            return
        performer_ids: list[str] = []
        for pname in performer_names:
            matches = stashdb_search_performer(pname, api_key)
            pid = next(
                (m["id"] for m in matches if m["name"].lower() == pname.lower()),
                None,
            )
            if not pid:
                emit(f"  Submit-StashDB skipped: performer '{pname}' has no exact match on StashDB")
                return
            performer_ids.append(pid)
        phash = db.get_phash(filename) if filename else None
        duration = 0
        try:
            dur = get_video_duration(video := (Path(settings.get("source_dir", "")) / filename))
            if dur:
                duration = int(dur)
        except Exception:
            pass
        image_url = ""
        imgs = scene.get("images") or []
        if imgs and isinstance(imgs[0], dict):
            image_url = imgs[0].get("url") or ""
        elif isinstance(scene.get("image"), str):
            image_url = scene["image"]
        result = stashdb_submit_scene(
            title=title,
            date=date,
            studio_id=studio_id,
            performer_ids=performer_ids,
            phash=phash,
            details=(scene.get("details") or ""),
            image_url=image_url,
            api_key=api_key,
            duration=duration,
        )
        if isinstance(result, dict) and result.get("error"):
            emit(f"  Submit-StashDB error: {result['error']}")
        else:
            emit(f"  Submit-StashDB ok: {title}")
    except Exception as exc:
        emit(f"  Submit-StashDB failed: {exc}")


