@app.post("/api/performers/fetch-ext-links")
async def api_performers_fetch_ext_links(payload: dict = Body(...)):
    """Manually re-fetch IAFD/Freeones/Babepedia links from a performer's stored DB IDs.
    Stores any links not already set and returns what was found/stored.
    """
    try:
        row_id = int(payload.get("row_id") or 0)
    except (TypeError, ValueError):
        return JSONResponse({"error": "bad row_id"}, status_code=400)
    row = db.favourite_get(row_id)
    if not row or row.get("kind") != "performer":
        return JSONResponse({"error": "Not found"}, status_code=404)
    mt_id = (row.get("match_tpdb_id") or "").strip() or None
    ms_id = (row.get("match_stashdb_id") or "").strip() or None
    mf_id = (row.get("match_fansdb_id") or "").strip() or None
    if not (mt_id or ms_id or mf_id):
        return {"found": {}, "stored": {}, "skipped": "no_db_ids"}
    ext = await run_in_threadpool(_fetch_performer_ext_links_from_db_ids, mt_id, ms_id, mf_id)
    stored: dict[str, str] = {}
    # TMDB: stored in match_tmdb_id
    tmdb_id = ext.get("tmdb")
    if tmdb_id and not (row.get("match_tmdb_id") or "").strip():
        try:
            db.favourite_set_ext_link(row_id, "tmdb", tmdb_id)
            stored["tmdb"] = tmdb_id
        except Exception:
            pass
    mj_id = (row.get("match_javstash_id") or "").strip() or None
    if mj_id:
        for k, v in _fetch_performer_ext_links_from_javstash(mj_id).items():
            if k not in ext:
                ext[k] = v
    for site in ("iafd", "freeones", "babepedia", "coomer", "javdatabase"):
        url = ext.get(site)
        if url and not (row.get(f"match_{site}_url") or "").strip():
            try:
                db.favourite_set_ext_link(row_id, site, url)
                stored[site] = url
            except Exception:
                pass
    if mj_id and not (row.get("match_javdatabase_url") or "").strip():
        _try_auto_link_javdatabase(row_id, dict(row))
    return {"found": ext, "stored": stored}


def _ext_link_url_search_hit(site: str, q: str, fallback_name: str) -> list[dict]:
    """When the user pastes a profile URL (or TMDB numeric id), return a single selectable hit."""
    s = _ext_site_key(site)
    raw = (q or "").strip()
    if not raw:
        return []
    label = (fallback_name or "").strip() or raw
    if s == "tmdb":
        m = re.search(r"/person/(\d+)", raw)
        pid = m.group(1) if m else (raw if re.fullmatch(r"\d+", raw) else "")
        if not pid:
            return []
        url = f"https://www.themoviedb.org/person/{pid}"
        return [{"name": label, "url": url, "thumb_url": _ext_link_preview_thumb(s, pid)}]
    if s == "javdatabase":
        hit = _javdatabase_hit_from_url(raw)
        if not hit:
            return []
        hit["thumb_url"] = _ext_link_preview_thumb(s, hit.get("url") or raw)
        return [hit]
    if re.match(r"^https?://", raw, re.I):
        return [{"name": label, "url": raw, "thumb_url": _ext_link_preview_thumb(s, raw)}]
    return []


@app.post("/api/performers/search-ext-link")
async def api_performers_search_ext_link(payload: dict = Body(...)):
    """Search IAFD or Freeones by performer name for candidate profile links."""
    try:
        row_id = int(payload.get("row_id") or 0)
    except (TypeError, ValueError):
        return JSONResponse({"error": "bad row_id"}, status_code=400)
    site = _ext_site_key(payload.get("site") or "")
    if not row_id or not site:
        return JSONResponse({"error": "row_id and site required"}, status_code=400)
    row = db.favourite_get(row_id)
    if not row or row.get("kind") != "performer":
        return JSONResponse({"error": "Not found"}, status_code=404)
    name = (payload.get("q") or payload.get("name") or row.get("folder_name") or "").strip()
    if not name:
        return {"results": []}
    if re.match(r"^https?://", name, re.I) or (site == "tmdb" and re.fullmatch(r"\d+", name)):
        results = await run_in_threadpool(
            _ext_link_url_search_hit, site, name, row.get("folder_name") or ""
        )
        return {"results": results}
    if site == "tmdb":
        results = await run_in_threadpool(_tmdb_person_search, name)
    elif site == "iafd":
        opts = await run_in_threadpool(_iafd_performer_query, name)
        results = [
            {"name": o.get("name", name), "url": o["urls"][0], "thumb_url": o.get("thumb_url") or None}
            for o in opts
            if o.get("urls")
        ]
    elif site == "freeones":
        results = await run_in_threadpool(_freeones_performer_search, name)
    elif site == "babepedia":
        results = await run_in_threadpool(_babepedia_performer_search, name)
    elif site == "javdatabase":
        # JAVStash is needed for AUTO-linking (canonical romanized name as
        # source-of-truth for the slug), but not for manual search — the
        # user is typing the query themselves and visually picking. Gating
        # the manual picker on JAVStash blocks legitimate searches like
        # "Saho Shinozaki" → /idols/saho-shinozaki/ when the performer
        # hasn't been linked to JAVStash yet.
        qnames: list[str] = []
        for cand in (name, (row.get("folder_name") or "").strip(), (row.get("match_javstash_name") or "").strip()):
            c = (cand or "").strip()
            if c and c not in qnames:
                qnames.append(c)
        results = await run_in_threadpool(_javdatabase_search_merged, qnames)
    else:
        return JSONResponse(
            {"error": "site must be tmdb, iafd, freeones, babepedia, or javdatabase"},
            status_code=400,
        )
    return {"results": results}


_EXT_LINKS_ENRICH_RUNNING = threading.Event()
_EXT_LINKS_ENRICH_PROGRESS: dict = {"total": 0, "done": 0, "current": "", "running": False}


def _background_enrich_all_ext_links() -> None:
    """Bulk backfill in two phases:
    Phase 1 — fetch IAFD/Freeones/Babepedia URLs from TPDB/StashDB/FansDB cross-references.
    Phase 2 — scrape headshots for all performers that still have none.
    Rate-limited with small sleeps. Safe to call at any time.
    """
    global _EXT_LINKS_ENRICH_PROGRESS
    if _EXT_LINKS_ENRICH_RUNNING.is_set():
        return
    _EXT_LINKS_ENRICH_RUNNING.set()
    try:
        all_rows = [r for r in db.favourite_list() if r.get("kind") == "performer"]

        # Phase 1: ext links from DB cross-references
        eligible_links = [r for r in all_rows if (
            (r.get("match_tpdb_id") or "").strip()
            or (r.get("match_stashdb_id") or "").strip()
            or (r.get("match_fansdb_id") or "").strip()
            or (r.get("match_javstash_id") or "").strip()
        )]
        # Phase 2: headshots for performers without any image
        def _needs_headshot(r: dict) -> bool:
            rid = int(r["id"])
            if _performers_custom_ref_resolve(rid):
                return False
            meta = _performers_iafd_read_meta(rid)
            return not (meta and (meta.get("image_files") or []))

        eligible_heads = [r for r in all_rows if _needs_headshot(r)]

        # Phase 3: posters for performers missing poster images
        def _needs_posters(r):
            return _perf_poster_resolve(int(r["id"]), "poster_secondary") is None
        eligible_posters = [r for r in all_rows if _needs_posters(r)]

        total = len(eligible_links) + len(eligible_heads) + len(eligible_posters)
        _EXT_LINKS_ENRICH_PROGRESS = {
            "total": total, "done": 0, "current": "", "phase": "links", "running": True
        }

        # --- Phase 1 ---
        for row in eligible_links:
            rid = int(row["id"])
            name = row.get("folder_name") or str(rid)
            _EXT_LINKS_ENRICH_PROGRESS["current"] = f"[links] {name}"
            mt_id = (row.get("match_tpdb_id") or "").strip() or None
            ms_id = (row.get("match_stashdb_id") or "").strip() or None
            mf_id = (row.get("match_fansdb_id") or "").strip() or None
            mj_id = (row.get("match_javstash_id") or "").strip() or None
            meta_now = _performers_iafd_read_meta(rid)
            missing_links = not all([
                (row.get("match_tmdb_id") or "").strip(),
                (row.get("match_iafd_url") or "").strip(),
                (row.get("match_freeones_url") or "").strip(),
                (row.get("match_javdatabase_url") or "").strip(),
            ])
            missing_bio = not (meta_now and meta_now.get("bio"))
            if missing_links or missing_bio:
                try:
                    _sync_performer_tmdb_link_from_meta(rid)
                    ext = _fetch_performer_ext_links_from_db_ids(mt_id, ms_id, mf_id)
                    for k, v in _fetch_performer_ext_links_from_javstash(mj_id).items():
                        if k not in ext:
                            ext[k] = v
                    tmdb_val = ext.get("tmdb")
                    if tmdb_val and not (row.get("match_tmdb_id") or "").strip():
                        try:
                            db.favourite_set_ext_link(rid, "tmdb", tmdb_val)
                        except Exception:
                            pass
                    for site in ("iafd", "freeones", "babepedia", "coomer", "javdatabase"):
                        url = ext.get(site)
                        if url and not (row.get(f"match_{site}_url") or "").strip():
                            try:
                                db.favourite_set_ext_link(rid, site, url)
                            except Exception:
                                pass
                    if mj_id and not (row.get("match_javdatabase_url") or "").strip():
                        _try_auto_link_javdatabase(rid, dict(row))
                    bio_text = ext.get("bio", "")
                    if bio_text:
                        storage = _performers_iafd_dir(rid)
                        meta_path = storage / f"{rid}.json"
                        m = json.loads(meta_path.read_text(encoding="utf-8")) if meta_path.is_file() else {}
                        if not m.get("bio"):
                            m["bio"] = bio_text
                            if not m.get("name"):
                                m["name"] = (row.get("folder_name") or "")
                            if not m.get("scraped_at"):
                                m["scraped_at"] = datetime.now(timezone.utc).isoformat()
                            meta_path.write_text(json.dumps(m, indent=2), encoding="utf-8")
                except Exception as exc:
                    _log.debug("Bulk ext links row %s: %s", rid, exc)
            _EXT_LINKS_ENRICH_PROGRESS["done"] += 1
            time.sleep(0.5)

        # --- Phase 2: headshots ---
        _EXT_LINKS_ENRICH_PROGRESS["phase"] = "headshots"
        for row in eligible_heads:
            rid = int(row["id"])
            name = row.get("folder_name") or str(rid)
            _EXT_LINKS_ENRICH_PROGRESS["current"] = f"[headshot] {name}"
            try:
                _enrich_performer_headshot_bg(rid)
            except Exception as exc:
                _log.debug("Bulk headshot row %s: %s", rid, exc)
            _EXT_LINKS_ENRICH_PROGRESS["done"] += 1
            time.sleep(0.3)

        # --- Phase 3: posters (2 per performer) + movie/studio images ---
        all_movies = [r for r in db.favourite_list() if r.get("kind") == "movie"]
        all_studios = [r for r in db.favourite_list() if r.get("kind") == "studio"]
        eligible_posters = eligible_posters + all_movies + all_studios
        _EXT_LINKS_ENRICH_PROGRESS["total"] = _EXT_LINKS_ENRICH_PROGRESS.get("total", 0) + len(all_movies) + len(all_studios)
        _EXT_LINKS_ENRICH_PROGRESS["phase"] = "posters"
        for row in eligible_posters:
            rid = int(row["id"])
            kind = row.get("kind") or "performer"
            name = row.get("folder_name") or str(rid)
            _EXT_LINKS_ENRICH_PROGRESS["current"] = f"[poster] {name}"
            try:
                if kind == "performer":
                    _ensure_performer_posters(rid)
                elif kind == "movie":
                    _ensure_movie_images(rid)
                elif kind == "studio":
                    _ensure_studio_images(rid)
                    # Also import the scene-style poster.jpg from the
                    # studio folder into the metadata cache so the
                    # /downloads Favourites tab can serve a stable
                    # URL. Returns None when the folder has no local
                    # poster — that's fine, the caller ignores.
                    _ensure_studio_poster_path(rid)
            except Exception as exc:
                _log.debug("Bulk poster row %s: %s", rid, exc)
            _EXT_LINKS_ENRICH_PROGRESS["done"] += 1
            time.sleep(0.3)
    finally:
        _EXT_LINKS_ENRICH_PROGRESS["running"] = False
        _EXT_LINKS_ENRICH_PROGRESS["current"] = ""
        _EXT_LINKS_ENRICH_RUNNING.clear()


def _background_enrich_headshots_only() -> None:
    """Headshots-only bulk job: scrape missing headshots for all performers without an image.
    Uses the same progress tracking as the full bulk job.
    Priority per performer: TMDB → IAFD → Freeones.
    """
    global _EXT_LINKS_ENRICH_PROGRESS
    if _EXT_LINKS_ENRICH_RUNNING.is_set():
        return
    _EXT_LINKS_ENRICH_RUNNING.set()
    try:
        all_rows = [r for r in db.favourite_list() if r.get("kind") == "performer"]

        def _needs_work(r: dict) -> bool:
            rid = int(r["id"])
            has_custom = bool(_performers_custom_ref_resolve(rid))
            meta = _performers_iafd_read_meta(rid)
            has_headshot = has_custom or (meta and (meta.get("image_files") or []))
            has_secondary = _perf_poster_resolve(rid, "poster_secondary") is not None
            return not has_headshot or not has_secondary

        eligible = [r for r in all_rows if _needs_work(r)]
        _EXT_LINKS_ENRICH_PROGRESS = {
            "total": len(eligible), "done": 0, "current": "", "phase": "headshots", "running": True
        }
        for row in eligible:
            rid = int(row["id"])
            name = row.get("folder_name") or str(rid)
            _EXT_LINKS_ENRICH_PROGRESS["current"] = f"[headshot] {name}"
            try:
                _enrich_performer_headshot_bg(rid)
            except Exception as exc:
                _log.debug("Bulk headshots-only row %s: %s", rid, exc)
            _EXT_LINKS_ENRICH_PROGRESS["done"] += 1
            time.sleep(0.3)
    finally:
        _EXT_LINKS_ENRICH_PROGRESS["running"] = False
        _EXT_LINKS_ENRICH_PROGRESS["current"] = ""
        _EXT_LINKS_ENRICH_RUNNING.clear()


@app.post("/api/performers/enrich-ext-links-bulk")
async def api_performers_enrich_ext_links_bulk():
    """Trigger full bulk enrichment: ext links + headshots."""
    if _EXT_LINKS_ENRICH_RUNNING.is_set():
        return {"started": False, "reason": "already_running"}
    threading.Thread(target=_background_enrich_all_ext_links, daemon=True).start()
    return {"started": True}


@app.post("/api/performers/enrich-headshots-bulk")
async def api_performers_enrich_headshots_bulk():
    """Trigger headshots-only bulk job for all performers without a saved headshot."""
    if _EXT_LINKS_ENRICH_RUNNING.is_set():
        return {"started": False, "reason": "already_running"}
    threading.Thread(target=_background_enrich_headshots_only, daemon=True).start()
    return {"started": True}


@app.get("/api/performers/enrichment-progress")
async def api_performers_enrichment_progress():
    """Current progress of the bulk ext-links enrichment job."""
    return dict(_EXT_LINKS_ENRICH_PROGRESS)


_STUDIO_ENRICH_RUNNING = threading.Event()
_STUDIO_ENRICH_PROGRESS: dict = {
    "total": 0, "done": 0, "current": "", "phase": "", "running": False,
}


def _background_enrich_all_studios() -> None:
    """Bulk backfill for studio rows: calls favourites_refresh_entity_row
    with only_missing=True for every studio row that has at least one
    match_*_id set but any other slot empty. Populates the canonical
    names (match_tpdb_name / stashdb_name / fansdb_name) from the
    source APIs so the filing pipeline can match against them later.
    Idempotent and rate-limited; safe to call on demand."""
    global _STUDIO_ENRICH_PROGRESS
    if _STUDIO_ENRICH_RUNNING.is_set():
        return
    _STUDIO_ENRICH_RUNNING.set()
    try:
        all_rows = [r for r in db.favourite_list() if r.get("kind") == "studio"]
        # Eligible = has at least one id but any id missing, so cross-populate
        # from the source(s) we do know about.
        def _needs_work(r: dict) -> bool:
            has_any = any(
                (r.get(f"match_{s}_id") or "").strip()
                for s in ("tpdb", "stashdb", "fansdb")
            )
            if not has_any:
                return False
            missing_any = any(
                not (r.get(f"match_{s}_id") or "").strip()
                for s in ("tpdb", "stashdb", "fansdb")
            )
            missing_name = any(
                not (r.get(f"match_{s}_name") or "").strip()
                for s in ("tpdb", "stashdb", "fansdb")
                if (r.get(f"match_{s}_id") or "").strip()
            )
            return missing_any or missing_name

        eligible = [r for r in all_rows if _needs_work(r)]
        _STUDIO_ENRICH_PROGRESS = {
            "total": len(eligible), "done": 0, "current": "",
            "phase": "studios", "running": True,
        }
        for row in eligible:
            rid = int(row["id"])
            name = row.get("folder_name") or str(rid)
            _STUDIO_ENRICH_PROGRESS["current"] = f"[studio] {name}"
            try:
                favourites_refresh_entity_row(rid, only_missing=True)
            except Exception as exc:
                _log.debug("Bulk studio enrich row %s: %s", rid, exc)
            _STUDIO_ENRICH_PROGRESS["done"] += 1
            time.sleep(0.3)
    finally:
        _STUDIO_ENRICH_PROGRESS["running"] = False
        _STUDIO_ENRICH_PROGRESS["current"] = ""
        _STUDIO_ENRICH_RUNNING.clear()


@app.post("/api/studios/enrich-bulk")
async def api_studios_enrich_bulk():
    """Trigger the studio bulk enrichment job — cross-populates
    TPDB/StashDB/FansDB IDs + names across linked studio rows."""
    if _STUDIO_ENRICH_RUNNING.is_set():
        return {"started": False, "reason": "already_running"}
    threading.Thread(target=_background_enrich_all_studios, daemon=True).start()
    return {"started": True}


@app.get("/api/studios/enrichment-progress")
async def api_studios_enrichment_progress():
    return dict(_STUDIO_ENRICH_PROGRESS)


def _studios_enrichment_status_payload() -> dict:
    logo_dir = _studio_logos_dir()
    out: list[dict] = []
    for r in db.favourite_list():
        if r.get("kind") != "studio":
            continue
        rid = int(r["id"])
        name = r.get("folder_name") or ""
        tpdb_id    = (r.get("match_tpdb_id")    or "").strip() or None
        stashdb_id = (r.get("match_stashdb_id") or "").strip() or None
        fansdb_id  = (r.get("match_fansdb_id")  or "").strip() or None
        # Check whether the studio has a local logo file by looking the
        # slug up in the studio_logos table (the same source the
        # /api/studio-logo endpoint uses).
        slug = db.studio_logo_slug(name)
        has_logo = False
        if slug:
            row = db.studio_logo_get_by_slug(slug)
            if row and row.get("logo_path"):
                p = logo_dir / row["logo_path"]
                try:
                    if p.is_file() and p.stat().st_size > 500:
                        has_logo = True
                except OSError:
                    pass
        out.append({
            "id":            rid,
            "name":          name,
            "path":          (r.get("path") or "").strip(),
            "tpdb_id":       tpdb_id,
            "stashdb_id":    stashdb_id,
            "fansdb_id":     fansdb_id,
            "has_logo":      has_logo,
            "path_missing":  bool(int(r.get("path_missing") or 0)),
        })
    return {"studios": out}


@app.get("/api/studios/enrichment-status")
async def api_studios_enrichment_status():
    """Full per-studio status: name, DB links (TPDB/StashDB/FansDB), local
    logo presence, folder path health. Mirrors the performer endpoint
    and drives the /health studios enrichment panel.

    Runs in a threadpool — the per-studio slug lookup + logo stat loop
    is linear in the favourites table, which blocks the event loop
    long enough to stall other requests on libraries with thousands
    of studios.
    """
    return await run_in_threadpool(_studios_enrichment_status_payload)


def _performers_enrichment_status_payload() -> dict:
    out = []
    for r in db.favourite_list():
        if r.get("kind") != "performer":
            continue
        rid = int(r["id"])
        name = r.get("folder_name") or ""
        # Headshot: check for custom image or iafd image file
        has_headshot = False
        cust = _performers_custom_ref_resolve(rid)
        if cust:
            has_headshot = True
        else:
            meta = _performers_iafd_read_meta(rid)
            if meta and (meta.get("image_files") or []):
                has_headshot = True
        tmdb_raw = (r.get("match_tmdb_id") or "").strip() or None
        group_ids = {"tpdb": [], "stashdb": [], "fansdb": []}
        raw_group = (r.get("group_ids_json") or "").strip()
        if raw_group:
            try:
                parsed = json.loads(raw_group) or {}
                if isinstance(parsed, dict):
                    for k in ("tpdb", "stashdb", "fansdb"):
                        group_ids[k] = [str(x) for x in (parsed.get(k) or [])]
            except Exception:
                pass
        # Flatten aliases_json into a plain string list so the UI can
        # render them as chips without having to re-parse the JSON.
        aliases: list[str] = []
        aj_raw = (r.get("aliases_json") or "").strip()
        if aj_raw:
            try:
                parsed = json.loads(aj_raw) or []
            except Exception:
                parsed = []
            if isinstance(parsed, list):
                for a in parsed:
                    if isinstance(a, str):
                        s_alias = a.strip()
                    elif isinstance(a, dict):
                        s_alias = str(a.get("name") or "").strip()
                    else:
                        s_alias = ""
                    if s_alias and s_alias not in aliases:
                        aliases.append(s_alias)
        # Router-weight override (int 1..10) used by the scene-filing
        # picker. Surfaced here so the /health performers table can
        # render the star badge + edit control.
        raw_weight = r.get("weight")
        try:
            weight_val: int | None = int(raw_weight) if raw_weight is not None and raw_weight != "" else None
        except (TypeError, ValueError):
            weight_val = None
        out.append({
            "id": rid,
            "name": name,
            "path": (r.get("path") or "").strip(),
            "tmdb_id": tmdb_raw,
            "tmdb_url": f"https://www.themoviedb.org/person/{tmdb_raw}" if tmdb_raw else None,
            "tpdb_id": (r.get("match_tpdb_id") or "").strip() or None,
            "stashdb_id": (r.get("match_stashdb_id") or "").strip() or None,
            "fansdb_id": (r.get("match_fansdb_id") or "").strip() or None,
            "iafd_url": (r.get("match_iafd_url") or "").strip() or None,
            "freeones_url": (r.get("match_freeones_url") or "").strip() or None,
            "babepedia_url": (r.get("match_babepedia_url") or "").strip() or None,
            "coomer_url": (r.get("match_coomer_url") or "").strip() or None,
            "javdatabase_url": (r.get("match_javdatabase_url") or "").strip() or None,
            "has_headshot": has_headshot,
            "is_group": int(r.get("is_group") or 0) == 1,
            "group_ids": group_ids,
            "aliases": aliases,
            "path_missing": bool(int(r.get("path_missing") or 0)),
            "is_favourite": bool(int(r.get("is_favourite") or 0)),
            "weight": weight_val,
        })
    return {"performers": out}


@app.get("/api/performers/enrichment-status")
async def api_performers_enrichment_status():
    """Full per-performer status: links present/missing, headshot saved.

    Runs in a threadpool — each performer triggers a filesystem check
    (custom headshot resolution + IAFD meta JSON read), and with large
    libraries that adds up to enough disk I/O to stall the event loop
    if done inline in the async handler.
    """
    return await run_in_threadpool(_performers_enrichment_status_payload)


@app.post("/api/performers/aliases")
async def api_performers_set_aliases(payload: dict = Body(...)):
    """Replace the aliases_json list on a performer row.

    Body: ``{"row_id": int, "aliases": ["Silvia Dellai", "Eveline Dellai", ...]}``

    Used by the alias editor on /health to tie individual performer
    names to a group folder (e.g. feeding "Silvia Dellai" / "Eveline
    Dellai" into the "Dellai Twins" folder so scenes crediting either
    twin resolve to the group's headshot via the existing matcher
    paths in ``_resolve_library_performers_for_movie`` and
    ``_rss_library_match_names``).

    Returns the canonicalised alias list (trimmed, deduped on a
    case-insensitive key while preserving the casing of the first
    occurrence, and capped at 50 entries so a misclick paste of a
    full bio doesn't balloon the row).
    """
    try:
        row_id = int(payload.get("row_id") or 0)
    except (TypeError, ValueError):
        row_id = 0
    if not row_id:
        return JSONResponse({"error": "row_id required"}, status_code=400)
    row = db.favourite_get(row_id)
    if not row or (row.get("kind") or "").lower() != "performer":
        return JSONResponse({"error": "performer row not found"}, status_code=404)
    raw = payload.get("aliases")
    if not isinstance(raw, list):
        return JSONResponse({"error": "aliases must be a list"}, status_code=400)
    seen_keys: set[str] = set()
    cleaned: list[str] = []
    for a in raw:
        if not isinstance(a, str):
            continue
        s = a.strip()
        if not s:
            continue
        key = s.lower()
        if key in seen_keys:
            continue
        seen_keys.add(key)
        cleaned.append(s)
        if len(cleaned) >= 50:
            break
    aliases_json = json.dumps(cleaned) if cleaned else None
    db.favourite_set_aliases_json(row_id, aliases_json)
    return {"ok": True, "aliases": cleaned}


@app.post("/api/studios/aliases")
async def api_studios_set_aliases(payload: dict = Body(...)):
    """Replace the aliases_json list on a studio row.

    Body: ``{"row_id": int, "aliases": ["Pure Mature", "Mature NL", ...]}``

    Sibling-site lumping: a user keeps one local folder for a network
    that publishes under several names. Aliases here feed
    ``_favourites_name_index`` so ``find_studio_dir`` resolves a scene
    whose studio is "Pure Mature" onto the canonical folder even when
    the folder is called "Mature NL". Same cleaning rules as the
    performer endpoint (trim, case-insensitive dedupe, cap at 50).
    """
    try:
        row_id = int(payload.get("row_id") or 0)
    except (TypeError, ValueError):
        row_id = 0
    if not row_id:
        return JSONResponse({"error": "row_id required"}, status_code=400)
    row = db.favourite_get(row_id)
    if not row or (row.get("kind") or "").lower() != "studio":
        return JSONResponse({"error": "studio row not found"}, status_code=404)
    raw = payload.get("aliases")
    if not isinstance(raw, list):
        return JSONResponse({"error": "aliases must be a list"}, status_code=400)
    seen_keys: set[str] = set()
    cleaned: list[str] = []
    for a in raw:
        if not isinstance(a, str):
            continue
        s = a.strip()
        if not s:
            continue
        key = s.lower()
        if key in seen_keys:
            continue
        seen_keys.add(key)
        cleaned.append(s)
        if len(cleaned) >= 50:
            break
    aliases_json = json.dumps(cleaned) if cleaned else None
    db.favourite_set_aliases_json(row_id, aliases_json)
    # Force the slug index to rebuild so the next /queue file attempt
    # sees the new aliases without the usual 30s TTL wait.
    _favourites_name_index_bump()
    return {"ok": True, "aliases": cleaned}


