@app.post("/api/favourites/group-enrich-members")
async def api_favourites_group_enrich_members(payload: dict = Body(...)):
    """Look up name + image for every bare-id entry in a row's
    group_ids_json and upgrade it in place to the rich
    ``{id, name, image}`` shape. The merge / group-add flow stored
    plain strings, so existing groups render as nameless orphan tiles
    until something fills in the metadata — this is the something.

    Walks each source's id list, calls :func:`fetch_performer_detail`,
    keeps the first image url if any, and writes back via the existing
    :func:`db.favourite_group_add_id` upgrade path (same ID with
    name/image supplied = bare entry promoted in place). Returns the
    refreshed group_ids dict so the client can re-render without a
    second round-trip.
    """
    try:
        row_id = int(payload.get("row_id") or 0)
    except (TypeError, ValueError):
        row_id = 0
    if not row_id:
        return JSONResponse({"error": "row_id required"}, status_code=400)
    row = db.favourite_get(row_id)
    if not row:
        return JSONResponse({"error": "row not found"}, status_code=404)
    if int(row.get("is_group") or 0) != 1:
        return JSONResponse({"error": "row is not a group"}, status_code=400)
    raw = (row.get("group_ids_json") or "").strip()
    if not raw:
        return {"ok": True, "group_ids": {"tpdb": [], "stashdb": [], "fansdb": [], "javstash": []}, "upgraded": 0}
    try:
        parsed = json.loads(raw) or {}
    except (json.JSONDecodeError, TypeError):
        return JSONResponse({"error": "group_ids_json malformed"}, status_code=500)

    SOURCE_MAP = {"tpdb": "TPDB", "stashdb": "StashDB", "fansdb": "FansDB", "javstash": "JAVStash"}
    upgraded = 0
    for src_key, label in SOURCE_MAP.items():
        for entry in (parsed.get(src_key) or []):
            if isinstance(entry, dict):
                # Already rich, but if name is empty we still want to
                # fill it in — the studio popup writes nm="" when the
                # search row had no name. Only skip if both are present.
                if entry.get("name") and entry.get("image"):
                    continue
                xid = str(entry.get("id") or "").strip()
            else:
                xid = str(entry or "").strip()
            if not xid:
                continue
            try:
                detail = fetch_performer_detail(label, xid)
            except Exception as e:
                emit(f"group-enrich-members: {label} {xid} failed: {e}")
                detail = None
            if not detail:
                continue
            new_name = str(detail.get("name") or "").strip()
            # Pull the first image URL from whatever shape the source returned.
            img_url = ""
            images = detail.get("images") or []
            if isinstance(images, list) and images:
                first = images[0]
                if isinstance(first, dict):
                    img_url = str(first.get("url") or "").strip()
                else:
                    img_url = str(first or "").strip()
            if not new_name and not img_url:
                continue
            try:
                db.favourite_group_add_id(row_id, src_key, xid, name=new_name or None, image=img_url or None)
                upgraded += 1
            except ValueError:
                continue

    # Re-read so we return the final state to the client.
    fresh = db.favourite_get(row_id) or {}
    raw2 = (fresh.get("group_ids_json") or "").strip()
    out: dict[str, list[dict]] = {"tpdb": [], "stashdb": [], "fansdb": [], "javstash": []}
    if raw2:
        try:
            parsed2 = json.loads(raw2) or {}
        except (json.JSONDecodeError, TypeError):
            parsed2 = {}
        if isinstance(parsed2, dict):
            for k in ("tpdb", "stashdb", "fansdb", "javstash"):
                rich: list[dict] = []
                for x in (parsed2.get(k) or []):
                    if isinstance(x, dict):
                        rich.append({
                            "id":    str(x.get("id") or "").strip(),
                            "name":  str(x.get("name") or "").strip(),
                            "image": str(x.get("image") or "").strip(),
                        })
                    else:
                        rich.append({"id": str(x or "").strip(), "name": "", "image": ""})
                out[k] = [r for r in rich if r["id"]]
    if upgraded:
        _favourites_name_index_bump()
    return {"ok": True, "group_ids": out, "upgraded": upgraded}


# ── Performer merge / group-add / ungroup ────────────────────────────
#
# Workflow:
#   • Add two or more performers to the library normally.
#   • Open one performer's popup → hamburger → "Merge into group…".
#   • Pick the other performer(s), give the group a name, choose a
#     destination dir, confirm.
#   • Merge moves video files into a new group folder, promotes the
#     primary row to is_group=1 with the others' crosswalk IDs in
#     group_ids_json, deletes the now-empty merged-in rows + folders.
#
# Once grouped: "Add another performer…" appends to the existing group;
# "Ungroup" moves the video files back to source_dir (queue) so the
# pipeline re-files them, then deletes the group row + folder.

def _video_files_in(directory: Path) -> list[Path]:
    """Recursively collect every video file under ``directory``.
    Used by the merge / ungroup flows to move only media (posters,
    NFOs, sprites, etc. stay behind so the destination folder doesn't
    inherit stale chrome from the source)."""
    out: list[Path] = []
    if not directory.is_dir():
        return out
    for p in directory.rglob("*"):
        try:
            if p.is_file() and p.suffix.lower() in VIDEO_EXTENSIONS:
                out.append(p)
        except OSError:
            continue
    return out


def _safe_remove_empty_tree(directory: Path) -> bool:
    """Delete an empty directory tree (any sub-tree with no remaining
    files). Returns True when the directory itself was removed.
    Leaves the tree intact and logs once if non-empty — caller's
    decision whether that's an error or expected (the user may have
    kept artwork they don't want auto-deleted)."""
    if not directory.is_dir():
        return False
    try:
        # Bottom-up rmdir — only succeeds when the dir is genuinely empty.
        for sub in sorted(
            (p for p in directory.rglob("*") if p.is_dir()),
            key=lambda p: len(p.parts),
            reverse=True,
        ):
            try:
                sub.rmdir()
            except OSError:
                pass
        directory.rmdir()
        return True
    except OSError as e:
        emit(f"  MERGE: cannot remove '{directory}' — {e}")
        return False


@app.post("/api/performers/merge")
async def api_performers_merge(payload: dict = Body(...)):
    """Merge two or more performer rows into a new group folder.

    Body:
      primary_row_id   — int, the row whose popup launched the merge.
      secondary_row_ids — list[int], performers to fold in.
      group_name       — str, the new group folder name.
      dest_dir         — str, absolute path of one of the configured
                         performer roots (must match an entry from
                         /api/metadata/dirs?kind=performer).
    """
    try:
        primary_id = int(payload.get("primary_row_id") or 0)
    except (TypeError, ValueError):
        primary_id = 0
    secondaries_raw = payload.get("secondary_row_ids") or []
    if not isinstance(secondaries_raw, list):
        return JSONResponse({"error": "secondary_row_ids must be a list"}, status_code=400)
    try:
        secondary_ids = [int(x) for x in secondaries_raw if int(x) and int(x) != primary_id]
    except (TypeError, ValueError):
        return JSONResponse({"error": "secondary_row_ids must contain integers"}, status_code=400)
    group_name = _sanitize_fs_component((payload.get("group_name") or "").strip())
    dest_dir = (payload.get("dest_dir") or "").strip()
    if not primary_id or not secondary_ids or not group_name or not dest_dir:
        return JSONResponse(
            {"error": "primary_row_id, secondary_row_ids, group_name, dest_dir required"},
            status_code=400,
        )
    # Whitelist dest_dir against the configured performer roots so a
    # malicious payload can't drop files anywhere on the filesystem.
    allowed_dirs = {d["path"] for d in db.get_directories("performer") if d.get("path")}
    if dest_dir not in allowed_dirs:
        return JSONResponse({"error": "dest_dir is not a configured performer root"}, status_code=400)
    primary_row = db.favourite_get(primary_id)
    if not primary_row or (primary_row.get("kind") or "").lower() != "performer":
        return JSONResponse({"error": "Primary performer not found"}, status_code=404)
    secondary_rows: list[dict] = []
    for sid in secondary_ids:
        r = db.favourite_get(sid)
        if not r or (r.get("kind") or "").lower() != "performer":
            return JSONResponse({"error": f"Secondary row {sid} not found"}, status_code=404)
        secondary_rows.append(r)

    dest_parent = Path(dest_dir).expanduser()
    dest_folder = dest_parent / group_name
    if dest_folder.exists() and dest_folder != Path((primary_row.get("path") or "").strip()):
        return JSONResponse(
            {"error": f"'{dest_folder}' already exists — pick a different name or destination"},
            status_code=409,
        )

    try:
        dest_parent.mkdir(parents=True, exist_ok=True)

        # Stage 1: relocate the primary's folder to the new group path.
        primary_path_raw = (primary_row.get("path") or "").strip()
        primary_path = Path(primary_path_raw).expanduser() if primary_path_raw else None
        if primary_path and primary_path.is_dir() and primary_path != dest_folder:
            # shutil.move handles cross-device renames + falls back to copy+rm.
            shutil.move(str(primary_path), str(dest_folder))
        elif not dest_folder.exists():
            dest_folder.mkdir(parents=True, exist_ok=True)

        # Stage 2: move every video from each secondary into the group.
        for srow in secondary_rows:
            spath = (srow.get("path") or "").strip()
            if not spath:
                continue
            src = Path(spath).expanduser()
            for vf in _video_files_in(src):
                target = dest_folder / vf.name
                # Collide-safe: suffix `(2)` etc on filename match.
                if target.exists() and target.resolve() != vf.resolve():
                    stem, ext = target.stem, target.suffix
                    n = 2
                    while True:
                        cand = dest_folder / f"{stem} ({n}){ext}"
                        if not cand.exists():
                            target = cand
                            break
                        n += 1
                safe_move(str(vf), str(target))
            # Clean up the now-empty source folder. Posters / NFOs are
            # left behind intentionally — they were per-performer and
            # don't belong in the group folder.
            _safe_remove_empty_tree(src)

        # Stage 3: union every crosswalk ID we have for primary +
        # secondaries into group_ids_json. The matcher's crosswalk
        # check resolves any scene whose performer matches any of these.
        group_ids = {"tpdb": [], "stashdb": [], "fansdb": [], "javstash": []}
        def _push_ids(src_row: dict) -> None:
            for src_key, col in (
                ("tpdb",     "match_tpdb_id"),
                ("stashdb",  "match_stashdb_id"),
                ("fansdb",   "match_fansdb_id"),
                ("javstash", "match_javstash_id"),
            ):
                v = (src_row.get(col) or "").strip()
                if v and v not in [_id if isinstance(_id, str) else _id.get("id") for _id in group_ids[src_key]]:
                    group_ids[src_key].append(v)
            existing_gj = (src_row.get("group_ids_json") or "").strip()
            if existing_gj:
                try:
                    parsed = json.loads(existing_gj) or {}
                except (json.JSONDecodeError, TypeError):
                    parsed = {}
                if isinstance(parsed, dict):
                    for src_key in ("tpdb", "stashdb", "fansdb", "javstash"):
                        for x in (parsed.get(src_key) or []):
                            xid = x if isinstance(x, str) else (x.get("id") if isinstance(x, dict) else "")
                            xid = str(xid or "").strip()
                            if xid and xid not in [
                                _id if isinstance(_id, str) else _id.get("id") for _id in group_ids[src_key]
                            ]:
                                group_ids[src_key].append(xid)
        _push_ids(primary_row)
        for srow in secondary_rows:
            _push_ids(srow)

        db.favourite_promote_to_group(
            primary_id,
            folder_name=group_name,
            path=str(dest_folder),
            group_ids_json=json.dumps(group_ids),
        )

        # Stage 4: delete the secondary rows. Their match IDs already
        # live in primary's group_ids_json so future filing still works.
        for srow in secondary_rows:
            db.favourite_delete(int(srow["id"]))

        _favourites_name_index_bump()
        return {
            "ok": True,
            "row_id": primary_id,
            "path": str(dest_folder),
            "folder_name": group_name,
        }
    except OSError as e:
        emit(f"MERGE error: {e}")
        return JSONResponse({"error": str(e)}, status_code=500)


@app.post("/api/performers/group-add")
async def api_performers_group_add(payload: dict = Body(...)):
    """Add one or more performer rows into an already-grouped folder.

    Same body shape as merge minus group_name/dest_dir — the group's
    name and location don't change. Moves every secondary's videos
    into the group folder, merges their match IDs into group_ids_json,
    deletes the secondary rows.
    """
    try:
        row_id = int(payload.get("row_id") or 0)
    except (TypeError, ValueError):
        row_id = 0
    secondaries_raw = payload.get("secondary_row_ids") or []
    try:
        secondary_ids = [int(x) for x in (secondaries_raw or []) if int(x) and int(x) != row_id]
    except (TypeError, ValueError):
        return JSONResponse({"error": "secondary_row_ids must contain integers"}, status_code=400)
    if not row_id or not secondary_ids:
        return JSONResponse({"error": "row_id and secondary_row_ids required"}, status_code=400)
    primary_row = db.favourite_get(row_id)
    if not primary_row or (primary_row.get("kind") or "").lower() != "performer":
        return JSONResponse({"error": "Group performer not found"}, status_code=404)
    if not int(primary_row.get("is_group") or 0):
        return JSONResponse({"error": "Target row is not a group — use /api/performers/merge"}, status_code=400)
    secondary_rows = []
    for sid in secondary_ids:
        r = db.favourite_get(sid)
        if not r or (r.get("kind") or "").lower() != "performer":
            return JSONResponse({"error": f"Secondary row {sid} not found"}, status_code=404)
        secondary_rows.append(r)
    dest_folder = Path((primary_row.get("path") or "").strip()).expanduser()
    if not dest_folder.is_dir():
        return JSONResponse({"error": "Group folder is missing on disk"}, status_code=409)

    try:
        for srow in secondary_rows:
            spath = (srow.get("path") or "").strip()
            if not spath:
                continue
            src = Path(spath).expanduser()
            for vf in _video_files_in(src):
                target = dest_folder / vf.name
                if target.exists() and target.resolve() != vf.resolve():
                    stem, ext = target.stem, target.suffix
                    n = 2
                    while True:
                        cand = dest_folder / f"{stem} ({n}){ext}"
                        if not cand.exists():
                            target = cand
                            break
                        n += 1
                safe_move(str(vf), str(target))
            _safe_remove_empty_tree(src)
            for src_key, col in (
                ("tpdb",     "match_tpdb_id"),
                ("stashdb",  "match_stashdb_id"),
                ("fansdb",   "match_fansdb_id"),
                ("javstash", "match_javstash_id"),
            ):
                v = (srow.get(col) or "").strip()
                if v:
                    db.favourite_group_add_id(row_id, src_key, v)
            db.favourite_delete(int(srow["id"]))

        _favourites_name_index_bump()
        return {"ok": True, "row_id": row_id}
    except OSError as e:
        emit(f"GROUP-ADD error: {e}")
        return JSONResponse({"error": str(e)}, status_code=500)


@app.post("/api/performers/ungroup")
async def api_performers_ungroup(payload: dict = Body(...)):
    """Dissolve a group performer.

    Moves every video file from the group folder back to ``source_dir``
    (the queue) so the filing pipeline re-sorts them. Then deletes the
    group folder + the row. The user re-adds individual performers as
    the queue refiles each scene.
    """
    try:
        row_id = int(payload.get("row_id") or 0)
    except (TypeError, ValueError):
        row_id = 0
    if not row_id:
        return JSONResponse({"error": "row_id required"}, status_code=400)
    row = db.favourite_get(row_id)
    if not row or (row.get("kind") or "").lower() != "performer":
        return JSONResponse({"error": "Performer not found"}, status_code=404)
    if not int(row.get("is_group") or 0):
        return JSONResponse({"error": "Row is not a group"}, status_code=400)
    settings = db.get_settings()
    source_dir = Path((settings.get("source_dir") or "").strip()).expanduser()
    if not source_dir.is_dir():
        return JSONResponse({"error": "Configured source_dir does not exist"}, status_code=409)
    group_dir = Path((row.get("path") or "").strip()).expanduser()
    moved = 0
    try:
        if group_dir.is_dir():
            for vf in _video_files_in(group_dir):
                target = source_dir / vf.name
                if target.exists() and target.resolve() != vf.resolve():
                    stem, ext = target.stem, target.suffix
                    n = 2
                    while True:
                        cand = source_dir / f"{stem} ({n}){ext}"
                        if not cand.exists():
                            target = cand
                            break
                        n += 1
                safe_move(str(vf), str(target))
                moved += 1
            _safe_remove_empty_tree(group_dir)
        db.favourite_delete(row_id)
        _favourites_name_index_bump()
        return {"ok": True, "moved_videos": moved, "source_dir": str(source_dir)}
    except OSError as e:
        emit(f"UNGROUP error: {e}")
        return JSONResponse({"error": str(e)}, status_code=500)


_IAFD_ENRICH_RUNNING = threading.Event()


def _background_iafd_enrich_all() -> None:
    """Auto-enrich performer rows with no IAFD metadata.

    Runs in a daemon thread after library scans. For each performer without a
    cached IAFD JSON:
      - If exactly 1 IAFD search result: auto-scrape profile + images.
      - If 0 results or no images: fall back to Freeones headshot.
      - If multiple IAFD results: skip (manual pick required).
    Rate-limited with small sleeps to avoid bot detection.
    """
    if _IAFD_ENRICH_RUNNING.is_set():
        return
    _IAFD_ENRICH_RUNNING.set()
    try:
        rows = [r for r in db.favourite_list() if r.get("kind") == "performer"]
        for row in rows:
            rid = int(row["id"])
            if (_performers_iafd_dir(rid) / f"{rid}.json").is_file():
                continue
            name = (row.get("folder_name") or "").strip()
            if not name:
                continue
            try:
                opts = _iafd_performer_query(name)
                if not opts:
                    _enrich_freeones_fallback(rid, name, row)
                elif len(opts) == 1:
                    iafd_url = opts[0]["urls"][0]
                    meta, _ = _performers_iafd_save(rid, iafd_url)
                    files = meta.get("image_files") or []
                    emit(f"IAFD enrich: '{name}' — {len(files)} image(s) saved")
                    try:
                        db.favourite_set_ext_link(rid, "iafd", iafd_url)
                    except Exception:
                        pass
                    if not files:
                        _enrich_freeones_fallback(rid, name, row)
                else:
                    emit(f"IAFD enrich: '{name}' — {len(opts)} results, needs manual pick")
                time.sleep(3)
            except Exception as exc:
                _log.debug("IAFD enrich '%s': %s", name, exc)
                time.sleep(2)
    finally:
        _IAFD_ENRICH_RUNNING.clear()


def _performers_iafd_image_api_url(row_id: int, index: int, meta: dict | None) -> str | None:
    """Stable cache-busted URL so browsers reload after a new scrape."""
    if not meta:
        return None
    files = meta.get("image_files") or []
    if index < 0 or index >= len(files):
        return None
    bust = hashlib.md5(
        ((meta.get("scraped_at") or "") + "\n" + ",".join(str(f) for f in files)).encode(
            "utf-8"
        ),
        usedforsecurity=False,
    ).hexdigest()[:12]
    return f"/api/performers/iafd-image?row_id={int(row_id)}&i={int(index)}&v={bust}"


def _performers_row_api_augment(r: dict) -> dict:
    out = dict(r)
    try:
        rid = int(out["id"])
    except (KeyError, TypeError, ValueError):
        return out
    try:
        meta = _performers_iafd_read_meta(rid)
        out["iafd_search_url"] = _performers_iafd_search_url(out.get("folder_name") or "")
        cust = _performers_custom_ref_resolve(rid)
        if cust:
            out["custom_primary_url"] = f"/api/performers/custom-image?row_id={rid}"
        else:
            out["custom_primary_url"] = None
        if meta:
            out["iafd_scraped_at"] = meta.get("scraped_at")
            out["iafd_url"] = meta.get("iafd_url")
            files = meta.get("image_files") or []
            out["iafd_image_count"] = len(files)
            out["iafd_primary_url"] = _performers_iafd_image_api_url(rid, 0, meta)
        else:
            out["iafd_scraped_at"] = None
            out["iafd_url"] = None
            out["iafd_image_count"] = 0
            out["iafd_primary_url"] = None
    except Exception:
        _log.exception("performers row augment failed id=%s", rid)
        out["iafd_search_url"] = _performers_iafd_search_url(out.get("folder_name") or "")
        out["custom_primary_url"] = None
        out["iafd_scraped_at"] = None
        out["iafd_url"] = None
        out["iafd_image_count"] = 0
        out["iafd_primary_url"] = None
    return out


@app.get("/api/performers")
async def api_performers_list():
    rows = [
        _performers_row_api_augment(_favourites_row_api(dict(x)))
        for x in db.favourite_list()
        if x.get("kind") == "performer"
    ]
    rows.sort(
        key=lambda r: (
            _movie_library_sort_key(r.get("folder_name") or ""),
            (r.get("folder_name") or "").lower(),
        )
    )
    return {"performers": rows}


@app.get("/api/performers/info")
async def api_performers_info(row_id: int):
    row = db.favourite_get(row_id)
    if not row or row.get("kind") != "performer":
        return JSONResponse({"error": "Not found"}, status_code=404)
    base = _favourites_row_api(dict(row))
    meta = _performers_iafd_read_meta(row_id)
    iafd_public = dict(meta) if meta else {}
    iafd_public.pop("image_files", None)
    links: dict = _performer_ext_links_from_row(dict(base))
    rid = int(row_id)
    iafd_hero = _performers_iafd_image_api_url(rid, 0, meta)
    cust = _performers_custom_ref_resolve(rid)
    custom_hero = (
        f"/api/performers/custom-image?row_id={rid}" if cust else None
    )
    # Poster URLs (never the headshot)
    md = _metadata_dir_for("performer", rid)
    poster_primary_url = None
    poster_secondary_url = None
    # Check all possible poster filenames
    for name in [f"{rid}_poster_primary.webp", f"{rid}_poster_primary.jpg", f"{rid}_poster_1.webp", f"{rid}_poster_1.jpg"]:
        if (md / name).is_file():
            poster_primary_url = f"/api/performers/poster-image?row_id={rid}&kind=primary"
            break
    for name in [f"{rid}_poster_secondary.webp", f"{rid}_poster_secondary.jpg", f"{rid}_poster_2.webp", f"{rid}_poster_2.jpg", f"{rid}_poster.webp", f"{rid}_poster.jpg"]:
        if (md / name).is_file():
            poster_secondary_url = f"/api/performers/poster-image?row_id={rid}&kind=secondary"
            break
    # If still nothing, check if local library poster exists and lazy-copy it
    if not poster_primary_url:
        row_check = db.favourite_get(rid)
        if row_check:
            p_local = _favourite_find_local_poster_file(row_check.get("path") or "")
            if p_local and p_local.is_file():
                dest = _perf_poster_write_path(rid, "poster_primary")
                try:
                    if save_image_bytes_optimized(p_local.read_bytes(), dest, max_edge=IMAGE_CACHE_POSTER_MAX):
                        poster_primary_url = f"/api/performers/poster-image?row_id={rid}&kind=primary"
                except OSError:
                    pass

    # Persisted IAFD filmography for the centre column. We resolve the
    # performer's IAFD URL from (preferred) the row's stored
    # ``match_iafd_url`` and fall back to a name lookup so older rows
    # still light up once the trickle worker has scraped them.
    perf_url = (base.get("match_iafd_url") or "").strip()
    perf_record = None
    if perf_url:
        perf_record = db.iafd_get_performer_by_url(perf_url)
    if not perf_record:
        nm = (base.get("folder_name") or "").strip()
        if nm:
            perf_record = db.iafd_get_performer_by_name(nm)
            if perf_record and not perf_url:
                perf_url = (perf_record.get("url") or "").strip()
    films = db.iafd_get_filmography(perf_url) if perf_url else []
    filmography = {
        "performer_url": perf_url or None,
        "last_scraped": (perf_record or {}).get("last_scraped"),
        "film_count": len(films),
        "first_year": (perf_record or {}).get("first_year"),
        "last_year": (perf_record or {}).get("last_year"),
        "films": films,
    }

    return {
        "row": base,
        "iafd": iafd_public,
        "links": links,
        "iafd_search_url": _performers_iafd_search_url(base.get("folder_name") or ""),
        "filmography": filmography,
        "hero": {
            "iafd_image_url": iafd_hero,
            "library_poster_url": base.get("image_url"),
            "custom_image_url": custom_hero,
            "poster_primary_url": poster_primary_url,
            "poster_secondary_url": poster_secondary_url,
        },
    }


def _performer_popup_cache_dir() -> Path:
    d = _metadata_base_dir() / "performer_popup"
    d.mkdir(parents=True, exist_ok=True)
    return d


_PERFORMER_POPUP_TTL_S = 6 * 3600


def _performer_popup_cache_get(key: str) -> dict | None:
    p = _performer_popup_cache_dir() / f"{key}.json"
    if not p.is_file():
        return None
    try:
        if (time.time() - p.stat().st_mtime) > _PERFORMER_POPUP_TTL_S:
            return None
        return json.loads(p.read_text(encoding="utf-8"))
    except Exception:
        return None


def _performer_popup_cache_set(key: str, payload: dict) -> None:
    p = _performer_popup_cache_dir() / f"{key}.json"
    try:
        p.write_text(json.dumps(payload), encoding="utf-8")
    except Exception:
        pass


def _performer_popup_cache_invalidate_row(row_id: int) -> None:
    """Drop cached popup payloads so new ext links show immediately."""
    keys = {f"row_{int(row_id)}"}
    row = db.favourite_get(int(row_id))
    if row:
        nm = (row.get("folder_name") or "").strip()
        if nm:
            keys.add(f"nm_{_performer_popup_safe_key(nm.lower())}")
        for col, prefix in (
            ("match_stashdb_id", "sb"),
            ("match_fansdb_id", "sb"),
            ("match_tpdb_id", "tp"),
            ("match_javstash_id", "sb"),
        ):
            v = (row.get(col) or "").strip()
            if v:
                keys.add(f"{prefix}_{_performer_popup_safe_key(v)}")
    cache_dir = _performer_popup_cache_dir()
    for key in keys:
        try:
            p = cache_dir / f"{key}.json"
            if p.is_file():
                p.unlink()
        except OSError:
            pass


def _normalize_ext_link_store(site: str, url: str) -> str:
    """Validate and normalise a manual ext-link URL before DB storage."""
    s = _ext_site_key(site)
    raw = (url or "").strip()
    if not raw:
        raise ValueError("url required")
    if s == "tmdb":
        m = re.search(r"/person/(\d+)", raw)
        if m:
            return m.group(1)
        if re.fullmatch(r"\d+", raw):
            return raw
        raise ValueError("TMDB link must be a person profile URL or numeric person ID")
    if s == "javdatabase":
        norm = _javdatabase_normalise_idol_url(raw)
        if not norm:
            raise ValueError("JAV Database link must be a javdatabase.com/idols/… profile URL")
        return norm
    if s in ("iafd", "freeones", "babepedia", "coomer"):
        if not re.match(r"^https?://", raw, re.I):
            raise ValueError(f"{site} link must start with http:// or https://")
        return raw
    raise ValueError(
        "site must be tmdb, iafd, freeones, babepedia, coomer, or javdatabase"
    )


def _ext_link_preview_thumb(site: str, url: str) -> str | None:
    """Best-effort preview image for ext-link search / manual URL."""
    s = _ext_site_key(site)
    if s == "tmdb":
        m = re.search(r"/person/(\d+)", url or "")
        pid = m.group(1) if m else ((url or "").strip() if re.fullmatch(r"\d+", (url or "").strip()) else "")
        if not pid:
            return None
        try:
            resp = requests.get(
                f"{TMDB_BASE}/person/{pid}",
                headers=get_tmdb_headers(),
                timeout=8,
            )
            if resp.status_code == 200:
                path = (resp.json() or {}).get("profile_path")
                if path:
                    return f"{TMDB_IMG_PROFILE_THUMB}{path}"
        except Exception:
            pass
        return None
    if s == "javdatabase":
        norm = _javdatabase_normalise_idol_url(url or "")
        if not norm:
            return None
        html = _javdatabase_fetch_html(norm)
        if not html:
            return None
        m = re.search(
            r'<meta[^>]+property=["\']og:image["\'][^>]+content=["\']([^"\']+)["\']',
            html,
            re.I,
        )
        if m:
            return m.group(1).strip()
    return None


def _performer_popup_safe_key(s: str) -> str:
    return re.sub(r"[^a-zA-Z0-9_-]+", "_", s or "")[:128] or "unknown"


def _performer_popup_local_images(row_id: int, meta: dict | None) -> list[dict]:
    """Compose every locally-cached image we have for a performer row."""
    out: list[dict] = []
    rid = int(row_id)
    md = _metadata_dir_for("performer", rid)
    for fname in (f"{rid}_poster_primary.webp", f"{rid}_poster_primary.jpg", f"{rid}_poster_1.webp", f"{rid}_poster_1.jpg"):
        if (md / fname).is_file():
            out.append({
                "url": f"/api/performers/poster-image?row_id={rid}&kind=primary",
                "kind": "poster",
                "is_primary": True,
            })
            break
    for fname in (f"{rid}_poster_secondary.webp", f"{rid}_poster_secondary.jpg", f"{rid}_poster_2.webp", f"{rid}_poster_2.jpg", f"{rid}_poster.webp", f"{rid}_poster.jpg"):
        if (md / fname).is_file():
            out.append({
                "url": f"/api/performers/poster-image?row_id={rid}&kind=secondary",
                "kind": "poster",
                "is_primary": False,
            })
            break
    cust = _performers_custom_ref_resolve(rid)
    if cust:
        out.append({
            "url": f"/api/performers/custom-image?row_id={rid}",
            "kind": "custom",
            "is_primary": False,
        })
    if meta:
        for i in range(len(meta.get("image_files", []) or [])):
            url = _performers_iafd_image_api_url(rid, i, meta)
            if url:
                out.append({"url": url, "kind": "iafd", "is_primary": i == 0})
    return out


def _performer_popup_stashbox_bio(stash_id: str, prefer_fansdb: bool = False) -> dict | None:
    """Fetch a performer bio from StashDB or FansDB by ID. Tries both
    when one fails — IDs are unique per source so a wrong-source guess
    just returns null."""
    sid = (stash_id or "").strip()
    if not sid:
        return None
    s = db.get_settings()
    sk = (s.get("api_key_stashdb") or "").strip()
    fk = (s.get("api_key_fansdb")  or "").strip()
    sources: list[tuple[str, str, str]] = []
    if prefer_fansdb:
        if fk: sources.append(("FansDB", FANSDB_ENDPOINT, fk))
        if sk: sources.append(("StashDB", STASHDB_ENDPOINT, sk))
    else:
        if sk: sources.append(("StashDB", STASHDB_ENDPOINT, sk))
        if fk: sources.append(("FansDB", FANSDB_ENDPOINT, fk))
    for label, ep, key in sources:
        try:
            data = _stashbox_post(ep, key, FANSDB_PERFORMER_DETAIL_GQL, {"id": sid})
        except Exception:
            continue
        p = data.get("findPerformer")
        if p:
            p["_source"] = label
            return p
    return None


def _tpdb_performer_fetch(tpdb_id: str) -> dict | None:
    """Fetch a single performer from TPDB by id. Returns the raw
    `data` block or None on failure. Used by the popup endpoint when
    a click came from a TPDB-sourced scene cast list."""
    sid = (tpdb_id or "").strip()
    if not sid:
        return None
    try:
        resp = requests.get(
            TPDB_PERFORMER_DETAIL.format(id=quote(sid, safe="")),
            headers=_tpdb_headers(),
            timeout=15,
        )
        if resp.status_code != 200:
            return None
        d = resp.json() or {}
        return d.get("data") if isinstance(d, dict) else None
    except Exception as exc:
        _log.debug("tpdb performer fetch %s failed: %s", sid, exc)
        return None


def _tpdb_performer_fetch_by_name(name: str) -> dict | None:
    """Find a TPDB performer by name and return the full detail payload.
    Two-step: search by name → take top hit → fetch detail (the search
    response is shallow; detail has bio/extras/posters)."""
    nm = (name or "").strip()
    if not nm:
        return None
    try:
        resp = requests.get(
            TPDB_PERFORMER_SEARCH,
            params={"q": nm},
            headers=_tpdb_headers(),
            timeout=15,
        )
        if resp.status_code != 200:
            return None
        hits = (resp.json() or {}).get("data") or []
        if not hits:
            return None
        nm_l = nm.lower()
        top = next((h for h in hits if str(h.get("name") or "").strip().lower() == nm_l), None) or hits[0]
        tid = str(top.get("id") or top.get("_id") or top.get("slug") or "").strip()
        if not tid:
            return None
        return _tpdb_performer_fetch(tid)
    except Exception as exc:
        _log.debug("tpdb performer fetch-by-name %r failed: %s", nm, exc)
        return None


# Hosts already represented as DB / profile pills (rendered via the
# `ext_links` block — StashDB/FansDB/TPDB/IAFD/Freeones/Babepedia/
# Coomer/TMDB). We skip these so the social row only carries Twitter/
# Instagram/OnlyFans/etc. and never duplicates a pill above it.
_PERFORMER_POPUP_SOCIAL_DB_HOSTS = frozenset({
    "stashdb.org", "fansdb.cc", "theporndb.net", "iafd.com",
    "freeones.com", "babepedia.com", "coomer.st", "themoviedb.org",
    "javdatabase.com", "javstash.org",
})

# Known social platforms — `key` is used by the frontend to pick a
# FontAwesome brand glyph; `label` is the human-readable site name.
# Hosts match either an exact equal or a trailing-dot suffix (covers
# `mobile.twitter.com` etc.). Order matters: first match wins.
_PERFORMER_POPUP_SOCIAL_PLATFORMS = (
    ("twitter",   "Twitter",    ("twitter.com", "x.com")),
    ("instagram", "Instagram",  ("instagram.com",)),
    ("onlyfans",  "OnlyFans",   ("onlyfans.com",)),
    ("fansly",    "Fansly",     ("fansly.com",)),
    ("tiktok",    "TikTok",     ("tiktok.com",)),
    ("threads",   "Threads",    ("threads.net",)),
    ("youtube",   "YouTube",    ("youtube.com", "youtu.be")),
    ("bluesky",   "Bluesky",    ("bsky.app", "bsky.social")),
    ("reddit",    "Reddit",     ("reddit.com",)),
    ("snapchat",  "Snapchat",   ("snapchat.com",)),
    ("telegram",  "Telegram",   ("t.me", "telegram.me")),
    ("pornhub",   "Pornhub",    ("pornhub.com",)),
    ("manyvids",  "ManyVids",   ("manyvids.com",)),
    ("clips4sale","Clips4Sale", ("clips4sale.com",)),
    ("linktree",  "Linktree",   ("linktr.ee",)),
    ("beacons",   "Beacons",    ("beacons.ai",)),
    ("amazon",    "Amazon",     ("amazon.com", "amazon.co.uk")),
)


def _performer_popup_social_links(
    sb_bio: dict | None,
    tpdb_data: dict | None,
    jav_data: dict | None,
    iafd_meta: dict | None,
    ext_links: dict,
) -> list[dict]:
    """Return ``[{key, label, url}]`` for social/external profile URLs
    surfaced from StashDB/FansDB/TPDB ``urls`` arrays plus IAFD's
    twitter/instagram fields. URLs already represented in ``ext_links``
    (DB profile pills) and known DB hosts are dropped so the social row
    never duplicates the pill grid above it."""
    seen: set[str] = set()
    for v in (ext_links or {}).values():
        u = (v.get("url") or "").strip().lower() if isinstance(v, dict) else ""
        if u:
            seen.add(u)

    def _collect(items) -> list[str]:
        out: list[str] = []
        for it in items or []:
            if isinstance(it, str):
                u = it.strip()
            elif isinstance(it, dict):
                u = (it.get("url") or it.get("link") or "").strip()
            else:
                continue
            if u and u.lower().startswith(("http://", "https://")):
                out.append(u)
        return out

    candidates: list[str] = []
    for src in (sb_bio, tpdb_data, jav_data):
        if not isinstance(src, dict):
            continue
        candidates.extend(_collect(src.get("urls")))
        candidates.extend(_collect(src.get("links")))
        ex = src.get("extras")
        if isinstance(ex, dict):
            candidates.extend(_collect(ex.get("urls")))
            candidates.extend(_collect(ex.get("links")))
    if isinstance(iafd_meta, dict):
        for k in ("twitter", "instagram"):
            v = (iafd_meta.get(k) or "").strip()
            if v.lower().startswith(("http://", "https://")):
                candidates.append(v)

    out: list[dict] = []
    for u in candidates:
        ul = u.lower()
        if ul in seen:
            continue
        try:
            host = urlparse(u).netloc.lower().replace("www.", "")
        except Exception:
            host = ""
        if host in _PERFORMER_POPUP_SOCIAL_DB_HOSTS:
            continue
        seen.add(ul)
        plat_key = ""
        plat_label = host or "Link"
        for key, label, hosts in _PERFORMER_POPUP_SOCIAL_PLATFORMS:
            if any(host == h or host.endswith("." + h) for h in hosts):
                plat_key = key
                plat_label = label
                break
        out.append({"key": plat_key, "label": plat_label, "url": u})
    return out


@app.get("/api/performer/popup")
async def api_performer_popup(
    row_id: int | None = None,
    stash_id: str | None = None,
    tpdb_id: str | None = None,
    name: str | None = None,
    refresh: int = 0,
    standalone: int = 0,
):
    """Universal performer popup endpoint. Resolves a click on a name into
    a unified payload regardless of which page made the call.

    Inputs (at least one required):
      row_id    — favourite_entities.id (preferred when known)
      stash_id  — StashDB or FansDB performer UUID (JAV scene UIs also
                  pass the JAVStash performer id here for ``data-stash-id``)
      tpdb_id   — ThePornDB performer id (used when click came from a
                  TPDB-sourced scene cast)
      name      — fallback when no id is known

    Resolution order: row_id → stash_id crosswalk → tpdb_id crosswalk
    → name lookup. If still no library row but tpdb_id is set, the
    endpoint fetches the performer from TPDB and uses that to populate
    the popup (so cast clicks on TPDB scenes show real bios + images
    instead of empty stubs). Cached to metadata/performer_popup/
    {key}.json for 6h.
    """
    rid_arg     = int(row_id) if row_id else None
    sid_arg     = (stash_id or "").strip() or None
    tid_arg     = (tpdb_id or "").strip() or None
    name_arg    = (name or "").strip() or None
    if not (rid_arg or sid_arg or tid_arg or name_arg):
        return JSONResponse({"error": "row_id, stash_id, tpdb_id, or name required"}, status_code=400)

    prefix = "solo_" if standalone else ""
    if rid_arg:
        cache_key = f"{prefix}row_{rid_arg}"
    elif sid_arg:
        cache_key = f"{prefix}sb_{_performer_popup_safe_key(sid_arg)}"
    elif tid_arg:
        cache_key = f"{prefix}tp_{_performer_popup_safe_key(tid_arg)}"
    else:
        cache_key = f"{prefix}nm_{_performer_popup_safe_key(name_arg.lower())}"

    if not refresh:
        cached = _performer_popup_cache_get(cache_key)
        if cached:
            return JSONResponse(cached)

    row: dict | None = None
    # ``standalone=1`` skips every crosswalk lookup so the popup paints
    # solely from the source-DB data the caller already has. Used by
    # the group-members modal: clicking a member tile must show that
    # member's standalone profile even though the parent group's
    # group_ids_json contains the same id and would otherwise resolve
    # the click back to the group row.
    bypass_library = bool(standalone)
    if rid_arg and not bypass_library:
        r = db.favourite_get(rid_arg)
        if r and r.get("kind") == "performer":
            row = dict(r)
    if not row and sid_arg and not bypass_library:
        r = db.favourite_find_performer_folder_by_crosswalk(None, sid_arg, sid_arg)
        if r:
            full = db.favourite_get(int(r["id"]))
            if full and full.get("kind") == "performer":
                row = dict(full)
        if not row:
            r = db.favourite_find_performer_folder_by_crosswalk(
                None, None, None, sid_arg
            )
            if r:
                full = db.favourite_get(int(r["id"]))
                if full and full.get("kind") == "performer":
                    row = dict(full)
    if not row and tid_arg and not bypass_library:
        r = db.favourite_find_performer_folder_by_crosswalk(tid_arg, None, None)
        if r:
            full = db.favourite_get(int(r["id"]))
            if full and full.get("kind") == "performer":
                row = dict(full)
    if not row and name_arg and not bypass_library:
        r = db.favourite_lookup_performer_by_name(name_arg)
        if not r:
            r = db.favourite_lookup_performer_by_alias(name_arg)
        if r and r.get("kind") == "performer":
            row = dict(r)

    # When click came from a TPDB-sourced scene and there's no library
    # match, scrape the TPDB performer profile to fill the popup. If no
    # tpdb_id was passed (cast click came from a CSV-only or stashbox
    # source where the upstream id wasn't TPDB) but we have a name and
    # no library/stashbox identity will resolve, fall back to a TPDB
    # name search so the popup still has bio + headshot + posters
    # rather than an empty stub.
    tpdb_data: dict | None = None
    if tid_arg and not row:
        tpdb_data = _tpdb_performer_fetch(tid_arg)
    if not tpdb_data and not row and not sid_arg and name_arg:
        tpdb_data = _tpdb_performer_fetch_by_name(name_arg)

    sb_bio: dict | None = None
    if sid_arg:
        sb_bio = _performer_popup_stashbox_bio(sid_arg)
    if not sb_bio and row:
        for cand_id in (row.get("match_stashdb_id"), row.get("match_fansdb_id")):
            cand = (cand_id or "").strip()
            if cand:
                sb_bio = _performer_popup_stashbox_bio(
                    cand,
                    prefer_fansdb=(cand == (row.get("match_fansdb_id") or "").strip()),
                )
                if sb_bio:
                    break

    jav_data: dict | None = None
    jav_arg = ""
    if row:
        jav_arg = (row.get("match_javstash_id") or "").strip()
    if jav_arg:
        try:
            jav_data = fetch_performer_detail("JAVStash", jav_arg)
        except Exception:
            jav_data = None
    # JAV scene/detail UIs pass the JAVStash performer UUID in ``stash_id``
    # (``performerLinkAttrs`` only has data-stash-id). StashDB/FansDB
    # ``findPerformer`` misses those IDs — try JAVStash when we still
    # have no jav_data.  Skip only when ``sb_bio`` was resolved *from
    # this same* ``sid_arg`` (it is a real StashDB/FansDB id).  If the
    # user has a library row, ``sb_bio`` may instead come from the row's
    # *different* crosswalk id while ``sid_arg`` is still the JAV id from
    # the scene card — we must not gate on ``not sb_bio`` or JAV never
    # hydrates.
    sb_from_same_sid = bool(
        sid_arg
        and sb_bio
        and str(sb_bio.get("id") or "").strip() == (sid_arg or "").strip()
    )
    if not jav_data and sid_arg and not sb_from_same_sid:
        try:
            cand = fetch_performer_detail("JAVStash", sid_arg)
        except Exception:
            cand = None
        if cand and isinstance(cand, dict) and (
            str(cand.get("id") or "").strip() or str(cand.get("name") or "").strip()
        ):
            jav_data = cand

    # TPDB extras dict — only populated when click came from a TPDB
    # scene and no library/stash-box data was found. Provides bio
    # fields, posters/images, scenes, etc. so the popup looks full
    # rather than a stub.
    tpdb_extras: dict = (tpdb_data.get("extras") or {}) if isinstance(tpdb_data, dict) else {}

    canonical_name = (
        (row.get("folder_name") if row else "") or
        (sb_bio or {}).get("name") or
        (jav_data or {}).get("name") or
        (tpdb_data or {}).get("name") or
        name_arg or ""
    ).strip()

    aliases: list[str] = []
    if row:
        try:
            for a in json.loads(row.get("aliases_json") or "[]") or []:
                if a and str(a).strip():
                    aliases.append(str(a).strip())
        except Exception:
            pass
    for a in (sb_bio or {}).get("aliases") or []:
        if a and str(a).strip() and str(a).strip() not in aliases:
            aliases.append(str(a).strip())
    for a in (tpdb_data or {}).get("aliases") or []:
        if a and str(a).strip() and str(a).strip() not in aliases:
            aliases.append(str(a).strip())
    for a in (jav_data or {}).get("aliases") or []:
        if a and str(a).strip() and str(a).strip() not in aliases:
            aliases.append(str(a).strip())

    iafd_meta = _performers_iafd_read_meta(int(row["id"])) if row else None
    bio = {
        "gender":            (iafd_meta or {}).get("gender") or (sb_bio or {}).get("gender") or tpdb_extras.get("gender") or "",
        "birthdate":         (iafd_meta or {}).get("birth_date") or (sb_bio or {}).get("birth_date") or tpdb_extras.get("birthday") or "",
        "death_date":        (iafd_meta or {}).get("death_date") or "",
        "country":           (iafd_meta or {}).get("country") or (sb_bio or {}).get("country") or tpdb_extras.get("nationality") or "",
        "ethnicity":         (iafd_meta or {}).get("ethnicity") or (sb_bio or {}).get("ethnicity") or tpdb_extras.get("ethnicity") or "",
        "hair_color":        (iafd_meta or {}).get("hair_color") or tpdb_extras.get("hair_colour") or tpdb_extras.get("hair_color") or "",
        "eye_color":         (iafd_meta or {}).get("eye_color") or tpdb_extras.get("eye_colour") or tpdb_extras.get("eye_color") or "",
        "height":            (iafd_meta or {}).get("height") or tpdb_extras.get("height") or "",
        "measurements":      (iafd_meta or {}).get("measurements") or tpdb_extras.get("measurements") or "",
        "career_start_year": (iafd_meta or {}).get("career_start_year") or "",
        "career_end_year":   (iafd_meta or {}).get("career_end_year") or "",
        "scene_count":       0,
        "tattoos":           (iafd_meta or {}).get("tattoos") or tpdb_extras.get("tattoos") or "",
        "piercings":         (iafd_meta or {}).get("piercings") or tpdb_extras.get("piercings") or "",
        "biography":         (iafd_meta or {}).get("biography") or (tpdb_data or {}).get("bio") or "",
        "aliases":           aliases,
    }
    jav_extras = (jav_data or {}).get("extras") or {}
    if not bio["gender"]:
        bio["gender"] = str(jav_extras.get("gender") or "").strip()
    if not bio["birthdate"]:
        bio["birthdate"] = str(jav_extras.get("birthday") or "").strip()
    if not bio["country"]:
        bio["country"] = str(jav_extras.get("nationality") or "").strip()
    if not bio["ethnicity"]:
        bio["ethnicity"] = str(jav_extras.get("ethnicity") or "").strip()
    if not bio["hair_color"]:
        bio["hair_color"] = str(jav_extras.get("hair_colour") or jav_extras.get("hair_color") or "").strip()
    if not bio["eye_color"]:
        bio["eye_color"] = str(jav_extras.get("eye_colour") or jav_extras.get("eye_color") or "").strip()
    if not bio["height"]:
        bio["height"] = str(jav_extras.get("height") or "").strip()
    if not bio["measurements"]:
        bio["measurements"] = str(jav_extras.get("measurements") or "").strip()
    if not bio["tattoos"]:
        bio["tattoos"] = str(jav_extras.get("tattoos") or "").strip()
    if not bio["piercings"]:
        bio["piercings"] = str(jav_extras.get("piercings") or "").strip()
    if not bio["biography"]:
        bio["biography"] = str((jav_data or {}).get("bio") or "").strip()

    # Persist the resolved country back to the IAFD JSON cache when the
    # bio fallback chain pulled it from StashDB or TPDB (not IAFD). This
    # lets /api/favourites surface the flag on /library tiles without
    # having to re-run the StashDB/TPDB lookup every time the page
    # loads. Only writes when (a) we have a library row, (b) we resolved
    # a country, and (c) the IAFD JSON exists but lacks the field. We
    # never create a new IAFD JSON here — the IAFD scraper owns that
    # lifecycle and we don't want to pre-empt it with a stub.
    if row and bio.get("country") and iafd_meta is not None and not (iafd_meta.get("country") or "").strip():
        try:
            rid = int(row["id"])
            meta_path = _performers_iafd_dir(rid) / f"{rid}.json"
            if meta_path.is_file():
                stored = json.loads(meta_path.read_text(encoding="utf-8"))
                if not (stored.get("country") or "").strip():
                    stored["country"] = bio["country"]
                    meta_path.write_text(json.dumps(stored, indent=2), encoding="utf-8")
        except (OSError, ValueError, json.JSONDecodeError):
            pass

    headshot_url = ""
    if row:
        rid = int(row["id"])
        if iafd_meta:
            headshot_url = _performers_iafd_image_api_url(rid, 0, iafd_meta) or ""
        if not headshot_url:
            headshot_url = (row.get("image_url") or "").strip()
    if not headshot_url and sb_bio:
        sb_imgs = sb_bio.get("images") or []
        if sb_imgs:
            first = sb_imgs[0]
            headshot_url = first.get("url") if isinstance(first, dict) else (first or "")
    if not headshot_url and tpdb_data:
        # TPDB performer payload shape: {image, posters: [{url}], ...}
        headshot_url = (tpdb_data.get("image") or "").strip()
        if not headshot_url:
            posters = tpdb_data.get("posters") or []
            if posters and isinstance(posters[0], dict):
                headshot_url = (posters[0].get("url") or "").strip()
    if not headshot_url and jav_data:
        posters = jav_data.get("posters") or []
        if posters and isinstance(posters[0], dict):
            headshot_url = (posters[0].get("url") or "").strip()

    images: list[dict] = []
    if row:
        images.extend(_performer_popup_local_images(int(row["id"]), iafd_meta))
    if sb_bio:
        for im in (sb_bio.get("images") or []):
            url = im.get("url") if isinstance(im, dict) else im
            if not url:
                continue
            if any(x.get("url") == url for x in images):
                continue
            images.append({"url": url, "kind": "stashbox", "is_primary": False})
    if tpdb_data:
        for kind_key in ("posters", "image_links"):
            for im in (tpdb_data.get(kind_key) or []):
                if isinstance(im, str):
                    url = im
                elif isinstance(im, dict):
                    url = im.get("url") or im.get("image") or ""
                else:
                    continue
                if not url or any(x.get("url") == url for x in images):
                    continue
                images.append({"url": url, "kind": "tpdb", "is_primary": False})
        if tpdb_data.get("image"):
            url = tpdb_data["image"]
            if not any(x.get("url") == url for x in images):
                images.insert(0, {"url": url, "kind": "tpdb", "is_primary": True})
    if jav_data:
        for im in (jav_data.get("posters") or []):
            if isinstance(im, str):
                url = im
            elif isinstance(im, dict):
                url = im.get("url") or im.get("image") or ""
            else:
                continue
            if not url or any(x.get("url") == url for x in images):
                continue
            images.append({"url": url, "kind": "javstash", "is_primary": False})

    filmography: list[dict] = []
    perf_url = ""
    if row:
        perf_url = (row.get("match_iafd_url") or "").strip()
        perf_record = None
        if perf_url:
            perf_record = db.iafd_get_performer_by_url(perf_url)
        if not perf_record and canonical_name:
            perf_record = db.iafd_get_performer_by_name(canonical_name)
            if perf_record and not perf_url:
                perf_url = (perf_record.get("url") or "").strip()
        if perf_url:
            filmography = db.iafd_get_filmography(perf_url)
    if not filmography and canonical_name:
        perf_record = db.iafd_get_performer_by_name(canonical_name)
        if perf_record:
            perf_url = (perf_record.get("url") or "").strip()
            if perf_url:
                filmography = db.iafd_get_filmography(perf_url)

    library_status = {
        "in_library":  bool(row),
        "row_id":      int(row["id"]) if row else None,
        "folder_name": row.get("folder_name") if row else "",
        "folder_path": row.get("path") if row else "",
        "is_favourite": bool(row and row.get("is_favourite")),
        "matches_locked": bool(row and row.get("matches_locked")),
        "is_group":    bool(row and int(row.get("is_group") or 0)),
    }

    sources_block = {
        "stashdb": bool((row and row.get("match_stashdb_id")) or (sb_bio and (sb_bio.get("_source") == "StashDB"))),
        "fansdb":  bool((row and row.get("match_fansdb_id"))  or (sb_bio and (sb_bio.get("_source") == "FansDB"))),
        "tpdb":    bool((row and row.get("match_tpdb_id")) or tid_arg),
        "javstash": bool((row and row.get("match_javstash_id")) or jav_data or (sb_bio and (sb_bio.get("_source") == "JAVStash"))),
        "iafd":    bool(perf_url),
    }
    ext_links: dict = _performer_ext_links_from_row(dict(row), iafd_url=perf_url) if row else {}
    # When the click came from a TPDB scene with no library match,
    # surface the TPDB profile pill (linked, green) so the user can
    # jump out to the actual TPDB page.
    if "tpdb" not in ext_links and tid_arg:
        slug = (tpdb_data or {}).get("slug") or tid_arg
        ext_links["tpdb"] = {
            "label": "ThePornDB",
            "url": f"https://theporndb.net/performers/{quote(str(slug), safe='')}",
        }
    if "javstash" not in ext_links and jav_data:
        jid = str(jav_data.get("id") or "").strip() or (sid_arg or "").strip()
        if jid:
            ext_links["javstash"] = {
                "label": "JAVStash",
                "url": f"https://javstash.org/performers/{quote(jid, safe='')}",
            }
    if perf_url:
        ext_links["iafd"] = {"label": "IAFD", "url": perf_url}

    stash_id_out = ((row or {}).get("match_stashdb_id") or "").strip()
    fansdb_id_out = ((row or {}).get("match_fansdb_id") or "").strip()
    javstash_id_out = ((row or {}).get("match_javstash_id") or "").strip()
    if sb_bio:
        src = (sb_bio.get("_source") or "").strip()
        pid = str(sb_bio.get("id") or "").strip() or (sid_arg or "").strip()
        if src == "StashDB":
            stash_id_out = stash_id_out or pid
        elif src == "FansDB":
            fansdb_id_out = fansdb_id_out or pid
    if jav_data:
        javstash_id_out = javstash_id_out or str(jav_data.get("id") or "").strip() or (
            (sid_arg or "").strip() if not sb_bio else ""
        )

    social_links = _performer_popup_social_links(sb_bio, tpdb_data, jav_data, iafd_meta, ext_links)

    # Surface group_ids_json so the popup carousel can fan out scene
    # lookups across every linked profile, not just the primary. A
    # group performer (e.g. "Fox Twins" with two members) has zero or
    # one primary id but the real performers' ids live here.
    #
    # Preserves the rich ``{id, name, image}`` shape when an entry was
    # written by the "Link DB profile" picker (so the popup can render
    # chips with the linked performer's name + headshot), while legacy
    # bare-string entries continue to surface as ``{id}`` only.
    group_ids_payload: dict[str, list[dict]] = {"tpdb": [], "stashdb": [], "fansdb": [], "javstash": []}
    if row:
        raw_gids = (row.get("group_ids_json") or "").strip()
        if raw_gids:
            try:
                parsed_g = json.loads(raw_gids) or {}
            except (json.JSONDecodeError, TypeError):
                parsed_g = {}
            if isinstance(parsed_g, dict):
                for k in ("tpdb", "stashdb", "fansdb", "javstash"):
                    out_list: list[dict] = []
                    for x in (parsed_g.get(k) or []):
                        if isinstance(x, dict):
                            xid = str(x.get("id") or "").strip()
                            if not xid:
                                continue
                            out_list.append({
                                "id":    xid,
                                "name":  str(x.get("name") or "").strip(),
                                "image": str(x.get("image") or "").strip(),
                            })
                        else:
                            xid = str(x or "").strip()
                            if not xid:
                                continue
                            out_list.append({"id": xid, "name": "", "image": ""})
                    group_ids_payload[k] = out_list

    payload = {
        "identity": {
            "stash_id":         stash_id_out,
            "fansdb_id":        fansdb_id_out,
            "tpdb_id":          (row.get("match_tpdb_id")    if row else "") or tid_arg or (str((tpdb_data or {}).get("id") or "") if tpdb_data else ""),
            "javstash_id":      javstash_id_out,
            "library_row_id":   int(row["id"]) if row else None,
            "canonical_name":   canonical_name,
            "aliases":          aliases,
            "is_group":         bool(int(row.get("is_group") or 0)) if row else False,
            "group_ids":        group_ids_payload,
        },
        "bio":            bio,
        "headshot_url":   headshot_url,
        "images":         images,
        "filmography":    filmography,
        "library_status": library_status,
        "sources":        sources_block,
        "ext_links":      ext_links,
        "social_links":   social_links,
        "iafd_search_url": _performers_iafd_search_url(canonical_name) if canonical_name else "",
        "is_stub":        not (row or sb_bio or filmography or tpdb_data or jav_data),
        "cat_gay":        (db.get_settings().get("cat_gay") or "false").lower() == "true",
    }

    _performer_popup_cache_set(cache_key, payload)
    return JSONResponse(payload)


