@app.get("/api/performers/iafd-image")
async def api_performers_iafd_image(
    row_id: int,
    i: int = Query(0, ge=0),
    v: str | None = None,  # cache-bust token (ignored; changes when scrape updates files)
):
    meta = _performers_iafd_read_meta(row_id)
    if not meta:
        return JSONResponse({"error": "No IAFD cache"}, status_code=404)
    files = meta.get("image_files") or []
    if i >= len(files):
        return JSONResponse({"error": "No such image"}, status_code=404)
    p = _performers_iafd_dir(row_id) / files[i]
    if not p.is_file():
        return JSONResponse({"error": "Missing file"}, status_code=404)
    mt, _ = mimetypes.guess_type(str(p))
    return FileResponse(
        p,
        media_type=mt or "image/jpeg",
        headers={"Cache-Control": "private, max-age=60, must-revalidate"},
    )


@app.get("/api/performers/poster-image")
async def api_performers_poster_image(row_id: int, kind: str = "secondary"):
    """Serve a cached performer poster image for popup background overlay.

    kind=primary  — local library poster (may not exist)
    kind=secondary — TPDB/StashDB/Babepedia poster
    """
    md = _metadata_dir_for("performer", row_id)
    k = kind.strip().lower()
    if k == "primary":
        candidates = [f"{row_id}_poster_primary.webp", f"{row_id}_poster_primary.jpg", f"{row_id}_poster_1.webp", f"{row_id}_poster_1.jpg", f"{row_id}_poster.webp", f"{row_id}_poster.jpg"]
    else:
        candidates = [f"{row_id}_poster_secondary.webp", f"{row_id}_poster_secondary.jpg", f"{row_id}_poster_2.webp", f"{row_id}_poster_2.jpg", f"{row_id}_poster_primary.webp", f"{row_id}_poster_primary.jpg", f"{row_id}_poster_1.webp", f"{row_id}_poster_1.jpg", f"{row_id}_poster.webp", f"{row_id}_poster.jpg"]
    p = None
    for name in candidates:
        c = md / name
        if c.is_file():
            p = c
            break
    if not p:
        return JSONResponse({"error": "No poster cached"}, status_code=404)
    mt, _ = mimetypes.guess_type(str(p))
    return FileResponse(
        p,
        media_type=mt or "image/jpeg",
        headers={"Cache-Control": "private, max-age=60, must-revalidate"},
    )


