def _performers_save_headshot_bytes(row_id: int, data: bytes) -> None:
    """Save raw image bytes as the performer's primary headshot (image_files[0])."""
    row = db.favourite_get(row_id)
    if not row or row.get("kind") != "performer":
        raise ValueError("Not a performer row")
    if not data:
        raise ValueError("Empty image data")
    bid = int(row_id)
    storage = _performers_iafd_dir(bid)
    dest = storage / f"{bid}_0_custom.jpg"
    if not save_image_bytes_optimized(data, dest, max_edge=IMAGE_CACHE_POSTER_MAX):
        raise ValueError("Could not decode or save image")
    meta_path = storage / f"{bid}.json"
    try:
        m = json.loads(meta_path.read_text(encoding="utf-8")) if meta_path.is_file() else {}
    except Exception:
        m = {}
    files = [f for f in (m.get("image_files") or []) if "_custom" not in f]
    files.insert(0, dest.name)
    m["image_files"] = files
    m["custom_upload_saved_at"] = datetime.now(timezone.utc).isoformat()
    if not m.get("scraped_at"):
        m["scraped_at"] = datetime.now(timezone.utc).isoformat()
    if not m.get("name"):
        m["name"] = row.get("folder_name") or ""
    meta_path.write_text(json.dumps(m, indent=2), encoding="utf-8")
    db.favourite_update_matches(row_id, image_url=f"/api/performers/iafd-image?row_id={bid}&i=0")


