@app.post("/api/performers/set-headshot-cropped")
async def api_performers_set_headshot_cropped(
    row_id: int = Form(...),
    crop_x: int = Form(...),
    crop_y: int = Form(...),
    crop_w: int = Form(...),
    crop_h: int = Form(...),
    image_url: str = Form(""),
    file: UploadFile | None = File(None),
):
    """Crop an image and save the result as the performer's headshot.

    Crop happens server-side with PIL so we don't care about the canvas
    CORS-taint problem that breaks client-side cropping of remote
    candidate images (TPDB/StashDB/FansDB hosts don't send CORS headers,
    which makes `canvas.toBlob()` throw).

    Accepts either:
      - `file` — the raw source image uploaded as multipart (used for
        client-side local uploads and for local `/api/…` URLs the
        frontend pre-fetches into a Blob),
      - `image_url` — a full http(s) URL the backend fetches directly.

    Crop rect is in the *original* image's natural pixel coordinates.
    Output is saved via the existing `_performers_save_headshot_bytes`
    path so it plugs into the same storage + metadata plumbing as the
    plain upload endpoint.
    """
    if crop_w <= 0 or crop_h <= 0:
        return JSONResponse({"error": "crop_w and crop_h must be positive"}, status_code=400)
    try:
        if file is not None:
            src_bytes = await file.read()
        elif image_url:
            u = image_url.strip()
            if not u.lower().startswith(("http://", "https://")):
                return JSONResponse({"error": "image_url must be http(s) or use file upload"}, status_code=400)
            src_bytes = await run_in_threadpool(_favourites_download_image_bytes, u)
        else:
            return JSONResponse({"error": "file or image_url required"}, status_code=400)
        if not src_bytes:
            return JSONResponse({"error": "empty source image"}, status_code=400)

        def _crop_and_encode() -> bytes:
            with Image.open(BytesIO(src_bytes)) as im:
                im.load()
                nat_w, nat_h = im.size
                x0 = max(0, min(int(crop_x), nat_w - 1))
                y0 = max(0, min(int(crop_y), nat_h - 1))
                x1 = max(x0 + 1, min(int(crop_x) + int(crop_w), nat_w))
                y1 = max(y0 + 1, min(int(crop_y) + int(crop_h), nat_h))
                cropped = im.crop((x0, y0, x1, y1))
                # Cap the saved headshot height so we don't write a huge
                # JPEG when the user crops from a big source. 1024 px on
                # the long edge is plenty for the 160 px thumbnail and
                # any higher-DPI future tile.
                max_h = 1024
                if cropped.height > max_h:
                    ratio = max_h / float(cropped.height)
                    new_w = max(1, int(round(cropped.width * ratio)))
                    cropped = cropped.resize((new_w, max_h), Image.LANCZOS)
                if cropped.mode not in ("RGB", "L"):
                    cropped = cropped.convert("RGB")
                buf = BytesIO()
                cropped.save(buf, "JPEG", quality=90)
                return buf.getvalue()

        out_bytes = await run_in_threadpool(_crop_and_encode)
        await run_in_threadpool(_performers_save_headshot_bytes, row_id, out_bytes)
    except ValueError as exc:
        return JSONResponse({"error": str(exc)}, status_code=400)
    except Exception as exc:
        _log.exception("set-headshot-cropped")
        return JSONResponse({"error": f"{type(exc).__name__}: {exc}"}, status_code=500)
    return {"ok": True}


