@app.post("/api/performers/clear-posters")
async def api_performers_clear_posters(payload: dict = Body(...)):
    """Delete cached poster images so they re-fetch on next enrichment."""
    row_id = int(payload.get("row_id") or 0)
    if not row_id:
        return JSONResponse({"error": "row_id required"}, status_code=400)
    md = _metadata_dir_for("performer", row_id)
    cleared = 0
    for name in [f"{row_id}_poster_primary.webp", f"{row_id}_poster_primary.jpg", f"{row_id}_poster_secondary.webp", f"{row_id}_poster_secondary.jpg", f"{row_id}_poster.webp", f"{row_id}_poster.jpg", f"{row_id}_poster_1.webp", f"{row_id}_poster_1.jpg", f"{row_id}_poster_2.webp", f"{row_id}_poster_2.jpg"]:
        p = md / name
        if p.is_file():
            try:
                p.unlink()
                cleared += 1
            except OSError:
                pass
    return {"ok": True, "cleared": cleared}


@app.post("/api/performers/clear-headshot")
async def api_performers_clear_headshot(payload: dict = Body(...)):
    """Delete the stored headshot files and clear image_url for a performer."""
    try:
        row_id = int(payload.get("row_id") or 0)
    except (TypeError, ValueError):
        return JSONResponse({"error": "bad row_id"}, status_code=400)
    if not row_id:
        return JSONResponse({"error": "row_id required"}, status_code=400)
    row = db.favourite_get(row_id)
    if not row or row.get("kind") != "performer":
        return JSONResponse({"error": "Not found"}, status_code=404)
    rid = int(row_id)
    storage = _performers_iafd_dir(rid)
    meta_path = storage / f"{rid}.json"
    try:
        if meta_path.is_file():
            m = json.loads(meta_path.read_text(encoding="utf-8"))
            for fname in (m.get("image_files") or []):
                p = storage / fname
                if p.is_file():
                    p.unlink(missing_ok=True)
            meta_path.unlink(missing_ok=True)
    except Exception as exc:
        _log.warning("clear-headshot meta cleanup row %s: %s", row_id, exc)
    db.favourite_clear_image_url(rid)
    return {"ok": True}


def _movie_library_sort_key(folder_name: str) -> str:
    """Case-insensitive sort key: leading English article 'The ' is ignored."""
    s = (folder_name or "").strip()
    sl = s.lower()
    if sl.startswith("the "):
        return sl[4:].strip()
    return sl


@app.get("/api/favourites/row")
async def api_favourites_row(id: int):
    """Return one favourites row in the same shape as items in
    ``GET /api/favourites``. Lets the /library frontend refresh a
    single tile after an action (match / unmatch / clear / refresh)
    without paying for the full all-rows endpoint plus its filesystem
    stats per row."""
    if not id:
        return JSONResponse({"error": "id required"}, status_code=400)
    raw = db.favourite_get(int(id))
    if not raw:
        return JSONResponse({"error": "Not found"}, status_code=404)
    return {"row": _favourites_row_api(dict(raw))}


def _build_favourites_snapshot() -> dict:
    """Compute the full /api/favourites payload (every kind). Heavy:
    runs a per-vice filesystem stat + cached-logo ensure + sort/normalise
    over all rows. Wrapped in `_favourites_warm` so the cost is paid by
    a background worker, never on the request thread."""
    rows = [_favourites_row_api(dict(x)) for x in db.favourite_list()]
    perf = [x for x in rows if x.get("kind") == "performer"]
    stud = [x for x in rows if x.get("kind") == "studio"]
    mov_rows = [x for x in rows if x.get("kind") == "movie"]
    jav_rows = [x for x in rows if x.get("kind") == "jav"]
    mov = sorted(
        mov_rows,
        key=lambda r: (
            _movie_library_sort_key(r.get("folder_name") or ""),
            (r.get("folder_name") or "").lower(),
        ),
    )
    jav = sorted(
        jav_rows,
        key=lambda r: (
            _movie_library_sort_key(r.get("folder_name") or ""),
            (r.get("folder_name") or "").lower(),
        ),
    )
    vices: list[dict] = []
    s = db.get_settings()
    vices_dir_raw = (s.get("vices_dir") or "").strip()
    vices_dir = Path(vices_dir_raw).expanduser() if vices_dir_raw else None
    tpdb_key = (s.get("api_key_tpdb") or "").strip()
    # Alphabetical order by name (case-insensitive) so /library tiles
    # render in a stable A-Z flow regardless of how the user added them
    # in Settings.
    sorted_vices = sorted(_load_vices(), key=lambda v: (v.get("name") or "").lower())
    for idx, vice in enumerate(sorted_vices):
        name = (vice.get("name") or "").strip()
        if not name:
            continue
        folder_name = _vice_folder_name(name) or name
        folder_path = str(vices_dir / folder_name) if vices_dir else ""
        path_missing = bool(folder_path) and not Path(folder_path).is_dir()
        # Ensure a cached logo exists (cached → TPDB → folder art →
        # generated placeholder). Each step is a no-op when its prereq
        # isn't met, and the whole chain is skipped once the cache file
        # is present, so this stays cheap on repeat loads.
        _ensure_vice_logo(vice, s, tpdb_key=tpdb_key)
        logo_file = _vice_logo_path(vice)
        image_url = f"/api/vice-logo?name={quote(name)}" if (logo_file and logo_file.is_file()) else ""
        # First tag id that looks like a TPDB integer — used for the
        # /health Vices table's external-link column.
        first_tpdb_id = ""
        for t in vice.get("tags", []):
            tid = str(t.get("id") or "").strip()
            if tid.isdigit():
                first_tpdb_id = tid
                break
        vices.append({
            "id": -1 - idx,  # stable negative id — no collision with real favourites.id
            "kind": "vice",
            "vice_id": vice.get("id"),
            "folder_name": folder_name,
            "folder_path": folder_path,
            "root_label": "Vices",
            "path_missing": path_missing,
            "is_favourite": False,
            "matches_locked": bool(vice.get("locked")),
            "locked": bool(vice.get("locked")),
            "aliases": [],
            "gender_filters": [],
            "match_tpdb_id": first_tpdb_id,
            "match_stashdb_id": "",
            "match_fansdb_id": "",
            "image_url": image_url,
            "tag_count": len(vice.get("tags", [])),
            "tags": vice.get("tags", []),
        })
    return {
        "performers": perf,
        "studios": stud,
        "movies": mov,
        "jav": jav,
        "vices": vices,
        "settings": {
            "favourites_scan_enabled": s.get("favourites_scan_enabled", "false"),
            "favourites_scan_hour": s.get("favourites_scan_hour", "3"),
            "api_key_tmdb_configured": bool((s.get("api_key_tmdb") or "").strip()),
            "features_dir": (s.get("features_dir") or "").strip(),
            "jav_dir": (s.get("jav_dir") or "").strip(),
            "stash_local_lookup_enabled": (
                (s.get("stash_enabled") or "true").lower() == "true"
                and bool((s.get("stash_url") or "").strip())
                and bool((s.get("stash_api_key") or "").strip())
            ),
        },
    }


# 1-hour backstop: user-driven mutations bust the cache instantly via
# the auth_middleware ``/api/favourites/*`` hook, so the backstop only
# exists as a safety net for changes the in-process invalidator can't
# see (background scanners, external sqlite edits, scheduled refresh
# jobs that mutate via the db layer rather than HTTP).
_favourites_warm = _WarmCache("favourites", _build_favourites_snapshot, 3600.0)


@app.get("/api/favourites")
async def api_favourites_list(kind: str | None = None):
    """Library index payload. Served from a background-refreshed
    warm snapshot — never blocks on the full build. With
    ``?kind=performer|studio|movie|jav|vice`` only that tab's rows
    return (others come back as empty arrays) so /library can lazy-load
    one tab at a time. ``settings`` always returns since the frontend
    uses it on every page load."""
    snap = _favourites_warm.get()
    want = (kind or "").strip().lower()
    if not want:
        return snap
    # The snapshot is a single shared dict — return a per-tab view
    # without copying the big lists. FastAPI serialises to JSON; the
    # underlying lists are never mutated by callers.
    return {
        "performers": snap["performers"] if want == "performer" else [],
        "studios":    snap["studios"]    if want == "studio"    else [],
        "movies":     snap["movies"]     if want == "movie"     else [],
        "jav":        snap["jav"]        if want == "jav"       else [],
        "vices":      snap["vices"]      if want == "vice"      else [],
        "settings":   snap["settings"],
    }


