@app.get("/api/stash/local-entity-from-favourite")
async def api_stash_local_entity_from_favourite(row_id: int):
    """Open local Stash using the first linked stash-box id on this library row (TPDB, then StashDB, then FansDB)."""
    row = db.favourite_get(row_id)
    if not row:
        return JSONResponse({"error": "Not found"}, status_code=404)
    kind = row.get("kind")
    if kind not in ("performer", "studio"):
        return JSONResponse({"error": "Performer or studio only"}, status_code=400)
    k = str(kind)
    for source_key, ext in (
        ("tpdb", row.get("match_tpdb_id")),
        ("stashdb", row.get("match_stashdb_id")),
        ("fansdb", row.get("match_fansdb_id")),
    ):
        eid = str(ext or "").strip()
        if not eid:
            continue
        url = stash_resolve_local_entity_url(k, source_key, eid)
        if url:
            return {"url": url, "via": source_key}
    return {"url": None, "via": None}


@app.get("/api/favourites/performer-thumb")
async def api_favourites_performer_thumb(row_id: int, prefer: str = "primary"):
    """Resized performer image for UI.

    prefer=primary   — headshot first, poster fallback (default, used by /library)
    prefer=secondary — **strict** poster-only lookup. Checks the secondary
                       poster first, then primary/legacy poster filenames,
                       then lazy-copies from the local library's poster.jpg.
                       Does NOT fall back to the headshot chain — if no
                       poster art exists the endpoint returns 404 so the
                       caller's no-image placeholder is visible and the
                       missing enrichment is obvious in the UI (e.g. the
                       /downloads tile, which shows a circled headshot
                       overlay separately on top of whatever loads here).
    """
    pth = None
    prefer_norm = prefer.strip().lower()
    if prefer_norm == "secondary":
        md = _metadata_dir_for("performer", row_id)
        # Check every known cached poster filename (including legacy _poster_1 /
        # _poster_2 variants written by older enrichment passes). Secondary
        # (poster 2) is preferred — the richer enrichment art fetched from
        # TPDB/StashDB/Babepedia — with the local library primary as fallback.
        # Resolver checks .webp first then legacy .jpg for each role
        # in the fallback chain. Same priority as the old explicit list.
        pth = _perf_poster_resolve(
            row_id,
            "poster_secondary", "poster_2",
            "poster_primary", "poster_1", "poster",
        )
        # Still nothing? Try to lazy-copy from the local library folder's
        # poster.jpg so a freshly-favourited performer doesn't return 404
        # just because the enrichment pass hasn't run yet.
        if not pth:
            row = db.favourite_get(row_id)
            if row:
                p_local = _favourite_find_local_poster_file(row.get("path") or "")
                if p_local and p_local.is_file():
                    dest = _perf_poster_write_path(row_id, "poster_primary")
                    try:
                        if save_image_bytes_optimized(
                            p_local.read_bytes(),
                            dest,
                            max_edge=FAVOURITES_FAV_IMAGE_MAX_EDGE,
                        ):
                            pth = dest
                    except OSError:
                        pass
        # Strict mode: do NOT fall back to the headshot chain. If we reach
        # here with pth still None the caller gets a 404 and their <img
        # onerror> handler can swap in a placeholder.
    else:
        # Default / prefer=primary: headshot-first with poster fallback.
        pth = _ensure_favourites_performer_thumb_path(row_id)
    if not pth or not pth.is_file():
        return JSONResponse({"error": "Not found"}, status_code=404)
    mt, _ = mimetypes.guess_type(str(pth))
    return FileResponse(
        pth,
        media_type=mt or "image/jpeg",
        # Long-cache for library grids — the row's image_url already
        # carries a `?v=<mtime>` cache-buster (preserved through
        # _favourites_row_api) so any actual change flips the URL and
        # the browser refetches. Without the long max-age, scrolling
        # back through a grid triggered a conditional GET per tile.
        headers={"Cache-Control": "private, max-age=86400, immutable"},
    )


@app.get("/api/favourites/studio-thumb")
async def api_favourites_studio_thumb(row_id: int):
    """Resized studio logo/poster for UI (disk cache only; library originals unchanged)."""
    pth = _ensure_favourites_studio_thumb_path(row_id)
    if not pth or not pth.is_file():
        return JSONResponse({"error": "Not found"}, status_code=404)
    mt, _ = mimetypes.guess_type(str(pth))
    return FileResponse(
        pth,
        media_type=mt or "image/png",
        # See performer-thumb above — row.image_url carries the
        # cache-buster; long max-age + immutable lets the browser
        # serve from cache without revalidation on scroll-back.
        headers={"Cache-Control": "private, max-age=86400, immutable"},
    )


# ── Studio logo overlay (used by /scenes feed cards + /downloads tiles) ──
# Logos are tracked in the studio_logos table and stored as files under
# {DB parent}/metadata/studio_logos/{slug}.png. Population happens via:
#   1) one-shot seed from the legacy static/logos/studio_logos/ archive
#      (runs at startup, idempotent — only fires when the table is empty),
#   2) library scanning that adds new studio names found in scene NFOs
#      (sets logo_path=NULL so the fetcher picks them up),
#   3) the background fetcher that downloads missing logos from StashDB.
def _studio_logos_dir() -> Path:
    """Canonical on-disk home for studio logos. This is the single location
    the /api/studio-logo endpoint serves from and the fetcher writes into.
    Manual-drop directories are scanned separately via
    `_studio_logo_drop_dirs()` so users can place files under whatever name
    feels natural and the sync pass will pull them in here."""
    d = _metadata_base_dir() / "studio_logos"
    d.mkdir(parents=True, exist_ok=True)
    return d


def _studio_logo_drop_dirs() -> list[Path]:
    """Directories the disk-sync pass reads from when importing manually
    dropped logos. Includes the canonical `studio_logos/` as well as the
    common aliases users have historically used (`studio_images/`). Every
    existing directory is returned; non-existent ones are skipped.

    Files imported from a non-canonical directory are normalised + moved
    into the canonical `studio_logos/` so everything ends up in one place
    for the endpoint to serve from."""
    base = _metadata_base_dir()
    candidates = [
        base / "studio_logos",   # canonical
        base / "studio_images",  # user-preferred alias
    ]
    return [p for p in candidates if p.is_dir()]


def _studio_logo_filename(slug: str) -> str:
    """Filesystem-safe filename for a slug. Spaces → underscores so the
    on-disk name doesn't need URL escaping."""
    return slug.replace(" ", "_") + ".png"


# ─────────────────────────── Vices ──────────────────────────────────
# Vices are the user-curated side of the content-filter system. Every
# vice lives at `metadata/vices/{vice_id}/` with two files alongside:
#
#   vice.json   — snapshot of the vice row (name / tags / lock state)
#   logo.png    — cached logo served to /library and /health
#
# The id is a stable integer (1, 2, 3, …) assigned by `_next_vice_id`
# when a vice is first created, persisted in vices_json so renames
# don't orphan the folder. Legacy string-slug ids from earlier versions
# auto-migrate to integers on first `_load_vices()` call (see the
# migration block there), which also renames the metadata folder.
# `metadata/vice_logos/` is preserved as a drop-dir alias for users
# who want to manually place a logo — the sync pass migrates anything
# dropped there into the canonical per-id folder.
def _vices_metadata_root() -> Path:
    """Root dir for all per-vice metadata: `metadata/vices/`."""
    d = _metadata_base_dir() / "vices"
    d.mkdir(parents=True, exist_ok=True)
    return d


def _vice_metadata_dir(vice: dict) -> Path | None:
    """Per-vice metadata directory. Folder name = the vice's stable
    slug id from vices_json (persists across renames if the id is
    kept). Returns None when the vice has no usable id."""
    vid = str((vice or {}).get("id") or "").strip()
    if not vid:
        return None
    d = _vices_metadata_root() / vid
    try:
        d.mkdir(parents=True, exist_ok=True)
    except OSError:
        return None
    return d


def _vice_logo_path(vice: dict) -> Path | None:
    """Cached logo path for a vice row: `metadata/vices/{id}/logo.png`."""
    d = _vice_metadata_dir(vice)
    if not d:
        return None
    return d / "logo.png"


def _vice_logo_path_for_name(name: str) -> Path | None:
    """Name-based convenience wrapper — resolves the vice in
    `_load_vices()` so the caller only has the display name. Returns
    None if the vice isn't in the saved list (ids are assigned on save
    now, so an unknown name has no canonical folder)."""
    nm = (name or "").strip()
    if not nm:
        return None
    for v in _load_vices():
        if (v.get("name") or "").strip().lower() == nm.lower():
            return _vice_logo_path(v)
    return None


def _write_vice_metadata_info(vice: dict) -> None:
    """Snapshot the current vice row into `metadata/vices/{id}/vice.json`
    so the on-disk folder is self-describing — useful for debugging and
    future tools that want to link disk state back to a row without
    re-parsing the vices_json setting."""
    d = _vice_metadata_dir(vice)
    if not d:
        return
    try:
        (d / "vice.json").write_text(json.dumps(vice, indent=2, ensure_ascii=False), encoding="utf-8")
        _ensure_library_filed_permissions(d / "vice.json")
    except OSError as e:
        _log.debug(f"vice-metadata write {d}: {e}")


def _vice_folder_name(tag_name: str) -> str:
    """Human-readable folder name under vices_dir. Strips filesystem-
    hostile characters but keeps capitalisation and spaces so folders
    look like the tag name (e.g. 'Foot Fetish/' not 'foot_fetish/')."""
    name = (tag_name or "").strip()
    if not name:
        return ""
    # Strip characters that break on Windows / confuse shells.
    for ch in '<>:"/\\|?*':
        name = name.replace(ch, " ")
    # Collapse whitespace runs.
    name = " ".join(name.split())
    # Trim trailing dots / spaces (Windows rejects these in folder names).
    return name.rstrip(". ")


def _match_vice_by_scene_tags(scene: dict, settings: dict) -> tuple[str, Path] | None:
    """If any of the scene's tags is assigned to a Vice, return (vice_name,
    vice_folder_path). First matching vice wins — determinism comes from
    the vices_json order, which the UI controls.

    Tag matching is case-insensitive and compares both `id` and `name`
    (either can match). A `_force_vice` hint on the scene dict short-
    circuits tag lookup and routes straight to the named vice (used by
    manual filing from the queue). Scenes with no tags and no override
    return None.
    """
    forced = str(scene.get("_force_vice") or "").strip()
    if forced:
        vices_dir_raw = (settings.get("vices_dir") or "").strip()
        if not vices_dir_raw:
            return None
        folder = _ensure_vice_folder(forced, Path(vices_dir_raw).expanduser())
        return (forced, folder) if folder else None

    raw_tags = scene.get("tags") or []
    if not raw_tags:
        return None
    scene_ids: set[str] = set()
    scene_names: set[str] = set()
    for t in raw_tags:
        if isinstance(t, dict):
            tid = str(t.get("id") or "").strip().lower()
            tname = str(t.get("name") or "").strip().lower()
            if tid:
                scene_ids.add(tid)
            if tname:
                scene_names.add(tname)
        elif isinstance(t, str):
            scene_names.add(t.strip().lower())
    if not scene_ids and not scene_names:
        return None

    vices_dir_raw = (settings.get("vices_dir") or "").strip()
    if not vices_dir_raw:
        return None
    vices_dir = Path(vices_dir_raw).expanduser()
    for vice in _load_vices():
        vice_name = (vice.get("name") or "").strip()
        if not vice_name:
            continue
        for t in vice.get("tags", []):
            tid = str(t.get("id") or "").strip().lower()
            tname = str(t.get("name") or "").strip().lower()
            if (tid and tid in scene_ids) or (tname and tname in scene_names):
                folder = _ensure_vice_folder(vice_name, vices_dir)
                if folder:
                    return vice_name, folder
                return None
    return None


def _ensure_vice_folder(tag_name: str, vices_dir: Path | None) -> Path | None:
    """Create the vice's library folder if it doesn't exist. Returns the
    Path (or None when vices_dir isn't configured / tag_name is blank)."""
    if not vices_dir or not tag_name:
        return None
    folder_name = _vice_folder_name(tag_name)
    if not folder_name:
        return None
    target = vices_dir / folder_name
    try:
        target.mkdir(parents=True, exist_ok=True)
        return target
    except OSError:
        return None


def build_vice_tvshow_nfo(vice_name: str) -> str:
    """Minimal tvshow.nfo so Kodi / Jellyfin recognise the vice folder
    as a TV show root — matches the shape the studio writer uses so
    downstream scrapers behave identically."""
    root = ET.Element("tvshow")
    ET.SubElement(root, "title").text     = vice_name
    ET.SubElement(root, "showtitle").text = vice_name
    ET.SubElement(root, "plot").text      = ""
    ET.SubElement(root, "studio").text    = vice_name
    ET.SubElement(root, "genre").text     = "Adult"
    ET.SubElement(root, "tag").text       = "Vice"
    ET.SubElement(root, "mpaa").text      = "Adult"
    tree = ET.ElementTree(root)
    ET.indent(tree, space="  ")
    buf = io.BytesIO()
    tree.write(buf, encoding="utf-8", xml_declaration=True)
    return buf.getvalue().decode("utf-8")


def _ensure_vice_nfo_and_art(vice_name: str, vice_folder: Path, settings: dict | None = None) -> None:
    """Drop a tvshow.nfo into the vice folder so Kodi / Jellyfin pick
    it up as a TV-show root. We don't auto-write logo.png here — doing
    so would stamp whatever happens to be in the cache (often a poster
    derivative) as the folder's authoritative logo. If the user wants
    Kodi to render a clearlogo they can drop their own logo.png in,
    which the cache-build pipeline will then pick up and use."""
    if not vice_folder or not vice_folder.is_dir():
        return
    nfo_path = vice_folder / "tvshow.nfo"
    if not nfo_path.is_file():
        try:
            nfo_path.write_text(build_vice_tvshow_nfo(vice_name), encoding="utf-8")
            _ensure_library_filed_permissions(nfo_path)
        except OSError as e:
            _log.debug(f"vice-nfo write {vice_folder}: {e}")
    # Warm the cache so /library has art — but don't touch the folder.
    src = _vice_logo_path_for_name(vice_name)
    if src and not src.is_file():
        s = settings if settings is not None else (db.get_settings() or {})
        # Look up the vice by name so we pass its real stored id (the
        # art cache folder is keyed by it). No silent fallback: if the
        # vice isn't in the saved list there's nothing to cache.
        vice = next(
            (v for v in _load_vices() if (v.get("name") or "").strip().lower() == vice_name.lower()),
            None,
        )
        if vice:
            _ensure_vice_logo(vice, s, include_tpdb=False)


def _load_monitored_tags() -> list[dict]:
    """Parse `monitored_tags` setting into a list of {id, slug, name} dicts.
    Accepts both the JSON-array form and the legacy comma-separated string."""
    settings = db.get_settings() or {}
    raw = (settings.get("monitored_tags") or "").strip()
    if not raw:
        return []
    if raw.startswith("["):
        try:
            parsed = json.loads(raw)
            if isinstance(parsed, list):
                return [
                    {
                        "id": str(t.get("id") or t.get("slug") or t.get("name") or ""),
                        "slug": str(t.get("slug") or ""),
                        "name": str(t.get("name") or t.get("id") or "").strip(),
                    }
                    for t in parsed
                    if isinstance(t, dict) and (t.get("name") or t.get("id"))
                ]
        except (ValueError, TypeError):
            pass
    # Legacy comma-separated text.
    return [
        {"id": s.lower(), "slug": "", "name": s}
        for s in (x.strip() for x in raw.split(","))
        if s
    ]


def _is_int_vice_id(v: str | int | None) -> bool:
    """True when `v` is already a pure integer id (string or int form)."""
    if v is None:
        return False
    s = str(v).strip()
    if not s:
        return False
    return s.isdigit()


def _next_vice_id(existing: list[dict]) -> str:
    """Next unused integer id for a new vice, returned as a string for
    JSON-friendly persistence. Scans existing vices for numeric ids and
    returns one above the max (or 1 if none are numeric)."""
    hi = 0
    for v in existing or []:
        raw = (v or {}).get("id") if isinstance(v, dict) else None
        if _is_int_vice_id(raw):
            try:
                hi = max(hi, int(raw))
            except (TypeError, ValueError):
                continue
    return str(hi + 1)


def _migrate_vice_metadata_folder(old_id: str, new_id: str) -> None:
    """Rename the per-vice metadata folder when a legacy string id is
    renumbered to an int. Copies/moves `metadata/vices/<old_id>/` →
    `metadata/vices/<new_id>/` if the source exists and the destination
    doesn't. No-op in every other case (destination already set,
    source missing, permission error, etc.) — the caller re-runs the
    folder-sync pass which recreates anything absent."""
    if not old_id or not new_id or old_id == new_id:
        return
    root = _vices_metadata_root()
    src = root / old_id
    dst = root / new_id
    if not src.is_dir():
        return
    if dst.exists():
        return
    try:
        src.rename(dst)
        _log.info(f"vice-id migration: renamed metadata folder {old_id!r} → {new_id!r}")
    except OSError as e:
        _log.warning(f"vice-id migration: could not rename {src} → {dst}: {e}")


def _normalize_vice_tag_row(t: dict) -> dict | None:
    """Normalize one vice tag dict, preserving every source's id when present."""
    if not isinstance(t, dict):
        return None
    tn = str(t.get("name") or "").strip()
    if not tn:
        return None
    row_tag: dict = {
        "id": str(t.get("id") or "").strip(),
        "slug": str(t.get("slug") or "").strip(),
        "name": tn,
    }
    tpdb_id     = str(t.get("tpdb_id") or "").strip()
    stashdb_id  = str(t.get("stashdb_id") or t.get("stash_id") or "").strip()
    fansdb_id   = str(t.get("fansdb_id") or "").strip()
    javstash_id = str(t.get("javstash_id") or "").strip()
    raw_id = row_tag["id"]
    if not tpdb_id and raw_id.isdigit():
        tpdb_id = raw_id
    if not stashdb_id and _is_stashdb_tag_uuid(raw_id):
        stashdb_id = raw_id
    if tpdb_id:     row_tag["tpdb_id"]     = tpdb_id
    if stashdb_id:  row_tag["stashdb_id"]  = stashdb_id
    if fansdb_id:   row_tag["fansdb_id"]   = fansdb_id
    if javstash_id: row_tag["javstash_id"] = javstash_id
    stash_id = _stash_uuid_for_saved_vice_tag(row_tag) or ""
    if stash_id:
        row_tag["id"] = stash_id
    elif tpdb_id:
        row_tag["id"] = tpdb_id
    elif fansdb_id:
        row_tag["id"] = fansdb_id
    elif javstash_id:
        row_tag["id"] = javstash_id
    return row_tag


def _load_vices() -> list[dict]:
    """Return the user's Vice list as {id, name, locked, tags: [...]}.

    `id` is now always an integer-as-string (e.g. "1", "2", …) assigned
    by `_next_vice_id`. Legacy string-slug ids from earlier versions
    (e.g. "foot_fetish") get renumbered on first load, their metadata
    folders renamed, and the new list persisted.

    `locked` is a boolean — when true, the /health regenerate button
    for this vice is disabled so the curated logo can't be overwritten
    by an auto-pass.

    Reads from the `vices_json` setting. Also migrates once from the
    legacy `monitored_tags` setting (1 tag → 1 vice) when vices_json is
    empty and the monitored list isn't, so users upgrading don't lose
    anything.
    """
    settings = db.get_settings() or {}
    raw = (settings.get("vices_json") or "").strip()
    if raw:
        try:
            parsed = json.loads(raw)
            if isinstance(parsed, list):
                out: list[dict] = []
                for v in parsed:
                    if not isinstance(v, dict):
                        continue
                    name = str(v.get("name") or "").strip()
                    if not name:
                        continue
                    tags = v.get("tags") or []
                    clean_tags: list[dict] = []
                    if isinstance(tags, list):
                        for t in tags:
                            row_tag = _normalize_vice_tag_row(t)
                            if row_tag:
                                clean_tags.append(row_tag)
                    out.append({
                        # Preserve whatever id is already there. Migration
                        # to ints happens in one pass below so we can see
                        # every existing id at once.
                        "id":     str(v.get("id") or "").strip(),
                        "name":   name,
                        "locked": bool(v.get("locked")),
                        "tags":   clean_tags,
                    })
                # One-time id migration: if any row is missing an id or
                # carries a legacy string slug, renumber ALL rows 1..N,
                # rename the matching metadata folders, and persist. Int
                # ids that already exist are preserved when possible.
                needs_migration = any(not _is_int_vice_id(v.get("id")) for v in out)
                if needs_migration and out:
                    preserved_ints: set[int] = set()
                    rename_plan: list[tuple[str, str]] = []
                    # First pass: keep already-numeric ids that don't
                    # collide with each other.
                    for v in out:
                        if _is_int_vice_id(v.get("id")):
                            n = int(v["id"])
                            if n not in preserved_ints:
                                preserved_ints.add(n)
                                v["_keep_id"] = True
                    # Second pass: assign fresh ids to everything else.
                    next_int = (max(preserved_ints) if preserved_ints else 0) + 1
                    for v in out:
                        if v.pop("_keep_id", False):
                            continue
                        old_id = str(v.get("id") or "").strip()
                        new_id = str(next_int)
                        next_int += 1
                        if old_id and old_id != new_id:
                            rename_plan.append((old_id, new_id))
                        v["id"] = new_id
                    for old_id, new_id in rename_plan:
                        _migrate_vice_metadata_folder(old_id, new_id)
                    try:
                        _save_vices(out, sync_monitored=False)
                    except Exception as e:
                        _log.debug(f"vice id migration save failed: {e}")
                return out
        except (ValueError, TypeError):
            pass

    # Migrate from legacy monitored_tags: each tag → its own vice. User
    # can then merge them in the UI. Persists the migration so we only
    # run it once.
    legacy = _load_monitored_tags()
    if not legacy:
        return []
    vices: list[dict] = []
    for idx, t in enumerate((x for x in legacy if x.get("name")), start=1):
        vices.append({"id": str(idx), "name": t["name"], "locked": False, "tags": [t]})
    try:
        _save_vices(vices, sync_monitored=False)
    except Exception as e:
        _log.debug(f"vice migration save failed: {e}")
    return vices


def _save_vices(vices: list[dict], sync_monitored: bool = True) -> None:
    """Persist vices_json and optionally rewrite monitored_tags to the
    flattened tag list so existing feed / blacklist logic keeps working.
    Also refreshes each vice's `metadata/vices/{id}/vice.json` snapshot."""
    db.save_settings({"vices_json": json.dumps(vices, ensure_ascii=False)})
    if sync_monitored:
        seen: set[str] = set()
        flat: list[dict] = []
        for v in vices:
            for t in v.get("tags", []):
                if not isinstance(t, dict):
                    continue
                row = dict(t)
                stash_id = _stash_uuid_for_saved_vice_tag(row) or ""
                tpdb_id = str(row.get("tpdb_id") or "").strip()
                if not tpdb_id:
                    raw_id = str(row.get("id") or "").strip()
                    if raw_id.isdigit():
                        tpdb_id = raw_id
                if stash_id:
                    row["id"] = stash_id
                    row["stashdb_id"] = stash_id
                elif tpdb_id:
                    row["id"] = tpdb_id
                if tpdb_id:
                    row["tpdb_id"] = tpdb_id
                key = str(row.get("id") or row.get("name") or "").lower()
                if not key or key in seen:
                    continue
                seen.add(key)
                flat.append(row)
        db.save_settings({"monitored_tags": json.dumps(flat, ensure_ascii=False)})
    for v in vices:
        _write_vice_metadata_info(v)


def _sync_vice_folders() -> None:
    """Create a folder under vices_dir for every configured Vice.
    Idempotent — existing folders are left alone, missing ones mkdir'd.
    Runs in a background thread after the setting changes and once on
    startup for migration of legacy monitored_tags."""
    settings = db.get_settings() or {}
    vices_dir_raw = (settings.get("vices_dir") or "").strip()
    if not vices_dir_raw:
        return
    vices_dir = Path(vices_dir_raw).expanduser()
    try:
        vices_dir.mkdir(parents=True, exist_ok=True)
    except OSError as e:
        _log.warning(f"vice-sync: cannot create vices_dir {vices_dir}: {e}")
        return
    for vice in _load_vices():
        name = (vice.get("name") or "").strip()
        if not name:
            continue
        folder = _ensure_vice_folder(name, vices_dir)
        if folder:
            _ensure_vice_nfo_and_art(name, folder, settings)
        # Per-vice metadata folder + link JSON — parallel to studios.
        _write_vice_metadata_info(vice)


_VICE_FOLDER_LOGO_NAMES = (
    "logo.png", "clearlogo.png", "logo.jpg", "clearlogo.jpg",
    "logo.webp", "clearlogo.webp",
    "landscape.png", "landscape.jpg", "landscape.webp",
    "banner.png", "banner.jpg", "banner.webp",
    "poster.jpg", "poster.png", "folder.jpg", "folder.png",
)


def _find_vice_folder_art(vice_folder: Path) -> Path | None:
    """Scan the vice's library folder for any existing logo / poster /
    banner image. Priority:
      1. canonical names (logo.png, poster.jpg, folder.jpg, …)
      2. any image file at the folder root (user-dropped art with an
         arbitrary filename — `my-vice-banner.jpg`, etc.)

    Returns the first match, or None if the folder has no images at all."""
    if not vice_folder or not vice_folder.is_dir():
        return None
    try:
        files = [c for c in vice_folder.iterdir() if c.is_file()]
    except OSError:
        return None
    by_lower = {c.name.lower(): c for c in files}
    # 1. Canonical-name pass.
    for name in _VICE_FOLDER_LOGO_NAMES:
        cand = by_lower.get(name)
        if cand:
            return cand
    # 2. Any image at the folder root — first one by sorted name so the
    # choice is deterministic. Video files are skipped so we don't pick
    # up the scenes themselves.
    image_exts = {".png", ".jpg", ".jpeg", ".webp", ".gif", ".bmp"}
    image_candidates = sorted(
        [c for c in files if c.suffix.lower() in image_exts],
        key=lambda p: p.name.lower(),
    )
    return image_candidates[0] if image_candidates else None


def _generate_vice_text_logo(name: str, dest: Path) -> bool:
    """Fallback logo — render the vice name in white Tox-Typewriter text
    on a transparent PNG so the /library duotone backdrop still shows
    through. Used when the user has no pre-existing art and no TPDB-
    sourced image. Wrapped in a broad try/except so any Pillow-version
    quirk returns False instead of bubbling a 500 up to the caller."""
    try:
        from PIL import Image, ImageDraw, ImageFont
    except ImportError:
        _log.debug("vice-logo generate: Pillow not installed")
        return False
    try:
        w, h = 800, 300
        img = Image.new("RGBA", (w, h), (0, 0, 0, 0))
        draw = ImageDraw.Draw(img)
        font = None
        candidates = [
            Path(__file__).parent / "static" / "fonts" / "Tox Typewriter.ttf",
            Path(__file__).parent / "static" / "fonts" / "DejaVuSans-Bold.ttf",
            Path("/usr/share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf"),
            Path("/usr/share/fonts/TTF/DejaVuSans-Bold.ttf"),
            Path("/Library/Fonts/Arial Bold.ttf"),
        ]
        target_size = 110
        for p in candidates:
            if p.is_file():
                try:
                    font = ImageFont.truetype(str(p), target_size)
                    break
                except (OSError, IOError):
                    continue
        if font is None:
            try:
                font = ImageFont.load_default()
            except Exception:
                return False
        text = (name or "VICE").upper()
        # textbbox is Pillow ≥ 8.0; fall back to textsize on older builds.
        def _measure(f, t):
            if hasattr(draw, "textbbox"):
                b = draw.textbbox((0, 0), t, font=f)
                return b[0], b[1], b[2] - b[0], b[3] - b[1]
            try:
                tw_, th_ = draw.textsize(t, font=f)
                return 0, 0, tw_, th_
            except Exception:
                return 0, 0, len(t) * 20, 30
        bx, by, tw, th = _measure(font, text)
        if tw > w - 40 and hasattr(font, "path"):
            scale = max(0.3, (w - 40) / max(1, tw))
            try:
                font = ImageFont.truetype(font.path, max(24, int(target_size * scale)))
                bx, by, tw, th = _measure(font, text)
            except (OSError, IOError):
                pass
        x = (w - tw) // 2 - bx
        y = (h - th) // 2 - by
        # Stacked fills: soft outline for legibility, white body on top.
        for ox, oy in [(-2, 0), (2, 0), (0, -2), (0, 2)]:
            try:
                draw.text((x + ox, y + oy), text, font=font, fill=(0, 0, 0, 160))
            except Exception:
                pass
        draw.text((x, y), text, font=font, fill=(255, 255, 255, 255))
        dest.parent.mkdir(parents=True, exist_ok=True)
        img.save(dest, "PNG")
        _ensure_library_filed_permissions(dest)
        return True
    except Exception as e:
        _log.exception(f"vice-logo generate failed for {name!r}: {e}")
        return False


def _ensure_vice_logo(vice: dict, settings: dict, include_tpdb: bool = False, tpdb_key: str = "") -> Path | None:
    """Produce a cached vice logo via the fallback chain:
         1. existing `metadata/vices/{id}/logo.png` — use it
         2. legacy `metadata/vice_logos/{slug}.png` — migrate into the
            per-id folder, then use it
         3. (only when include_tpdb=True) matching TPDB tag → normalise into cache
         4. any logo/poster file inside the vice's library folder → cache
         5. generate a text PNG with the vice name

    Synchronous callers (like /api/favourites) pass include_tpdb=False
    so a flaky TPDB network call can't stall the endpoint. The background
    `_fetch_missing_vice_logos()` thread uses include_tpdb=True.

    Returns the cached Path on success, None on total failure (only
    happens if the filesystem itself is unwriteable)."""
    name = (vice.get("name") or "").strip()
    if not name:
        return None
    # The caller must supply a stored id — vices are always loaded via
    # `_load_vices()` which guarantees one, and synchronous fallbacks
    # through `_vice_logo_path_for_name()` already look it up. Bail if
    # the dict is malformed rather than silently synthesising.
    dest = _vice_logo_path(vice)
    if not dest:
        return None
    if dest.is_file():
        return dest
    # Migration: pull from the legacy `metadata/vice_logos/{slug}.png`
    # location into the per-id folder so existing installs don't have
    # to regenerate their art. Move, don't copy, so there's a single
    # source of truth going forward.
    legacy_slug = db.studio_logo_slug(name)
    if legacy_slug:
        legacy = _metadata_base_dir() / "vice_logos" / (legacy_slug.replace(" ", "_") + ".png")
        if legacy.is_file():
            try:
                dest.parent.mkdir(parents=True, exist_ok=True)
                legacy.replace(dest)
                _ensure_library_filed_permissions(dest)
                return dest
            except OSError as e:
                _log.debug(f"vice-logo legacy migrate {legacy} → {dest}: {e}")

    if include_tpdb and tpdb_key:
        for tag in vice.get("tags", []):
            tag_id = str(tag.get("id") or "").strip()
            if not tag_id or not tag_id.isdigit():
                continue
            img_url = _tpdb_tag_image_url(tag_id, tpdb_key)
            if not img_url:
                continue
            try:
                r = requests.get(img_url, timeout=15, allow_redirects=True)
                if r.status_code == 200 and r.content:
                    if _normalise_studio_logo_to_png(r.content, dest):
                        _ensure_library_filed_permissions(dest)
                        return dest
            except (requests.RequestException, OSError) as e:
                _log.debug(f"vice-logo TPDB fetch: {name} → {e}")

    # 3. User-dropped art inside the vice's folder — poster.jpg, logo.png, etc.
    vices_dir_raw = (settings.get("vices_dir") or "").strip()
    if vices_dir_raw:
        vice_folder = Path(vices_dir_raw).expanduser() / (_vice_folder_name(name) or name)
        local = _find_vice_folder_art(vice_folder)
        if local:
            try:
                if _normalise_studio_logo_to_png(local.read_bytes(), dest):
                    _ensure_library_filed_permissions(dest)
                    return dest
            except OSError:
                pass

    # 4. Generated placeholder — last resort so /library always has art.
    if _generate_vice_text_logo(name, dest):
        return dest
    return None


def _fetch_missing_vice_logos() -> None:
    """Background pass: TPDB-enabled logo hydration for every Vice.
    Safe to call repeatedly — cached logos short-circuit the chain."""
    settings = db.get_settings() or {}
    tpdb_key = (settings.get("api_key_tpdb") or "").strip()
    for vice in _load_vices():
        _ensure_vice_logo(vice, settings, include_tpdb=True, tpdb_key=tpdb_key)


def _tpdb_tag_image_url(tag_id: str, api_key: str) -> str | None:
    """Best-effort TPDB tag-image URL. Returns None if the tag has no
    image or the API call fails. Small wrapper — TPDB's tag endpoint
    returns an `image` field when populated."""
    try:
        r = requests.get(
            f"https://api.theporndb.net/tags/{tag_id}",
            headers={"Authorization": f"Bearer {api_key}", "Accept": "application/json"},
            timeout=10,
        )
        if r.status_code != 200:
            return None
        data = r.json() or {}
        payload = data.get("data") if isinstance(data.get("data"), dict) else data
        img = (payload or {}).get("image") or (payload or {}).get("poster")
        return img if isinstance(img, str) and img else None
    except (requests.RequestException, ValueError):
        return None


_STUDIO_NFO_TAG_BIN = re.compile(rb"<studio[^>]*>([^<]+)</studio>", re.I)
_PNG_MAGIC = b"\x89PNG\r\n\x1a\n"


def _normalise_studio_logo_to_png(src_bytes: bytes, dest: Path, target_width: int = 300) -> bool:
    """Convert any image bytes (SVG, JPEG, WebP, GIF, raw PNG…) into a
    transparent PNG at most `target_width` px wide and write to `dest`.

    Strategy:
      1) ImageMagick `magick` (handles SVG + every raster format + transparency).
         Falls back to legacy `convert` binary if `magick` isn't on PATH.
      2) Pillow — raster only, no SVG support, used when ImageMagick is missing.

    Returns True on a clean write, False on any failure.
    """
    if not src_bytes:
        return False
    dest.parent.mkdir(parents=True, exist_ok=True)

    # Fast path: bytes are already a valid PNG and within the width budget.
    if src_bytes.startswith(_PNG_MAGIC):
        try:
            with Image.open(BytesIO(src_bytes)) as im:
                if im.width <= target_width:
                    dest.write_bytes(src_bytes)
                    return True
                # Resize wider PNGs via Pillow so the on-disk shape is uniform.
                im = im.convert("RGBA")
                ratio = target_width / im.width
                im = im.resize((target_width, max(1, int(im.height * ratio))), Image.LANCZOS)
                im.save(dest, format="PNG", optimize=True)
                return True
        except Exception:
            pass  # malformed PNG header — fall through to magick

    # Try ImageMagick — it can render SVG, AVIF, WebP, etc.
    import subprocess, tempfile
    src_tmp = None
    try:
        with tempfile.NamedTemporaryFile(suffix=".bin", delete=False) as tf:
            tf.write(src_bytes)
            src_tmp = tf.name
        for binary in ("magick", "convert"):
            cmd = [
                binary,
                "-background", "none",
                src_tmp,
                "-resize", f"{target_width}x>",
                "-alpha", "set",
                f"PNG32:{dest}",
            ]
            try:
                r = subprocess.run(cmd, capture_output=True, timeout=30)
            except FileNotFoundError:
                continue  # try next binary
            except subprocess.TimeoutExpired:
                continue
            if r.returncode == 0 and dest.is_file() and dest.stat().st_size > 0:
                # Sanity-check the output header — magick has been known to
                # write something it can't read back. Pillow re-open
                # confirms it's a valid PNG before we declare success.
                try:
                    with Image.open(dest) as _im:
                        _im.verify()
                    return True
                except Exception:
                    pass
    finally:
        if src_tmp:
            try:
                os.unlink(src_tmp)
            except OSError:
                pass

    # Final fallback: raw Pillow (no SVG, but handles every raster format).
    try:
        with Image.open(BytesIO(src_bytes)) as im:
            im = im.convert("RGBA")
            if im.width > target_width:
                ratio = target_width / im.width
                im = im.resize((target_width, max(1, int(im.height * ratio))), Image.LANCZOS)
            im.save(dest, format="PNG", optimize=True)
            return True
    except Exception:
        return False


def _normalise_existing_studio_logos() -> int:
    """One-shot pass: walk metadata/studio_logos/, find any file that isn't
    a real PNG (e.g. SVG-with-.png from the legacy archive), and convert it
    in place via `_normalise_studio_logo_to_png`. Gated by the
    `studio_logos_normalised_v1` setting so it only runs once per install.
    Returns the number of files converted.
    """
    s = db.get_settings()
    if (s.get("studio_logos_normalised_v1") or "").lower() == "true":
        return 0
    dest_dir = _studio_logos_dir()
    if not dest_dir.is_dir():
        db.save_settings({"studio_logos_normalised_v1": "true"})
        return 0
    converted = 0
    failed = 0
    inspected = 0
    for p in dest_dir.iterdir():
        if not p.is_file() or p.suffix.lower() != ".png":
            continue
        inspected += 1
        try:
            with open(p, "rb") as fh:
                head = fh.read(16)
        except OSError:
            continue
        if head.startswith(_PNG_MAGIC):
            continue  # already a real PNG
        try:
            data = p.read_bytes()
        except OSError:
            failed += 1
            continue
        if _normalise_studio_logo_to_png(data, p):
            converted += 1
        else:
            failed += 1
            _log.warning(f"studio-logo normalise: failed to convert {p.name}")
    db.save_settings({"studio_logos_normalised_v1": "true"})
    if converted or failed:
        emit(f"studio-logo normalise: inspected {inspected}, converted {converted}, failed {failed}")
    return converted


def _studio_logos_discover_from_nfos(*, since_ts: float = 0.0, budget_s: float = 600.0) -> int:
    """Walk every configured library root, scan NFOs for `<studio>…</studio>`
    tags, and add any new studio names to the studio_logos table with
    logo_path=NULL so the background fetcher will pick them up.

    `since_ts` allows incremental scans — only NFOs whose mtime is newer than
    the timestamp are read. The first run uses 0 (full walk); subsequent runs
    use the timestamp persisted in the `studio_logos_last_nfo_scan` setting.
    `budget_s` caps the wall-clock time so a giant first run can't block the
    library scan thread forever.

    Returns the number of NEW slugs inserted.
    """
    s = db.get_settings()
    roots: list[Path] = []
    for key in ("series_dir", "features_dir"):
        v = (s.get(key) or "").strip()
        if v:
            roots.append(Path(v).expanduser())
    for d in db.get_directories("performer"):
        p = (d.get("path") or "").strip()
        if p:
            roots.append(Path(p).expanduser())

    # Pre-load existing slugs so we don't re-insert.
    existing_slugs = {r["slug"] for r in db.studio_logo_list_all() if r.get("slug")}

    inserted = 0
    nfo_count = 0
    start = time.time()
    for root in roots:
        if not root.is_dir():
            continue
        for dirpath, _dirs, filenames in os.walk(root):
            if (time.time() - start) >= budget_s:
                emit(f"studio-logo discover: budget exhausted at {nfo_count} NFOs")
                return inserted
            for fn in filenames:
                if not fn.lower().endswith(".nfo"):
                    continue
                fp = os.path.join(dirpath, fn)
                try:
                    if since_ts > 0:
                        st = os.stat(fp)
                        if st.st_mtime <= since_ts:
                            continue
                    nfo_count += 1
                    with open(fp, "rb") as fh:
                        head = fh.read(4096)
                    for m in _STUDIO_NFO_TAG_BIN.finditer(head):
                        name = m.group(1).decode("utf-8", errors="ignore").strip()
                        if not name:
                            continue
                        slug = db.studio_logo_slug(name)
                        if not slug or slug in existing_slugs:
                            continue
                        rid = db.studio_logo_upsert(name)
                        if rid is not None:
                            existing_slugs.add(slug)
                            inserted += 1
                except OSError:
                    pass
    emit(f"studio-logo discover: scanned {nfo_count} NFOs, {inserted} new studios added")
    return inserted


def _studio_logos_discover_run(*, force_full: bool = False) -> int:
    """Persists last-run timestamp so each call only walks NFOs modified since
    the previous successful run. The first run takes a few minutes for a big
    library; subsequent runs are near-instant."""
    s = db.get_settings()
    try:
        last_ts = 0.0 if force_full else float(s.get("studio_logos_last_nfo_scan") or 0.0)
    except (TypeError, ValueError):
        last_ts = 0.0
    inserted = _studio_logos_discover_from_nfos(since_ts=last_ts)
    db.save_settings({"studio_logos_last_nfo_scan": str(time.time())})
    return inserted


def _studio_logo_fetch_one(row: dict, api_key: str, dest_dir: Path) -> tuple[bool, str]:
    """Pull a single logo from StashDB → save to disk → mark the row done.

    Returns ``(ok, reason)`` where ``reason`` is a short machine-friendly
    slug ("" on success, e.g. "no_search_results", "no_images",
    "http_404", "normalise_failed", "stashdb_exception: ...") so the
    caller can persist it on the row for the dead-letter UI.
    """
    name = (row.get("name") or "").strip()
    slug = row.get("slug") or ""
    if not name or not slug:
        return False, "missing_name_or_slug"
    try:
        results = stashdb_search_studio(name, api_key)
    except Exception as e:
        return False, f"stashdb_exception: {type(e).__name__}: {str(e)[:120]}"
    if not results:
        return False, "no_search_results"
    # Prefer the best name match (case-insensitive equality), else first result.
    chosen = None
    name_lc = name.lower()
    for r in results:
        if (r.get("name") or "").strip().lower() == name_lc:
            chosen = r
            break
    chosen = chosen or results[0]
    images = chosen.get("images") or []
    if not images:
        return False, "no_images"
    img = images[0]
    img_url = img.get("url") if isinstance(img, dict) else img
    if not img_url:
        return False, "no_image_url"
    try:
        resp = requests.get(img_url, timeout=15)
        if resp.status_code != 200:
            return False, f"http_{resp.status_code}"
        if not resp.content:
            return False, "empty_response"
        dest_name = _studio_logo_filename(slug)
        dest = dest_dir / dest_name
        # Always normalise the payload — StashDB serves a mix of SVG / PNG /
        # WebP / JPEG, and the endpoint hardcodes media_type=image/png so the
        # bytes on disk MUST be a valid PNG.
        if not _normalise_studio_logo_to_png(resp.content, dest):
            return False, "normalise_failed"
        db.studio_logo_set_path(int(row["id"]), dest_name, source="stashdb")
        return True, ""
    except Exception as e:
        return False, f"download_exception: {type(e).__name__}: {str(e)[:120]}"


_STUDIO_LOGO_IMAGE_EXTS = {".png", ".jpg", ".jpeg", ".webp", ".gif", ".bmp", ".svg", ".tif", ".tiff"}


def _sync_manual_studio_logos_from_disk() -> dict:
    """Scan every studio-logo drop directory and reconcile the studio_logos
    table with the files on disk. Designed so manual drops always win:

      1) For each drop dir (see `_studio_logo_drop_dirs()`): normalise every
         supported image to a canonical PNG stored at
         `metadata/studio_logos/{slug}.png`. Accepts png / jpg / jpeg / webp
         / gif / bmp / svg / tif / tiff. Source files (including PNGs in
         non-canonical dirs) are moved/copied into `studio_logos/` and the
         original is removed once the target exists so everything ends up
         in one place for the endpoint to serve from.
      2) When two files collide on the same normalised slug, keep whichever
         was written most recently (the user's latest intentional drop).
      3) Reconcile the DB against the canonical `studio_logos/` contents:
         - no row for this slug         → INSERT (source='manual')
         - row exists with NULL path    → BACKFILL (source='manual')
         - row points at the same file  → no-op
         - row points at a DIFFERENT file → REPLACE logo_path (source='manual')

    Returns a dict of counts (inspected / normalised / normalise_failed /
    new / backfilled / updated / unchanged). Also emits() a one-line summary
    when anything moved, for the activity log.
    """
    canonical = _studio_logos_dir()
    drop_dirs = _studio_logo_drop_dirs()
    if canonical not in drop_dirs:
        drop_dirs.insert(0, canonical)

    # ── Pass 1: import every image from every drop directory into the
    # canonical `studio_logos/` directory, normalising non-PNGs along the
    # way. Hot-path skip: a `.png` file already at its canonical name
    # inside `studio_logos/` is trusted and not touched — this matters a
    # lot when the drop dir holds thousands of already-processed logos
    # because even an 8-byte header read per file costs ~7ms/file on
    # networked storage. SVG-mislabeled-as-PNG stragglers in the
    # canonical dir are handled by `_normalise_existing_studio_logos()`
    # which runs once on startup gated by `studio_logos_normalised_v1`;
    # for new drops users should prefer `studio_images/` which always
    # runs through the normaliser because it's never "canonical".
    normalised = 0
    normalise_failed = 0
    for src_dir in drop_dirs:
        in_canonical_dir = (src_dir == canonical)
        for p in list(src_dir.iterdir()):
            if not p.is_file():
                continue
            ext = p.suffix.lower()
            if ext not in _STUDIO_LOGO_IMAGE_EXTS:
                continue
            slug = db.studio_logo_slug(p.stem)
            if not slug:
                continue
            target_name = _studio_logo_filename(slug)
            # Trust-by-name fast path: file already in canonical dir at
            # canonical slug filename with a .png extension → leave it
            # alone, zero I/O, Pass 2 picks it up by listing the dir.
            if in_canonical_dir and ext == ".png" and p.name == target_name:
                continue
            # Slow path: file is either in a non-canonical dir (needs
            # moving + normalising) OR at a non-canonical name in the
            # canonical dir (e.g. "Brazzers Rough.png" → "brazzers_rough.png"
            # rename). Read bytes, run through the normaliser.
            target = canonical / target_name
            try:
                src_bytes = p.read_bytes()
            except OSError as e:
                emit(f"studio-logo import: could not read {p} ({e})")
                normalise_failed += 1
                continue
            if _normalise_studio_logo_to_png(src_bytes, target):
                normalised += 1
                # Remove the source unless it IS the target (same path).
                try:
                    if p.resolve() != target.resolve():
                        p.unlink()
                except OSError:
                    pass
            else:
                emit(f"studio-logo import: could not normalise {p} to PNG")
                normalise_failed += 1

    # ── Pass 2: reconcile the DB against the canonical directory.
    rows = db.studio_logo_list_all()
    rows_by_slug: dict[str, dict] = {}
    for r in rows:
        if r.get("slug"):
            rows_by_slug[r["slug"]] = r

    # Full accounting: every directory entry is counted into exactly one
    # bucket so the caller can see at a glance whether files are being
    # silently dropped, and why. The raw_entries count is every entry
    # iterdir() returned, including dotfiles, subdirectories, symlinks,
    # and device files.
    files_per_slug: dict[str, Path] = {}
    files_inspected = 0
    skipped_no_slug = 0
    skipped_non_png = 0
    skipped_hidden = 0
    skipped_dir = 0
    skipped_symlink_broken = 0
    skipped_not_regular = 0
    skipped_unreadable = 0
    duplicate_slug = 0
    raw_entries = 0
    sample_skipped: list[str] = []

    def _sample(label: str, name: str) -> None:
        if len(sample_skipped) < 20:
            sample_skipped.append(f"{label}: {name}")

    try:
        entries = list(canonical.iterdir())
    except OSError as e:
        emit(f"studio-logo sync: could not list {canonical}: {e}")
        entries = []

    for p in entries:
        raw_entries += 1
        name = p.name
        # Hidden files (e.g. .DS_Store, macOS sidecars, SynoResource stubs)
        # should be visible in the count so the user can clean them up.
        if name.startswith("."):
            skipped_hidden += 1
            _sample("hidden", name)
            continue
        try:
            if p.is_symlink() and not p.exists():
                skipped_symlink_broken += 1
                _sample("broken symlink", name)
                continue
            if p.is_dir():
                skipped_dir += 1
                _sample("subdir", name)
                continue
            if not p.is_file():
                skipped_not_regular += 1
                _sample("not-a-file", name)
                continue
        except OSError as e:
            skipped_unreadable += 1
            _sample(f"unreadable ({e})", name)
            continue
        if p.suffix.lower() != ".png":
            # After Pass 1 every supported image type should already have been
            # normalised → PNG. Anything still non-PNG here is either an
            # unsupported extension or a normalise failure — either way the
            # user needs to see it.
            skipped_non_png += 1
            _sample("non-png", name)
            continue
        files_inspected += 1
        slug = db.studio_logo_slug(p.stem)
        if not slug:
            skipped_no_slug += 1
            _sample("empty slug", name)
            emit(f"studio-logo sync: file {name!r} normalised to empty slug, skipping")
            continue
        existing = files_per_slug.get(slug)
        if existing is None:
            files_per_slug[slug] = p
            continue
        duplicate_slug += 1
        _sample(f"slug collision {slug!r}", name)
        try:
            if p.stat().st_mtime > existing.stat().st_mtime:
                files_per_slug[slug] = p
        except OSError:
            pass

    synced = 0          # new row inserted
    backfilled = 0      # existing row had NULL logo_path → filled in
    updated = 0         # existing row pointed at a different file → rewritten
    unchanged = 0       # row already matches the disk → no-op
    for slug, p in files_per_slug.items():
        filename = p.name
        row = rows_by_slug.get(slug)
        if row is None:
            rid = db.studio_logo_upsert(p.stem, logo_path=filename, source="manual")
            if rid is not None:
                synced += 1
            continue
        current_path = row.get("logo_path") or ""
        if not current_path:
            db.studio_logo_set_path(int(row["id"]), filename, source="manual")
            backfilled += 1
            continue
        if current_path == filename:
            unchanged += 1
            continue
        # Disk disagrees with the DB. Manual drops always win so the row is
        # rewritten to point at whatever the user actually put on disk.
        db.studio_logo_set_path(int(row["id"]), filename, source="manual")
        updated += 1

    if synced or backfilled or updated or normalised or normalise_failed or skipped_no_slug or skipped_non_png or skipped_hidden or skipped_dir or skipped_symlink_broken or skipped_not_regular or skipped_unreadable or duplicate_slug:
        emit(
            f"studio-logo sync: raw={raw_entries} inspected={files_inspected} "
            f"hidden={skipped_hidden} subdirs={skipped_dir} "
            f"not_regular={skipped_not_regular} broken_symlinks={skipped_symlink_broken} "
            f"unreadable={skipped_unreadable} non_png={skipped_non_png} "
            f"empty_slug={skipped_no_slug} dup_slug={duplicate_slug} "
            f"normalised={normalised} normalise_failed={normalise_failed} "
            f"new={synced} backfilled={backfilled} "
            f"updated={updated} unchanged={unchanged}"
        )
        if sample_skipped:
            for line in sample_skipped[:20]:
                emit(f"  skipped sample → {line}")
    return {
        "raw_entries": raw_entries,
        "inspected": files_inspected,
        "skipped_hidden": skipped_hidden,
        "skipped_dir": skipped_dir,
        "skipped_not_regular": skipped_not_regular,
        "skipped_symlink_broken": skipped_symlink_broken,
        "skipped_unreadable": skipped_unreadable,
        "skipped_non_png": skipped_non_png,
        "skipped_no_slug": skipped_no_slug,
        "duplicate_slug": duplicate_slug,
        "normalised": normalised,
        "normalise_failed": normalise_failed,
        "new": synced,
        "backfilled": backfilled,
        "updated": updated,
        "unchanged": unchanged,
        "sample_skipped": sample_skipped,
    }


@app.post("/api/studio-logos/resync")
async def api_studio_logos_resync():
    """One-shot studio-logo maintenance: disk→DB sync, NFO discovery, and a
    StashDB fetch pass for any pending rows. Run this after dropping image
    files into metadata/studio_logos/ OR after adding new scenes to the
    library so studios referenced in fresh NFOs get picked up on demand
    instead of waiting for the 6-hour background tick.

    Pipeline:
      1) normalise + import any image files in metadata/studio_logos/
         (png / jpg / jpeg / webp / gif / bmp / svg / tif / tiff)
      2) walk the library roots for NFOs, insert any new <studio> names
         as pending rows (logo_path = NULL)
      3) fetch StashDB logos for every pending row, up to the fetcher budget
    """
    sync_result: dict = {}
    try:
        r = _sync_manual_studio_logos_from_disk()
        if isinstance(r, dict):
            sync_result = r
    except Exception as e:
        return JSONResponse({"error": f"sync failed: {e}"}, status_code=500)

    discovered = 0
    try:
        # force_full=True so the user's "button mash" picks up NFOs the
        # scheduler may have skipped (e.g. library added while the app was
        # offline). On a warm cache this is near-instant anyway.
        discovered = _studio_logos_discover_run(force_full=True) or 0
    except Exception as e:
        return JSONResponse(
            {"error": f"discover failed: {e}", "sync": sync_result},
            status_code=500,
        )

    fetch_result: dict = {}
    try:
        fetch_result = _studio_logos_drain() or {}
    except Exception as e:
        return JSONResponse(
            {"error": f"fetch failed: {e}", "sync": sync_result, "discovered": discovered},
            status_code=500,
        )
    unresolvable = db.studio_logo_list_unresolvable()
    return {
        "ok": True,
        "sync": sync_result,
        "discovered": discovered,
        "fetched": fetch_result.get("fetched", 0),
        "fetch_failed": fetch_result.get("failed", 0),
        "fetch_skipped": fetch_result.get("skipped"),
        "fetch_passes": fetch_result.get("passes", 0),
        "fetch_duration_s": fetch_result.get("duration_s", 0),
        "pending_after": db.studio_logo_count_pending(),
        "unresolvable": len(unresolvable),
        "total_rows": db.studio_logo_count(),
        "rows_with_logo": db.studio_logo_count(only_with_file=True),
    }


@app.get("/api/studio-logos/unresolvable")
async def api_studio_logos_unresolvable():
    """Dead-letter list: studios the fetcher has given up on.

    Returns rows whose ``fetch_attempts`` has hit the cap so the UI can
    show which studios need a manual PNG drop (or deletion if it's a
    junk row from an NFO typo).
    """
    return {"rows": db.studio_logo_list_unresolvable()}


@app.post("/api/studio-logos/retry")
async def api_studio_logos_retry(payload: dict = Body(default={})):
    """Re-queue dead-letter rows by resetting their attempt counter.

    ``ids`` (list[int]) retries only those rows; omit to retry every
    parked row. The user typically calls this after pasting a manual
    alias into the studio_logos NFO cache or fixing the studio name.
    """
    raw_ids = (payload or {}).get("ids") or []
    try:
        ids = [int(x) for x in raw_ids if x is not None]
    except (TypeError, ValueError):
        return JSONResponse({"ok": False, "error": "ids must be integers"}, status_code=400)
    updated = db.studio_logo_reset_attempts(ids if ids else None)
    return {"ok": True, "retried": updated}


@app.post("/api/studio-logos/delete")
async def api_studio_logos_delete(payload: dict = Body(default={})):
    """Delete studio_logos rows by id (typically invoked from the
    dead-letter UI to purge garbage entries that got in via NFO typos)."""
    raw_ids = (payload or {}).get("ids") or []
    try:
        ids = [int(x) for x in raw_ids if x is not None]
    except (TypeError, ValueError):
        return JSONResponse({"ok": False, "error": "ids must be integers"}, status_code=400)
    if not ids:
        return JSONResponse({"ok": False, "error": "no ids given"}, status_code=400)
    # Also drop the on-disk logo files — otherwise the disk sweep on
    # next resync would re-insert rows for the same slugs.
    deleted_files = 0
    try:
        logo_dir = _studio_logos_dir()
        for rid in ids:
            row = db.studio_logo_get_by_id(rid)
            if not row:
                continue
            lp = (row.get("logo_path") or "").strip()
            if lp:
                p = logo_dir / lp
                try:
                    if p.is_file():
                        p.unlink()
                        deleted_files += 1
                except OSError:
                    pass
    except Exception:
        pass
    deleted = db.studio_logo_delete(ids)
    return {"ok": True, "deleted": deleted, "files_removed": deleted_files}


@app.get("/api/studio-logos/saved")
async def api_studio_logos_saved():
    """Every studio_logos row with a file on disk — drives the
    'Logo library' manager panel under /health → Studios. The UI
    shows each logo with its thumbnail, source, fetch date, and
    controls to refetch or delete."""
    rows = await run_in_threadpool(db.studio_logo_list_with_files)
    return {"rows": rows}


def _studio_logo_refetch_one_sync(row_id: int) -> dict:
    """Re-download a single studio logo from StashDB. Used by the
    'Logo library' panel's per-row refresh button.

    Clears the row's existing ``logo_path`` so the fetcher re-enters
    it on the pending queue, then runs the one-shot fetch immediately
    so the UI can refresh inline without waiting for the scheduled
    background job.
    """
    try:
        row_id = int(row_id)
    except (TypeError, ValueError):
        return {"ok": False, "error": "invalid id"}
    try:
        row = db.studio_logo_get_by_id(row_id)
    except AttributeError:
        row = None
    if not row:
        # Fall back to list scan if the helper isn't there (older schema).
        for r in db.studio_logo_list_with_files():
            if int(r["id"]) == row_id:
                row = r
                break
    if not row:
        return {"ok": False, "error": "row not found"}
    s = db.get_settings()
    api_key = (s.get("api_key_stashdb") or "").strip()
    if not api_key:
        return {"ok": False, "error": "no_stashdb_key"}
    # Clear the current file path + attempt counters so the fetcher
    # treats this row as pending again.
    db.studio_logo_set_path(row_id, None)
    dest_dir = _studio_logos_dir()
    ok, reason = _studio_logo_fetch_one(row, api_key, dest_dir)
    if ok:
        return {"ok": True}
    try:
        db.studio_logo_mark_attempt_failed(row_id, reason)
    except Exception:
        pass
    return {"ok": False, "error": reason or "fetch_failed"}


@app.post("/api/studio-logos/refetch")
async def api_studio_logos_refetch(payload: dict = Body(default={})):
    """Refetch a single logo from StashDB. Body: ``{"row_id": int}``."""
    rid = (payload or {}).get("row_id")
    res = await run_in_threadpool(_studio_logo_refetch_one_sync, rid)
    if not res.get("ok"):
        return JSONResponse(res, status_code=400 if res.get("error") == "invalid id" else 200)
    return res


def _studio_logo_upload_sync(
    src_bytes: bytes,
    *,
    row_id: int | None,
    name: str,
) -> dict:
    """Save an uploaded image as a 300px-wide transparent PNG under
    metadata/studio_logos/, then update (or create) the matching
    studio_logos row.

    - If ``row_id`` is provided, the existing row's slug is reused so
      the on-disk filename stays consistent (any previous file is
      overwritten).
    - Otherwise a new row is created from ``name`` — the user-facing
      display name becomes the row's name, and the slug is derived
      through ``db.studio_logo_slug`` for consistency with the rest
      of the lookup pipeline.

    All uploads flow through ``_normalise_studio_logo_to_png`` which
    (a) converts any input format to PNG, (b) resizes to 300px max
    width via ImageMagick's ``-resize >`` operator (only shrinks, never
    enlarges), and (c) sets ``-background none -alpha set`` so the
    output preserves whatever transparency the source already had.
    """
    if not src_bytes:
        return {"ok": False, "error": "empty upload"}
    if row_id is not None:
        try:
            row_id = int(row_id)
        except (TypeError, ValueError):
            return {"ok": False, "error": "invalid row_id"}
        row = db.studio_logo_get_by_id(row_id)
        if not row:
            return {"ok": False, "error": "row not found"}
        slug = row["slug"]
        display_name = row.get("name") or slug
    else:
        nm = (name or "").strip()
        if not nm:
            return {"ok": False, "error": "name required"}
        slug = db.studio_logo_slug(nm)
        if not slug:
            return {"ok": False, "error": "invalid name"}
        display_name = nm
    dest_dir = _studio_logos_dir()
    dest_name = _studio_logo_filename(slug)
    dest = dest_dir / dest_name
    ok = _normalise_studio_logo_to_png(src_bytes, dest, target_width=300)
    if not ok:
        return {"ok": False, "error": "image processing failed"}
    try:
        rid = db.studio_logo_upsert(display_name, logo_path=dest_name, source="upload")
    except Exception as exc:
        return {"ok": False, "error": f"upsert failed: {exc}"}
    return {"ok": True, "row_id": rid, "slug": slug, "logo_path": dest_name}


@app.post("/api/studio-logos/upload")
async def api_studio_logos_upload(
    file: UploadFile = File(...),
    row_id: int | None = Form(None),
    name: str = Form(""),
):
    """Upload a custom studio logo. Body is multipart/form-data:

      * ``file`` — image (PNG / JPEG / WebP / GIF / SVG all accepted;
        ImageMagick does the conversion).
      * ``row_id`` — if set, replace the existing row's logo with the
        upload (slug is kept; the on-disk PNG is overwritten).
      * ``name`` — required when ``row_id`` is not set; the new row's
        display name.

    All uploads are normalised to transparent-background PNGs, 300px
    wide — same shape the /api/studio-logo endpoint serves from.
    """
    try:
        src_bytes = await file.read()
    except Exception as exc:
        return JSONResponse({"ok": False, "error": f"read failed: {exc}"}, status_code=400)
    res = await run_in_threadpool(
        _studio_logo_upload_sync, src_bytes, row_id=row_id, name=name,
    )
    if not res.get("ok"):
        return JSONResponse(res, status_code=400)
    return res


def _studio_logo_fetcher_job(max_items: int = 50, budget_s: float = 60.0) -> dict:
    """Background fetcher for studio_logos rows with logo_path IS NULL.

    Schedules pull up to `max_items` rows, calls StashDB for each, downloads
    the first image, saves it to metadata/studio_logos/, and updates the row.
    Failures bump `last_attempted_at` so the round-robin in
    `studio_logo_list_pending()` rotates fairly across the queue.
    """
    # Pick up any files the user dropped into metadata/studio_logos/ since
    # the last tick — cheap (just a listdir + slug compute) and keeps manual
    # drops visible within the next 6-hour window without a restart.
    try:
        _sync_manual_studio_logos_from_disk()
    except Exception as e:
        _log.warning(f"studio-logo disk sync failed: {e}")

    s = db.get_settings()
    api_key = (s.get("api_key_stashdb") or "").strip()
    if not api_key:
        return {"fetched": 0, "failed": 0, "skipped": "no_stashdb_key"}
    pending = db.studio_logo_list_pending(limit=max_items)
    if not pending:
        return {"fetched": 0, "failed": 0, "pending": 0}
    dest_dir = _studio_logos_dir()
    fetched = 0
    failed = 0
    start = time.time()
    for row in pending:
        if (time.time() - start) >= budget_s:
            break
        ok, reason = _studio_logo_fetch_one(row, api_key, dest_dir)
        if ok:
            fetched += 1
        else:
            failed += 1
            try:
                db.studio_logo_mark_attempt_failed(int(row["id"]), reason)
            except Exception:
                pass
    emit(f"studio-logo fetcher: {fetched} fetched, {failed} failed (of {len(pending)} pending)")
    return {"fetched": fetched, "failed": failed, "pending": len(pending)}


def _studio_logos_drain(max_passes: int = 20, per_pass_items: int = 50, total_budget_s: float = 240.0) -> dict:
    """Repeatedly call the fetcher until every eligible pending row has been
    attempted, no forward progress is being made, or the time budget is
    spent. Returns an aggregate summary suitable for the resync response.

    Each pass grabs up to ``per_pass_items`` rows ordered by oldest
    ``last_attempted_at`` first, so within one drain every pending row
    gets a turn before any single row retries. Rows that hit
    ``STUDIO_LOGO_MAX_ATTEMPTS`` drop into the dead-letter list and stop
    consuming budget.
    """
    started = time.time()
    totals = {"fetched": 0, "failed": 0, "passes": 0, "skipped": None}
    for i in range(max_passes):
        elapsed = time.time() - started
        remaining = total_budget_s - elapsed
        if remaining <= 0:
            break
        pass_budget = max(10.0, min(60.0, remaining))
        pending_before = db.studio_logo_count_pending()
        if pending_before == 0:
            break
        pass_result = _studio_logo_fetcher_job(
            max_items=per_pass_items, budget_s=pass_budget
        ) or {}
        totals["passes"] += 1
        totals["fetched"] += int(pass_result.get("fetched") or 0)
        totals["failed"] += int(pass_result.get("failed") or 0)
        if pass_result.get("skipped"):
            totals["skipped"] = pass_result["skipped"]
            break
        # Forward-progress guard: a pass with zero fetches AND zero
        # failures means the fetcher has nothing to chew on (budget
        # exhausted mid-pass, or list genuinely drained). Don't exit
        # when failures > 0 — each failure bumps the row's attempt
        # counter, so the next pass will eventually park those rows
        # and drain the queue organically.
        if not pass_result.get("fetched") and not pass_result.get("failed"):
            break
    totals["duration_s"] = round(time.time() - started, 2)
    return totals


def _seed_studio_logos_from_archive() -> int:
    """One-shot copy of static/logos/studio_logos/*.png into the new
    metadata/studio_logos/ store, with a row per file in the studio_logos
    table. Idempotent: re-running with a populated table is a no-op.
    Returns the number of NEW rows inserted on this run.
    """
    if db.studio_logo_count() > 0:
        return 0  # already seeded
    archive = Path(__file__).parent / "static" / "logos" / "studio_logos"
    if not archive.is_dir():
        emit("studio-logo seed: legacy archive not found, nothing to migrate")
        return 0
    dest_dir = _studio_logos_dir()
    inserted = 0
    skipped = 0
    for src in archive.iterdir():
        if src.suffix.lower() != ".png":
            continue
        name = src.stem
        slug = db.studio_logo_slug(name)
        if not slug:
            skipped += 1
            continue
        dest_name = _studio_logo_filename(slug)
        dest = dest_dir / dest_name
        try:
            if not dest.exists():
                shutil.copy2(src, dest)
            row_id = db.studio_logo_upsert(
                name,
                logo_path=dest_name,
                source="local-seed",
            )
            if row_id is not None:
                inserted += 1
        except OSError as e:
            _log.warning(f"studio-logo seed: {src.name} → {e}")
            skipped += 1
    emit(f"studio-logo seed: {inserted} rows seeded into studio_logos ({skipped} skipped)")
    return inserted


def _favourite_performer_slugs() -> set[str]:
    """Normalised folder-name slugs for every `performer` row in favourites.

    Used by `/api/studio-logo` to exclude performer-named "studios" from
    matches — e.g. a scene with `<studio>Alex Coal</studio>` in its NFO
    would otherwise plant an "alex coal" slug in studio_logos and the
    substring matcher would happily hand back that row whenever a
    release title mentions her. Returning the set here lets the endpoint
    ban every performer-slug from both the exact and substring passes.
    """
    out: set[str] = set()
    try:
        for row in db.favourite_list():
            if (row.get("kind") or "").strip().lower() != "performer":
                continue
            fn = (row.get("folder_name") or "").strip()
            if not fn:
                continue
            s = db.studio_logo_slug(fn)
            if s:
                out.add(s)
    except Exception:
        pass
    return out


@app.get("/api/studio-logo")
async def api_studio_logo(name: str = "", q: str = ""):
    """Resolve a studio name (or arbitrary search text) to a logo PNG.

    Both `name=` and `q=` accept any input; the lookup runs three strategies
    in order:
      1) exact slug lookup against studio_logos.slug
      2) spaceless slug match (handles "BackroomCastingCouch" vs "Backroom Casting Couch")
      3) longest-first substring scan over the table (whole-word + spaceless)
         for messy release titles like "DorcelClub.Foo.Bar.PRT.1080p"

    Performer exclusion: every slug that matches a favourited `performer`
    row's folder name is banned from all three passes. This fixes the
    case where a scene's NFO uses a performer's name as the `<studio>`
    (common for solo content / self-run production companies), which
    would otherwise cause the substring matcher to return the performer-
    named row and stamp a face-shot onto unrelated releases that merely
    mention her name. The `name=` param bypasses the ban ONLY on the
    exact-slug pass so a deliberate "her studio" lookup still works.

    `name=` and `q=` exist as documentation hints — `name=` is for callers
    that already have a clean studio name (e.g. /scenes feed), `q=` is for
    /downloads which only has the raw RSS title to look at. Both inputs are
    tried in order, first hit wins.

    Returns 404 (no JSON noise) so the frontend's `onerror` handler can hide
    the overlay cleanly.
    """
    candidates = [(name or "").strip(), (q or "").strip()]
    candidates = [c for c in candidates if c]
    if not candidates:
        return JSONResponse({"error": "missing name or q"}, status_code=400)

    dest_dir = _studio_logos_dir()
    pth: Path | None = None

    banned_perf_slugs = _favourite_performer_slugs()

    # Cache the all-rows pull for substring fallback so the second `q` pass
    # doesn't re-hit SQLite.
    rows_cache: list[dict] | None = None

    for idx, src in enumerate(candidates):
        is_name_arg = (idx == 0 and (name or "").strip() == src)
        target = db.studio_logo_slug(src)
        if not target:
            continue
        # 1. exact slug lookup. If the caller used `name=` (clean studio
        # name), we allow the match even when the slug is banned — that
        # only triggers when the caller explicitly *asked* for that name,
        # which is meaningfully different from substring fishing in a
        # messy release title.
        if is_name_arg or target not in banned_perf_slugs:
            row = db.studio_logo_get_by_slug(target)
            if row and row.get("logo_path"):
                cand = dest_dir / row["logo_path"]
                if cand.is_file():
                    pth = cand
                    break
        # 2. spaceless exact lookup — banned slugs are excluded here even
        # when `name=` was used, because a spaceless collision is fuzzier
        # and more likely to be accidental.
        if not pth:
            spaceless = target.replace(" ", "")
            if rows_cache is None:
                rows_cache = db.studio_logo_list_all()
            for r in rows_cache:
                if not r.get("logo_path"):
                    continue
                slug = r["slug"] or ""
                if slug in banned_perf_slugs:
                    continue
                if slug.replace(" ", "") == spaceless:
                    cand = dest_dir / r["logo_path"]
                    if cand.is_file():
                        pth = cand
                        break
        if pth:
            break
        # 3. substring scan (longest-first). Only considers slugs that are
        # distinctive enough to be statistically unique — single-word common
        # English words like "around" / "studio" / "fake" would otherwise
        # false-positive on release titles that just happen to contain them
        # (e.g. "goingaroundtown" spuriously matching "around.png"). Rule:
        # a slug qualifies if it has ≥2 words, OR ≥8 chars of a single word.
        # Common short proper nouns (brazzers, bangbros, mofos) still match;
        # everyday English words don't. Performer slugs are ALWAYS banned
        # from this pass — the whole point of excluding them is to stop
        # release titles that mention a performer's name from picking up
        # her studio-logo row as a false positive.
        if rows_cache is None:
            rows_cache = db.studio_logo_list_all()
        target_padded = f" {target} "
        target_spaceless = target.replace(" ", "")
        for r in rows_cache:
            if not r.get("logo_path"):
                continue
            slug = r["slug"] or ""
            if slug in banned_perf_slugs:
                continue
            word_count = len(slug.split())
            slug_len = len(slug)
            # Whole-word pass has a space on each side — the slug must
            # appear as a standalone token in the normalised query.
            # That's strong enough to trust short single-word brand
            # names (Milfy, Deeper, Vixen, Tushy, Blacked, Mofos) that
            # couldn't otherwise pass the spaceless pass's stricter
            # 8-char gate. Multi-word slugs need ≥5 chars so "a b c"
            # etc. don't slip through; single-word needs ≥4 so we
            # still block trivial tokens like "xxx" / "1080".
            min_whole = 5 if word_count >= 2 else 4
            if slug_len >= min_whole and f" {slug} " in target_padded:
                cand = dest_dir / r["logo_path"]
                if cand.is_file():
                    pth = cand
                    break
            ss = slug.replace(" ", "")
            # Spaceless pass: still requires ≥8 chars AFTER stripping
            # spaces so "the 1" / "hot 12" / "around" in
            # "goingaroundtown" can't leak through.
            if len(ss) >= 8 and ss in target_spaceless:
                cand = dest_dir / r["logo_path"]
                if cand.is_file():
                    pth = cand
                    break
        if pth:
            break

    # Vice fallback — when no studio logo matched, check whether any
    # configured Vice name appears as a whole word (or spaceless chunk)
    # inside the query / candidate text. Lets us show a sensible logo
    # for release titles that carry a vice tag (e.g. "…BDSM…" / "…Feet…")
    # but no studio we know about.
    if not pth or not pth.is_file():
        for cand_text in candidates:
            target_slug = db.studio_logo_slug(cand_text)
            if not target_slug:
                continue
            target_padded = f" {target_slug} "
            target_spaceless = target_slug.replace(" ", "")
            for vice in _load_vices():
                vname = (vice.get("name") or "").strip()
                if not vname:
                    continue
                vslug = db.studio_logo_slug(vname)
                if not vslug or len(vslug) < 3:
                    continue
                # Whole-word match OR spaceless match with the same ≥8
                # char rule the studio substring pass uses, so very
                # short vice names ("BDSM", "Feet") still get multi-
                # word matches but can't false-positive inside unrelated
                # longer strings.
                hit = (
                    f" {vslug} " in target_padded
                    or (len(vslug) >= 8 and vslug.replace(" ", "") in target_spaceless)
                )
                if hit:
                    vcand = _vice_logo_path(vice)
                    if vcand and vcand.is_file():
                        pth = vcand
                        break
            if pth:
                break

    if not pth or not pth.is_file():
        # 204 No Content rather than 404. Same effective UX — the
        # `<img>`'s `onerror` handler still fires (no image data to
        # decode) so the layout hides cleanly — but browsers don't
        # surface 204 as a console error, which keeps the queue page's
        # devtools quiet when dozens of rows can't resolve a logo.
        return Response(status_code=204)
    return FileResponse(
        pth,
        media_type="image/png",
        headers={"Cache-Control": "private, max-age=60, must-revalidate"},
    )


@app.get("/api/vices")
async def api_vices_list():
    """Return the user's Vice list — the canonical source of truth
    the Settings UI reads from. Each vice has its own folder and any
    number of TPDB tags assigned to it."""
    return {"vices": _load_vices()}


@app.post("/api/vices")
async def api_vices_save(payload: dict):
    """Overwrite the Vice list with the submitted array. Triggers a
    folder-sync + logo-fetch pass so changes land on disk immediately.
    `monitored_tags` is kept in sync with the flattened tag set so
    existing feed / blacklist logic keeps working."""
    vices = payload.get("vices") or []
    if not isinstance(vices, list):
        return JSONResponse({"error": "vices must be a list"}, status_code=400)
    # New vices (no id in the payload) get the next available int id.
    # Existing vices keep their id if it's already numeric; anything
    # else is treated as "new" and reassigned — keeps the folder naming
    # consistent with the migration in `_load_vices`.
    clean: list[dict] = []
    preserved_ids: set[int] = set()
    pending_unassigned: list[dict] = []
    for v in vices:
        if not isinstance(v, dict):
            continue
        name = str(v.get("name") or "").strip()
        if not name:
            continue
        tags_raw = v.get("tags") or []
        tags_clean: list[dict] = []
        if isinstance(tags_raw, list):
            for t in tags_raw:
                row_tag = _normalize_vice_tag_row(t)
                if row_tag:
                    tags_clean.append(row_tag)
        row: dict = {
            "id":     "",
            "name":   name,
            "locked": bool(v.get("locked")),
            "tags":   tags_clean,
        }
        raw_id = v.get("id")
        if _is_int_vice_id(raw_id):
            n = int(raw_id)
            if n not in preserved_ids:
                preserved_ids.add(n)
                row["id"] = str(n)
        clean.append(row)
        if not row["id"]:
            pending_unassigned.append(row)
    if pending_unassigned:
        next_int = (max(preserved_ids) if preserved_ids else 0) + 1
        for row in pending_unassigned:
            row["id"] = str(next_int)
            next_int += 1
    _save_vices(clean)
    threading.Thread(target=_sync_vice_folders, daemon=True, name="vice-folder-sync").start()
    threading.Thread(target=_fetch_missing_vice_logos, daemon=True, name="vice-logo-fetch").start()
    threading.Thread(target=_refresh_tag_scene_pools, daemon=True, name="tag-pools-vices-save").start()
    return {"saved": True, "count": len(clean)}


@app.post("/api/vices/lock")
async def api_vices_lock(payload: dict):
    """Flip a single Vice's lock flag. Locked vices are excluded from
    the regenerate endpoint so a curated logo can't be auto-replaced."""
    name = (payload.get("name") or "").strip()
    if not name:
        return JSONResponse({"error": "name required"}, status_code=400)
    locked = bool(payload.get("locked"))
    vices = _load_vices()
    hit = False
    for v in vices:
        if (v.get("name") or "").strip().lower() == name.lower():
            v["locked"] = locked
            hit = True
            break
    if not hit:
        return JSONResponse({"error": f"Vice '{name}' not found"}, status_code=404)
    _save_vices(vices)
    return {"ok": True, "name": name, "locked": locked}


@app.post("/api/vice-logo/regenerate")
async def api_vice_logo_regenerate(payload: dict):
    """Wipe the cached vice logo + the folder's logo.png, then re-run
    the full ensure chain (TPDB tag image → local folder art →
    generated Tox-Typewriter placeholder). Used by /health's vices
    table when the user wants a fresh logo — e.g. after dropping new
    art into the vice folder or adding a TPDB tag."""
    name = (payload.get("name") or "").strip()
    if not name:
        return JSONResponse({"error": "name required"}, status_code=400)
    try:
        vices = _load_vices()
        vice = next((v for v in vices if (v.get("name") or "").strip().lower() == name.lower()), None)
        if not vice:
            return JSONResponse({"error": f"Vice '{name}' not found"}, status_code=404)
        if vice.get("locked"):
            return JSONResponse({"error": f"Vice '{name}' is locked — unlock it to regenerate"}, status_code=409)

        settings = db.get_settings() or {}
        cached = _vice_logo_path(vice)
        if cached and cached.is_file():
            try: cached.unlink()
            except OSError: pass
        # Also purge any leftover legacy copy so a stale file there can't
        # be re-migrated back into the per-id folder by _ensure_vice_logo.
        slug = db.studio_logo_slug(name)
        if slug:
            legacy = _metadata_base_dir() / "vice_logos" / (slug.replace(" ", "_") + ".png")
            if legacy.is_file():
                try: legacy.unlink()
                except OSError: pass
        # Do NOT delete the folder's logo.png — it's the user's source of
        # truth and _ensure_vice_logo uses it as the preferred art source.
        # Wiping it would make the ensure chain fall through to poster.jpg
        # and silently replace the user's curated logo.

        tpdb_key = (settings.get("api_key_tpdb") or "").strip()
        result = _ensure_vice_logo(vice, settings, include_tpdb=bool(tpdb_key), tpdb_key=tpdb_key)
        # Refresh NFO (if missing) — _ensure_vice_nfo_and_art won't
        # overwrite an existing logo.png, so the user's file is safe.
        vices_dir_raw = (settings.get("vices_dir") or "").strip()
        if vices_dir_raw:
            vice_folder = Path(vices_dir_raw).expanduser() / (_vice_folder_name(name) or name)
            if vice_folder.is_dir():
                _ensure_vice_nfo_and_art(name, vice_folder, settings)

        if not result:
            return JSONResponse(
                {"error": "regeneration failed — no TPDB match, no folder art, and placeholder generation failed (is Pillow installed?)"},
                status_code=500,
            )
        return {"ok": True, "name": name, "image_url": f"/api/vice-logo?name={quote(name)}"}
    except Exception as e:
        _log.exception(f"vice-logo regenerate failed for {name!r}")
        return JSONResponse({"error": f"{type(e).__name__}: {e}"}, status_code=500)


@app.get("/api/vice-logo")
async def api_vice_logo(name: str = ""):
    """Serve the cached vice logo PNG by tag name.

    Resolves the vice in vices_json to find its stable id, then serves
    `metadata/vices/{id}/logo.png`. Unlike /api/studio-logo there are
    no substring / spaceless fallbacks and no performer bans — vices
    are user-curated and always carry their canonical tag name.
    """
    key = (name or "").strip()
    if not key:
        return JSONResponse({"error": "missing name"}, status_code=400)
    path = _vice_logo_path_for_name(key)
    if not path or not path.is_file():
        return JSONResponse({"error": "Not found"}, status_code=404)
    return FileResponse(
        path,
        media_type="image/png",
        headers={"Cache-Control": "private, max-age=60, must-revalidate"},
    )


@app.get("/api/favourites/studio-detail")
async def api_favourites_studio_detail(row_id: int):
    """Return scraped description/bio for a studio from TPDB or StashDB."""
    row = db.favourite_get(row_id)
    if not row or row.get("kind") != "studio":
        return JSONResponse({"error": "Not found"}, status_code=404)
    tpdb_id = (row.get("match_tpdb_id") or "").strip()
    stashdb_id = (row.get("match_stashdb_id") or "").strip()
    fansdb_id = (row.get("match_fansdb_id") or "").strip()
    javstash_id = (row.get("match_javstash_id") or "").strip()
    detail: dict | None = None
    source_used = None
    if tpdb_id:
        detail = await asyncio.get_event_loop().run_in_executor(
            None, fetch_studio_detail, "TPDB", tpdb_id
        )
        if detail:
            source_used = "TPDB"
    if not detail and stashdb_id:
        detail = await asyncio.get_event_loop().run_in_executor(
            None, fetch_studio_detail, "StashDB", stashdb_id
        )
        if detail:
            source_used = "StashDB"
    if not detail and fansdb_id:
        # FansDB shares the StashDB GraphQL schema, but fetch_studio_detail
        # doesn't have a dedicated branch yet. JAVStash does, and uses the
        # same shape, so we leave FansDB as a no-op until a real branch is
        # added — at least the pill in the header links out to the page.
        pass
    if not detail and javstash_id:
        detail = await asyncio.get_event_loop().run_in_executor(
            None, fetch_studio_detail, "JAVStash", javstash_id
        )
        if detail:
            source_used = "JAVStash"
    if not detail:
        return {"description": None, "source": None, "parent": None, "links": []}
    desc = (detail.get("description") or detail.get("details") or "").strip()
    # TPDB sites return parent / network as nested studio objects.
    # StashDB's findStudio query in fetch_studio_detail doesn't pull a
    # parent today — leave it null and let the frontend fall back to the
    # disk-path heuristic if the user really wants to see it.
    parent_obj = None
    raw_parent = detail.get("parent") if isinstance(detail.get("parent"), dict) else None
    raw_network = detail.get("network") if isinstance(detail.get("network"), dict) else None
    candidate = raw_parent or raw_network
    if candidate:
        pn = (candidate.get("name") or candidate.get("title") or "").strip()
        if pn:
            pid = str(
                candidate.get("uuid") or candidate.get("id") or ""
            ).strip() or None
            # Extract a direct logo URL when the upstream DB gives us
            # one — TPDB sites carry `logo` on the parent object, and
            # StashDB / JAVStash carry `images: [{url}]`. Without this
            # the frontend has to fall back to `/api/studio-logo?name=`,
            # which only works when we have a local logo file matching
            # the parent name's slug (often missing for networks like
            # "BANG!" that aren't catalogued).
            plogo = ""
            for k in ("logo", "image", "image_url"):
                v = candidate.get(k)
                if isinstance(v, str) and v.strip():
                    plogo = v.strip()
                    break
            if not plogo:
                imgs = candidate.get("images")
                if isinstance(imgs, list) and imgs:
                    first = imgs[0]
                    if isinstance(first, dict):
                        u = first.get("url") or ""
                        if isinstance(u, str) and u.strip():
                            plogo = u.strip()
                    elif isinstance(first, str):
                        plogo = first.strip()
            parent_obj = {
                "name": pn,
                "id": pid,
                "source": source_used,
                "logo_url": plogo or None,
            }

    # Normalise external URLs from whichever DB answered. TPDB sites
    # carry `home_page` (sometimes nested under `extras`) + a `links`
    # array of `{type, url}` socials; StashDB returns `urls` as a list
    # of `{url, site {name}}`. Dedup by URL so the same handle from
    # multiple sources doesn't render twice.
    seen_urls: set[str] = set()
    links_out: list[dict] = []
    def _add_link(url: str, label: str | None) -> None:
        u = (url or "").strip()
        if not u or not re.match(r"^https?://", u, re.I):
            return
        key = u.lower().rstrip("/")
        if key in seen_urls:
            return
        seen_urls.add(key)
        lbl = (label or "").strip() or _studio_link_label_from_url(u)
        links_out.append({"url": u, "label": lbl})

    extras = detail.get("extras") if isinstance(detail.get("extras"), dict) else {}
    home = (
        detail.get("home_page")
        or detail.get("homepage")
        or detail.get("url")
        or extras.get("home_page")
        or extras.get("homepage")
    )
    if isinstance(home, str):
        _add_link(home, "Site")
    raw_links = detail.get("links")
    if isinstance(raw_links, list):
        for entry in raw_links:
            if isinstance(entry, dict):
                _add_link(entry.get("url") or "", entry.get("type") or entry.get("label") or "")
            elif isinstance(entry, str):
                _add_link(entry, "")
    raw_urls = detail.get("urls")
    if isinstance(raw_urls, list):
        for entry in raw_urls:
            if isinstance(entry, dict):
                site_obj = entry.get("site")
                site_name = (site_obj or {}).get("name") if isinstance(site_obj, dict) else ""
                _add_link(entry.get("url") or "", site_name or entry.get("type") or "")

    return {
        "description": desc or None,
        "source": source_used,
        "name": detail.get("name") or detail.get("title"),
        "parent": parent_obj,
        "links": links_out,
    }


def _studio_link_label_from_url(url: str) -> str:
    """Friendly label for a studio external URL when the upstream DB
    didn't carry a tag (TPDB's bare ``home_page`` etc.)."""
    try:
        host = re.sub(r"^https?://", "", url, flags=re.I).split("/")[0].lower()
    except Exception:
        return "Website"
    host = host.lstrip("www.")
    if not host:
        return "Website"
    if "twitter.com" in host or host == "x.com":
        return "X / Twitter"
    if "instagram.com" in host:
        return "Instagram"
    if "facebook.com" in host:
        return "Facebook"
    if "youtube.com" in host or host == "youtu.be":
        return "YouTube"
    if "tiktok.com" in host:
        return "TikTok"
    if "onlyfans.com" in host:
        return "OnlyFans"
    if "fansly.com" in host:
        return "Fansly"
    if "reddit.com" in host:
        return "Reddit"
    return host


