_FANART_BASENAMES = (
    "background.jpg",  "background.png",  "background.webp",  "background.jpeg",
    "fanart.jpg",      "fanart.png",      "fanart.webp",      "fanart.jpeg",
    "backdrop.jpg",    "backdrop.png",    "backdrop.webp",    "backdrop.jpeg",
)


def _favourite_find_local_fanart(folder_path: str) -> Path | None:
    """First on-disk fanart-like image inside the row's folder. Checks
    canonical names plus ``{folder}-fanart.jpg`` (the convention the
    filer uses for movie back-cover sidecars). Used by the popup
    backdrop overlay endpoint."""
    raw = (folder_path or "").strip()
    if not raw:
        return None
    try:
        root = Path(raw).expanduser().resolve()
    except (OSError, RuntimeError):
        return None
    if not root.is_dir():
        return None
    folder_stem = root.name
    # Folder-named sidecars take priority (Kodi-style "<show>-fanart.jpg").
    for ext in (".jpg", ".jpeg", ".png", ".webp"):
        p = root / f"{folder_stem}-fanart{ext}"
        if p.is_file():
            try: return p.resolve()
            except OSError: continue
    for name in _FANART_BASENAMES:
        p = root / name
        if p.is_file():
            try: return p.resolve()
            except OSError: continue
    return None


