@app.get("/api/studios/external-panel")
async def api_studios_external_panel(
    source: str,
    id: str | None = None,
    name: str | None = None,
):
    """Render-ready payload for a studio that isn't in the library yet.
    Same shape as ``/api/favourites/entity-panel`` (``row`` + ``tpdb_scenes`` +
    ``scenes_source``) so the studio popup can render the external source's
    logo, description and recent scenes without any code-path forking.

    ``source`` is one of ``TPDB``, ``StashDB``, ``FansDB``, ``JAVStash``.
    ``id`` is the source-specific studio id (preferred); ``name`` is used as
    a fallback display when no detail fetch succeeds.
    """
    src = (source or "").strip()
    sid = (id or "").strip()
    nm = (name or "").strip()
    if not src or (not sid and not nm):
        return JSONResponse({"error": "source and id (or name) required"}, status_code=400)

    # Hit fetch_studio_detail when we have an id. Falls through to a
    # bare row when the lookup fails, so the popup still renders a
    # title + Prowlarr panel instead of an empty modal.
    detail: dict | None = None
    if sid:
        try:
            detail = await run_in_threadpool(fetch_studio_detail, src, sid)
        except Exception:
            detail = None

    detail = detail or {}
    display_name = (detail.get("name") or detail.get("title") or nm or "").strip() or "Studio"
    description = (detail.get("description") or detail.get("bio") or "").strip()

    # Pick a square-ish logo from the detail payload. TPDB exposes
    # ``logo`` / ``image``; stashbox sources nest under ``images`` (list
    # of ``{url}``). Falls back to the studio-list image hint in our
    # ``best_studio_image_url`` helper if the detail call returned a
    # raw stash-box studio dict.
    logo_url = ""
    if isinstance(detail.get("logo"), str):
        logo_url = detail["logo"]
    if not logo_url and isinstance(detail.get("image"), str):
        logo_url = detail["image"]
    if not logo_url:
        try:
            logo_url = best_studio_image_url(detail.get("images") or []) or ""
        except Exception:
            logo_url = ""

    # Crosswalk-shaped fake row so the existing popup-render path can
    # reuse favourites_recent_scenes without library lookups.
    fake_row: dict = {
        "id": 0,
        "kind": "studio",
        "display_name": display_name,
        "folder_name": display_name,
        "image_url": logo_url,
        "description": description,
        "match_tpdb_id":     sid if src.upper() == "TPDB"     else "",
        "match_stashdb_id":  sid if src.upper() == "STASHDB"  else "",
        "match_fansdb_id":   sid if src.upper() == "FANSDB"   else "",
        "match_javstash_id": sid if src.upper() == "JAVSTASH" else "",
        # Parent + urls passthrough for the popup links rail.
        "external_parent": detail.get("parent") or None,
        "external_urls":   detail.get("urls") or [],
        "external_source": src,
        "external_id":     sid,
    }

    scenes: list[dict] = []
    scenes_source: str | None = None
    try:
        scenes, scenes_source = await run_in_threadpool(
            favourites_recent_scenes, fake_row, 12
        )
    except Exception:
        scenes, scenes_source = [], None

    return {"row": fake_row, "tpdb_scenes": scenes, "scenes_source": scenes_source}


