@app.get("/api/favourites/index-progress")
async def api_favourites_index_progress():
    """Poll scan / refresh-all progress (in-memory)."""
    with _favourites_index_lock:
        return dict(_favourites_index_progress)


@app.get("/api/favourites/index-progress/stream")
async def api_favourites_index_progress_stream(request: Request):
    """SSE stream of favourites index/scan progress. The client opens one
    connection when a scan starts; the server pushes a state event on
    every actual change (and a heartbeat every 25 s so proxies don't
    drop the idle connection). Replaces the previous 1.5-second polling
    loop. The connection stays open after the scan finishes so the
    client gets one final state=done event without needing to reconnect.
    """
    import asyncio as _aio

    async def _gen():
        last_sig: str | None = None
        last_push = 0.0
        # Tight poll on the in-memory dict — every read is just a copy
        # under a short-lived lock; no I/O.
        snapshot_poll_s = 0.5
        idle_after_finish = 5.0
        finished_at: float | None = None
        while True:
            if await request.is_disconnected():
                return
            with _favourites_index_lock:
                snap = dict(_favourites_index_progress)
            try:
                data = json.dumps(snap, default=str, sort_keys=True)
            except Exception:
                data = json.dumps({"error": "serialise failed"})
            sig = hashlib.sha1(data.encode("utf-8")).hexdigest()
            now = time.time()
            should_push = (sig != last_sig) or ((now - last_push) > 25.0)
            if should_push:
                yield f"event: state\ndata: {data}\n\n"
                last_sig = sig
                last_push = now
            # Close the stream a few seconds after the scan ends so the
            # browser EventSource lands on a clean shutdown.
            if not snap.get("running", False):
                if finished_at is None:
                    finished_at = now
                elif now - finished_at > idle_after_finish:
                    return
            else:
                finished_at = None
            try:
                await _aio.sleep(snapshot_poll_s)
            except _aio.CancelledError:
                return

    return StreamingResponse(
        _gen(),
        media_type="text/event-stream",
        headers={
            "Cache-Control": "no-cache, no-transform",
            "X-Accel-Buffering": "no",
        },
    )


@app.post("/api/favourites/scan")
async def api_favourites_scan(
    background_tasks: BackgroundTasks,
    prune_missing: bool = False,
    only_missing: bool = True,
):
    folders = _favourites_collect_folder_rows()
    _favourites_progress_start(
        "scan_missing" if only_missing else "scan_full", len(folders)
    )

    def run():
        try:
            favourites_scan_index(
                prune_missing=prune_missing,
                folders=folders,
                progress_init=False,
                only_missing=only_missing,
            )
        except Exception as e:
            emit(f"FAVOURITES scan error: {e}")
            _favourites_progress_finish()
        threading.Thread(target=_background_iafd_enrich_all, daemon=True).start()

    background_tasks.add_task(run)
    return {"started": True}


