def _library_sorted_vices() -> list[dict]:
    return sorted(_load_vices(), key=lambda v: (v.get("name") or "").lower())


def _library_vice_by_negative_id(row_id: int) -> dict | None:
    if row_id >= 0:
        return None
    idx = -row_id - 1
    vices = _library_sorted_vices()
    if idx < 0 or idx >= len(vices):
        return None
    return vices[idx]


def _library_vice_by_id(vice_id: str) -> dict | None:
    vid = str(vice_id or "").strip()
    if not vid:
        return None
    for v in _load_vices():
        if str(v.get("id") or "").strip() == vid:
            return v
    return None


def _library_vice_folder_path(vice: dict) -> Path | None:
    name = (vice.get("name") or "").strip()
    if not name:
        return None
    vices_dir_raw = (db.get_settings().get("vices_dir") or "").strip()
    if not vices_dir_raw:
        return None
    folder_name = _vice_folder_name(name) or name
    return Path(vices_dir_raw).expanduser() / folder_name


def _library_purge_metadata_cache(row_id: int, kind: str) -> None:
    try:
        favourites_clear_image_disk_cache(int(row_id))
    except Exception:
        pass
    try:
        if kind == "performer":
            shutil.rmtree(_performers_iafd_dir(row_id), ignore_errors=True)
        else:
            md = _metadata_base_dir() / (kind + "s") / str(int(row_id))
            if md.is_dir():
                shutil.rmtree(md, ignore_errors=True)
    except Exception:
        pass


def _library_purge_folder_index(folder: Path) -> int:
    """Remove library_files rows for everything under ``folder``."""
    if not folder:
        return 0
    try:
        return db.library_files_delete_under_folder(str(folder))
    except Exception:
        return 0


def _library_remove_favourite_row(row_id: int) -> bool:
    row = db.favourite_get(row_id)
    if not row:
        return False
    kind = (row.get("kind") or "").strip()
    _library_purge_metadata_cache(row_id, kind or "performer")
    db.favourite_delete(row_id)
    return True


def _library_remove_vice(vice_id: str) -> bool:
    vid = str(vice_id or "").strip()
    if not vid:
        return False
    kept = [v for v in _load_vices() if str(v.get("id") or "").strip() != vid]
    if len(kept) == len(_load_vices()):
        return False
    _save_vices(kept)
    return True


def _library_delete_folder_on_disk(folder: Path) -> None:
    if not folder:
        return
    if folder.is_dir():
        shutil.rmtree(folder, ignore_errors=True)
    elif folder.is_file():
        folder.unlink(missing_ok=True)


def _library_delete_favourite_from_disk(row_id: int) -> bool:
    row = db.favourite_get(row_id)
    if not row:
        return False
    kind = (row.get("kind") or "").strip()
    folder_raw = (row.get("path") or "").strip()
    if folder_raw:
        roots = _health_library_roots()
        try:
            folder = _health_assert_path_under_roots(folder_raw, roots)
            _library_purge_folder_index(folder)
            _library_delete_folder_on_disk(folder)
        except ValueError:
            # Path outside configured roots — still drop index rows.
            _library_purge_folder_index(Path(folder_raw))
    _library_purge_metadata_cache(row_id, kind or "performer")
    db.favourite_delete(row_id)
    return True


def _library_delete_vice_from_disk(vice_id: str) -> bool:
    vice = _library_vice_by_id(vice_id)
    if not vice:
        return False
    folder = _library_vice_folder_path(vice)
    if folder and folder.exists():
        roots = _health_library_roots()
        try:
            checked = _health_assert_path_under_roots(str(folder), roots)
            _library_purge_folder_index(checked)
            _library_delete_folder_on_disk(checked)
        except ValueError:
            _library_purge_folder_index(folder)
            _library_delete_folder_on_disk(folder)
    meta = _vice_metadata_dir(vice)
    if meta and meta.is_dir():
        shutil.rmtree(meta, ignore_errors=True)
    _library_remove_vice(vice_id)
    return True


@app.post("/api/library/entity/remove-from-library")
async def api_library_entity_remove_from_library(payload: dict = Body(...)):
    """Drop a library entity from the app index. Does not delete files on disk."""
    row_id = int(payload.get("id") or 0)
    vice_id = str(payload.get("vice_id") or "").strip()
    if row_id < 0:
        vice = _library_vice_by_id(vice_id) if vice_id else _library_vice_by_negative_id(row_id)
        if not vice:
            return JSONResponse({"error": "Vice not found"}, status_code=404)
        vid = str(vice.get("id") or "").strip()
        label = (vice.get("name") or "vice").strip() or "vice"
        if not _library_remove_vice(vid):
            return JSONResponse({"error": "Vice not found"}, status_code=404)
        db.notification_add("success", f"Removed “{label}” from the library", ttl_seconds=180)
        return {"ok": True, "kind": "vice"}
    if not row_id:
        return JSONResponse({"error": "id required"}, status_code=400)
    row = db.favourite_get(row_id)
    if not row:
        return JSONResponse({"error": "Not found"}, status_code=404)
    kind = (row.get("kind") or "").strip()
    label = (row.get("folder_name") or row.get("name") or "entry").strip() or "entry"
    _library_remove_favourite_row(row_id)
    db.notification_add("success", f"Removed “{label}” from the library", ttl_seconds=180)
    return {"ok": True, "kind": kind}


@app.post("/api/library/entity/delete-from-disk")
async def api_library_entity_delete_from_disk(payload: dict = Body(...)):
    """Delete entity folder (and all files inside) plus remove from the app index."""
    row_id = int(payload.get("id") or 0)
    vice_id = str(payload.get("vice_id") or "").strip()
    if row_id < 0:
        vice = _library_vice_by_id(vice_id) if vice_id else _library_vice_by_negative_id(row_id)
        if not vice:
            return JSONResponse({"error": "Vice not found"}, status_code=404)
        vid = str(vice.get("id") or "").strip()
        label = (vice.get("name") or "vice").strip() or "vice"
        if not _library_delete_vice_from_disk(vid):
            return JSONResponse({"error": "Vice not found"}, status_code=404)
        db.notification_add("success", f"Deleted “{label}” from disk", ttl_seconds=240)
        return {"ok": True, "kind": "vice"}
    if not row_id:
        return JSONResponse({"error": "id required"}, status_code=400)
    row = db.favourite_get(row_id)
    label = (row.get("folder_name") or row.get("name") or "entry").strip() if row else "entry"
    if not _library_delete_favourite_from_disk(row_id):
        return JSONResponse({"error": "Not found"}, status_code=404)
    db.notification_add("success", f"Deleted “{label}” from disk", ttl_seconds=240)
    return {"ok": True}


@app.get("/api/library/performer-move-targets")
async def api_library_performer_move_targets(row_id: int):
    """Other configured performer directory roots for Change directory."""
    row = db.favourite_get(row_id)
    if not row or (row.get("kind") or "") != "performer":
        return JSONResponse({"error": "performer row required"}, status_code=400)
    folder_raw = (row.get("path") or "").strip()
    if not folder_raw:
        return JSONResponse({"error": "performer has no folder path"}, status_code=400)
    try:
        current = Path(folder_raw).expanduser().resolve()
    except OSError:
        current = Path(folder_raw).expanduser()
    current_root = str(current.parent)
    targets: list[dict] = []
    for entry in db.get_directories("performer"):
        p_raw = (entry.get("path") or "").strip()
        if not p_raw:
            continue
        try:
            p = str(Path(p_raw).expanduser().resolve())
        except OSError:
            p = str(Path(p_raw).expanduser())
        if p == current_root:
            continue
        targets.append({
            "id": entry.get("id"),
            "label": (entry.get("label") or "Performers").strip() or "Performers",
            "path": p,
        })
    return {
        "folder_name": current.name,
        "current_path": str(current),
        "targets": targets,
    }


@app.post("/api/library/entity/change-directory")
async def api_library_entity_change_directory(payload: dict = Body(...)):
    """Move a performer folder (and all files) to another configured performer root."""
    row_id = int(payload.get("id") or 0)
    target_directory_id = payload.get("target_directory_id")
    if not row_id:
        return JSONResponse({"error": "id required"}, status_code=400)
    row = db.favourite_get(row_id)
    if not row or (row.get("kind") or "") != "performer":
        return JSONResponse({"error": "Only performers can change directory"}, status_code=400)
    folder_raw = (row.get("path") or "").strip()
    if not folder_raw:
        return JSONResponse({"error": "performer has no folder path"}, status_code=400)
    target_entry = None
    for entry in db.get_directories("performer"):
        if entry.get("id") == target_directory_id or str(entry.get("id")) == str(target_directory_id):
            target_entry = entry
            break
    if not target_entry:
        return JSONResponse({"error": "target directory not found"}, status_code=400)
    target_root_raw = (target_entry.get("path") or "").strip()
    if not target_root_raw:
        return JSONResponse({"error": "target directory has no path"}, status_code=400)
    roots = _health_library_roots()
    try:
        src = _health_assert_path_under_roots(folder_raw, roots)
        dst_root = Path(target_root_raw).expanduser()
        dst_root_resolved = dst_root.resolve()
    except ValueError as e:
        return JSONResponse({"error": str(e)}, status_code=400)
    except OSError as e:
        return JSONResponse({"error": str(e)}, status_code=400)
    dest = dst_root / src.name
    if dest.exists():
        return JSONResponse(
            {"error": f"A folder named “{src.name}” already exists in the target directory."},
            status_code=409,
        )
    try:
        safe_move(src, dest)
    except OSError as e:
        return JSONResponse({"error": f"Move failed: {e}"}, status_code=500)
    new_path = str(dest)
    db.favourite_update_path(row_id, new_path)
    # Re-key library_files destinations from old prefix to new.
    old_prefix = str(src.resolve()) + os.sep
    new_prefix = str(dest.resolve()) + os.sep
    try:
        with db.get_conn() as conn:
            rows = conn.execute(
                "SELECT id, destination FROM library_files WHERE destination = ? OR destination LIKE ?",
                (str(src.resolve()), old_prefix + "%"),
            ).fetchall()
            for r in rows:
                dest_old = str(r["destination"] or "")
                if dest_old == str(src.resolve()):
                    dest_new = new_path
                elif dest_old.startswith(old_prefix):
                    dest_new = new_prefix + dest_old[len(old_prefix):]
                else:
                    continue
                conn.execute(
                    "UPDATE library_files SET destination = ?, updated_at = ? WHERE id = ?",
                    (dest_new, datetime.now(timezone.utc).isoformat(), int(r["id"])),
                )
            conn.commit()
    except Exception as e:
        emit(f"LIBRARY move: library_files re-key failed for row {row_id}: {e}")
    return {"ok": True, "path": new_path}


# ── Performer rename ───────────────────────────────────────────────
# Rename a performer in-place: change the on-disk folder name, the
# favourites row, tvshow.nfo, every episode file matching the
# canonical `[old] - SyyyyEMMDD - …` pattern, and the matching
# `<showtitle>` / `<actor><name>` fields in each episode NFO. Streams
# progress as NDJSON so the popup can render a five-stage progress
# checklist.

_PERF_RENAME_SE_TOKEN = re.compile(r"\s*-\s*S(\d{4})E(\d{4})\b", re.IGNORECASE)
_PERF_RENAME_VIDEO_EXTS = {
    ".mp4", ".mkv", ".m4v", ".avi", ".wmv", ".mov", ".flv", ".webm",
    ".ts", ".m2ts", ".mpg", ".mpeg",
}


def _perf_rename_stem_starts_with(stem: str, old_name: str) -> tuple[str, str] | None:
    """If ``stem`` begins with ``old_name`` followed by the canonical
    ` - S####E####` season-episode token, return ``(prefix, tail)`` where
    prefix is the old name as it actually appears in the stem and tail
    is everything from the SE token onwards.

    Case-insensitive on the name match; preserves the original casing
    of the matched prefix so we can replace it precisely.
    """
    m = _PERF_RENAME_SE_TOKEN.search(stem)
    if not m:
        return None
    head = stem[:m.start()].rstrip()
    if head.lower() != old_name.strip().lower():
        return None
    tail = stem[m.start():]
    return head, tail


def _perf_rename_rewrite_tvshow_nfo(folder: Path, old_name: str, new_name: str) -> dict:
    """Rewrite tvshow.nfo: update <title>, any <actor><name> matching the
    old performer, and append the old name to the AKA list in <plot> if
    missing. Returns ``{"updated": bool, "skipped_reason": str|None}``.
    Best-effort — never raises."""
    nfo_path = folder / "tvshow.nfo"
    if not nfo_path.is_file():
        return {"updated": False, "skipped_reason": "no_tvshow_nfo"}
    try:
        raw = nfo_path.read_bytes()
        root = ET.fromstring(raw)
    except Exception as exc:
        return {"updated": False, "skipped_reason": f"parse_error: {exc}"}
    changed = False
    old_lc = old_name.strip().lower()
    new_clean = new_name.strip()
    title_el = root.find("title")
    if title_el is not None and (title_el.text or "").strip().lower() == old_lc:
        title_el.text = new_clean
        changed = True
    for actor in root.findall("actor"):
        name_el = actor.find("name")
        if name_el is None:
            continue
        if (name_el.text or "").strip().lower() == old_lc:
            name_el.text = new_clean
            changed = True
    # Append the old name to the AKA list in <plot> if it isn't already
    # there. The AKA line follows the literal `AKA: ` prefix as written
    # by ``build_performer_tvshow_nfo``.
    plot_el = root.find("plot")
    if plot_el is not None and plot_el.text:
        plot = plot_el.text
        aka_marker = "AKA: "
        idx = plot.find(aka_marker)
        if idx >= 0:
            after = plot[idx + len(aka_marker):]
            line_end = after.find("\n\n")
            aka_segment = after if line_end < 0 else after[:line_end]
            existing = [a.strip() for a in aka_segment.split(",") if a.strip()]
            if not any(a.lower() == old_lc for a in existing):
                existing.append(old_name.strip())
                new_aka = ", ".join(existing)
                new_plot = plot[:idx + len(aka_marker)] + new_aka + (
                    "" if line_end < 0 else after[line_end:]
                )
                plot_el.text = new_plot
                changed = True
        else:
            insert_pos = 0  # prepend on a new line block
            block = f"AKA: {old_name.strip()}"
            plot_el.text = (plot.rstrip() + "\n\n" + block) if plot.strip() else block
            changed = True
    if not changed:
        return {"updated": False, "skipped_reason": "no_match_in_nfo"}
    try:
        tree = ET.ElementTree(root)
        ET.indent(tree, space="  ")
        buf = io.BytesIO()
        tree.write(buf, encoding="utf-8", xml_declaration=True)
        nfo_path.write_bytes(buf.getvalue())
        _ensure_library_filed_permissions(nfo_path)
    except Exception as exc:
        return {"updated": False, "skipped_reason": f"write_error: {exc}"}
    return {"updated": True, "skipped_reason": None}


def _perf_rename_rewrite_episode_nfo(nfo_path: Path, old_name: str, new_name: str) -> bool:
    """Update <showtitle> and matching <actor><name> in an episode NFO.
    Returns True if the file was modified."""
    try:
        root = ET.fromstring(nfo_path.read_bytes())
    except Exception:
        return False
    old_lc = old_name.strip().lower()
    new_clean = new_name.strip()
    changed = False
    for tag in ("showtitle", "set"):
        el = root.find(tag)
        if el is not None and (el.text or "").strip().lower() == old_lc:
            el.text = new_clean
            changed = True
    for actor in root.findall("actor"):
        name_el = actor.find("name")
        if name_el is None:
            continue
        if (name_el.text or "").strip().lower() == old_lc:
            name_el.text = new_clean
            changed = True
    if not changed:
        return False
    try:
        tree = ET.ElementTree(root)
        ET.indent(tree, space="  ")
        buf = io.BytesIO()
        tree.write(buf, encoding="utf-8", xml_declaration=True)
        nfo_path.write_bytes(buf.getvalue())
        _ensure_library_filed_permissions(nfo_path)
    except Exception:
        return False
    return True


def _perf_rename_collect_video_jobs(
    folder: Path, old_name: str, new_name: str
) -> list[dict]:
    """Walk ``folder`` for video files that begin with the canonical
    `<old_name> - S####E####` prefix and produce a rename plan: each
    entry has ``video`` plus its sidecar files (NFO, thumb, fanart,
    poster, subs)."""
    jobs: list[dict] = []
    for vid in folder.rglob("*"):
        if not vid.is_file():
            continue
        if vid.suffix.lower() not in _PERF_RENAME_VIDEO_EXTS:
            continue
        match = _perf_rename_stem_starts_with(vid.stem, old_name)
        if not match:
            continue
        head, tail = match  # tail starts with ` - S####E####…`
        new_stem = f"{new_name.strip()}{tail}"
        if new_stem == vid.stem:
            continue
        sidecars: list[tuple[Path, Path]] = []
        parent = vid.parent
        stem_lc = vid.stem.lower()
        for other in parent.iterdir():
            if not other.is_file() or other == vid:
                continue
            on = other.name
            if not on.lower().startswith(stem_lc):
                continue
            suffix = on[len(vid.stem):]
            # Guard against accidentally catching unrelated files whose
            # stems share this video's stem as a prefix (e.g.
            # `<stem>1.mp4`). Real sidecars start with `.` (extension)
            # or `-` / `_` (e.g. `-thumb.jpg`, `_orig.nfo`).
            if suffix and suffix[0] not in {".", "-", "_"}:
                continue
            new_other = parent / f"{new_stem}{suffix}"
            try:
                if other.resolve() == new_other.resolve():
                    continue
            except OSError:
                pass
            sidecars.append((other, new_other))
        jobs.append({
            "video": vid,
            "video_new": parent / f"{new_stem}{vid.suffix}",
            "sidecars": sidecars,
        })
    return jobs


def _perf_rename_apply_aliases(existing_json: str | None, old_name: str) -> str | None:
    """Append ``old_name`` to the aliases list parsed from ``existing_json``
    if not already present (case-insensitive). Returns JSON-encoded list
    or None if empty."""
    try:
        lst = json.loads(existing_json or "[]") or []
        if not isinstance(lst, list):
            lst = []
    except Exception:
        lst = []
    cleaned: list[str] = []
    seen: set[str] = set()
    for a in lst:
        if not isinstance(a, str):
            continue
        s = a.strip()
        if not s:
            continue
        k = s.lower()
        if k in seen:
            continue
        seen.add(k)
        cleaned.append(s)
    on = old_name.strip()
    if on and on.lower() not in seen:
        cleaned.append(on)
    return json.dumps(cleaned) if cleaned else None


@app.post("/api/library/performer/rename")
async def api_library_performer_rename(payload: dict = Body(...)):
    """Rename a performer everywhere: DB row, on-disk folder,
    tvshow.nfo, episode file names, episode NFO showtitle/actor.

    Streams NDJSON progress lines so the UI can render a five-stage
    progress checklist:
        {"stage": "dir",          "ok": true, "from": "...", "to": "..."}
        {"stage": "app",          "ok": true, "aliases_added": 1}
        {"stage": "tvshow_nfo",   "ok": true, "updated": true}
        {"stage": "videos",       "ok": true, "renamed": 17}
        {"stage": "episode_nfo",  "ok": true, "updated": 17, "scanned": 18}
        {"stage": "done",         "ok": true}
    """
    try:
        row_id = int(payload.get("row_id") or 0)
    except (TypeError, ValueError):
        row_id = 0
    new_name_raw = (payload.get("new_name") or "").strip()
    if not row_id:
        return JSONResponse({"error": "row_id required"}, status_code=400)
    if not new_name_raw:
        return JSONResponse({"error": "new_name required"}, status_code=400)
    row = db.favourite_get(row_id)
    if not row or (row.get("kind") or "") != "performer":
        return JSONResponse({"error": "performer row required"}, status_code=404)
    folder_raw = (row.get("path") or "").strip()
    if not folder_raw:
        return JSONResponse({"error": "performer has no folder path"}, status_code=400)
    old_name = (row.get("folder_name") or "").strip()
    new_name_safe = _sanitize_fs_component(new_name_raw)
    if not new_name_safe:
        return JSONResponse(
            {"error": "new name contains no usable characters"}, status_code=400,
        )
    if new_name_safe.lower() == old_name.lower():
        return JSONResponse(
            {"error": "new name is the same as the current name"}, status_code=400,
        )
    # Validate the source folder lives under a configured library root.
    roots = _health_library_roots()
    try:
        src_path = _health_assert_path_under_roots(folder_raw, roots)
    except (ValueError, OSError) as exc:
        return JSONResponse({"error": str(exc)}, status_code=400)
    if not src_path.is_dir():
        return JSONResponse(
            {"error": f"source folder does not exist: {src_path}"}, status_code=400,
        )
    dst_path = src_path.parent / new_name_safe
    if dst_path.exists():
        return JSONResponse(
            {"error": f"a folder named “{new_name_safe}” already exists in this directory"},
            status_code=409,
        )
    # Capture the resolved string before the rename so we can re-key
    # library_files rows that stored the resolved (canonical) path.
    try:
        src_resolved_str = str(src_path.resolve())
    except OSError:
        src_resolved_str = str(src_path)
    src_raw_str = str(Path(folder_raw).expanduser())

    def gen():
        def emit_line(payload: dict) -> str:
            return json.dumps(payload) + "\n"

        # Stage 1: rename the on-disk folder.
        try:
            os.rename(str(src_path), str(dst_path))
        except OSError as exc:
            yield emit_line({"stage": "dir", "ok": False, "error": str(exc)})
            yield emit_line({"stage": "done", "ok": False, "error": str(exc)})
            return
        yield emit_line({
            "stage": "dir", "ok": True,
            "from": str(src_path), "to": str(dst_path),
        })

        # Stage 2: update the favourites row. On failure, attempt to
        # roll the disk rename back so the DB and disk stay in sync.
        try:
            new_aliases_json = _perf_rename_apply_aliases(
                row.get("aliases_json") or "", old_name,
            )
            now_iso = datetime.now(timezone.utc).isoformat()
            with db.get_conn() as conn:
                conn.execute(
                    "UPDATE favourite_entities "
                    "SET folder_name = ?, path = ?, aliases_json = ?, "
                    "    path_missing = 0, updated_at = ? "
                    "WHERE id = ?",
                    (
                        new_name_safe,
                        str(dst_path),
                        new_aliases_json,
                        now_iso,
                        row_id,
                    ),
                )
                conn.commit()
            # Re-key library_files rows under the renamed folder so the
            # /health Library index and dup detection stay accurate. DB
            # rows may carry either the resolved canonical path or the
            # raw configured-root path, so check both prefixes.
            try:
                new_path_str = str(dst_path)
                prefix_candidates = []
                seen_prefix: set[str] = set()
                for base in (src_resolved_str, src_raw_str, str(src_path)):
                    p = base + os.sep
                    if p in seen_prefix:
                        continue
                    seen_prefix.add(p)
                    prefix_candidates.append((base, p))
                with db.get_conn() as conn:
                    for base, prefix in prefix_candidates:
                        rows = conn.execute(
                            "SELECT id, destination FROM library_files "
                            "WHERE destination = ? OR destination LIKE ?",
                            (base, prefix + "%"),
                        ).fetchall()
                        for r in rows:
                            dest_old = str(r["destination"] or "")
                            if dest_old == base:
                                dest_new = new_path_str
                            elif dest_old.startswith(prefix):
                                dest_new = new_path_str + os.sep + dest_old[len(prefix):]
                            else:
                                continue
                            conn.execute(
                                "UPDATE library_files SET destination = ?, "
                                "updated_at = ? WHERE id = ?",
                                (dest_new, now_iso, int(r["id"])),
                            )
                    conn.commit()
            except Exception as exc:
                emit(f"performer rename: library_files re-key failed: {exc}")
            _performer_popup_cache_invalidate_row(row_id)
        except Exception as exc:
            # Try to roll back the disk rename.
            try:
                os.rename(str(dst_path), str(src_path))
            except OSError:
                pass
            yield emit_line({"stage": "app", "ok": False, "error": str(exc)})
            yield emit_line({"stage": "done", "ok": False, "error": str(exc)})
            return
        yield emit_line({"stage": "app", "ok": True})

        # Stage 3: rewrite tvshow.nfo (best-effort, never aborts).
        try:
            tv_result = _perf_rename_rewrite_tvshow_nfo(
                dst_path, old_name, new_name_safe,
            )
        except Exception as exc:
            tv_result = {"updated": False, "skipped_reason": f"exception: {exc}"}
        yield emit_line({
            "stage": "tvshow_nfo", "ok": True,
            "updated": bool(tv_result.get("updated")),
            "note": tv_result.get("skipped_reason") or "",
        })

        # Stage 4: rename matching video files + sidecars, update
        # library_files DB rows.
        renamed = 0
        rename_failed = 0
        try:
            jobs = _perf_rename_collect_video_jobs(
                dst_path, old_name, new_name_safe,
            )
        except Exception as exc:
            yield emit_line({
                "stage": "videos", "ok": False, "error": str(exc),
                "renamed": 0, "failed": 0,
            })
            jobs = []
        for job in jobs:
            vid_old: Path = job["video"]
            vid_new: Path = job["video_new"]
            try:
                if vid_new.exists():
                    rename_failed += 1
                    continue
                os.rename(str(vid_old), str(vid_new))
                _ensure_library_filed_permissions(vid_new)
                for src_sc, dst_sc in job["sidecars"]:
                    try:
                        if dst_sc.exists():
                            continue
                        os.rename(str(src_sc), str(dst_sc))
                        _ensure_library_filed_permissions(dst_sc)
                    except OSError:
                        continue
                renamed += 1
                # Update library_files row to track the new path.
                try:
                    old_dest = str(vid_old.resolve()) if vid_old.exists() else str(vid_old)
                except OSError:
                    old_dest = str(vid_old)
                try:
                    new_dest = str(vid_new.resolve())
                except OSError:
                    new_dest = str(vid_new)
                try:
                    existing = db.library_file_get_by_destination(old_dest)
                    if existing:
                        db.library_file_update_destination_row(
                            int(existing["id"]),
                            destination=new_dest,
                            current_filename=vid_new.name,
                            filename_stem=vid_new.stem,
                        )
                except Exception as exc:
                    emit(f"performer rename: library_files update failed for {vid_new.name}: {exc}")
            except OSError as exc:
                rename_failed += 1
                emit(f"performer rename: file rename failed: {vid_old.name} → {vid_new.name}: {exc}")
        yield emit_line({
            "stage": "videos", "ok": True,
            "renamed": renamed, "failed": rename_failed,
        })

        # Stage 5: rewrite <showtitle>/<actor><name> in episode NFOs.
        nfo_updated = 0
        nfo_scanned = 0
        try:
            for nfo in dst_path.rglob("*.nfo"):
                if not nfo.is_file():
                    continue
                if nfo.name.lower() in {
                    "tvshow.nfo", "season.nfo", "season-all.nfo",
                    "season-specials.nfo",
                }:
                    continue
                nfo_scanned += 1
                if _perf_rename_rewrite_episode_nfo(nfo, old_name, new_name_safe):
                    nfo_updated += 1
        except Exception as exc:
            yield emit_line({
                "stage": "episode_nfo", "ok": False, "error": str(exc),
                "updated": nfo_updated, "scanned": nfo_scanned,
            })
            yield emit_line({"stage": "done", "ok": False, "error": str(exc)})
            return
        yield emit_line({
            "stage": "episode_nfo", "ok": True,
            "updated": nfo_updated, "scanned": nfo_scanned,
        })

        try:
            db.notification_add(
                "success",
                f"Renamed “{old_name}” → “{new_name_safe}”",
                ttl_seconds=240,
            )
        except Exception:
            pass
        yield emit_line({
            "stage": "done", "ok": True,
            "old_name": old_name, "new_name": new_name_safe,
            "path": str(dst_path), "row_id": row_id,
        })

    return StreamingResponse(gen(), media_type="application/x-ndjson")


@app.post("/api/favourites/unmatch")
async def api_favourites_unmatch(payload: dict = Body(...)):
    row_id = int(payload.get("id") or 0)
    source = (payload.get("source") or "").strip().upper()
    if not row_id:
        return JSONResponse({"error": "id required"}, status_code=400)
    row = db.favourite_get(row_id)
    if not row:
        return JSONResponse({"error": "Not found"}, status_code=404)
    try:
        db.favourite_clear_source_match(row_id, source)
    except ValueError as e:
        return JSONResponse({"error": str(e)}, status_code=400)
    row = db.favourite_get(row_id)
    if row:
        kind = row.get("kind")
        mt = (row.get("match_tpdb_id") or "").strip() or None
        ms = (row.get("match_stashdb_id") or "").strip() or None
        mf = (row.get("match_fansdb_id") or "").strip() or None
        if kind == "performer":
            sd = _favourite_performer_sort_birth_date(mt, ms, mf)
        elif kind == "movie":
            sd = _favourite_row_sort_birth_date_movie(dict(row))
        elif kind == "jav":
            _, _, aired = _favourite_parse_javstash_from_folder(row.get("path") or "")
            sd = _normalize_sort_birth_date(aired)
        else:
            sd = _favourite_studio_sort_birth_date(mt)
        db.favourite_set_sort_birth_date(row_id, sd)
    return {"ok": True}


@app.post("/api/favourites/ext-link")
async def api_favourites_ext_link(payload: dict = Body(...)):
    """Set a confirmed external profile URL (IAFD / Freeones / Babepedia) for a performer row."""
    row_id = int(payload.get("row_id") or 0)
    site = _ext_site_key(payload.get("site") or "")
    url = (payload.get("url") or "").strip()
    if not row_id:
        return JSONResponse({"error": "row_id required"}, status_code=400)
    if not site:
        return JSONResponse({"error": "site required"}, status_code=400)
    if not url:
        return JSONResponse({"error": "url required"}, status_code=400)
    row = db.favourite_get(row_id)
    if not row or row.get("kind") != "performer":
        return JSONResponse({"error": "Not found"}, status_code=404)
    try:
        store_val = _normalize_ext_link_store(site, url)
        db.favourite_set_ext_link(row_id, site, store_val)
    except ValueError as e:
        return JSONResponse({"error": str(e)}, status_code=400)
    _performer_popup_cache_invalidate_row(row_id)
    threading.Thread(
        target=_enrich_performer_headshot_bg, args=(row_id,), daemon=True
    ).start()
    return {"ok": True}


@app.post("/api/favourites/set-match")
async def api_favourites_set_match(payload: dict = Body(...)):
    """Set a database match (TPDB/StashDB/FansDB) for a performer/studio row from search results."""
    row_id = int(payload.get("row_id") or 0)
    source = (payload.get("source") or "").strip().lower()
    mid = (payload.get("id") or "").strip()
    name = (payload.get("name") or "").strip()
    if not row_id or not source or not mid:
        return JSONResponse({"error": "row_id, source, and id required"}, status_code=400)
    row = db.favourite_get(row_id)
    if not row:
        return JSONResponse({"error": "Not found"}, status_code=404)
    update = {}
    if source == "tpdb":
        update["match_tpdb_id"] = mid
        update["match_tpdb_name"] = name
    elif source == "stashdb":
        update["match_stashdb_id"] = mid
        update["match_stashdb_name"] = name
    elif source == "fansdb":
        update["match_fansdb_id"] = mid
        update["match_fansdb_name"] = name
    else:
        return JSONResponse({"error": f"Unknown source: {source}"}, status_code=400)
    db.favourite_update_matches(row_id, **update)
    # Trigger enrichment in background
    threading.Thread(
        target=_enrich_performer_ext_links_bg, args=(row_id,), daemon=True
    ).start()
    return {"ok": True, "source": source, "id": mid, "name": name}


@app.post("/api/favourites/match")
async def api_favourites_match(payload: dict = Body(...)):
    """Apply a chosen TPDB / StashDB / FansDB hit from manual search. Not gated by matches_locked."""
    row_id = int(payload.get("row_id") or 0)
    source = (payload.get("source") or "").strip().upper()
    ext_id = (payload.get("external_id") or "").strip()
    name = (payload.get("name") or "").strip()
    image = payload.get("image")
    if not row_id or not source or not ext_id:
        return JSONResponse(
            {"error": "row_id, source, and external_id required"},
            status_code=400,
        )
    kw: dict = {}
    if source == "TPDB":
        kw = {
            "match_tpdb_id": ext_id,
            "match_tpdb_name": name,
        }
    elif source == "STASHDB":
        kw = {
            "match_stashdb_id": ext_id,
            "match_stashdb_name": name,
        }
    elif source == "FANSDB":
        kw = {
            "match_fansdb_id": ext_id,
            "match_fansdb_name": name,
        }
    elif source == "TMDB":
        kw = {
            "match_tmdb_id": ext_id,
            "match_tmdb_name": name,
        }
    elif source == "JAVSTASH":
        kw = {
            "match_javstash_id": ext_id,
            "match_javstash_name": name,
        }
    else:
        return JSONResponse(
            {"error": "source must be TMDB, TPDB, StashDB, FansDB, or JAVSTASH"},
            status_code=400,
        )
    row_pre = db.favourite_get(row_id)
    if row_pre and row_pre.get("kind") in ("performer", "movie", "jav") and _favourite_find_local_poster_file(
        row_pre.get("path") or ""
    ):
        kw["image_url"] = f"/api/favourites/folder-poster?row_id={row_id}"
    elif row_pre and row_pre.get("kind") == "studio" and _favourite_find_local_studio_art(
        row_pre.get("path") or ""
    ):
        kw["image_url"] = f"/api/favourites/folder-logo?row_id={row_id}"
    elif image:
        kw["image_url"] = image
    db.favourite_update_matches(row_id, **kw)
    row = db.favourite_get(row_id)
    if row:
        kind = row.get("kind")
        mt = (row.get("match_tpdb_id") or "").strip() or None
        ms = (row.get("match_stashdb_id") or "").strip() or None
        mf = (row.get("match_fansdb_id") or "").strip() or None
        if kind == "performer":
            sd = _favourite_performer_sort_birth_date(mt, ms, mf)
        elif kind == "movie":
            sd = _favourite_row_sort_birth_date_movie(dict(row))
        elif kind == "jav":
            _, _, aired = _favourite_parse_javstash_from_folder(row.get("path") or "")
            sd = _normalize_sort_birth_date(aired)
        else:
            sd = _favourite_studio_sort_birth_date(mt)
        db.favourite_set_sort_birth_date(row_id, sd)
    if row and row.get("kind") == "performer":
        threading.Thread(
            target=_enrich_performer_ext_links_bg, args=(row_id,), daemon=True
        ).start()
    return {"ok": True}


@app.get("/api/favourites/image-search")
async def api_favourites_image_search(row_id: int):
    """Return image URLs from linked DB profiles (all posters/images on each).

    Studios also include any image files already in the source folder
    (logo.png, clearlogo.png, banner.png, plus any extras the user has
    dropped in) tagged with ``source: "Local"`` and a ``local_name`` key
    so the picker can route the apply call through the local-file path
    rather than downloading a remote URL."""
    row = db.favourite_get(row_id)
    if not row:
        return JSONResponse({"error": "Not found"}, status_code=404)
    kind = row.get("kind")
    if kind not in ("performer", "studio"):
        return JSONResponse({"error": "Invalid row kind"}, status_code=400)
    items = _favourites_matched_link_image_items(row)
    if kind == "studio":
        local: list[dict] = []
        for p in _favourite_studio_folder_image_files(row.get("path") or ""):
            local.append({
                "source": "Local",
                "id": "",
                "name": p.name,
                "image": f"/api/favourites/folder-image?row_id={row_id}&name={quote(p.name)}",
                "local_name": p.name,
            })
        items = local + items
    return {"items": items, "query": "", "kind": kind}


@app.get("/api/favourites/folder-image")
async def api_favourites_folder_image(row_id: int, name: str):
    """Serve a named image file from a studio folder. Path-safe: the
    name must be a bare filename (no separators, no traversal) with an
    allowed image extension, and the resolved file must live directly
    in the row's folder."""
    safe = (name or "").strip()
    if not safe or "/" in safe or "\\" in safe or safe in (".", ".."):
        return JSONResponse({"error": "Bad name"}, status_code=400)
    if Path(safe).suffix.lower() not in _STUDIO_ART_IMAGE_EXT:
        return JSONResponse({"error": "Bad extension"}, status_code=400)
    row = db.favourite_get(row_id)
    if not row or row.get("kind") != "studio":
        return JSONResponse({"error": "Not found"}, status_code=404)
    folder = (row.get("path") or "").strip()
    if not folder:
        return JSONResponse({"error": "Not found"}, status_code=404)
    try:
        root = Path(folder).expanduser().resolve()
        p = (root / safe).resolve()
    except (OSError, RuntimeError):
        return JSONResponse({"error": "Bad path"}, status_code=400)
    if root not in p.parents and p != root:
        return JSONResponse({"error": "Bad path"}, status_code=400)
    if not p.is_file():
        return JSONResponse({"error": "Not found"}, status_code=404)
    mt, _ = mimetypes.guess_type(str(p))
    return FileResponse(p, media_type=mt or "image/jpeg")


@app.get("/api/performers/poster-roles")
async def api_performers_poster_roles(row_id: int):
    """Return URLs for the currently-saved primary + secondary posters of a
    performer row, plus the scraped candidate list from linked DB profiles.
    Used by the /library performer "manage posters" modal.

    The candidates list is prepended with a "Local library" entry pointing
    at the performer folder's local `poster.jpg` (if one exists on disk),
    so users can re-assign their existing on-disk poster to either role
    without having to re-download anything from a remote DB."""
    row = db.favourite_get(row_id)
    if not row or row.get("kind") != "performer":
        return JSONResponse({"error": "Not a performer row"}, status_code=404)
    md = _metadata_dir_for("performer", row_id)
    def _role_url(role: str) -> str | None:
        for name in (f"{row_id}_poster_{role}.jpg",
                     f"{row_id}_poster_{1 if role == 'primary' else 2}.jpg"):
            p = md / name
            if p.is_file() and p.stat().st_size > 500:
                return (f"/api/performers/poster-role-image?row_id={row_id}"
                        f"&role={role}&v={int(p.stat().st_mtime)}")
        return None
    candidates = _favourites_matched_link_image_items(row) or []
    # Prepend the local library poster.jpg if present. The image URL is a
    # local API path that serves the file straight off disk — the frontend
    # opens it as <img> and it round-trips back through set-poster-role
    # which calls _favourites_download_image_bytes() with the absolute URL.
    local = _favourite_find_local_poster_file(row.get("path") or "")
    if local and local.is_file():
        local_url = f"/api/favourites/folder-poster?row_id={row_id}&v={int(local.stat().st_mtime)}"
        candidates.insert(0, {
            "name":   "Local library poster",
            "source": "Local",
            "image":  local_url,
        })
    # Current headshot URL — prefer the cached IAFD image (same path the
    # bio popup uses) so the preview matches what's actually on disk.
    # Fall back to any custom upload, then to whatever image_url is
    # stored on the favourite row. The stored image_url can go stale
    # (external scrape URL that 404s, wrong row from an earlier match),
    # so the IAFD-cached path is the most reliable signal.
    headshot_url = _performers_iafd_image_api_url(
        row_id, 0, _performers_iafd_read_meta(row_id)
    )
    if not headshot_url:
        cust = _performers_custom_ref_resolve(row_id)
        if cust:
            headshot_url = f"/api/performers/custom-image?row_id={row_id}"
    if not headshot_url:
        headshot_url = (row.get("image_url") or "").strip() or None
    return {
        "primary_url":   _role_url("primary"),
        "secondary_url": _role_url("secondary"),
        "headshot_url":  headshot_url,
        "candidates":    candidates,
        "name":          row.get("folder_name") or "",
    }


@app.get("/api/performers/poster-role-image")
async def api_performers_poster_role_image(row_id: int, role: str, v: int = 0):
    """Serve the current primary or secondary poster as a plain image for the
    modal preview. `role` is 'primary' or 'secondary'; `v` is a cache-bust
    mtime token from the poster-roles endpoint."""
    role = (role or "").strip().lower()
    if role not in ("primary", "secondary"):
        return JSONResponse({"error": "role must be primary or secondary"}, status_code=400)
    md = _metadata_dir_for("performer", row_id)
    for name in (
        f"{row_id}_poster_{role}.jpg",
        f"{row_id}_poster_{1 if role == 'primary' else 2}.jpg",
    ):
        p = md / name
        if p.is_file() and p.stat().st_size > 500:
            return FileResponse(
                p,
                media_type="image/jpeg",
                headers={"Cache-Control": "private, max-age=60"},
            )
    return JSONResponse({"error": "Not found"}, status_code=404)


@app.post("/api/performers/set-poster-role")
async def api_performers_set_poster_role(payload: dict = Body(...)):
    """Download a remote image (or copy the local library poster) and write
    it as the performer's primary or secondary poster in
    `metadata/performers/{row_id}/`. Body:
        { row_id: int, image_url: str, role: 'primary'|'secondary' }

    `image_url` is either an http(s) URL (scraped DB image) or the local
    `/api/favourites/folder-poster?row_id=…` path — in the second case we
    skip the HTTP fetch and read the file straight from the library folder.

    Returns {ok: True, role, poster_url} where poster_url is a cache-busted
    URL the frontend can load to refresh its preview.
    """
    try:
        row_id = int(payload.get("row_id") or 0)
    except (TypeError, ValueError):
        row_id = 0
    image_url = (payload.get("image_url") or "").strip()
    role = (payload.get("role") or "").strip().lower()
    if not row_id or not image_url or role not in ("primary", "secondary"):
        return JSONResponse(
            {"error": "row_id, image_url and role ('primary'|'secondary') required"},
            status_code=400,
        )
    row = db.favourite_get(row_id)
    if not row or row.get("kind") != "performer":
        return JSONResponse({"error": "Not a performer row"}, status_code=404)
    # Local-poster shortcut: `/api/favourites/folder-poster?row_id=…` is our
    # own endpoint exposing the library folder's poster.jpg. Rather than
    # HTTP-fetch ourselves, read the file straight from disk.
    data: bytes
    if image_url.startswith("/api/favourites/folder-poster"):
        local = _favourite_find_local_poster_file(row.get("path") or "")
        if not local or not local.is_file():
            return JSONResponse(
                {"error": "Local poster file not found on disk"},
                status_code=404,
            )
        try:
            data = local.read_bytes()
        except OSError as e:
            return JSONResponse({"error": f"Could not read local poster: {e}"}, status_code=500)
    else:
        if not image_url.lower().startswith(("http://", "https://")):
            return JSONResponse({"error": "image_url must be http(s) or the local folder-poster path"}, status_code=400)
        try:
            data = _favourites_download_image_bytes(image_url)
        except requests.RequestException as e:
            return JSONResponse({"error": f"Download failed: {e}"}, status_code=502)
        except ValueError as e:
            return JSONResponse({"error": str(e)}, status_code=400)
    result = await run_in_threadpool(_performers_write_poster_role_bytes, row_id, role, data)
    if isinstance(result, JSONResponse):
        return result
    return result


def _performers_write_poster_role_bytes(row_id: int, role: str, data: bytes) -> dict | JSONResponse:
    """Persist primary/secondary poster bytes; shared by URL and file upload."""
    row = db.favourite_get(row_id)
    if not row or row.get("kind") != "performer":
        return JSONResponse({"error": "Not a performer row"}, status_code=404)
    if not data:
        return JSONResponse({"error": "empty image"}, status_code=400)
    md = _metadata_dir_for("performer", row_id)
    dest = md / f"{row_id}_poster_{role}.jpg"
    try:
        ok = save_image_bytes_optimized(data, dest, max_edge=IMAGE_CACHE_POSTER_MAX)
    except OSError as e:
        return JSONResponse({"error": f"Write failed: {e}"}, status_code=500)
    if not ok:
        return JSONResponse({"error": "Could not encode image"}, status_code=500)
    legacy = md / f"{row_id}_poster_{1 if role == 'primary' else 2}.jpg"
    if legacy.is_file() and legacy != dest:
        try:
            legacy.unlink()
        except OSError:
            pass
    emit(f"performer row {row_id}: {role} poster replaced via manual picker")
    return {
        "ok": True,
        "role": role,
        "poster_url": (f"/api/performers/poster-role-image?row_id={row_id}"
                       f"&role={role}&v={int(dest.stat().st_mtime)}"),
    }


@app.post("/api/performers/set-poster-role-file")
async def api_performers_set_poster_role_file(
    row_id: int = Form(...),
    role: str = Form(...),
    file: UploadFile = File(...),
):
    """Upload a local image file as primary or secondary poster (blob: imports)."""
    role = (role or "").strip().lower()
    if not row_id or role not in ("primary", "secondary"):
        return JSONResponse(
            {"error": "row_id and role ('primary'|'secondary') required"},
            status_code=400,
        )
    try:
        data = await file.read()
    except Exception as e:
        return JSONResponse({"error": f"Read failed: {e}"}, status_code=500)
    result = await run_in_threadpool(_performers_write_poster_role_bytes, row_id, role, data)
    if isinstance(result, JSONResponse):
        return result
    return result


@app.post("/api/favourites/apply-image")
async def api_favourites_apply_image(payload: dict = Body(...)):
    """Set favourites tile image from a remote URL or an existing file
    inside the row's folder. ``local_name`` is the bare filename of an
    image already in the studio folder (returned by image-search items
    tagged ``source: "Local"``); ``image_url`` is an http(s) URL from a
    linked DB. Exactly one must be supplied. With ``save_local=true``
    the chosen image bytes are written to ``logo.png`` /``poster.jpg``
    in the folder; without it, the row's image_url just points at the
    chosen file or URL."""
    try:
        row_id = int(payload.get("row_id") or 0)
    except (TypeError, ValueError):
        row_id = 0
    image_url = (payload.get("image_url") or "").strip()
    local_name = (payload.get("local_name") or "").strip()
    save_local = bool(payload.get("save_local"))
    if not row_id or (not image_url and not local_name):
        return JSONResponse(
            {"error": "row_id plus image_url or local_name required"},
            status_code=400,
        )
    if image_url and not image_url.lower().startswith(("http://", "https://")):
        return JSONResponse(
            {"error": "image_url must be http(s)"},
            status_code=400,
        )
    if local_name and ("/" in local_name or "\\" in local_name or local_name in (".", "..")):
        return JSONResponse(
            {"error": "Bad local_name"},
            status_code=400,
        )
    row = db.favourite_get(row_id)
    if not row:
        return JSONResponse({"error": "Not found"}, status_code=404)
    kind = row.get("kind")
    folder = (row.get("path") or "").strip()
    new_stored_url: str
    # When picking a local file we have to resolve it up-front so both
    # the save-to-logo path and the bare image_url path agree on the
    # same source file.
    local_path: Path | None = None
    if local_name:
        if not folder:
            return JSONResponse({"error": "Folder path missing"}, status_code=400)
        try:
            root = Path(folder).expanduser().resolve()
            cand = (root / local_name).resolve()
        except (OSError, RuntimeError):
            return JSONResponse({"error": "Invalid folder path"}, status_code=400)
        if (root not in cand.parents and cand != root) or not cand.is_file():
            return JSONResponse({"error": "Local file not found"}, status_code=404)
        if cand.suffix.lower() not in _STUDIO_ART_IMAGE_EXT:
            return JSONResponse({"error": "Bad extension"}, status_code=400)
        local_path = cand

    if save_local:
        if not folder:
            return JSONResponse(
                {"error": "Folder path missing — cannot save file"},
                status_code=400,
            )
        try:
            root = Path(folder).expanduser().resolve()
        except (OSError, RuntimeError):
            return JSONResponse(
                {"error": "Invalid folder path"},
                status_code=400,
            )
        if not root.is_dir():
            return JSONResponse(
                {"error": "Folder not on disk — cannot save file"},
                status_code=400,
            )
        if local_path is not None:
            try:
                data = local_path.read_bytes()
            except OSError as e:
                return JSONResponse({"error": f"Read failed: {e}"}, status_code=500)
        else:
            try:
                data = _favourites_download_image_bytes(image_url)
            except requests.RequestException as e:
                return JSONResponse(
                    {"error": f"Download failed: {e}"},
                    status_code=502,
                )
            except ValueError as e:
                return JSONResponse({"error": str(e)}, status_code=400)
        try:
            if kind in ("performer", "movie", "jav"):
                dest = root / "poster.jpg"
                ok = save_image_bytes_optimized(
                    data,
                    dest,
                    max_edge=FAVOURITES_SAVED_POSTER_MAX_EDGE,
                )
            elif kind == "studio":
                dest = root / "logo.png"
                ok = save_image_bytes_optimized(
                    data,
                    dest,
                    max_edge=FAVOURITES_SAVED_POSTER_MAX_EDGE,
                )
            else:
                return JSONResponse({"error": "Invalid row kind"}, status_code=400)
        except OSError:
            return JSONResponse({"error": "Could not write file"}, status_code=500)
        if not ok:
            return JSONResponse({"error": "Could not encode image"}, status_code=500)
        # Cache-bust by appending the freshly-written file's mtime so the
        # browser (and any downstream tiles binding to row.image_url)
        # fetches the new bytes instead of serving the previous payload
        # at the unchanged folder-poster/folder-logo URL.
        try:
            mtime = int(dest.stat().st_mtime)
        except OSError:
            mtime = int(time.time())
        if kind in ("performer", "movie", "jav"):
            new_stored_url = f"/api/favourites/folder-poster?row_id={row_id}&v={mtime}"
        else:
            new_stored_url = f"/api/favourites/folder-logo?row_id={row_id}&v={mtime}"
            #: Studio logos also live in the central `studio_logos`
            #: table (queried by /api/studio-logo?name=X for every scene
            #: card across /scenes / /library / /queue). Without
            #: mirroring the change there, the popup logo updates but
            #: the per-scene overlays keep showing the old logo. Push
            #: the new bytes through _normalise_studio_logo_to_png →
            #: studio_logos so the central cache stays in sync.
            try:
                display_name = (row.get("display_name") or row.get("folder_name") or "").strip()
                if display_name:
                    sl_dest_dir = _studio_logos_dir()
                    sl_slug = db.studio_logo_slug(display_name)
                    if sl_slug:
                        sl_name = _studio_logo_filename(sl_slug)
                        sl_dest = sl_dest_dir / sl_name
                        sl_ok = _normalise_studio_logo_to_png(data, sl_dest, target_width=300)
                        if sl_ok:
                            db.studio_logo_upsert(display_name, logo_path=sl_name, source="manual")
            except Exception as exc:
                emit(f"studio_logos sync failed for row {row_id}: {exc}")
        #: Drop the resized thumb cache so the next /studio-thumb or
        #: /performer-thumb hit rebuilds from the new on-disk bytes.
        #: Without this `_ensure_studio_images` returns the previously
        #: cached PNG and the popup keeps showing the old logo even
        #: though the source file is fresh.
        try:
            thumb_md = _metadata_dir_for("studio" if kind == "studio" else "performer", row_id)
            for tname in (
                # WebP + legacy extensions — runtime caches mid-migration
                # may have either on disk, drop both.
                f"{row_id}_logo.webp",
                f"{row_id}_logo.png",
                f"{row_id}_poster.webp",
                f"{row_id}_poster.jpg",
                f"{row_id}_poster_primary.webp",
                f"{row_id}_poster_primary.jpg",
                f"{row_id}_poster_secondary.webp",
                f"{row_id}_poster_secondary.jpg",
            ):
                tp = thumb_md / tname
                if tp.is_file():
                    try: tp.unlink()
                    except OSError: pass
        except Exception:
            pass
    else:
        if local_path is not None:
            new_stored_url = (
                f"/api/favourites/folder-image?row_id={row_id}"
                f"&name={quote(local_path.name)}"
            )
        else:
            new_stored_url = image_url

    favourites_clear_image_disk_cache(row_id)
    db.favourite_update_matches(row_id, image_url=new_stored_url)
    return {"ok": True, "image_url": new_stored_url}


