@app.get("/api/movies/search")
async def movies_search(q: str = "", year: str = "", page: int = 1):
    try:
        base_params = {}
        if q.strip():
            base_params["parse"] = q.strip()
        if year:
            base_params["year"] = year
        # Search is an explicit user query — don't apply the 2-year
        # age floor that the /latest feed uses, otherwise searching
        # for older titles by name returns nothing.
        base_params["_no_age_floor"] = True
        payload = _collect_filtered_tpdb_movies(base_params, page=page, page_size=20)
        try:
            payload["jav_scenes"] = _javstash_scenes_for_movie_search(q, year, limit=18)
        except Exception:
            payload["jav_scenes"] = []
        return payload
    except Exception as e:
        return JSONResponse({"error": str(e)}, status_code=500)


@app.get("/api/movies/tpdb/latest")
async def movies_tpdb_latest(page: int = 1, refresh: int = 0):
    """Get latest TPDB movie releases, filtered by content categories.

    Page-1 rows merge into a capped SQLite pool (``feed_display_pools``) so
    the grid survives restarts. When the in-memory page-1 cache is cold, the
    merged SQLite pool is returned immediately (``from_disk``) without waiting
    on TPDB. ``refresh=1`` clears that pool and the
    in-process page-1 cache so TPDB ordering / filter logic changes take
    effect immediately (same contract as ``/api/scenes/feed``).
    """
    try:
        p = max(1, int(page or 1))
        if refresh:
            try:
                with _content_cache_lock:
                    _movies_latest_cache["results"] = []
                    _movies_latest_cache["ts"] = 0
                    _movies_latest_cache["filter_key"] = None
            except Exception:
                pass
            try:
                db.feed_display_pools_clear_kind("movies")
            except Exception:
                pass
        if p == 1:
            fk = _movies_cache_filter_key()
            if not refresh:
                try:
                    inst = _movies_latest_try_instant_disk(fk)
                    if inst is not None:
                        return inst
                except Exception:
                    pass
            with _content_cache_lock:
                age = time.time() - _movies_latest_cache["ts"]
                cache_ok = (
                    _movies_latest_cache["results"]
                    and age < _MOVIES_CACHE_TTL
                    and _movies_latest_cache.get("filter_key") == fk
                )
                fresh = list(_movies_latest_cache["results"] or []) if cache_ok else []
            if cache_ok and fresh:
                merged = _persist_movies_feed_display_pool(fk, fresh)
                _scenes_feed_rewrite_thumbs(merged)
                return {
                    "results": merged,
                    "cached": True,
                    "cache_age_s": int(age),
                    "page": 1,
                    "total_pages": 1,
                }
            payload = _collect_filtered_tpdb_movies({}, page=1, page_size=30)
            fresh = list(payload.get("results") or [])
            merged = _persist_movies_feed_display_pool(fk, fresh)
            out = dict(payload)
            out["results"] = merged
            with _content_cache_lock:
                _movies_latest_cache["results"] = fresh
                _movies_latest_cache["ts"] = time.time()
                _movies_latest_cache["filter_key"] = fk
            _scenes_feed_rewrite_thumbs(out["results"])
            return out
        page_payload = _collect_filtered_tpdb_movies({}, page=p, page_size=30)
        _scenes_feed_rewrite_thumbs(page_payload.get("results") or [])
        return page_payload
    except Exception as e:
        return {"results": [], "error": str(e)}


