def _resolve_library_performers_for_movie(names: list) -> list:
    """Cross-reference a list of performer names against the library, returning headshot URLs.

    Matching strategies, in order of preference:
      1. Exact folder-name match (``Silvia Dellai`` → ``Silvia Dellai``)
      2. Canonical primary-name match (``match_tpdb_name`` /
         ``match_stashdb_name`` / ``match_fansdb_name``) — picks up
         folders where the library folder name differs from the name
         the external DBs return as the performer's primary.

    ``aliases_json`` is deliberately NOT consulted here. That column
    holds the alternate-name lists scraped off TPDB / StashDB / FansDB,
    which are too noisy to use for credit matching (first-name-only
    entries, stage names shared across multiple performers). Only
    names the external DBs flag as a performer's *primary* name are
    trusted — those live in the ``match_*_name`` columns above.

    Multiple input names resolving to the same library row are
    deduplicated on the row id, so a scene crediting the same
    performer twice only surfaces one headshot tile.
    """
    try:
        rows = db.favourite_list()
        # Precompute every lookup surface for every performer folder so
        # the per-name loop below is O(1). Pulling this into a single
        # normalised dict keeps the resolver scan linear in the library
        # size rather than quadratic.
        folder_map: dict[str, dict] = {}
        canonical_map: dict[str, dict] = {}
        for r in rows:
            if r.get("kind") != "performer":
                continue
            fn = (r.get("folder_name") or "").lower().strip()
            if fn and fn not in folder_map:
                folder_map[fn] = r
            for canon_field in ("match_tpdb_name", "match_stashdb_name", "match_fansdb_name"):
                cn = (r.get(canon_field) or "").lower().strip()
                if cn and cn not in canonical_map:
                    canonical_map[cn] = r
        result = []
        seen_row_ids: set[int] = set()
        seen_input: set[str] = set()
        for name in (names or []):
            key = (name or "").lower().strip()
            if not key or key in seen_input:
                continue
            seen_input.add(key)
            row = folder_map.get(key) or canonical_map.get(key)
            if not row:
                continue
            rid = int(row["id"])
            if rid in seen_row_ids:
                continue
            seen_row_ids.add(rid)
            meta = _performers_iafd_read_meta(rid)
            headshot_url = _performers_iafd_image_api_url(rid, 0, meta) or row.get("image_url") or None
            result.append({
                "name": row["folder_name"],
                "row_id": rid,
                "headshot_url": headshot_url,
            })
        return result
    except Exception:
        return []


#: Server-side cache for the `/api/performers/headshots-by-name` endpoint.
#: Each /queue render fans out one batched request listing every cast
#: name on screen. The resolver underneath walks favourite_list() + reads
#: an IAFD meta JSON per matched performer, which adds up when the same
#: cast names repeat across queue rows / pages and across rapid tab
#: switches. 5-minute TTL per name matches the genders-by-name cache
#: above — name → headshot URL doesn't churn between fetches.
_headshots_by_name_cache: dict[str, tuple[float, dict | None]] = {}
_headshots_by_name_lock = threading.Lock()
_HEADSHOTS_BY_NAME_TTL = 300.0


@app.get("/api/performers/headshots-by-name")
async def api_performers_headshots_by_name(names: str):
    """Return library headshot data for one or more comma-separated performer names."""
    name_list = [n.strip() for n in (names or "").split(",") if n.strip()]
    if not name_list:
        return {"performers": []}
    now = time.time()
    cached_hits: list[dict] = []
    pending: list[str] = []
    with _headshots_by_name_lock:
        for name in name_list:
            k = name.lower()
            entry = _headshots_by_name_cache.get(k)
            if entry and (now - entry[0]) < _HEADSHOTS_BY_NAME_TTL:
                if entry[1] is not None:
                    cached_hits.append(entry[1])
            else:
                pending.append(name)
    if not pending:
        return {"performers": cached_hits}
    resolved = _resolve_library_performers_for_movie(pending)
    # Index resolved results by lower-cased input name so we can record
    # both hits AND misses in the cache (None marks "this name doesn't
    # match anything in the library" — saves the re-walk next time).
    by_lower_name = {(r.get("name") or "").lower(): r for r in resolved}
    fresh_ts = time.time()
    with _headshots_by_name_lock:
        for name in pending:
            k = name.lower()
            _headshots_by_name_cache[k] = (fresh_ts, by_lower_name.get(k))
    return {"performers": cached_hits + resolved}


#: Server-side cache for the `/api/performers/genders-by-name` endpoint.
#: Several pages (history, library tables, queue, wanted) fan out a
#: lot of name→gender lookups on first paint; caching the result for 5
#: minutes per name keeps repeat lookups from re-walking the library
#: index + reading the IAFD meta JSON every time.
_genders_by_name_cache: dict[str, tuple[float, str]] = {}
_genders_by_name_lock = threading.Lock()
_GENDERS_BY_NAME_TTL = 300.0


@app.get("/api/performers/genders-by-name")
async def api_performers_genders_by_name(names: str):
    """Map a list of performer names to their genders.

    Used by the front-end to inject gender badges next to performer
    names that come from local-DB string columns (queue rows, history,
    library tables, favourites scenes) where the renderer only has the
    name. Resolves each name against the library via the same matcher
    `_resolve_library_performers_for_movie` uses, then reads the cached
    IAFD/Stash metadata for the gender field. Names that don't resolve
    are returned with an empty gender so the front-end can render the
    name without a badge.

    Per-name results are memoised for 5 minutes so a freshly-loaded
    page that fans out hundreds of lookups across many tables only
    hits the library index + meta-JSON read once per unique name.
    """
    name_list = [n.strip() for n in (names or "").split(",") if n.strip()]
    if not name_list:
        return {"genders": {}}
    out: dict[str, str] = {}
    now = time.time()
    pending: list[str] = []
    with _genders_by_name_lock:
        for name in name_list:
            k = name.lower()
            entry = _genders_by_name_cache.get(k)
            if entry and (now - entry[0]) < _GENDERS_BY_NAME_TTL:
                out[name] = entry[1]
            else:
                pending.append(name)
    if not pending:
        return {"genders": out}
    try:
        rows = db.favourite_list()
        folder_map: dict[str, dict] = {}
        canonical_map: dict[str, dict] = {}
        for r in rows:
            if r.get("kind") != "performer":
                continue
            fn = (r.get("folder_name") or "").lower().strip()
            if fn and fn not in folder_map:
                folder_map[fn] = r
            for canon_field in ("match_tpdb_name", "match_stashdb_name", "match_fansdb_name"):
                cn = (r.get(canon_field) or "").lower().strip()
                if cn and cn not in canonical_map:
                    canonical_map[cn] = r
        seen_input: set[str] = set()
        for name in pending:
            key = (name or "").lower().strip()
            if not key or key in seen_input:
                continue
            seen_input.add(key)
            row = folder_map.get(key) or canonical_map.get(key)
            if not row:
                g = ""
            else:
                g = _favourite_row_tile_gender(row).lower()
            out[name] = g
            with _genders_by_name_lock:
                _genders_by_name_cache[key] = (now, g)
    except Exception:
        pass
    return {"genders": out}


@app.get("/api/movies/tpdb/{movie_id}")
async def movies_tpdb_detail(movie_id: str):
    """Get full TPDB movie detail."""
    try:
        resp = requests.get(f"https://api.theporndb.net/movies/{movie_id}",
                            headers=_tpdb_headers(), timeout=15)
        if resp.status_code != 200:
            return JSONResponse({"error": f"TPDB returned {resp.status_code}"}, status_code=resp.status_code)
        m = resp.json().get("data") or {}
        # image = front cover (portrait), back_image = back cover
        poster = m.get("image") or m.get("poster") or m.get("poster_image")
        bg = m.get("back_image") or m.get("poster")
        if not poster:
            posters_obj = m.get("posters") or {}
            if isinstance(posters_obj, dict):
                poster = posters_obj.get("full") or posters_obj.get("large")
        # Dedup on a case-insensitive name key so TPDB records that list
        # the same performer twice (happens on older / merged entries)
        # don't surface a duplicate tag in the detail popup.
        performers = []
        performer_links = []
        seen_perf_keys: set[str] = set()
        def _register_perf(name_s: str, url: str = "", image: str = "", gender: str = "") -> None:
            s = (name_s or "").strip()
            if not s:
                return
            k = s.lower()
            if k in seen_perf_keys:
                return
            seen_perf_keys.add(k)
            performers.append(s)
            performer_links.append({
                "name":   s,
                "url":    url,
                "image":  image,
                "gender": (gender or "").strip().lower(),
            })

        def _perf_gender(perf: dict, parent: dict | None = None) -> str:
            """Pull the gender field out of a TPDB performer record. The
            payload occasionally tucks it under `extras.gender` or on the
            outer wrapper instead of the inner performer dict, so probe
            the same fan of paths used by `_scene_display_performers`."""
            cands = [
                perf.get("gender"),
                perf.get("sex"),
                ((perf.get("extras") or {}).get("gender")
                    if isinstance(perf.get("extras"), dict) else None),
                ((parent or {}).get("gender") if parent else None),
                (((parent or {}).get("extras") or {}).get("gender")
                    if parent and isinstance(parent.get("extras"), dict) else None),
            ]
            for g in cands:
                if g and str(g).strip():
                    return str(g).strip().lower()
            return ""

        def _perf_image(perf: dict) -> str:
            for key in ("image", "poster", "poster_image", "headshot", "thumbnail"):
                v = perf.get(key)
                if isinstance(v, str) and v.strip():
                    return v.strip()
                if isinstance(v, dict):
                    u = v.get("url") or v.get("full") or v.get("large")
                    if u:
                        return str(u).strip()
            posters = perf.get("posters") or []
            if isinstance(posters, list) and posters:
                p0 = posters[0]
                if isinstance(p0, str) and p0.strip():
                    return p0.strip()
                if isinstance(p0, dict):
                    u = p0.get("url") or p0.get("full") or p0.get("large")
                    if u:
                        return str(u).strip()
            return ""

        for p in (m.get("performers") or []):
            if isinstance(p, dict):
                perf = p.get("performer") or p
                name = perf.get("name") or perf.get("full_name") or ""
                slug = perf.get("slug") or perf.get("_id") or perf.get("id")
                url = ""
                if slug:
                    url = f"https://theporndb.net/performers/{slug}"
                elif perf.get("url"):
                    url = str(perf.get("url"))
                _register_perf(name, url, _perf_image(perf), _perf_gender(perf, p))
            elif isinstance(p, str):
                _register_perf(p)
        scenes = []
        for s in (m.get("scenes") or []):
            thumb = s.get("poster_image") or s.get("image")
            scenes.append({
                "id": str(s.get("_id") or s.get("id") or ""),
                "title": s.get("title") or "",
                "date": s.get("date") or "",
                "thumb": thumb,
            })
        tmdb_id = (
            m.get("tmdb_id")
            or (m.get("tmdb") or {}).get("id")
            or (m.get("movie") or {}).get("tmdb_id")
        )
        tmdb_url = ""
        if tmdb_id:
            tmdb_url = f"https://www.themoviedb.org/movie/{tmdb_id}"
        else:
            tmdb_url = f"https://www.themoviedb.org/search/movie?query={quote_plus(m.get('title') or '')}"

        raw_dirs = m.get("directors") or []
        directors_norm = []
        for d in raw_dirs:
            if isinstance(d, dict):
                dn = d.get("name") or d.get("full_name") or ""
                if dn:
                    directors_norm.append(dn)
            elif isinstance(d, str) and d:
                directors_norm.append(d)
        library_perfs = _resolve_library_performers_for_movie(performers)
        # When true, clients may treat poster/background as one wide spread
        # (lower aspect-ratio threshold). TPDB detail leaves this false;
        # JAV / other sources can set true explicitly.
        cover_art_is_spread = False
        return {
            "id":          str(m.get("_id") or m.get("id") or ""),
            "slug":        m.get("slug") or m.get("_id") or str(m.get("id", "")),
            "title":       m.get("title") or "",
            "date":        m.get("date") or "",
            "year":        (m.get("date") or "")[:4],
            "studio":      (m.get("site") or {}).get("name") or (m.get("studio") or {}).get("name") or "",
            "duration":    m.get("duration") or 0,
            "synopsis":    m.get("description") or m.get("synopsis") or "",
            "poster":      poster,
            "background":  bg,
            "cover_art_is_spread": cover_art_is_spread,
            "performers":  performers,
            "performer_links": performer_links,
            "library_performers": library_perfs,
            "directors":   directors_norm,
            "scenes":      scenes,
            "tags":        _tpdb_scene_tag_names(m),
            "url":         f"https://theporndb.net/movies/{m.get('slug') or m.get('_id') or movie_id}",
            "tmdb_url":    tmdb_url,
        }
    except Exception as e:
        return JSONResponse({"error": str(e)}, status_code=500)


