@app.get("/api/movies/stats")
async def movies_stats():
    # The warm queue cache already reconciles on every rebuild (every
    # 60s + on filesystem events). When its snapshot is fresh we can
    # skip the duplicate reconcile here entirely — saves a full source
    # dir walk on every loadQueueStats() fan-out call. Falls back to
    # the inline reconcile if the cache is stale or hasn't been built
    # yet (covers cold-start before the worker first ticks).
    try:
        if _movies_queue_warm.age_seconds() > 90.0:
            settings = db.get_settings()
            source_dir = Path((settings.get("movies_source_dir") or "").strip()).expanduser()
            if source_dir.is_dir():
                db.reconcile_movies_source(source_dir)
    except Exception:
        pass
    return db.get_movie_stats()


@app.post("/api/movies/file")
async def file_movie_endpoint(payload: dict, background_tasks: BackgroundTasks):
    """File a video as a movie using TMDB id, TPDB id, or JAVStash scene id (TMDB takes precedence if multiple sent)."""
    if processing_state["running"]:
        return JSONResponse({"error": "Pipeline already running"}, status_code=409)

    filename = payload.get("filename", "").strip()
    tmdb_id = payload.get("tmdb_id", "").strip()
    tpdb_id = payload.get("tpdb_id", "").strip()
    javstash_id = payload.get("javstash_id", "").strip()

    pick_n = int(bool(tmdb_id)) + int(bool(tpdb_id)) + int(bool(javstash_id))
    if not filename or pick_n != 1:
        return JSONResponse(
            {"error": "filename and exactly one of tmdb_id, tpdb_id, or javstash_id required"},
            status_code=400,
        )

    settings = db.get_settings()
    source_dir = Path((settings.get("movies_source_dir") or "").strip()).expanduser()
    video = source_dir / filename

    if not video.exists():
        return JSONResponse({"error": f"File not found: {filename}"}, status_code=404)

    def run():
        processing_state["running"] = True
        processing_state["log"] = []
        processing_state["pipeline_total"] = 1
        processing_state["pipeline_done"] = 0
        processing_state["current_file"] = filename
        try:
            emit(f"FILE {filename}")
            if tmdb_id:
                emit(f"  Fetching TMDB details for ID {tmdb_id}...")
                movie = get_tmdb_movie(tmdb_id)
                file_movie(video, movie, match_source="tmdb")
            elif tpdb_id:
                emit(f"  Fetching TPDB movie {tpdb_id}...")
                detail = _fetch_tpdb_movie_detail(tpdb_id)
                if not detail:
                    raise RuntimeError("TPDB movie not found")
                md = _tpdb_detail_as_movie_filing_dict(detail)
                tid = md.pop("_tpdb_id", None) or tpdb_id
                file_movie(video, md, tpdb_id=str(tid), match_source="tpdb")
            else:
                emit(f"  Fetching JAVStash scene {javstash_id}...")
                jscene = _fetch_javstash_scene_for_filing(javstash_id)
                if not jscene:
                    raise RuntimeError("JAVStash scene not found")
                md = _javstash_scene_as_movie_filing_dict(jscene)
                jid = md.pop("_javstash_id", None) or javstash_id
                file_movie(video, md, javstash_id=str(jid), match_source="javstash")
        except Exception as e:
            emit(f"  ERROR: {e}")
            db.update_movie(filename, status="error", error=str(e))
        finally:
            processing_state["running"] = False
            processing_state["current_file"] = None
            processing_state["pipeline_total"] = 0
            processing_state["pipeline_done"] = 0
            emit("---")

    background_tasks.add_task(run)
    return {"started": True, "filename": filename}


