@app.post("/api/file/manual/metadata")
async def file_manual_metadata(payload: dict, background_tasks: BackgroundTasks):
    """
    File a video using manually entered metadata, bypassing all database lookups.
    Accepts: filename, title, studio, date (YYYY-MM-DD), performers (comma-separated),
             plot (optional), image_url (optional)
    """
    if processing_state["running"]:
        return JSONResponse({"error": "Pipeline already running"}, status_code=409)

    filename       = payload.get("filename", "").strip()
    title          = payload.get("title", "").strip()
    studio         = payload.get("studio", "").strip()
    date           = payload.get("date", "").strip()
    performers     = payload.get("performers", "").strip()
    plot           = payload.get("plot", "").strip()
    image_url      = payload.get("image_url", "").strip()
    thumb_data_url = payload.get("thumb_data_url", "").strip()

    if not all([filename, title, studio, date]):
        return JSONResponse({"error": "filename, title, studio and date are required"}, status_code=400)

    settings   = db.get_settings()
    source_dir = Path(settings.get("source_dir", ""))
    video      = source_dir / filename

    if not video.exists():
        return JSONResponse({"error": f"File not found: {filename}"}, status_code=404)

    # Build a scene dict in stash-box shape so file_scene_from_match can handle it
    perf_list = [p.strip() for p in performers.split(",") if p.strip()]
    scene = {
        "title":           title,
        "release_date":    date,
        "studio":          {"name": studio},
        "performers":      [{"performer": {"name": n, "gender": ""}} for n in perf_list],
        "images":          [{"url": image_url, "width": 0, "height": 0}] if image_url else [],
        "_plot":           plot,
        "_thumb_data_url": thumb_data_url,
    }

    def run():
        processing_state["running"] = True
        processing_state["log"] = []
        processing_state["pipeline_total"] = 1
        processing_state["pipeline_done"] = 0
        processing_state["current_file"] = filename
        try:
            db.upsert_file(filename)
            emit(f"FILE {filename}")
            emit("  Source: manual metadata")
            result = file_scene_from_match(video, scene, source="Manual")
            emit(f"  Result: {result.get('status')}")
        except Exception as e:
            emit(f"  ERROR: {e}")
            db.update_file(filename, status="error", error=str(e))
        finally:
            processing_state["running"] = False
            processing_state["current_file"] = None
            processing_state["pipeline_total"] = 0
            processing_state["pipeline_done"] = 0
            emit("---")

    background_tasks.add_task(run)
    return {"started": True, "filename": filename}


@app.get("/api/queue/file-mtime")
async def queue_file_mtime(filename: str):
    """Return the mtime of a source-dir file as YYYY-MM-DD so the Vice
    modal can prepopulate its date field with the video's creation date.
    Falls back to today's date if the file isn't found."""
    settings = db.get_settings()
    source_dir = Path(settings.get("source_dir", ""))
    p = source_dir / filename
    try:
        if p.is_file():
            return {"date": datetime.fromtimestamp(p.stat().st_mtime).strftime("%Y-%m-%d")}
    except OSError:
        pass
    return {"date": datetime.now().strftime("%Y-%m-%d")}


@app.get("/api/queue/file-probe")
async def queue_file_probe(filename: str):
    """Lightweight metadata probe for a queue file. Used by the Scene
    Search modal header to surface resolution + duration so the user
    can sanity-check what they're matching against. Two ffprobe
    invocations: one for the first video stream's codec/dimensions
    (`probe_video_stream_meta`) and one for duration
    (`get_video_duration`). Both already exist as helpers; this just
    wraps them in a JSON response. Errors are swallowed and reported
    as `null` so the modal can render "Unknown" gracefully."""
    settings = db.get_settings()
    source_dir = Path(settings.get("source_dir", ""))
    video = db.resolve_source_video_path(source_dir, filename)
    if video is None or not video.is_file():
        return JSONResponse({"error": "File not found"}, status_code=404)

    codec = width = height = None
    try:
        codec, width, height = await run_in_threadpool(probe_video_stream_meta, video)
    except Exception:
        pass

    duration_s: float | None = None
    try:
        duration_s = await run_in_threadpool(get_video_duration, video)
    except Exception:
        pass

    return {
        "filename": filename,
        "codec":    codec,
        "width":    width,
        "height":   height,
        "duration": duration_s,
        "size_mb":  round(video.stat().st_size / 1024 / 1024, 1),
    }


@app.post("/api/file/manual/vice")
async def file_manual_vice(payload: dict, background_tasks: BackgroundTasks):
    """Manually file a queued scene into the chosen Vice's folder.

    Bypasses studio/performer routing entirely — the Vice is treated
    like a studio for NFO generation (show_title = vice name, season =
    scene year, episode = MMDD) but the destination path is forced to
    `<vices_dir>/<vice_name>/Season YYYY/...`.

    Required fields: filename, vice_name, title, date (YYYY-MM-DD).
    Optional: performers (comma-separated), image_url, thumb_data_url.
    """
    if processing_state["running"]:
        return JSONResponse({"error": "Pipeline already running"}, status_code=409)

    filename       = (payload.get("filename") or "").strip()
    vice_name      = (payload.get("vice_name") or "").strip()
    title          = (payload.get("title") or "").strip()
    date           = (payload.get("date") or "").strip()
    performers     = (payload.get("performers") or "").strip()
    image_url      = (payload.get("image_url") or "").strip()
    thumb_data_url = (payload.get("thumb_data_url") or "").strip()

    if not all([filename, vice_name, title, date]):
        return JSONResponse(
            {"error": "filename, vice_name, title and date are required"},
            status_code=400,
        )

    settings = db.get_settings()
    vices_dir_raw = (settings.get("vices_dir") or "").strip()
    if not vices_dir_raw:
        return JSONResponse(
            {"error": "Vices Library Directory not configured"},
            status_code=400,
        )

    # Verify the chosen vice exists in the user's list.
    if not any((v.get("name") or "").strip().lower() == vice_name.lower() for v in _load_vices()):
        return JSONResponse({"error": f"Vice '{vice_name}' not found"}, status_code=404)

    source_dir = Path(settings.get("source_dir", ""))
    video = source_dir / filename
    if not video.exists():
        return JSONResponse({"error": f"File not found: {filename}"}, status_code=404)

    perf_list = [p.strip() for p in performers.split(",") if p.strip()]
    scene = {
        "title":           title,
        "release_date":    date,
        "studio":          {"name": vice_name},  # show_title on the NFO
        "performers":      [{"performer": {"name": n, "gender": ""}} for n in perf_list],
        "images":          [{"url": image_url, "width": 0, "height": 0}] if image_url else [],
        "_thumb_data_url": thumb_data_url,
        "_force_vice":     vice_name,  # overrides all studio/performer routing
    }

    def run():
        processing_state["running"] = True
        processing_state["log"] = []
        processing_state["pipeline_total"] = 1
        processing_state["pipeline_done"] = 0
        processing_state["current_file"] = filename
        try:
            db.upsert_file(filename)
            emit(f"FILE {filename}")
            emit(f"  Source: manual vice → {vice_name}")
            result = file_scene_from_match(video, scene, source="Manual")
            emit(f"  Result: {result.get('status')}")
        except Exception as e:
            emit(f"  ERROR: {e}")
            db.update_file(filename, status="error", error=str(e))
        finally:
            processing_state["running"] = False
            processing_state["current_file"] = None
            processing_state["pipeline_total"] = 0
            processing_state["pipeline_done"] = 0
            emit("---")

    background_tasks.add_task(run)
    return {"started": True, "filename": filename, "vice": vice_name}


def _ensure_parsed_filename(
    filename: str,
    settings: dict,
    source_dir: Path,
    *,
    force: bool = False,
) -> dict:
    """Return cached filename-parser output for ``filename``, parsing
    on first call and stashing the result on the ``processed_files``
    row so subsequent reads are zero-cost.

    Set ``force=True`` to bypass the cache (e.g. after the user edits
    their parser settings).
    """
    if not filename:
        return {}
    if not force:
        cached = db.get_parsed_meta(filename)
        if cached is not None:
            return cached
    result = parse_filename(filename, settings)
    try:
        src = source_dir / filename
        if src.is_file():
            import datetime as _dt
            result["file_mtime"] = _dt.date.fromtimestamp(
                src.stat().st_mtime
            ).isoformat()
    except Exception:
        pass
    result["parsed_at"] = datetime.now(timezone.utc).isoformat()
    try:
        db.set_parsed_meta(filename, result)
    except Exception as exc:
        emit(f"parsed-meta cache write failed for {filename}: {exc}")
    return result


@app.get("/api/parse/filename")
async def parse_filename_endpoint(filename: str, refresh: int = 0):
    """Parse a filename and return extracted metadata fields.

    Backed by ``_ensure_parsed_filename`` so repeat reads (manual
    search modal, suggestions modal, scene search) all hit the cached
    JSON on the ``processed_files`` row instead of re-running the
    regex pipeline + file-stat on every request.

    Pass ``?refresh=1`` to bypass the cache after editing parser
    patterns or rename-map settings.
    """
    settings = db.get_settings()
    source_dir = Path(settings.get("source_dir", ""))
    return _ensure_parsed_filename(
        filename, settings, source_dir, force=bool(refresh)
    )


@app.get("/api/queue/match-scene")
async def queue_match_scene(filename: str):
    """
    For a queue file that has already been matched against a stash-box
    database, return the full scene detail (description, image URLs,
    performer list) so the manual-filing modal can pre-populate.

    Returns `{"found": False}` if no prior match is stored or the
    configured API key can't reach the scene.
    """
    fname = (filename or "").strip()
    if not fname:
        return {"found": False, "error": "filename required"}
    hist = db.get_history(limit=10000)
    pf = next((r for r in hist if r.get("filename") == fname), None)
    if not pf:
        return {"found": False}
    scene, label = _fetch_scene_for_processed_row(pf)
    if not scene:
        return {"found": False, "source": _stashbox_normalize_match_source(pf.get("match_source") or "")}
    images = scene.get("images") or []
    image_url = ""
    if images:
        best = max(images, key=lambda im: (im.get("width") or 0) * (im.get("height") or 0))
        image_url = best.get("url") or ""
    perfs = []
    for p in (scene.get("performers") or []):
        perf = (p or {}).get("performer") or {}
        nm = (perf.get("name") or "").strip()
        if nm:
            perfs.append(nm)
    studio_name = ((scene.get("studio") or {}).get("name") or "").strip()
    return {
        "found": True,
        "source": label,
        "source_tag": _api_source_tag(pf.get("match_source") or "") or "",
        "external_id": str(scene.get("id") or ""),
        "title": scene.get("title") or "",
        "date": scene.get("release_date") or "",
        "studio": studio_name,
        "performers": perfs,
        "description": scene.get("details") or "",
        "image_url": image_url,
    }


# ---------------------------------------------------------------------------
# Library issue finder
# ---------------------------------------------------------------------------

NFO_SKIP = {"tvshow.nfo", "season.nfo", "season-all.nfo", "season-specials.nfo"}


def _folder_has_any_video_recursive(dir_path: Path) -> bool:
    try:
        for _dp, _dn, fnames in os.walk(dir_path):
            for f in fnames:
                if Path(f).suffix.lower() in VIDEO_EXTENSIONS:
                    return True
    except OSError:
        pass
    return False


def _folder_has_tvshow_nfo(dir_path: Path) -> bool:
    """Jellyfin/Kodi-style show folder: tvshow.nfo at the show root (case-insensitive)."""
    try:
        for child in dir_path.iterdir():
            if child.is_file() and child.name.lower() == "tvshow.nfo":
                return True
    except OSError:
        pass
    return False


def _scan_performer_series_show_folder_issues(settings_dict: dict) -> tuple[list[str], list[str]]:
    """Immediate subfolders under Series dir + performer library roots:
    (no tvshow.nfo, no video anywhere under folder).
    """
    no_tvshow: list[str] = []
    no_video: list[str] = []
    seen_show_roots: set[str] = set()
    bases: list[Path] = []
    sd = (settings_dict.get("series_dir") or "").strip()
    if sd:
        bases.append(Path(sd))
    for row in db.get_directories("performer"):
        raw = (row.get("path") or "").strip()
        if raw:
            bases.append(Path(raw))
    for base in bases:
        try:
            br = base.expanduser().resolve()
        except OSError:
            br = base.expanduser()
        key = str(br)
        if key in seen_show_roots:
            continue
        seen_show_roots.add(key)
        if not br.is_dir():
            continue
        try:
            children = sorted(br.iterdir(), key=lambda p: p.name.lower())
        except OSError:
            continue
        for child in children:
            if not child.is_dir() or child.name.startswith("."):
                continue
            try:
                cpath = str(child.resolve())
            except OSError:
                cpath = str(child)
            if not _folder_has_tvshow_nfo(child):
                no_tvshow.append(cpath)
            if not _folder_has_any_video_recursive(child):
                no_video.append(cpath)
    return sorted(set(no_tvshow)), sorted(set(no_video))


def scan_library_issues(root_dirs: list[str], movie_dirs: list[str] = None) -> dict:
    """
    Scan library directories for common issues:
    - NFO without matching video
    - Video without NFO
    - Performer / Series show folders missing tvshow.nfo
    - Performer / Series show folders with no videos anywhere underneath

    movie_dirs: library roots where each *immediate* subfolder is a movie folder
    (typically ``features_dir``). For those folders only:
    a video is satisfied if ``movie.nfo`` exists or a same-stem ``.nfo`` exists.
    All other roots use scene/episode rules: only a same-stem ``.nfo`` beside the video.
    """
    issues = {
        "nfo_no_video": [],
        "video_no_nfo": [],
        "folder_no_tvshow_nfo": [],
        "empty_folder": [],
        # Retained empty so older cached scans deserialize; always empty.
        "missing_thumb": [],
    }

    movie_dir_set = set(str(Path(d)) for d in (movie_dirs or []) if d)

    for root_dir in root_dirs:
        base = Path(root_dir)
        if not base.exists():
            continue

        is_movie_root = str(base) in movie_dir_set

        for dirpath, dirnames, filenames in os.walk(base):
            dp = Path(dirpath)
            videos = [f for f in filenames if Path(f).suffix.lower() in VIDEO_EXTENSIONS]
            nfos = [f for f in filenames if f.endswith(".nfo") and f.lower() not in NFO_SKIP]

            # Movie folder logic - one level below the movie root
            if is_movie_root and dp.parent == base:
                for video in videos:
                    stem = Path(video).stem
                    # Accept: matching name NFO or movie.nfo
                    has_nfo = f"{stem}.nfo" in filenames or "movie.nfo" in filenames
                    if not has_nfo:
                        issues["video_no_nfo"].append(str(dp / video))
                for nfo in nfos:
                    if nfo.lower() == "movie.nfo":
                        continue
                    stem = Path(nfo).stem
                    if not any(Path(v).stem == stem for v in videos):
                        issues["nfo_no_video"].append(str(dp / nfo))
                continue

            # Standard scene library logic
            for nfo in nfos:
                stem = Path(nfo).stem
                if not any(Path(v).stem == stem for v in videos):
                    issues["nfo_no_video"].append(str(dp / nfo))

            for video in videos:
                stem = Path(video).stem
                if f"{stem}.nfo" not in filenames:
                    issues["video_no_nfo"].append(str(dp / video))

    s = db.get_settings()
    show_no_nfo, show_no_vid = _scan_performer_series_show_folder_issues(s)
    issues["folder_no_tvshow_nfo"] = show_no_nfo
    issues["empty_folder"] = show_no_vid

    return {k: sorted(v) for k, v in issues.items()}


# ---------------------------------------------------------------------------
# Library health helpers (indexed files, tree, duplicate phash)
# ---------------------------------------------------------------------------


def _health_library_roots(settings: dict | None = None) -> list[dict]:
    """Configured library roots for Health scope, stats, and path checks.

    Includes the Vices library directory so Health actions (delete, dedup,
    recreate-metadata, etc.) on files inside a Vice folder pass the
    `_health_assert_path_under_roots` gate — without this entry the gate
    rejects any `/library/Vices/<name>/…` path with "Path is not under a
    configured library directory" even though the user's vices_dir setting
    is configured.
    """
    s = settings if settings is not None else db.get_settings()
    out: list[dict] = []
    sd = (s.get("series_dir") or "").strip()
    if sd:
        rp = str(Path(sd).expanduser())
        out.append({"key": "series", "path": rp, "label": "Series"})
    fd = (s.get("features_dir") or "").strip()
    if fd:
        rp = str(Path(fd).expanduser())
        out.append({"key": "features", "path": rp, "label": "Features"})
    vd = (s.get("vices_dir") or "").strip()
    if vd:
        rp = str(Path(vd).expanduser())
        out.append({"key": "vices", "path": rp, "label": "Vices"})
    jd = (s.get("jav_dir") or "").strip()
    if jd:
        rp = str(Path(jd).expanduser())
        out.append({"key": "jav", "path": rp, "label": "JAV"})
    for row in db.get_directories("performer"):
        p = (row.get("path") or "").strip()
        if not p:
            continue
        lbl = (row.get("label") or "Performers").strip() or "Performers"
        rid = row.get("id")
        out.append({
            "key": f"performer:{rid}" if rid is not None else f"performer:{len(out)}",
            "path": str(Path(p).expanduser()),
            "label": lbl,
        })
    return out


def _health_resolve_library_root_for_path(abs_path: Path, roots: list[dict]) -> str:
    """Return the configured root path string that should own ``abs_path``.

    Must match the ``path`` values from ``_health_library_roots`` (expanduser,
    not necessarily resolve) so ``library_files_count_for_root`` and the
    Health tree agree with ``library_files.library_root``. Longest-prefix
    resolution uses resolved paths only for containment checks.
    """
    try:
        ap = abs_path.resolve()
    except OSError:
        ap = abs_path.expanduser()
    best_key = ""
    best_len = -1
    for r in roots:
        key = str(Path(r["path"]).expanduser())
        try:
            base = Path(r["path"]).expanduser().resolve()
        except OSError:
            base = Path(r["path"]).expanduser()
        try:
            ap.relative_to(base)
            sl = len(str(base))
            if sl > best_len:
                best_len = sl
                best_key = key
        except ValueError:
            continue
    return best_key


def _health_nested_root_prefixes_inside(
    parent_path: str, all_roots: list[dict]
) -> list[str]:
    """Configured library roots strictly inside parent_path (for root-level video counts)."""
    try:
        parent = Path(parent_path).expanduser().resolve()
    except OSError:
        parent = Path(parent_path).expanduser()
    out: list[str] = []
    for r in all_roots or []:
        rp = (r.get("path") or "").strip()
        if not rp:
            continue
        try:
            other = Path(rp).expanduser().resolve()
        except OSError:
            other = Path(rp).expanduser()
        if other == parent:
            continue
        try:
            other.relative_to(parent)
            out.append(str(other))
        except ValueError:
            continue
    return out


def _health_count_videos_for_tree_root(
    root_path: str,
    all_roots: list[dict],
    scope_prefix: str | None = None,
) -> int:
    """Videos indexed under this library root by destination path (robust vs library_root column)."""
    nested = _health_nested_root_prefixes_inside(root_path, all_roots)
    return db.library_files_count_under_destination(
        root_path,
        scope_prefix=scope_prefix,
        exclude_destination_prefixes=nested,
    )


def _health_enumerate_videos_under_roots(
    roots: list[dict],
    on_video: Callable[[int, str], None] | None = None,
    *,
    prune_basenames: frozenset[str] | None = None,
) -> list[tuple[str, Path]]:
    """
    Pairs of (library_root path string, video Path).
    Uses os.scandir. Skips descending into prune_basenames (dir basenames, lowercased),
    like find -prune. Optional on_video(n, path_str) throttled for UI progress.

    Symlinked directories ARE followed (libraries often live on a
    different mount with the library root symlinked into place, e.g.
    /home/user/JAV → /mnt/big/jav). To guard against cyclic symlinks,
    track each directory's resolved path in ``visited_dirs`` and skip
    repeats.
    """
    prune = (
        prune_basenames
        if prune_basenames is not None
        else _library_walk_prune_basenames(None)
    )
    found: list[tuple[str, Path]] = []
    seen_rp: set[str] = set()
    visited_dirs: set[str] = set()
    last_pstr = ""
    ev = _LIBRARY_WALK_PROGRESS_EVERY

    def maybe_tick(n: int, pstr: str) -> None:
        nonlocal last_pstr
        last_pstr = pstr
        if not on_video:
            return
        if n == 1 or (ev > 0 and n % ev == 0):
            on_video(n, pstr)

    def _resolved_key(p: Path) -> str:
        try:
            return str(p.resolve(strict=False))
        except OSError:
            return str(p)

    for r in roots:
        key = r["path"]
        if key in seen_rp:
            continue
        seen_rp.add(key)
        base = Path(key)
        if not base.is_dir():
            continue
        # Seed the visited set with the root's real path so a symlink
        # *into* the root (or sibling root pointing at the same disk
        # location) does not cause a re-walk.
        base_real = _resolved_key(base)
        if base_real in visited_dirs:
            continue
        visited_dirs.add(base_real)
        stack: list[Path] = [base]
        try:
            while stack:
                cur = stack.pop()
                try:
                    with os.scandir(cur) as it:
                        for entry in it:
                            try:
                                # Follow symlinked dirs: a real `JAV/`
                                # tree often mounts in via a symlink.
                                # `follow_symlinks=True` is the default
                                # for is_dir, but spelled out here for
                                # clarity vs the file branch below.
                                if entry.is_dir(follow_symlinks=True):
                                    if entry.name.lower() in prune:
                                        continue
                                    real = _resolved_key(Path(entry.path))
                                    if real in visited_dirs:
                                        continue
                                    visited_dirs.add(real)
                                    stack.append(Path(entry.path))
                                elif entry.is_file(follow_symlinks=True) and _is_video_filename(
                                    entry.name
                                ):
                                    vpath = Path(entry.path)
                                    found.append((key, vpath))
                                    maybe_tick(len(found), str(vpath))
                            except OSError:
                                continue
                except OSError:
                    continue
        except OSError:
            continue

    if on_video and found:
        on_video(len(found), last_pstr or str(found[-1][1]))

    return found


def _health_library_file_row_for_destination(path_str: str) -> dict | None:
    """Resolve a ``library_files`` row when the caller's path string may not
    exactly match the stored ``destination`` (expanduser / resolve variants).
    """
    ps = (path_str or "").strip()
    if not ps:
        return None
    variants: list[str] = [ps]
    p = Path(ps).expanduser()
    variants.append(str(p))
    try:
        variants.append(str(p.resolve()))
    except OSError:
        pass
    seen: set[str] = set()
    for v in variants:
        v = (v or "").strip()
        if not v or v in seen:
            continue
        seen.add(v)
        row = db.library_file_get_by_destination(v)
        if row:
            return row
    return None


def _health_assert_path_under_roots(path_str: str, roots: list[dict]) -> Path:
    p = Path(path_str).expanduser()
    try:
        rp = p.resolve()
    except OSError:
        rp = p
    for r in roots:
        try:
            base = Path(r["path"]).expanduser().resolve()
        except OSError:
            base = Path(r["path"]).expanduser()
        try:
            rp.relative_to(base)
            return rp
        except ValueError:
            continue
    # Indexed files may still sit under the ``library_root`` string that was
    # recorded when Library Index ran, even if Series / performer paths in
    # Settings were later renamed or the bind mount moved (same data, new
    # prefix). Without this fallback, duplicate resolve and delete-video
    # reject paths that are no longer under *current* roots but are still
    # valid index rows.
    row = _health_library_file_row_for_destination(path_str)
    if row:
        lr_raw = (row.get("library_root") or "").strip()
        if lr_raw:
            try:
                lr_base = Path(lr_raw).expanduser().resolve()
            except OSError:
                lr_base = Path(lr_raw).expanduser()
            try:
                rp.relative_to(lr_base)
                return rp
            except ValueError:
                pass
    raise ValueError("Path is not under a configured library directory")


def _health_register_filed_scene(filename: str, destination: str) -> None:
    try:
        settings = db.get_settings()
        roots = _health_library_roots(settings)
        dest_p = Path(destination).expanduser()
        try:
            dest_res = str(dest_p.resolve())
        except OSError:
            dest_res = str(dest_p)
        lr = _health_resolve_library_root_for_path(dest_p, roots)
        ph = db.get_phash(filename)
        pid = db.get_processed_file_id_by_filename(filename)
        db.library_file_upsert_from_pipeline(
            destination=dest_res,
            current_filename=dest_p.name,
            filename_stem=dest_p.stem,
            library_root=lr,
            source_record_id=pid,
            phash_1=ph,
        )
    except Exception as e:
        emit(f"  Library file index: {e}")


def _health_register_filed_movie(destination: str, phash_val: str | None) -> None:
    try:
        settings = db.get_settings()
        roots = _health_library_roots(settings)
        dest_p = Path(destination).expanduser()
        try:
            dest_res = str(dest_p.resolve())
        except OSError:
            dest_res = str(dest_p)
        lr = _health_resolve_library_root_for_path(dest_p, roots)
        db.library_file_upsert_from_movie_filing(
            destination=dest_res,
            current_filename=dest_p.name,
            filename_stem=dest_p.stem,
            library_root=lr,
            phash_1=phash_val,
        )
    except Exception as e:
        emit(f"  Library file index (movie): {e}")


def _health_library_phash_status(row: dict) -> dict:
    return {
        "has_1": bool((row.get("phash_1") or "").strip()),
        "has_2": bool((row.get("phash_2") or "").strip()),
        "has_3": bool((row.get("phash_3") or "").strip()),
    }


def _health_library_leaf_payload(row: dict) -> dict | None:
    dest_s = (row.get("destination") or "").strip()
    lr = (row.get("library_root") or "").strip()
    if not dest_s or not lr:
        return None
    dest_p = Path(dest_s)
    try:
        sz = dest_p.stat().st_size
    except OSError:
        sz = None
    phs = _health_library_phash_status(row)
    return {
        "name": dest_p.name,
        "destination": dest_s,
        "size": sz,
        "phash": phs,
        "phash_any": phs["has_1"] or phs["has_2"] or phs["has_3"],
        "codec": ((row.get("media_codec") or "").strip()),
        "width": row.get("media_width"),
        "height": row.get("media_height"),
        "file_created": ((row.get("file_created_iso") or "").strip()),
        "has_nfo": _health_video_has_sidecar_nfo(dest_p, lr),
    }


def _health_build_tree_roots_payload(scope_prefix: str | None) -> dict:
    """Library roots only; folder contents load on expand via /api/health/tree-node."""
    roots_order = _health_library_roots()
    sp_for_db: str | None = scope_prefix
    if scope_prefix:
        sp = os.path.normpath(scope_prefix.strip().rstrip(os.sep))
        roots_order = [
            r
            for r in roots_order
            if os.path.normpath(str(r.get("path") or "").rstrip(os.sep)) == sp
        ]
        # Destinations in library_files are stored resolved (symlinks followed),
        # so the scope LIKE prefix must also be resolved or a symlinked root
        # (e.g. /library/JAV -> /mnt/big/jav) excludes every row.
        try:
            sp_for_db = str(Path(scope_prefix).expanduser().resolve())
        except OSError:
            sp_for_db = scope_prefix
    forest = []
    for meta in sorted(roots_order, key=lambda x: str(x.get("path") or "").lower()):
        rk = str(meta["path"])
        cnt = _health_count_videos_for_tree_root(rk, roots_order, sp_for_db)
        forest.append(
            {
                "type": "dir",
                "name": Path(rk).name,
                "path": rk,
                "file_count": cnt,
                "children": [],
                "leaves": [],
                "depth": 0,
                "lazy": cnt > 0,
                "label": meta.get("label") or Path(rk).name,
                "key": meta.get("key") or "",
            }
        )
    return {"roots": forest}


def _health_expand_tree_node(dir_path: str, scope_prefix: str | None) -> dict:
    settings = db.get_settings()
    roots = _health_library_roots(settings)
    raw = (dir_path or "").strip()
    if not raw:
        return {"error": "path required"}
    path_p = Path(raw).expanduser()
    try:
        resolved = str(path_p.resolve())
    except OSError:
        resolved = str(path_p)
    lr_str = _health_resolve_library_root_for_path(path_p, roots)
    if not lr_str:
        return {"error": "Not under a configured library root"}
    sp_for_db: str | None = scope_prefix
    if scope_prefix:
        try:
            sp_for_db = str(Path(scope_prefix).expanduser().resolve())
        except OSError:
            sp_for_db = scope_prefix
    try:
        leaf_rows, subdir_pairs = db.library_files_expand_dir_by_destination(
            dir_path=resolved,
            scope_prefix=sp_for_db,
        )
    except Exception as e:
        return {"error": str(e)}
    try:
        rel = Path(resolved).relative_to(Path(lr_str))
        depth_base = len(rel.parts)
    except ValueError:
        depth_base = 0
    children = []
    for name, fc in sorted(subdir_pairs, key=lambda x: x[0].lower()):
        cp = str(Path(resolved) / name)
        children.append(
            {
                "type": "dir",
                "name": name,
                "path": cp,
                "file_count": fc,
                "children": [],
                "leaves": [],
                "depth": depth_base + 1,
                "lazy": fc > 0,
            }
        )
    leaves: list[dict] = []
    for r in leaf_rows:
        leaf = _health_library_leaf_payload(r)
        if not leaf:
            continue
        # Stash the row's phashes so we can bulk-look-up scene matches
        # (StashDB / TPDB / FansDB scene IDs) below in a single query.
        leaf["_phashes"] = [
            (r.get("phash_1") or "").strip().lower(),
            (r.get("phash_2") or "").strip().lower(),
            (r.get("phash_3") or "").strip().lower(),
        ]
        leaves.append(leaf)
    all_phashes: list[str] = []
    for leaf in leaves:
        for p in leaf.get("_phashes") or []:
            if p:
                all_phashes.append(p)
    matches_by_phash = (
        db.scene_fingerprints_match_phashes(all_phashes) if all_phashes else {}
    )
    for leaf in leaves:
        seen: set[tuple[str, str]] = set()
        out_matches: list[dict] = []
        for p in leaf.pop("_phashes", []) or []:
            if not p:
                continue
            for m in matches_by_phash.get(p, []) or []:
                src = (m.get("source") or "").lower()
                sid = (m.get("scene_id") or "").strip()
                if not src or not sid:
                    continue
                key = (src, sid)
                if key in seen:
                    continue
                seen.add(key)
                if src == "stashdb":
                    url = f"https://stashdb.org/scenes/{sid}"
                elif src == "tpdb":
                    url = f"https://theporndb.net/scenes/{sid}"
                elif src == "fansdb":
                    url = f"https://fansdb.cc/scenes/{sid}"
                else:
                    continue
                out_matches.append({"source": src, "scene_id": sid, "url": url})
        leaf["matches"] = out_matches
    return {
        "path": resolved,
        "library_root": lr_str,
        "children": children,
        "leaves": leaves,
    }


def _health_library_stats_payload() -> dict:
    """Per-root video count + total size under every library root.

    Uses the same ``os.scandir`` stack walker pattern as
    ``_dir_tree_size_bytes`` — avoids ``os.walk`` + ``Path.stat`` per
    file, which is GC-heavy and much slower on big libraries.
    """
    roots = _health_library_roots()
    root_stats: list[dict] = []
    total_c = 0
    total_sz = 0
    for r in roots:
        c = 0
        sz = 0
        base = Path(r["path"])
        if base.is_dir():
            stack: list[str] = [str(base)]
            while stack:
                d = stack.pop()
                try:
                    with os.scandir(d) as it:
                        for e in it:
                            try:
                                if e.is_dir(follow_symlinks=False):
                                    stack.append(e.path)
                                elif e.is_file(follow_symlinks=False):
                                    # Suffix check on the raw name is
                                    # cheaper than wrapping in Path().
                                    dot = e.name.rfind(".")
                                    if dot < 0:
                                        continue
                                    if e.name[dot:].lower() not in VIDEO_EXTENSIONS:
                                        continue
                                    c += 1
                                    sz += e.stat(follow_symlinks=False).st_size
                            except OSError:
                                pass
                except OSError:
                    pass
        total_c += c
        total_sz += sz
        root_stats.append({
            "key": r["key"],
            "path": r["path"],
            "label": r["label"],
            "count": c,
            "size_bytes": sz,
        })
    return {
        "roots": root_stats,
        "total_count": total_c,
        "total_size_bytes": total_sz,
    }


def _format_bytes_pretty(n: int) -> str:
    """Human-readable byte size for UI (B through TB)."""
    n = max(0, int(n))
    if n < 1024:
        return f"{n} B"
    v = float(n) / 1024.0
    for unit in ("KB", "MB", "GB", "TB"):
        if v < 1024.0 or unit == "TB":
            if unit == "KB":
                return f"{v:.1f} {unit}"
            if unit in ("GB", "TB"):
                return f"{v:.2f} {unit}"
            return f"{v:.1f} {unit}"
        v /= 1024.0
    return f"{v:.2f} TB"


def _dir_tree_size_bytes(root: Path) -> int:
    """Recursive sum of file sizes under a directory.

    Uses an explicit ``os.scandir`` stack instead of ``os.walk`` so we
    can read each entry's size off the DirEntry's cached stat (saves
    one syscall per file vs. a fresh ``Path(...).stat()``). Big wins
    on libraries with tens of thousands of files — the old walker was
    blocking the request long enough to stall /health's event loop.
    """
    if not root.is_dir():
        return 0
    total = 0
    stack: list[str] = [str(root)]
    while stack:
        d = stack.pop()
        try:
            with os.scandir(d) as it:
                for e in it:
                    try:
                        if e.is_file(follow_symlinks=False):
                            # DirEntry.stat() caches the result from
                            # readdir on Linux/macOS — much cheaper
                            # than re-stat'ing a Path.
                            total += e.stat(follow_symlinks=False).st_size
                        elif e.is_dir(follow_symlinks=False):
                            stack.append(e.path)
                    except OSError:
                        pass
        except OSError:
            pass
    return total


def _health_library_disk_usage_payload(include_keys: set[str] | None = None) -> dict:
    """
    Full-disk usage under configured library roots (all files, not only videos).
    Pie slices = configured roots (Series, Features, each performer root).
    Top entities = largest immediate subfolders under Series (studios), Features (movies),
    and each performer root (performers).

    include_keys: if non-empty, only these root keys are measured (matched against ``key``
    from ``_health_library_roots``). Empty or None means all roots.
    """
    all_roots_list = _health_library_roots()
    all_roots_meta = [
        {"key": r["key"], "label": r["label"], "path": r["path"]}
        for r in all_roots_list
    ]
    if include_keys is not None and len(include_keys) > 0:
        roots_cfg = [r for r in all_roots_list if r["key"] in include_keys]
    else:
        roots_cfg = list(all_roots_list)

    cfg_keys = {r["key"] for r in roots_cfg}

    root_slices: list[dict] = []
    total_bytes = 0
    for r in roots_cfg:
        p = Path(r["path"])
        b = _dir_tree_size_bytes(p)
        total_bytes += b
        root_slices.append({
            "key": r["key"],
            "label": r["label"],
            "path": r["path"],
            "bytes": b,
            "pretty": _format_bytes_pretty(b),
        })

    entity_rows: list[dict] = []
    s = db.get_settings()

    def push_child(base: Path, child_name: str, kind: str, parent_label: str) -> None:
        cpath = base / child_name
        if not cpath.is_dir():
            return
        b = _dir_tree_size_bytes(cpath)
        entity_rows.append({
            "name": child_name,
            "kind": kind,
            "path": str(cpath),
            "bytes": b,
            "pretty": _format_bytes_pretty(b),
            "parent_label": parent_label,
        })

    if "series" in cfg_keys:
        sd = (s.get("series_dir") or "").strip()
        if sd:
            base = Path(sd).expanduser()
            if base.is_dir():
                try:
                    with os.scandir(base) as it:
                        for e in it:
                            if e.is_dir(follow_symlinks=False):
                                push_child(base, e.name, "studio", "Series")
                except OSError:
                    pass

    if "features" in cfg_keys:
        fd = (s.get("features_dir") or "").strip()
        if fd:
            base = Path(fd).expanduser()
            if base.is_dir():
                try:
                    with os.scandir(base) as it:
                        for e in it:
                            if e.is_dir(follow_symlinks=False):
                                push_child(base, e.name, "movie", "Movies")
                except OSError:
                    pass

    for r in roots_cfg:
        rk = str(r.get("key") or "")
        if not rk.startswith("performer:"):
            continue
        plabel = (r.get("label") or "Performers").strip() or "Performers"
        base = Path((r.get("path") or "").strip()).expanduser()
        if not base.is_dir():
            continue
        try:
            with os.scandir(base) as it:
                for e in it:
                    if e.is_dir(follow_symlinks=False):
                        push_child(base, e.name, "performer", plabel)
        except OSError:
            pass

    entity_rows.sort(key=lambda x: x["bytes"], reverse=True)
    top10 = entity_rows[:10]

    return {
        "total_bytes": total_bytes,
        "total_pretty": _format_bytes_pretty(total_bytes),
        "roots": root_slices,
        "all_roots": all_roots_meta,
        "top_entities": top10,
    }


def _performer_poster_url_from_detail(data: dict) -> str | None:
    posters = data.get("posters") or []
    if not posters:
        return None
    p0 = posters[0]
    if isinstance(p0, dict):
        return (p0.get("url") or "").strip() or None
    if isinstance(p0, str):
        return p0.strip() or None
    return None


def _studio_poster_url_for_tvshow(data: dict, source: str) -> str | None:
    if source == "TPDB":
        u = _tpdb_scalar_media_url(data.get("poster"))
        if u:
            return u
        u = _tpdb_site_image_url(data)
        if u:
            return u
        return _tpdb_scalar_media_url(data.get("logo"))
    return best_image_url(data.get("images") or []) or best_studio_image_url(
        data.get("images") or []
    )


def _favourite_fetch_detail_for_tvshow(kind: str, row: dict) -> tuple[dict | None, str]:
    """Try TPDB → StashDB → FansDB → JAVStash IDs from index; return (detail_dict, source_used)."""
    tries: list[tuple[str, str]] = []
    if (row.get("match_tpdb_id") or "").strip():
        tries.append(("TPDB", row["match_tpdb_id"].strip()))
    if (row.get("match_stashdb_id") or "").strip():
        tries.append(("StashDB", row["match_stashdb_id"].strip()))
    if (row.get("match_fansdb_id") or "").strip():
        tries.append(("FansDB", row["match_fansdb_id"].strip()))
    if (row.get("match_javstash_id") or "").strip():
        tries.append(("JAVStash", row["match_javstash_id"].strip()))
    for src, eid in tries:
        if kind == "performer":
            data = fetch_performer_detail(src, eid)
        else:
            data = fetch_studio_detail(src, eid)
        if data:
            return data, src
    return None, ""


def _favourite_group_member_ids(row: dict) -> list[tuple[str, str]]:
    """Flat list of ``(source, external_id)`` for every member of a group
    folder. Combines the row's primary ``match_*_id`` columns with the
    per-source crosswalk lists in ``group_ids_json``. Order is stable
    across calls (TPDB → StashDB → FansDB, primary first then extras)
    and the same source/id pair is never returned twice."""
    out: list[tuple[str, str]] = []
    seen: set[tuple[str, str]] = set()

    def push(src: str, eid: str) -> None:
        eid = (eid or "").strip()
        if not eid:
            return
        key = (src, eid)
        if key in seen:
            return
        seen.add(key)
        out.append(key)

    push("TPDB", row.get("match_tpdb_id") or "")
    push("StashDB", row.get("match_stashdb_id") or "")
    push("FansDB", row.get("match_fansdb_id") or "")

    try:
        raw = json.loads(row.get("group_ids_json") or "{}") or {}
    except Exception:
        raw = {}
    if isinstance(raw, dict):
        for src_key, source_label in (("tpdb", "TPDB"), ("stashdb", "StashDB"), ("fansdb", "FansDB")):
            vals = raw.get(src_key) or []
            if not isinstance(vals, list):
                continue
            for v in vals:
                push(source_label, str(v))
    return out


def _favourite_fetch_group_details_for_tvshow(row: dict) -> list[tuple[dict, str]]:
    """Resolve every performer linked to a group folder. Returns a list
    of ``(data, source)`` pairs, one per successful fetch. Skips members
    whose source returns nothing rather than failing the whole group —
    we want a partial amalgam over no NFO at all."""
    if (row.get("kind") or "").strip() != "performer":
        return []
    members = _favourite_group_member_ids(row)
    out: list[tuple[dict, str]] = []
    for src, eid in members:
        data = fetch_performer_detail(src, eid)
        if data:
            out.append((data, src))
    return out


def build_group_tvshow_nfo(row: dict, members: list[tuple[dict, str]]) -> str:
    """Build a tvshow.nfo for a group folder by amalgamating each
    member performer's metadata. The folder name is used as the show
    title (groups are by definition a custom label, not a single
    performer's canonical name); the plot stitches together each
    performer's bio + key facts under a heading; every member is
    emitted as its own ``<actor>`` block so Kodi / Jellyfin / Plex can
    render the cast pile from a single tvshow.nfo. UIDs combine all
    matched IDs across all members so external linking still works."""
    title = (row.get("folder_name") or "Group").strip() or "Group"
    plot_parts: list[str] = []
    seen_uids: set[tuple[str, str]] = set()
    uid_specs: list[tuple[str, str]] = []
    actors_added: list[tuple[str, str | None, str]] = []  # (name, poster_url, role)

    for data, _src in members:
        perf_name = (data.get("name") or "").strip() or "Unknown"
        extras_flat = _performer_flatten_extras_for_tvshow_nfo(data)
        section: list[str] = [perf_name.upper()]

        bio = (data.get("bio") or data.get("description") or "").strip()
        if bio:
            section.append(bio)

        aliases = _performer_aliases_as_strings(data.get("aliases"))
        if aliases:
            section.append("AKA: " + ", ".join(aliases))

        info_lines: list[str] = []
        for key, label in [
            ("gender", "Gender"),
            ("birthday", "Birthday"),
            ("birthplace", "Birthplace"),
            ("career_start_year", "Active since"),
            ("career_end_year", "Active until"),
            ("ethnicity", "Ethnicity"),
            ("nationality", "Country"),
            ("hair_colour", "Hair"),
            ("hair_color", "Hair"),
            ("height", "Height"),
            ("weight", "Weight"),
            ("measurements", "Measurements"),
            ("breast_type", "Breast type"),
            ("cup_size", "Cup"),
            ("eye_color", "Eyes"),
            ("fake_tits", "Enhanced"),
            ("tattoos", "Tattoos"),
            ("piercings", "Piercings"),
        ]:
            raw_v = extras_flat.get(key)
            if not raw_v:
                continue
            if str(raw_v).lower() in ("true", "false"):
                val = "Yes" if str(raw_v).lower() == "true" else "No"
            else:
                val = raw_v
            line = f"{label}: {val}"
            if line not in info_lines:
                info_lines.append(line)
        if info_lines:
            section.append("\n".join(info_lines))

        url_lines = _performer_external_urls_for_plot(data)
        if url_lines:
            section.append("Links:\n" + "\n".join(url_lines))

        plot_parts.append("\n\n".join(section))

        # Collect uniqueids per member without duplicating across the group.
        tid = str(data.get("_id") or data.get("id") or "").strip()
        if tid and ("theporndb", tid) not in seen_uids:
            seen_uids.add(("theporndb", tid))
            uid_specs.append(("theporndb", tid))
        sid = str(data.get("stash_id") or "").strip()
        if sid and ("stashdb", sid) not in seen_uids:
            seen_uids.add(("stashdb", sid))
            uid_specs.append(("stashdb", sid))
        fid = str(data.get("fansdb_id") or "").strip()
        if fid and ("fansdb", fid) not in seen_uids:
            seen_uids.add(("fansdb", fid))
            uid_specs.append(("fansdb", fid))

        posters = data.get("posters") or []
        poster_url = None
        if posters:
            poster_url = posters[0].get("url") if isinstance(posters[0], dict) else posters[0]
        if isinstance(poster_url, str):
            poster_url = poster_url.strip() or None
        actors_added.append((perf_name, poster_url, _performer_cast_role_from_extras(extras_flat)))

    intro = (
        f"Group folder containing {len(members)} performer"
        f"{'s' if len(members) != 1 else ''}: "
        + ", ".join(name for name, _, _ in actors_added)
    )
    plot_text = intro + ("\n\n" + "\n\n".join(plot_parts) if plot_parts else "")

    root = ET.Element("tvshow")
    ET.SubElement(root, "title").text = title
    ET.SubElement(root, "plot").text = plot_text
    ET.SubElement(root, "mpaa").text = "Adult"
    ET.SubElement(root, "genre").text = "Adult"
    ET.SubElement(root, "tag").text = "Porn"

    for i, (typ, val) in enumerate(uid_specs):
        uid_el = ET.SubElement(root, "uniqueid")
        uid_el.set("type", typ)
        uid_el.set("default", "true" if i == 0 else "false")
        uid_el.text = val

    for order, (name, poster_url, role) in enumerate(actors_added):
        actor = ET.SubElement(root, "actor")
        ET.SubElement(actor, "name").text = name
        role_el = ET.SubElement(actor, "role")
        role_el.text = role
        ET.SubElement(actor, "order").text = str(order)
        if poster_url:
            ET.SubElement(actor, "thumb").text = poster_url

    # Use the earliest career-start across members as the show year so
    # the library sorts the group sensibly. Fall back to a sane default.
    years: list[int] = []
    for data, _src in members:
        extras_flat = _performer_flatten_extras_for_tvshow_nfo(data)
        y = (extras_flat.get("career_start_year") or "").strip()
        if y.isdigit():
            years.append(int(y))
            continue
        bd = (extras_flat.get("birthday") or "")[:4]
        if bd.isdigit():
            years.append(int(bd))
    year = str(min(years)) if years else "2000"
    ET.SubElement(root, "premiered").text = f"{year}-01-01"
    ET.SubElement(root, "year").text = year

    tree = ET.ElementTree(root)
    ET.indent(tree, space="  ")
    buf = io.BytesIO()
    tree.write(buf, encoding="utf-8", xml_declaration=True)
    return buf.getvalue().decode("utf-8")


def _health_maybe_download_show_poster(folder: Path, poster_url: str | None) -> None:
    """Save poster.jpg only when missing; never replace an existing poster."""
    if not poster_url or not str(poster_url).strip():
        return
    dest = folder / "poster.jpg"
    if dest.is_file():
        return
    if download_image(
        str(poster_url).strip(),
        dest,
        max_edge=IMAGE_CACHE_POSTER_MAX,
    ):
        _ensure_library_filed_permissions(dest)


def _health_apply_tvshow_nfo_from_index(folder_raw: str, roots: list[dict]) -> dict:
    """Write tvshow.nfo from favourites index metadata; optional poster.jpg if absent."""
    folder_raw = (folder_raw or "").strip()
    try:
        folder = _health_assert_path_under_roots(folder_raw, roots)
    except ValueError as e:
        return {"ok": False, "path": folder_raw, "error": str(e)}
    if not folder.is_dir():
        return {"ok": False, "path": folder_raw, "error": "Not a directory"}
    row = db.favourite_get_by_path(str(folder))
    if not row:
        return {
            "ok": False,
            "path": folder_raw,
            "error": "No favourites index row for this folder (match it under Favourites first)",
        }
    kind = (row.get("kind") or "").strip()
    if kind not in ("performer", "studio"):
        return {
            "ok": False,
            "path": folder_raw,
            "error": "Indexed entity kind must be performer or studio for tvshow.nfo",
        }
    is_group = bool(row.get("is_group"))
    has_primary_ids = any(
        (row.get(k) or "").strip()
        for k in ("match_tpdb_id", "match_stashdb_id", "match_fansdb_id")
    )
    # Group folders amalgamate metadata across every linked member, so
    # they only need at least one ID *somewhere* (primary OR any of the
    # crosswalk lists in `group_ids_json`). The old check rejected
    # groups whose primary slots were empty even when `group_ids_json`
    # had a full cast list, which is the bug the user hit.
    if is_group and kind == "performer":
        group_members = _favourite_group_member_ids(row)
        if not group_members:
            return {
                "ok": False,
                "path": folder_raw,
                "error": "Group folder has no linked TPDB/StashDB/FansDB IDs (open Favourites and add the members)",
            }
        details = _favourite_fetch_group_details_for_tvshow(row)
        if not details:
            return {
                "ok": False,
                "path": folder_raw,
                "error": "Could not load metadata for any of the group's linked IDs",
            }
        nfo = build_group_tvshow_nfo(row, details)
        # Use the first successfully-fetched member's poster as the
        # group's show poster — there's no canonical group image,
        # the folder-name portrait is up to the user.
        poster_url = None
        for data, _src in details:
            poster_url = _performer_poster_url_from_detail(data)
            if poster_url:
                break
        target = folder / "tvshow.nfo"
        target.write_text(nfo, encoding="utf-8")
        _ensure_library_filed_permissions(target)
        _health_maybe_download_show_poster(folder, poster_url)
        trigger_media_scans()
        return {
            "ok": True,
            "path": folder_raw,
            "nfo": str(target),
            "group_member_count": len(details),
        }
    if not has_primary_ids:
        return {
            "ok": False,
            "path": folder_raw,
            "error": "No TPDB/StashDB/FansDB match IDs stored for this folder",
        }
    data, src = _favourite_fetch_detail_for_tvshow(kind, row)
    if not data:
        return {
            "ok": False,
            "path": folder_raw,
            "error": "Could not load metadata for stored match IDs",
        }
    if kind == "performer":
        nfo = build_performer_tvshow_nfo(data)
        poster_url = _performer_poster_url_from_detail(data)
    else:
        nfo = build_studio_tvshow_nfo(data)
        poster_url = _studio_poster_url_for_tvshow(data, src)
    target = folder / "tvshow.nfo"
    target.write_text(nfo, encoding="utf-8")
    _ensure_library_filed_permissions(target)
    _health_maybe_download_show_poster(folder, poster_url)
    trigger_media_scans()
    return {"ok": True, "path": folder_raw, "nfo": str(target)}


def _health_delete_video_and_sidecars(video_path: Path) -> None:
    if not video_path.is_file():
        return
    folder = video_path.parent
    stem = video_path.stem
    for f in sorted(folder.iterdir()):
        if not f.is_file():
            continue
        if f.stem == stem:
            try:
                f.unlink()
            except OSError:
                pass


def run_library_index_job() -> None:
    if not _library_index_sema.acquire(blocking=False):
        emit("LIBRARY INDEX skipped (already running)")
        return
    try:
        settings = db.get_settings()
        roots = _health_library_roots(settings)
        _library_index_progress_start_walk()
        videos = _health_enumerate_videos_under_roots(
            roots,
            on_video=lambda n, p: _library_index_progress_walk_tick(n, p),
            prune_basenames=_library_walk_prune_basenames(settings),
        )
        # De-dupe by destination and pick ``library_root`` via the same longest-
        # prefix rule as the Health tree / filing code. Enumeration alone ties
        # each file to whichever root was walked first; if ``series_dir`` (or
        # any root) is a parent directory of a performer/JAV tree, every file
        # under that subtree incorrectly inherited the broad root and performer
        # tiles on /health showed zero videos.
        norm_videos: list[tuple[str, Path]] = []
        seen_dest: set[str] = set()
        for lib_root, vpath in videos:
            try:
                ds = str(vpath.resolve())
            except OSError:
                ds = str(vpath)
            if ds in seen_dest:
                continue
            seen_dest.add(ds)
            lr_here = (_health_resolve_library_root_for_path(vpath, roots) or "").strip()
            if not lr_here:
                lr_here = (lib_root or "").strip()
            if not lr_here:
                continue
            norm_videos.append((lr_here, vpath))
        videos = norm_videos
        total = len(videos)
        emit(f"LIBRARY INDEX staged {total} unique video path(s) from library tree")
        _library_index_progress_set_persist(total)

        plans: list[dict] = []
        for i, (lr, vpath) in enumerate(videos):
            try:
                dest_str = str(vpath.resolve())
            except OSError:
                dest_str = str(vpath)
            stem = vpath.stem
            row = db.library_file_get_by_destination(dest_str)
            if not row:
                alt = db.library_file_find_by_stem_root(stem, lr)
                if alt:
                    db.library_file_update_destination_row(
                        int(alt["id"]),
                        destination=dest_str,
                        current_filename=vpath.name,
                        filename_stem=stem,
                    )
                    db.library_file_clear_removed_if_exists(dest_str)
                    row = db.library_file_get_by_destination(dest_str)
            if row:
                cur_lr = (row.get("library_root") or "").strip()
                if lr and cur_lr != lr:
                    db.library_file_set_library_root(int(row["id"]), lr)
                db.library_file_clear_removed_if_exists(dest_str)
                row = db.library_file_get_by_destination(dest_str) or row
            else:
                sid = db.library_files_find_processed_match_for_stem(stem)
                try:
                    db.library_file_insert_index_stub(
                        destination=dest_str,
                        current_filename=vpath.name,
                        filename_stem=stem,
                        library_root=lr,
                        source_record_id=sid,
                    )
                except sqlite3.IntegrityError:
                    pass
                row = db.library_file_get_by_destination(dest_str)
            if not row:
                emit(f"LIBRARY INDEX persist: could not create row for {vpath.name}")
                _library_index_progress_tick(i + 1, str(vpath))
                continue
            need_phash = not (row.get("phash_2") or "").strip()
            need_probe = _library_index_probe_needed(row, vpath)
            plans.append(
                {
                    "lib_root": lr,
                    "vpath": vpath,
                    "dest_str": dest_str,
                    "stem": stem,
                    "row_id": int(row["id"]),
                    "need_phash": need_phash,
                    "need_probe": need_probe,
                    "probe_snap": _library_index_row_probe_snapshot(row),
                }
            )
            _library_index_progress_tick(i + 1, str(vpath))

        emit(f"LIBRARY INDEX saved {len(plans)} path(s) to library_files; starting media pass")

        heavy_tasks: list[dict] = []
        for p in plans:
            if not p["need_phash"] and not p["need_probe"]:
                continue
            t: dict = {
                "dest_str": p["dest_str"],
                "path_str": str(p["vpath"]),
                "row_id": p["row_id"],
                "need_phash": p["need_phash"],
                "need_probe": p["need_probe"],
            }
            if p["need_probe"]:
                t["row_for_probe"] = p["probe_snap"]
            heavy_tasks.append(t)

        results_by_dest: dict[str, dict] = {}
        if heavy_tasks:
            emit(
                f"LIBRARY INDEX {len(heavy_tasks)} media decode(s) "
                f"(parallel phash/ffprobe; DB commit per success)"
            )
            _library_index_progress_set_decode(len(heavy_tasks))
            dec_done = 0
            workers = max(1, (os.cpu_count() or 4) // 4)
            with ThreadPoolExecutor(max_workers=workers) as executor:
                futures = {executor.submit(_library_index_heavy_task, t): t for t in heavy_tasks}
                for future in as_completed(futures):
                    t_done = futures[future]
                    r = future.result()
                    _library_index_persist_heavy_task_result(t_done, r)
                    results_by_dest[r["dest_str"]] = r
                    dec_done += 1
                    _library_index_progress_decode_tick(dec_done, r["dest_str"])

        _library_index_progress_set_apply(len(plans))

        done = 0
        for p in plans:
            done += 1
            _library_index_progress_tick(done - 1, str(p["vpath"]))
            vpath = p["vpath"]
            dest_str = p["dest_str"]
            heavy = results_by_dest.get(dest_str)

            db.library_file_clear_removed_if_exists(dest_str)
            row = db.library_file_get_by_destination(dest_str)
            if not row:
                _library_index_progress_tick(done, str(vpath))
                continue

            row_up = db.library_file_get_by_destination(dest_str) or row
            applied_probe = bool(heavy and heavy.get("__probe_persisted"))
            if p["need_probe"] and not applied_probe:
                try:
                    _library_index_sync_media_for_row(row_up, vpath)
                except Exception as e:
                    emit(f"LIBRARY INDEX media {vpath.name}: {e}")
            _library_index_progress_tick(done, str(vpath))

        for r in db.library_files_list_active_rows():
            dst = (r.get("destination") or "").strip()
            if not dst:
                continue
            if not Path(dst).is_file():
                db.library_file_mark_removed(int(r["id"]))
        emit("LIBRARY INDEX complete")
        try:
            db.notification_add(
                "library",
                "Library index finished",
                ttl_seconds=200,
            )
        except Exception:
            pass
        try:
            stats = db.wanted_reconcile_with_library()
            if stats.get("cleared"):
                emit(
                    f"WANTED reconcile after library index: cleared "
                    f"{stats['cleared']} of {stats['checked']} active item(s)"
                )
        except Exception as e:
            emit(f"WANTED reconcile after library index: {e}")
    finally:
        _library_index_progress_finish()
        _library_index_sema.release()


def run_phash3_rescan_job(*, scheduled_interval: bool = False) -> None:
    if not _phash3_job_sema.acquire(blocking=False):
        emit("PHASH3 rescan skipped (already running)")
        return
    try:
        settings = db.get_settings()
        interval_days = max(1, int(settings.get("library_phash3_rescan_interval_days", "30") or 30))
        recurring = settings.get("library_phash3_rescan_enabled", "false").lower() == "true"
        rows = db.library_files_list_active_rows()
        to_process: list[dict] = []
        now = datetime.now(timezone.utc)
        for r in rows:
            p3 = (r.get("phash_3") or "").strip()
            p3s = (r.get("phash_3_scanned_at") or "").strip()
            need = False
            if not p3:
                need = True
            elif scheduled_interval and recurring:
                try:
                    scanned = datetime.fromisoformat(p3s.replace("Z", "+00:00"))
                    if (now - scanned).days >= interval_days:
                        need = True
                except Exception:
                    need = True
            if need:
                to_process.append(r)

        _phash3_progress_start(len(to_process))
        done = 0
        for r in to_process:
            dst = (r.get("destination") or "").strip()
            _phash3_progress_tick(done, dst)
            done += 1
            if not dst:
                continue
            vp = Path(dst)
            if not vp.is_file():
                db.library_file_mark_removed(int(r["id"]))
                continue
            try:
                h = compute_phash(vp)
                db.library_file_set_phash3(int(r["id"]), h)
            except Exception as e:
                emit(f"PHASH3 rescan {dst}: {e}")
        emit("PHASH3 rescan complete")
    finally:
        _phash3_progress_finish()
        _phash3_job_sema.release()


def run_library_phash3_scheduled_job() -> None:
    s = db.get_settings()
    if s.get("library_phash3_rescan_enabled", "false").lower() != "true":
        return
    run_phash3_rescan_job(scheduled_interval=True)


@app.get("/api/library/scan")
async def library_scan(background_tasks: BackgroundTasks):
    """Trigger a library issue scan across all configured dirs."""
    settings = db.get_settings()
    dirs = [
        settings.get("series_dir", ""),
        settings.get("features_dir", ""),
    ]
    # Add performer dirs
    for d in db.get_directories():
        dirs.append(d["path"])
    jav_d = (settings.get("jav_dir") or "").strip()
    if jav_d:
        dirs.append(jav_d)
    dirs = [d for d in dirs if d]

    features_dir = settings.get("features_dir", "")
    movie_dirs = [features_dir] if features_dir else []

    def run():
        results = scan_library_issues(dirs, movie_dirs=movie_dirs)
        db.save_setting("_library_scan_results", __import__("json").dumps(results))
        db.save_setting("_library_scan_time", __import__("datetime").datetime.now().isoformat(timespec="seconds"))

    background_tasks.add_task(run)
    return {"started": True}


