def _health_dup_file_payload(r: dict) -> dict:
    """Fields for duplicate-compare UI (size from disk; phash / media from index row)."""
    dst = (r.get("destination") or "").strip()
    on_disk = Path(dst).is_file() if dst else False
    sz = None
    if dst and on_disk:
        try:
            sz = int(Path(dst).stat().st_size)
        except OSError:
            sz = None
    p3 = (r.get("phash_3") or "").strip()
    p2 = (r.get("phash_2") or "").strip()
    p1 = (r.get("phash_1") or "").strip()
    eff = p3 or p2 or p1 or None
    mw = r.get("media_width")
    mh = r.get("media_height")
    try:
        w = int(mw) if mw is not None else None
    except (TypeError, ValueError):
        w = None
    try:
        h = int(mh) if mh is not None else None
    except (TypeError, ValueError):
        h = None
    mcc = ((r.get("media_codec") or "").strip()) or None
    drp = r.get("duplicate_review_pending")
    try:
        pending = int(drp) if drp is not None else 0
    except (TypeError, ValueError):
        pending = 0
    dig = r.get("duplicate_ignored")
    try:
        ign = int(dig) if dig is not None else 0
    except (TypeError, ValueError):
        ign = 0
    sid = r.get("source_record_id")
    return {
        "id": r.get("id"),
        "destination": dst,
        "on_disk": on_disk,
        "current_filename": r.get("current_filename"),
        "size_bytes": sz,
        "media_width": w,
        "media_height": h,
        "media_codec": mcc,
        "phash_effective": eff,
        "duplicate_review_pending": 1 if pending else 0,
        "duplicate_ignored": 1 if ign else 0,
        "source_record_id": int(sid) if sid is not None else None,
    }


_QUEUE_PHASH_NEW_COMPARE_ID = 9_999_999_999


def _queue_source_video_dup_compare_payload(video: Path) -> dict:
    """Shape compatible with _duplicate_recommend / _health_dup_file_payload (incoming queue file)."""
    dst = str(video.resolve())
    sz = 0
    try:
        sz = int(video.stat().st_size)
    except OSError:
        pass
    _c, w, h = probe_video_stream_meta(video)
    return {
        "id": _QUEUE_PHASH_NEW_COMPARE_ID,
        "destination": dst,
        "on_disk": True,
        "current_filename": video.name,
        "size_bytes": sz,
        "media_width": w,
        "media_height": h,
        "media_codec": None,
    }


def _queue_discard_source_after_library_phash(
    video: Path, filename: str, phash: str, err: str, *, movie: bool = False
) -> dict:
    """Delete the queue file and mark processed_files / processed_movies removed."""
    try:
        if video.is_file():
            video.unlink()
    except OSError as e:
        emit(f"  Remove queue file: {e}")
    if movie:
        db.update_movie(filename, status="removed", error=err)
    else:
        db.update_file(filename, status="removed", phash=phash, error=err)
    return {"status": "removed", "error": err}


def _queue_resolve_phash_vs_indexed_library(
    video: Path, filename: str, phash: str, *, movie: bool = False
) -> dict | None:
    """
    If library_files already has this phash, pick the better copy using the same rules as
    duplicate resolution. If the queue file loses, delete it and return a result dict.
    If it wins, delete worse indexed file(s) and return None so filing continues.
    """
    lib_rows = db.library_files_active_matching_phash(phash)
    if not lib_rows:
        return None
    new_payload = _queue_source_video_dup_compare_payload(video)
    lib_payloads = [_health_dup_file_payload(dict(r)) for r in lib_rows]
    group = lib_payloads + [new_payload]
    rec = _duplicate_recommend(group)
    new_dest = (new_payload.get("destination") or "").strip()

    if rec.get("confidence") == "low":
        emit(
            "  Library phash match: ambiguous quality (tie) — keeping indexed copy; "
            "removing queue file"
        )
        return _queue_discard_source_after_library_phash(
            video,
            filename,
            phash,
            "Indexed library copy kept (phash tie)",
            movie=movie,
        )

    keeper = rec.get("keeper") or {}
    kdest = (keeper.get("destination") or "").strip()
    if kdest != new_dest:
        emit(
            "  Library phash match: indexed copy is better or equal — removing queue file"
        )
        return _queue_discard_source_after_library_phash(
            video,
            filename,
            phash,
            "Indexed library copy kept (phash)",
            movie=movie,
        )

    emit("  Library phash match: queue file is better — removing superseded indexed copy(ies)")
    seen: set[str] = set()
    for r in lib_rows:
        d = (r.get("destination") or "").strip()
        if not d or d == new_dest or d in seen:
            continue
        seen.add(d)
        try:
            _duplicate_delete_one_library_video(d)
        except Exception as e:
            emit(f"  Replace: could not remove indexed file {d}: {e}")
    return None


_QUEUE_DUP_IGNORE_SETTING = "queue_duplicate_ignored"


def _queue_duplicate_ignored_get() -> set[str]:
    raw = (db.get_settings().get(_QUEUE_DUP_IGNORE_SETTING) or "").strip()
    if not raw:
        return set()
    try:
        parsed = json.loads(raw)
        if isinstance(parsed, list):
            return {str(x).strip().lower() for x in parsed if str(x).strip()}
    except Exception:
        pass
    return set()


def _queue_duplicate_ignored_set_phash(phash: str, ignored: bool) -> None:
    ph = (phash or "").strip().lower()
    if not ph:
        return
    cur = _queue_duplicate_ignored_get()
    if ignored:
        cur.add(ph)
    else:
        cur.discard(ph)
    db.save_settings({_QUEUE_DUP_IGNORE_SETTING: json.dumps(sorted(cur))})


def _queue_dup_row_id(filename: str) -> int:
    fst, _ = db._filename_stem_ext(filename)
    with db.get_conn() as conn:
        row = conn.execute(
            "SELECT id FROM processed_files WHERE filename = ? OR filename = ? LIMIT 1",
            (filename, fst),
        ).fetchone()
    if row:
        return int(row["id"])
    return abs(hash(filename)) % 900_000_000


def _queue_dup_file_payload(filename: str, video: Path, *, phash: str = "") -> dict:
    """Compare payload for queue duplicate groups (same shape as library health)."""
    dst = str(video.resolve())
    sz = 0
    try:
        sz = int(video.stat().st_size)
    except OSError:
        pass
    _c, w, h = probe_video_stream_meta(video)
    return {
        "id": _queue_dup_row_id(filename),
        "destination": dst,
        "on_disk": video.is_file(),
        "current_filename": filename,
        "size_bytes": sz,
        "media_width": w,
        "media_height": h,
        "media_codec": None,
        "phash_effective": (phash or "").strip() or None,
        "duplicate_ignored": 0,
    }


def _annotate_queue_files_duplicate_flags(files: list[dict]) -> None:
    """Set in_duplicate_group + duplicate_group_size on each queue row."""
    phash_to_names: dict[str, list[str]] = {}
    name_to_phash: dict[str, str] = {}
    for f in files:
        fn = (f.get("filename") or "").strip()
        if not fn:
            continue
        ph = db.get_phash(fn)
        if not ph:
            f["in_duplicate_group"] = False
            f["duplicate_group_size"] = 0
            continue
        key = ph.strip().lower()
        name_to_phash[fn] = key
        phash_to_names.setdefault(key, []).append(fn)
    dup_phashes = {ph for ph, names in phash_to_names.items() if len(names) >= 2}
    for f in files:
        fn = (f.get("filename") or "").strip()
        ph = name_to_phash.get(fn)
        if ph and ph in dup_phashes:
            f["in_duplicate_group"] = True
            f["duplicate_group_size"] = len(phash_to_names[ph])
        else:
            f["in_duplicate_group"] = False
            f["duplicate_group_size"] = 0


def _queue_duplicate_groups_payload(*, compute_missing_phash: bool = False) -> dict:
    """
    Groups of 2+ source-dir videos sharing the same cached phash.
    Uses the same keeper recommendation as Library Health duplicates.
    """
    settings = db.get_settings()
    source_dir = Path(settings.get("source_dir", ""))
    if not source_dir.is_dir():
        return {
            "groups": [],
            "group_count": 0,
            "file_count": 0,
            "no_phash_count": 0,
            "error": f"Source dir not found: {source_dir}",
        }

    history = {r["filename"]: r for r in db.get_history(limit=10000)}
    ignored = _queue_duplicate_ignored_get()
    buckets: dict[str, list[tuple[str, Path]]] = {}
    no_phash = 0

    for f in sorted(source_dir.iterdir()):
        if not f.is_file() or f.suffix.lower() not in VIDEO_EXTENSIONS:
            continue
        ph = db.get_phash(f.name)
        if not ph and compute_missing_phash:
            try:
                ph = compute_phash(f) or ""
            except Exception:
                ph = ""
            if ph:
                hrow = history.get(f.name) or history.get(f.stem) or {}
                status = (hrow.get("status") or "").strip() or "unmatched"
                try:
                    db.upsert_file(f.name)
                    db.update_file(f.name, status=status, phash=ph)
                except Exception:
                    pass
        if not ph:
            no_phash += 1
            continue
        buckets.setdefault(ph.strip().lower(), []).append((f.name, f))

    groups_out: list[dict] = []
    for ph, members in sorted(buckets.items()):
        if len(members) < 2:
            continue
        files_out = [_queue_dup_file_payload(fn, vp, phash=ph) for fn, vp in members]
        rec = _duplicate_recommend(files_out)
        keeper = rec.get("keeper") or {}
        kfn = (keeper.get("current_filename") or "").strip()
        if not kfn and keeper.get("destination"):
            try:
                kfn = Path(keeper["destination"]).name
            except Exception:
                kfn = ""
        groups_out.append(
            {
                "kind": "phash",
                "phash": ph,
                "name_score": None,
                "ignored": ph in ignored,
                "files": files_out,
                "recommendation": {
                    "keeper_filename": kfn,
                    "keeper_destination": (keeper.get("destination") or "").strip(),
                    "confidence": rec.get("confidence") or "high",
                },
            }
        )

    active = [g for g in groups_out if not g.get("ignored")]
    file_count = sum(len(g.get("files") or []) for g in active)
    return {
        "groups": groups_out,
        "group_count": len(active),
        "file_count": file_count,
        "no_phash_count": no_phash,
    }


def _queue_delete_filename_sync(filename: str) -> dict:
    """Delete one source-dir video (shared by queue delete + duplicate resolve)."""
    fn = (filename or "").strip()
    if not fn:
        return {"ok": False, "error": "filename required"}
    settings = db.get_settings()
    source_dir = Path(settings.get("source_dir", ""))
    if not source_dir.exists():
        return {"ok": False, "error": f"Source dir not found: {source_dir}"}
    target = source_dir / fn
    try:
        target_resolved = target.resolve()
        source_resolved = source_dir.resolve()
        target_resolved.relative_to(source_resolved)
    except ValueError:
        return {"ok": False, "error": "filename escapes source directory"}
    except OSError as exc:
        return {"ok": False, "error": f"path resolution failed: {exc}"}
    if not target_resolved.is_file():
        try:
            db.update_file(fn, status="removed")
        except Exception:
            pass
        return {"ok": True, "deleted": False, "already_missing": True, "freed_bytes": 0}
    freed = 0
    try:
        freed = int(target_resolved.stat().st_size)
    except OSError:
        pass
    try:
        target_resolved.unlink()
    except OSError as exc:
        return {"ok": False, "error": f"delete failed: {exc}"}
    stem = target_resolved.stem
    parent = target_resolved.parent
    for sidecar in (
        parent / f"{stem}.nfo",
        parent / f"{stem}-thumb.jpg",
        parent / f"{stem}-poster.jpg",
    ):
        try:
            if sidecar.is_file():
                sidecar.unlink()
        except OSError:
            pass
    try:
        db.update_file(fn, status="removed")
    except Exception:
        pass
    emit(f"Deleted from disk: {fn}")
    return {"ok": True, "deleted": True, "filename": fn, "freed_bytes": freed}


def _queue_duplicate_resolve_one_sync(keep_filename: str, delete_filenames: list) -> dict:
    keep_fn = (keep_filename or "").strip()
    if not keep_fn:
        return {"ok": False, "error": "keep_filename required", "freed_bytes": 0}
    freed = 0
    deleted = 0
    for raw in delete_filenames or []:
        fn = (raw or "").strip()
        if not fn or fn == keep_fn:
            continue
        r = _queue_delete_filename_sync(fn)
        if not r.get("ok"):
            return {"ok": False, "error": r.get("error") or "delete failed", "freed_bytes": freed}
        freed += int(r.get("freed_bytes") or 0)
        if r.get("deleted"):
            deleted += 1
    return {"ok": True, "freed_bytes": freed, "deleted": deleted}


def _health_duplicate_groups_payload() -> list[dict]:
    phash_raw = db.library_files_duplicate_groups()
    out: list[dict] = []
    for g in phash_raw:
        files_out = []
        for r in g["files"]:
            files_out.append(_health_dup_file_payload(dict(r)))
        rec = _duplicate_recommend(files_out)
        keeper = rec.get("keeper") or {}
        kdest = (keeper.get("destination") or "").strip()
        ignored = any(int(f.get("duplicate_ignored") or 0) for f in files_out)
        out.append(
            {
                "kind": "phash",
                "phash": g["phash"],
                "name_score": None,
                "ignored": bool(ignored),
                "files": files_out,
                "recommendation": {
                    "keeper_destination": kdest,
                    "confidence": rec.get("confidence") or "high",
                },
            }
        )
    return out


