@app.post("/api/health/duplicates/ignore")
async def health_duplicates_ignore(payload: dict = Body(...)):
    ph = (payload.get("phash") or "").strip()
    if not ph:
        return JSONResponse({"ok": False, "error": "phash required"}, status_code=400)
    raw_ig = payload.get("ignored")
    if raw_ig is None:
        return JSONResponse({"ok": False, "error": "ignored required"}, status_code=400)
    want = 1 if raw_ig in (True, 1, "1", "true") else 0
    n = db.library_files_set_duplicate_ignored_for_phash(ph, want)
    if n <= 0:
        return JSONResponse(
            {"ok": False, "error": "No library rows matched phash"},
            status_code=404,
        )
    return {"ok": True, "ignored": bool(want), "updated": n}


#: Cache + concurrency tracking for the /health duplicates filmstrip.
#: Mirrors the queue filmstrip flow (5 frames at 10/30/50/70/90%, cached
#: under metadata) but keyed by the **absolute library path** rather
#: than a queue filename. Backoff prevents a wedged file from being
#: re-poked every poll.
_dup_thumb_inflight: set[str] = set()
_dup_thumb_inflight_lock = threading.Lock()
_dup_thumb_backoff: dict[str, float] = {}
_dup_thumb_backoff_lock = threading.Lock()
_DUP_THUMB_BACKOFF_SECONDS = 60 * 60


def _dup_thumbs_dir(path_str: str, *, ensure: bool = False) -> Path:
    """Per-library-file cache dir keyed by sha1(absolute path). Same
    layout as the queue strip — distinct namespace so the two never
    collide."""
    import hashlib as _hashlib
    h = _hashlib.sha1((path_str or "").encode("utf-8")).hexdigest()
    d = _metadata_base_dir() / "dup_thumbs" / h
    if ensure:
        d.mkdir(parents=True, exist_ok=True)
    return d


def _dup_thumb_path(path_str: str, i: int) -> Path:
    return _dup_thumbs_dir(path_str, ensure=False) / f"{int(i)}.jpg"


def _ensure_dup_thumbs(abs_path: str) -> list[Path]:
    """Generate (or reuse) the 5-frame filmstrip for an absolute library
    path. Mirrors ``_ensure_queue_thumbs`` but takes a resolved path
    directly instead of resolving against ``source_dir``."""
    p = Path(abs_path)
    if not p.is_file():
        return []
    dest_dir = _dup_thumbs_dir(abs_path, ensure=False)
    paths: list[Path] = [dest_dir / f"{i}.jpg" for i in range(QUEUE_THUMB_COUNT)]
    if all(pp.is_file() and pp.stat().st_size > 0 for pp in paths):
        return paths
    dest_dir.mkdir(parents=True, exist_ok=True)
    try:
        duration = get_video_duration(p)
    except Exception as exc:
        try: emit(f"dup thumbs: ffprobe duration failed for {abs_path!r}: {exc}")
        except Exception: pass
        return []
    if not duration or duration <= 0:
        return []
    out: list[Path] = []
    work: list[tuple[int, float, Path]] = []
    for i, pct in enumerate(QUEUE_THUMB_PERCENTS):
        pp = paths[i]
        if pp.is_file() and pp.stat().st_size > 0:
            out.append(pp)
            continue
        work.append((i, duration * (pct / 100.0), pp))
    if work:
        from concurrent.futures import ThreadPoolExecutor
        sem = _queue_thumb_fg_semaphore
        results: dict[int, Path | None] = {}
        if len(work) == 1:
            (idx, ts, dest) = work[0]
            results[idx] = dest if _generate_queue_thumb(p, dest, ts, semaphore=sem) else None
        else:
            with ThreadPoolExecutor(max_workers=min(len(work), _QUEUE_THUMB_FG_CONCURRENCY)) as pool:
                futures = {
                    pool.submit(_generate_queue_thumb, p, dest, ts, semaphore=sem): (idx, dest)
                    for (idx, ts, dest) in work
                }
                for fut in futures:
                    idx, dest = futures[fut]
                    try:
                        ok = fut.result()
                    except Exception:
                        ok = False
                    results[idx] = dest if ok else None
        for (idx, _ts, dest) in sorted(work):
            pp = results.get(idx)
            if pp is not None:
                out.append(pp)
        out.sort(key=lambda x: int(x.stem))
    return out


def _prewarm_dup_thumbs_async(abs_path: str) -> None:
    """Dispatch a background prewarm for *abs_path*. Dedup'd by inflight
    set so polling stays cheap."""
    with _dup_thumb_inflight_lock:
        if abs_path in _dup_thumb_inflight:
            return
        _dup_thumb_inflight.add(abs_path)
    def _worker() -> None:
        try:
            paths = _ensure_dup_thumbs(abs_path)
            if len(paths) < QUEUE_THUMB_COUNT:
                with _dup_thumb_backoff_lock:
                    _dup_thumb_backoff[abs_path] = time.time() + _DUP_THUMB_BACKOFF_SECONDS
                try: emit(f"dup thumbs: backing off {abs_path!r} for 1h ({len(paths)}/{QUEUE_THUMB_COUNT} frames)")
                except Exception: pass
        finally:
            with _dup_thumb_inflight_lock:
                _dup_thumb_inflight.discard(abs_path)
    threading.Thread(target=_worker, daemon=True).start()


@app.get("/api/health/duplicate-thumbs")
async def health_duplicate_thumbs(path: str = Query("", description="Absolute library video path")):
    """Filmstrip state poll for a single duplicate file. Same shape as
    ``/api/queue/thumbs`` — the /health UI reuses the queue's polling
    pattern (frames trickle in as ffmpeg seeks complete)."""
    raw = (path or "").strip()
    if not raw:
        return JSONResponse({"error": "path required"}, status_code=400)
    try:
        roots = _health_library_roots()
        _health_assert_path_under_roots(raw, roots)
    except ValueError as e:
        return JSONResponse({"error": str(e)}, status_code=400)
    items: list[dict] = []
    for i in range(QUEUE_THUMB_COUNT):
        pp = _dup_thumb_path(raw, i)
        if pp.is_file() and pp.stat().st_size > 0:
            mt = int(pp.stat().st_mtime)
            items.append({
                "i": i,
                "percent": QUEUE_THUMB_PERCENTS[i],
                "url": f"/api/health/duplicate-thumb?path={quote(raw, safe='')}&i={i}&v={mt}",
            })
    ready = len(items) == QUEUE_THUMB_COUNT
    generating = False
    backoff = False
    retry_at: float | None = None
    if not ready:
        with _dup_thumb_backoff_lock:
            expiry = _dup_thumb_backoff.get(raw)
        now = time.time()
        if expiry is not None and expiry > now:
            backoff = True
            retry_at = expiry
        else:
            _prewarm_dup_thumbs_async(raw)
            generating = True
    return {
        "path":       raw,
        "thumbs":     items,
        "count":      len(items),
        "ready":      ready,
        "generating": generating,
        "backoff":    backoff,
        "retry_at":   retry_at,
    }


@app.get("/api/health/duplicate-thumb")
async def health_duplicate_thumb(path: str = Query(""), i: int = 0, v: int = 0):
    """Serve a cached duplicate-filmstrip frame (JPEG)."""
    raw = (path or "").strip()
    if not raw or i < 0 or i >= QUEUE_THUMB_COUNT:
        return JSONResponse({"error": "bad request"}, status_code=400)
    try:
        roots = _health_library_roots()
        _health_assert_path_under_roots(raw, roots)
    except ValueError as e:
        return JSONResponse({"error": str(e)}, status_code=400)
    pp = _dup_thumb_path(raw, i)
    if not pp.is_file() or pp.stat().st_size == 0:
        await run_in_threadpool(_ensure_dup_thumbs, raw)
    if not pp.is_file() or pp.stat().st_size == 0:
        return JSONResponse({"error": "no thumb"}, status_code=404)
    return FileResponse(
        pp,
        media_type="image/jpeg",
        headers={"Cache-Control": "private, max-age=3600"},
    )


@app.post("/api/health/duplicate-thumbs/retry")
async def health_duplicate_thumbs_retry(payload: dict):
    """Clear the 1h backoff for *path* and re-dispatch the prewarm."""
    raw = (payload.get("path") or "").strip()
    if not raw:
        return JSONResponse({"error": "path required"}, status_code=400)
    try:
        roots = _health_library_roots()
        _health_assert_path_under_roots(raw, roots)
    except ValueError as e:
        return JSONResponse({"error": str(e)}, status_code=400)
    with _dup_thumb_backoff_lock:
        cleared = _dup_thumb_backoff.pop(raw, None) is not None
    _prewarm_dup_thumbs_async(raw)
    return {"path": raw, "cleared": cleared, "generating": True}


@app.get("/api/health/duplicate-frames")
async def health_duplicate_frames(path: str = Query("", description="Absolute video path")):
    raw = (path or "").strip()
    if not raw:
        return {"frames": [], "error": "path required"}
    p = Path(raw)
    if not p.is_file():
        return {"frames": [], "error": "File not found"}
    if p.suffix.lower() not in VIDEO_EXTENSIONS:
        return {"frames": [], "error": "Not a video file"}

    def grab() -> dict:
        out: list[str] = []
        for pct in (20.0, 50.0, 80.0):
            b64 = capture_frame_as_base64(p, pct)
            if b64:
                out.append(b64)
        if not out:
            return {"frames": [], "error": "Could not capture frames (ffmpeg or duration)"}
        return {"frames": out}

    loop = asyncio.get_event_loop()
    try:
        return await loop.run_in_executor(None, grab)
    except Exception as e:
        return {"frames": [], "error": str(e)}


@app.get("/api/health/duplicate-db-record")
async def health_duplicate_db_record(path: str = Query("")):
    raw = (path or "").strip()
    if not raw:
        return {"source": None}
    row = db.library_file_get_by_destination(raw)
    if not row:
        return {"source": None}
    sid = row.get("source_record_id")
    if sid is None:
        return {"source": None}
    pf = db.processed_file_get_by_id(int(sid))
    if not pf:
        return {"source": None}
    ms = (pf.get("match_source") or "").strip()
    tag = _api_source_tag(ms)
    if not tag:
        return {"source": None}
    perf_raw = (pf.get("performers") or "").strip()
    performers = [x.strip() for x in perf_raw.split(",") if x.strip()]
    match_id = None
    phash = (pf.get("phash") or "").strip()
    title = (pf.get("match_title") or "").strip()
    date = (pf.get("match_date") or "").strip()
    ep = _endpoint_query_var_for_match_source(ms)
    if ep:
        endpoint, api_key, _qvar = ep
        if (api_key or "").strip() and phash:
            q = STASHDB_QUERY if _qvar == "full" else TPDB_QUERY
            try:
                matches = query_stashbox(phash, endpoint, api_key, q, _qvar)
            except Exception:
                matches = []
            scene = _pick_scene_from_matches(matches, title, date)
            if scene and scene.get("id"):
                match_id = str(scene.get("id"))
    out = {
        "source": tag,
        "title": pf.get("match_title") or "",
        "studio": pf.get("match_studio") or "",
        "date": pf.get("match_date") or "",
        "performers": performers,
        "match_id": match_id or "",
    }
    return out


