NFO_DELETE_SIDECAR_EXTS = {".png", ".jpg", ".jpeg", ".webm"}


def _nfo_sidecar_stem_matches(nfo_stem: str, candidate_stem: str) -> bool:
    """Match same-stem sidecars and stems that continue after the NFO stem (e.g. 'Episode - Cabo-thumb')."""
    if candidate_stem == nfo_stem:
        return True
    if len(candidate_stem) <= len(nfo_stem) or not candidate_stem.startswith(nfo_stem):
        return False
    return candidate_stem[len(nfo_stem)] in " -._"


def _unlink_nfo_sidecar_files(nfo_path: Path) -> None:
    parental = nfo_path.parent
    nfo_stem = nfo_path.stem
    try:
        nfo_key = nfo_path.resolve()
    except OSError:
        nfo_key = nfo_path
    for child in list(parental.iterdir()):
        if not child.is_file():
            continue
        try:
            if child.resolve() == nfo_key:
                continue
        except OSError:
            continue
        if child.suffix.lower() not in NFO_DELETE_SIDECAR_EXTS:
            continue
        if not _nfo_sidecar_stem_matches(nfo_stem, child.stem):
            continue
        try:
            child.unlink()
        except OSError:
            pass


def _health_delete_nfo_one(path_raw: str, roots: list[dict]) -> str | None:
    """Delete one .nfo and matching png/jpg/jpeg/webm sidecars. Returns None on success, else error string."""
    path_raw = (path_raw or "").strip()
    if not path_raw or not path_raw.lower().endswith(".nfo"):
        return "nfo path required"
    try:
        p = _health_assert_path_under_roots(path_raw, roots)
    except ValueError as e:
        return str(e)
    if not p.is_file():
        return "Not found"
    if p.name.lower() == "tvshow.nfo":
        return "refusing tvshow.nfo"
    _unlink_nfo_sidecar_files(p)
    try:
        p.unlink()
    except OSError as e:
        return str(e)
    return None


@app.post("/api/health/delete-nfo")
async def health_delete_nfo(payload: dict = Body(...)):
    roots = _health_library_roots()
    paths_bulk = payload.get("paths")
    if paths_bulk is not None:
        if not isinstance(paths_bulk, list):
            return JSONResponse({"error": "paths must be a list"}, status_code=400)
        deleted: list[str] = []
        errors: list[dict] = []
        for raw in paths_bulk:
            if not isinstance(raw, str):
                errors.append({"path": str(raw), "error": "invalid path"})
                continue
            err = _health_delete_nfo_one(raw, roots)
            if err:
                errors.append({"path": raw.strip(), "error": err})
            else:
                deleted.append(raw.strip())
        return {"ok": len(errors) == 0, "deleted": deleted, "errors": errors}
    path_raw = (payload.get("path") or "").strip()
    err = _health_delete_nfo_one(path_raw, roots)
    if err is None:
        return {"ok": True}
    if err == "Not found":
        return JSONResponse({"error": err}, status_code=404)
    if err in ("nfo path required", "refusing tvshow.nfo", "Path is not under a configured library directory"):
        return JSONResponse({"error": err}, status_code=400)
    return JSONResponse({"error": err}, status_code=500)


