@app.get("/api/news/feed")
async def api_news_feed(refresh: bool = False):
    """Return the cached news-feed items. ``?refresh=true`` forces a
    background re-fetch before responding so users can pull-to-refresh.

    Per-item ``tint`` is stamped here (not at fetch time) so changing a
    feed's colour in Settings shows up on the next page load without
    needing to invalidate or rebuild the cache.
    """
    if not refresh:
        _maybe_hydrate_news_rss_cache_from_disk()
    if refresh or _news_rss_cache["fetched_at"] == 0.0:
        await asyncio.get_event_loop().run_in_executor(None, _refresh_news_rss_cache)
    with _news_rss_cache_lock:
        items = list(_news_rss_cache["items"])
        errors = list(_news_rss_cache["errors"])
        fetched_at = _news_rss_cache["fetched_at"]
    tint_map = _news_tint_map()
    if tint_map:
        items = [
            ({**it, "tint": tint_map[it.get("source_feed")]} if it.get("source_feed") in tint_map else it)
            for it in items
        ]
    return {
        "results": items,
        "errors": errors,
        "fetched_at": fetched_at,
        "configured_urls": len(_news_configured_urls()),
    }


