@app.get("/api/library/scenes-in/debug")
async def api_library_scenes_in_debug():
    """Diagnostic for the phash crosswalk. Returns counts so you can
    tell whether scene_fingerprints is being populated, whether
    library_files has phashes to match against, and how big the
    intersection is. Helpful when the in-library badge isn't showing
    on cards you know are in your collection."""
    with db.get_conn() as conn:
        sf_total = int(conn.execute("SELECT COUNT(*) AS c FROM scene_fingerprints").fetchone()["c"])
        sf_by_src = {
            r["source"]: int(r["c"])
            for r in conn.execute(
                "SELECT source, COUNT(*) AS c FROM scene_fingerprints GROUP BY source"
            ).fetchall()
        }
        lf_total = int(conn.execute(
            "SELECT COUNT(*) AS c FROM library_files WHERE is_removed = 0"
        ).fetchone()["c"])
        lf_with_phash = int(conn.execute(
            "SELECT COUNT(*) AS c FROM library_files "
            "WHERE is_removed = 0 AND ("
            "  COALESCE(phash_1,'') <> '' "
            "  OR COALESCE(phash_2,'') <> '' "
            "  OR COALESCE(phash_3,'') <> '')"
        ).fetchone()["c"])
        # Intersection count — phashes present in both tables
        intersect = int(conn.execute(
            "SELECT COUNT(DISTINCT sf.phash) AS c "
            "FROM scene_fingerprints sf "
            "JOIN library_files lf "
            "  ON  lf.is_removed = 0 "
            "  AND (lf.phash_1 = sf.phash OR lf.phash_2 = sf.phash OR lf.phash_3 = sf.phash)"
        ).fetchone()["c"])
        pf_total = int(conn.execute(
            "SELECT COUNT(*) AS c FROM processed_files WHERE status = 'success'"
        ).fetchone()["c"])
        pf_with_external_id = int(conn.execute(
            "SELECT COUNT(*) AS c FROM processed_files "
            "WHERE status = 'success' "
            "  AND COALESCE(match_external_id, '') <> ''"
        ).fetchone()["c"])
    return {
        "library_files": {"total": lf_total, "with_phash": lf_with_phash},
        "scene_fingerprints": {"total": sf_total, "by_source": sf_by_src},
        "processed_files": {"matched_total": pf_total, "with_external_id": pf_with_external_id},
        "phash_intersect": intersect,
    }


@app.post("/api/library/scenes-in/seed-fingerprints")
async def api_library_seed_fingerprints():
    """One-shot: for every successfully-imported file in
    ``processed_files`` that has a ``match_source`` + ``match_external_id``,
    fetch its fingerprints from the corresponding stash-box / TPDB
    and persist them into ``scene_fingerprints``. Without this, the
    fingerprint cache only fills up via browse-driven backfill —
    which means tiles for old imports never light up the badge.

    Returns immediately; the actual fetch loop runs on a daemon thread.
    """
    rows: list[tuple[str, str]] = []
    with db.get_conn() as conn:
        cur = conn.execute(
            "SELECT DISTINCT lower(match_source) AS src, match_external_id AS sid "
            "FROM processed_files "
            "WHERE status = 'success' "
            "  AND COALESCE(match_external_id, '') <> '' "
            "  AND lower(COALESCE(match_source, '')) IN ('stashdb', 'fansdb', 'tpdb', 'javstash')"
        )
        for r in cur.fetchall():
            rows.append((r["src"], r["sid"]))
    if not rows:
        return {"ok": True, "queued": 0, "note": "no processed_files rows with match_external_id"}
    # Skip ones already cached
    known: set[str] = set()
    for src in ("stashdb", "fansdb", "tpdb", "javstash"):
        ids_for_src = [i for (s, i) in rows if s == src]
        if ids_for_src:
            known |= {f"{src}:{x}" for x in db.scene_fingerprints_known_ids(src, ids_for_src)}
    todo: list[tuple[str, str]] = [(s, i) for (s, i) in rows if f"{s}:{i}" not in known]
    if not todo:
        return {"ok": True, "queued": 0, "total": len(rows), "note": "all already cached"}
    # Fire off a daemon thread that walks the queue at a moderate pace.
    def _runner(targets):
        for chunk_start in range(0, len(targets), 30):
            _library_scene_backfill_worker(targets[chunk_start:chunk_start + 30])
    threading.Thread(target=_runner, args=(todo,), daemon=True, name="lib-fp-seed").start()
    return {"ok": True, "queued": len(todo), "total": len(rows)}


@app.post("/api/queue/reset-shutdown-errors")
async def api_queue_reset_shutdown_errors():
    """One-shot cleanup for rows that failed with the 'cannot schedule
    new futures after interpreter shutdown' RuntimeError. Those errors
    are spurious — the files were caught mid-shutdown — so we flip the
    rows back to ``pending`` so the matcher picks them up next pass."""
    with db.get_conn() as conn:
        cur = conn.execute(
            "UPDATE processed_files "
            "SET status = 'pending', error = NULL "
            "WHERE error LIKE '%cannot schedule new futures%'"
        )
        n = cur.rowcount
        conn.commit()
    return {"ok": True, "reset": int(n or 0)}


# ── Suggestions: name-based matches for unmatched queue files ──────
# When a phash lookup misses, the unmatched-handler kicks off a
# background `_run_name_search_async` pass that searches StashDB →
# TPDB → FansDB by the cleaned filename and stashes the top scoring
# candidates in `queue_suggestions`. The endpoints below let the UI
# read those suggestions, accept one (which files the scene through
# the same pipeline a phash hit would use), reject one (so it never
# resurfaces for that file), or re-run the search on demand.

@app.get("/api/queue/duplicates")
async def api_queue_duplicates():
    """Perceptual-hash duplicate groups among videos currently in source_dir."""
    return await run_in_threadpool(_queue_duplicate_groups_payload)


@app.get("/api/queue/duplicates/count")
async def api_queue_duplicates_count():
    payload = await run_in_threadpool(_queue_duplicate_groups_payload)
    return {
        "groups": int(payload.get("group_count") or 0),
        "files": int(payload.get("file_count") or 0),
        "no_phash_count": int(payload.get("no_phash_count") or 0),
    }


@app.post("/api/queue/duplicates/compute-phash")
async def api_queue_duplicates_compute_phash():
    """Compute and cache phash for queue files that lack one (enables grouping)."""
    payload = await run_in_threadpool(
        lambda: _queue_duplicate_groups_payload(compute_missing_phash=True)
    )
    return {"ok": True, **payload}


@app.post("/api/queue/duplicates/ignore")
async def api_queue_duplicates_ignore(payload: dict = Body(...)):
    ph = (payload.get("phash") or "").strip()
    if not ph:
        return JSONResponse({"ok": False, "error": "phash required"}, status_code=400)
    raw_ig = payload.get("ignored")
    if raw_ig is None:
        return JSONResponse({"ok": False, "error": "ignored required"}, status_code=400)
    want = raw_ig in (True, 1, "1", "true")
    await run_in_threadpool(_queue_duplicate_ignored_set_phash, ph, want)
    return {"ok": True, "ignored": bool(want)}


@app.post("/api/queue/duplicates/resolve-one")
async def api_queue_duplicates_resolve_one(payload: dict = Body(...)):
    """Keep one queue file; delete the rest in the group (same quality rules as /health)."""
    keep_fn = (payload.get("keep_filename") or "").strip()
    delete_fns = payload.get("delete_filenames")
    if not isinstance(delete_fns, list):
        return JSONResponse({"error": "delete_filenames must be a list"}, status_code=400)
    r = await run_in_threadpool(_queue_duplicate_resolve_one_sync, keep_fn, delete_fns)
    if not r.get("ok"):
        return JSONResponse(r, status_code=400)
    return {"ok": True, "freed_bytes": r.get("freed_bytes", 0), "deleted": r.get("deleted", 0)}


@app.get("/api/queue/suggestions")
async def api_queue_suggestions():
    """Every unmatched file with at least one cached suggestion, plus
    its candidates ordered by score. Drives the Suggestions counter
    tile and modal in the queue UI."""
    files = await run_in_threadpool(db.queue_suggestions_all_with_files)
    files = _filter_suggestion_file_list(files)
    return {"files": files, "count": len(files)}


@app.get("/api/queue/suggestions/count")
async def api_queue_suggestions_count():
    """Light endpoint for the stat tile — pure SQL count. Content
    filters (category toggles, tag blacklist) aren't applied here
    because doing so would force a full payload load; the count may
    therefore be a few rows higher than the suggestions modal shows
    once filters drop blacklisted candidates."""
    n = await run_in_threadpool(db.queue_suggestions_count_files)
    return {"count": int(n)}


#: Per-file source-meta cache. Probing ffprobe + duration takes a
#: couple hundred ms; the suggestions modal pages through dozens of
#: files but each one is shown multiple times during a session, so
#: cache-on-first-read keeps the UI snappy.
_SOURCE_META_CACHE: dict[str, dict] = {}
_SOURCE_META_CACHE_LOCK = threading.Lock()


@app.get("/api/queue/suggestions/iafd-cast")
async def api_queue_suggestions_iafd_cast(source_id: str):
    """Return the IAFD title-page cast for a cached suggestion. Used
    by the Suggestions modal to enrich IAFD candidate cards — the
    `searchScene` scrape only carries title/year/studio, so the cards
    arrive with empty performers until this fills them in. Hits the
    `_iafd_cast_cache` populated by the suggestion pre-warmer, so the
    request usually returns instantly."""
    sid = (source_id or "").strip()
    if not sid:
        return {"performers": []}
    url = sid[len("iafd:"):] if sid.startswith("iafd:") else sid
    if not url:
        return {"performers": []}
    cast = await run_in_threadpool(_iafd_scene_detail_performers, url)
    names: list[str] = []
    seen: set[str] = set()
    for p in cast or []:
        if isinstance(p, dict):
            n = ((p.get("performer") or {}).get("name") or "").strip()
            if n and n.lower() not in seen:
                seen.add(n.lower())
                names.append(n)
    return {"performers": names}


@app.get("/api/queue/suggestions/source-meta")
async def api_queue_suggestions_source_meta(filename: str):
    """Resolution + runtime for one queue file, used by the
    Suggestions modal's file-row caption (replaces the static
    'Source video · 5-frame preview' text). Cached in-process so
    re-renders of the same file are instant."""
    fn = (filename or "").strip()
    if not fn:
        return {"width": None, "height": None, "duration_sec": None}
    with _SOURCE_META_CACHE_LOCK:
        hit = _SOURCE_META_CACHE.get(fn)
        if hit is not None:
            return hit

    def _probe() -> dict:
        settings = db.get_settings()
        source_dir = Path(settings.get("source_dir", "") or "")
        video = db.resolve_source_video_path(source_dir, fn)
        if video is None or not video.is_file():
            return {"width": None, "height": None, "duration_sec": None}
        _, w, h = probe_video_stream_meta(video)
        try:
            dur = get_video_duration(video) or 0
        except Exception:
            dur = 0
        return {
            "width": int(w) if w else None,
            "height": int(h) if h else None,
            "duration_sec": int(dur) if dur else None,
        }

    meta = await run_in_threadpool(_probe)
    with _SOURCE_META_CACHE_LOCK:
        _SOURCE_META_CACHE[fn] = meta
    return meta


@app.post("/api/queue/suggestions/run")
async def api_queue_suggestions_run(payload: dict = Body(default={})):
    """Manual re-run of the name search for one file (or every
    unmatched file when ``filename`` is omitted)."""
    filename = (payload or {}).get("filename") or ""
    if filename:
        n = await run_in_threadpool(_run_name_search_for_file, filename)
        return {"ok": True, "filename": filename, "added": int(n)}
    # All-unmatched mode — fan out one thread per file. Capped via the
    # internal pool so a thousand-file backlog doesn't all hit the
    # source DBs at once.
    def _run_all() -> dict:
        with db.get_conn() as conn:
            rows = conn.execute(
                "SELECT filename FROM processed_files WHERE status = 'unmatched'"
            ).fetchall()
        names = [r["filename"] for r in rows]
        from concurrent.futures import ThreadPoolExecutor
        with ThreadPoolExecutor(max_workers=4) as pool:
            list(pool.map(_run_name_search_for_file, names))
        return {"scanned": len(names)}
    res = await run_in_threadpool(_run_all)
    return {"ok": True, **res}


@app.post("/api/queue/suggestions/reject")
async def api_queue_suggestions_reject(payload: dict = Body(...)):
    """Persist a rejection and drop the candidate row. The (filename,
    source_db, source_id) tuple stays in `queue_suggestion_rejects`
    forever so future name-search passes skip it."""
    filename  = (payload.get("filename") or "").strip()
    source_db = (payload.get("source_db") or "").strip()
    source_id = (payload.get("source_id") or "").strip()
    if not filename or not source_db or not source_id:
        return JSONResponse(
            {"error": "filename, source_db, source_id required"}, status_code=400
        )
    n = await run_in_threadpool(
        db.queue_suggestions_reject, filename, source_db, source_id
    )
    return {"ok": True, "removed": int(n)}


def _filter_breakdown_to_filename_performer(
    scenes: list[dict], filename: str,
) -> list[dict]:
    """Narrow a scene-picker breakdown using cues from the filename.

    Two passes, in order:
      1. **Scene number** — when the filename literally names a scene
         ('Movie Scene 12.mp4'), and the breakdown contains a scene
         with that number, return only that one. Beats every other
         heuristic since the filename is an explicit user signal.
      2. **Library performer** — fall back to scenes whose cast
         intersects with the performer the library index detects
         from the filename.

    When neither narrows the list, the full breakdown is returned so
    the user still has something to pick from. The Suggestions modal
    auto-pins whenever the filtered list collapses to a single entry.
    """
    if not scenes or not filename:
        return scenes
    # 1. Direct scene-number index.
    sn = _extract_scene_number_from_filename(filename)
    if sn is not None:
        for sc in scenes:
            try:
                if int(sc.get("number") or 0) == sn:
                    return [sc]
            except (TypeError, ValueError):
                continue
    # 2. Performer-cast intersection.
    try:
        guess = db._library_guess_from_release_name(Path(filename).stem)
        perfs = [p.strip() for p in (guess.get("performers") or []) if p and p.strip()]
    except Exception:
        return scenes
    if not perfs:
        return scenes
    targets = {p.lower() for p in perfs}
    filtered: list[dict] = []
    for sc in scenes:
        cast_lower = {
            (c or "").strip().lower()
            for c in (sc.get("cast") or [])
            if (c or "").strip()
        }
        if cast_lower & targets:
            filtered.append(sc)
    return filtered if filtered else scenes


@app.get("/api/queue/suggestions/iafd-breakdown")
async def api_queue_suggestions_iafd_breakdown(filename: str, source_id: str):
    """Return the IAFD per-scene breakdown for a cached suggestion.
    The Suggestions modal calls this when the user clicks Accept on
    an IAFD candidate so the user can drill into the right scene
    before the file is committed (IAFD title pages are movie-level,
    so a one-click accept would file the comp-cast against a
    single-scene file).

    The breakdown is filtered to scenes featuring the filename's
    detected performer when possible — if that yields exactly one
    scene, the Suggestions modal auto-pins it on the user's behalf.
    """
    candidates = await run_in_threadpool(db.queue_suggestions_for_file, filename)
    match = next(
        (c for c in candidates
         if c["source_db"] == "IAFD" and c["source_id"] == source_id),
        None,
    )
    if not match:
        return JSONResponse({"error": "suggestion not found"}, status_code=404)
    try:
        scene = json.loads(match.get("payload_json") or "{}")
    except Exception:
        scene = {}
    iafd_url = (scene.get("_iafd_url") or "").strip()
    if not iafd_url and isinstance(scene.get("id"), str) and scene["id"].startswith("iafd:"):
        iafd_url = scene["id"][len("iafd:"):]
    if not iafd_url:
        return {"scenes": [], "movie_cast": []}
    scenes = await run_in_threadpool(_iafd_scene_breakdowns, iafd_url)
    scenes = _filter_breakdown_to_filename_performer(scenes, filename)
    movie_cast = await run_in_threadpool(_iafd_scene_detail_performers, iafd_url)
    return {"scenes": scenes, "movie_cast": movie_cast, "iafd_url": iafd_url}


@app.get("/api/queue/suggestions/tpdb-breakdown")
async def api_queue_suggestions_tpdb_breakdown(filename: str, source_id: str):
    """TPDB analogue of the IAFD breakdown endpoint. When the cached
    suggestion's TPDB scene is part of a movie (multi-scene feature),
    return the sibling scene list so the user can pin the right one
    before the suggestion is filed. When no parent movie exists (web
    scene with no compilation context), returns an empty `scenes` list
    and the accept flow falls through to a one-click file."""
    candidates = await run_in_threadpool(db.queue_suggestions_for_file, filename)
    match = next(
        (c for c in candidates
         if c["source_db"] == "TPDB" and c["source_id"] == source_id),
        None,
    )
    if not match:
        return JSONResponse({"error": "suggestion not found"}, status_code=404)
    scenes = await run_in_threadpool(_tpdb_scene_breakdowns, source_id)
    scenes = _filter_breakdown_to_filename_performer(scenes, filename)
    return {"scenes": scenes}


@app.post("/api/queue/suggestions/accept")
async def api_queue_suggestions_accept(payload: dict = Body(...)):
    """Run the chosen suggestion through `file_scene_from_match`. On
    success the file is moved + NFO/poster/fanart written + media
    server pinged, exactly the same path a phash hit takes. The
    suggestion rows for that file are cleared regardless so the row
    stops appearing in the modal.

    Optional `scene_override` (dict) is shallow-merged into the cached
    scene payload before filing — used by the IAFD scene picker to
    pin the user-chosen scene's performers + title onto the movie-
    level payload (since IAFD title pages don't carry per-scene
    metadata in the search result)."""
    filename  = (payload.get("filename") or "").strip()
    source_db = (payload.get("source_db") or "").strip()
    source_id = (payload.get("source_id") or "").strip()
    scene_override = payload.get("scene_override")
    if not filename or not source_db or not source_id:
        return JSONResponse(
            {"error": "filename, source_db, source_id required"}, status_code=400
        )

    def _accept() -> dict:
        # Pull the cached scene payload — we already have a stash-box
        # shaped dict from the original search call, no need to re-hit
        # the source DB.
        candidates = db.queue_suggestions_for_file(filename)
        match = next(
            (c for c in candidates
             if c["source_db"] == source_db and c["source_id"] == source_id),
            None,
        )
        if not match:
            return {"status": "error", "error": "suggestion not found"}
        try:
            scene = json.loads(match.get("payload_json") or "{}")
        except Exception:
            scene = {}
        if not scene or not scene.get("id"):
            return {"status": "error", "error": "suggestion payload missing"}
        if isinstance(scene_override, dict) and scene_override:
            # Shallow merge — caller-supplied keys win. Used to pin a
            # picked IAFD/TPDB scene's performers + title onto the
            # cached movie-level payload.
            scene = {**scene, **scene_override}
        else:
            # No explicit override (no breakdown picker fired) — but if
            # the filename literally names a scene number, append
            # ' - Scene N' to the title so two files matched against the
            # same parent record (e.g. `Movie Scene 5.mp4` and
            # `Movie Scene 8.mp4` both filing through one Stash scene
            # whose breakdown is empty) don't collide on a single
            # destination filename. Without this, `_quality_gate_move`
            # would silently delete one of them as a "duplicate".
            sn_hint = _extract_scene_number_from_filename(filename)
            if sn_hint is not None:
                base_title = (scene.get("title") or "").strip()
                scene = {
                    **scene,
                    "title": (
                        f"{base_title} - Scene {sn_hint}"
                        if base_title else f"Scene {sn_hint}"
                    ),
                }
        settings = db.get_settings()
        source_dir = Path(settings.get("source_dir", "") or "")
        video = db.resolve_source_video_path(source_dir, filename)
        if video is None or not video.is_file():
            return {"status": "error", "error": "source file not found"}
        result = file_scene_from_match(video, scene, source=source_db)
        # Only drop cached suggestions on a successful file — `no_dir` /
        # `error` results may be transient (missing dest folder, network
        # blip on poster fetch) and the user might want to retry the
        # same accept later.
        if result.get("status") == "filed":
            db.queue_suggestions_clear(filename)
        return result

    res = await run_in_threadpool(_accept)
    return {"ok": (res.get("status") == "filed"), **res}


# ── Scene-in-library check (phash crosswalk) ───────────────────────

# Stash-box findScene query — pulls fingerprints for the scene id so we
# can populate scene_fingerprints. Used as a backfill when /api/library/
# scenes-in is asked about scenes we haven't crosswalked yet. The schema
# is shared by StashDB and FansDB; ThePornDB doesn't expose phash via
# its public scene endpoint, so TPDB lookups are skipped here.
STASHBOX_SCENE_FINGERPRINTS_QUERY = """
query SceneFingerprints($id: ID!) {
  findScene(id: $id) {
    id
    fingerprints { hash algorithm duration }
  }
}
"""

_LIBRARY_SCENES_BACKFILL_LOCK = threading.Lock()
_LIBRARY_SCENES_BACKFILL_PENDING: set[tuple[str, str]] = set()


def _library_scene_backfill_worker(pairs: list[tuple[str, str]]) -> None:
    """Best-effort fingerprint backfill — fetched off the request path
    so /api/library/scenes-in returns immediately. Subsequent calls for
    the same pair pick up the now-cached fingerprints. Handles all
    three sources:
      • stashdb / fansdb — GraphQL findScene(id).fingerprints
      • tpdb              — REST /scenes/{id} scene.hashes (and the
                            top-level scene.hash field on older
                            entries). Extracted via the existing
                            phash-aware helpers."""
    s = db.get_settings()
    sk = (s.get("api_key_stashdb") or "").strip()
    fk = (s.get("api_key_fansdb")  or "").strip()
    jk = (s.get("api_key_javstash") or "").strip()
    for src, sid in pairs:
        try:
            if src == "stashdb" and sk:
                ep, key = STASHDB_ENDPOINT, sk
                data = _stashbox_post(ep, key, STASHBOX_SCENE_FINGERPRINTS_QUERY, {"id": sid})
                scn = data.get("findScene") or {}
                fps = scn.get("fingerprints") or []
                if fps:
                    db.scene_fingerprints_upsert(src, sid, fps)
            elif src == "fansdb" and fk:
                ep, key = FANSDB_ENDPOINT, fk
                data = _stashbox_post(ep, key, STASHBOX_SCENE_FINGERPRINTS_QUERY, {"id": sid})
                scn = data.get("findScene") or {}
                fps = scn.get("fingerprints") or []
                if fps:
                    db.scene_fingerprints_upsert(src, sid, fps)
            elif src == "javstash" and jk:
                data = _stashbox_post(JAVSTASH_ENDPOINT, jk, STASHBOX_SCENE_FINGERPRINTS_QUERY, {"id": sid})
                scn = data.get("findScene") or {}
                fps = scn.get("fingerprints") or []
                if fps:
                    db.scene_fingerprints_upsert(src, sid, fps)
            elif src == "tpdb":
                # TPDB returns hashes on the per-scene detail endpoint
                # (the listing only carries summary fields). Extract
                # phash + duration and shape into stash-box-compatible
                # fingerprint dicts so scene_fingerprints_upsert lands
                # them correctly.
                resp = requests.get(
                    f"https://api.theporndb.net/scenes/{quote(sid, safe='')}",
                    headers=_tpdb_headers(),
                    timeout=12,
                )
                if resp.status_code != 200:
                    continue
                detail = (resp.json() or {}).get("data") or {}
                fps_out: list[dict] = []
                # Hashes can land as a list of {type, hash, duration}
                # or a dict of {phash:..., oshash:...}. Both shapes
                # carry through here — strip case, prefer phash, drop
                # anything we can't normalise.
                hashes = detail.get("hashes")
                if isinstance(hashes, list):
                    for h in hashes:
                        if not isinstance(h, dict):
                            continue
                        ht = (h.get("type") or "").strip().upper()
                        hv = (h.get("hash") or "").strip().lower()
                        if not hv:
                            continue
                        if ht and ht not in ("PHASH", "OSHASH", "MD5"):
                            continue
                        fps_out.append({
                            "hash": hv,
                            "algorithm": ht or "PHASH",
                            "duration": int(h.get("duration") or 0) or None,
                        })
                elif isinstance(hashes, dict):
                    for algo_key in ("phash", "oshash", "md5"):
                        v = hashes.get(algo_key) or hashes.get(algo_key.upper())
                        if v:
                            fps_out.append({
                                "hash": str(v).strip().lower(),
                                "algorithm": algo_key.upper(),
                            })
                # Some legacy TPDB entries also surface a top-level
                # `hash` field — pick it up if hashes was empty.
                if not fps_out and detail.get("hash"):
                    fps_out.append({
                        "hash": str(detail["hash"]).strip().lower(),
                        "algorithm": "PHASH",
                    })
                if fps_out:
                    db.scene_fingerprints_upsert(src, sid, fps_out)
                # Cross-source fallback: TPDB scenes often don't carry
                # phashes on their own record, but they DO link out to
                # StashDB / FansDB via `stash_ids`. If the linked stash-
                # box scene already has fingerprints cached (from the
                # reverse seeder or a prior backfill), copy them onto
                # the TPDB id so step 2 of `library_match_scenes` can
                # resolve a TPDB browse against a StashDB-side hit.
                stash_ids = detail.get("stash_ids") or []
                if isinstance(stash_ids, list):
                    for si in stash_ids:
                        if not isinstance(si, dict):
                            continue
                        ep = (si.get("endpoint") or "").lower()
                        sid_x = (si.get("stash_id") or "").strip()
                        if not sid_x:
                            continue
                        if "stashdb" in ep:
                            x_src = "stashdb"
                        elif "fansdb" in ep:
                            x_src = "fansdb"
                        else:
                            continue
                        try:
                            with db.get_conn() as _conn:
                                _cur = _conn.execute(
                                    "SELECT phash, algorithm, duration "
                                    "FROM scene_fingerprints "
                                    "WHERE source = ? AND scene_id = ?",
                                    (x_src, sid_x),
                                )
                                copied = [
                                    {
                                        "hash": r["phash"],
                                        "algorithm": r["algorithm"] or "PHASH",
                                        "duration": r["duration"],
                                    }
                                    for r in _cur.fetchall()
                                    if r["phash"]
                                ]
                            if copied:
                                db.scene_fingerprints_upsert(src, sid, copied)
                        except Exception:
                            pass
            else:
                continue
        except Exception as exc:
            _log.debug("scenes-in backfill %s/%s failed: %s", src, sid, exc)
        finally:
            with _LIBRARY_SCENES_BACKFILL_LOCK:
                _LIBRARY_SCENES_BACKFILL_PENDING.discard((src, sid))


@app.post("/api/library/scenes-in")
async def api_library_scenes_in(payload: dict = Body(...)):
    """Bulk "do I have this scene in my library?" lookup.

    Body accepts either of:
      ``{"pairs": [["stashdb","<id>"], ["tpdb","<id>"], ...]}`` (legacy)
      ``{"items": [{"source", "id", "title"?, "date"?, "studio"?}, ...]}``

    Returns ``{"matches": {"<source>:<scene_id>": {"row_id": int}, ...}}``
    — only matched scenes appear in the dict. Three strategies tried in
    order: id direct hit on processed_files → phash crosswalk via
    scene_fingerprints → title+date fallback on processed_files (catches
    files imported via a different stash-box than the one being browsed).
    Scenes with no fingerprints cached yet are queued for a background
    backfill so the next browse picks them up.
    """
    items: list = payload.get("items") or []
    if not items:
        # Legacy `pairs` form — promote to dict items so the matcher's
        # title/date fallback simply has nothing to fall back on.
        items = payload.get("pairs") or []
    pairs: list[tuple[str, str]] = []
    norm_items: list[dict] = []
    for entry in items:
        if isinstance(entry, dict):
            src = str(entry.get("source") or "").strip().lower()
            sid = str(entry.get("id") or "").strip()
            if not src or not sid:
                continue
            norm_items.append({
                "source": src, "id": sid,
                "title": entry.get("title") or "",
                "date": entry.get("date") or "",
                "studio": entry.get("studio") or "",
            })
            pairs.append((src, sid))
        elif isinstance(entry, (list, tuple)) and len(entry) >= 2:
            src = str(entry[0] or "").strip().lower()
            sid = str(entry[1] or "").strip()
            if src and sid:
                norm_items.append({"source": src, "id": sid, "title": "", "date": "", "studio": ""})
                pairs.append((src, sid))

    matches = db.library_match_scenes(norm_items)

    # Backfill: any unmatched scene whose fingerprints we haven't seen
    # yet. We BLOCK on the backfill (with a tight time budget) so the
    # response includes any matches the source DB can confirm during
    # this round-trip. Anything that didn't make the budget falls back
    # to the async worker so a follow-up call still benefits.
    if pairs:
        unmatched = [
            (s, i) for (s, i) in pairs
            if f"{s}:{i}" not in matches and s in ("stashdb", "fansdb", "tpdb", "javstash")
        ]
        if unmatched:
            known: set[str] = set()
            for src in ("stashdb", "fansdb", "tpdb", "javstash"):
                ids_for_src = [i for (s, i) in unmatched if s == src]
                if ids_for_src:
                    known |= {f"{src}:{x}" for x in db.scene_fingerprints_known_ids(src, ids_for_src)}
            todo: list[tuple[str, str]] = []
            with _LIBRARY_SCENES_BACKFILL_LOCK:
                for (s, i) in unmatched:
                    if f"{s}:{i}" in known:
                        continue
                    if (s, i) in _LIBRARY_SCENES_BACKFILL_PENDING:
                        continue
                    _LIBRARY_SCENES_BACKFILL_PENDING.add((s, i))
                    todo.append((s, i))
            if todo:
                # In-budget portion runs synchronously so the user gets
                # a fresh match on first load; the rest is queued.
                _SYNC_BACKFILL_BUDGET = 6
                _SYNC_BACKFILL_DEADLINE_S = 3.0
                sync_chunk = todo[:_SYNC_BACKFILL_BUDGET]
                async_chunk = todo[_SYNC_BACKFILL_BUDGET:_SYNC_BACKFILL_BUDGET + 30]
                if sync_chunk:
                    sync_thread = threading.Thread(
                        target=_library_scene_backfill_worker,
                        args=(sync_chunk,),
                        daemon=True,
                        name="lib-scenes-fp-backfill-sync",
                    )
                    sync_thread.start()
                    sync_thread.join(_SYNC_BACKFILL_DEADLINE_S)
                    # Re-run match for the freshly-backfilled scenes —
                    # whatever landed in scene_fingerprints will now be
                    # caught by step 2.
                    sync_pairs_set = set(sync_chunk)
                    rerun_items = [
                        it for it in norm_items
                        if (str(it["source"]).lower(), str(it["id"])) in sync_pairs_set
                        and f"{it['source']}:{it['id']}" not in matches
                    ]
                    if rerun_items:
                        more = db.library_match_scenes(rerun_items)
                        for k, v in more.items():
                            matches.setdefault(k, v)
                if async_chunk:
                    threading.Thread(
                        target=_library_scene_backfill_worker,
                        args=(async_chunk,),
                        daemon=True, name="lib-scenes-fp-backfill",
                    ).start()

    return {"matches": matches}


@app.get("/api/library/check")
async def library_check(
    name: str = "",
    kind: str = "",
    stash_id: str = "",
    tpdb_id: str = "",
    fans_id: str = "",
    javstash_id: str = "",
):
    """Check if a performer/studio exists on disk or in the favourites index.

    Discover passes ``kind`` + source ids so JAVStash rows match Stash-indexed
    library folders, and ``kind=performer`` enables alias matching (e.g. Japanese
    display names stored in ``aliases_json``).
    """
    k = (kind or "").strip().lower()
    s = db.get_settings()
    dirs = [
        s.get("series_dir", ""),
        s.get("features_dir", ""),
    ] + [d["path"] for d in db.get_directories()]
    jav_d = (s.get("jav_dir") or "").strip()
    if jav_d:
        dirs.append(jav_d)

    def _hit(path: Path) -> dict:
        return {"found": True, "path": str(path), "dir": str(path.parent)}

    tid = (tpdb_id or "").strip()
    sid = (stash_id or "").strip()
    fid = (fans_id or "").strip()
    jid = (javstash_id or "").strip()

    def _hit_with_links(row: dict, p: Path) -> dict:
        # Surface the favourites row's stored crosswalk IDs so callers
        # (e.g. /discover loadScenes) can fetch scenes from every linked
        # DB without doing their own name-search across DBs.
        out = _hit(p)
        out["row_id"] = row.get("id")
        out["linked_ids"] = {
            "tpdb":     (row.get("match_tpdb_id") or "").strip(),
            "stashdb":  (row.get("match_stashdb_id") or "").strip(),
            "fansdb":   (row.get("match_fansdb_id") or "").strip(),
            "javstash": (row.get("match_javstash_id") or "").strip(),
        }
        return out

    any_id_provided = bool(tid or sid or fid or jid)

    if k == "studio" and (tid or sid or fid):
        row = db.favourite_find_studio_folder_by_crosswalk(
            tid or None, sid or None, fid or None
        )
        if row:
            p = Path(row["path"])
            if p.is_dir():
                return _hit_with_links(row, p)
    elif k == "performer" and (tid or sid or fid or jid):
        row = db.favourite_find_performer_folder_by_crosswalk(
            tid or None, sid or None, fid or None, jid or None
        )
        if row:
            p = Path(row["path"])
            if p.is_dir():
                return _hit_with_links(row, p)

    # When the caller supplied any source ID, treat ID match as
    # authoritative — don't fall back to name/alias scanning. A
    # same-named performer on disk without a linked profile shouldn't
    # be claimed as "in library" for a Discover hit from a specific DB.
    if any_id_provided:
        return {"found": False}

    norm = normalise(name) if (name or "").strip() else ""
    if norm:
        for dir_path in dirs:
            if not dir_path:
                continue
            base = Path(dir_path)
            if not base.exists():
                continue
            for folder in base.iterdir():
                if folder.is_dir() and normalise(folder.name) == norm:
                    return _hit(folder)

    if k == "performer" and norm:
        for entity in db.favourite_list():
            if entity.get("kind") != "performer":
                continue
            raw = entity.get("aliases_json")
            if not raw:
                continue
            try:
                aliases = json.loads(raw) if isinstance(raw, str) else raw
            except (json.JSONDecodeError, TypeError):
                continue
            for alias in _performer_aliases_as_strings(aliases):
                if normalise(alias) == norm:
                    pth = (entity.get("path") or "").strip()
                    if not pth:
                        continue
                    p = Path(pth)
                    if p.is_dir():
                        return _hit(p)

    return {"found": False}


@app.get("/api/metadata/search")
async def metadata_search(
    q: str,
    type: str = "performer",
    genders: str = "",
    strict: str = "",
):
    if not q.strip():
        return JSONResponse({"error": "Query required"}, status_code=400)
    if type == "studio":
        results = search_studios(q.strip())
    else:
        allow: frozenset[str] | None = None
        if genders.strip():
            parts = [
                x.strip()
                for x in genders.split(",")
                if x.strip() in ALLOWED_GENDER_BUCKETS
            ]
            if parts:
                allow = frozenset(parts)
        # Default strict (exact normalised name): Stash/TPDB/Fans search is fuzzy; disable with strict=0 (e.g. Scenes browse).
        s = (strict or "").strip().lower()
        strict_name = s not in ("0", "false", "no", "off")
        results = search_performers(
            q.strip(),
            gender_allowlist=allow,
            strict_name_match=strict_name,
        )
    return {"results": results}


def _fetch_performer_detail_javstash_by_name(name: str) -> dict | None:
    """Resolve a JAVStash performer by exact name when find-by-id fails."""
    q = (name or "").strip()
    if not q:
        return None
    hits = [
        r for r in search_performers(q, strict_name_match=True)
        if r.get("source") == "JAVStash" and (r.get("id") or "")
    ]
    if not hits:
        return None
    return fetch_performer_detail("JAVStash", str(hits[0]["id"]))


@app.post("/api/metadata/create")
async def metadata_create(payload: dict):
    """
    Fetch full metadata and create tvshow.nfo + poster in the chosen directory.
    Accepts: type (performer|studio), source (TPDB|StashDB|FansDB|JAVStash), id, dest_dir
    """
    mtype   = payload.get("type", "performer")
    source  = _normalize_metadata_db_source(payload.get("source", "TPDB"))
    mid     = str(payload.get("id") or "").strip()
    dest    = payload.get("dest_dir", "")
    requested_source = source
    requested_id = mid
    jav_payload_id = str(payload.get("javstash_id") or "").strip()
    if jav_payload_id and (source == "JAVStash" or not mid):
        source = "JAVStash"
        mid = jav_payload_id or mid
        requested_source = "JAVStash"
        requested_id = mid

    if not all([mid, dest]):
        return JSONResponse({"error": "id and dest_dir required"}, status_code=400)

    dest_path = Path(dest)
    if not dest_path.exists():
        return JSONResponse({"error": f"Directory not found: {dest}"}, status_code=404)

    if mtype == "performer":
        data = fetch_performer_detail(source, mid)
        if not data:
            # Retry once
            emit(f"CREATE: fetch_performer_detail({source}, {mid}) failed, retrying…")
            import time as _time; _time.sleep(1)
            data = fetch_performer_detail(source, mid)
        if not data and source == "JAVStash":
            name_q = (payload.get("name") or "").strip()
            emit(f"CREATE: trying JAVStash name search for {name_q!r}")
            data = _fetch_performer_detail_javstash_by_name(name_q)
        if not data and source != "TPDB":
            emit(f"CREATE: trying TPDB fallback for {mid}")
            try:
                name_q = payload.get("name") or ""
                if name_q:
                    sr = requests.get(TPDB_PERFORMER_SEARCH, params={"q": name_q}, headers=_tpdb_headers(), timeout=10)
                    if sr.status_code == 200:
                        hits = sr.json().get("data") or []
                        if hits:
                            data = fetch_performer_detail("TPDB", str(hits[0].get("id") or ""))
            except Exception:
                pass
        if not data:
            emit(f"CREATE: all sources failed for {source}/{mid}")
            return JSONResponse({"error": f"Failed to fetch performer data from {source} (id: {mid})"}, status_code=500)
        if requested_source == "JAVStash" and requested_id:
            data = dict(data)
            data["javstash_id"] = requested_id
        db_name = (data.get("name") or "Unknown").strip() or "Unknown"
        folder_label = _sanitize_fs_component(
            (payload.get("folder_name") or "").strip() or db_name
        )
        canonical = (payload.get("name") or "").strip()
        client_aliases = payload.get("aliases")
        if not isinstance(client_aliases, list):
            client_aliases = []
        initial_aliases = _performer_initial_aliases_for_folder(
            folder_label,
            canonical=canonical,
            db_name=db_name,
            client_aliases=client_aliases,
        )
        data_nfo = dict(data)
        data_nfo["name"] = folder_label
        nfo        = build_performer_tvshow_nfo(data_nfo)
        posters    = data.get("posters") or []
        poster_url = posters[0].get("url") if posters and isinstance(posters[0], dict) else (posters[0] if posters else None)
        folder = create_tvshow_folder(folder_label, dest_path, nfo, poster_url)
        name = folder_label
        has_poster = poster_url is not None
        performer_initial_aliases = initial_aliases
    else:
        data = fetch_studio_detail(source, mid)
        if not data:
            return JSONResponse({"error": "Failed to fetch studio data"}, status_code=500)
        name      = data.get("name") or data.get("title", "Unknown")
        nfo       = build_studio_tvshow_nfo(data)
        logo_url = _tpdb_scalar_media_url(data.get("logo"))
        poster_url = _tpdb_scalar_media_url(data.get("poster"))
        if not logo_url and not poster_url:
            poster_url = _tpdb_site_image_url(data)
        folder = create_tvshow_folder(
            name, dest_path, nfo, poster_url, logo_url=logo_url
        )
        has_poster = bool(logo_url or poster_url)
        performer_initial_aliases = None

    fav_row_id = _favourites_index_created_folder(
        "performer" if mtype == "performer" else "studio",
        folder,
        dest_path,
        create_source=requested_source if mtype == "performer" else None,
        create_id=requested_id if mtype == "performer" else None,
        create_name=(name if mtype == "performer" else None),
        initial_aliases=performer_initial_aliases if mtype == "performer" else None,
    )
    if fav_row_id:
        _performer_popup_cache_invalidate_row(fav_row_id)

    detail_bits: list[str] = []
    if has_poster:
        detail_bits.append("poster downloaded")
    if fav_row_id:
        detail_bits.append("added to favourites index")
    extra = (" · " + " · ".join(detail_bits)) if detail_bits else ""
    emit(f"Created {mtype} library folder: {folder}{extra}")
    try:
        db.notification_add(
            "library",
            f"✓ Created: {folder}",
            ttl_seconds=300,
        )
    except Exception:
        pass

    return {
        "success":    True,
        "name":       name,
        "folder":     str(folder),
        "has_poster": has_poster,
        "favourites_indexed": bool(fav_row_id),
        "row_id":     fav_row_id,
    }


# ---------------------------------------------------------------------------
# Discover / recent-scenes: persistent JPEG cache for remote thumbnails
# ---------------------------------------------------------------------------

_DISCOVER_DISK_IMG_LOCK_GUARD = threading.Lock()
_DISCOVER_DISK_IMG_LOCKS: dict[str, threading.Lock] = {}


def _discover_image_cache_dir() -> Path:
    """On-disk cache for images used by /discover (gallery + scene tiles)."""
    d = _metadata_base_dir() / "discover_cache"
    d.mkdir(parents=True, exist_ok=True)
    return d


def _discover_image_disk_hash(url: str) -> str:
    return hashlib.sha256((url or "").strip().encode("utf-8")).hexdigest()


def _discover_image_disk_lock(h: str) -> threading.Lock:
    with _DISCOVER_DISK_IMG_LOCK_GUARD:
        lo = _DISCOVER_DISK_IMG_LOCKS.get(h)
        if lo is None:
            lo = threading.Lock()
            _DISCOVER_DISK_IMG_LOCKS[h] = lo
        return lo


def _discover_download_to_cache_path(url: str, dest: Path) -> bool:
    try:
        resp = requests.get(
            url,
            timeout=25,
            headers={"User-Agent": "Top-Shelf/1.0 (discover image cache)"},
        )
        if resp.status_code != 200:
            return False
        return save_image_bytes_optimized(
            resp.content,
            dest,
            max_edge=IMAGE_CACHE_SCENE_THUMB_MAX,
        )
    except Exception:
        return False


def _discover_ensure_cached_image_url(url: str) -> str:
    """Return same-origin cache URL when the cached image exists or
    downloads successfully; else raw URL. New caches write WebP; legacy
    JPEG files on disk are still served via the lookup endpoint."""
    u = (url or "").strip()
    if not u.startswith("http://") and not u.startswith("https://"):
        return u
    h = _discover_image_disk_hash(u)
    cache_dir = _discover_image_cache_dir()
    webp_path = cache_dir / f"{h}.webp"
    jpg_path = cache_dir / f"{h}.jpg"
    try:
        if webp_path.is_file() and webp_path.stat().st_size > 200:
            return f"/api/discover/cached-image/{h}"
        if jpg_path.is_file() and jpg_path.stat().st_size > 200:
            return f"/api/discover/cached-image/{h}"
    except OSError:
        pass
    lock = _discover_image_disk_lock(h)
    with lock:
        try:
            if webp_path.is_file() and webp_path.stat().st_size > 200:
                return f"/api/discover/cached-image/{h}"
            if jpg_path.is_file() and jpg_path.stat().st_size > 200:
                return f"/api/discover/cached-image/{h}"
        except OSError:
            pass
        if _discover_download_to_cache_path(u, webp_path):
            try:
                if webp_path.is_file() and webp_path.stat().st_size > 200:
                    return f"/api/discover/cached-image/{h}"
            except OSError:
                pass
    return u


def _discover_rewrite_image_url_list(urls: list[str]) -> list[str]:
    if not urls:
        return urls
    with ThreadPoolExecutor(max_workers=8) as pool:
        return list(pool.map(_discover_ensure_cached_image_url, urls))


# Background worker pool for opportunistic image warming. We spin it up
# lazily so the import sequence stays cheap on startup.
_DISCOVER_CACHE_WARM_POOL: ThreadPoolExecutor | None = None
_DISCOVER_CACHE_WARM_LOCK = threading.Lock()
# Hashes we've already enqueued for warming this process lifetime — keeps
# the same URL from being re-submitted every time a feed refresh runs.
_DISCOVER_CACHE_WARM_INFLIGHT: set[str] = set()


def _discover_cache_warm_worker() -> ThreadPoolExecutor:
    global _DISCOVER_CACHE_WARM_POOL
    with _DISCOVER_CACHE_WARM_LOCK:
        if _DISCOVER_CACHE_WARM_POOL is None:
            # 4 workers is enough to warm a feed in the background without
            # crowding out request handlers. Each download is bounded by
            # _discover_download_to_cache_path's 25 s timeout.
            _DISCOVER_CACHE_WARM_POOL = ThreadPoolExecutor(
                max_workers=4, thread_name_prefix="img-warm"
            )
        return _DISCOVER_CACHE_WARM_POOL


def _discover_warm_image_async(url: str) -> None:
    """Queue a remote image for background caching. Cheap: no-op if the
    image is already on disk or if it's already been queued this process."""
    u = (url or "").strip()
    if not u.startswith("http://") and not u.startswith("https://"):
        return
    h = _discover_image_disk_hash(u)
    cache_dir = _discover_image_cache_dir()
    webp_path = cache_dir / f"{h}.webp"
    jpg_path = cache_dir / f"{h}.jpg"
    try:
        if webp_path.is_file() and webp_path.stat().st_size > 200:
            return
        if jpg_path.is_file() and jpg_path.stat().st_size > 200:
            return
    except OSError:
        pass
    with _DISCOVER_CACHE_WARM_LOCK:
        if h in _DISCOVER_CACHE_WARM_INFLIGHT:
            return
        _DISCOVER_CACHE_WARM_INFLIGHT.add(h)

    def _do() -> None:
        try:
            lock = _discover_image_disk_lock(h)
            with lock:
                try:
                    if webp_path.is_file() and webp_path.stat().st_size > 200:
                        return
                    if jpg_path.is_file() and jpg_path.stat().st_size > 200:
                        return
                except OSError:
                    pass
                _discover_download_to_cache_path(u, webp_path)
        finally:
            # Drop from the in-flight set so a later retry can run after
            # transient network failures.
            with _DISCOVER_CACHE_WARM_LOCK:
                _DISCOVER_CACHE_WARM_INFLIGHT.discard(h)

    try:
        _discover_cache_warm_worker().submit(_do)
    except Exception:
        with _DISCOVER_CACHE_WARM_LOCK:
            _DISCOVER_CACHE_WARM_INFLIGHT.discard(h)


def _discover_serve_or_warm_url(url: str) -> str:
    """Return the local cached URL if the image is already on disk;
    otherwise schedule a background download and return the raw URL so
    the current page still renders the picture. Subsequent feed loads
    pick up the cached path automatically."""
    u = (url or "").strip()
    if not u.startswith("http://") and not u.startswith("https://"):
        return u
    h = _discover_image_disk_hash(u)
    cache_dir = _discover_image_cache_dir()
    webp_path = cache_dir / f"{h}.webp"
    jpg_path = cache_dir / f"{h}.jpg"
    try:
        if webp_path.is_file() and webp_path.stat().st_size > 200:
            return f"/api/discover/cached-image/{h}"
        if jpg_path.is_file() and jpg_path.stat().st_size > 200:
            return f"/api/discover/cached-image/{h}"
    except OSError:
        pass
    _discover_warm_image_async(u)
    return u


def _scenes_feed_rewrite_thumbs(scenes: list[dict]) -> None:
    """In-place rewrite of every scene's thumb to the local cache URL.
    Misses fall back to the raw URL and trigger a background warm."""
    if not scenes:
        return
    for sc in scenes:
        if not isinstance(sc, dict):
            continue
        for field in ("thumb", "poster", "background", "image"):
            v = sc.get(field)
            if isinstance(v, str) and v.startswith("http"):
                sc[field] = _discover_serve_or_warm_url(v)


def _discover_rewrite_scene_thumbs_in_payload(payload: dict) -> None:
    """Point remote scene thumb URLs at /api/discover/cached-image/{sha} once on disk."""
    sources = payload.get("sources") or {}
    uniq: list[str] = []
    seen: set[str] = set()
    for bucket in ("tpdb", "stashdb", "fansdb", "javstash"):
        for s in sources.get(bucket) or []:
            if not isinstance(s, dict):
                continue
            t = s.get("thumb")
            if isinstance(t, str) and t.startswith("http") and t not in seen:
                seen.add(t)
                uniq.append(t)
    for s in payload.get("scenes") or []:
        if not isinstance(s, dict):
            continue
        t = s.get("thumb")
        if isinstance(t, str) and t.startswith("http") and t not in seen:
            seen.add(t)
            uniq.append(t)
    if not uniq:
        return
    with ThreadPoolExecutor(max_workers=8) as pool:
        resolved = list(pool.map(_discover_ensure_cached_image_url, uniq))
    url_map = dict(zip(uniq, resolved))
    for bucket in ("tpdb", "stashdb", "fansdb", "javstash"):
        for s in sources.get(bucket) or []:
            if isinstance(s, dict):
                t = s.get("thumb")
                if isinstance(t, str) and t in url_map:
                    s["thumb"] = url_map[t]
    for s in payload.get("scenes") or []:
        if isinstance(s, dict):
            t = s.get("thumb")
            if isinstance(t, str) and t in url_map:
                s["thumb"] = url_map[t]


_SCENES_RECENT_CACHE: dict[tuple, tuple[float, dict]] = {}
_SCENES_RECENT_CACHE_LOCK = threading.Lock()
_SCENES_RECENT_CACHE_TTL = 1800.0  # 30 min — discover panel + prewarm hit this often
_SCENES_RECENT_CACHE_MAX = 400


def get_scenes_recent_cached_or_compute(
    source: str, id: str, type: str = "performer", slug: str = "", name: str = "",
    *,
    tpdb_id: str = "",
    stashdb_id: str = "",
    fansdb_id: str = "",
    javstash_id: str = "",
) -> dict:
    """Get recent scenes for a performer or studio from all sources.
    Returns scenes grouped by source:
    ``{tpdb: [...], stashdb: [...], fansdb: [...], javstash: [...]}``.
    Cached per (source, id, type, slug, name, per-source IDs) for 30
    minutes — repeat clicks on the same tile are served from memory.
    Remote ``thumb`` URLs are rewritten to
    ``/api/discover/cached-image/{sha256}`` when the JPEG exists under
    ``metadata/discover_cache/`` (downloaded once per distinct URL).

    Strict-id only: scenes come from linked profiles, not name
    guesses. The legacy ``source + id`` pair is auto-promoted into
    the per-source ID slot, so name-fallback never runs. Each
    source bucket fetches only when its own ID is present (either
    explicitly supplied as ``tpdb_id``/``stashdb_id``/etc., or
    promoted from a matching ``source``). A search hit against one
    DB returns scenes only from that DB; to fetch scenes from
    multiple DBs the caller must pass crosswalk IDs for each (the
    /discover frontend reads these from /api/library/check when
    the entity is linked in the library)."""
    from concurrent.futures import ThreadPoolExecutor, as_completed

    explicit_ids = {
        "tpdb":     (tpdb_id or "").strip(),
        "stashdb":  (stashdb_id or "").strip(),
        "fansdb":   (fansdb_id or "").strip(),
        "javstash": (javstash_id or "").strip(),
    }
    # Auto-promote the legacy (source, id) pair into the per-source ID
    # slot so name-fallback never fires for /discover callers that
    # only pass source+id. The user's directive: scenes come only
    # from linked profiles; no cross-DB name guessing.
    _src_bucket = {
        "TPDB":     "tpdb",
        "STASHDB":  "stashdb",
        "FANSDB":   "fansdb",
        "JAVSTASH": "javstash",
    }.get((source or "").strip().upper())
    _legacy_id = (id or "").strip()
    if _src_bucket and _legacy_id and not explicit_ids[_src_bucket]:
        explicit_ids[_src_bucket] = _legacy_id
    strict_id_mode = any(explicit_ids.values())

    cache_key = (
        (source or "").strip().upper(),
        (id or "").strip(),
        (type or "performer").strip(),
        (slug or "").strip(),
        (name or "").strip().lower(),
        explicit_ids["tpdb"],
        explicit_ids["stashdb"],
        explicit_ids["fansdb"],
        explicit_ids["javstash"],
    )
    now = time.time()
    with _SCENES_RECENT_CACHE_LOCK:
        hit = _SCENES_RECENT_CACHE.get(cache_key)
        if hit and (now - hit[0]) < _SCENES_RECENT_CACHE_TTL:
            return hit[1]

    entity_type = type
    performer_name = name
    settings = db.get_settings()

    def _fetch_tpdb_scenes(*, allow_name_fallback: bool = True):
        """Fetch scenes from TPDB API.

        ``allow_name_fallback=False`` skips the name-search branch — used
        by strict-id callers (and by the last-ditch helper below, which
        re-enters with the flag set so each bucket name-searches once)."""
        try:
            tpdb_match_kind = "id"
            # Per-source ID hint wins (strict mode).
            tpdb_explicit = explicit_ids["tpdb"]
            tpdb_id = tpdb_explicit or (id if source == "TPDB" else None)
            tpdb_slug = slug if (source == "TPDB" and not tpdb_explicit) else None

            if not tpdb_id and performer_name and allow_name_fallback:
                if entity_type == "performer":
                    r = requests.get(TPDB_PERFORMER_SEARCH, params={"q": performer_name},
                                     headers=_tpdb_headers(), timeout=10)
                else:
                    r = requests.get(TPDB_STUDIO_SEARCH, params={"q": performer_name},
                                     headers=_tpdb_headers(), timeout=10)
                if r.status_code == 200:
                    data = r.json().get("data") or []
                    if data:
                        tpdb_id = str(data[0].get("id") or data[0].get("_id") or "")
                        tpdb_slug = data[0].get("slug") or data[0].get("_id") or tpdb_id
                        tpdb_match_kind = "name"

            if not tpdb_id:
                return []

            lookups = []
            if tpdb_slug and tpdb_slug != tpdb_id:
                lookups.append(tpdb_slug)
            lookups.append(tpdb_id)

            for lookup in lookups:
                url = f"https://api.theporndb.net/{'performers' if entity_type == 'performer' else 'sites'}/{lookup}/scenes"
                # Bumped per_page from 20 → 60: studio results pass through
                # the content/tag filters, and prolific studios like
                # Backroom Casting Couch were ending up with <18 cards
                # because the smaller pool was too thin to survive
                # filtering. 60 gives the 6×3 studio grid headroom.
                resp = requests.get(url, params={"page": 1, "per_page": 60},
                                    headers=_tpdb_headers(), timeout=15)
                if resp.status_code != 200:
                    continue
                data_raw = resp.json().get("data")
                if not isinstance(data_raw, list):
                    continue
                out = []
                for s in data_raw:
                    genders = _extract_movie_genders(s)
                    if not _passes_content_filter(genders):
                        continue
                    if not _passes_tag_filter(s, "tpdb"):
                        continue
                    if not _passes_title_filter(s):
                        continue
                    if not _passes_raw_scene_runtime_filter(s):
                        continue
                    # TPDB scene images, in preference order:
                    #   • `background.medium` — direct
                    #     `cdn.theporndb.net/.../background/c/...-medium.jpg`
                    #     URL (no watermark, no 800×1200 portrait
                    #     re-crop). This is the wide hero / collage
                    #     that the source site uses, sized for grid
                    #     thumbnails. All `background.{small/medium/
                    #     large/full}` keys point at the same CDN
                    #     prefix; medium is the most appropriate
                    #     thumbnail size.
                    #   • `posters.*` and the top-level `poster`
                    #     field route through `thumb.theporndb.net`,
                    #     which re-crops to portrait 800×1200 and
                    #     stamps a studio-logo watermark. Avoid.
                    #   • `image` is the original studio CDN (often
                    #     hotlink-protected); used as a last resort.
                    thumb = ""
                    bg = s.get("background") or {}
                    if isinstance(bg, dict):
                        thumb = (
                            bg.get("medium")
                            or bg.get("large")
                            or bg.get("full")
                            or bg.get("small")
                            or bg.get("url")
                            or ""
                        )
                    if not thumb:
                        thumb = s.get("image") or s.get("poster") or s.get("poster_image") or ""
                    if not thumb:
                        posters = s.get("posters") or []
                        if posters:
                            if isinstance(posters[0], str):
                                thumb = posters[0]
                            else:
                                p0 = posters[0] or {}
                                thumb = (
                                    p0.get("large")
                                    or p0.get("full")
                                    or p0.get("url")
                                    or p0.get("medium")
                                    or ""
                                )
                    perf_names = []
                    seen_pn: set[str] = set()
                    for p in s.get("performers") or s.get("credits") or []:
                        if isinstance(p, dict):
                            pn = (p.get("name") or p.get("parent", {}).get("name") or "").strip()
                            if pn:
                                k = pn.lower()
                                if k not in seen_pn:
                                    seen_pn.add(k)
                                    perf_names.append(pn)
                    out.append({
                        "id":     str(s.get("_id") or s.get("id") or ""),
                        "title":  s.get("title", ""),
                        "date":   s.get("date", ""),
                        "studio": (s.get("site") or {}).get("name", ""),
                        "performer": ", ".join(perf_names),
                        "thumb":  thumb,
                        "source": "TPDB",
                        "match":  tpdb_match_kind,
                    })
                return out
        except Exception:
            pass
        return []

    def _fetch_stashbox_scenes(endpoint: str, api_key: str, *, allow_name_fallback: bool = True):
        """Fetch scenes from a stash-box instance (StashDB, FansDB, JAVStash).

        ``allow_name_fallback=False`` skips the name-search branch (used
        by strict-id callers and the last-ditch helper)."""
        if not api_key:
            return []
        try:
            search_name = performer_name or name
            src_u = (source or "").strip().upper()
            entity_id = (id or "").strip()
            # Per-source ID hint wins (strict mode).
            if endpoint == JAVSTASH_ENDPOINT:
                bucket_key = "javstash"
                src_legacy_match = (src_u == "JAVSTASH")
            elif endpoint == FANSDB_ENDPOINT:
                bucket_key = "fansdb"
                src_legacy_match = (src_u == "FANSDB")
            else:
                bucket_key = "stashdb"
                src_legacy_match = (src_u == "STASHDB")
            explicit_pid = explicit_ids.get(bucket_key, "")
            perf_id = None
            match_kind = "id"
            if entity_type == "performer":
                if explicit_pid:
                    perf_id = explicit_pid
                elif entity_id and src_legacy_match:
                    perf_id = entity_id
            if not perf_id:
                if not allow_name_fallback or not search_name:
                    return []
                search_gql = """
                query($term: String!) {
                  searchPerformer(term: $term, limit: 1) { id name }
                }
                """
                r = requests.post(endpoint,
                    json={"query": search_gql, "variables": {"term": search_name}},
                    headers={"ApiKey": api_key, "Content-Type": "application/json"},
                    timeout=10)
                if r.status_code != 200:
                    return []
                performers = (r.json().get("data") or {}).get("searchPerformer") or []
                if not performers:
                    return []
                perf_id = performers[0]["id"]
                match_kind = "name"

            scenes_gql = """
            query($input: SceneQueryInput!) {
              queryScenes(input: $input) {
                scenes {
                  id title release_date
                  studio { name }
                  performers { as performer { id name gender } }
                  images { url width height }
                  tags { name }
                }
              }
            }
            """
            variables = {
                "input": {
                    "performers": {
                        "value": [perf_id],
                        "modifier": "INCLUDES"
                    },
                    "per_page": 60,
                    "page": 1,
                    "sort": "DATE",
                    "direction": "DESC"
                }
            }
            r2 = requests.post(endpoint,
                json={"query": scenes_gql, "variables": variables},
                headers={"ApiKey": api_key, "Content-Type": "application/json"},
                timeout=15)
            if r2.status_code != 200:
                return []
            scenes_data = (r2.json().get("data") or {}).get("queryScenes", {}).get("scenes") or []
            out = []
            src_label = (
                "JAVStash" if endpoint == JAVSTASH_ENDPOINT else
                ("FansDB" if endpoint == FANSDB_ENDPOINT else "StashDB")
            )
            src_key = (
                "javstash" if endpoint == JAVSTASH_ENDPOINT else
                ("fansdb" if endpoint == FANSDB_ENDPOINT else "stashdb")
            )
            for s in scenes_data:
                if not _passes_tag_filter(s, src_key):
                    continue
                if not _passes_title_filter(s):
                    continue
                if not _passes_raw_scene_runtime_filter(s):
                    continue
                genders = _extract_movie_genders(s)
                if not _passes_content_filter(genders):
                    continue
                imgs = s.get("images") or []
                thumb = imgs[0].get("url") if imgs and isinstance(imgs[0], dict) else None
                sb_perfs: list[str] = []
                seen_sb: set[str] = set()
                for pa in s.get("performers") or []:
                    pn = ((pa.get("performer") or {}).get("name") or pa.get("as") or "").strip()
                    if not pn:
                        continue
                    key = pn.lower()
                    if key in seen_sb:
                        continue
                    seen_sb.add(key)
                    sb_perfs.append(pn)
                jid = str(s.get("id", "") or "").strip()
                row = {
                    "id":     jid,
                    "title":  s.get("title", ""),
                    "date":   s.get("release_date", ""),
                    "studio": (s.get("studio") or {}).get("name", ""),
                    "performer": ", ".join(sb_perfs),
                    "thumb":  thumb,
                    "source": src_label,
                    "match":  match_kind,
                }
                if endpoint == JAVSTASH_ENDPOINT:
                    row["javstash_id"] = jid
                out.append(row)
            return out
        except Exception:
            pass
        return []

    # Fetch from all sources in parallel. In strict-id mode, only run
    # buckets that have their own ID hint — empty buckets stay empty
    # rather than guess by name. The legacy ``source==X`` fallback also
    # honors strict mode: if the caller supplied per-source IDs at all,
    # we trust those exclusively.
    result = {"tpdb": [], "stashdb": [], "fansdb": [], "javstash": []}
    if strict_id_mode:
        run_tpdb     = bool(explicit_ids["tpdb"])
        run_stashdb  = bool(explicit_ids["stashdb"])
        run_fansdb   = bool(explicit_ids["fansdb"])
        run_javstash = bool(explicit_ids["javstash"])
    else:
        run_tpdb = run_stashdb = run_fansdb = run_javstash = True
    # Name-fallback hard-disabled everywhere — scenes come only from
    # linked profiles (per-source IDs). Same-name performers across
    # DBs no longer leak scenes into the wrong bucket.
    with ThreadPoolExecutor(max_workers=4) as pool:
        futures = {}
        if run_tpdb:
            futures["tpdb"] = pool.submit(
                _fetch_tpdb_scenes, allow_name_fallback=False,
            )
        if run_stashdb and settings.get("api_key_stashdb"):
            futures["stashdb"] = pool.submit(
                _fetch_stashbox_scenes, STASHDB_ENDPOINT, settings["api_key_stashdb"],
                allow_name_fallback=False,
            )
        if run_fansdb and settings.get("api_key_fansdb"):
            futures["fansdb"] = pool.submit(
                _fetch_stashbox_scenes, FANSDB_ENDPOINT, settings["api_key_fansdb"],
                allow_name_fallback=False,
            )
        if run_javstash and settings.get("api_key_javstash"):
            futures["javstash"] = pool.submit(
                _fetch_stashbox_scenes, JAVSTASH_ENDPOINT, settings["api_key_javstash"],
                allow_name_fallback=False,
            )
        for key, future in futures.items():
            try:
                result[key] = future.result()
            except Exception:
                pass

    # For backward compat, also return flat "scenes" from first non-empty source
    scenes = (
        result["tpdb"] or result["stashdb"] or result["fansdb"] or result["javstash"]
    )
    payload = {"scenes": scenes, "sources": result}
    _discover_rewrite_scene_thumbs_in_payload(payload)
    with _SCENES_RECENT_CACHE_LOCK:
        if len(_SCENES_RECENT_CACHE) > _SCENES_RECENT_CACHE_MAX:
            cutoff = sorted(_SCENES_RECENT_CACHE.items(), key=lambda kv: kv[1][0])
            for k, _ in cutoff[: _SCENES_RECENT_CACHE_MAX // 4]:
                _SCENES_RECENT_CACHE.pop(k, None)
        _SCENES_RECENT_CACHE[cache_key] = (now, payload)
    return payload


@app.get("/api/scenes/recent")
async def scenes_recent(
    source: str = "",
    id: str = "",
    type: str = "performer",
    slug: str = "",
    name: str = "",
    tpdb_id: str = "",
    stashdb_id: str = "",
    fansdb_id: str = "",
    javstash_id: str = "",
):
    """Get recent scenes for a performer or studio from all sources.

    Strict-id mode kicks in when any of ``tpdb_id`` / ``stashdb_id`` /
    ``fansdb_id`` / ``javstash_id`` is supplied — each bucket only
    runs against its own ID (no name-search guessing across DBs). The
    performer-popup carousel uses this; legacy callers (``/scenes``
    source-tabs, ``/discover`` info panel) omit the per-source IDs and
    get the previous name-fallback behavior. Rows carry ``match`` =
    ``"id"`` or ``"name"`` so the UI can flag name-matched results."""
    data = await run_in_threadpool(
        get_scenes_recent_cached_or_compute,
        source, id, type, slug, name,
        tpdb_id=tpdb_id,
        stashdb_id=stashdb_id,
        fansdb_id=fansdb_id,
        javstash_id=javstash_id,
    )
    return JSONResponse(
        content=data,
        headers={"Cache-Control": "private, max-age=120"},
    )


_DISCOVER_IMAGES_CACHE: dict[tuple, tuple[float, dict]] = {}
_DISCOVER_IMAGES_CACHE_LOCK = threading.Lock()
_DISCOVER_IMAGES_CACHE_TTL = 7200.0  # 2 h — gallery URLs stable; longer TTL for discover UX
_DISCOVER_IMAGES_CACHE_MAX = 600


@app.get("/api/discover/cached-image/{h}")
async def discover_cached_image(h: str):
    """Serve a cached discover image — WebP for new caches, JPEG for
    pre-migration files still on disk."""
    if not re.fullmatch(r"[0-9a-f]{64}", h or ""):
        return JSONResponse({"error": "Not found"}, status_code=404)
    cache_dir = _discover_image_cache_dir()
    p_webp = cache_dir / f"{h}.webp"
    p_jpg = cache_dir / f"{h}.jpg"
    if p_webp.is_file():
        return FileResponse(
            p_webp,
            media_type="image/webp",
            headers={"Cache-Control": "public, max-age=604800"},
        )
    if p_jpg.is_file():
        return FileResponse(
            p_jpg,
            media_type="image/jpeg",
            headers={"Cache-Control": "public, max-age=604800"},
        )
    return JSONResponse({"error": "Not found"}, status_code=404)



def get_discover_performer_images_cached_or_compute(
    source: str, id: str = "", type: str = "performer", name: str = "", slug: str = ""
) -> dict:
    """All images for a performer/studio. Pulls from the primary source
    using `id`, and for performers additionally searches all configured
    stash-boxes by name to broaden the gallery. Returns
    {"images": [url, ...]} with http(s) URLs rewritten to
    ``/api/discover/cached-image/{sha256}`` once stored under
    ``metadata/discover_cache/``. In-memory list cache: 2 hours."""
    from concurrent.futures import ThreadPoolExecutor

    src  = (source or "").strip().upper()
    pid  = (id or "").strip()
    nm   = (name or "").strip()
    sl   = (slug or "").strip()
    kind = (type or "performer").strip()

    cache_key = (src, pid, kind, sl, nm.lower())
    now = time.time()
    with _DISCOVER_IMAGES_CACHE_LOCK:
        hit = _DISCOVER_IMAGES_CACHE.get(cache_key)
        if hit and (now - hit[0]) < _DISCOVER_IMAGES_CACHE_TTL:
            return hit[1]

    settings = db.get_settings()
    stashdb_key = (settings.get("api_key_stashdb") or "").strip()
    fansdb_key  = (settings.get("api_key_fansdb")  or "").strip()
    javstash_key = (settings.get("api_key_javstash") or "").strip()

    def _from_tpdb_id(lookup: str) -> list[str]:
        if not lookup:
            return []
        try:
            if kind == "performer":
                d = fetch_performer_detail("TPDB", lookup) or {}
                return _favourite_urls_from_poster_like_list(d.get("posters"))
            d = fetch_studio_detail("TPDB", lookup) or {}
            return _tpdb_site_all_media_urls(d)
        except Exception:
            return []

    def _from_tpdb_by_name(qname: str) -> list[str]:
        if not qname:
            return []
        try:
            url = TPDB_PERFORMER_SEARCH if kind == "performer" else TPDB_STUDIO_SEARCH
            r = requests.get(url, params={"q": qname}, headers=_tpdb_headers(), timeout=8)
            if r.status_code != 200:
                return []
            data = r.json().get("data") or []
            urls: list[str] = []
            for hit in data[:5]:
                if (hit.get("name") or "").strip().lower() != qname.lower():
                    continue
                # Cross-source name matching can collide when multiple
                # performers share a name (e.g. a female "Dani West"
                # on StashDB and a male "Dani West" on TPDB). Skip hits
                # whose gender isn't female / trans-female so the wrong
                # performer's images don't get folded into the gallery.
                if kind == "performer":
                    g = (hit.get("gender") or "").strip().lower()
                    if g and "female" not in g:
                        continue
                tid = str(hit.get("id") or hit.get("_id") or "")
                if not tid:
                    continue
                urls.extend(_from_tpdb_id(tid))
                break  # only the first matching candidate
            return urls
        except Exception:
            return []

    def _stashbox_perf_search_images(endpoint: str, key: str, qname: str) -> list[str]:
        if not key or not qname or kind != "performer":
            return []
        try:
            gql = """
            query($term: String!) {
              searchPerformer(term: $term, limit: 5) {
                id name gender images { url }
              }
            }"""
            r = requests.post(endpoint, json={"query": gql, "variables": {"term": qname}},
                              headers={"ApiKey": key, "Content-Type": "application/json"}, timeout=8)
            if r.status_code != 200:
                return []
            perfs = (r.json().get("data") or {}).get("searchPerformer") or []
            urls: list[str] = []
            for p in perfs:
                if (p.get("name") or "").strip().lower() != qname.lower():
                    continue
                # Skip same-name male performers that would otherwise
                # leak into a female performer's gallery.
                g = (p.get("gender") or "").strip().upper()
                if g and "FEMALE" not in g:
                    continue
                for img in (p.get("images") or []):
                    if isinstance(img, dict) and img.get("url"):
                        urls.append(str(img["url"]).strip())
                break  # only the first matching candidate
            return urls
        except Exception:
            return []

    # Primary source by id (fast path).
    primary: list[str] = []
    try:
        if src == "TPDB":
            lookup = pid or sl
            if not lookup and nm:
                try:
                    qurl = TPDB_PERFORMER_SEARCH if kind == "performer" else TPDB_STUDIO_SEARCH
                    r = requests.get(qurl, params={"q": nm}, headers=_tpdb_headers(), timeout=8)
                    if r.status_code == 200:
                        data = r.json().get("data") or []
                        if data:
                            lookup = str(data[0].get("id") or data[0].get("_id") or "")
                except Exception:
                    pass
            primary = _from_tpdb_id(lookup)
        elif src == "STASHDB" and pid:
            if kind == "performer":
                primary = _stashdb_performer_all_image_urls(pid)
            else:
                primary = _stashdb_studio_all_image_urls(pid)
        elif src == "FANSDB" and pid:
            if kind == "performer":
                d = fetch_performer_detail("FansDB", pid) or {}
                primary = _favourite_urls_from_poster_like_list(d.get("posters"))
            else:
                primary = _fansdb_studio_all_image_urls(pid)
        elif src == "JAVSTASH" and pid:
            if kind == "performer":
                primary = _javstash_performer_all_image_urls(pid)
            else:
                primary = _javstash_studio_all_image_urls(pid)
    except Exception:
        primary = []

    # Broaden by name across all sources (performers only).
    extras: list[str] = []
    if kind == "performer" and nm:
        with ThreadPoolExecutor(max_workers=4) as pool:
            f_tpdb = None if src == "TPDB" else pool.submit(_from_tpdb_by_name, nm)
            f_sdb  = None if src == "STASHDB" else pool.submit(_stashbox_perf_search_images,
                                                               STASHDB_ENDPOINT,
                                                               stashdb_key, nm)
            f_fdb  = None if src == "FANSDB"  else pool.submit(_stashbox_perf_search_images,
                                                               FANSDB_ENDPOINT,
                                                               fansdb_key, nm)
            f_jav  = None if src == "JAVSTASH" else pool.submit(_stashbox_perf_search_images,
                                                                JAVSTASH_ENDPOINT,
                                                                javstash_key, nm)
            for fut in (f_tpdb, f_sdb, f_fdb, f_jav):
                if fut is None:
                    continue
                try:
                    extras.extend(fut.result() or [])
                except Exception:
                    pass

    seen: set[str] = set()
    deduped: list[str] = []
    for u in (primary + extras):
        if u and u not in seen:
            seen.add(u)
            deduped.append(u)
    cached_list = _discover_rewrite_image_url_list(deduped)
    payload = {"images": cached_list, "count": len(cached_list)}
    with _DISCOVER_IMAGES_CACHE_LOCK:
        if len(_DISCOVER_IMAGES_CACHE) > _DISCOVER_IMAGES_CACHE_MAX:
            cutoff = sorted(_DISCOVER_IMAGES_CACHE.items(), key=lambda kv: kv[1][0])
            for k, _ in cutoff[: _DISCOVER_IMAGES_CACHE_MAX // 4]:
                _DISCOVER_IMAGES_CACHE.pop(k, None)
        _DISCOVER_IMAGES_CACHE[cache_key] = (now, payload)
    return payload


# ── /discover info panel: async job + spotlight prewarm ─────────────────
_DISCOVER_PANEL_JOBS: dict[str, dict] = {}
_DISCOVER_PANEL_JOB_LOCK = threading.Lock()
_DISCOVER_PANEL_JOB_MAX_AGE = 900.0


def _discover_panel_job_prune_locked(now: float) -> None:
    dead = [
        jid
        for jid, v in _DISCOVER_PANEL_JOBS.items()
        if now - float(v.get("created") or 0) > _DISCOVER_PANEL_JOB_MAX_AGE
    ]
    for jid in dead:
        _DISCOVER_PANEL_JOBS.pop(jid, None)


def _discover_info_panel_job_worker(job_id: str, payload: dict) -> None:
    kind = (payload.get("kind") or "performer").strip()
    src = (payload.get("source") or "TPDB").strip()
    eid = (payload.get("id") or "").strip()
    slug = (payload.get("slug") or "").strip()
    nm = (payload.get("name") or "").strip()
    typ = (payload.get("type") or kind).strip()
    try:
        if kind == "studio":
            sr = get_scenes_recent_cached_or_compute(src, eid, typ, slug, nm)
            with _DISCOVER_PANEL_JOB_LOCK:
                _discover_panel_job_prune_locked(time.time())
                j = _DISCOVER_PANEL_JOBS.get(job_id)
                if j:
                    j["status"] = "done"
                    j["scenes_recent"] = sr
                    j["performer_images"] = {"images": [], "count": 0}
            return
        sr = get_scenes_recent_cached_or_compute(src, eid, typ, slug, nm)
        with _DISCOVER_PANEL_JOB_LOCK:
            _discover_panel_job_prune_locked(time.time())
            j = _DISCOVER_PANEL_JOBS.get(job_id)
            if j:
                j["status"] = "scenes"
                j["scenes_recent"] = sr
        im = get_discover_performer_images_cached_or_compute(src, eid, typ, nm, slug)
        with _DISCOVER_PANEL_JOB_LOCK:
            _discover_panel_job_prune_locked(time.time())
            j = _DISCOVER_PANEL_JOBS.get(job_id)
            if j:
                j["status"] = "done"
                j["scenes_recent"] = sr
                j["performer_images"] = im
    except Exception as e:
        with _DISCOVER_PANEL_JOB_LOCK:
            j = _DISCOVER_PANEL_JOBS.get(job_id)
            if j:
                j["status"] = "error"
                j["error"] = str(e)




def _prewarm_discover_for_spotlight(performers: list[dict]) -> None:
    """Warm scenes_recent + performer-images caches for first spotlight tiles."""

    def run() -> None:
        for p in performers[:8]:
            try:
                src = (p.get("source") or "").strip()
                if not src or src.lower() == "library":
                    continue
                nm = (p.get("name") or "").strip()
                pid = str(p.get("id") or "").strip()
                if not nm and not pid:
                    continue
                get_scenes_recent_cached_or_compute(src, pid, "performer", "", nm)
                get_discover_performer_images_cached_or_compute(
                    src, pid, "performer", nm, ""
                )
            except Exception:
                pass

    threading.Thread(
        target=run, daemon=True, name="discover-prewarm-spotlight"
    ).start()


# ---------------------------------------------------------------------------
# TPDB Feed & Favourites Sync
# ---------------------------------------------------------------------------

_feed_cache: dict = {
    "studios": {"scenes": [], "ts": 0, "source": "", "filter_key": None},
    "performers": {"scenes": [], "ts": 0, "source": "", "filter_key": None},
    "random": {"scenes": [], "ts": 0, "source": "", "filter_key": None},
    "favourites": {"scenes": [], "ts": 0, "source": "", "filter_key": None},
    "jav": {"scenes": [], "ts": 0, "source": "", "filter_key": None},
}
_movies_latest_cache: dict = {"results": [], "ts": 0, "filter_key": None}
_FEED_CACHE_TTL = 3600  # 1 hour
_MOVIES_CACHE_TTL = 3600  # 1 hour

# Durable merged /scenes + Latest Movies grids (SQLite ``feed_display_pools``).
_FEED_SCENE_DISPLAY_POOL_CAP = 220
_FEED_MOVIE_DISPLAY_POOL_CAP = 90


def _scene_feed_row_dedupe_key(sc: dict) -> str:
    sid = str((sc or {}).get("id") or "").strip()
    if not sid:
        return ""
    src = str((sc or {}).get("source") or "").strip().lower()
    return f"{src}:{sid}"


def _merge_scene_feed_pool_lists(prev: list, new: list, cap: int) -> list:
    by: dict[str, dict] = {}
    for s in prev or []:
        if not isinstance(s, dict):
            continue
        k = _scene_feed_row_dedupe_key(s)
        if k:
            by[k] = s
    for s in new or []:
        if not isinstance(s, dict):
            continue
        k = _scene_feed_row_dedupe_key(s)
        if k:
            by[k] = s
    out = list(by.values())
    out.sort(key=lambda c: str((c or {}).get("date") or ""), reverse=True)
    return out[:cap] if cap > 0 else out


def _movie_feed_row_dedupe_key(m: dict) -> str:
    mid = str((m or {}).get("id") or (m or {}).get("slug") or "").strip()
    return f"m:{mid}" if mid else ""


def _merge_movie_feed_pool_lists(prev: list, new: list, cap: int) -> list:
    by: dict[str, dict] = {}
    for x in prev or []:
        if not isinstance(x, dict):
            continue
        k = _movie_feed_row_dedupe_key(x)
        if k:
            by[k] = x
    for x in new or []:
        if not isinstance(x, dict):
            continue
        k = _movie_feed_row_dedupe_key(x)
        if k:
            by[k] = x
    out = list(by.values())
    out.sort(
        key=lambda c: str((c or {}).get("date") or (c or {}).get("year") or ""),
        reverse=True,
    )
    return out[:cap] if cap > 0 else out


def _persist_scenes_feed_display_pool(pool_key: str, fk, fresh_scenes: list) -> list:
    """Merge ``fresh_scenes`` into the SQLite-backed pool; return merged rows.

    Empty ``fresh_scenes`` leaves the stored pool unchanged (bad refetch
    must not wipe a warm grid).

    Runtime filter (future dates + RSS keyword blacklist) is applied to
    both stored-prev and merged result so a pool persisted yesterday
    sheds future-dated entries that have now matured into the past (or
    are still future), and any newly-blacklisted keywords drop out on
    the next serve.
    """
    fk_s = str(fk)
    row = db.feed_display_pool_get("scenes", pool_key)
    prev: list = []
    if row and row.get("filter_key") == fk_s:
        prev = _filter_feed_cards(row.get("items") or [])
    if not fresh_scenes:
        return prev if isinstance(prev, list) else []
    fresh_clean = _filter_feed_cards(fresh_scenes)
    merged = _merge_scene_feed_pool_lists(prev, fresh_clean, _FEED_SCENE_DISPLAY_POOL_CAP)
    db.feed_display_pool_upsert("scenes", pool_key, fk_s, merged)
    return merged


def _persist_movies_feed_display_pool(fk, fresh_results: list) -> list:
    fk_s = str(fk)
    row = db.feed_display_pool_get("movies", "latest")
    prev: list = []
    if row and row.get("filter_key") == fk_s:
        prev = _filter_feed_cards(row.get("items") or [])
    if not fresh_results:
        return prev if isinstance(prev, list) else []
    fresh_clean = _filter_feed_cards(fresh_results)
    merged = _merge_movie_feed_pool_lists(prev, fresh_clean, _FEED_MOVIE_DISPLAY_POOL_CAP)
    db.feed_display_pool_upsert("movies", "latest", fk_s, merged)
    return merged


def _scenes_feed_try_instant_disk(
    m: str,
    cache_key: str,
    fk,
    tag_selection: list[str],
) -> dict | None:
    """When the 1h RAM cache is empty or stale, return merged rows from
    ``feed_display_pools`` so the first ``/api/scenes/feed`` after a process
    restart does not block on StashDB / TPDB / JAVStash (including Vices —
    ``cache_key`` embeds the selected tag ids).
    """
    if m == "tags" and not tag_selection:
        return None
    with _content_cache_lock:
        b = _feed_cache.get(cache_key) or {}
        age = time.time() - float(b.get("ts") or 0)
        ram_warm = bool(
            b.get("scenes")
            and age < _FEED_CACHE_TTL
            and b.get("filter_key") == fk
        )
    if ram_warm:
        return None
    row = db.feed_display_pool_get("scenes", cache_key)
    if not row or str(row.get("filter_key") or "") != str(fk):
        return None
    items = row.get("items") or []
    if not isinstance(items, list) or not items:
        return None
    # Re-apply the runtime filter on serve so a pool that included a
    # tomorrow-dated scene (when it was yesterday) doesn't keep showing
    # it today, and newly-added blacklist keywords prune in immediately.
    merged = _filter_feed_cards(items)
    if not merged:
        return None
    with _content_cache_lock:
        sc = merged
        slice30 = sc[:30] if len(sc) > 30 else list(sc)
        _feed_cache[cache_key] = {
            "scenes": slice30,
            "ts": time.time(),
            "source": "disk_warm",
            "filter_key": fk,
        }
    # Point every thumb at the local disk cache when the image is already
    # saved; otherwise return the raw URL and queue a background download.
    _scenes_feed_rewrite_thumbs(merged)
    return {
        "scenes": merged,
        "source": "disk_warm",
        "feed_mode": m,
        "tag_ids": tag_selection,
        "cached": True,
        "cache_age_s": 0,
        "from_disk": True,
    }


def _movies_latest_try_instant_disk(fk) -> dict | None:
    """Page-1 Latest Movies from ``feed_display_pools`` when RAM cache is cold."""
    fk_s = str(fk)
    with _content_cache_lock:
        age = time.time() - float(_movies_latest_cache.get("ts") or 0)
        ram_warm = bool(
            _movies_latest_cache.get("results")
            and age < _MOVIES_CACHE_TTL
            and _movies_latest_cache.get("filter_key") == fk
        )
    if ram_warm:
        return None
    row = db.feed_display_pool_get("movies", "latest")
    if not row or str(row.get("filter_key") or "") != fk_s:
        return None
    items = row.get("items") or []
    if not isinstance(items, list) or not items:
        return None
    # Strip future-dated + blacklisted entries from the pool on serve.
    merged = _filter_feed_cards(items)
    if not merged:
        return None
    fresh_slice = merged[:30] if len(merged) > 30 else list(merged)
    with _content_cache_lock:
        _movies_latest_cache["results"] = fresh_slice
        _movies_latest_cache["ts"] = time.time()
        _movies_latest_cache["filter_key"] = fk
    # Point every poster/background at the local disk cache when the
    # image is already saved; misses queue a background download.
    _scenes_feed_rewrite_thumbs(merged)
    return {
        "results": merged,
        "cached": True,
        "cache_age_s": 0,
        "page": 1,
        "total_pages": 1,
        "from_disk": True,
    }


def _movies_cache_filter_key() -> tuple:
    """Fingerprint for latest-movies cache (categories + tag blacklist)."""
    return _content_filters_fingerprint()


def _fetch_performer_scenes(name: str, headers: dict) -> list[dict]:
    """Fetch recent scenes for a single performer from TPDB. Used in thread pool."""
    scenes = []
    try:
        resp = requests.get(
            TPDB_PERFORMER_SEARCH,
            params={"q": name},
            headers=headers,
            timeout=10,
        )
        if resp.status_code != 200:
            return []
        perf_data = resp.json().get("data") or []
        if not perf_data:
            return []

        perf = perf_data[0]
        perf_id = perf.get("id") or perf.get("_id")
        if not perf_id:
            return []

        resp2 = requests.get(
            f"https://api.theporndb.net/performers/{perf_id}/scenes",
            headers=headers,
            timeout=10,
        )
        if resp2.status_code != 200:
            return []

        for sc in (resp2.json().get("data") or [])[:4]:
            genders = _extract_movie_genders(sc)
            if not _passes_content_filter(genders):
                continue
            if not _passes_tag_filter(sc, "tpdb"):
                continue
            if not _passes_title_filter(sc):
                continue
            if not _passes_raw_scene_runtime_filter(sc):
                continue
            thumb = ""
            bg = sc.get("background") or {}
            if isinstance(bg, dict):
                # Prefer `background.medium` — direct CDN, no watermark,
                # no portrait re-crop (see scenes_recent for the same
                # priority list and rationale).
                thumb = (
                    bg.get("medium")
                    or bg.get("large")
                    or bg.get("full")
                    or bg.get("small")
                    or bg.get("url")
                    or ""
                )
            if not thumb:
                thumb = sc.get("image") or sc.get("poster") or sc.get("poster_image") or ""
            if not thumb:
                posters = sc.get("posters") or []
                if posters:
                    thumb = posters[0] if isinstance(posters[0], str) else posters[0].get("url", "")

            sc_perfs: list[str] = []
            seen_sc: set[str] = set()
            for p in sc.get("performers") or sc.get("credits") or []:
                if isinstance(p, dict):
                    pn = (p.get("name") or p.get("parent", {}).get("name") or "").strip()
                    if not pn:
                        continue
                    key = pn.lower()
                    if key in seen_sc:
                        continue
                    seen_sc.add(key)
                    sc_perfs.append(pn)
            scenes.append({
                "id": str(sc.get("_id") or sc.get("id") or ""),
                "title": sc.get("title", ""),
                "date": sc.get("date", ""),
                "studio": (sc.get("site") or {}).get("name", ""),
                "thumb": thumb,
                "link": "",
                "source": "feed",
                "performer": ", ".join(sc_perfs) if sc_perfs else name,
            })
    except Exception as e:
        emit(f"FEED error fetching {name}: {e}")
    return scenes


def _tpdb_scene_rows_from_api_payload(scenes_data: list, *, label: str, slice_n: int) -> list[dict]:
    """Turn raw TPDB /scenes list into feed cards (filters + thumb)."""
    out = []
    for sc in (scenes_data or [])[:slice_n]:
        genders = _extract_movie_genders(sc)
        if not _passes_content_filter(genders):
            continue
        if not _passes_tag_filter(sc, "tpdb"):
            continue
        if not _passes_title_filter(sc):
            continue
        if not _passes_raw_scene_runtime_filter(sc):
            continue
        thumb = _tpdb_pick_thumb(sc)
        sc_perfs: list[str] = []
        seen_sc2: set[str] = set()
        for p in sc.get("performers") or sc.get("credits") or []:
            if isinstance(p, dict):
                pn = (p.get("name") or p.get("parent", {}).get("name") or "").strip()
                if not pn:
                    continue
                key = pn.lower()
                if key in seen_sc2:
                    continue
                seen_sc2.add(key)
                sc_perfs.append(pn)
        out.append({
            "id": str(sc.get("_id") or sc.get("id") or ""),
            "title": sc.get("title", ""),
            "date": sc.get("date", ""),
            "studio": (sc.get("site") or {}).get("name", ""),
            "thumb": thumb,
            "link": "",
            "source": "feed",
            "performer": ", ".join(sc_perfs) if sc_perfs else label,
            "hover_performers": _scene_hover_performer_names(sc) or ([label] if label else []),
            "display_performers": _scene_display_performers(sc),
            "tags": _tpdb_scene_tag_names(sc),
            "description": (sc.get("description") or sc.get("synopsis") or "").strip(),
        })
    return out


def _fetch_tpdb_performer_scenes_by_id(perf_id: str, label: str, headers: dict, slice_n: int = 6) -> list[dict]:
    """Recent TPDB scenes for a performer when we already have the TPDB id.

    Explicit `order=date direction=desc` so we pick up the performer's
    most recent *releases*, not the most recently *added* TPDB entries
    (default would be `created_at desc`, which can surface old scenes
    that were just imported).
    """
    if not (perf_id or "").strip():
        return []
    try:
        resp2 = requests.get(
            f"https://api.theporndb.net/performers/{perf_id.strip()}/scenes",
            params={"order": "date", "direction": "desc", "per_page": max(slice_n * 2, 10)},
            headers=headers,
            timeout=12,
        )
        if resp2.status_code != 200:
            return []
        return _tpdb_scene_rows_from_api_payload(
            resp2.json().get("data") or [], label=label, slice_n=slice_n,
        )
    except Exception as e:
        emit(f"FEED error performer id {perf_id}: {e}")
        return []


def _fetch_tpdb_site_scenes_by_id(site_id: str, label: str, headers: dict, slice_n: int = 6) -> list[dict]:
    """Recent TPDB scenes for a site/studio when we already have the TPDB id.

    Sends an explicit `per_page` so dormant sites still return their
    full visible page, AND an explicit `order=date direction=desc` to
    sort by release date rather than TPDB's server default (which is
    `created_at desc` — recently *added* to TPDB, not recently
    *released*). Without the explicit order, a studio that backfilled
    a 2019 scene yesterday would push their actual fresh 2026 release
    off the slice. The response is then trimmed to `slice_n` inside
    `_tpdb_scene_rows_from_api_payload`. The aggregating caller is
    responsible for date-floor filtering before merging across sites
    — see `_fetch_tpdb_starred_favourites_feed` (starred studio rows).
    """
    if not (site_id or "").strip():
        return []
    try:
        resp2 = requests.get(
            f"https://api.theporndb.net/sites/{site_id.strip()}/scenes",
            params={
                "page": 1,
                "per_page": max(slice_n * 2, 10),
                "order": "date",
                "direction": "desc",
            },
            headers=headers,
            timeout=12,
        )
        if resp2.status_code != 200:
            return []
        return _tpdb_scene_rows_from_api_payload(
            resp2.json().get("data") or [], label=label, slice_n=slice_n,
        )
    except Exception as e:
        emit(f"FEED error site id {site_id}: {e}")
        return []


def _fetch_tpdb_starred_favourites_feed(limit: int = 24) -> list[dict]:
    """Scenes featuring heart-starred Favourites rows that have a TPDB link."""
    from concurrent.futures import ThreadPoolExecutor, as_completed

    s = db.get_settings()
    if not (s.get("api_key_tpdb") or "").strip():
        return []

    rows = db.favourite_starred_with_tpdb_ids()
    if not rows:
        emit("FEED starred favourites: no starred entities with TPDB id")
        return []

    headers = _tpdb_headers()
    # Cap fan-out so the feed stays snappy
    cap = min(len(rows), 12)
    rows = rows[:cap]
    slice_n = max(3, min(8, (limit + cap - 1) // cap))

    all_scenes: list[dict] = []
    with ThreadPoolExecutor(max_workers=4) as pool:
        futures = []
        for r in rows:
            tid = (r.get("match_tpdb_id") or "").strip()
            label = (r.get("folder_name") or "").strip() or tid
            kind = (r.get("kind") or "").strip().lower()
            if kind == "studio":
                futures.append(pool.submit(_fetch_tpdb_site_scenes_by_id, tid, label, headers, slice_n))
            else:
                futures.append(pool.submit(_fetch_tpdb_performer_scenes_by_id, tid, label, headers, slice_n))
        for fut in as_completed(futures):
            try:
                all_scenes.extend(fut.result())
            except Exception:
                pass

    seen: set[str] = set()
    deduped: list[dict] = []
    for sc in all_scenes:
        sid = sc.get("id") or ""
        if sid and sid not in seen:
            seen.add(sid)
            deduped.append(sc)
    deduped.sort(key=lambda x: x.get("date", ""), reverse=True)
    emit(f"FEED starred favourites: {len(deduped)} scenes from {len(rows)} entities")
    return deduped[:limit]


def _fetch_tpdb_feed(limit: int = 24) -> list[dict]:
    """Build a personalised feed from library performer directories.

    Uses a thread pool for parallel API calls and caches results for 15 min.
    """
    import random
    from concurrent.futures import ThreadPoolExecutor, as_completed

    s = db.get_settings()
    api_key = s.get("api_key_tpdb", "")
    if not api_key:
        return []

    # Gather performer names from library directories
    performer_dirs = db.get_directories("performer")
    performer_names = []
    for entry in performer_dirs:
        base = Path((entry.get("path") or "").strip()).expanduser()
        if not base.is_dir():
            continue
        for folder in base.iterdir():
            if folder.is_dir() and not folder.name.startswith("."):
                performer_names.append(folder.name)

    if not performer_names:
        emit("FEED no performer folders found in library")
        return []

    # Sample up to 8 performers
    sample = random.sample(performer_names, min(8, len(performer_names)))
    emit(f"FEED fetching scenes for {len(sample)} performers (parallel)...")

    headers = _tpdb_headers()
    all_scenes = []

    # Parallel fetch — up to 4 concurrent requests
    with ThreadPoolExecutor(max_workers=4) as pool:
        futures = {pool.submit(_fetch_performer_scenes, name, headers): name for name in sample}
        for future in as_completed(futures):
            result = future.result()
            all_scenes.extend(result)

    # Deduplicate by id, sort by date descending
    seen = set()
    deduped = []
    for sc in all_scenes:
        if sc["id"] and sc["id"] not in seen:
            seen.add(sc["id"])
            deduped.append(sc)

    deduped.sort(key=lambda x: x.get("date", ""), reverse=True)
    result = deduped[:limit]

    emit(f"FEED built {len(result)} scenes from {len(sample)} performers")
    return result


def _preferred_display_genders(allowed: set[str] | None = None) -> set[str]:
    """Which performer genders the user actually wants to see on a hover
    label, derived from their Content Filter category toggles.

    - Any of straight / lesbian / solo_female enabled → show females.
    - Gay enabled → show males.
    - Trans enabled → show trans performers.

    If every category is on (no filtering), all genders qualify so the
    hover shows every performer.
    """
    if allowed is None:
        _, _, allowed = _get_content_filter_config()
    all_five = allowed and len(allowed) == 5
    out: set[str] = set()
    if all_five:
        return {"female", "male", "trans", "transgender_female", "transgender_male", ""}
    if allowed and ("straight" in allowed or "lesbian" in allowed or "solo_female" in allowed):
        out.add("female")
    if allowed and "gay" in allowed:
        out.add("male")
    if allowed and "trans" in allowed:
        out.update({"trans", "transgender_female", "transgender_male"})
    return out


def _scene_display_performers(s_item: dict) -> list[dict]:
    """All scene performers as ``[{"name": str, "gender": str, "id"?: str}]``.

    ``id`` is the upstream stash-box / TPDB performer id when the scene
    payload includes it — used by the performer popup as ``stash_id`` /
    ``tpdb_id`` so unmatched JAV (and other) cast clicks still resolve.

    Unlike :func:`_scene_hover_performer_names` this does **not** filter
    by the user's Content Filter — the front-end uses it for the
    rendered name list + gender badges so a co-star still shows up
    next to the headline performer with their own colour-coded symbol.
    Gender is normalised to ``male`` / ``female`` / ``transgender_female``
    / ``transgender_male`` / ``intersex`` / ``""`` (lowercased TPDB /
    StashDB keys) so the JS helper can map straight to a glyph.
    """
    if not isinstance(s_item, dict):
        return []
    raw = s_item.get("performers") or s_item.get("credits") or []
    if not isinstance(raw, list):
        return []
    out: list[dict] = []
    seen: set[str] = set()
    for p in raw:
        credited_as = ""
        if isinstance(p, dict):
            perf = p.get("performer") or p
            credited_as = (str(p.get("as") or "")).strip()
            name = (
                perf.get("name")
                or perf.get("full_name")
                or (p.get("parent") or {}).get("name")
                or credited_as
                or ""
            ).strip()
            gender_candidates = [
                perf.get("gender"),
                perf.get("sex"),
                ((perf.get("extras") or {}).get("gender") if isinstance(perf.get("extras"), dict) else None),
                ((p.get("parent") or {}).get("extras", {}) or {}).get("gender") if isinstance(p.get("parent"), dict) else None,
                p.get("gender"),
            ]
            gender = ""
            for g in gender_candidates:
                if g and str(g).strip():
                    gender = str(g).strip().lower()
                    break
        elif isinstance(p, str):
            name = p.strip()
            gender = ""
        else:
            continue
        if not name:
            continue
        k = name.lower()
        if k in seen:
            continue
        seen.add(k)
        pid = ""
        if isinstance(p, dict):
            perf_for_id = p.get("performer") or p
            if isinstance(perf_for_id, dict):
                pid = str(perf_for_id.get("id") or perf_for_id.get("_id") or "").strip()
        row_d: dict = {"name": name, "gender": gender}
        if pid:
            row_d["id"] = pid
        out.append(row_d)
        # Stash-box ``as`` = on-screen / credited-as string; often CJK or a
        # stage name while ``performer.name`` is Romanised — include both so
        # library alias matching and the Performers feed filter see it.
        if credited_as and credited_as.lower() != name.lower():
            k2 = credited_as.lower()
            if k2 not in seen:
                seen.add(k2)
                row2 = {"name": credited_as, "gender": gender}
                if pid:
                    row2["id"] = pid
                out.append(row2)
    return out


def _scene_hover_performer_names(s_item: dict, allowed: set[str] | None = None) -> list[str]:
    """Names of performers on the scene whose gender matches the user's
    Content Filter preferences — used for the bottom-pill hover label on
    /scenes. Falls back to every performer when gender metadata is
    missing so we don't strip perfectly good labels just because TPDB
    didn't tag the gender field."""
    if not isinstance(s_item, dict):
        return []
    prefs = _preferred_display_genders(allowed)

    raw = s_item.get("performers") or s_item.get("credits") or []
    if not isinstance(raw, list):
        return []
    names_kept: list[str] = []
    names_any: list[str] = []
    seen_kept: set[str] = set()
    seen_any: set[str] = set()
    for p in raw:
        if isinstance(p, dict):
            perf = p.get("performer") or p
            name = (
                perf.get("name")
                or perf.get("full_name")
                or (p.get("parent") or {}).get("name")
                or ""
            ).strip()
            gender_candidates = [
                perf.get("gender"),
                perf.get("sex"),
                ((perf.get("extras") or {}).get("gender") if isinstance(perf.get("extras"), dict) else None),
                ((p.get("parent") or {}).get("extras", {}) or {}).get("gender") if isinstance(p.get("parent"), dict) else None,
                p.get("gender"),
            ]
            gender = ""
            for g in gender_candidates:
                if g and str(g).strip():
                    gender = str(g).strip().lower()
                    break
        elif isinstance(p, str):
            name = p.strip()
            gender = ""
        else:
            continue
        if not name:
            continue
        key_any = name.lower()
        if key_any not in seen_any:
            seen_any.add(key_any)
            names_any.append(name)
        if gender in prefs or (not gender and not prefs):
            # Keep when gender matches, or when we can't filter at all
            # (prefs empty = filtering off). Unknown gender still surfaces
            # via the fallback below if nothing else matches.
            if key_any not in seen_kept:
                seen_kept.add(key_any)
                names_kept.append(name)
    if names_kept:
        return names_kept
    # Fallback: TPDB didn't tag any performer's gender — return all names
    # rather than an empty pill so the user still sees context.
    return names_any


def _tpdb_scene_tag_names(s_item: dict) -> list[str]:
    """Ordered list of display tag names from a TPDB scene payload.

    Preserves TPDB's original tag order and titlecases for display (the
    payload usually ships lowercase). Dedupes case-insensitively.
    """
    if not isinstance(s_item, dict):
        return []
    raw = s_item.get("tags")
    if not isinstance(raw, list):
        return []
    out: list[str] = []
    seen: set[str] = set()
    for t in raw:
        name = ""
        if isinstance(t, str):
            name = t.strip()
        elif isinstance(t, dict):
            name = (t.get("name") or t.get("label") or "").strip()
            if not name and isinstance(t.get("tag"), dict):
                name = (t["tag"].get("name") or "").strip()
        if not name:
            continue
        key = name.lower()
        if key in seen:
            continue
        seen.add(key)
        # TPDB sends lowercase; titlecase so "anal" → "Anal", but keep
        # multi-word phrases like "big tits" sensible → "Big Tits".
        out.append(" ".join(w[:1].upper() + w[1:] for w in name.split()))
    return out


def _tpdb_unwatermark_url(url: str) -> str:
    """Strip TPDB's `thumb.theporndb.net` proxy off a URL, returning
    the embedded `cdn.theporndb.net/...` direct CDN path.

    A proxied URL looks like:
        https://thumb.theporndb.net/<sig>/800x1200/smart/filters:...(<args>)/<urlencoded-cdn-path>

    where the watermark/upscale/sharpen filters live inside the parens
    and the original CDN path is URL-encoded after the closing `)/`.
    Decoding that suffix and prefixing `cdn.theporndb.net/` yields the
    same scene image *without* the studio-logo watermark or the forced
    800×1200 portrait crop.

    Non-proxied URLs (or anything we can't parse) pass through
    unchanged.
    """
    if not url or "thumb.theporndb.net" not in url:
        return url
    idx = url.rfind(")/")
    if idx < 0:
        return url
    encoded = url[idx + 2:]
    if not encoded:
        return url
    try:
        decoded = unquote(encoded)
    except Exception:
        return url
    if not decoded:
        return url
    return "https://cdn.theporndb.net/" + decoded.lstrip("/")


def _tpdb_pick_thumb(s_item: dict) -> str:
    """Pick the best-loading thumbnail URL from a TPDB scene OR movie
    payload. The selector reorders depending on which one we're given:

    Scenes — `background` is the wide hero / collage on
        `cdn.theporndb.net` (no watermark, no portrait re-crop).
        `posters.*` and the top-level `poster` field route through
        `thumb.theporndb.net` and arrive watermarked + portrait-cropped
        (visually wrong for a 16:9 thumb), so they're only fallbacks.

    Movies — `posters.*` is the actual sleeve artwork (the print
        cover the user expects). `background` is a backdrop banner
        when it exists at all, which would replace the proper poster.
        Posters first.

    Detected via the payload's ``type`` field (TPDB returns
    ``"Scene"`` / ``"Movie"``); also infers from
    ``background_back`` (scenes) and ``back_image`` (movies). Falls
    back to scene-style preference when ambiguous.
    """
    if not isinstance(s_item, dict):
        return ""

    type_label = str(s_item.get("type") or "").strip().lower()
    # The TPDB scene resource includes a `"back_image": null` field, so
    # the previous `"back_image" in s_item` test mis-classified scenes as
    # movies (which skipped the un-watermark rewrite below). Use the
    # explicit `type` label as the primary signal and only fall back to
    # the `back_image` heuristic when its value is *truthy*.
    is_movie = (
        type_label == "movie"
        or (type_label not in ("scene", "")
            and bool(s_item.get("back_image")))
    )

    def _from_bg() -> str:
        bg = s_item.get("background")
        if isinstance(bg, dict):
            for k in ("medium", "large", "full", "small", "url"):
                v = bg.get(k)
                if isinstance(v, str) and v:
                    return v
        return ""

    def _from_posters() -> str:
        posters = s_item.get("posters")
        if isinstance(posters, dict):
            for k in ("medium", "large", "small", "full"):
                v = posters.get(k)
                if isinstance(v, str) and v:
                    return v
        elif isinstance(posters, list):
            for p in posters:
                if isinstance(p, str) and p:
                    return p
                if isinstance(p, dict):
                    for k in ("url", "medium", "large", "small", "full"):
                        v = p.get(k)
                        if isinstance(v, str) and v:
                            return v
        return ""

    def _from_top_level() -> str:
        for key in ("poster", "poster_image", "image"):
            v = s_item.get(key)
            if isinstance(v, str) and v:
                return v
            if isinstance(v, dict):
                for k in ("medium", "large", "small", "full", "url"):
                    u = v.get(k)
                    if isinstance(u, str) and u:
                        return u
        return ""

    if is_movie:
        return _from_posters() or _from_bg() or _from_top_level()
    # Scenes: every TPDB scene field can fall back to the proxied
    # `thumb.theporndb.net` URL (watermark + 800×1200 portrait
    # re-crop). Run the final URL through the un-watermark rewriter
    # so even a `posters.*` or top-level `poster` fallback resolves
    # to the direct `cdn.theporndb.net` CDN copy.
    return _tpdb_unwatermark_url(_from_bg() or _from_posters() or _from_top_level())


def _tpdb_scene_payload_to_feed_card(s_item: dict, source: str = "tpdb") -> dict | None:
    """Single scene resource → feed card, or None if filtered out."""
    # Future-dated scenes: TPDB occasionally lists releases days /
    # weeks ahead of asset availability. Drop universally so the
    # /scenes grid only shows things the user could actually watch
    # today. Same filter the stash-box card builder applies.
    rd = (s_item.get("date") or s_item.get("release_date") or "")[:10]
    if rd:
        try:
            from datetime import date as _date
            if rd > _date.today().isoformat():
                return None
        except Exception:
            pass
    # RSS keyword blacklist (substring match on title): user-configured
    # blacklist is the single source of truth — apply to every TPDB
    # scene feed/search path, not just the RSS reader.
    bl_terms = _rss_keyword_blacklist_terms()
    if bl_terms:
        title_l = str(s_item.get("title") or "").lower()
        if any(term in title_l for term in bl_terms):
            return None
    genders = _extract_movie_genders(s_item)
    if not _passes_content_filter(genders):
        return None
    if not _passes_tag_filter(s_item, "tpdb"):
        return None
    if not _passes_title_filter(s_item):
        return None
    thumb = _tpdb_pick_thumb(s_item)
    perf_names = []
    for p in s_item.get("performers") or s_item.get("credits") or []:
        if isinstance(p, dict):
            n = (p.get("name") or p.get("parent", {}).get("name") or "").strip()
            if n:
                perf_names.append(n)
        elif isinstance(p, str) and p.strip():
            perf_names.append(p.strip())
    return {
        "id": str(s_item.get("_id") or s_item.get("id") or ""),
        "title": s_item.get("title", ""),
        "date": s_item.get("date", ""),
        "studio": (s_item.get("site") or {}).get("name", ""),
        "performer": ", ".join(perf_names),
        "hover_performers": _scene_hover_performer_names(s_item),
        "display_performers": _scene_display_performers(s_item),
        "thumb": thumb,
        "link": "",
        "source": source,
        "tags": _tpdb_scene_tag_names(s_item),
        "description": (s_item.get("description") or s_item.get("synopsis") or "").strip(),
    }


def _stashbox_scene_to_feed_card(sc: dict, *, source_label: str) -> dict | None:
    """Stash-box ``queryScenes`` scene → feed card, or None if filtered out."""
    # Future-dated scenes: every stash-box source can publish metadata
    # ahead of the asset (JAVStash does it routinely; StashDB / FansDB
    # less often but it happens). Apply the same drop universally so
    # tomorrow's placeholders never reach the grid.
    rd = (sc.get("release_date") or "")[:10]
    if rd:
        try:
            from datetime import date as _date
            if rd > _date.today().isoformat():
                return None
        except Exception:
            pass
    # RSS keyword blacklist (substring match on title): historically
    # only applied to RSS / Prowlarr search. Apply to /scenes feed
    # cards too so the user's blacklist is a single source of truth.
    bl_terms = _rss_keyword_blacklist_terms()
    if bl_terms:
        title_l = str(sc.get("title") or "").lower()
        if any(term in title_l for term in bl_terms):
            return None
    genders = _extract_movie_genders(sc)
    if not _passes_content_filter(genders):
        return None
    src_key = {"stashdb": "stashdb", "fansdb": "fansdb", "javstash": "javstash"}.get(
        (source_label or "").lower()
    )
    if not _passes_tag_filter(sc, src_key):
        return None
    if not _passes_title_filter(sc):
        return None
    imgs = sc.get("images") or []
    thumb = ""
    if imgs and isinstance(imgs[0], dict):
        thumb = (imgs[0].get("url") or "").strip()
    sid = str(sc.get("id") or "").strip()
    if not sid:
        return None
    perf_bits: list[str] = []
    seen_pb: set[str] = set()
    for pa in sc.get("performers") or []:
        if not isinstance(pa, dict):
            continue
        perf_obj = pa.get("performer") or {}
        base = (perf_obj.get("name") or "").strip()
        as_cred = (str(pa.get("as") or "")).strip()
        pn = (base or as_cred or "").strip()
        if not pn:
            continue
        for bit in ([pn, as_cred] if as_cred and as_cred.lower() != base.lower() else [pn]):
            k = bit.lower()
            if k in seen_pb:
                continue
            seen_pb.add(k)
            perf_bits.append(bit)
    link = ""
    jav_id = None
    if source_label == "JAVStash":
        link = f"https://javstash.org/scenes/{sid}"
        jav_id = sid
    elif source_label == "StashDB":
        link = f"https://stashdb.org/scenes/{sid}"
    elif source_label == "FansDB":
        link = f"https://fansdb.cc/scenes/{sid}"
    tag_names: list[str] = []
    for t in sc.get("tags") or []:
        if isinstance(t, dict) and (t.get("name") or "").strip():
            tag_names.append(str(t["name"]).strip())
    out: dict = {
        "id": sid,
        "title": sc.get("title", "") or "",
        "date": (sc.get("release_date") or "")[:10],
        "studio": (sc.get("studio") or {}).get("name", "") or "",
        "performer": ", ".join(perf_bits),
        "hover_performers": _scene_hover_performer_names(sc),
        "display_performers": _scene_display_performers(sc),
        "thumb": thumb,
        "link": link,
        "source": source_label,
        "tags": tag_names,
        "description": (sc.get("details") or "").strip(),
        "javstash_id": jav_id,
    }
    if source_label == "JAVStash":
        poster_url = thumb
        back_url = ""
        if len(imgs) > 1 and isinstance(imgs[1], dict):
            u2 = (imgs[1].get("url") or "").strip()
            if u2:
                back_url = u2
        out["poster"] = poster_url
        out["background"] = back_url
    return out


def _fetch_javstash_feed_scenes(limit: int = 24) -> list[dict]:
    """Random page of recent JAVStash scenes (stash-box GraphQL)."""
    import random

    key = (db.get_settings().get("api_key_javstash") or "").strip()
    if not key:
        return []
    try:
        gql = """
        query($input: SceneQueryInput!) {
          queryScenes(input: $input) {
            scenes {
              id title release_date details
              studio { name }
              performers { as performer { id name gender } }
              images { url width height }
              tags { name }
            }
          }
        }
        """
        page = random.randint(1, 120)
        body = _stashbox_post(
            JAVSTASH_ENDPOINT,
            key,
            gql,
            {
                "input": {
                    "page": page,
                    "per_page": max(limit * 2, 30),
                    "sort": "DATE",
                    "direction": "DESC",
                }
            },
        )
        raw = ((body.get("queryScenes") or {}).get("scenes")) or []
        out: list[dict] = []
        for sc in raw:
            if not isinstance(sc, dict):
                continue
            card = _stashbox_scene_to_feed_card(sc, source_label="JAVStash")
            if card:
                out.append(card)
            if len(out) >= limit:
                break
        return out[:limit]
    except Exception as e:
        emit(f"FEED javstash error: {e}")
        return []


def _javstash_scenes_for_movie_search(q: str, year: str, *, limit: int = 18) -> list[dict]:
    """JAVStash ``queryScenes`` hits for the /discover (and /scenes) movie title search.

    Merged into ``GET /api/movies/search`` as ``jav_scenes`` — same feed-card
    shape as the JAV feed / scene search (poster, background, filters).
    """
    key = (db.get_settings().get("api_key_javstash") or "").strip()
    if not key:
        return []
    q = (q or "").strip()
    year = (year or "").strip()
    if not q and not (year.isdigit() and len(year) == 4):
        return []
    try:
        per_page = min(max(int(limit or 18), 1), 40)
        input_obj: dict = {
            "page": 1,
            "per_page": per_page,
            "sort": "DATE",
            "direction": "DESC",
        }
        if q:
            input_obj["text"] = q
        if year.isdigit() and len(year) == 4:
            y = int(year)
            input_obj["date"] = {
                "value": f"{y:04d}-01-01",
                "value2": f"{y:04d}-12-31",
                "modifier": "BETWEEN",
            }
        gql = """
        query SearchScenes($input: SceneQueryInput!) {
          queryScenes(input: $input) {
            scenes {
              id title release_date details
              studio { name }
              performers { as performer { id name gender } }
              images { url width height }
              tags { name }
            }
          }
        }
        """
        body = _stashbox_post(
            JAVSTASH_ENDPOINT,
            key,
            gql,
            {"input": input_obj},
        )
        if body.get("errors"):
            emit(f"movies_search javstash GraphQL: {str(body.get('errors'))[:200]}")
        raw = ((body.get("queryScenes") or {}).get("scenes")) or []
        out: list[dict] = []
        for sc in raw:
            if not isinstance(sc, dict):
                continue
            card = _stashbox_scene_to_feed_card(sc, source_label="JAVStash")
            if card:
                out.append(card)
        return out
    except Exception as e:
        emit(f"movies_search javstash: {e}")
        return []


JAVSTASH_FIND_SCENE_FILING_GQL = """
query JavSceneFiling($id: ID!) {
  findScene(id: $id) {
    id title details release_date duration
    studio { name }
    performers { as performer { id name gender } }
    images { url width height }
    tags { name }
  }
}
"""


def _fetch_javstash_scene_for_filing(scene_id: str) -> dict | None:
    sid = str(scene_id or "").strip()
    if not sid:
        return None
    key = (db.get_settings().get("api_key_javstash") or "").strip()
    if not key:
        return None
    try:
        body = _stashbox_post(
            JAVSTASH_ENDPOINT,
            key,
            JAVSTASH_FIND_SCENE_FILING_GQL,
            {"id": sid},
        )
        if body.get("errors"):
            emit(f"javstash findScene: {str(body.get('errors'))[:180]}")
        sc = body.get("findScene") or {}
        if isinstance(sc, dict) and (str(sc.get("id") or "").strip() or (sc.get("title") or "").strip()):
            return sc
        return None
    except Exception as e:
        emit(f"javstash findScene {sid!r}: {e}")
        return None


def _javstash_scene_as_movie_filing_dict(sc: dict) -> dict:
    """Shape a JAVStash stash-box scene into the dict :func:`file_movie` / :func:`build_movie_nfo` expect."""
    imgs = sc.get("images") or []
    poster = ""
    back = None
    if imgs and isinstance(imgs[0], dict):
        poster = (imgs[0].get("url") or "").strip()
    if len(imgs) > 1 and isinstance(imgs[1], dict):
        u2 = (imgs[1].get("url") or "").strip()
        if u2 and u2 != poster:
            back = u2
    perfs: list[str] = []
    for p in sc.get("performers") or []:
        if not isinstance(p, dict):
            continue
        perf = p.get("performer") or {}
        n = perf.get("name") or (p.get("as") or "")
        if n:
            perfs.append(str(n).strip())
    genres: list[str] = []
    for g in sc.get("tags") or []:
        if isinstance(g, dict):
            n = g.get("name")
            if n:
                genres.append(str(n).strip())
    yraw = (sc.get("release_date") or "")[:4]
    y = yraw if len(yraw) == 4 and yraw.isdigit() else "0000"
    sid = str(sc.get("id") or "").strip()
    dur = sc.get("duration")
    try:
        runtime_out = int(dur) if dur is not None else 0
    except (TypeError, ValueError):
        runtime_out = 0
    return {
        "id": "",
        "title": sc.get("title") or "Unknown",
        "year": y,
        "overview": (sc.get("details") or "").strip(),
        "poster_url": poster or None,
        "backdrop_url": back if isinstance(back, str) and back.startswith("http") else None,
        "rating": None,
        "cast": perfs,
        "directors": [],
        "genres": genres,
        "runtime": runtime_out,
        "tagline": "",
        "_javstash_id": sid,
    }


def _javstash_movie_search_first_scene_for_pipeline(query: str, year: str | None) -> dict | None:
    """First JAVStash scene hit for movie-queue auto-match (title + optional year)."""
    cards = _javstash_scenes_for_movie_search(query or "", (year or "").strip(), limit=8)
    for card in cards or []:
        cid = str((card or {}).get("id") or "").strip()
        if not cid:
            continue
        raw = _fetch_javstash_scene_for_filing(cid)
        if raw:
            return raw
    return None


def _tpdb_atom_feed_scene_ids(xml_text: str) -> list[str]:
    """Parse TPDB Atom feeds; return scene UUIDs in document order."""
    import re
    uuid_re = re.compile(
        r"([0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12})",
        re.I,
    )
    try:
        root = ET.fromstring(xml_text)
    except Exception:
        return []
    ns = {"atom": "http://www.w3.org/2005/Atom"}
    entries = root.findall("atom:entry", ns) or root.findall("entry")
    out: list[str] = []
    for entry in entries:
        sid = None
        for link in list(entry.findall("atom:link", ns)) + list(entry.findall("link")):
            href = (link.get("href") or "").strip()
            m = uuid_re.search(href)
            if m:
                sid = m.group(1).lower()
                break
        if not sid:
            id_el = entry.find("atom:id", ns) or entry.find("id")
            if id_el is not None and (id_el.text or "").strip():
                m = uuid_re.search(id_el.text)
                if m:
                    sid = m.group(1).lower()
        if sid:
            out.append(sid)
    return out


TPDB_RSS_FAVORITE_PERFORMERS = (
    "https://theporndb.net/feeds/scenes/recently-added-by-favorite-performers"
)
TPDB_RSS_FAVORITE_SITES = (
    "https://theporndb.net/feeds/scenes/recently-added-by-favorite-sites"
)


def _fetch_tpdb_favorite_rss_feed_scenes(feed_url: str, limit: int, source_tag: str) -> list[dict]:
    """Hydrate scene cards from a single TPDB Atom feed URL (API key auth)."""
    from concurrent.futures import ThreadPoolExecutor, as_completed

    if not (db.get_settings().get("api_key_tpdb") or "").strip():
        return []

    headers = _tpdb_headers()
    ordered_ids: list[str] = []
    try:
        resp = requests.get(feed_url, headers=headers, timeout=22)
        if resp.status_code != 200:
            emit(f"FEED RSS fetch HTTP {resp.status_code} ({feed_url})")
            return []
        ordered_ids = _tpdb_atom_feed_scene_ids(resp.text)
    except Exception as e:
        emit(f"FEED RSS fetch error ({feed_url}): {e}")
        return []

    if not ordered_ids:
        emit(f"FEED RSS: no entries ({feed_url})")
        return []

    take = ordered_ids[: max(limit * 2, limit)]

    def _one(sid: str) -> tuple[str, dict | None]:
        try:
            resp = requests.get(
                f"https://api.theporndb.net/scenes/{sid}",
                headers=_tpdb_headers(),
                timeout=14,
            )
            if resp.status_code != 200:
                return sid, None
            data = resp.json().get("data") or {}
            card = _tpdb_scene_payload_to_feed_card(data, source=source_tag)
            return sid, card
        except Exception:
            return sid, None

    by_id: dict[str, dict] = {}
    with ThreadPoolExecutor(max_workers=4) as pool:
        futures = [pool.submit(_one, sid) for sid in take]
        for fut in as_completed(futures):
            try:
                sid, card = fut.result()
                if card:
                    by_id[sid] = card
            except Exception:
                pass

    ordered = [by_id[sid] for sid in take if sid in by_id]
    ordered.sort(key=lambda x: x.get("date", ""), reverse=True)
    result = ordered[:limit]
    emit(f"FEED RSS ({source_tag}): {len(result)} scenes (from {len(ordered_ids)} feed ids)")
    return result


def _fetch_tpdb_feed_from_favorites_rss(limit: int = 24) -> list[dict]:
    """Scenes from both TPDB favourite-atom feeds (performers then sites), deduped."""
    from concurrent.futures import ThreadPoolExecutor, as_completed

    if not (db.get_settings().get("api_key_tpdb") or "").strip():
        return []

    headers = _tpdb_headers()
    feed_urls = (TPDB_RSS_FAVORITE_PERFORMERS, TPDB_RSS_FAVORITE_SITES)
    seen: set[str] = set()
    ordered_ids: list[str] = []
    for url in feed_urls:
        try:
            resp = requests.get(url, headers=headers, timeout=22)
            if resp.status_code != 200:
                continue
            for sid in _tpdb_atom_feed_scene_ids(resp.text):
                if sid not in seen:
                    seen.add(sid)
                    ordered_ids.append(sid)
        except Exception as e:
            emit(f"FEED RSS fetch error ({url}): {e}")

    if not ordered_ids:
        emit("FEED RSS: no entries (add favourite performers/sites on ThePornDB, or check API key)")
        return []

    take = ordered_ids[: max(limit * 2, limit)]

    def _one(sid: str) -> tuple[str, dict | None]:
        try:
            resp = requests.get(
                f"https://api.theporndb.net/scenes/{sid}",
                headers=_tpdb_headers(),
                timeout=14,
            )
            if resp.status_code != 200:
                return sid, None
            data = resp.json().get("data") or {}
            # Source is "tpdb" (not "rss_favorites") so the frontend's
            # tag-click handler can resolve the per-source blacklist
            # bucket — the rss-vs-api distinction was never consumed.
            card = _tpdb_scene_payload_to_feed_card(data, source="tpdb")
            return sid, card
        except Exception:
            return sid, None

    by_id: dict[str, dict] = {}
    with ThreadPoolExecutor(max_workers=4) as pool:
        futures = [pool.submit(_one, sid) for sid in take]
        for fut in as_completed(futures):
            try:
                sid, card = fut.result()
                if card:
                    by_id[sid] = card
            except Exception:
                pass

    ordered = [by_id[sid] for sid in take if sid in by_id]
    ordered.sort(key=lambda x: x.get("date", ""), reverse=True)
    result = ordered[:limit]
    emit(f"FEED RSS favourites: {len(result)} scenes (from {len(ordered_ids)} feed ids)")
    return result


def _fetch_tpdb_feed_from_api(limit: int = 24) -> list[dict]:
    """Fallback: fetch latest scenes from TPDB API (not personalised).

    Sorts by release date (`order=date direction=desc`) so the global
    fallback feed reflects what's actually been released recently, not
    what TPDB has been busy importing/backfilling.
    """
    try:
        resp = requests.get(
            "https://api.theporndb.net/scenes",
            params={
                "page": 1,
                "per_page": limit,
                "order": "date",
                "direction": "desc",
            },
            headers=_tpdb_headers(),
            timeout=15,
        )
        if resp.status_code != 200:
            return []
        data = resp.json().get("data") or []
        out = []
        for s_item in data:
            card = _tpdb_scene_payload_to_feed_card(s_item, source="tpdb")
            if card:
                out.append(card)
        return out
    except Exception:
        return []


# Raw-scene cache for /scenes Vices (Stash-box ``queryScenes``, tags
# INCLUDES). Feed requests scope the pool to the user's selected tag UUIDs;
# background warmup may still load the full monitored set.
_tag_combined_pool: dict = {"scenes": [], "ts": 0.0, "key": ""}
_TAG_POOL_TTL = 1800  # 30 min
_TAG_POOL_DEEP = 150  # pool depth vs StashDB latency trade-off (still enough for ~30-card feed)

_STASH_TAG_UUID_RE = re.compile(
    r"^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$",
    re.I,
)


def _is_stashdb_tag_uuid(val: object) -> bool:
    s = str(val or "").strip()
    return bool(s and _STASH_TAG_UUID_RE.match(s))


def _stash_uuid_for_saved_vice_tag(t: dict) -> str | None:
    """Resolve one vice / monitored tag row to a StashDB tag UUID."""
    if not isinstance(t, dict):
        return None
    settings = db.get_settings() or {}
    ak = (settings.get("api_key_stashdb") or "").strip()
    name = str(t.get("name") or "").strip()
    tid = str(t.get("stashdb_id") or t.get("stash_id") or "").strip()
    if not _is_stashdb_tag_uuid(tid):
        tid = str(t.get("id") or "").strip()
    if not _is_stashdb_tag_uuid(tid):
        tid = ""
    if not tid and name and ak:
        hits = _stashbox_resolve_entity(STASHDB_ENDPOINT, ak, "tag", name)
        if hits:
            tid = hits[0]
    return tid if tid and _is_stashdb_tag_uuid(tid) else None


def _monitored_stashdb_tag_resolution(stored: list) -> tuple[str, list[str]]:
    """Resolve monitored tag dicts to StashDB tag UUIDs for the vices pool.

    Returns ``(cache_key, tag_uuids)``. Each tag may carry a UUID in
    ``stashdb_id``, ``stash_id``, or ``id``; otherwise ``name`` is resolved
    via StashDB when an API key is configured."""
    ids_out: list[str] = []
    seen: set[str] = set()
    key_bits: list[str] = []

    for t in stored or []:
        if not isinstance(t, dict):
            continue
        name = str(t.get("name") or "").strip()
        tid = _stash_uuid_for_saved_vice_tag(t) or ""
        if tid:
            key_bits.append(f"id:{tid}")
            if tid not in seen:
                seen.add(tid)
                ids_out.append(tid)
        elif name:
            key_bits.append(f"n:{name.lower()}")
        else:
            key_bits.append("x:empty")

    key_bits.sort()
    return (",".join(key_bits), ids_out)


def _fetch_stashdb_scenes_for_tags(tag_ids: list[str], max_scenes: int = _TAG_POOL_DEEP) -> list[dict]:
    """Fetch scenes carrying ANY of ``tag_ids`` from StashDB via ``queryScenes``
    (``tags`` ``INCLUDES``). Paginates up to ``max_scenes``. Mirrors the old
    TPDB two-id padding so a single monitored tag still engages the filter.

    Pages are fetched in parallel batches (4 workers) to cut wall-clock
    latency when the combined pool is cold.
    """
    from concurrent.futures import ThreadPoolExecutor, as_completed

    ids = [str(t).strip() for t in tag_ids or [] if t and str(t).strip()]
    if not ids:
        return []
    api_key = (db.get_settings().get("api_key_stashdb") or "").strip()
    if not api_key:
        return []
    effective = ids if len(ids) >= 2 else ids + ids
    gql = """
    query TagPoolScenes($input: SceneQueryInput!) {
      queryScenes(input: $input) {
        scenes {
          id title release_date details
          studio { name }
          performers { as performer { id name gender } }
          images { url width height }
          tags { id name }
        }
      }
    }
    """
    page_size = 50
    max_page = min(8, max(1, (max_scenes + page_size - 1) // page_size))

    def _one_page(page_no: int) -> tuple[int, list]:
        try:
            body = _stashbox_post(
                STASHDB_ENDPOINT,
                api_key,
                gql,
                {
                    "input": {
                        "tags": {"value": effective, "modifier": "INCLUDES"},
                        "page": page_no,
                        "per_page": page_size,
                        "sort": "DATE",
                        "direction": "DESC",
                    }
                },
            )
            return page_no, ((body.get("queryScenes") or {}).get("scenes")) or []
        except Exception as e:
            emit(f"FEED tags combined fetch page {page_no}: {e}")
            return page_no, []

    seen: set[str] = set()
    out: list[dict] = []
    start = 1
    while len(out) < max_scenes and start <= max_page:
        batch_end = min(start + 3, max_page)
        with ThreadPoolExecutor(max_workers=4) as pool:
            futures = {pool.submit(_one_page, p): p for p in range(start, batch_end + 1)}
            by_page: dict[int, list] = {}
            for fut in as_completed(futures):
                pno, scenes = fut.result()
                by_page[pno] = scenes
        hit_short = False
        for pno in sorted(by_page):
            scenes = by_page[pno]
            if not scenes and pno == 1:
                emit("FEED tags combined fetch: 0 results from StashDB")
            for sc in scenes:
                if not isinstance(sc, dict):
                    continue
                sid = str(sc.get("id") or "").strip()
                if not sid or sid in seen:
                    continue
                seen.add(sid)
                out.append(sc)
                if len(out) >= max_scenes:
                    break
            if len(scenes) < page_size:
                hit_short = True
            if len(out) >= max_scenes:
                break
        if hit_short or len(out) >= max_scenes:
            break
        start = batch_end + 1
    return out[:max_scenes]


def _tag_combined_scene_pool(tag_uuids: list[str] | None = None) -> list[dict]:
    """Return a fresh-enough pool of StashDB scenes for vice tags.

    When ``tag_uuids`` is set (the user's current /scenes Vices selection),
    only those StashDB tag ids are queried and cached — not every monitored
    tag. Background warmup (``tag_uuids is None``) still loads the full
    monitored set for users who select all vices."""
    if tag_uuids is not None:
        ids = []
        seen: set[str] = set()
        for t in tag_uuids:
            s = str(t or "").strip()
            if s and _is_stashdb_tag_uuid(s) and s not in seen:
                seen.add(s)
                ids.append(s)
        key = "sel:" + ",".join(sorted(ids))
        tag_ids = ids
    else:
        try:
            stored = json.loads(db.get_settings().get("monitored_tags") or "[]")
        except Exception:
            stored = []
        key, tag_ids = _monitored_stashdb_tag_resolution(stored if isinstance(stored, list) else [])
    if not tag_ids:
        return []
    fk = _content_filters_fingerprint()
    disk_key = "tag_combined_pool|" + key
    with _content_cache_lock:
        ts = float(_tag_combined_pool.get("ts") or 0)
        scenes = _tag_combined_pool.get("scenes") or []
        cached_key = _tag_combined_pool.get("key") or ""
        if scenes and cached_key == key and (time.time() - ts) < _TAG_POOL_TTL:
            return scenes
    try:
        snap = db.app_json_cache_get(disk_key)
        if isinstance(snap, dict):
            if str(snap.get("key") or "") == key and str(snap.get("content_fp") or "") == str(fk):
                st = float(snap.get("ts") or 0)
                raw_scenes = snap.get("scenes")
                if (time.time() - st) < _TAG_POOL_TTL and isinstance(raw_scenes, list) and raw_scenes:
                    with _content_cache_lock:
                        _tag_combined_pool["scenes"] = raw_scenes
                        _tag_combined_pool["ts"] = time.time()
                        _tag_combined_pool["key"] = key
                    emit(
                        f"FEED tags combined pool: hydrated {len(raw_scenes)} scenes from SQLite ({len(tag_ids)} tag ids, key={key[:48]})"
                    )
                    return raw_scenes
    except Exception:
        pass
    fresh = _fetch_stashdb_scenes_for_tags(tag_ids)
    with _content_cache_lock:
        _tag_combined_pool["scenes"] = fresh
        _tag_combined_pool["ts"] = time.time()
        _tag_combined_pool["key"] = key
    try:
        db.app_json_cache_put(
            disk_key,
            {
                "key": key,
                "content_fp": str(fk),
                "ts": time.time(),
                "scenes": fresh,
            },
        )
    except Exception:
        pass
    emit(f"FEED tags combined pool: cached {len(fresh)} raw StashDB scenes ({len(tag_ids)} tag ids, key={key[:48]})")
    return fresh


def _refresh_tag_scene_pools() -> None:
    """Warm the combined monitored-tag pool. Called on startup and by
    the APScheduler job so selections on /scenes are served instantly."""
    if not (db.get_settings().get("api_key_stashdb") or "").strip():
        return
    with _content_cache_lock:
        _tag_combined_pool["ts"] = 0.0
    _tag_combined_scene_pool()


def _fetch_stashdb_tags_feed_scenes(
    tag_tokens: list[str],
    limit: int = 30,
    selected_names: set[str] | None = None,
    name_by_token: dict[str, str] | None = None,
) -> list[dict]:
    """Scenes for the Vices tab: pool is fetched for ``tag_tokens`` only
    (StashDB UUIDs), then category/blacklist applied. ``matched_tags`` lists
    which selected vice names appear on each scene."""
    toks = [t.strip() for t in (tag_tokens or []) if t and t.strip()]
    if not toks:
        return []
    tok_to_name = name_by_token or {}
    selected_ids: set[str] = {str(t) for t in toks}

    # Build monitored lookups for the *selection* only — scene tags may
    # carry an id (preferred) or just a name; exact equality only.
    sel_by_id: dict[str, str] = {}
    sel_by_name_lower: dict[str, str] = {}
    for tid, raw_name in tok_to_name.items():
        display = (raw_name or "").strip()
        if not display:
            continue
        if tid and str(tid) in selected_ids:
            sel_by_id[str(tid)] = display
            sel_by_name_lower[display.lower()] = display

    merged = _tag_combined_scene_pool(toks)
    if not merged:
        emit("FEED tags: combined pool empty (not warmed yet, or monitored list empty)")
        return []

    def _scene_date(s_item: dict) -> str:
        if not isinstance(s_item, dict):
            return ""
        return str(s_item.get("date") or s_item.get("release_date") or "")[:10]

    merged = sorted(merged, key=_scene_date, reverse=True)

    def _scene_monitored_matches(s_item: dict) -> list[str]:
        """Display names of the currently-selected monitored tags that
        actually appear on this scene's ``tags[]`` payload (by id or
        exact lowercase name)."""
        raw = (s_item or {}).get("tags")
        if not isinstance(raw, list):
            return []
        matched_names: list[str] = []
        seen: set[str] = set()
        for t in raw:
            hit: str | None = None
            if isinstance(t, dict):
                for k in ("id", "_id", "uuid"):
                    v = t.get(k)
                    if v is not None and str(v) in sel_by_id:
                        hit = sel_by_id[str(v)]
                        break
                if hit is None:
                    name = (t.get("name") or t.get("label") or "").strip()
                    if not name and isinstance(t.get("tag"), dict):
                        name = (t["tag"].get("name") or "").strip()
                    if name and name.lower() in sel_by_name_lower:
                        hit = sel_by_name_lower[name.lower()]
            elif isinstance(t, str):
                key = t.strip().lower()
                if key in sel_by_name_lower:
                    hit = sel_by_name_lower[key]
            if hit and hit not in seen:
                seen.add(hit)
                matched_names.append(hit)
        return matched_names

    out: list[dict] = []
    dropped_filter = 0
    dropped_no_match = 0
    for s_item in merged:
        if len(out) >= limit:
            break
        matches = _scene_monitored_matches(s_item)
        if not matches:
            dropped_no_match += 1
            continue
        try:
            card = _stashbox_scene_to_feed_card(s_item, source_label="StashDB")
        except Exception as e:
            emit(f"FEED tags card exception: {e}")
            continue
        if not card:
            dropped_filter += 1
            continue
        card["matched_tags"] = matches
        out.append(card)
    emit(
        f"FEED tags merged: {len(out)} cards "
        f"({len(merged)} pool, {dropped_filter} category/blacklist, "
        f"{dropped_no_match} no-monitored-tag)"
    )
    return out


def _library_performer_name_keys() -> set[str]:
    """Lowercased lookup keys for every performer in the library —
    folder name, canonical match_*_name columns, saved aliases, and JAV
    display name. Used so the Performers tab keeps scenes whose Stash
    credits use stage names / CJK aliases that match the library row."""
    keys: set[str] = set()
    try:
        rows = db.favourite_list()
    except Exception:
        return keys
    for r in rows:
        if r.get("kind") != "performer":
            continue
        for field in (
            "folder_name",
            "match_tpdb_name",
            "match_stashdb_name",
            "match_fansdb_name",
            "match_javstash_name",
        ):
            v = (r.get(field) or "").lower().strip()
            if v:
                keys.add(v)
        raw_aliases = r.get("aliases_json")
        if not raw_aliases:
            continue
        try:
            parsed = json.loads(raw_aliases) if isinstance(raw_aliases, str) else raw_aliases
        except (json.JSONDecodeError, TypeError):
            parsed = None
        for a in _performer_aliases_as_strings(parsed):
            v = a.lower().strip()
            if v:
                keys.add(v)
    return keys


def _scene_credit_names(scene: dict) -> list[str]:
    """All performer-name strings carried on a feed scene card —
    pulled from `display_performers`, `hover_performers`, and the
    flat comma-joined `performer` string."""
    names: list[str] = []
    for entry in (scene.get("display_performers") or []):
        if isinstance(entry, dict):
            n = (entry.get("name") or "").strip()
            if n:
                names.append(n)
        elif isinstance(entry, str) and entry.strip():
            names.append(entry.strip())
    for n in (scene.get("hover_performers") or []):
        if isinstance(n, str) and n.strip():
            names.append(n.strip())
    pflat = (scene.get("performer") or "").strip()
    if pflat:
        for piece in pflat.split(","):
            piece = piece.strip()
            if piece:
                names.append(piece)
    return names


def _filter_scenes_to_library_performers(scenes: list[dict]) -> list[dict]:
    """Drop scenes whose credits don't intersect the library performer set.
    No-op when the library is empty (avoids returning an empty grid for a
    fresh install)."""
    lib = _library_performer_name_keys()
    if not lib:
        return scenes
    out: list[dict] = []
    for s in scenes or []:
        for n in _scene_credit_names(s):
            if n.lower() in lib:
                out.append(s)
                break
    return out


def _library_stashdb_performer_ids() -> list[str]:
    """Ordered unique ``match_stashdb_id`` values from performer favourites."""
    out: list[str] = []
    seen: set[str] = set()
    try:
        for r in db.favourite_list():
            if r.get("kind") != "performer":
                continue
            pid = str(r.get("match_stashdb_id") or "").strip()
            if not pid or pid in seen:
                continue
            seen.add(pid)
            out.append(pid)
    except Exception:
        pass
    return out


