def _merge_feed_cards_by_date_desc(
    a: list[dict],
    b: list[dict],
    limit: int,
) -> list[dict]:
    """Combine two feed lists, newest ``date`` first, dedupe by (source, id)."""
    seen: set[tuple[str, str]] = set()
    out: list[dict] = []
    for card in sorted(
        (a or []) + (b or []),
        key=lambda c: str(c.get("date") or ""),
        reverse=True,
    ):
        if not isinstance(card, dict):
            continue
        sid = str(card.get("id") or "").strip()
        if not sid:
            continue
        src = str(card.get("source") or "")
        key = (src, sid)
        if key in seen:
            continue
        seen.add(key)
        out.append(card)
        if len(out) >= limit:
            break
    return out


def _stashbox_scenes_for_performer_id_chunks(
    endpoint: str,
    api_key: str,
    pids_all: list[str],
    per_page: int,
    *,
    gql_query: str,
    log_label: str,
) -> tuple[list[dict], bool]:
    """Run ``queryScenes`` with ``performers INCLUDES`` for each 50-id chunk;
    merge and dedupe by scene id, sort by ``release_date`` desc.

    Returns ``(scenes, any_request_ok)`` so callers can distinguish API
    failure from an empty result set.
    """
    if not (api_key or "").strip() or not pids_all:
        return [], False
    merged: dict[str, dict] = {}
    any_ok = False
    max_chunks = 12  # 600 performer ids max per feed build — keeps latency bounded
    for ci, i in enumerate(range(0, len(pids_all), 50)):
        if ci >= max_chunks:
            break
        chunk = pids_all[i : i + 50]
        if not chunk:
            continue
        try:
            body = _stashbox_post(
                endpoint,
                api_key,
                gql_query,
                {
                    "input": {
                        "performers": {"value": chunk, "modifier": "INCLUDES"},
                        "page": 1,
                        "per_page": per_page,
                        "sort": "DATE",
                        "direction": "DESC",
                    }
                },
            )
            any_ok = True
            raw = ((body.get("queryScenes") or {}).get("scenes")) or []
        except Exception as e:
            emit(f"FEED {log_label} performers chunk {i // 50 + 1}: {e}")
            continue
        for sc in raw:
            if not isinstance(sc, dict):
                continue
            sid = str(sc.get("id") or "").strip()
            if sid and sid not in merged:
                merged[sid] = sc
    ordered = sorted(
        merged.values(),
        key=lambda sc: str(sc.get("release_date") or "")[:10],
        reverse=True,
    )
    return ordered, any_ok


def _fetch_stashdb_performers_feed_scenes(
    limit: int = 24,
    *,
    cap: int | None = None,
) -> tuple[list[dict], str]:
    """Performers tab: recent StashDB scenes credited to any library performer
    with a ``match_stashdb_id``. Uses one ``queryScenes`` per 50 performer ids
    (``INCLUDES`` = any in chunk), merged so large libraries are not randomly
    subsampled.

    ``cap`` — stop after this many raw cards (defaults to ``limit``); use a
    larger value when merging with FansDB so the post-filter list stays full.
    """
    settings = db.get_settings()
    api_key = (settings.get("api_key_stashdb") or "").strip()
    if not api_key:
        return [], "no_stashdb_key"

    pids = _library_stashdb_performer_ids()
    if not pids:
        return [], "no_stashdb_performer_ids"

    gql = """
    query StashdbPerformerFeed($input: SceneQueryInput!) {
      queryScenes(input: $input) {
        scenes {
          id title release_date details
          studio { name }
          performers { as performer { id name gender } }
          images { url width height }
          tags { name }
        }
      }
    }
    """
    fetch_count = min(max(limit * 2, limit + 6), 50)
    raw, ok = _stashbox_scenes_for_performer_id_chunks(
        STASHDB_ENDPOINT,
        api_key,
        pids,
        fetch_count,
        gql_query=gql,
        log_label="stashdb",
    )
    if not raw and pids and not ok:
        return [], "stashdb_error"

    stop = cap if cap is not None else limit
    cards: list[dict] = []
    for sc in raw:
        card = _stashbox_scene_to_feed_card(sc, source_label="StashDB")
        if card:
            cards.append(card)
        if len(cards) >= stop:
            break
    return _filter_scenes_to_library_performers(cards), "stashdb_performers"


