@app.get("/api/downloads")
async def api_downloads(category: str | None = None):
    """Active + recent NZB history and torrent list from Settings download
    clients. Default category serves from the warm snapshot (instant);
    explicit non-default categories fall back to a live build."""
    if category is None or category == "":
        return _downloads_warm.get()
    return download_clients_combined_status(category)


@app.get("/api/downloads/stream")
async def api_downloads_stream(request: Request, category: str | None = None):
    """SSE stream of download-client state. The client connects once when
    /downloads loads; we poll the warm snapshot, hash it, and push only
    when the payload actually changes (plus a 25-second heartbeat so
    proxies don't drop idle connections). The warm snapshot already
    drives upstream client polling at 10s — the SSE loop never hits the
    download clients directly, it just observes snapshot changes."""
    async def _gen():
        import asyncio as _aio
        last_sig: str | None = None
        last_push = 0.0
        # Tight poll on the snapshot (cheap — it's just a dict
        # reference read). The warm cache decides when to actually
        # hit NZBGet / SAB / qBittorrent.
        snapshot_poll_s = 2.0
        while True:
            if await request.is_disconnected():
                return
            if category is None or category == "":
                payload = _downloads_warm.get()
            else:
                try:
                    payload = await run_in_threadpool(
                        download_clients_combined_status, category
                    )
                except Exception as e:
                    payload = {"error": str(e)}
            try:
                data = json.dumps(payload, default=str, sort_keys=True)
            except Exception:
                data = json.dumps({"error": "serialise failed"})
            sig = hashlib.sha1(data.encode("utf-8")).hexdigest()
            now = time.time()
            should_push = (sig != last_sig) or ((now - last_push) > 25.0)
            if should_push:
                yield f"event: state\ndata: {data}\n\n"
                last_sig = sig
                last_push = now
            try:
                await _aio.sleep(snapshot_poll_s)
            except _aio.CancelledError:
                return
    return StreamingResponse(
        _gen(),
        media_type="text/event-stream",
        headers={
            "Cache-Control": "no-cache, no-transform",
            "X-Accel-Buffering": "no",  # disable nginx buffering if proxied
        },
    )


@app.get("/api/downloads/stats")
async def api_downloads_stats():
    """Lightweight active / pending / complete counters for the header LCD strip.

    Re-uses ``download_clients_combined_status`` (already aggregates NZB +
    torrent rows) and bins each item by queue + status:

    * active   — ``queue == 'active'`` and the client status does NOT
                 indicate paused / queued / stalled. These are jobs
                 currently downloading bytes.
    * pending  — ``queue == 'active'`` but status reads paused / queued
                 / stalled. Job is in the active queue but not running.
    * complete — ``queue == 'history'``. Successfully finished jobs from
                 each client's recent history.
    """
    data = _downloads_warm.get()
    active = 0
    pending = 0
    complete = 0
    for it in (data.get("items") or []):
        q = str(it.get("queue") or "").lower()
        st = str(it.get("status") or "").lower()
        if q == "active":
            if any(tok in st for tok in ("paus", "queue", "stalled", "waiting")):
                pending += 1
            else:
                active += 1
        elif q == "history":
            complete += 1
    try:
        qdata = _queue_warm.get()
        queue_count = len(qdata.get("files") or [])
    except Exception:
        queue_count = 0
    return {"active": active, "pending": pending, "complete": complete, "queue": queue_count}


@app.get("/api/downloads/rss-feed")
async def api_downloads_rss_feed(refresh: bool = False):
    """Grouped RSS feed results, served from hourly cache. Pass ?refresh=true to force a reload."""
    if not refresh:
        _maybe_hydrate_rss_cache_from_disk()
    with _rss_cache_lock:
        has_cache = bool(_rss_cache.get("fetched_at"))
    if refresh:
        await asyncio.get_event_loop().run_in_executor(None, _refresh_rss_cache)
    elif not has_cache:
        await asyncio.get_event_loop().run_in_executor(None, _refresh_rss_cache)
    else:
        _schedule_rss_cache_refresh_if_stale()

    with _rss_cache_lock:
        items = list(_rss_cache["items"])
        errors = list(_rss_cache["errors"])
        fetched_at = _rss_cache["fetched_at"]

    s = db.get_settings()
    raw = s.get("download_rss_feeds") or "[]"
    try:
        urls = json.loads(raw)
    except Exception:
        urls = []
    urls = [u.strip() for u in (urls if isinstance(urls, list) else []) if isinstance(u, str) and u.strip()]

    diagnostics = {
        "configured_urls": len(urls),
        "items_after_filter": len(items),
        "fetched_at": fetched_at,
        "cache_age_minutes": round((time.time() - fetched_at) / 60, 1) if fetched_at else None,
    }

    return {"results": items, "errors": errors, "diagnostics": diagnostics}


@app.get("/api/prowlarr/status")
async def prowlarr_status():
    s = db.get_settings()
    base = s.get("prowlarr_url", "").rstrip("/")
    if not base:
        return {"connected": False, "error": "Not configured"}
    try:
        resp = requests.get(f"{base}/api/v1/system/status",
                            headers=_prowlarr_headers(), timeout=8)
        resp.raise_for_status()
        d = resp.json()
        return {"connected": True, "version": d.get("version")}
    except Exception as e:
        return {"connected": False, "error": str(e)}


@app.post("/api/settings/test-download-client")
async def settings_test_download_client(payload: dict):
    """Test NZB or torrent client credentials from the Settings form.

    Body: ``{"kind": "nzb"|"torrent", "config": {...}}``. Secret fields left
    blank in ``config`` fall back to values already saved in SQLite.
    """
    kind = (payload.get("kind") or "").strip().lower()
    if kind not in ("nzb", "torrent"):
        return JSONResponse({"ok": False, "error": "kind must be nzb or torrent"}, status_code=400)
    stored = db.get_settings()
    s = _dl_test_settings_overlay(stored, kind, payload.get("config") or {})
    if kind == "nzb":
        ncfg = _dl_resolve_nzb_settings(s)
        if not ncfg:
            return {"ok": False, "error": "Configure client and host first"}
        return _test_dl_nzb_connection(ncfg)
    tcfg = _dl_resolve_torrent_settings(s)
    if not tcfg:
        return {"ok": False, "error": "Configure client and host first"}
    return _test_dl_torrent_connection(tcfg)


@app.get("/api/metadata/preview")
async def metadata_preview(type: str, source: str, id: str):
    """Fetch preview data (image, bio, meta, links) without creating any files."""
    if type == "performer":
        source = _normalize_metadata_db_source(source)
        data = fetch_performer_detail(source, id)
        if not data:
            return {"image": None, "bio": "", "meta": "", "links": []}
        extras  = data.get("extras") or {}
        posters = data.get("posters") or []
        image   = posters[0].get("url") if posters and isinstance(posters[0], dict) else (posters[0] if posters else None)
        bio     = data.get("bio") or ""
        aliases = data.get("aliases") or []
        slug    = data.get("slug") or data.get("_id") or id
        meta_parts = [f"<span>{source}</span>"]
        if extras.get("birthday"):       meta_parts.append(f"Born: <span>{extras['birthday']}</span>")
        if extras.get("birthplace"):     meta_parts.append(f"From: <span>{extras['birthplace']}</span>")
        if extras.get("career_start_year"): meta_parts.append(f"Active: <span>{extras['career_start_year']}</span>")
        if extras.get("ethnicity"):      meta_parts.append(f"Ethnicity: <span>{extras['ethnicity']}</span>")
        if extras.get("measurements"):   meta_parts.append(f"Stats: <span>{extras['measurements']}</span>")
        if aliases: meta_parts.append(f"AKA: <span>{', '.join(aliases[:3])}</span>")

        # Build links — cross-reference all databases
        links = []
        performer_name = data.get("name") or ""
        settings = db.get_settings()

        # TPDB link
        if source == "TPDB":
            links.append({"label": "TPDB", "url": f"https://theporndb.net/performers/{slug}"})
        elif performer_name and settings.get("api_key_tpdb"):
            try:
                r = requests.get(TPDB_PERFORMER_SEARCH, params={"q": performer_name},
                                 headers=_tpdb_headers(), timeout=8)
                if r.status_code == 200:
                    pd = r.json().get("data") or []
                    if pd:
                        tslug = pd[0].get("slug") or pd[0].get("_id") or str(pd[0].get("id", ""))
                        links.append({"label": "TPDB", "url": f"https://theporndb.net/performers/{tslug}"})
            except Exception:
                pass

        # StashDB link + external URLs
        if settings.get("api_key_stashdb"):
            try:
                gql = 'query($t:String!){searchPerformer(term:$t,limit:1){id name urls{url type}}}'
                r = requests.post("https://stashdb.org/graphql",
                    json={"query": gql, "variables": {"t": performer_name}},
                    headers={"ApiKey": settings['api_key_stashdb'],
                             "Content-Type": "application/json"}, timeout=8)
                if r.status_code == 200:
                    sp = (r.json().get("data") or {}).get("searchPerformer") or []
                    if sp:
                        links.append({"label": "StashDB", "url": f"https://stashdb.org/performers/{sp[0]['id']}"})
                        # Add external URLs from StashDB performer profile
                        for u in (sp[0].get("urls") or []):
                            url = u.get("url", "")
                            if url:
                                label = _url_label(url)
                                # Don't duplicate links we already have
                                if not any(l["url"] == url for l in links):
                                    links.append({"label": label, "url": url})
            except Exception:
                pass

        # FansDB link
        if source == "FansDB":
            links.append({"label": "FansDB", "url": f"https://fansdb.cc/performers/{id}"})
        elif performer_name and settings.get("api_key_fansdb"):
            try:
                gql = "query($term:String!){searchPerformer(term:$term,limit:1){id name}}"
                data = _fansdb_gql(gql, {"term": performer_name})
                sp = (data or {}).get("searchPerformer") or []
                if sp:
                    links.append({"label": "FansDB", "url": f"https://fansdb.cc/performers/{sp[0]['id']}"})
            except Exception:
                pass

        if source == "JAVStash":
            links.append({"label": "JAVStash", "url": f"https://javstash.org/performers/{id}"})
        elif performer_name and (settings.get("api_key_javstash") or "").strip():
            try:
                # Same searchPerformer shape as ``search_performers`` / scenes/recent
                # (JAVStash stash-box can be picky about query formatting).
                gql = """
                query($t: String!) {
                  searchPerformer(term: $t, limit: 1) {
                    id name
                  }
                }
                """
                jk = (settings.get("api_key_javstash") or "").strip()
                r = requests.post(
                    JAVSTASH_ENDPOINT,
                    json={"query": gql, "variables": {"t": performer_name}},
                    headers={"ApiKey": jk, "Content-Type": "application/json"},
                    timeout=8,
                )
                if r.status_code == 200:
                    body = r.json() or {}
                    if body.get("errors"):
                        emit(f"metadata_preview: JAVStash searchPerformer errors: {body.get('errors')}")
                    else:
                        sp = (body.get("data") or {}).get("searchPerformer") or []
                        if sp:
                            links.append({"label": "JAVStash", "url": f"https://javstash.org/performers/{sp[0]['id']}"})
            except Exception as e:
                emit(f"metadata_preview: JAVStash cross-ref search failed: {e}")

        # Pull external links from TPDB extras if available
        for link_item in (data.get("urls") or data.get("links") or []):
            if isinstance(link_item, str):
                links.append({"label": _url_label(link_item), "url": link_item})
            elif isinstance(link_item, dict):
                url = link_item.get("url") or link_item.get("link") or ""
                label = link_item.get("type") or link_item.get("label") or _url_label(url)
                if url:
                    links.append({"label": label, "url": url})

        return {"image": image, "bio": bio if bio else "", "meta": " &middot; ".join(meta_parts),
                "slug": slug, "links": links,
                "country": (extras.get("nationality") or "").strip()}
    else:
        data = fetch_studio_detail(source, id)
        if not data:
            return {"image": None, "bio": "", "meta": "", "links": []}
        image = data.get("logo") or data.get("poster")
        bio   = data.get("description") or data.get("bio") or ""
        slug  = data.get("slug") or data.get("_id") or id
        links = []
        if source == "TPDB":
            links.append({"label": "TPDB", "url": f"https://theporndb.net/sites/{slug}"})
        # Pull external links
        for link_item in (data.get("urls") or data.get("links") or data.get("url") and [data["url"]] or []):
            if isinstance(link_item, str):
                links.append({"label": _url_label(link_item), "url": link_item})
            elif isinstance(link_item, dict):
                url = link_item.get("url") or link_item.get("link") or ""
                label = link_item.get("type") or link_item.get("label") or _url_label(url)
                if url:
                    links.append({"label": label, "url": url})
        return {"image": image, "bio": bio if bio else "", "meta": f"<span>{source}</span>",
                "links": links}


def _url_label(url: str) -> str:
    """Extract a short label from a URL domain."""
    try:
        from urllib.parse import urlparse
        domain = urlparse(url).netloc.lower().replace("www.", "")
        labels = {
            "twitter.com": "Twitter", "x.com": "Twitter",
            "instagram.com": "Instagram",
            "reddit.com": "Reddit",
            "onlyfans.com": "OnlyFans",
            "fansly.com": "Fansly",
            "pornhub.com": "Pornhub",
            "xvideos.com": "XVideos",
            "theporndb.net": "TPDB",
            "stashdb.org": "StashDB",
            "fansdb.cc": "FansDB",
            "javstash.org": "JAVStash",
            "babepedia.com": "Babepedia",
            "freeones.com": "FreeOnes",
            "iafd.com": "IAFD",
        }
        return labels.get(domain, domain.split(".")[0].title())
    except Exception:
        return "Link"


def _fmt_measurements(p: dict | None) -> str:
    """Format performer measurement fields → '34D-24-36' from top-level StashDB fields."""
    if not p:
        return ""
    parts = []
    band = p.get("band_size")
    cup  = (p.get("cup_size") or "").strip().upper()
    if band and cup:
        parts.append(f"{band}{cup}")
    elif band:
        parts.append(str(band))
    if p.get("waist_size"):
        parts.append(str(p["waist_size"]))
    if p.get("hip_size"):
        parts.append(str(p["hip_size"]))
    return "-".join(parts)


# StashDB performer query for spotlight row
STASHDB_PERFORMER_QUERY = """
query QueryPerformers($input: PerformerQueryInput!) {
  queryPerformers(input: $input) {
    count
    performers {
      id
      name
      gender
      images { url }
      scene_count
      age
      created
      updated
      birth_date
      death_date
      career_start_year
      height
      cup_size
      band_size
      waist_size
      hip_size
      breast_type
      country
      ethnicity
      eye_color
      hair_color
      tattoos { location }
      piercings { location }
    }
  }
}
"""

# Scene-driven spotlight query — walks recent scenes and harvests their
# performers. Densely-populated, naturally surfaces active performers,
# and accepts a tag filter so the spotlight can be narrowed to specific
# scene types. The nested performer block mirrors the fields requested
# by STASHDB_PERFORMER_QUERY so the existing scoring/filter pipeline
# runs unchanged on the harvested candidates.
SPOTLIGHT_SCENES_QUERY = """
query SpotlightScenes($input: SceneQueryInput!) {
  queryScenes(input: $input) {
    count
    scenes {
      id release_date
      studio { name }
      performers {
        performer {
          id
          name
          gender
          images { url }
          scene_count
          age
          created
          updated
          birth_date
          death_date
          career_start_year
          height
          cup_size
          band_size
          waist_size
          hip_size
          breast_type
          country
          ethnicity
          eye_color
          hair_color
          tattoos { location }
          piercings { location }
        }
      }
    }
  }
}
"""


def _spotlight_studio_blacklist(s: dict) -> list[str]:
    """Parse the spotlight studio blacklist setting into lowercase phrases.

    Comma-separated input. Each entry is a contiguous phrase match (matched
    as a case-insensitive substring against the scene's studio name). So
    "JAV" rejects any studio whose name contains "jav" anywhere; "i feel
    myself" rejects studios whose name contains that exact phrase in that
    order. Empty list disables filtering.
    """
    raw = (s.get("spotlight_studio_blacklist") or "").strip()
    if not raw:
        return []
    return [p.strip().lower() for p in raw.split(",") if p.strip()]


def _spotlight_studio_preferred(s: dict) -> list[str]:
    """Parse the spotlight preferred-studio setting. Same format as the
    blacklist — comma-separated lowercase phrases, substring-matched
    case-insensitively against the studio name. Empty list disables."""
    raw = (s.get("spotlight_studio_preferred") or "").strip()
    if not raw:
        return []
    return [p.strip().lower() for p in raw.split(",") if p.strip()]


def _spotlight_studio_name_matches(name: str, phrases: list[str]) -> bool:
    """True when the studio name contains any of the phrases. Shared
    primitive for both blacklist (reject) and preferred (boost/require)
    matching so behaviour stays in sync between the two lists."""
    if not phrases or not name:
        return False
    nl = name.lower()
    return any(kw in nl for kw in phrases)


def _spotlight_scene_studio_blacklisted(scene: dict, blacklist: list[str]) -> bool:
    """True when the scene's studio name contains any blacklist phrase."""
    return _spotlight_studio_name_matches((scene.get("studio") or {}).get("name") or "", blacklist)


def _spotlight_studios_in_payload_match_preferred(payload_studios: list[str], preferred: list[str]) -> bool:
    """True when ANY of the studio names attached to a cached performer
    payload matches a preferred phrase. Used by the scorer at read-time
    to award the prefer-mode bonus without re-harvest."""
    if not preferred or not payload_studios:
        return False
    return any(_spotlight_studio_name_matches(s, preferred) for s in payload_studios)

# Cup size ordinal for body-type classification
_CUP_RANK: dict[str, int] = {
    "A": 1, "B": 2, "C": 3, "D": 4, "DD": 5, "DDD": 6, "E": 6,
    "F": 7, "FF": 7, "G": 8, "GG": 8, "H": 9, "HH": 9,
}


def _spotlight_body_types(p: dict) -> set[str]:
    """Derive body-type tags from a performer's measurement/height fields.

    Tags: petite | tall | slim | athletic | curvy | busty | voluptuous
    Returns an empty set when there is not enough data to classify.
    """
    cup_raw  = (p.get("cup_size") or "").strip().upper()
    cup_rank = _CUP_RANK.get(cup_raw, 0)
    band     = p.get("band_size")     # int, inches
    waist    = p.get("waist_size")    # int, inches
    hip      = p.get("hip_size")      # int, inches
    height   = p.get("height")        # int, cm

    tags: set[str] = set()

    # Height-based
    if height:
        if height <= 163:
            tags.add("petite")
        if height >= 173:
            tags.add("tall")

    # Bust-based
    if cup_rank >= 5:                          # DD or larger
        tags.add("busty")
    if cup_rank >= 5 or (band and band >= 36):
        tags.add("voluptuous")

    # Waist-driven shape
    if waist:
        if waist <= 25 and (not cup_rank or cup_rank <= 3) and (not band or band <= 34):
            tags.add("slim")
        # Athletic: taller, lean waist, smaller bust
        if height and height >= 168 and waist <= 27 and cup_rank and cup_rank <= 3:
            tags.add("athletic")

    # Hip-to-waist ratio
    if hip and waist and (hip - waist) >= 12:
        tags.add("curvy")
    elif cup_rank >= 4 and not ("voluptuous" in tags):
        tags.add("curvy")

    return tags


def _spotlight_age_hard_limits(s: dict) -> tuple[int | None, int | None]:
    """Hard lower/upper age gates (independent of prefer/require mode)."""
    lo = int(s.get("spotlight_age_limit_min") or 0) or None
    hi = int(s.get("spotlight_age_limit_max") or 0) or None
    return lo, hi


def _spotlight_fails_age_hard_limits(age: int | None, cfg: dict) -> bool:
    if cfg.get("age_hard_min") is None and cfg.get("age_hard_max") is None:
        return False
    if age is None:
        return not cfg.get("age_incl_null")
    if cfg.get("age_hard_min") is not None and age < cfg["age_hard_min"]:
        return True
    if cfg.get("age_hard_max") is not None and age > cfg["age_hard_max"]:
        return True
    return False


def _spotlight_age(birthdate_str: str) -> int | None:
    if not birthdate_str:
        return None
    try:
        bd = _date.fromisoformat(birthdate_str[:10])
        today = _date.today()
        return today.year - bd.year - ((today.month, today.day) < (bd.month, bd.day))
    except Exception:
        return None


_SPOTLIGHT_LIB_LOOKUP_CACHE: dict = {"ts": 0.0, "data": None}
_SPOTLIGHT_LIB_LOOKUP_TTL = 90.0


def _spotlight_library_lookup(s: dict | None = None) -> dict:
    """Cached index of library performers: normalised names + source ids."""
    now = time.time()
    cached = _SPOTLIGHT_LIB_LOOKUP_CACHE.get("data")
    if cached and (now - float(_SPOTLIGHT_LIB_LOOKUP_CACHE.get("ts") or 0)) < _SPOTLIGHT_LIB_LOOKUP_TTL:
        return cached

    s = s or (db.get_settings() or {})
    names: set[str] = set()
    stash_ids: set[str] = set()
    tpdb_ids: set[str] = set()
    fans_ids: set[str] = set()
    jav_ids: set[str] = set()

    def _add_name(raw: object) -> None:
        n = normalise(str(raw or ""))
        if n:
            names.add(n)

    def _add_id(bucket: set[str], raw: object) -> None:
        v = str(raw or "").strip()
        if v:
            bucket.add(v)

    dirs = [s.get("series_dir", ""), s.get("features_dir", "")] + [
        d["path"] for d in db.get_directories()
    ]
    jav_d = (s.get("jav_dir") or "").strip()
    if jav_d:
        dirs.append(jav_d)
    for dir_path in dirs:
        if not dir_path:
            continue
        base = Path(dir_path)
        if not base.exists():
            continue
        try:
            for folder in base.iterdir():
                if folder.is_dir():
                    _add_name(folder.name)
        except OSError:
            continue

    try:
        for entity in db.favourite_list():
            if (entity.get("kind") or "").strip().lower() != "performer":
                continue
            _add_name(entity.get("folder_name"))
            for field in (
                "match_tpdb_name",
                "match_stashdb_name",
                "match_fansdb_name",
                "match_javstash_name",
            ):
                _add_name(entity.get(field))
            _add_id(stash_ids, entity.get("match_stashdb_id"))
            _add_id(tpdb_ids, entity.get("match_tpdb_id"))
            _add_id(fans_ids, entity.get("match_fansdb_id"))
            _add_id(jav_ids, entity.get("match_javstash_id"))
            raw = entity.get("aliases_json")
            if not raw:
                continue
            try:
                aliases = json.loads(raw) if isinstance(raw, str) else raw
            except (json.JSONDecodeError, TypeError):
                continue
            for alias in _performer_aliases_as_strings(aliases):
                _add_name(alias)
    except Exception as e:
        _log.debug("spotlight library lookup favourites: %s", e)

    data = {
        "names": names,
        "stash_ids": stash_ids,
        "tpdb_ids": tpdb_ids,
        "fans_ids": fans_ids,
        "jav_ids": jav_ids,
    }
    _SPOTLIGHT_LIB_LOOKUP_CACHE["ts"] = now
    _SPOTLIGHT_LIB_LOOKUP_CACHE["data"] = data
    return data


def _spotlight_performer_in_library(
    performer: dict,
    s: dict | None = None,
    lookup: dict | None = None,
) -> bool:
    """True when this spotlight row matches a library performer folder or id."""
    if not isinstance(performer, dict):
        return False
    pid = str(performer.get("id") or "").strip()
    if pid.startswith("lib:"):
        return True
    if lookup is None:
        lookup = _spotlight_library_lookup(s)
    name = (performer.get("name") or "").strip()
    if name and normalise(name) in lookup["names"]:
        return True
    if not pid:
        return False
    src = (performer.get("source") or performer.get("_source") or "").strip().upper()
    if src in ("STASHDB", "STASH"):
        return pid in lookup["stash_ids"]
    if src == "TPDB":
        return pid in lookup["tpdb_ids"]
    if src in ("FANSDB", "FANS"):
        return pid in lookup["fans_ids"]
    if src in ("JAVSTASH", "JAV"):
        return pid in lookup["jav_ids"]
    return (
        pid in lookup["stash_ids"]
        or pid in lookup["tpdb_ids"]
        or pid in lookup["fans_ids"]
        or pid in lookup["jav_ids"]
    )


def _spotlight_in_library(name: str, s: dict, lookup: dict | None = None) -> bool:
    """Name-only library check (used where only a string is available)."""
    norm = normalise(name)
    if not norm:
        return False
    if lookup is None:
        lookup = _spotlight_library_lookup(s)
    return norm in lookup["names"]


