def _normalise_country(raw: str) -> str:
    """Lowercase and canonicalise a country string using known alias mapping."""
    s = (raw or "").strip().lower()
    return _COUNTRY_ALIASES.get(s, s)


def _spotlight_infer_career_start(p: dict, age: int | None) -> int | None:
    """Return career_start_year from the performer dict, or infer it from age (assumed start at 18)."""
    csy = p.get("career_start_year")
    if csy is not None:
        return csy
    if age is not None:
        return _date.today().year - age + 18
    return None


def _spotlight_first_failing_filter(p: dict, cfg: dict, age: int | None) -> str | None:
    """Return the name of the first hard filter that rejected this performer,
    or None if they pass everything. Used by the debug endpoint to show
    which filter is killing the most candidates. Mirrors the logic in
    `_spotlight_passes_hard_filters` exactly so a `None` result here is
    equivalent to a True there."""
    if (p.get("death_date") or "").strip():
        return "deceased"
    if cfg["min_scenes_mode"] == "require":
        if (p.get("scene_count") or 0) < cfg["min_scenes"]:
            return "min_scenes"
    if cfg["active_mode"] == "require" and cfg["recent_cutoff"]:
        updated_str = p.get("updated") or ""
        if not updated_str:
            if not cfg["recent_incl_null"]:
                return "active"
        else:
            try:
                updated_dt = datetime.fromisoformat(updated_str.replace("Z", "+00:00"))
                if updated_dt < cfg["recent_cutoff"]:
                    return "active"
            except Exception:
                if not cfg["recent_incl_null"]:
                    return "active"
    if cfg["gender_mode"] == "require" and cfg["genders_filter"] and len(cfg["genders_filter"]) > 1:
        val = (p.get("gender") or "").upper()
        if not val:
            if not cfg["genders_incl_null"]:
                return "gender"
        elif val not in cfg["genders_filter"]:
            return "gender"
    if _spotlight_fails_age_hard_limits(age, cfg):
        if age is None:
            return "age_hard_null"
        if cfg.get("age_hard_min") is not None and age < cfg["age_hard_min"]:
            return "age_below_hard_min"
        return "age_above_hard_max"
    if cfg["age_mode"] == "require" and (cfg["min_age"] is not None or cfg["max_age"] is not None):
        if age is None:
            if not cfg["age_incl_null"]:
                return "age_null"
        else:
            if cfg["min_age"] is not None and age < cfg["min_age"]:
                return "age_below_min"
            if cfg["max_age"] is not None and age > cfg["max_age"]:
                return "age_above_max"
    if cfg["career_min"] is not None or cfg["career_max"] is not None:
        csy = _spotlight_infer_career_start(p, age)
        if csy is None:
            if not cfg["career_incl_null"]:
                return "career_start_null"
        else:
            if cfg["career_min"] is not None and csy < cfg["career_min"]:
                return "career_start_too_old"
            if cfg["career_max"] is not None and csy > cfg["career_max"]:
                return "career_start_too_recent"
    if cfg["tattoo_mode"] == "require":
        if cfg["tattoo_pref"] == "yes" and not p.get("tattoos"):
            return "tattoos"
        if cfg["tattoo_pref"] == "no" and p.get("tattoos"):
            return "tattoos"
    if cfg["piercing_mode"] == "require":
        if cfg["piercing_pref"] == "yes" and not p.get("piercings"):
            return "piercings"
        if cfg["piercing_pref"] == "no" and p.get("piercings"):
            return "piercings"
    for field, mode_key, filter_key, incl_key, name in (
        ("hair_color",  "hair_mode",      "hair_filter",      "hair_incl_null",      "hair_color"),
        ("breast_type", "breast_mode",    "breast_filter",    "breast_incl_null",    "breast_type"),
        ("ethnicity",   "ethnicity_mode", "ethnicity_filter", "ethnicity_incl_null", "ethnicity"),
    ):
        if cfg[mode_key] == "require" and cfg[filter_key]:
            val = (p.get(field) or "").upper()
            if not val:
                if not cfg[incl_key]:
                    return f"{name}_null"
            elif val not in cfg[filter_key]:
                return name
    if cfg["country_mode"] == "require" and cfg["country_filter"]:
        val = _normalise_country(p.get("country") or "")
        if not val:
            if not cfg["country_incl_null"]:
                return "country_null"
        elif val not in cfg["country_filter"]:
            return "country"
    if cfg["body_type_mode"] == "require" and cfg["body_type_filter"]:
        btypes = _spotlight_body_types(p)
        if not btypes:
            if not cfg["body_type_incl_null"]:
                return "body_type_null"
        elif not (btypes & {t.lower() for t in cfg["body_type_filter"]}):
            return "body_type"
    return None


def _spotlight_newness_stats(served: list[dict], buffer: list[dict]) -> dict:
    """Surface 'how fresh is this spotlight' metrics in the debug payload.

    Reports both for what was actually served (the 10 tiles) and for
    the full eligible buffer, so the user can see if the buffer is
    rich in newcomers but the sampler is still favouring veterans —
    or if the buffer itself is veteran-heavy."""
    def _stats(rows: list[dict]) -> dict:
        if not rows:
            return {"count": 0}
        scs    = [int(r.get("scene_count") or 0) for r in rows]
        scs_s  = sorted(scs)
        median_sc = scs_s[len(scs_s) // 2] if scs_s else 0
        avg_sc    = sum(scs) / len(scs)
        # % whose scene_count is small enough to count as "new" (≤10).
        new_pct   = 100.0 * sum(1 for x in scs if x <= 10) / len(scs)
        # Days since `created` for those that have one.
        ages = []
        now  = datetime.now(timezone.utc)
        for r in rows:
            cs = (r.get("created") or "").strip()
            if not cs: continue
            try:
                dt = datetime.fromisoformat(cs.replace("Z", "+00:00"))
                ages.append((now - dt).days)
            except Exception:
                pass
        return {
            "count":               len(rows),
            "avg_scene_count":     round(avg_sc, 1),
            "median_scene_count":  median_sc,
            "min_scene_count":     scs_s[0]  if scs_s else 0,
            "max_scene_count":     scs_s[-1] if scs_s else 0,
            "percent_new_le10":    round(new_pct, 1),
            "avg_created_age_days": round(sum(ages) / len(ages), 1) if ages else None,
            "library_fill_count":  sum(1 for r in rows if r.get("library_fill")),
        }
    return {"served": _stats(served), "buffer": _stats(buffer)}


def _spotlight_lib_image_url(row_id: int) -> str:
    """Pick the best on-disk image URL for a library performer.

    The /api/performers/poster-image endpoint 404s when no poster file
    exists on disk (most rows DON'T have one — posters only generate
    after `_ensure_performer_posters` runs for that row). Check what's
    actually present and return a URL that points to a real file:
        1. cached secondary poster (TPDB/StashDB/Babepedia)
        2. cached primary poster (local library poster.jpg)
        3. cached headshot via the existing performer-thumb endpoint,
           which falls back through every cached image variant.

    When neither poster exists, kick off a background thread to generate
    them so the next spotlight load has the secondary (network-fetched)
    or primary (local poster.jpg copy) cached on disk."""
    for kind, role in (("secondary", "poster_secondary"), ("primary", "poster_primary")):
        if _perf_poster_resolve(row_id, role) is not None:
            return f"/api/performers/poster-image?row_id={row_id}&kind={kind}"

    # Posters not cached — fire-and-forget background generation so the
    # NEXT spotlight load can serve them. Same row may get hit multiple
    # times in quick succession; the in-function `_spotlight_lib_pending`
    # set dedupes so we only spawn one thread per row at a time.
    if row_id not in _spotlight_lib_pending:
        _spotlight_lib_pending.add(row_id)
        def _gen_and_release(rid: int) -> None:
            try:
                _ensure_performer_posters(rid)
            except Exception as exc:
                _log.warning("spotlight lib poster gen row %s: %s", rid, exc)
            finally:
                _spotlight_lib_pending.discard(rid)
        threading.Thread(
            target=_gen_and_release, args=(row_id,),
            daemon=True, name=f"spotlight-lib-poster-{row_id}",
        ).start()

    # Fallback for THIS request: headshot via performer-thumb, which
    # already exists for every library row with image_url populated.
    return f"/api/favourites/performer-thumb?row_id={row_id}"


# Module-level dedupe set so multiple concurrent spotlight requests for
# the same library row don't each spawn their own _ensure_performer_posters
# thread. Cleared per-row when generation completes.
_spotlight_lib_pending: set[int] = set()


def _spotlight_library_only(mode: str, count: int) -> list[dict]:
    """Return up to `count` library performers shaped as spotlight entries.

    Used when the user picks `spotlight_mode = newly_added` or `random` —
    these modes bypass the StashDB/FansDB fetch entirely and source the
    spotlight row from favourite_entities (kind=performer). Entries
    carry source="Library" + library_fill=True so the frontend renders
    the database-icon badge to indicate the library origin."""
    try:
        all_rows = list(db.favourite_list())
    except Exception as e:
        _log.warning(f"spotlight library-only fetch failed: {e}")
        return []
    candidates = [
        r for r in all_rows
        if r.get("kind") == "performer"
        and (r.get("image_url") or "").strip()
        and (r.get("folder_name") or "").strip()
    ]
    if mode == "newly_added":
        candidates.sort(
            key=lambda r: (
                (r.get("added_at") or r.get("scanned_at") or ""),
                int(r.get("id") or 0),
            ),
            reverse=True,
        )
    else:  # random
        random.shuffle(candidates)
    out: list[dict] = []
    for r in candidates[:count]:
        rid = int(r.get("id") or 0)
        if not rid:
            continue
        out.append({
            "id":            f"lib:{rid}",
            "source":        "Library",
            "name":          (r.get("folder_name") or "").strip(),
            "image":         _spotlight_lib_image_url(rid),
            "scene_count":   0,
            "library_fill":  True,
            "added_at":      r.get("added_at") or "",
        })
    return out


def _spotlight_probe_filter_breakdown(s: dict) -> dict:
    """Fetch one page from each configured stash-box source and tally which
    hard filter rejected how many performers. Used by the spotlight debug
    endpoint to expose "country killed 38, breast_type killed 7" so the user
    can spot which filter is doing the most damage. Reuses the same cfg
    builder logic as `_fetch_spotlight_performers` to stay in sync."""
    sources: list[tuple[str, str, str]] = []
    sk = (s.get("api_key_stashdb") or "").strip()
    fk = (s.get("api_key_fansdb") or "").strip()
    jk = (s.get("api_key_javstash") or "").strip()
    if sk: sources.append(("StashDB", STASHDB_ENDPOINT, sk))
    if fk: sources.append(("FansDB", FANSDB_ENDPOINT, fk))
    if jk: sources.append(("JAVStash", JAVSTASH_ENDPOINT, jk))
    if not sources:
        return {"error": "no api keys"}

    # Mirror cfg construction from _fetch_spotlight_performers.
    def _csv_set(key: str) -> set[str]:
        return {v.strip().upper() for v in (s.get(key) or "").split(",") if v.strip()}
    def _incl_null(key: str) -> bool:
        return (s.get(key) or "false").lower() == "true"
    def _mode(key: str, default: str = "prefer") -> str:
        v = (s.get(key) or default).lower().strip()
        return v if v in ("ignore", "prefer", "require") else default

    _career_years = int(s.get("spotlight_career_years") or 0) or None
    _age_hard_min, _age_hard_max = _spotlight_age_hard_limits(s)
    cfg = dict(
        min_scenes=max(1, int(s.get("spotlight_min_scenes") or 5)),
        min_scenes_mode=_mode("spotlight_min_scenes_mode", "require"),
        recent_cutoff=(datetime.now(timezone.utc) - timedelta(days=int(s.get("spotlight_recent_days") or 0))) if (int(s.get("spotlight_recent_days") or 0)) else None,
        recent_incl_null=_incl_null("spotlight_recent_incl_null"),
        active_mode=_mode("spotlight_active_mode", "ignore"),
        genders_filter=_csv_set("spotlight_genders"),
        genders_incl_null=_incl_null("spotlight_genders_incl_null"),
        gender_mode=_mode("spotlight_gender_mode", "require"),
        age_hard_min=_age_hard_min,
        age_hard_max=_age_hard_max,
        min_age=(int(s.get("spotlight_min_age") or 0) or None),
        max_age=(int(s.get("spotlight_max_age") or 0) or None),
        age_incl_null=_incl_null("spotlight_age_incl_null"),
        age_mode=_mode("spotlight_age_mode", "require"),
        career_min=((_date.today().year - _career_years) if _career_years else None),
        career_max=None,
        career_incl_null=(s.get("spotlight_career_start_incl_null") or "true").lower() == "true",
        tattoo_pref=s.get("spotlight_tattoos") or "any",
        tattoo_mode=_mode("spotlight_tattoo_mode", "ignore"),
        piercing_pref=s.get("spotlight_piercings") or "any",
        piercing_mode=_mode("spotlight_piercing_mode", "ignore"),
        hair_filter=_csv_set("spotlight_hair_colors"),
        hair_mode=_mode("spotlight_hair_mode", "prefer"),
        hair_incl_null=_incl_null("spotlight_hair_colors_incl_null"),
        breast_filter=_csv_set("spotlight_breast_types"),
        breast_mode=_mode("spotlight_breast_mode", "prefer"),
        breast_incl_null=_incl_null("spotlight_breast_types_incl_null"),
        ethnicity_filter=_csv_set("spotlight_ethnicities"),
        ethnicity_mode=_mode("spotlight_ethnicity_mode", "ignore"),
        ethnicity_incl_null=_incl_null("spotlight_ethnicities_incl_null"),
        country_filter={_normalise_country(v) for v in (s.get("spotlight_countries") or "").split(",") if v.strip()},
        country_mode=_mode("spotlight_country_mode", "prefer"),
        country_incl_null=_incl_null("spotlight_countries_incl_null"),
        body_type_filter=_csv_set("spotlight_body_types"),
        body_type_mode=_mode("spotlight_body_type_mode", "prefer"),
        body_type_incl_null=_incl_null("spotlight_body_types_incl_null"),
        source_filter=_csv_set("spotlight_sources"),
        source_mode=_mode("spotlight_source_mode", "ignore"),
    )

    raw_sort = (s.get("spotlight_sort") or "DATE").strip().upper()
    sort_field = raw_sort if raw_sort in ("DATE", "UPDATED_AT", "CREATED_AT", "TRENDING") else "DATE"
    api_input = {
        "per_page": _SPOTLIGHT_PER_PAGE,
        "sort":     sort_field,
        "direction": (s.get("spotlight_direction") or "DESC").strip().upper(),
        "page": 1,
    }
    tags_filter = [v.strip() for v in (s.get("spotlight_tags") or "").split(",") if v.strip()]

    studio_blacklist = _spotlight_studio_blacklist(s)
    results: dict = {}
    for src_label, endpoint, key in sources:
        rejects: dict[str, int] = {}
        passed = 0
        no_image = 0
        scenes_skipped_studio = 0
        # Tags are StashDB-only (UUID space differs across sources).
        src_input = dict(api_input)
        if tags_filter and src_label == "StashDB":
            src_input["tags"] = {"value": tags_filter, "modifier": "INCLUDES"}
        try:
            data = _stashbox_post(endpoint, key, SPOTLIGHT_SCENES_QUERY, {"input": src_input})
            page_scenes = (data.get("queryScenes") or {}).get("scenes") or []
            total_count = (data.get("queryScenes") or {}).get("count") or 0
        except Exception as e:
            results[src_label] = {"error": f"{type(e).__name__}: {e}"}
            continue
        seen_pid: set[str] = set()
        page_performers: list[dict] = []
        for sc in page_scenes:
            if _spotlight_scene_studio_blacklisted(sc, studio_blacklist):
                scenes_skipped_studio += 1
                continue
            for pa in (sc.get("performers") or []):
                p = (pa or {}).get("performer") or {}
                pid = p.get("id") or ""
                if not pid or pid in seen_pid:
                    continue
                seen_pid.add(pid)
                page_performers.append(p)
        for p in page_performers:
            if not (p.get("images") or []):
                no_image += 1
                continue
            age = p.get("age") or _spotlight_age(p.get("birth_date") or "")
            reason = _spotlight_first_failing_filter(p, cfg, age)
            if reason is None:
                passed += 1
            else:
                rejects[reason] = rejects.get(reason, 0) + 1
        results[src_label] = {
            "total_count":           total_count,
            "scenes_on_page":        len(page_scenes),
            "scenes_skipped_studio": scenes_skipped_studio,
            "unique_performers":     len(page_performers),
            "passed_hard_filters":   passed,
            "rejected_no_image":     no_image,
            "rejected_by_filter":    rejects,
        }
    return results


def _spotlight_passes_hard_filters(p: dict, cfg: dict, age: int | None) -> bool:
    """Return True only if the performer passes all hard eligibility criteria.

    Only traits whose mode == 'require' (or whose mode has no preference system,
    i.e. career start) are applied as hard exclusions here.
    """
    # Deceased — always reject. StashDB returns `age` as age-at-death for
    # deceased performers, which silently bypasses age-range filters (e.g.
    # someone born 1963 who died at 20 reports age=20 and slips past a
    # max_age=35 cutoff despite their 1963 birthdate). The spotlight is
    # for currently-active performers, so death_date being set is a hard
    # exclusion regardless of any other config.
    if (p.get("death_date") or "").strip():
        return False

    # Minimum scenes — only hard filter when mode is require
    if cfg["min_scenes_mode"] == "require":
        if (p.get("scene_count") or 0) < cfg["min_scenes"]:
            return False

    # Recent activity — only hard filter when mode is require
    if cfg["active_mode"] == "require" and cfg["recent_cutoff"]:
        updated_str = p.get("updated") or ""
        if not updated_str:
            if not cfg["recent_incl_null"]:
                return False
        else:
            try:
                updated_dt = datetime.fromisoformat(updated_str.replace("Z", "+00:00"))
                if updated_dt < cfg["recent_cutoff"]:
                    return False
            except Exception:
                if not cfg["recent_incl_null"]:
                    return False

    # Gender — only hard filter when mode is require (and multi-select; single pushed to API)
    if cfg["gender_mode"] == "require" and cfg["genders_filter"] and len(cfg["genders_filter"]) > 1:
        val = (p.get("gender") or "").upper()
        if not val:
            if not cfg["genders_incl_null"]:
                return False
        elif val not in cfg["genders_filter"]:
            return False

    # Age hard limits — always enforced when set (independent of prefer/require)
    if _spotlight_fails_age_hard_limits(age, cfg):
        return False

    # Preferred age range — only hard filter when mode is require
    if cfg["age_mode"] == "require" and (cfg["min_age"] is not None or cfg["max_age"] is not None):
        if age is None:
            if not cfg["age_incl_null"]:
                return False
        else:
            if cfg["min_age"] is not None and age < cfg["min_age"]:
                return False
            if cfg["max_age"] is not None and age > cfg["max_age"]:
                return False

    # Career start year — always a hard filter; infer from age when not set
    if cfg["career_min"] is not None or cfg["career_max"] is not None:
        csy = _spotlight_infer_career_start(p, age)
        if csy is None:
            if not cfg["career_incl_null"]:
                return False
        else:
            if cfg["career_min"] is not None and csy < cfg["career_min"]:
                return False
            if cfg["career_max"] is not None and csy > cfg["career_max"]:
                return False

    # Tattoos — only hard filter when mode is require
    if cfg["tattoo_mode"] == "require":
        if cfg["tattoo_pref"] == "yes" and not p.get("tattoos"):
            return False
        if cfg["tattoo_pref"] == "no" and p.get("tattoos"):
            return False

    # Piercings — only hard filter when mode is require
    if cfg["piercing_mode"] == "require":
        if cfg["piercing_pref"] == "yes" and not p.get("piercings"):
            return False
        if cfg["piercing_pref"] == "no" and p.get("piercings"):
            return False

    # Soft traits in require mode (hair, breast, ethnicity, country, body type)
    for field, mode_key, filter_key, incl_key in (
        ("hair_color",  "hair_mode",      "hair_filter",      "hair_incl_null"),
        ("breast_type", "breast_mode",    "breast_filter",    "breast_incl_null"),
        ("ethnicity",   "ethnicity_mode", "ethnicity_filter", "ethnicity_incl_null"),
    ):
        if cfg[mode_key] == "require" and cfg[filter_key]:
            val = (p.get(field) or "").upper()
            if not val:
                if not cfg[incl_key]:
                    return False
            elif val not in cfg[filter_key]:
                return False

    if cfg["country_mode"] == "require" and cfg["country_filter"]:
        val = _normalise_country(p.get("country") or "")
        if not val:
            if not cfg["country_incl_null"]:
                return False
        elif val not in cfg["country_filter"]:
            return False

    if cfg["body_type_mode"] == "require" and cfg["body_type_filter"]:
        btypes = _spotlight_body_types(p)
        if not btypes:
            if not cfg["body_type_incl_null"]:
                return False
        elif not (btypes & {t.lower() for t in cfg["body_type_filter"]}):
            return False

    return True


# ── Spotlight scoring v3 — normalised four-category blend ───────────
#
# Replaces the original additive `prefer-mode weights + emerging/established/
# recency shape adjustments` model with four independently-normalised
# categories blended at fixed (configurable) ratios:
#
#   FinalScore(p) =
#       DemographicMatch(p)  × 0.50  ← preference proximity, primary signal
#     + ConfidenceScore(p)   × 0.25  ← established / well-documented (log-norm)
#     + DiscoveryScore(p)    × 0.15  ← inverse of catalogue size, surfaces newer
#     + ActivityScore(p)     × 0.10  ← recency of last update
#
# Each category returns a value in [0,1]. The blend is also in [0,1].
# Gamma compression (W = S**gamma × R) is applied at sampling time, not here.
#
# Why this shape: the additive model accumulated permanent score advantages
# for veterans (50-scene profile sat ~20 points above any preference signal
# could reach), let scene_count act as an uncontrolled popularity multiplier,
# and forced demographic preferences to be binary cliffs. Normalising every
# signal to [0,1] before blending caps the damage any one metric can do, and
# proximity decay on age stops cliff-edge cutoffs.
#
# Backward compatibility: `_spotlight_score_performer` (further down) still
# returns the legacy {total: int, breakdown: list[{reason, points}]} shape
# so the existing debug endpoint and dedup tiebreakers keep working — the
# legacy total is the v3 [0,1] float scaled to [0,100].

def _spotlight_demographic_match(p: dict, cfg: dict, age: int | None) -> tuple[float, list[dict]]:
    """Weighted mean of enabled prefer-mode demographic preferences.
    Each preference contributes a [0,1] score weighted by its `_weight`.
    Returns (score, breakdown) where breakdown is a list of
    {trait, value, weight, score} dicts for ?debug=1 surfacing.

    Age uses a Gaussian falloff around the midpoint of the preferred
    window so just-outside-range performers aren't unfairly cut off.
    Categorical traits remain binary (1.0 matched / 0.0 not).
    `min_scenes_mode` and `active_mode` are intentionally excluded —
    they overlap with ConfidenceScore / ActivityScore respectively
    and would double-count if mixed in here.
    """
    parts: list[tuple[float, float, dict]] = []  # (score, weight, breakdown_entry)

    def _add(trait: str, score: float, weight: float, value: object = None) -> None:
        s = max(0.0, min(1.0, float(score)))
        if weight <= 0:
            return
        parts.append((s, float(weight), {
            "trait": trait,
            "value": value,
            "weight": float(weight),
            "score": round(s, 3),
        }))

    # Age — Gaussian falloff around midpoint of preferred window.
    if cfg.get("age_mode") == "prefer" and age is not None and (
        cfg.get("min_age") is not None or cfg.get("max_age") is not None
    ):
        lo = cfg.get("min_age") or 18
        hi = cfg.get("max_age") or 99
        target = (lo + hi) / 2.0
        sigma = max(3.0, (hi - lo) / 2.0)  # half-window as soft sigma
        d = age - target
        s = math.exp(-(d * d) / (2.0 * sigma * sigma))
        _add("age", s, cfg.get("age_weight") or 3, age)

    # Gender (categorical)
    if cfg.get("gender_mode") == "prefer" and cfg.get("genders_filter"):
        val = (p.get("gender") or "").upper()
        s = 1.0 if (val and val in cfg["genders_filter"]) else 0.0
        _add("gender", s, cfg.get("gender_weight") or 3, val)

    # Tattoos (binary preference yes/no)
    if cfg.get("tattoo_mode") == "prefer" and cfg.get("tattoo_pref") in ("yes", "no"):
        has = bool(p.get("tattoos"))
        matched = (cfg["tattoo_pref"] == "yes" and has) or (cfg["tattoo_pref"] == "no" and not has)
        _add("tattoos", 1.0 if matched else 0.0, cfg.get("tattoo_weight") or 2, has)

    # Piercings (binary preference yes/no)
    if cfg.get("piercing_mode") == "prefer" and cfg.get("piercing_pref") in ("yes", "no"):
        has = bool(p.get("piercings"))
        matched = (cfg["piercing_pref"] == "yes" and has) or (cfg["piercing_pref"] == "no" and not has)
        _add("piercings", 1.0 if matched else 0.0, cfg.get("piercing_weight") or 2, has)

    # Hair colour
    if cfg.get("hair_mode") == "prefer" and cfg.get("hair_filter"):
        val = (p.get("hair_color") or "").upper()
        s = 1.0 if (val and val in cfg["hair_filter"]) else 0.0
        _add("hair", s, cfg.get("hair_weight") or 3, val)

    # Breast type
    if cfg.get("breast_mode") == "prefer" and cfg.get("breast_filter"):
        val = (p.get("breast_type") or "").upper()
        s = 1.0 if (val and val in cfg["breast_filter"]) else 0.0
        _add("breast", s, cfg.get("breast_weight") or 3, val)

    # Ethnicity
    if cfg.get("ethnicity_mode") == "prefer" and cfg.get("ethnicity_filter"):
        val = (p.get("ethnicity") or "").upper()
        s = 1.0 if (val and val in cfg["ethnicity_filter"]) else 0.0
        _add("ethnicity", s, cfg.get("ethnicity_weight") or 3, val)

    # Country
    if cfg.get("country_mode") == "prefer" and cfg.get("country_filter"):
        val = _normalise_country(p.get("country") or "")
        s = 1.0 if (val and val in cfg["country_filter"]) else 0.0
        _add("country", s, cfg.get("country_weight") or 3, val)

    # Body type (intersection)
    if cfg.get("body_type_mode") == "prefer" and cfg.get("body_type_filter"):
        btypes = _spotlight_body_types(p)
        wanted = {t.lower() for t in cfg["body_type_filter"]}
        s = 1.0 if (btypes and (btypes & wanted)) else 0.0
        _add("body_type", s, cfg.get("body_type_weight") or 4, sorted(btypes))

    # Source (preferred stash-box)
    if cfg.get("source_mode") == "prefer" and cfg.get("source_filter"):
        src = (p.get("source") or "").upper()
        s = 1.0 if (src and src in cfg["source_filter"]) else 0.0
        _add("source", s, cfg.get("source_weight") or 3, src)

    if not parts:
        # Neutral score when the user has set no preferences — every
        # candidate is equally "demographically aligned" (i.e. nothing
        # to align against). 0.5 keeps DemographicMatch from steamrolling
        # the other categories with zero in this case.
        return 0.5, []
    total_w = sum(w for _, w, _ in parts)
    if total_w <= 0:
        return 0.5, [e for _, _, e in parts]
    score = sum(s * w for s, w, _ in parts) / total_w
    return max(0.0, min(1.0, score)), [e for _, _, e in parts]


def _spotlight_confidence_score(p: dict, cfg: dict) -> tuple[float, dict]:
    """Confidence that the performer is established and well-documented.
    Blends three log-normalised signals so diminishing returns prevent
    catalogue veterans from running away with the score:

      scene_score = log(scene_count + 1) / log(scene_cap + 1)
      image_score = log(image_count + 1) / log(image_cap + 1)
      db_score    = source_count / 3        (1, 2, or 3 stash-boxes)

    Sub-blend defaults: scene 0.50, image 0.25, db 0.25 (configurable).
    Returns (score, {scene, image, db_presence}) for breakdown surfacing.
    """
    scene_cap = max(1, int(cfg.get("scene_cap") or 200))
    image_cap = max(1, int(cfg.get("image_cap") or 30))
    sc = max(0, int(p.get("scene_count") or 0))
    ic = len(p.get("images") or [])
    src = max(1, min(3, int(p.get("source_count") or 1)))

    scene_pts = math.log(sc + 1) / math.log(scene_cap + 1)
    image_pts = math.log(ic + 1) / math.log(image_cap + 1)
    db_pts    = src / 3.0
    scene_pts = max(0.0, min(1.0, scene_pts))
    image_pts = max(0.0, min(1.0, image_pts))

    w_scene = float(cfg.get("confidence_scene_w") or 0.50)
    w_image = float(cfg.get("confidence_image_w") or 0.25)
    w_db    = float(cfg.get("confidence_db_w") or 0.25)
    w_total = max(0.0001, w_scene + w_image + w_db)
    # Renormalise sub-blend in case caller supplied non-1.0-summing weights.
    w_scene, w_image, w_db = w_scene / w_total, w_image / w_total, w_db / w_total
    score = scene_pts * w_scene + image_pts * w_image + db_pts * w_db
    return max(0.0, min(1.0, score)), {
        "scene":       round(scene_pts, 3),
        "image":       round(image_pts, 3),
        "db_presence": round(db_pts, 3),
    }


def _spotlight_discovery_score(p: dict, cfg: dict) -> float:
    """Inverse of normalised scene count — small catalogues score higher.
    Designed to be a *light* nudge in the unified weighted sample, not the
    sole diversity mechanism (the previous hard discovery slice carried
    that load and over-corrected)."""
    scene_cap = max(1, int(cfg.get("scene_cap") or 200))
    sc = max(0, int(p.get("scene_count") or 0))
    norm = math.log(sc + 1) / math.log(scene_cap + 1)
    return max(0.0, 1.0 - min(1.0, norm))


def _spotlight_activity_score(p: dict, cfg: dict) -> float:
    """Linear decay over `activity_window_days` (default 90).
    Prefers `_latest_scene_at` (v2 cache signal — actual scene release date)
    when available, falls back to `updated` (StashDB record-modified date).
    Returns 1.0 today, 0.0 at window+ days, linear in between."""
    window = max(1, int(cfg.get("activity_window_days") or 90))
    days_old: float | None = None
    latest_ts = p.get("_latest_scene_at") or 0
    if latest_ts:
        days_old = max(0.0, (time.time() - float(latest_ts)) / 86400.0)
    else:
        updated_str = (p.get("updated") or "").strip()
        if updated_str:
            try:
                upd = datetime.fromisoformat(updated_str.replace("Z", "+00:00"))
                days_old = max(0, (datetime.now(timezone.utc) - upd).days)
            except Exception:
                pass
    if days_old is None:
        # No timestamp at all — assume neutral so missing-data performers
        # aren't punished into invisibility.
        return 0.5
    return max(0.0, 1.0 - days_old / window)


def _spotlight_v3_score(p: dict, cfg: dict, age: int | None) -> dict:
    """Compute the four-category blend for one performer.
    Returns {"total": float in [0,1], "categories": {...}, "demographic_breakdown": [...]}
    so callers can both rank by `total` and surface per-category sub-scores.
    """
    d, demo_bd = _spotlight_demographic_match(p, cfg, age)
    c, conf_bd = _spotlight_confidence_score(p, cfg)
    n          = _spotlight_discovery_score(p, cfg)
    a          = _spotlight_activity_score(p, cfg)

    bd = float(cfg.get("blend_demographic") or 0.50)
    bc = float(cfg.get("blend_confidence")  or 0.25)
    bn = float(cfg.get("blend_discovery")   or 0.15)
    ba = float(cfg.get("blend_activity")    or 0.10)
    btot = max(0.0001, bd + bc + bn + ba)
    # Renormalise the top-level blend so user-supplied weights that don't
    # sum to 1.0 still produce a [0,1] final score.
    bd, bc, bn, ba = bd / btot, bc / btot, bn / btot, ba / btot

    total = d * bd + c * bc + n * bn + a * ba
    return {
        "total": max(0.0, min(1.0, total)),
        "categories": {
            "demographic": round(d, 3),
            "confidence":  round(c, 3),
            "discovery":   round(n, 3),
            "activity":    round(a, 3),
        },
        "blend_weights": {
            "demographic": round(bd, 3),
            "confidence":  round(bc, 3),
            "discovery":   round(bn, 3),
            "activity":    round(ba, 3),
        },
        "demographic_breakdown": demo_bd,
        "confidence_breakdown":  conf_bd,
    }


def _spotlight_score_performer(p: dict, cfg: dict, age: int | None) -> dict:
    """Backward-compatible wrapper around the v3 four-category blend.
    Returns {total: int 0-100, breakdown: list[{reason, points}]} so existing
    callers (sort, dedup tiebreakers, ?debug=1 surfacing) keep working.

    The legacy additive model that used to live here (per-trait weight sums
    + emerging/established/recency shape adjustments) is gone — see the v3
    helpers above. The breakdown rows now describe the four categories and
    their contribution to the final 0-100 number, rather than per-trait
    points.
    """
    res = _spotlight_v3_score(p, cfg, age)
    cats   = res["categories"]
    bw     = res["blend_weights"]
    breakdown: list[dict] = []
    for key in ("demographic", "confidence", "discovery", "activity"):
        sub = cats[key]
        wt  = bw[key]
        contribution = int(round(sub * wt * 100))
        if contribution:
            breakdown.append({
                "reason": f"{key.capitalize()} {sub:.2f} × {wt:.2f}",
                "points": contribution,
            })
    return {
        "total": int(round(res["total"] * 100)),
        "breakdown": breakdown,
        "v3": res,  # full normalised payload for v2-aware callers
    }


def _spotlight_score_performer_legacy_unused(p: dict, cfg: dict, age: int | None) -> dict:
    """Original additive scorer — preserved for reference; not called.
    See `_spotlight_score_performer` above for the new implementation."""
    breakdown: list[dict] = []
    total = 0

    def _add(points: int, reason: str) -> None:
        nonlocal total
        if points:
            breakdown.append({"reason": reason, "points": points})
            total += points

    # Minimum scenes (prefer)
    if cfg["min_scenes_mode"] == "prefer":
        if (p.get("scene_count") or 0) >= cfg["min_scenes"]:
            _add(cfg["min_scenes_weight"], "Scene count met")

    # Gender (prefer)
    if cfg["gender_mode"] == "prefer" and cfg["genders_filter"]:
        val = (p.get("gender") or "").upper()
        if val and val in cfg["genders_filter"]:
            _add(cfg["gender_weight"], "Gender match")

    # Age range (prefer)
    if cfg["age_mode"] == "prefer" and (cfg["min_age"] is not None or cfg["max_age"] is not None):
        if age is not None:
            in_range = (
                (cfg["min_age"] is None or age >= cfg["min_age"]) and
                (cfg["max_age"] is None or age <= cfg["max_age"])
            )
            if in_range:
                _add(cfg["age_weight"], "Age range match")

    # Recently active (prefer)
    if cfg["active_mode"] == "prefer" and cfg["recent_cutoff"]:
        updated_str = p.get("updated") or ""
        if updated_str:
            try:
                updated_dt = datetime.fromisoformat(updated_str.replace("Z", "+00:00"))
                if updated_dt >= cfg["recent_cutoff"]:
                    _add(cfg["active_weight"], "Recently active")
            except Exception:
                pass

    # Tattoos (prefer)
    if cfg["tattoo_mode"] == "prefer" and cfg["tattoo_pref"] != "any":
        has_tattoos = bool(p.get("tattoos"))
        if cfg["tattoo_pref"] == "yes" and has_tattoos:
            _add(cfg["tattoo_weight"], "Has tattoos")
        elif cfg["tattoo_pref"] == "no" and not has_tattoos:
            _add(cfg["tattoo_weight"], "No tattoos")

    # Piercings (prefer)
    if cfg["piercing_mode"] == "prefer" and cfg["piercing_pref"] != "any":
        has_piercings = bool(p.get("piercings"))
        if cfg["piercing_pref"] == "yes" and has_piercings:
            _add(cfg["piercing_weight"], "Has piercings")
        elif cfg["piercing_pref"] == "no" and not has_piercings:
            _add(cfg["piercing_weight"], "No piercings")

    # Hair colour (prefer)
    if cfg["hair_mode"] == "prefer" and cfg["hair_filter"]:
        val = (p.get("hair_color") or "").upper()
        if val and val in cfg["hair_filter"]:
            _add(cfg["hair_weight"], "Hair colour match")

    # Breast type (prefer)
    if cfg["breast_mode"] == "prefer" and cfg["breast_filter"]:
        val = (p.get("breast_type") or "").upper()
        if val and val in cfg["breast_filter"]:
            _add(cfg["breast_weight"], "Breast type match")

    # Ethnicity (prefer)
    if cfg["ethnicity_mode"] == "prefer" and cfg["ethnicity_filter"]:
        val = (p.get("ethnicity") or "").upper()
        if val and val in cfg["ethnicity_filter"]:
            _add(cfg["ethnicity_weight"], "Ethnicity match")

    # Country (prefer)
    if cfg["country_mode"] == "prefer" and cfg["country_filter"]:
        val = _normalise_country(p.get("country") or "")
        if val and val in cfg["country_filter"]:
            _add(cfg["country_weight"], "Country match")

    # Body type (prefer)
    if cfg["body_type_mode"] == "prefer" and cfg["body_type_filter"]:
        btypes = _spotlight_body_types(p)
        if btypes and (btypes & {t.lower() for t in cfg["body_type_filter"]}):
            _add(cfg["body_type_weight"], "Body type match")

    # Source (prefer) — boost performers from selected stash-box(es).
    if cfg.get("source_mode") == "prefer" and cfg.get("source_filter"):
        src = (p.get("source") or "").upper()
        if src and src in cfg["source_filter"]:
            _add(cfg.get("source_weight") or 3, "Source match")

    # ── Establishment vs. emerging balance ──────────────────────────
    # Earlier curve was `max(0, 30 - sc)` which gave a 0-scene profile
    # +30 points — enough to dominate every preference signal and sink
    # genuinely working performers under one-time wannabees. Flattened
    # to a small +10 max for genuinely new (sc < 10) AND added an
    # opposing "established" boost so a real catalog of work actually
    # earns score. Net effect: a 5-scene profile gets +5, a 25-scene
    # profile gets +20, a brand-new 0-scene profile still gets a token
    # +10 so newcomers aren't invisible.
    sc = int(p.get("scene_count") or 0)
    emerging_pts = max(0, 10 - sc)
    if emerging_pts:
        _add(emerging_pts, f"Emerging ({sc} scenes)")
    established_pts = min(20, max(0, sc - 5))
    if established_pts:
        _add(established_pts, f"Established ({sc} scenes)")
    updated_str = (p.get("updated") or "").strip()
    if updated_str:
        try:
            updated_dt = datetime.fromisoformat(updated_str.replace("Z", "+00:00"))
            days_since = max(0, (datetime.now(timezone.utc) - updated_dt).days)
            recency_pts = max(0, 15 - (days_since // 6))
            if recency_pts:
                _add(recency_pts, f"Active ({days_since}d ago)")
        except Exception:
            pass

    return {"total": total, "breakdown": breakdown}


_SPOTLIGHT_PER_PAGE = 50
# Buffer target raised from 100 → 300 so the discovery half of the
# 50/50 split (lowest-scene-count) has a real long tail to draw from.
# At 100 the "low scene count" pool was just the same 30-40 prolific
# performers ordered slightly differently each call.
_SPOTLIGHT_CACHE_TARGET = 300
_SPOTLIGHT_BUFFER_TARGET = 300
# Safety cap on pages per source. Scene pages are dense (~100-200 unique
# performers each after dedup), so the cache target is hit in 5-10 pages
# typically. The safety cap exists only to bound runaway loops.
_SPOTLIGHT_MAX_PAGES = 200
_SPOTLIGHT_FETCH_BUDGET_S = 18.0  # legacy total — kept for back-compat
# Per-source fetch budget. Halved from 45s → 22s now that we walk scenes
# instead of performers — each scene page yields ~2-4× more unique
# performers than a performer page did, so we hit the cache target
# faster. Total cold-fetch wait with 2 sources is ~44s.
_SPOTLIGHT_PER_SOURCE_BUDGET_S = 22.0
# How long a served performer stays dampened in the weighted-sample pool.
# After this window elapses their weight recovers fully; inside it, weights
# ramp linearly from 0.1× (just shown) back to 1.0× at the window edge.
_SPOTLIGHT_RECENT_WINDOW_S = 15 * 60


def _spotlight_fetch_from_stashbox(
    source_label: str,
    endpoint: str,
    api_key: str,
    api_input_base: dict,
    cfg: dict,
    excluded_ids: set[str],
    excl_library: bool,
    s: dict,
    visible_target: int,
    budget_s: float,
    diag: dict | None = None,
) -> list[dict]:
    """Fetch scored spotlight candidates from one stash-box instance.

    Walks recent scenes (queryScenes, sort=DATE/UPDATED_AT/CREATED_AT) and
    harvests unique performers from each scene. Scenes are denser per page
    than performers and naturally surface currently-active talent — every
    performer on a recent scene has at least one recent appearance, which
    is the quality the spotlight wants to bias for.

    StashDB and FansDB share the same GraphQL schema so the same query /
    scoring / filtering pipeline runs against either endpoint unchanged.
    Each call gets its own budget slice and page counter; the caller
    merges the per-source results.
    """
    candidates: list[dict] = []
    seen_ids: set[str] = set()
    # Scene-driven walk: page 1 is always the most-recent slice (DATE,
    # UPDATED_AT, CREATED_AT all sort dense at the front). No null-bucket
    # gymnastics needed — every recent scene has performers, and recent
    # scenes naturally surface working talent.
    page_num = 1
    pages_checked = 0
    total_pages_hint: int | None = None
    fetch_started = time.time()
    api_input = dict(api_input_base)
    studio_blacklist = _spotlight_studio_blacklist(s)
    lib_lookup = _spotlight_library_lookup(s) if excl_library else None
    if diag is not None:
        diag.setdefault("pages_walked", 0)
        diag.setdefault("total_count", 0)
        diag.setdefault("scenes_seen", 0)
        diag.setdefault("performers_seen", 0)
        diag.setdefault("rejected_no_image", 0)
        diag.setdefault("rejected_studio_blacklist", 0)
        diag.setdefault("rejected_excluded", 0)
        diag.setdefault("rejected_in_library", 0)
        diag.setdefault("rejected_by_filter", {})
        diag.setdefault("passed", 0)
        diag.setdefault("api_errors", [])
        diag.setdefault("first_page", page_num)
        diag.setdefault("api_input", dict(api_input))

    while pages_checked < _SPOTLIGHT_MAX_PAGES and len(candidates) < _SPOTLIGHT_CACHE_TARGET:
        if (time.time() - fetch_started) >= budget_s:
            if diag is not None:
                diag["budget_exhausted"] = True
            break
        pages_checked += 1
        api_input["page"] = page_num
        try:
            data = _stashbox_post(
                endpoint, api_key,
                SPOTLIGHT_SCENES_QUERY, {"input": api_input},
            )
            page_scenes = (data.get("queryScenes") or {}).get("scenes") or []
            total_count = (data.get("queryScenes") or {}).get("count") or 0
        except Exception as e:
            _log.warning(f"Spotlight scenes fetch failed ({source_label} page {page_num}): {e}")
            if diag is not None:
                diag["api_errors"].append(f"page {page_num}: {type(e).__name__}: {e}")
            break

        if total_pages_hint is None and total_count:
            try:
                total_pages_hint = max(
                    1, math.ceil(float(total_count) / float(_SPOTLIGHT_PER_PAGE))
                )
            except Exception:
                total_pages_hint = None

        # Flatten performers off each scene into a unique-id stream.
        # Scenes whose studio name matches a blacklist phrase are skipped
        # wholesale — every performer on that scene is excluded from the
        # spotlight. Substring match on the studio name, case-insensitive.
        page_performers: list[dict] = []
        for sc in page_scenes:
            if _spotlight_scene_studio_blacklisted(sc, studio_blacklist):
                if diag is not None:
                    diag["rejected_studio_blacklist"] += 1
                continue
            for pa in (sc.get("performers") or []):
                p = (pa or {}).get("performer") or {}
                pid = p.get("id") or ""
                if not pid or pid in seen_ids:
                    continue
                # Mark seen here so the same performer appearing on a later
                # scene in this same page doesn't get re-evaluated.
                seen_ids.add(pid)
                page_performers.append(p)

        _log.info(
            "Spotlight lazy page %s [%s]: scenes=%s unique_performers=%s total_scenes=%s matched_so_far=%s",
            page_num,
            source_label,
            len(page_scenes),
            len(page_performers),
            total_count,
            len(candidates),
        )

        if diag is not None:
            diag["pages_walked"] += 1
            diag["total_count"] = total_count
            diag["scenes_seen"] += len(page_scenes)

        # The earlier per-page cap on prolific performers (scene_count
        # > 100) was actively hiding the working performers we want to
        # surface — explicitly removed. The scoring pipeline still has
        # `spotlight_discovery_ratio` and the split-sample if the user
        # wants to dial newcomers back in.

        for p in page_performers:
            if diag is not None:
                diag["performers_seen"] += 1
            pid = p.get("id") or ""

            if pid in excluded_ids:
                if diag is not None:
                    diag["rejected_excluded"] += 1
                continue

            images = p.get("images") or []
            if not images:
                if diag is not None:
                    diag["rejected_no_image"] += 1
                continue

            bd_str = p.get("birth_date") or ""
            age    = p.get("age") or _spotlight_age(bd_str)

            if diag is not None:
                reason = _spotlight_first_failing_filter(p, cfg, age)
                if reason is not None:
                    diag["rejected_by_filter"][reason] = diag["rejected_by_filter"].get(reason, 0) + 1
                    continue
            else:
                if not _spotlight_passes_hard_filters(p, cfg, age):
                    continue

            if excl_library and _spotlight_performer_in_library(p, s, lib_lookup):
                if diag is not None:
                    diag["rejected_in_library"] += 1
                continue
            if diag is not None:
                diag["passed"] += 1

            p["source"] = source_label
            scored         = _spotlight_score_performer(p, cfg, age)
            # Random pick — first poster is frequently the worst shot.
            # Mirrors the same behaviour in the v2 cache scorer.
            img_raw        = images[random.randrange(len(images))] if len(images) > 1 else images[0]
            image_url      = img_raw.get("url") if isinstance(img_raw, dict) else img_raw
            inferred_csy   = _spotlight_infer_career_start(p, age)

            candidates.append({
                "id":                      p.get("id") or "",
                "source":                  source_label,
                "name":                    p.get("name") or "",
                "gender":                  p.get("gender") or "",
                "image":                   image_url or "",
                "scene_count":             p.get("scene_count") or 0,
                "age":                     age,
                "birthdate":               bd_str,
                "death_date":              (p.get("death_date") or ""),
                "updated":                 p.get("updated") or "",
                "created":                 p.get("created") or "",
                "career_start_year":       p.get("career_start_year"),
                "career_start_inferred":   inferred_csy if p.get("career_start_year") is None else None,
                "height":                  p.get("height"),
                "measurements":            _fmt_measurements(p),
                "cup_size":                (p.get("cup_size") or "").upper(),
                "band_size":               p.get("band_size"),
                "waist_size":              p.get("waist_size"),
                "hip_size":                p.get("hip_size"),
                "body_types":              sorted(_spotlight_body_types(p)),
                "breast_type":             p.get("breast_type") or "",
                "country":                 p.get("country") or "",
                "ethnicity":               p.get("ethnicity") or "",
                "eye_color":               p.get("eye_color") or "",
                "hair_color":              p.get("hair_color") or "",
                "tattoos":                 bool(p.get("tattoos")),
                "piercings":               bool(p.get("piercings")),
                "score":                   scored["total"],
                "score_breakdown":         scored["breakdown"],
            })

        # Page advance: scenes sort dense at the front for every supported
        # sort key (DATE, UPDATED_AT, CREATED_AT), so a sequential walk
        # never misses recent entries. Bail when there are no scenes left.
        if len(page_scenes) == 0:
            break
        page_num += 1
        if total_pages_hint is not None and page_num > total_pages_hint:
            break

        # Partial-return shortcut: once we have enough to display from this
        # source AND the source has used half its budget, stop and let the
        # caller move on to the next source.
        if len(candidates) >= visible_target and (time.time() - fetch_started) >= (budget_s * 0.5):
            break

    return candidates


def _fetch_spotlight_performers(_diag: dict | None = None) -> list[dict]:
    """Fetch performers from all configured stash-box instances for the spotlight row.

    Strategy:
    - Queries StashDB, FansDB, and JAVStash (whichever API keys are configured). All
      expose the same GraphQL schema so the same query / scoring pipeline runs
      against each.
    - Hard filters (gender, age, career start, min scenes, tattoos) are applied in Python.
      Career start is inferred from age (assumed start at 18) for performers missing the field.
    - Soft traits (hair, breast, ethnicity, country, body type) can each be set to:
        ignore  — not used
        prefer  — contributes to score, no exclusion
        require — applied as a hard filter (exclusion)
    - Candidates from both sources are merged and deduplicated by normalised
      name (the same performer has different IDs on StashDB vs FansDB); when a
      duplicate is found, the entry with the higher scene_count wins.
    - All candidates that pass hard filters are scored and sorted by score DESC.
    - Returns up to `count` top-scoring performers.
    """
    s = db.get_settings()
    stashdb_key = (s.get("api_key_stashdb") or "").strip()
    fansdb_key  = (s.get("api_key_fansdb") or "").strip()
    javstash_key = (s.get("api_key_javstash") or "").strip()
    sources: list[tuple[str, str, str]] = []
    if stashdb_key and _spotlight_source_enabled(s, "spotlight_use_stashdb"):
        sources.append(("StashDB", STASHDB_ENDPOINT, stashdb_key))
    if fansdb_key and _spotlight_source_enabled(s, "spotlight_use_fansdb"):
        sources.append(("FansDB",  FANSDB_ENDPOINT,  fansdb_key))
    if javstash_key and _spotlight_source_enabled(s, "spotlight_use_javstash"):
        sources.append(("JAVStash", JAVSTASH_ENDPOINT, javstash_key))
    if not sources:
        return []

    # Map legacy performer-sort settings onto the SceneSortEnum. Scenes
    # don't expose SCENE_COUNT or BIRTHDATE — both fall back to DATE
    # (release date) since recent scenes are the strongest signal of an
    # active performer. UPDATED_AT/CREATED_AT pass through.
    raw_sort = (s.get("spotlight_sort") or "DATE").strip().upper()
    if raw_sort in ("DATE", "UPDATED_AT", "CREATED_AT", "TRENDING"):
        sort_field = raw_sort
    else:
        sort_field = "DATE"
    direction  = (s.get("spotlight_direction") or "DESC").strip().upper()
    count      = max(10, min(100, int(s.get("spotlight_count") or 10)))

    def _csv_set(key: str) -> set[str]:
        return {v.strip().upper() for v in (s.get(key) or "").split(",") if v.strip()}

    def _incl_null(key: str) -> bool:
        return (s.get(key) or "false").lower() == "true"

    def _mode(key: str, default: str = "prefer") -> str:
        v = (s.get(key) or default).lower().strip()
        return v if v in ("ignore", "prefer", "require") else default

    def _weight(key: str, default: int = 3) -> int:
        try:
            return max(0, min(100, int(s.get(key) or default)))
        except (ValueError, TypeError):
            return default

    # Settings
    genders_filter   = _csv_set("spotlight_genders")
    min_age          = int(s.get("spotlight_min_age") or 0) or None
    max_age          = int(s.get("spotlight_max_age") or 0) or None
    age_hard_min, age_hard_max = _spotlight_age_hard_limits(s)
    _career_years    = int(s.get("spotlight_career_years") or 0) or None
    career_min       = (_date.today().year - _career_years) if _career_years else None
    career_max       = None
    min_scenes       = max(1, int(s.get("spotlight_min_scenes") or 5))
    recent_days      = int(s.get("spotlight_recent_days") or 0) or None
    excl_library     = (s.get("spotlight_excl_library") or "false").lower() == "true"
    lib_lookup       = _spotlight_library_lookup(s) if excl_library else None
    tattoo_pref      = s.get("spotlight_tattoos") or "any"
    piercing_pref    = s.get("spotlight_piercings") or "any"

    genders_incl_null   = _incl_null("spotlight_genders_incl_null")
    age_incl_null       = _incl_null("spotlight_age_incl_null")
    career_incl_null    = (s.get("spotlight_career_start_incl_null") or "true").lower() == "true"
    recent_incl_null    = _incl_null("spotlight_recent_incl_null")

    # Modes for previously hard-coded filters
    gender_mode         = _mode("spotlight_gender_mode",     "require")
    age_mode            = _mode("spotlight_age_mode",        "require")
    active_mode         = _mode("spotlight_active_mode",     "ignore")
    min_scenes_mode     = _mode("spotlight_min_scenes_mode", "require")
    tattoo_mode         = _mode("spotlight_tattoo_mode",     "ignore")
    piercing_mode       = _mode("spotlight_piercing_mode",   "ignore")

    gender_weight       = _weight("spotlight_gender_weight",     3)
    age_weight          = _weight("spotlight_age_weight",        3)
    active_weight       = _weight("spotlight_active_weight",     2)
    min_scenes_weight   = _weight("spotlight_min_scenes_weight", 2)
    tattoo_weight       = _weight("spotlight_tattoo_weight",     2)
    piercing_weight     = _weight("spotlight_piercing_weight",   2)

    # Soft-trait settings (mode + weight + selected values + incl_null)
    hair_filter         = _csv_set("spotlight_hair_colors")
    breast_filter       = _csv_set("spotlight_breast_types")
    ethnicity_filter    = _csv_set("spotlight_ethnicities")
    country_filter      = {_normalise_country(v) for v in (s.get("spotlight_countries") or "").split(",") if v.strip()}  # normalised lowercase
    body_type_filter    = _csv_set("spotlight_body_types")
    # Source filter (StashDB / FansDB). 'require' restricts the fetch to
    # the selected sources entirely; 'prefer' fetches from all configured
    # sources but adds a score bonus to performers from selected sources;
    # 'ignore' uses every configured source equally.
    source_filter       = _csv_set("spotlight_sources")  # uppercase {"STASHDB","FANSDB"}

    hair_mode           = _mode("spotlight_hair_mode",      "prefer")
    breast_mode         = _mode("spotlight_breast_mode",    "prefer")
    ethnicity_mode      = _mode("spotlight_ethnicity_mode", "ignore")
    country_mode        = _mode("spotlight_country_mode",   "prefer")
    body_type_mode      = _mode("spotlight_body_type_mode", "prefer")
    source_mode         = _mode("spotlight_source_mode",    "ignore")

    hair_weight         = _weight("spotlight_hair_weight",      3)
    breast_weight       = _weight("spotlight_breast_weight",    3)
    ethnicity_weight    = _weight("spotlight_ethnicity_weight", 3)
    country_weight      = _weight("spotlight_country_weight",   3)
    body_type_weight    = _weight("spotlight_body_type_weight", 4)
    source_weight       = _weight("spotlight_source_weight",    3)

    hair_incl_null      = _incl_null("spotlight_hair_colors_incl_null")
    breast_incl_null    = _incl_null("spotlight_breast_types_incl_null")
    ethnicity_incl_null = _incl_null("spotlight_ethnicities_incl_null")
    country_incl_null   = _incl_null("spotlight_countries_incl_null")
    body_type_incl_null = _incl_null("spotlight_body_types_incl_null")

    recent_cutoff = (
        datetime.now(timezone.utc) - timedelta(days=recent_days) if recent_days else None
    )

    cfg = dict(
        # formerly hard-coded filters — now mode-aware
        min_scenes=min_scenes, min_scenes_mode=min_scenes_mode, min_scenes_weight=min_scenes_weight,
        recent_cutoff=recent_cutoff, recent_incl_null=recent_incl_null, active_mode=active_mode, active_weight=active_weight,
        genders_filter=genders_filter, genders_incl_null=genders_incl_null, gender_mode=gender_mode, gender_weight=gender_weight,
        age_hard_min=age_hard_min, age_hard_max=age_hard_max,
        min_age=min_age, max_age=max_age, age_incl_null=age_incl_null, age_mode=age_mode, age_weight=age_weight,
        career_min=career_min, career_max=career_max, career_incl_null=career_incl_null,
        tattoo_pref=tattoo_pref, tattoo_mode=tattoo_mode, tattoo_weight=tattoo_weight,
        piercing_pref=piercing_pref, piercing_mode=piercing_mode, piercing_weight=piercing_weight,
        # soft traits
        hair_filter=hair_filter,       hair_mode=hair_mode,       hair_weight=hair_weight,       hair_incl_null=hair_incl_null,
        breast_filter=breast_filter,   breast_mode=breast_mode,   breast_weight=breast_weight,   breast_incl_null=breast_incl_null,
        ethnicity_filter=ethnicity_filter, ethnicity_mode=ethnicity_mode, ethnicity_weight=ethnicity_weight, ethnicity_incl_null=ethnicity_incl_null,
        country_filter=country_filter, country_mode=country_mode, country_weight=country_weight, country_incl_null=country_incl_null,
        body_type_filter=body_type_filter, body_type_mode=body_type_mode, body_type_weight=body_type_weight, body_type_incl_null=body_type_incl_null,
        source_filter=source_filter, source_mode=source_mode, source_weight=source_weight,
    )

    # ── Build SceneQueryInput ───────────────────────────────────────────────
    # Keep API filters intentionally light; all settings/filters are applied
    # in Python against the harvested performer stream. The one server-side
    # filter we DO use is `spotlight_tags` — it shrinks the scene pool to the
    # categories the user cares about (e.g. "anal" or "lesbian"), which is
    # cheap on stash-box and would be wasteful to do client-side.
    #
    # Tag IDs are stash-box-instance-specific (StashDB / FansDB / JAVStash
    # use independent UUIDs for the same conceptual tag). The settings-modal
    # helper text directs users to stashdb.org/tags so we apply the
    # filter ONLY to StashDB; other stash-box sources are queried unfiltered.
    api_input: dict = {
        "per_page": _SPOTLIGHT_PER_PAGE,
        "sort":     sort_field,
        "direction": direction,
        "page": 1,
    }
    tags_filter = [v.strip() for v in (s.get("spotlight_tags") or "").split(",") if v.strip()]

    # Source require-mode: restrict the source list itself so we don't
    # spend budget fetching from a source the user excluded.
    if source_mode == "require" and source_filter:
        sources = [
            (lbl, ep, key) for (lbl, ep, key) in sources
            if lbl.upper() in source_filter
        ]
        if not sources:
            _log.info("Spotlight: source require filter excluded every configured source")
            return []

    # ── Exclusion list — never show these performers ────────────────────
    excluded_ids = db.spotlight_get_excluded_ids()

    # ── Fetch from every configured stash-box source ─────────────────────
    # Every source contributes its own share — there is NO "skip when we
    # already have enough" shortcut, because that would turn multi-source
    # integration into a fallback (StashDB is dense enough to saturate the
    # cushion on its own, leaving FansDB dormant). Instead each source is
    # asked for an equal slice of the target and a proportional slice of
    # the budget, so the final merged pool always interleaves both.
    visible_target = max(10, count)
    # Each source aims for ~half the final cushion (rounded up + a small
    # constant). dedup_loss of 30-40% across the two sources is absorbed.
    n_sources = max(1, len(sources))
    per_source_target = max(visible_target, (visible_target * 2) // n_sources + 4)
    overall_start = time.time()
    raw_candidates: list[dict] = []

    # Each source gets its own independent budget slice (not a share of
    # whatever the previous source left behind). 30s per source is enough
    # for StashDB to escape its ~1180-page NULLS-FIRST birthdate bucket
    # via the +200 page-skip and still walk through valid-birthdate pages
    # for actual matches.
    per_source_budget = _SPOTLIGHT_PER_SOURCE_BUDGET_S

    for src_label, endpoint, src_key in sources:
        per_source_diag = {} if _diag is not None else None
        # Tag IDs are source-specific UUIDs — only apply to StashDB.
        # FansDB is left unfiltered so we still get scene candidates
        # from it when the user has set StashDB tag IDs.
        src_input = dict(api_input)
        if tags_filter and src_label == "StashDB":
            src_input["tags"] = {"value": tags_filter, "modifier": "INCLUDES"}
        src_candidates = _spotlight_fetch_from_stashbox(
            source_label=src_label,
            endpoint=endpoint,
            api_key=src_key,
            api_input_base=src_input,
            cfg=cfg,
            excluded_ids=excluded_ids,
            excl_library=excl_library,
            s=s,
            visible_target=per_source_target,
            budget_s=per_source_budget,
            diag=per_source_diag,
        )
        if _diag is not None and per_source_diag is not None:
            per_source_diag["candidates_returned"] = len(src_candidates)
            _diag.setdefault("sources", {})[src_label] = per_source_diag
        raw_candidates.extend(src_candidates)
        _log.info(
            "Spotlight: %s returned %s raw candidates (per-source target %s, budget %.1fs)",
            src_label, len(src_candidates), per_source_target, per_source_budget,
        )

    # ── Merge & dedup across sources by normalised name ──────────────────
    # StashDB, FansDB, and JAVStash use independent performer IDs, so the same
    # person can appear twice after the merge. Earlier rule was
    # "newcomer first" (invert scene_count) — that biased toward the
    # LEAST-established profile of every duplicate, opposite the
    # user's "real performers, not wannabees" intent. Flipped: higher
    # scene_count wins, then richer score, then more recent updated.
    source_priority = {lbl: idx for idx, (lbl, _, _) in enumerate(sources)}
    by_name: dict[str, dict] = {}
    def _dedup_key(d: dict) -> tuple:
        # All fields ordered so HIGHER tuple wins.
        sc = min(int(d.get("scene_count") or 0), 200)
        score = int(d.get("score") or 0)
        upd = (d.get("updated") or "")  # ISO string sorts lexically by recency
        return (sc, score, upd, -source_priority.get(d.get("source", ""), 99))
    for c in raw_candidates:
        nkey = (c.get("name") or "").strip().lower()
        if not nkey:
            continue
        existing = by_name.get(nkey)
        if existing is None:
            by_name[nkey] = c
            continue
        if _dedup_key(c) > _dedup_key(existing):
            by_name[nkey] = c
    candidates = list(by_name.values())

    # Fallback: top-up from prior cache if strict filters + sparse pages underfill.
    cached_used = 0
    if len(candidates) < _SPOTLIGHT_CACHE_TARGET:
        cached_performers = db.spotlight_load_top_cache(max_age_days=30)
        fresh_names = {(c.get("name") or "").strip().lower() for c in candidates}
        fresh_ids = {c.get("id") or "" for c in candidates}
        for cp in cached_performers:
            if len(candidates) >= _SPOTLIGHT_CACHE_TARGET:
                break
            pid = cp.get("id") or ""
            nkey = (cp.get("name") or "").strip().lower()
            if not pid or pid in fresh_ids or pid in excluded_ids:
                continue
            if nkey and nkey in fresh_names:
                continue
            bd_str = cp.get("birthdate") or ""
            age = cp.get("age") or _spotlight_age(bd_str)
            if not _spotlight_passes_hard_filters(cp, cfg, age):
                continue
            if excl_library and _spotlight_performer_in_library(cp, s, lib_lookup):
                continue
            scored = _spotlight_score_performer(cp, cfg, age)
            cp["score"] = scored["total"]
            cp["score_breakdown"] = scored["breakdown"]
            candidates.append(cp)
            fresh_ids.add(pid)
            if nkey:
                fresh_names.add(nkey)
            cached_used += 1

    # Sort by score DESC, then scene_count DESC for ties.
    candidates.sort(key=lambda x: (-x["score"], -x["scene_count"]))

    # Persist top 100 cache rows.
    cache_rows = candidates[:_SPOTLIGHT_CACHE_TARGET]
    db.spotlight_save_top_cache(cache_rows)

    # Keep a buffer of 50 for endpoint exclusions/replacements.
    results = cache_rows[:_SPOTLIGHT_BUFFER_TARGET]

    _log.info(
        "Spotlight: buffered=%s candidates=%s cache=%s sources=%s "
        "sort=%s %s cached_fallback=%s",
        len(results),
        len(candidates),
        len(cache_rows),
        ",".join(lbl for lbl, _, _ in sources),
        sort_field,
        direction,
        cached_used,
    )
    return results


# ── Spotlight v2 ─────────────────────────────────────────────────────
# Persistent raw-performer cache + scene-driven harvest + rotation +
# TTL eviction. The harvest is decoupled from rendering: scrape ticks
# upsert into spotlight_performers, the endpoint reads from that table
# and scores+samples synchronously. No live API call on render.
#
# Rotation policy:
#   - First scan after install: every enabled source in parallel.
#   - Subsequent ticks: round-robin one source per tick using the
#     spotlight_rotation_cursor settings key.
#   - Newly-enabled source (key added later): triggered as a one-shot
#     full scrape outside the rotation slot on its next tick.
#
# Eviction runs on every tick regardless of which source was scraped —
# `last_seen` belongs to the row, not the scrape.

_SPOTLIGHT_V2_HARVEST_PAGES = 1   # scene pages per source per tick (50 scenes/page → ~80-150 performers)
_SPOTLIGHT_V2_HARVEST_LOCK  = threading.Lock()
_SPOTLIGHT_V2_TICK_LOCK     = threading.Lock()


def _spotlight_source_enabled(s: dict, key: str) -> bool:
    """Per-source spotlight enable check. Defaults to True so existing
    installs (where the setting was never written) keep their current
    sources active until the user explicitly opts one out.
    """
    return (s.get(key) or "true").strip().lower() != "false"


def _spotlight_v2_sources() -> list[tuple[str, str, str]]:
    """All currently-configured stash-box sources for spotlight harvesting,
    in canonical order (StashDB → TPDB → FansDB → JAVStash). A source is included
    only when its API key is set AND its `spotlight_use_*` toggle is on
    (defaults to on)."""
    s = db.get_settings()
    out: list[tuple[str, str, str]] = []
    sk = (s.get("api_key_stashdb") or "").strip()
    if sk and _spotlight_source_enabled(s, "spotlight_use_stashdb"):
        out.append(("StashDB", STASHDB_ENDPOINT, sk))
    tk = (s.get("api_key_tpdb") or "").strip()
    if tk and _spotlight_source_enabled(s, "spotlight_use_tpdb"):
        out.append(("TPDB", TPDB_ENDPOINT, tk))
    fk = (s.get("api_key_fansdb") or "").strip()
    if fk and _spotlight_source_enabled(s, "spotlight_use_fansdb"):
        out.append(("FansDB", FANSDB_ENDPOINT, fk))
    jk = (s.get("api_key_javstash") or "").strip()
    if jk and _spotlight_source_enabled(s, "spotlight_use_javstash"):
        out.append(("JAVStash", JAVSTASH_ENDPOINT, jk))
    return out


def _spotlight_v2_scene_date_to_ts(release_date: str | None) -> int | None:
    """Parse a scene's release_date (YYYY-MM-DD or ISO) to a unix ts.
    Returns None on failure so MAX() in the upsert ignores it."""
    if not release_date:
        return None
    try:
        return int(datetime.fromisoformat(release_date[:10])
                   .replace(tzinfo=timezone.utc).timestamp())
    except Exception:
        try:
            return int(datetime.fromisoformat(release_date.replace("Z", "+00:00")).timestamp())
        except Exception:
            return None


# ── TPDB harvest helpers ────────────────────────────────────────────
# TPDB exposes performers via REST (`/performers`), not GraphQL, and
# stores bio fields under `extras` rather than as first-class columns.
# The helpers below parse the heterogeneous string formats TPDB uses
# (heights as `5'9"` / `175 cm` / bare cm; measurements as `34D-26-36`)
# back into the integer/cup-string shape the existing
# `_spotlight_body_types` / scoring pipeline expects.

_TPDB_HEIGHT_FT_RE = re.compile(r"^(\d+)\s*[′'`]\s*(\d+)?", re.UNICODE)
_TPDB_HEIGHT_CM_RE = re.compile(r"^(\d{2,3})\s*(?:cm)?\s*$", re.IGNORECASE)
_TPDB_MEASUREMENTS_RE = re.compile(
    r"^(\d{2,3})([A-Z]+)?\s*[-–]\s*(\d{2,3})\s*[-–]\s*(\d{2,3})$",
    re.IGNORECASE,
)


def _tpdb_parse_height_cm(raw) -> int | None:
    """Best-effort cm parse from TPDB's freeform height string."""
    if not raw:
        return None
    s = str(raw).strip()
    if not s:
        return None
    m = _TPDB_HEIGHT_FT_RE.match(s)
    if m:
        ft = int(m.group(1))
        inch = int(m.group(2) or 0)
        if 3 <= ft <= 7:
            return int(round((ft * 12 + inch) * 2.54))
    m = _TPDB_HEIGHT_CM_RE.match(s)
    if m:
        n = int(m.group(1))
        if 120 <= n <= 230:
            return n
    return None


def _tpdb_parse_measurements(raw) -> tuple[int | None, str | None, int | None, int | None]:
    """Split TPDB's `34D-26-36` style measurements into (band, cup, waist, hip)."""
    if not raw:
        return None, None, None, None
    s = str(raw).strip()
    m = _TPDB_MEASUREMENTS_RE.match(s)
    if not m:
        return None, None, None, None
    band = int(m.group(1))
    cup = (m.group(2) or "").upper() or None
    waist = int(m.group(3))
    hip = int(m.group(4))
    return band, cup, waist, hip


def _tpdb_truthy_list(raw) -> list[str]:
    """Normalise TPDB's tattoos/piercings (string or list) to a non-empty
    list when there's any signal — `bool()` on the result is what the
    scorer/filter actually checks."""
    if not raw:
        return []
    if isinstance(raw, list):
        return [str(x) for x in raw if x]
    s = str(raw).strip()
    if not s or s.lower() in ("none", "no", "n/a", "false", "0"):
        return []
    return [s]


def _spotlight_tpdb_payload_from_detail(tp: dict) -> dict:
    """Build a v2 cache payload from a /performers/{id} detail response."""
    extras = tp.get("extras") or {}
    poster_urls: list[str] = []
    for p0 in (tp.get("posters") or []):
        u = p0 if isinstance(p0, str) else (
            p0.get("url") or p0.get("src") if isinstance(p0, dict) else None
        )
        if u and u not in poster_urls:
            poster_urls.append(u)
    for fallback in (tp.get("image"), tp.get("thumbnail")):
        if fallback and fallback not in poster_urls:
            poster_urls.append(fallback)
    images = [{"url": u} for u in poster_urls]
    band, cup_from_meas, waist, hip = _tpdb_parse_measurements(extras.get("measurements"))
    cup = cup_from_meas or ((extras.get("cupsize") or "").strip().upper() or None)
    pid = str(tp.get("id") or tp.get("_id") or tp.get("slug") or "").strip()
    return {
        "id":                pid,
        "name":              tp.get("name") or "",
        "gender":            ((extras.get("gender") or "").upper() or None),
        "images":            images,
        "scene_count":       None,
        "age":               None,
        "created":           tp.get("created_at") or "",
        "updated":           tp.get("updated_at") or "",
        "birth_date":        extras.get("birthday") or "",
        "death_date":        "",
        "career_start_year": None,
        "height":            _tpdb_parse_height_cm(extras.get("height")),
        "cup_size":          cup,
        "band_size":         band,
        "waist_size":        waist,
        "hip_size":          hip,
        "breast_type":       None,
        "country":           extras.get("nationality") or "",
        "ethnicity":         extras.get("ethnicity") or "",
        "eye_color":         ((extras.get("eye_colour") or extras.get("eye_color") or "").upper() or None),
        "hair_color":        ((extras.get("hair_colour") or extras.get("hair_color") or "").upper() or None),
        "tattoos":           _tpdb_truthy_list(extras.get("tattoos")),
        "piercings":         _tpdb_truthy_list(extras.get("piercings")),
    }


def _spotlight_v2_harvest_tpdb(api_key: str, pages: int) -> int:
    """Walk TPDB's /scenes endpoint and harvest performers from each
    recent scene — the same pattern StashDB/FansDB use, just with TPDB's
    REST API. The old approach (dump /performers ordered by updated_at)
    was surfacing the entire TPDB performer DB, including stub profiles
    and machine-imported rows with no real signal that the performer is
    active. Walking scenes filters down to performers who actually
    appear on a recent release.

    Studio blacklist applies — any scene whose `site.name` matches a
    blacklist phrase is skipped wholesale. Each unique performer ID is
    then fetched via /performers/{id} so we get the full bio payload
    (birth_date, measurements, etc.) the scorer needs.
    """
    if not api_key:
        return 0
    s = db.get_settings()
    studio_blacklist = _spotlight_studio_blacklist(s)
    studio_preferred = _spotlight_studio_preferred(s)
    studio_preferred_mode = (s.get("spotlight_studio_preferred_mode") or "prefer").strip().lower()
    studio_require = bool(studio_preferred) and studio_preferred_mode == "require"
    headers = {
        "Accept": "application/json",
        "Authorization": f"Bearer {api_key}",
    }
    # Map performer_id → latest scene date (unix ts). Built as we walk
    # so a performer appearing on multiple recent scenes keeps the
    # newest scene's timestamp for the activity-recency scorer.
    latest_ts: dict[str, int | None] = {}
    # Aggregate every studio site name a performer was seen under in
    # this tick. Stored on the payload for read-time preferred-studio
    # scoring without needing a re-harvest when the user edits the
    # preferred list.
    pid_studios: dict[str, set[str]] = {}
    scenes_walked = 0
    scenes_blocked = 0
    scenes_skipped_preferred = 0
    for page in range(1, max(1, pages) + 1):
        try:
            resp = requests.get(
                "https://api.theporndb.net/scenes",
                params={"page": page, "per_page": _SPOTLIGHT_PER_PAGE},
                headers=headers,
                timeout=20,
            )
            if resp.status_code != 200:
                _log.warning("spotlight v2 tpdb scenes page %s: HTTP %s",
                             page, resp.status_code)
                break
            scenes = (resp.json() or {}).get("data") or []
            if not scenes:
                break
        except Exception as exc:
            _log.warning("spotlight v2 tpdb scenes page %s: %s", page, exc)
            break
        scenes_walked += len(scenes)
        for sc in scenes:
            # TPDB exposes the studio under `site.name`. The shared
            # blacklist helper expects `scene["studio"]["name"]`, so
            # adapt here rather than overloading the helper.
            site = (sc.get("site") or {})
            site_name = (site.get("name") or "")
            if _spotlight_studio_name_matches(site_name, studio_blacklist):
                scenes_blocked += 1
                continue
            if studio_require and not _spotlight_studio_name_matches(site_name, studio_preferred):
                scenes_skipped_preferred += 1
                continue
            scene_ts = _spotlight_v2_scene_date_to_ts(sc.get("date"))
            for p in (sc.get("performers") or []):
                if not isinstance(p, dict):
                    continue
                # TPDB sometimes wraps the performer under a `parent`
                # object (the canonical performer) with `extras.id`
                # carrying the scene-credit id. Prefer the parent id so
                # all credits collapse onto one cache row.
                parent = p.get("parent") if isinstance(p.get("parent"), dict) else {}
                pid = str(parent.get("id") or p.get("id") or "").strip()
                if not pid:
                    continue
                prev = latest_ts.get(pid)
                if prev is None or (scene_ts and (prev is None or scene_ts > prev)):
                    latest_ts[pid] = scene_ts
                if site_name:
                    pid_studios.setdefault(pid, set()).add(site_name)
    # Fetch full bio for each unique performer ID concurrently. ~8 workers
    # is enough to keep the harvest tick under ~30s for ~200 unique IDs
    # without overwhelming the TPDB API.
    rows: list[dict] = []
    detail_errors = 0
    with ThreadPoolExecutor(max_workers=8, thread_name_prefix="tpdb-spotlight") as pool:
        futs = {pool.submit(fetch_performer_detail, "TPDB", pid): pid for pid in latest_ts.keys()}
        for fut in futs:
            pid = futs[fut]
            try:
                tp = fut.result(timeout=20)
            except Exception:
                detail_errors += 1
                continue
            if not tp:
                detail_errors += 1
                continue
            payload = _spotlight_tpdb_payload_from_detail(tp)
            if not payload.get("id"):
                continue
            payload["studios"]     = sorted(pid_studios.get(pid, set()))
            payload["tag_matches"] = []  # TPDB scenes endpoint doesn't expose tag list here
            rows.append({
                "source":          "TPDB",
                "performer_id":    payload["id"],
                "name":            payload["name"],
                "payload_json":    json.dumps(payload),
                "latest_scene_at": latest_ts.get(pid),
            })
    written = db.spotlight_perf_upsert_many(rows) if rows else 0
    _log.info(
        "spotlight v2 tpdb scene harvest: pages=%s scenes_seen=%s scenes_blocked_studio=%s "
        "scenes_skipped_preferred=%s unique_performers=%s detail_errors=%s upserted=%s",
        pages, scenes_walked, scenes_blocked,
        scenes_skipped_preferred, len(latest_ts), detail_errors, written,
    )
    return written


def _spotlight_v2_harvest_source(source_label: str, endpoint: str, api_key: str,
                                 pages: int = _SPOTLIGHT_V2_HARVEST_PAGES) -> int:
    """Walk recent scenes from one source, harvest unique performers, upsert
    them into spotlight_performers. Returns the number of rows written.

    StashDB / FansDB use the shared GraphQL scenes-driven path. TPDB is
    REST-only with no scenes-by-performer query that maps onto this
    flow, so it dispatches to a dedicated `/performers` listing
    harvester."""
    if not api_key:
        return 0
    if source_label == "TPDB":
        return _spotlight_v2_harvest_tpdb(api_key, pages)
    s = db.get_settings()
    studio_blacklist = _spotlight_studio_blacklist(s)
    studio_preferred = _spotlight_studio_preferred(s)
    studio_preferred_mode = (s.get("spotlight_studio_preferred_mode") or "prefer").strip().lower()
    studio_require = bool(studio_preferred) and studio_preferred_mode == "require"
    tags_filter = [v.strip() for v in (s.get("spotlight_tags") or "").split(",") if v.strip()]
    tags_mode = (s.get("spotlight_tags_mode") or "require").strip().lower()
    tags_require = bool(tags_filter) and tags_mode == "require"
    api_input = {
        "per_page": _SPOTLIGHT_PER_PAGE,
        "sort": "DATE",
        "direction": "DESC",
        "page": 1,
    }
    # `require` keeps the API-level tag filter (StashDB only — FansDB
    # rejects unknown tag IDs across the UUID gap). `prefer` removes
    # the server-side filter so we harvest everything; the per-row tag
    # data is then stashed on the cache row for the score-time bonus.
    if tags_require and source_label == "StashDB":
        api_input["tags"] = {"value": tags_filter, "modifier": "INCLUDES"}
    tags_filter_set = {t.lower() for t in tags_filter}
    # Per-tick aggregation: collect every studio name + tag-id match
    # we see for each performer across all scenes walked in this tick.
    # The scorer reads them at /api/metadata/spotlight-performers time,
    # so changes to preferred-list or tag-mode take effect without a
    # fresh harvest (require-mode changes still need a wipe because
    # they affect membership, not just scoring).
    per_pid_studios: dict[str, set[str]] = {}
    per_pid_tags: dict[str, set[str]] = {}
    per_pid_latest_payload: dict[str, dict] = {}
    per_pid_latest_ts: dict[str, int | None] = {}
    for page in range(1, max(1, pages) + 1):
        api_input["page"] = page
        try:
            data = _stashbox_post(endpoint, api_key, SPOTLIGHT_SCENES_QUERY, {"input": api_input})
        except Exception as exc:
            _log.warning("spotlight v2 harvest (%s page %s): %s", source_label, page, exc)
            break
        scenes = (data.get("queryScenes") or {}).get("scenes") or []
        if not scenes:
            break
        for sc in scenes:
            if _spotlight_scene_studio_blacklisted(sc, studio_blacklist):
                continue
            studio_name = (sc.get("studio") or {}).get("name") or ""
            if studio_require and not _spotlight_studio_name_matches(studio_name, studio_preferred):
                continue
            scene_ts = _spotlight_v2_scene_date_to_ts(sc.get("release_date"))
            # Collect any tag ids on this scene that overlap the user's
            # tag filter. The shared scene query doesn't currently fetch
            # tags, so the prefer-mode bonus only fires when the
            # caller has switched to a query variant that does. For now
            # we still wire the plumbing so a future query update can
            # turn it on without re-touching the harvester.
            scene_tag_ids: set[str] = set()
            if tags_filter_set and not tags_require:
                for t in (sc.get("tags") or []):
                    tid = ""
                    if isinstance(t, dict):
                        tid = str(t.get("id") or t.get("slug") or "").lower()
                    elif isinstance(t, str):
                        tid = t.lower()
                    if tid and tid in tags_filter_set:
                        scene_tag_ids.add(tid)
            for pa in (sc.get("performers") or []):
                p = (pa or {}).get("performer") or {}
                pid = p.get("id") or ""
                if not pid:
                    continue
                # Aggregate studio + tag hits across every scene this
                # performer appears on. The PAYLOAD itself is held to
                # the FIRST occurrence (recent-scenes are sorted DESC
                # so the first is the freshest — matches the previous
                # behaviour where we early-continued once seen).
                if studio_name:
                    per_pid_studios.setdefault(pid, set()).add(studio_name)
                if scene_tag_ids:
                    per_pid_tags.setdefault(pid, set()).update(scene_tag_ids)
                if pid in per_pid_latest_payload:
                    prev_ts = per_pid_latest_ts.get(pid)
                    if scene_ts and (prev_ts is None or scene_ts > prev_ts):
                        per_pid_latest_ts[pid] = scene_ts
                    continue
                per_pid_latest_payload[pid] = {
                    "id":                p.get("id"),
                    "name":              p.get("name"),
                    "gender":            p.get("gender"),
                    "images":            p.get("images") or [],
                    "scene_count":       p.get("scene_count"),
                    "age":               p.get("age"),
                    "created":           p.get("created"),
                    "updated":           p.get("updated"),
                    "birth_date":        p.get("birth_date"),
                    "death_date":        p.get("death_date"),
                    "career_start_year": p.get("career_start_year"),
                    "height":            p.get("height"),
                    "cup_size":          p.get("cup_size"),
                    "band_size":         p.get("band_size"),
                    "waist_size":        p.get("waist_size"),
                    "hip_size":          p.get("hip_size"),
                    "breast_type":       p.get("breast_type"),
                    "country":           p.get("country"),
                    "ethnicity":         p.get("ethnicity"),
                    "eye_color":         p.get("eye_color"),
                    "hair_color":        p.get("hair_color"),
                    "tattoos":           list(p.get("tattoos") or []),
                    "piercings":         list(p.get("piercings") or []),
                }
                per_pid_latest_ts[pid] = scene_ts
    rows: list[dict] = []
    for pid, payload in per_pid_latest_payload.items():
        payload["studios"]     = sorted(per_pid_studios.get(pid, set()))
        payload["tag_matches"] = sorted(per_pid_tags.get(pid, set()))
        rows.append({
            "source":          source_label,
            "performer_id":    pid,
            "name":            payload.get("name") or "",
            "payload_json":    json.dumps(payload),
            "latest_scene_at": per_pid_latest_ts.get(pid),
        })
    written = db.spotlight_perf_upsert_many(rows)
    _log.info("spotlight v2 harvest [%s]: pages=%s perfs_upserted=%s",
              source_label, pages, written)
    return written


def _spotlight_v2_tick(reason: str = "scheduled") -> dict:
    """One scrape tick. First scan after install hits every enabled source
    in parallel; subsequent ticks round-robin one source. Eviction always
    runs. Newly-enabled sources jump the queue with a one-shot full scrape.
    """
    if not _SPOTLIGHT_V2_TICK_LOCK.acquire(blocking=False):
        _log.info("spotlight v2 tick already running, skipping (%s)", reason)
        return {"skipped": "already_running"}
    try:
        s = db.get_settings()
        sources = _spotlight_v2_sources()
        if not sources:
            db.spotlight_evict_stale(int(s.get("spotlight_ttl_days") or 30))
            return {"sources_scraped": [], "reason": "no_sources_configured"}

        first_done = (s.get("spotlight_first_scan_done") or "false").lower() == "true"
        last_known_csv = (s.get("spotlight_known_sources") or "").strip()
        known_sources = {x.strip() for x in last_known_csv.split(",") if x.strip()}
        current_labels = {lbl for (lbl, _, _) in sources}
        newly_enabled = current_labels - known_sources

        scraped: list[str] = []
        pages = max(1, int(s.get("spotlight_scrape_pages") or _SPOTLIGHT_V2_HARVEST_PAGES))

        # 1. First-ever scan: hit everything in parallel and seed the cache.
        if not first_done:
            with ThreadPoolExecutor(max_workers=max(1, len(sources)),
                                    thread_name_prefix="spotlight-v2-seed") as pool:
                futs = {pool.submit(_spotlight_v2_harvest_source, lbl, ep, k, pages): lbl
                        for (lbl, ep, k) in sources}
                for fut in futs:
                    try:
                        fut.result(timeout=180)
                        scraped.append(futs[fut])
                    except Exception as exc:
                        _log.warning("spotlight v2 seed source %s: %s", futs[fut], exc)
            db.save_settings({
                "spotlight_first_scan_done": "true",
                "spotlight_known_sources": ",".join(sorted(current_labels)),
                "spotlight_last_scan_at": str(int(time.time())),
                "spotlight_rotation_cursor": "0",
            })
        else:
            # 2. Newly-enabled sources jump the queue (one-shot full harvest).
            for lbl, ep, k in sources:
                if lbl in newly_enabled:
                    try:
                        _spotlight_v2_harvest_source(lbl, ep, k, pages)
                        scraped.append(lbl)
                    except Exception as exc:
                        _log.warning("spotlight v2 catch-up scrape %s: %s", lbl, exc)

            # 3. Round-robin one source per tick (skip sources we just caught up).
            if not scraped:
                cursor = int(s.get("spotlight_rotation_cursor") or 0) % len(sources)
                lbl, ep, k = sources[cursor]
                try:
                    _spotlight_v2_harvest_source(lbl, ep, k, pages)
                    scraped.append(lbl)
                except Exception as exc:
                    _log.warning("spotlight v2 rotation scrape %s: %s", lbl, exc)
                next_cursor = (cursor + 1) % len(sources)
            else:
                next_cursor = int(s.get("spotlight_rotation_cursor") or 0) % len(sources)

            db.save_settings({
                "spotlight_known_sources": ",".join(sorted(current_labels)),
                "spotlight_last_scan_at": str(int(time.time())),
                "spotlight_rotation_cursor": str(next_cursor),
            })

        # 4. Eviction always runs.
        ttl = max(1, int(s.get("spotlight_ttl_days") or 30))
        evicted = db.spotlight_evict_stale(ttl)
        counts = db.spotlight_perf_count_by_source()
        _log.info("spotlight v2 tick (%s): scraped=%s evicted=%s counts=%s",
                  reason, scraped, evicted, counts)
        return {
            "scraped": scraped,
            "evicted": evicted,
            "counts": counts,
            "first_scan": not first_done,
        }
    finally:
        _SPOTLIGHT_V2_TICK_LOCK.release()


def _spotlight_v2_build_cfg(s: dict) -> dict:
    """Build the scoring cfg dict from settings. Every mode collapses to
    `prefer` EXCEPT `spotlight_gender_mode`, which remains a real hard
    gate so gender-mismatched performers never slip in via weighting."""

    def _csv_set(key: str) -> set[str]:
        return {v.strip().upper() for v in (s.get(key) or "").split(",") if v.strip()}

    def _incl_null(key: str) -> bool:
        return (s.get(key) or "false").lower() == "true"

    def _mode(key: str, default: str = "prefer") -> str:
        v = (s.get(key) or default).lower().strip()
        # Most require-mode settings are downgraded to prefer here so the
        # v2 scorer (which scores everything and lets weighting decide)
        # doesn't accidentally hard-filter on softer traits. Carve-outs
        # for `gender` (always a real gate) and `min_scenes` (user
        # explicitly wants stub profiles excluded — was being silently
        # demoted to prefer here, so the < 5-scene exclusion never bit).
        if v == "require" and key not in ("spotlight_gender_mode", "spotlight_min_scenes_mode"):
            return "prefer"
        if v in ("ignore", "prefer", "require"):
            return v
        return default if default in ("ignore", "prefer", "require") else "prefer"

    def _weight(key: str, default: int = 3) -> int:
        try:
            return max(0, min(100, int(s.get(key) or default)))
        except (ValueError, TypeError):
            return default

    genders_filter   = _csv_set("spotlight_genders")
    min_age          = int(s.get("spotlight_min_age") or 0) or None
    max_age          = int(s.get("spotlight_max_age") or 0) or None
    age_hard_min, age_hard_max = _spotlight_age_hard_limits(s)
    _career_years    = int(s.get("spotlight_career_years") or 0) or None
    career_min       = (_date.today().year - _career_years) if _career_years else None
    min_scenes       = max(1, int(s.get("spotlight_min_scenes") or 5))
    recent_days      = int(s.get("spotlight_recent_days") or 0) or None
    tattoo_pref      = s.get("spotlight_tattoos") or "any"
    piercing_pref    = s.get("spotlight_piercings") or "any"

    recent_cutoff = (
        datetime.now(timezone.utc) - timedelta(days=recent_days) if recent_days else None
    )

    return dict(
        min_scenes=min_scenes, min_scenes_mode=_mode("spotlight_min_scenes_mode", "prefer"),
        min_scenes_weight=_weight("spotlight_min_scenes_weight", 2),
        recent_cutoff=recent_cutoff, recent_incl_null=_incl_null("spotlight_recent_incl_null"),
        active_mode=_mode("spotlight_active_mode", "ignore"),
        active_weight=_weight("spotlight_active_weight", 2),
        genders_filter=genders_filter, genders_incl_null=_incl_null("spotlight_genders_incl_null"),
        gender_mode=_mode("spotlight_gender_mode", "require"),
        gender_weight=_weight("spotlight_gender_weight", 3),
        age_hard_min=age_hard_min, age_hard_max=age_hard_max,
        min_age=min_age, max_age=max_age, age_incl_null=_incl_null("spotlight_age_incl_null"),
        age_mode=_mode("spotlight_age_mode", "prefer"),
        age_weight=_weight("spotlight_age_weight", 3),
        career_min=career_min, career_max=None,
        career_incl_null=(s.get("spotlight_career_start_incl_null") or "true").lower() == "true",
        tattoo_pref=tattoo_pref, tattoo_mode=_mode("spotlight_tattoo_mode", "ignore"),
        tattoo_weight=_weight("spotlight_tattoo_weight", 2),
        piercing_pref=piercing_pref, piercing_mode=_mode("spotlight_piercing_mode", "ignore"),
        piercing_weight=_weight("spotlight_piercing_weight", 2),
        hair_filter=_csv_set("spotlight_hair_colors"),
        hair_mode=_mode("spotlight_hair_mode", "prefer"),
        hair_weight=_weight("spotlight_hair_weight", 3),
        hair_incl_null=_incl_null("spotlight_hair_colors_incl_null"),
        breast_filter=_csv_set("spotlight_breast_types"),
        breast_mode=_mode("spotlight_breast_mode", "prefer"),
        breast_weight=_weight("spotlight_breast_weight", 3),
        breast_incl_null=_incl_null("spotlight_breast_types_incl_null"),
        ethnicity_filter=_csv_set("spotlight_ethnicities"),
        ethnicity_mode=_mode("spotlight_ethnicity_mode", "ignore"),
        ethnicity_weight=_weight("spotlight_ethnicity_weight", 3),
        ethnicity_incl_null=_incl_null("spotlight_ethnicities_incl_null"),
        country_filter={_normalise_country(v) for v in (s.get("spotlight_countries") or "").split(",") if v.strip()},
        country_mode=_mode("spotlight_country_mode", "prefer"),
        country_weight=_weight("spotlight_country_weight", 3),
        country_incl_null=_incl_null("spotlight_countries_incl_null"),
        body_type_filter=_csv_set("spotlight_body_types"),
        body_type_mode=_mode("spotlight_body_type_mode", "prefer"),
        body_type_weight=_weight("spotlight_body_type_weight", 4),
        body_type_incl_null=_incl_null("spotlight_body_types_incl_null"),
        source_filter=_csv_set("spotlight_sources"),
        source_mode=_mode("spotlight_source_mode", "ignore"),
        source_weight=_weight("spotlight_source_weight", 3),
        # ── v3 normalised-blend tuning knobs ─────────────────────────
        # Top-level category blend — adds to 1.0 by default, but the
        # final-score helper renormalises if the user supplies non-
        # 1.0-summing weights.
        blend_demographic=float(s.get("spotlight_blend_demographic") or 0.50),
        blend_confidence =float(s.get("spotlight_blend_confidence")  or 0.25),
        blend_discovery  =float(s.get("spotlight_blend_discovery")   or 0.15),
        blend_activity   =float(s.get("spotlight_blend_activity")    or 0.10),
        # Confidence sub-blend
        confidence_scene_w=float(s.get("spotlight_confidence_scene_w") or 0.50),
        confidence_image_w=float(s.get("spotlight_confidence_image_w") or 0.25),
        confidence_db_w   =float(s.get("spotlight_confidence_db_w")    or 0.25),
        # Caps and windows for log-normalisation / decay
        scene_cap=int(s.get("spotlight_scene_cap") or 200),
        image_cap=int(s.get("spotlight_image_cap") or 30),
        activity_window_days=int(s.get("spotlight_activity_window_days") or 90),
        # Sampling-time gamma compression (used by _spotlight_weighted_sample,
        # not the score itself — passed through for convenience).
        gamma=float(s.get("spotlight_gamma") or 0.5),
    )


def _spotlight_v2_score_from_cache(_diag: dict | None = None) -> list[dict]:
    """Read raw performers from spotlight_performers, score each, dedup by
    normalised name, sort by score DESC, return up to _SPOTLIGHT_BUFFER_TARGET.

    The only hard gate is "must have at least one image" (we can't render a
    tile without one). Every other criterion contributes via weighting.
    """
    s = db.get_settings()
    cfg = _spotlight_v2_build_cfg(s)
    excluded_ids = db.spotlight_get_excluded_ids()
    excl_library = (s.get("spotlight_excl_library") or "false").lower() == "true"
    lib_lookup = _spotlight_library_lookup(s) if excl_library else None

    # Load every performer seen recently. The TTL already trims dead rows;
    # we additionally only consider rows whose `last_seen` is within the
    # active window so a brief outage doesn't surface long-stale entries.
    active_window_days = max(1, int(s.get("spotlight_active_window_days") or 14))
    perfs = db.spotlight_perf_load_active(min_last_seen_days=active_window_days)

    if not perfs:
        # Fall back to the full TTL window if the active window is empty
        # (covers fresh installs that haven't built up signal yet).
        perfs = db.spotlight_perf_load_active(min_last_seen_days=None)

    # Per-source enable gate — drop any cached rows whose source the user
    # has disabled. Lets `Use TPDB for spotlight` toggle off remove TPDB
    # performers from the served buffer immediately (before TTL eviction
    # purges them from the cache itself).
    src_enabled = {
        "STASHDB":   _spotlight_source_enabled(s, "spotlight_use_stashdb"),
        "TPDB":      _spotlight_source_enabled(s, "spotlight_use_tpdb"),
        "FANSDB":    _spotlight_source_enabled(s, "spotlight_use_fansdb"),
        "JAVSTASH":  _spotlight_source_enabled(s, "spotlight_use_javstash"),
    }
    perfs = [p for p in perfs if src_enabled.get((p.get("_source") or "").upper(), True)]

    # Preferred studio + tag bonuses are applied at the bottom of this
    # function (after the v3 score is computed) — we read the lists here
    # so the per-row loop can build the augmented score in one pass.
    preferred_studios = _spotlight_studio_preferred(s)
    preferred_mode    = (s.get("spotlight_studio_preferred_mode") or "prefer").strip().lower()
    try:
        preferred_weight = max(0, min(100, int(s.get("spotlight_studio_preferred_weight") or 5)))
    except (TypeError, ValueError):
        preferred_weight = 5
    # `require` already filtered at harvest, but a user can have rows
    # in the cache from BEFORE switching to require. Re-apply at read
    # time so settings changes take effect without waiting for the
    # cache wipe + re-harvest cycle to land.
    if preferred_studios and preferred_mode == "require":
        perfs = [
            p for p in perfs
            if _spotlight_studios_in_payload_match_preferred(p.get("studios") or [], preferred_studios)
        ]
    tags_filter_set = {t.strip().lower() for t in (s.get("spotlight_tags") or "").split(",") if t.strip()}
    tags_mode       = (s.get("spotlight_tags_mode") or "require").strip().lower()
    try:
        tags_weight = max(0, min(100, int(s.get("spotlight_tags_weight") or 5)))
    except (TypeError, ValueError):
        tags_weight = 5

    if _diag is not None:
        _diag["raw_loaded"] = len(perfs)
        _diag["rejected_no_image"] = 0
        _diag["rejected_excluded"] = 0
        _diag["rejected_in_library"] = 0
        _diag["rejected_dormant"] = 0
        _diag["passed"] = 0

    # The single non-image hard gate: if the user has set
    # spotlight_gender_mode = require AND selected one or more genders, drop
    # everyone whose gender doesn't match (or is unknown, unless incl_null
    # is set). Every other criterion is purely weighted in the scorer.
    gender_hard = (cfg.get("gender_mode") == "require"
                   and bool(cfg.get("genders_filter")))
    gender_set = cfg.get("genders_filter") or set()
    gender_incl_null = bool(cfg.get("genders_incl_null"))

    # Min-scenes hard gate (StashDB / FansDB only). Earlier this was a
    # silent no-op: `_mode` downgraded `require` to `prefer` and the
    # scorer never read `min_scenes` back out, so stub profiles with 0–4
    # scenes filled the spotlight even with the exclusion turned on.
    # TPDB rows are carved out — they have no `scene_count` on the
    # listing endpoint (`scene_count: None`), so we can't judge them by
    # this filter and they pass through unchanged.
    # Min-scenes is now an unconditional hard gate for StashDB/FansDB
    # rows (was previously gated behind `spotlight_min_scenes_mode ==
    # "require"`, but the default mode is "prefer", which let stub
    # profiles like 1-scene StashDB performers slip through).
    min_scenes_threshold = int(cfg.get("min_scenes") or 0)
    # Min-images hard gate: every spotlight tile renders an image at
    # rest plus secondary slots in the popup, so we want at least 3
    # images per performer. Applies to every source.
    min_images_threshold = 3
    # Each kept image must be at least this size on the smaller axis
    # — anything smaller renders blurry on the spotlight tile or
    # popup poster. StashDB / FansDB return `width` / `height` per
    # image from the GraphQL query so we can filter by pixel size;
    # TPDB images come from the listing endpoint without dimensions
    # (just URLs), so they can't be measured at this stage and pass
    # through unfiltered. The size-filtered list is what feeds the
    # min-images count, the image-count bonus, AND the random pick.
    min_image_axis_px = 400

    def _img_passes_size(img: dict) -> bool:
        if not isinstance(img, dict):
            return True
        w = int(img.get("width") or 0)
        h = int(img.get("height") or 0)
        if w == 0 or h == 0:
            return True  # unknown dims (e.g. TPDB) — can't filter, pass
        return w >= min_image_axis_px and h >= min_image_axis_px

    # Cross-source pre-pass: count how many distinct stash-sources have
    # the same normalised name. A performer in StashDB + TPDB is a far
    # stronger "real" signal than one only on TPDB — one-time wannabees
    # rarely propagate across databases. Also lets the scoring step
    # award a bonus per extra source without re-walking `perfs`.
    source_map: dict[str, set[str]] = {}
    for _pre in perfs:
        _nkey = (_pre.get("name") or "").strip().lower()
        _src = (_pre.get("_source") or "").strip()
        if _nkey and _src:
            source_map.setdefault(_nkey, set()).add(_src)

    # 3-year dormant cutoff. Performers whose latest scene is older than
    # this fail unless their cross-scrape `_times_seen` count vouches for
    # them (intermittent regulars who happen to have a quiet stretch).
    # TPDB rows have no `_latest_scene_at` so they bypass the gate
    # entirely — TPDB has no scene timestamp on the listing, so we can't
    # judge dormancy from its data alone.
    _dormant_cutoff_secs = 365 * 3 * 86400
    _dormant_now = time.time()

    candidates: list[dict] = []
    for p in perfs:
        pid = p.get("id") or ""
        if not pid or pid in excluded_ids:
            if _diag is not None:
                _diag["rejected_excluded"] += 1
            continue
        # Filter to only large-enough images (TPDB rows pass through
        # because they have no dimensions). Subsequent reads of
        # `images` — count gate, count bonus, random pick — all use
        # the filtered list, so tiny thumbnails never get selected.
        images = [im for im in (p.get("images") or []) if _img_passes_size(im)]
        if len(images) < min_images_threshold:
            if _diag is not None:
                _diag["rejected_no_image"] += 1
            continue
        if gender_hard:
            gval = (p.get("gender") or "").upper()
            if not gval:
                if not gender_incl_null:
                    if _diag is not None:
                        _diag.setdefault("rejected_by_filter", {})
                        _diag["rejected_by_filter"]["gender"] = _diag["rejected_by_filter"].get("gender", 0) + 1
                    continue
            elif gval not in gender_set:
                if _diag is not None:
                    _diag.setdefault("rejected_by_filter", {})
                    _diag["rejected_by_filter"]["gender"] = _diag["rejected_by_filter"].get("gender", 0) + 1
                continue

        # Min-scenes hard gate: drop StashDB/FansDB stubs below the
        # threshold. TPDB rows skip — `scene_count` is None on TPDB rows
        # and `int(None or 0) == 0`, which would wipe every TPDB
        # performer out if we didn't carve them out.
        _src_for_minsc = (p.get("_source") or "").upper()
        if _src_for_minsc in ("STASHDB", "FANSDB", "JAVSTASH"):
            if int(p.get("scene_count") or 0) < min_scenes_threshold:
                if _diag is not None:
                    _diag.setdefault("rejected_by_filter", {})
                    _diag["rejected_by_filter"]["min_scenes"] = _diag["rejected_by_filter"].get("min_scenes", 0) + 1
                continue

        if excl_library and _spotlight_performer_in_library(p, s, lib_lookup):
            if _diag is not None:
                _diag["rejected_in_library"] += 1
            continue

        # Dormant-profile gate. Drop performers whose latest scene is
        # >3 years old UNLESS they've shown up in 3+ scrape cycles —
        # the latter pattern is intermittent regulars, not abandoned
        # profiles. Bypassed entirely when `_latest_scene_at` is null
        # (TPDB rows; the cache schema can't tell us when they last
        # worked).
        _ts_count_for_dormant = int(p.get("_times_seen") or 1)
        _latest_for_dormant = p.get("_latest_scene_at") or 0
        if _latest_for_dormant and _ts_count_for_dormant < 3:
            if (_dormant_now - _latest_for_dormant) > _dormant_cutoff_secs:
                if _diag is not None:
                    _diag["rejected_dormant"] += 1
                continue

        bd_str = p.get("birth_date") or ""
        age = p.get("age") or _spotlight_age(bd_str)
        source_label = p.get("_source") or ""
        p["source"] = source_label
        # Cross-source presence — fed into ConfidenceScore.db_presence by
        # the v3 scorer. The legacy +12-per-extra-source bonus that used
        # to live below was replaced by the normalised db_presence
        # component (1, 2, 3 sources → 0.33 / 0.66 / 1.00).
        _name_key = (p.get("name") or "").strip().lower()
        p["source_count"] = len(source_map.get(_name_key, set())) or 1
        # Use the size-filtered images list for ConfidenceScore.image —
        # tiny thumbnails shouldn't count toward "well documented".
        p["images"] = images
        scored = _spotlight_score_performer(p, cfg, age)
        # Note: legacy v2 bonuses (recency, times_seen, cross-source,
        # bio-completeness, image count) are no longer added here.
        # Their signal is absorbed into the four normalised categories:
        #   - recency (latest_scene_at)  → ActivityScore
        #   - cross-source presence      → ConfidenceScore.db_presence
        #   - image count                → ConfidenceScore.image
        # `times_seen` and bio-completeness signals were dropped on the
        # v3 cutover — the user can revive them as additional sub-
        # components of ConfidenceScore if rotation/quality drifts.

        # Image count + bio-completeness bonuses removed in v3 cutover.
        # Image-count signal lives in ConfidenceScore.image (log-norm).
        # Bio-completeness was dropped — revive as a sub-component of
        # ConfidenceScore if quality drifts post-rollout.

        # Preferred-studio + tag prefer-mode bonuses. Applied on TOP of
        # the v3 normalised blend so a configured weight of 5 lifts the
        # final score by 0.05, 100 lifts it by 1.0 (effectively pinning
        # the performer to the top of the buffer). Caps at 1.0 so the
        # weighted sampler keeps its [0,1] domain intact.
        bonus = 0.0
        if preferred_studios and preferred_mode == "prefer":
            if _spotlight_studios_in_payload_match_preferred(p.get("studios") or [], preferred_studios):
                bonus += preferred_weight / 100.0
        if tags_filter_set and tags_mode == "prefer":
            row_tags = {str(t).lower() for t in (p.get("tag_matches") or [])}
            if row_tags & tags_filter_set:
                bonus += tags_weight / 100.0
        v3_score = float((scored.get("v3") or {}).get("total", 0.0))
        v3_score = max(0.0, min(1.0, v3_score + bonus))
        legacy_pct = int(scored.get("total") or 0) + int(round(bonus * 100))
        # Random pick across all available images. The first slot is
        # frequently the worst (low-res scrape, off-pose, watermarked)
        # so always picking it makes the spotlight look bad. Random
        # selection at score time means each cache rebuild rerolls the
        # image. Note: AWB cache is keyed by performer_id, so the very
        # first random pick is the one the on-disk cache stores until
        # eviction — giving a noticeable refresh cadence without paying
        # the AWB cost on every page load.
        img_raw   = images[random.randrange(len(images))] if len(images) > 1 else images[0]
        image_url = img_raw.get("url") if isinstance(img_raw, dict) else img_raw
        candidates.append({
            "id":                      pid,
            "source":                  source_label,
            "name":                    p.get("name") or "",
            "gender":                  p.get("gender") or "",
            "image":                   image_url or "",
            "scene_count":             p.get("scene_count") or 0,
            "age":                     age,
            "birthdate":               bd_str,
            "death_date":              (p.get("death_date") or ""),
            "updated":                 p.get("updated") or "",
            "created":                 p.get("created") or "",
            "career_start_year":       p.get("career_start_year"),
            "career_start_inferred":   _spotlight_infer_career_start(p, age) if p.get("career_start_year") is None else None,
            "height":                  p.get("height"),
            "measurements":            _fmt_measurements(p),
            "cup_size":                (p.get("cup_size") or "").upper(),
            "band_size":               p.get("band_size"),
            "waist_size":              p.get("waist_size"),
            "hip_size":                p.get("hip_size"),
            "body_types":              sorted(_spotlight_body_types(p)),
            "breast_type":             p.get("breast_type") or "",
            "country":                 p.get("country") or "",
            "ethnicity":               p.get("ethnicity") or "",
            "eye_color":               p.get("eye_color") or "",
            "hair_color":              p.get("hair_color") or "",
            "tattoos":                 bool(p.get("tattoos")),
            "piercings":               bool(p.get("piercings")),
            # v3: `score` stores the normalised [0,1] FinalScore so the
            # gamma-compressed weighted sampler can read it directly.
            # `score_pct` is the legacy 0-100 integer kept around for
            # display + the dedup tiebreaker below.
            "score":                   v3_score,
            "score_pct":               legacy_pct,
            "score_breakdown":         scored.get("breakdown", []),
            "score_v3":                scored.get("v3", {}),
            "_last_seen":              p.get("_last_seen"),
            "_latest_scene_at":        p.get("_latest_scene_at"),
            "_times_seen":             p.get("_times_seen"),
        })
        if _diag is not None:
            _diag["passed"] += 1

    # Dedup across sources by normalised name. Earlier rule was
    # "newcomer first" — invert scene_count so 1-scene wins over 50.
    # That biased the dedup toward the LEAST-established profile of
    # every duplicate, exactly opposite the user's "real performers,
    # not wannabees" intent. Flipped: higher scene_count wins, then
    # more `_times_seen`, then richer score, then more recent
    # `updated`. Source priority drops to last-resort tiebreaker.
    src_priority = {"StashDB": 2, "FansDB": 1, "TPDB": 0}
    by_name: dict[str, dict] = {}
    def _dedup_key(d: dict) -> tuple:
        sc = min(int(d.get("scene_count") or 0), 200)
        ts = min(int(d.get("_times_seen") or 1), 20)
        # v3: `score` is now a float [0,1]; multiply by 1000 to keep
        # int-tuple ordering precision in the dedup tiebreaker.
        score = int(round(float(d.get("score") or 0.0) * 1000))
        upd = (d.get("updated") or "")
        return (sc, ts, score, upd, src_priority.get(d.get("source", ""), 0))
    for c in candidates:
        nkey = (c.get("name") or "").strip().lower()
        if not nkey:
            continue
        existing = by_name.get(nkey)
        if existing is None or _dedup_key(c) > _dedup_key(existing):
            by_name[nkey] = c
    candidates = list(by_name.values())

    # v3: sort by float score DESC, scene_count DESC tiebreaker
    candidates.sort(key=lambda x: (-float(x.get("score") or 0.0), -int(x.get("scene_count") or 0)))
    results = candidates[:_SPOTLIGHT_BUFFER_TARGET]

    # Persist a snapshot to spotlight_top_cache so the existing fallback
    # paths (legacy v1 `_fetch_spotlight_performers` underfill recovery) keep
    # working during the v1→v2 cutover.
    try:
        db.spotlight_save_top_cache(results[:_SPOTLIGHT_CACHE_TARGET])
    except Exception as exc:
        _log.warning("spotlight v2 top-cache snapshot: %s", exc)

    _log.info("spotlight v2 score: raw=%s candidates=%s buffered=%s",
              len(perfs), len(candidates), len(results))
    return results


_spotlight_cache: dict = {"performers": [], "fetched_at": 0.0}
_spotlight_cache_lock = threading.Lock()


def _refresh_spotlight_cache() -> None:
    """Spotlight v2 refresh: run a scrape tick (rotation-aware) then rebuild
    the in-memory scored buffer from the persistent cache. Called by the
    scheduler at the configured interval.
    """
    try:
        s = db.get_settings()
        if not _spotlight_v2_sources():
            return
        _spotlight_v2_tick(reason="scheduled")
        performers = _spotlight_v2_score_from_cache()
        with _spotlight_cache_lock:
            _spotlight_cache["performers"] = performers
            _spotlight_cache["fetched_at"] = time.time()
        _log.info(f"Spotlight cache refreshed: {len(performers)} performers")
        if performers:
            threading.Thread(
                target=_prefetch_spotlight_images,
                args=(list(performers),),
                daemon=True,
                name="spotlight-image-prefetch",
            ).start()
    except Exception as e:
        _log.error(f"Spotlight cache refresh error: {type(e).__name__}: {e}", exc_info=True)


def _prefetch_spotlight_images(performers: list[dict]) -> None:
    """Download + auto-balance every performer image in the buffer ahead of
    time so endpoint hits serve from disk. Runs in parallel to keep the
    warm-up under ~30s for a 100-item buffer. Also prunes stale cached
    JPGs whose IDs are no longer in the buffer so disk usage stays bounded.
    """
    if not performers:
        return
    started = time.time()
    keep_ids: set[str] = set()
    jobs: list[tuple[str, str]] = []
    for p in performers:
        pid = (p.get("id") or "").strip()
        raw = (p.get("image") or "").strip()
        if not pid:
            continue
        safe_id = pid.replace("/", "_").replace("\\", "_")
        keep_ids.add(safe_id)
        if raw and raw.startswith("http"):
            jobs.append((pid, raw))
    if jobs:
        # 8 workers — StashDB's CDN serves images comfortably in parallel
        # and the auto-balance step is CPU-bound anyway (numpy + PIL).
        with ThreadPoolExecutor(max_workers=8, thread_name_prefix="spotlight-prefetch") as pool:
            futures = [pool.submit(_get_or_create_spotlight_image, pid, url) for pid, url in jobs]
            for _f in as_completed(futures):
                try:
                    _f.result()
                except Exception:
                    pass
    try:
        _prune_stale_spotlight_images(keep_ids)
    except Exception as exc:
        _log.warning(f"Spotlight image prune skipped: {exc}")
    _log.info(
        "Spotlight image prefetch done: %d jobs in %.1fs, %d ids retained",
        len(jobs), time.time() - started, len(keep_ids),
    )


def _prune_stale_spotlight_images(keep_ids: set[str]) -> None:
    """Remove cached spotlight JPGs whose ids aren't in the current buffer.

    Keeps the cache dir bounded to the working set (≈100 files). Preserves
    everything matching ``keep_ids`` even if their mtime is old — the buffer
    dictates relevance, not disk age.
    """
    d = _spotlight_cache_dir()
    if not d.is_dir():
        return
    removed = 0
    for f in d.iterdir():
        if not f.is_file() or f.suffix.lower() != ".jpg":
            continue
        if f.stem not in keep_ids:
            try:
                f.unlink()
                removed += 1
            except OSError:
                pass
    if removed:
        _log.info("Spotlight image prune: removed %d stale files", removed)


def _spotlight_cache_dir() -> Path:
    d = _metadata_base_dir() / "spotlight"
    d.mkdir(parents=True, exist_ok=True)
    return d


def _spotlight_autobalance_image(src_bytes: bytes, max_edge: int = 800) -> bytes | None:
    """Auto-balance an image for duotone display: auto-contrast + brightness normalisation.

    Returns JPEG bytes or None on failure.
    """
    from PIL import ImageOps, ImageStat
    import numpy as np
    try:
        im = Image.open(io.BytesIO(src_bytes))
        if im.mode == "CMYK":
            im = im.convert("RGB")
        if im.mode != "RGB":
            im = im.convert("RGB")
        # Resize to max edge for performance
        w, h = im.size
        if max(w, h) > max_edge:
            scale = max_edge / max(w, h)
            im = im.resize((max(1, int(w * scale)), max(1, int(h * scale))), Image.Resampling.LANCZOS)
        # Auto white balance — grey-world algorithm
        # Scale each channel so their averages converge to a neutral grey
        arr = np.array(im, dtype=np.float32)
        avg_r = arr[:, :, 0].mean()
        avg_g = arr[:, :, 1].mean()
        avg_b = arr[:, :, 2].mean()
        avg_all = (avg_r + avg_g + avg_b) / 3.0
        if avg_r > 1 and avg_g > 1 and avg_b > 1:
            arr[:, :, 0] *= avg_all / avg_r
            arr[:, :, 1] *= avg_all / avg_g
            arr[:, :, 2] *= avg_all / avg_b
            arr = np.clip(arr, 0, 255)
        im = Image.fromarray(arr.astype(np.uint8))
        buf = io.BytesIO()
        im.save(buf, format="JPEG", quality=85, optimize=True)
        return buf.getvalue()
    except Exception as exc:
        emit(f"Spotlight AWB error: {exc}")
        return None


def _spotlight_image_serve_url(performer_id: str, image_url: str) -> str:
    """Fast serve path: local AWB URL only when already prefetched.

    Never blocks on download/processing — the scheduler's
    ``_prefetch_spotlight_images`` pass fills the on-disk cache. Until then
    the browser loads the remote CDN URL directly.
    """
    raw = (image_url or "").strip()
    pid = (performer_id or "").strip()
    if not raw:
        return ""
    if not raw.startswith("http"):
        return raw
    if not pid:
        return raw
    safe_id = pid.replace("/", "_").replace("\\", "_")
    cached = _spotlight_cache_dir() / f"{safe_id}.jpg"
    try:
        if cached.is_file() and cached.stat().st_size > 500:
            return f"/api/metadata/spotlight-image?id={safe_id}"
    except OSError:
        pass
    return raw


def _get_or_create_spotlight_image(performer_id: str, image_url: str) -> str | None:
    """Return the local API URL for an auto-balanced spotlight image.

    Downloads and processes the image on first call, serves from cache thereafter.
    Returns the API URL path or None. Used by background prefetch only — the
    spotlight performers endpoint must call ``_spotlight_image_serve_url`` instead
    so page loads never block on AWB.
    """
    if not performer_id or not image_url:
        return None
    safe_id = str(performer_id).replace("/", "_").replace("\\", "_")
    cached = _spotlight_cache_dir() / f"{safe_id}.jpg"
    if cached.is_file() and cached.stat().st_size > 500:
        return f"/api/metadata/spotlight-image?id={safe_id}"
    if not image_url.startswith("http"):
        return None
    # Download and process
    try:
        resp = requests.get(image_url, timeout=10, headers={"User-Agent": "Top-Shelf/1.0"})
        if resp.status_code != 200:
            emit(f"Spotlight image download failed: HTTP {resp.status_code} for {image_url[:60]}")
            return None
        balanced = _spotlight_autobalance_image(resp.content)
        if not balanced:
            emit(f"Spotlight AWB processing failed for {safe_id}")
            return None
        cached.write_bytes(balanced)
        emit(f"Spotlight AWB: saved {safe_id}.jpg ({len(balanced)} bytes)")
        return f"/api/metadata/spotlight-image?id={safe_id}"
    except Exception as exc:
        emit(f"Spotlight image error for {safe_id}: {exc}")
        return None



_spotlight_recent: dict[str, float] = {}
_spotlight_recent_lock = threading.Lock()


def _spotlight_recent_weight(pid: str, now: float, scene_count: int = 999) -> float:
    """Dampening multiplier in [0.1, 1.0] based on how recently ``pid`` was served.

    A just-served performer gets 0.1×; the multiplier ramps linearly back to
    1.0× across ``_SPOTLIGHT_RECENT_WINDOW_S``. Stops the same two or three
    names dominating consecutive page loads without ever hard-excluding them.

    Newcomers (scene_count < 10) get NO dampening — they're already rare in
    the buffer, so the 0.1× multiplier was effectively pushing them out of
    the weighted-sample lottery for 15 minutes after a single appearance."""
    if not pid:
        return 1.0
    if scene_count < 10:
        return 1.0  # never dampen emerging performers
    with _spotlight_recent_lock:
        ts = _spotlight_recent.get(pid)
    if ts is None:
        return 1.0
    elapsed = now - ts
    if elapsed >= _SPOTLIGHT_RECENT_WINDOW_S:
        return 1.0
    return max(0.1, elapsed / _SPOTLIGHT_RECENT_WINDOW_S)


def _spotlight_mark_served(ids: list[str]) -> None:
    """Record that ``ids`` were just served, and prune entries past the window."""
    now = time.time()
    cutoff = now - _SPOTLIGHT_RECENT_WINDOW_S
    with _spotlight_recent_lock:
        for pid in ids:
            if pid:
                _spotlight_recent[pid] = now
        for k in [k for k, v in _spotlight_recent.items() if v < cutoff]:
            _spotlight_recent.pop(k, None)


def _discovery_sort_key(p: dict) -> tuple:
    """Sort key for the discovery half of `_spotlight_split_sample`.

    Lower is better. Combines low scene_count with recency: an abandoned
    profile (2 scenes from 2016) gets a heavy staleness penalty so it
    sorts AFTER an active newcomer with 8 scenes. Without this, the
    discovery slice surfaces dead/incomplete profiles instead of real
    rising talent."""
    sc = int(p.get("scene_count") or 0)
    upd_str = (p.get("updated") or "").strip()
    days_old = 9999
    if upd_str:
        try:
            dt = datetime.fromisoformat(upd_str.replace("Z", "+00:00"))
            days_old = max(0, (datetime.now(timezone.utc) - dt).days)
        except Exception:
            pass
    # +1 to the discovery rank per month stale, capped at +50 so a
    # 5-year-stale 1-scene profile sorts at rank 51, well after a
    # 30-scene active performer (rank 30).
    staleness_penalty = min(50, days_old // 30)
    return (sc + staleness_penalty, random.random())


def _spotlight_split_sample(
    pool: list[dict],
    k: int,
    discovery_ratio: float = 0.5,
    min_newcomers: int = 0,
    gamma: float = 0.5,
) -> list[dict]:
    """v3: Single gamma-compressed weighted sample over the whole pool,
    plus an optional newcomer-floor swap-in.

    The legacy "discovery half" / "weighted half" split is gone — the
    new normalised-blend score includes `DiscoveryScore` (inverse of
    log-normalised scene_count) at 15% by default, which surfaces newer
    profiles naturally without needing a hard quota. `discovery_ratio`
    is kept in the signature for backward compat with the endpoint
    plumbing but is no longer read.

    `min_newcomers` is preserved as the optional 1-2 reserved-slot
    guarantee mentioned in the v3 spec — performers with `scene_count
    <= 10` are swapped in for the highest-scene-count picks if the
    weighted sample produces too few of them. Capped at what the pool
    actually supplies (won't fabricate newcomers).

    `gamma` is forwarded to `_spotlight_weighted_sample` so the
    compression curve is set per-call from the active settings.
    """
    if not pool or k <= 0:
        return []
    out = _spotlight_weighted_sample(pool, k, gamma=gamma)

    if min_newcomers > 0:
        def _is_newcomer(d: dict) -> bool:
            return int(d.get("scene_count") or 0) <= 10
        current_newcomers = sum(1 for p in out if _is_newcomer(p))
        deficit = min_newcomers - current_newcomers
        if deficit > 0:
            out_ids = {p.get("id") or "" for p in out}
            available_newcomers = [
                p for p in pool
                if _is_newcomer(p) and (p.get("id") or "") not in out_ids
            ]
            extra = random.sample(
                available_newcomers,
                k=min(len(available_newcomers), deficit),
            )
            if extra:
                # Drop the highest-scene-count non-newcomers from `out`
                # so the count stays at k. Cap at len(extra) drops.
                veterans = [(i, p) for i, p in enumerate(out) if not _is_newcomer(p)]
                veterans.sort(key=lambda ip: int(ip[1].get("scene_count") or 0), reverse=True)
                drop_indices = {ip[0] for ip in veterans[:len(extra)]}
                kept = [p for i, p in enumerate(out) if i not in drop_indices]
                out = kept + extra

    random.shuffle(out)
    return out[:k]


def _spotlight_weighted_sample(pool: list[dict], k: int, gamma: float = 0.5) -> list[dict]:
    """Weighted sample without replacement from the spotlight buffer.

    Weight model (v3):

        W(p) = (FinalScore(p))**gamma × R(p)

    Where:
      - FinalScore is the v3 normalised blend in [0,1] (`p["score"]`).
      - gamma (default 0.5 → sqrt) compresses the dominance of top-scoring
        performers so the distribution has a longer tail. gamma < 1 →
        flattens (more diversity), gamma > 1 → sharpens (more elitism).
      - R(p) is the recent-served dampener in [0.1, 1.0]; newcomers
        (scene_count < 10) are exempt and always 1.0.

    A 1e-3 floor below the gamma compression keeps zero-scoring candidates
    in the lottery — score 0 pre-gamma → 0 post-gamma without the floor,
    which would silently exclude any performer who happens to score zero
    against the user's preferences.
    """
    if not pool or k <= 0:
        return []
    now = time.time()
    items = list(pool)
    g = max(0.05, min(5.0, float(gamma)))

    def _w(p: dict) -> float:
        s = max(0.0, float(p.get("score") or 0))
        # Score is in [0,1] — apply gamma after a small floor so a 0.0
        # score produces a non-zero weight (1e-3 ** 0.5 ≈ 0.032) and the
        # candidate still has a chance.
        compressed = max(s, 1e-3) ** g
        return compressed * _spotlight_recent_weight(
            p.get("id") or "", now, int(p.get("scene_count") or 0)
        )

    wts = [_w(p) for p in items]
    picked: list[dict] = []
    for _ in range(min(k, len(items))):
        total = sum(wts)
        if total <= 0:
            idx = random.randrange(len(items))
        else:
            r = random.uniform(0, total)
            cum = 0.0
            idx = len(items) - 1
            for i, w in enumerate(wts):
                cum += w
                if r <= cum:
                    idx = i
                    break
        picked.append(items.pop(idx))
        wts.pop(idx)
    return picked



@app.post("/api/cache/clear")
async def api_cache_clear():
    """Clear all cached images: spotlight, discover thumbnails, performer posters, movie/studio thumbs, old cache dir."""
    cleared = 0
    # Discover / recent-scenes remote image JPEGs
    discover_dir = _discover_image_cache_dir()
    if discover_dir.is_dir():
        for f in list(discover_dir.iterdir()):
            if f.is_file():
                try:
                    f.unlink()
                    cleared += 1
                except OSError:
                    pass
    # Spotlight auto-balanced images
    spotlight_dir = _spotlight_cache_dir()
    if spotlight_dir.is_dir():
        for f in list(spotlight_dir.iterdir()):
            if f.is_file():
                try:
                    f.unlink()
                    cleared += 1
                except Exception:
                    pass
    # Performer poster images (poster_1, poster_2, old poster.jpg)
    perf_base = _metadata_base_dir() / "performers"
    if perf_base.is_dir():
        for sub in perf_base.iterdir():
            if sub.is_dir():
                for f in sub.glob("*_poster*.jpg"):
                    try:
                        f.unlink()
                        cleared += 1
                    except Exception:
                        pass
    # Movie cached images
    movie_base = _metadata_base_dir() / "movies"
    if movie_base.is_dir():
        for sub in movie_base.iterdir():
            if sub.is_dir():
                for f in sub.iterdir():
                    if f.is_file():
                        try:
                            f.unlink()
                            cleared += 1
                        except Exception:
                            pass
    # Studio cached images
    studio_base = _metadata_base_dir() / "studios"
    if studio_base.is_dir():
        for sub in studio_base.iterdir():
            if sub.is_dir():
                for f in sub.iterdir():
                    if f.is_file():
                        try:
                            f.unlink()
                            cleared += 1
                        except Exception:
                            pass
    # Legacy favourites_img_cache
    if FAVOURITES_IMG_CACHE_DIR.is_dir():
        for f in FAVOURITES_IMG_CACHE_DIR.iterdir():
            if f.is_file():
                try:
                    f.unlink()
                    cleared += 1
                except Exception:
                    pass
    emit(f"CACHE: cleared {cleared} cached image(s)")
    return {"ok": True, "cleared": cleared, "message": f"Cleared {cleared} cached image(s)"}






@app.get("/api/metadata/dirs")
async def metadata_dirs(kind: str = ""):
    """Return configured library directories for the destination picker.

    ``kind=performer`` — ranked performer library roots only (add-performer flows).
    ``kind=studio`` — series library root only.
    ``kind=movie`` — features + JAV roots.
    Omit ``kind`` for the legacy union of every root (avoid for new UI).
    """
    s = db.get_settings()
    k = (kind or "").strip().lower()

    if k == "performer":
        return {
            "dirs": [
                {"label": d["label"], "path": d["path"], "type": "performer"}
                for d in db.get_directories("performer")
            ]
        }

    if k == "studio":
        series = (s.get("series_dir") or "").strip()
        return {
            "dirs": (
                [{"label": "Series", "path": series, "type": "studio"}]
                if series
                else []
            )
        }

    if k == "movie":
        dirs = []
        features = (s.get("features_dir") or "").strip()
        if features:
            dirs.append({"label": "Features", "path": features, "type": "movie"})
        jav_d = (s.get("jav_dir") or "").strip()
        if jav_d:
            dirs.append({"label": "JAV", "path": jav_d, "type": "movie"})
        return {"dirs": dirs}

    dirs = []
    for label, path in [
        ("Series",   s.get("series_dir",   "")),
        ("Features", s.get("features_dir", "")),
    ]:
        if path:
            dirs.append({"label": label, "path": path})
    jav_d = (s.get("jav_dir") or "").strip()
    if jav_d:
        dirs.append({"label": "JAV", "path": jav_d})
    for d in db.get_directories():
        dirs.append({"label": d["label"], "path": d["path"], "type": d.get("type") or ""})
    return {"dirs": dirs}


@app.get("/api/log/stream")
async def log_stream():
    async def event_generator() -> AsyncGenerator[str, None]:
        for line in processing_state["log"]:
            yield f"data: {json.dumps(line)}\n\n"
        while True:
            try:
                msg = await asyncio.wait_for(log_queue.get(), timeout=15.0)
                yield f"data: {json.dumps(msg)}\n\n"
            except asyncio.TimeoutError:
                yield 'data: {"ping":true}\n\n'
    return StreamingResponse(event_generator(), media_type="text/event-stream")
